window.HADITH_CACHE["tirmidzi_5"] = {"2501":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَخْبَرَنَا شُعْبَةُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ وَعَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ وَالْأَعْمَشِ كُلُّهُمْ سَمِعُوا زَيْدَ بْنَ وَهْبٍ عَنْ أَبِي ذَرٍّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَانِي جِبْرِيلُ فَبَشَّرَنِي فَأَخْبَرَنِي أَنَّهُ مَنْ مَاتَ لَا يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ الْجَنَّةَ قُلْتُ وَإِنْ زَنَى وَإِنْ سَرَقَ قَالَ نَعَمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ أَبِي الدَّرْدَاءِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah mengabarkan kepada kami [Syu'bah] dari [Habib bin Abi Tsabit] dan [Abdul Aziz bin Rufai'] dan [al A'masy] maisng-masing dari mereka mendengar [Zaid bin Wahb] dari [Abu Dzar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jibril mendatangiku, dan dia memberiku kabar gembira, dia mengabarkan kepadaku bahwasanya siapa yang meninggal sedang dia tidak menyekutukan Allah dengan sesuatu maka dia masuk surga.\" Saya bertanya, \"Walaupun dia berzina dan mencuri?\" Beliau bersabda: \"Ya\" Abu Isa berkata; 'Ini adalah hadits hasan shahih. Dan dalam hadits bab tersebut juga diriwayatkan dari Abu ad Darda'"},"2502":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يُرِدْ اللَّهُ بِهِ خَيْرًا يُفَقِّهْهُ فِي الدِّينِوَفِي الْبَاب عَنْ عُمَرَ وَأَبِي هُرَيْرَةَ وَمُعَاوِيَةَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah menceritakan kepada kami [Ismail bin Ja'far] telah menceritakan kepadaku [Abdullah bin Sa'id bin Abi Hind] dari [Bapaknya] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang di kehendaki Allah kebaikan padanya, niscaya Dia memahamkannya dalam agama.\" Dan dalam bab tersebut juga diriwayatkan dari Umar dan Abu Hurairah serta Mu'awiyah. Hadits Ini hadits hasan shahih."},"2503":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللَّهُ لَهُ طَرِيقًا إِلَى الْجَنَّةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Usamah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berjalan di suatu jalan untuk mencari ilmu, niscaya Allah akan memudahkan baginya jalan ke surga.\" Abu Isa berkata; 'Ini adalah hadits hasan.'"},"2504":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا خَالِدُ بْنُ يَزِيدَ الْعَتَكِيُّ عَنْ أَبِي جَعْفَرٍ الرَّازِيِّ عَنْ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ خَرَجَ فِي طَلَبِ الْعِلْمِ كَانَ فِي سَبِيلِ اللَّهِ حَتَّى يَرْجِعَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَرَوَاهُ بَعْضُهُمْ فَلَمْ يَرْفَعْهُ","id":"Telah bercerita kepada kami [Nahsr bin Ali] dia berkata, telah bercerita kepada kami [Khalid bin Yazid Al Ataki] dari [Abu Ja'far Ar Razi] dari [Ar Rabi' bin Anas] dari [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa keluar dalam rangka menuntut ilmu maka dia berada di jalan Allah sampai dia kembali.\" Abu Isa berkata; 'Hadits ini hasan gharib, sebagian perawi telah meriwayatkannya namun tidak merafa'kannya.'"},"2505":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ الرَّازِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُعَلَّى حَدَّثَنَا زِيَادُ بْنُ خَيْثَمَةَ عَنْ أَبِي دَاوُدَ عَنْ عَبْدِ اللَّهِ بْنِ سَخْبَرَةَ عَنْ سَخْبَرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ طَلَبَ الْعِلْمَ كَانَ كَفَّارَةً لِمَا مَضَىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ ضَعِيفُ الْإِسْنَادِ أَبُو دَاوُدَ يُضَعَّفُ فِي الْحَدِيثِ وَلَا نَعْرِفُ لِعَبْدِ اللَّهِ بْنِ سَخْبَرَةَ كَبِيرَ شَيْءٍ وَلَا لِأَبِيهِ وَاسْمُ أَبِي دَاوُدَ نُفَيْعٌ الْأَعْمَى تَكَلَّمَ فِيهِ قَتَادَةُ وَغَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ","id":"Telah bercerita kepada kami [Muhammmad bin Humaid ar Razi] telah menceritakan kepada kami [Muhammad bin Al Mu'alla] telah bercerita kepada kami [Ziyad bin Khaitsamah] dari [Abu Dawud] dari [Abdullah bin Syakhbarah] dari [Syakhbarah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menuntut ilmu, maka itu sebagai penghapus dosa-dosanya yang telah lalu\". Abu Isa berkata; 'Hadits ini sanadnya dhaif, karena Abu Daud dilemahkan dalam hadits ini, dan kami tidak mengetahui Abdullah bin Syakhbarah memiliki sesuatu yang besar, dan tidak pula bapaknya. Adapun nama Abu Daud adalah Nufai' Al A'ma. Qatadah dan tidak hanya seorang ahli ilmu membicarakannya.'"},"2506":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ بُدَيْلِ بْنِ قُرَيْشٍ الْيَامِيُّ الْكُوفِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُمَارَةَ بْنِ زَاذَانَ عَنْ عَلِيِّ بْنِ الْحَكَمِ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سُئِلَ عَنْ عِلْمٍ عَلِمَهُ ثُمَّ كَتَمَهُ أُلْجِمَ يَوْمَ الْقِيَامَةِ بِلِجَامٍ مِنْ نَارٍوَفِي الْبَاب عَنْ جَابِرٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Ahmad bin Budail bin Quraisy al Yamiyyu al Kufi] telah menceritakan kepada kami [Abdullah bin Numair] dari [Umarah bin Zadzan] dari [Ali bin al Hakam] dari ['Atha'] dari [Abu Hurairah] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ditanya tentang suatu ilmu yang dia ketahui kemudian dia menyembunyikannya, maka dia akan dicambuk pada hari kiamat dengan cambuk dari neraka.\" Dan pada bab tersebut juga diriwayatkan dari Jabir dan Abdullah bin 'Amru, Abu Isa berkata; 'Hadits Abu Hurairah adalah hadits hasan.'"},"2507":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ سُفْيَانَ عَنْ أَبِي هَارُونَ الْعَبْدِيِّ قَالَكُنَّا نَأْتِي أَبَا سَعِيدٍ فَيَقُولُ مَرْحَبًا بِوَصِيَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ النَّاسَ لَكُمْ تَبَعٌ وَإِنَّ رِجَالًا يَأْتُونَكُمْ مِنْ أَقْطَارِ الْأَرَضِينَ يَتَفَقَّهُونَ فِي الدِّينِ فَإِذَا أَتَوْكُمْ فَاسْتَوْصُوا بِهِمْ خَيْرًاقَالَ أَبُو عِيسَى قَالَ عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ يَحْيَى بْنُ سَعِيدٍ كَانَ شُعْبَةُ يُضَعِّفُ أَبَا هَارُونَ الْعَبْدِيَّ قَالَ يَحْيَى بْنُ سَعِيدٍ مَا زَالَ ابْنُ عَوْنٍ يَرْوِي عَنْ أَبِي هَارُونَ الْعَبْدِيِّ حَتَّى مَاتَ وَأَبُو هَارُونَ اسْمُهُ عُمَارَةُ بْنُ جُوَيْنٍ","id":"Telah bercerita kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [Abu Daud Al Hafari] dari [Sufyan] dari [Abu Harun Al 'Abdi] dia berkata; Kami datang kepada [Abu Sa'id] dan dia menyambut dengan mengatakan; Selamat datang kepada wasiat Rasulullah shallallahu 'alaihi wasallam, sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang-orang mengikuti kalian, dan sesungguhnya orang-orang datang kepada kalian dari penjuru dunia untuk belajar agama, maka jika mereka datang kepada kalian wasiatkanlah kepada mereka kebaikan\". Abu Isa berkata, Ali bin Abdullah berkata, Yahya bin Sa'id berkata; 'Syu'bah melemahkan Abu Harun Al 'Abdi, ' Yahya bin Sa'id berkata; 'Ibnu Aun masih terus menerus meriwayat dari Abu Harun Al 'Abdi sampai dia wafat. Adapun nama Abu Harun adalah Umarah bin Juwain.'"},"2508":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا نُوحُ بْنُ قَيْسٍ عَنْ أَبِي هَارُونَ الْعَبْدِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَأْتِيكُمْ رِجَالٌ مِنْ قِبَلِ الْمَشْرِقِ يَتَعَلَّمُونَ فَإِذَا جَاءُوكُمْ فَاسْتَوْصُوا بِهِمْ خَيْرًاقَالَ فَكَانَ أَبُو سَعِيدٍ إِذَا رَآنَا قَالَ مَرْحَبًا بِوَصِيَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَذَا حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ أَبِي هَارُونَ عَنْ أَبِي سَعِيدٍ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Nuh bin Qais] dari [Abu Harun al 'Abdi] dari [Abu Sa'id al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Akan datang kepada kalian dari arah timur (bertujuan untuk) belajar, maka apabila mereka mendatangi kalian, maka berwasiatlah kepada mereka dengan kebaikan.\" Perawi berkata; Abu Sa'id apabila melihat kami, maka dia berkata; 'Selamat datang dengan wasiat Rasulullah shallallahu 'alaihi wasallam'. Dia berkata, 'Hadits ini kami tidak mengetahuinya kecuali dari hadits Abu Harun dari Abu Sa'id.'"},"2509":{"ar":"حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ الْهَمْدَانِيُّ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَا يَقْبِضُ الْعِلْمَ انْتِزَاعًا يَنْتَزِعُهُ مِنْ النَّاسِ وَلَكِنْ يَقْبِضُ الْعِلْمَ بِقَبْضِ الْعُلَمَاءِ حَتَّى إِذَا لَمْ يَتْرُكْ عَالِمًا اتَّخَذَ النَّاسُ رُءُوسًا جُهَّالًا فَسُئِلُوا فَأَفْتَوْا بِغَيْرِ عِلْمٍ فَضَلُّوا وَأَضَلُّواوَفِي الْبَاب عَنْ عَائِشَةَ وَزِيَادِ بْنِ لَبِيدٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى هَذَا الْحَدِيثَ الزُّهْرِيُّ عَنْ عُرْوَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ هَذَا","id":"Telah menceritakan kepada kami [Harun bin Ishaq al Hamdani] telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Abdullah bin 'Amru bin al 'Ash] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah tidak mencabut ilmu dengan cara mencabutnya langsung dari manusia, akan tetapi Dia mencabut ilmu dengan mewafatkan para ulama, hingga ketika Dia tidak meninggalkan seorang alim (di muka bumi) maka manusia menjadikan orang-orang jahil sebagai pemimpin, lalu mereka ditanya, maka mereka memberikan fatwa tanpa ilmu, mereka sesat dan menyesatkan.\" Dan pada bab tersebut juga diriwayatkan dari Aisyah dan Ziyad bin Labid. Abu Isa berkata; 'Ini adalah hadits hasan shahih. Dan [az Zuhri] telah meriwayatkan hadits ini dari [Urwah] dari [Abdullah bin 'Amru] dan dari [Urwah] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam hadits semisal ini."},"2510":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي الدَّرْدَاءِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَخَصَ بِبَصَرِهِ إِلَى السَّمَاءِ ثُمَّ قَالَ هَذَا أَوَانُ يُخْتَلَسُ الْعِلْمُ مِنْ النَّاسِ حَتَّى لَا يَقْدِرُوا مِنْهُ عَلَى شَيْءٍفَقَالَ زِيَادُ بْنُ لَبِيدٍ الْأَنْصَارِيُّ كَيْفَ يُخْتَلَسُ مِنَّا وَقَدْ قَرَأْنَا الْقُرْآنَ فَوَاللَّهِ لَنَقْرَأَنَّهُ وَلَنُقْرِئَنَّهُ نِسَاءَنَا وَأَبْنَاءَنَا فَقَالَ ثَكِلَتْكَ أُمُّكَ يَا زِيَادُ إِنْ كُنْتُ لَأَعُدُّكَ مِنْ فُقَهَاءِ أَهْلِ الْمَدِينَةِ هَذِهِ التَّوْرَاةُ وَالْإِنْجِيلُ عِنْدَ الْيَهُودِ وَالنَّصَارَى فَمَاذَا تُغْنِي عَنْهُمْ قَالَ جُبَيْرٌ فَلَقِيتُ عُبَادَةَ بْنَ الصَّامِتِ قُلْتُ أَلَا تَسْمَعُ إِلَى مَا يَقُولُ أَخُوكَ أَبُو الدَّرْدَاءِ فَأَخْبَرْتُهُ بِالَّذِي قَالَ أَبُو الدَّرْدَاءِ قَالَ صَدَقَ أَبُو الدَّرْدَاءِ إِنْ شِئْتَ لَأُحَدِّثَنَّكَ بِأَوَّلِ عِلْمٍ يُرْفَعُ مِنْ النَّاسِ الْخُشُوعُ يُوشِكُ أَنْ تَدْخُلَ مَسْجِدَ جَمَاعَةٍ فَلَا تَرَى فِيهِ رَجُلًا خَاشِعًا قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَمُعَاوِيَةُ بْنُ صَالِحٍ ثِقَةٌ عِنْدَ أَهْلِ الْحَدِيثِ وَلَا نَعْلَمُ أَحَدًا تَكَلَّمَ فِيهِ غَيْرَ يَحْيَى بْنِ سَعِيدٍ الْقَطَّانِ وَقَدْ رُوِيَ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ نَحْوُ هَذَا وَرَوَى بَعْضُهُمْ هَذَا الْحَدِيثَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ عَوْفِ بْنِ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah bercerita kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Abdurrahman bin Jubair bin Nufair] dari [bapaknya, Jubair bin Nufair] dari [Abu Ad Darda'] dia berkata; Ketika kami bersama Rasulullah shallallahu 'alaihi wasallam, beliau menengadahkan pandangannya ke langit kemudian berkata; \"Inilah saatnya ilmu dicabut dari manusia sehingga mereka tidak mampu mengetahui darinya sama sekali\", maka Ziyad bin Labid Al Anshari bertanya; 'Bagaimana ilmu dicabut dari kami, padahal kami membaca Al Qur'an? Demi Allah, kami pasti akan membacanya dan membacakannya kepada istri-istri dan anak-anak kami.' Maka beliau berkata: \"alangkah malangnya dirimu wahai Ziyad, sesungguhnya aku menganggapmu termasuk orang yang faqih di Madinah, inilah kitab Taurat dan Injil milik Yahudi dan Nashrani maka apakah bermanfaat bagi mereka?\" Jubair berkata; Kemudian aku bertemu dengan [Ubadah bin Ash Shamith], maka aku bertanya; 'Tidakkah kamu mendengar sesuatu yang dikatakan saudaramu yaitu Abu Ad Darda'? ' Maka aku memberitahukan kepadanya apa yang dikatakan oleh Abu Ad Darda'. Dia berkata; 'Abu Ad Darda' benar, jika kamu berkehendak sungguh pasti aku ceritakan kepadamu tentang ilmu yang pertama kali akan diangkat dari manusia yaitu Al Khusyu' (rasa khusyu') hampir-hampir kamu masuk ke dalam masjid jami' namun kamu tidak melihat seorang pun di dalamnya orang yang khusyu'.' Abu Isa berkata; 'Hadits ini hasan gharib. Mu'awiyah bin Shalih adalah seorang yang tsiqah menurut para ahli hadits, dan kami tidak mengetahui ada seorang pun yang berbicara tentang dia kecuali Yahya bin Sa'id Al Qaththan, dan telah diriwayatkan dari Mu'awiyah bin Shalih hadits yang semakna dengan ini, sedangkan sebagian perawi yang lain telah meriwayatkan hadits ini dari Abdurrahman bin Jubair bin Nufair dari bapaknya dari Auf bin Malik dari Nabi shallallahu 'alaihi wasallam.\""},"2511":{"ar":"حَدَّثَنَا أَبُو الْأَشْعَثِ أَحْمَدُ بْنُ الْمِقْدَامِ الْعِجْلِيُّ الْبَصْرِيُّ حَدَّثَنَا أُمَيَّةُ بْنُ خَالِدٍ حَدَّثَنَا إِسْحَقُ بْنُ يَحْيَى بْنِ طَلْحَةَ حَدَّثَنِي ابْنُ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ طَلَبَ الْعِلْمَ لِيُجَارِيَ بِهِ الْعُلَمَاءَ أَوْ لِيُمَارِيَ بِهِ السُّفَهَاءَ أَوْ يَصْرِفَ بِهِ وُجُوهَ النَّاسِ إِلَيْهِ أَدْخَلَهُ اللَّهُ النَّارَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَإِسْحَقُ بْنُ يَحْيَى بْنِ طَلْحَةَ لَيْسَ بِذَاكَ الْقَوِيِّ عِنْدَهُمْ تُكُلِّمَ فِيهِ مِنْ قِبَلِ حِفْظِهِ","id":"Telah menceritakan kepada kami [Abu al Asy'ats Ahmad bin al Miqdam Al 'Ijli Al Bashri] telah menceritakan kepada kami [Umayyah bin Khalid] telah menceritakan kepada kami [Ishaq bin Yahya bin Thalhah] telah bercerita kepada kami [Ibnu Ka'b bin Malik] dari [bapaknya] dia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menuntut ilmu untuk mendebat para ulama, atau untuk mengolok-olok orang bodoh atau untuk mengalihkan pandangan manusia kepadanya, niscaya Allah akan memasukkannya ke dalam neraka\". Abu Isa berkata; 'Hadits ini gharib, kami tidak mengetahuinya kecuali dari jalur sanad ini. Ishaq bin Yahya bin Thalhah derajatnya bukan kuat menurut mereka, dan dia dibicarakan dari segi hafalannya.'"},"2512":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ نَصْرِ بْنِ عَلِيٍّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ الْهُنَائِيُّ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ أَيُّوبَ السَّخْتِيَانِيِّ عَنْ خَالِدِ بْنِ دُرَيْكٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَعَلَّمَ عِلْمًا لِغَيْرِ اللَّهِ أَوْ أَرَادَ بِهِ غَيْرَ اللَّهِ فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِوَفِي الْبَاب عَنْ جَابِرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ أَيُّوبَ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Ali bin Nashr bin Ali] telah menceritakan kepada kami [Muhammad bin 'Abbad Al Huna'i] telah menceritakan kepada kami [Ali bin Al Mubarak] dari [Ayyub as Sakhtiyani] dari [Khalid bin Duraik] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa belajar Ilmu untuk selain Allah atau menginginkan selain Allah, maka hendaklah dia menempati tempat duduknya (kelak) di neraka\". Dan dalam hadits bab ini juga diriwayatkan dari Jabir. Abu Isa berkata; 'Hadits ini hasan gharib, kami tidak mengetahuinya dari hadits Ayyub kecuali dari jalur sanad ini.'"},"2513":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَخْبَرَنَا شُعْبَةُ أَخْبَرَنَا عُمَرُ بْنُ سُلَيْمَانَ مِنْ وَلَدِ عُمَرَ بْنِ الْخَطَّابِ قَال سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ أَبَانَ بْنِ عُثْمَانَ يُحَدِّثُ عَنْ أَبِيهِ قَالَخَرَجَ زَيْدُ بْنُ ثَابِتٍ مِنْ عِنْدِ مَرْوَانَ نِصْفَ النَّهَارِ قُلْنَا مَا بَعَثَ إِلَيْهِ فِي هَذِهِ السَّاعَةِ إِلَّا لِشَيْءٍ سَأَلَهُ عَنْهُ فَسَأَلْنَاهُ فَقَالَ نَعَمْ سَأَلَنَا عَنْ أَشْيَاءَ سَمِعْنَاهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ نَضَّرَ اللَّهُ امْرَأً سَمِعَ مِنَّا حَدِيثًا فَحَفِظَهُ حَتَّى يُبَلِّغَهُ غَيْرَهُ فَرُبَّ حَامِلِ فِقْهٍ إِلَى مَنْ هُوَ أَفْقَهُ مِنْهُ وَرُبَّ حَامِلِ فِقْهٍ لَيْسَ بِفَقِيهٍوَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَمُعَاذِ بْنِ جَبَلٍ وَجُبَيْرِ بْنِ مُطْعِمٍ وَأَبِي الدَّرْدَاءِ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ زَيْدِ بْنِ ثَابِتٍ حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah mengabarkan kepada kami [Syu'bah] telah mengabarkan kepada kami [Umar bin Sulaiman] dari kalangan anak-anak Umar bin al Khaththab, dia berkata; Saya mendengar [Abdurrahman bin Aban bin Utsman] menyampaikan hadits dari [bapaknya], dia berkata; [Zaid bin Tsabit] keluar dari sisi Marwan di pertengahan hari, maka kami berkata; 'tidaklah dia diutus di waktu seperti ini kecuali karena satu urusan yang akan di tanyakan kepadanya, ' maka kamipun bertanya kepadanya, dia menjawab; 'ya, dia bertanya kepada kami tentang perkara-perkara yang kami dengan dari Rasulullah shallallahu 'alaihi wasallam, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah akan memperindah seseorang yang mendengar hadits dari kami, dia menghafalnya sehingga dia menyampaikannya kepada yang lainnya, bisa jadi orang yang mengusung fiqih menyampaikan kepada orang yang lebih faqih darinya, dan bisa jadi orang yang mengusung fiqih tidak termasuk orang yang faqih.\" Dan pada bab lain, dari Abdullah bin Mas'ud, Muadz bin Jabal, Jubair bin Muth'im, Abu ad-Darda', dan Anas. Abu Isa berkata; 'Hadits Zaid bin Tsabit adalah hadits hasan."},"2514":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَنْبَأَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ قَال سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ يُحَدِّثُ عَنْ أَبِيهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ نَضَّرَ اللَّهُ امْرَأً سَمِعَ مِنَّا شَيْئًا فَبَلَّغَهُ كَمَا سَمِعَ فَرُبَّ مُبَلِّغٍ أَوْعَى مِنْ سَامِعٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ","id":"[Mahmud bin Ghoilan] telah bercerita kepada kami, bahwa [Abu Daud] telah bercerita kepada kami, bahwa [Syu'bah] telah memberitakan kepada kami dari [Simak bin Harb] dia berkata; aku mendengar [Abdurrahman bin Abdullah bin Mas'ud] bercerita dari [bapaknya] dia berkata; aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Allah akan memperindah seseorang yang mendengar sesuatu dariku kemudian dia sampaikan sebagaimana dia mendengarnya, maka bisa jadi orang yang menyampaikan lebih faqih dari yang mendengar\". Abu Isa berkata; 'hadits ini hasan shahih, [Abdul Malik bin Umair] telah meriwayatkannya dari [Abdurrahman bin Abdullah].'"},"2515":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ يُحَدِّثُ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَضَّرَ اللَّهُ امْرَأً سَمِعَ مَقَالَتِي فَوَعَاهَا وَحَفِظَهَا وَبَلَّغَهَا فَرُبَّ حَامِلِ فِقْهٍ إِلَى مَنْ هُوَ أَفْقَهُ مِنْهُ ثَلَاثٌ لَا يُغِلُّ عَلَيْهِنَّ قَلْبُ مُسْلِمٍ إِخْلَاصُ الْعَمَلِ لِلَّهِ وَمُنَاصَحَةُ أَئِمَّةِ الْمُسْلِمِينَ وَلُزُومُ جَمَاعَتِهِمْ فَإِنَّ الدَّعْوَةَ تُحِيطُ مِنْ وَرَائِهِمْ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [sufyan] dari [Abdul Malik bin Umair] dari [Abdurrahman bin Abdullah bin Mas'ud] dia telah menyampaikan hadits dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah memperindah seseorang yang mendengar perkataanku, dia memahaminya, menghafalnya dan menyampaikannya, bisa jadi orang yang mengusung fiqih menyampaikan kepada orang yang lebih faqih darinya. Dan tiga perkara yang mana hati seorang muslim tidak akan dengki terhadapnya; mengikhlaskan amalan karena Allah, saling menasehati terhadap para pemimpin kaum muslimin, berpegang teguh terhadap jama'ah mereka, sesungguhnya da'wah meliputi dari belakang mereka.\""},"2516":{"ar":"حَدَّثَنَا أَبُو هِشَامٍ الرِّفَاعِيُّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ حَدَّثَنَا عَاصِمٌ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abu Hisyam ar Rifa'i] telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] telah menceritakan kepada kami [Hasyim] dari [Zirr] dari [Abdullah bin Mas'ud] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berbohong kepadaku dengan sengaja maka hendaklah mempersiapkan tempat duduknya di neraka.\""},"2517":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى الْفَزَارِيُّ ابْنُ بِنْتِ السُّدِّيِّ حَدَّثَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ عَنْ مَنْصُورِ بْنِ الْمُعْتَمِرِ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَكْذِبُوا عَلَيَّ فَإِنَّهُ مَنْ كَذَبَ عَلَيَّ يَلِجُ فِي النَّارِوَفِي الْبَاب عَنْ أَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ وَالزُّبَيْرِ وَسَعِيدِ بْنِ زَيْدٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَأَنَسٍ وَجَابِرٍ وَابْنِ عَبَّاسٍ وَأَبِي سَعِيدٍ وَعَمْرِو بْنِ عَبَسَةَ وَعُقْبَةَ بْنِ عَامِرٍ وَمُعَاوِيَةَ وَبُرَيْدَةَ وَأَبِي مُوسَى وَأَبِي أُمَامَةَ وَعَبْدِ اللَّهِ بْنِ عُمَرَ وَالْمُقَنَّعِ وَأَوْسٍ الثَّقَفِيِّ قَالَ أَبُو عِيسَى حَدِيثُ عَلِيٍّ حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ مَنْصُورُ بْنُ الْمُعْتَمِرِ أَثْبَتُ أَهْلِ الْكُوفَةِ و قَالَ وَكِيعٌ لَمْ يَكْذِبْ رِبْعِيُّ بْنُ حِرَاشٍ فِي الْإِسْلَامِ كَذْبَةً","id":"Telah menceritakan kepada kami [Ismail bin Musa al Fazari] cucu dari as Suddi, telah menceritakan kepada kami [Syarik bin Abdullah] dari [Manshur bin al Mu'tamar] dari [Rib'i bin Hirasy] dari [Ali bin Abi Thalib] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"janganlah kalian berdusta atas namaku, sesungguhnya barangsiapa yang berdusta atas namaku dia akan masuk kedalam neraka.\" dan dalam bab lain dari Abu Bakar, Umar, Utsman, az Zubair, Sa'id bin Zaid, Abdullah bin 'Amru, Anas, Jabir, Ibnu Abbas, Abu Sa'id, 'Amr bin 'ABasah, Uqbah bin 'Amir, Muawiyah, Buraidah, Abu Musa, Abu Umamah, Abdullah bin Umar, al Muqanna' dan Aus ats Tsaqafi. Abu Isa berkata; 'Hadits Ali adalah hadits hasan shahih.' Abdurrahman bin Mahdi berkata; 'Manshur bin Al Mu'tamir adalah ahlul Kufah yang paling tsiqah.' Waki' berkata; 'Rib'I bin Hirasy tidak pernah berdusta sekalipun di dalam Islam.'"},"2518":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَذَبَ عَلَيَّ حَسِبْتُ أَنَّهُ قَالَ مُتَعَمِّدًا فَلْيَتَبَوَّأْ بَيْتَهُ مِنْ النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ الزُّهْرِيِّ عَنْ أَنَسٍ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits bin Sa'id] dari [Ibnu Syihab] dari [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berbohong atas namaku -aku mengira dia mengatakan; - dengan sengaja, maka hendaknya dia mempersiapkan tempat tinggalnya di dalam neraka.\" Abu Isa berkata; 'Ini hadits hasan shahih gharib dari sisi ini dari hadits az Zuhri dari Anas, dan hadits ini telah diriwayatkan dari sisi yang lain dari Anas dari Nabi shallallahu 'alaihi wasallam.'"},"2519":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مَيْمُونِ بْنِ أَبِي شَبِيبٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَدَّثَ عَنِّي حَدِيثًا وَهُوَ يَرَى أَنَّهُ كَذِبٌ فَهُوَ أَحَدُ الْكَاذِبِينَوَفِي الْبَاب عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ وَسَمُرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى شُعْبَةُ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ سَمُرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا الْحَدِيثَ وَرَوَى الْأَعْمَشُ وَابْنُ أَبِي لَيْلَى عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَأَنَّ حَدِيثَ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ سَمُرَةَ عِنْدَ أَهْلِ الْحَدِيثِ أَصَحُّ قَالَ سَأَلْتُ أَبَا مُحَمَّدٍ عَبْدَ اللَّهِ بْنَ عَبْدِ الرَّحْمَنِ عَنْ حَدِيثِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَدَّثَ عَنِّي حَدِيثًا وَهُوَ يَرَى أَنَّهُ كَذِبٌ فَهُوَ أَحَدُ الْكَاذِبِينَ قُلْتُ لَهُ مَنْ رَوَى حَدِيثًا وَهُوَ يَعْلَمُ أَنَّ إِسْنَادَهُ خَطَأٌ أَيُخَافُ أَنْ يَكُونَ قَدْ دَخَلَ فِي حَدِيثِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ إِذَا رَوَى النَّاسُ حَدِيثًا مُرْسَلًا فَأَسْنَدَهُ بَعْضُهُمْ أَوْ قَلَبَ إِسْنَادَهُ يَكُونُ قَدْ دَخَلَ فِي هَذَا الْحَدِيثِ فَقَالَ لَا إِنَّمَا مَعْنَى هَذَا الْحَدِيثِ إِذَا رَوَى الرَّجُلُ حَدِيثًا وَلَا يُعْرَفُ لِذَلِكَ الْحَدِيثِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصْلٌ فَحَدَّثَ بِهِ فَأَخَافُ أَنْ يَكُونَ قَدْ دَخَلَ فِي هَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Habib bin Abi Tsabit] dari [Maimun bin Abi Syabib] dari [al Mughirah bin Syu'bah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa meriwayatkan satu hadits dariku, dan dia melihat bahwa hadits itu dusta, maka dia adalah salah satu dari para pendusta.\" dan dalam bab lain dari Ali bin Abi Thalib dan Samurah. Abu Isa berkata; 'Ini adalah hadits hasan shahih. dan [Syu'bah] telah meriwayatkan dari [Al Hakam] dari [Abdurrahman bin Abi Laila] dari [Samurah] dari Nabi shallallahu 'alaihi wasallam. Hadits ini di riwayatkan oleh [al A'masy] dan [Ibnu Abi Laila] dari [al Hakam] dari [Abdurrahman bin Abu Laila] dari [Ali] dari Nabi shallallahu 'alaihi wasallam. Dan seakan-akan hadits Abdurrahman bin Abi Laila dari Samurah menurut ahlul hadits lebih absah. Abu Isa berkata; aku bertanya kepada Abu Muhammad Abdullah bin Abdurrahman tentang hadits Nabi shallallahu 'alaihi wasallam; \"Barangsiapa meriwayatkan satu hadits dariku, dan dia melihat bahwa hadits itu dusta, maka dia adalah salah satu dari para pendusta.\" Aku berkata kepadanya; 'jika seserang meriwayatkan satu hadits sedang dia mengetahui bahwa isnadnya salah, maka apakah di khawatirkan dia termasuk kategori hadits Nabi ini, atau jika orang-orang meriwayatkan satu hadits mursal, kemudian sebagian mereka menyambungkannya atau membalik isnadnya, apakah dia termasuk kategori hadits ini? ' dia menjawab; 'tidak, hanyasanya makna hadits ini adalah jika seseorang meriwayatkan satu hadits, dan dia tidak mengetahui sama sekali kedudukan hadits tersebut dari Nabi shallallahu 'alaihi wasallam, kemudian dia meriwayatkannya, maka aku khawatir dia termasuk kategori hadits ini.'"},"2520":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ وَسَالِمٍ أَبِي النَّضْرِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ أَبِي رَافِعٍ وَغَيْرِهِ رَفَعَهُقَالَ لَا أُلْفِيَنَّ أَحَدَكُمْ مُتَّكِئًا عَلَى أَرِيكَتِهِ يَأْتِيهِ أَمْرٌ مِمَّا أَمَرْتُ بِهِ أَوْ نَهَيْتُ عَنْهُ فَيَقُولُ لَا أَدْرِي مَا وَجَدْنَا فِي كِتَابِ اللَّهِ اتَّبَعْنَاهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى بَعْضُهُمْ عَنْ سُفْيَانَ عَنْ ابْنِ الْمُنْكَدِرِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا وَسَالِمٍ أَبِي النَّضْرِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ ابْنُ عُيَيْنَةَ إِذَا رَوَى هَذَا الْحَدِيثَ عَلَى الِانْفِرَادِ بَيَّنَ حَدِيثَ مُحَمَّدِ بْنِ الْمُنْكَدِرِ مِنْ حَدِيثِ سَالِمٍ أَبِي النَّضْرِ وَإِذَا جَمَعَهُمَا رَوَى هَكَذَا وَأَبُو رَافِعٍ مَوْلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْمُهُ أَسْلَمُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Muhammad bin al Munkadir] dan [Salim Abi an Nadhar] dari [Ubaidullah bin Abi Rafi'] dari [Abu Rafi'] dan yang lainnya, dan dia memarfu'kannya, beliau bersabda: \"sungguh aku akan mendapati salah seorang dari kalian yang bersandaran ke peraduannya, kemudian datang kepadanya salah satu perkara yang telah aku perintahkan atau yang telah aku larang, maka dia berkata; 'aku tidak tahu, apa yang aku dapati di dalam kitabullah maka kami akan mengikutinya.\" Abu Isa berkata; 'ini hadits hasan shahih.\" Dan sebagian mereka meriwayatkan dari Sufyan dari Ibnu al Munkadir dari Nabi shallallahu 'alaihi wasallam secara mursal, dan Salim Abi an Nadhar dari Ubaidullah bin Abi Rafi' dari bapaknya dari Nabi shallallahu 'alaihi wasallam. Dan Ibnu 'Uyainah apabila dia meriwayatkan hadits ini dengan hanya satu jalur, dia menerangkan hadits Muhammad bin Al Munkadir dari hadits Salim Abi Nadhr. Dan apabila menggabungkan keduanya dia meriwayatkan seperti ini. Dan Abu Rafi' adalah mantan budak Nabi shallallahu 'alaihi wasallam, namanya Aslam."},"2521":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ الْحَسَنِ بْنِ جَابِرٍ اللَّخْمِيِّ عَنْ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا هَلْ عَسَى رَجُلٌ يَبْلُغُهُ الْحَدِيثُ عَنِّي وَهُوَ مُتَّكِئٌ عَلَى أَرِيكَتِهِ فَيَقُولُ بَيْنَنَا وَبَيْنَكُمْ كِتَابُ اللَّهِ فَمَا وَجَدْنَا فِيهِ حَلَالًا اسْتَحْلَلْنَاهُ وَمَا وَجَدْنَا فِيهِ حَرَامًا حَرَّمْنَاهُ وَإِنَّ مَا حَرَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا حَرَّمَ اللَّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Muawiyah bin Shalih] dari [al Hasan bin Jabir al Lakhmi] dari [al Miqdam bin Ma'di karib] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"ketahuilah, bisa jadi sampai sebuah hadits dariku kepada seseorang yang sedang bersandaran ke peraduannya, kemudian dia berkata; 'diantara kami dan kalian adalah kitabullah, maka perkara halal yang kita temukan di dalamnya kita halalkan, dan perkara haram yang kita temukan di dalamnya kita haramkan.' Dan sesungguhnya apa yang di haramkan Rasulullah shallallahu 'alaihi wasallam seperti apa yang di haramkan Allah.\" Abu Isa berkata; 'Ini hadits hasan gharib dari sisi ini.\""},"2522":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَاسْتَأْذَنَّا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْكِتَابَةِ فَلَمْ يَأْذَنْ لَنَاقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ هَذَا الْوَجْهِ أَيْضًا عَنْ زَيْدِ بْنِ أَسْلَمَ رَوَاهُ هَمَّامٌ عَنْ زَيْدِ بْنِ أَسْلَمَ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Zaid bin Aslam] dari ['Atha' bin Yasar] dari [Abu Sa'id al Khudzri] dia berkata; 'Kami meminta izin kepada Nabi dalam hal penulisan tetapi beliau tidak mengizinkan kami.' Abu Isa berkata; 'Dan hadits ini telah diriwayatkan tidak dari sisi ini saja, juga dari Zaid bin Aslam yang diriwayatkan oleh [Hammam] dari [Zaid bin Aslam]."},"2523":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ الْخَلِيلِ بْنِ مُرَّةَ عَنْ يَحْيَى بْنِ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَجُلٌ مِنْ الْأَنْصَارِ يَجْلِسُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَسْمَعُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَدِيثَ فَيُعْجِبُهُ وَلَا يَحْفَظُهُ فَشَكَا ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَسْمَعُ مِنْكَ الْحَدِيثَ فَيُعْجِبُنِي وَلَا أَحْفَظُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعِنْ بِيَمِينِكَ وَأَوْمَأَ بِيَدِهِ لِلْخَطِّوَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ إِسْنَادُهُ لَيْسَ بِذَلِكَ الْقَائِمِ و سَمِعْت مُحَمَّدَ بْنَ إِسْمَعِيلَ يَقُولُ الْخَلِيلُ بْنُ مُرَّةَ مُنْكَرُ الْحَدِيثِ","id":"[Qutaibah] telah bercerita kepada kami bahwa [Al Laits] telah bercerita kepada kami dari [Al Khalil bin Murrah] dari [Yahya bin Abu Shalih] dari [Abu Hurairah] dia berkata; ada seorang lelaki dari kaum Anshar yang duduk ke hadapan Nabi shallallahu 'alaihi wasallam, lalu mendengarkan hadits dari Nabi shallallahu 'alaihi wasallam dan dia terkagum-kagum, tetapi dia tidak dapat menghafalnya, maka dia mengadu kepada Nabi shallallahu 'alaihi wasallam dan berkata; \"wahai Rasulullah sesungguhnya aku mendengar hadits darimu dan hadits tersebut membuat aku terkagum-kagum, akan tetapi aku tidak dapat menghafalnya, ' maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"gunakanlah bantuan dengan tangan kananmu.\" sambil beliau mengisyaratkan menulis dengan tangannya. Dan dalam bab ini ada hadits dari Abdullah bin Amru. Abu Isa berkata; 'hadits ini isnadnya tidak sedemikian kuat, dan aku mendengar Muhammad bin Isma'il berkata, \"Al Khalil bin Murrah adalah munkarul hadits (hadits haditsnya munkar).'"},"2524":{"ar":"حَدَّثَنَا يَحْيَى بْن�� مُوسَى وَمَحْمُودُ بْنُ غَيْلَانَ قَالَا حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ فَذَكَرَ الْقِصَّةَ فِي الْحَدِيثِ قَالَ أَبُو شَاهٍ اكْتُبُوا لِي يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اكْتُبُوا لِأَبِي شَاهٍ وَفِي الْحَدِيثِ قِصَّةٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى شَيْبَانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ مِثْلَ هَذَا","id":"Telah menceritakan kepada kami [Yahya bin Musa] dan [Mahmud bin Ghailan] keduanya berkata; telah menceritakan kepada kami [al Walid bin Muslim] telah menceritakan kepada kami [al Auza'i] dari [Yahya bin Abi Katsir] dari [Abu Salamah] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam berkhuthbah, lalu menyebutkan suatu kisah dalam hadits, maka Abu Syah berkata; '(suruhlah mereka agar) menuliskan untukku wahai Rasulullah'. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian tuliskanlah untuk Abu Syah.\" Dan dalam hadits tersebut terdapat suatu kisah. Abu Isa berkata; 'Ini hadits hasan shahih, [Syaiban] telah meriwayatkan dari [Yahya bin Abi Katsir] seperti hadits ini.'"},"2525":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ وَهْبِ بْنِ مُنَبِّهٍ عَنْ أَخِيهِ وَهُوَ هَمَّامُ بْنُ مُنَبِّهٍ قَال سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُلَيْسَ أَحَدٌ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرَ حَدِيثًا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنِّي إِلَّا عَبْدَ اللَّهِ بْنَ عَمْرٍو فَإِنَّهُ كَانَ يَكْتُبُ وَكُنْتُ لَا أَكْتُبُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَوَهْبُ بْنُ مُنَبِّهٍ عَنْ أَخِيهِ هُوَ هَمَّامُ بْنُ مُنَبِّهٍ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] dari [Wahab bin Munabbih] dari [saudaranya, yaitu Hammam bin Munabbih] dia berkata, aku mendengar [Abu Hurairah] berkata; Tidak ada seorang pun sahabat Rasulullah shallallahu 'alaihi wasallam yang lebih banyak hafalan haditsnya dari Rasulullah shallallahu 'alaihi wasallam daripada aku, kecuali Abdullah bin Amru, karena dia dahulu menulis, sedangkan aku tidak menulis.\" Abu Isa berkata; 'Ini hadits hasan shahih, dan Wahab bin Munabbih dari saudaranya, yaitu Hammam bin Munabbih.\""},"2526":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ ابْنِ ثَوْبَانَ هُوَ عَبْدُ الرَّحْمَنِ بْنُ ثَابِتِ بْنِ ثَوْبَانَ عَنْ حَسَّانَ بْنِ عَطِيَّةَ عَنْ أَبِي كَبْشَةَ السَّلُولِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلِّغُوا عَنِّي وَلَوْ آيَةً وَحَدِّثُوا عَنْ بَنِي إِسْرَائِيلَ وَلَا حَرَجَ وَمَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ عَنْ أَبِي كَبْشَةَ السَّلُولِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَهَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Ibnu Tsauban], yaitu Abdurrahman bin Tsabit bin Tsauban, dari [Hassan bin Athiyyah] dari [Abu Kabsyah as Saluli] dari [Abdullah bin Amru] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sampaikanlah dariku walaupun hanya satu ayat, dan ceritakanlah dari bani Israil, dan tidak ada dosa, barangsiapa berdusta atas namaku secara sengaja, maka hendaklah dia menempati tempat duduknya dari neraka.\" Abu Isa berkata; 'Ini hadits hasan shahih.' Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Ashim] dari [al Auza'i] dari [Hassan bin Athiyyah] dari [Abu Kabsyah as Saluli] dari [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam semisalnya, dan ini hadits shahih."},"2527":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَبْدِ الرَّحْمَنِ الْكُوفِيُّ حَدَّثَنَا أَحْمَدُ بْنُ بَشِيرٍ عَنْ شَبِيبِ بْنِ بِشْرٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ يَسْتَحْمِلُهُ فَلَمْ يَجِدْ عِنْدَهُ مَا يَتَحَمَّلُهُ فَدَلَّهُ عَلَى آخَرَ فَحَمَلَهُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ فَقَالَ إِنَّ الدَّالَّ عَلَى الْخَيْرِ كَفَاعِلِهِوَفِي الْبَاب عَنْ أَبِي مَسْعُودٍ الْبَدْرِيِّ وَبُرَيْدَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"[Nashr bin Abdurrahman Al Kufi] telah bercerita kepada kami bahwa [Ahmad bin Basyir] telah bercerita kepada kami dari [Syabib bin Bisyr] dari [Anas bin Malik] dia berkata; seorang lelaki datang kepada Nabi shallallahu 'alaihi wasallam meminta kendaraan namun dia tidak mendapatkan dari beliau kendaraan yang dapat membawanya, dan beliau menunjukkan kepada yang lain dan dapat memberinya kendaraan, lalu dia datang kepada Nabi shallallahu 'alaihi wasallam dan menceritakannya maka Nabi bersabda: \"sesungguhnya orang yang menunjukkan kepada kebaikan sama seperti orang yang melakukannya\". Dan dalam bab ini ada hadits dari Abu Mas'ud Al Badri dan Buraidah. Abu Isa berkata; 'hadits ini gharib dari jalur sanad ini dari hadits Anas dari Nabi shallallahu 'alaihi wasallam\"."},"2528":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَنْبَأَنَا شُعْبَةُ عَنْ الْأَعْمَشِ قَال سَمِعْتُ أَبَا عَمْرٍو الشَّيْبَانِيَّ يُحَدِّثُ عَنْ أَبِي مَسْعُودٍ الْبَدْرِيِّأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَحْمِلُهُ فَقَالَ إِنَّهُ قَدْ أُبْدِعَ بِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ائْتِ فُلَانًا فَأَتَاهُ فَحَمَلَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ دَلَّ عَلَى خَيْرٍ فَلَهُ مِثْلُ أَجْرِ فَاعِلِهِ أَوْ قَالَ عَامِلِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو عَمْرٍو الشَّيْبَانِيُّ اسْمُهُ سَعْدُ بْنُ إِيَاسٍ وَأَبُو مَسْعُودٍ الْبَدْرِيُّ اسْمُهُ عُقْبَةُ بْنُ عَمْرٍو حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ أَبِي مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَقَالَ مِثْلُ أَجْرِ فَاعِلِهِ وَلَمْ يَشُكَّ فِيهِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah memberitakan kepada kami [Syu'bah] dari [al A'masy] dia berkata, aku mendengar [Abu Amru asy Syaibani] menceritakan dari [Abu Mas'ud al Badri]; bahwa seorang laki-laki mendatangi Nabi shallallahu 'alaihi wasallam meminta kendaraan dari beliau (untuk mengangkut), seraya dia berkata; 'Sesungguhnya perjalananku terhenti (karena kendaraanku mati) '. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Datanglah kepada fulan.\" Maka dia mendatanginya, lalu dia memberinya kendaraan, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menunjukkan pada kebaikan, maka dia mendapatkan seperti pahala pelakunya, atau orang yang mengerjakannya'.\" Abu Isa berkata; 'Ini hadits hasan shahih, dan nama Abu Amru asy Syaibani adalah Sa'ad bin 'Iyas, sedangkan nama Abu Mas'ud al Badri adalah Uqbah bin Amru. Telah menceritakan kepada kami [al Hasan bin Ali al Khallal] telah menceritakan kepada kami [Abdullah bin Numair] dari [al A'masy] dari [Abu Amru asy Syaibani] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam semisalnya, seraya berkata, \"Seperti pahala pelakunya.\" Dan dia tidak ragu sama sekali padanya."},"2529":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ وَالْحَسَنُ بْنُ عَلِيٍّ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ جَدِّهِ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اشْفَعُوا وَلْتُؤْجَرُوا وَلْيَقْضِ اللَّهُ عَلَى لِسَانِ نَبِيِّهِ مَا شَاءَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَبُرَيْدٌ يُكْنَى أَبَا بُرْدَةَ أَيْضًا هُوَ ابْنُ أَبِي مُوسَى الْأَشْعَرِيِّ وَهُوَ كُوفِيٌّ ثِقَةٌ فِي الْحَدِيثِ رَوَى عَنْهُ شُعْبَةُ وَالثَّوْرِيُّ وَابْنُ عُيَيْنَةَ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] dan [al Hasan bin Ali] serta tidak hanya satu perawi mereka berkata; telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah bin Abi Burdah] dari [kakeknya, Abu Burdah] dari [Abu Musa al Asy'ari] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Berilah pertolongan, dan agar kalian diberi pahala, dan sungguh Allah akan memenuhi kebutuhannya melalui lisan nabinya sesuatu yang dikehendakinya.\" Abu Isa berkata; 'Ini hadits hasan shahih. Dan Buraid diberi kunyah Abu Burdah juga, dia adalah Ibnu Abi Musa al Asy'ari, seorang kufi, tsiqah dalam hadits. Syu'bah dan ats Tsauri, serta Ibnu Uyainah meriwayatkan darinya.'"},"2530":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ وَعَبْدُ الرَّزَّاقِ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ نَفْسٍ تُقْتَلُ ظُلْمًا إِلَّا كَانَ عَلَى ابْنِ آدَمَ كِفْلٌ مِنْ دَمِهَا وَذَلِكَ لِأَنَّهُ أَوَّلُ مَنْ أَسَنَّ الْقَتْلَو قَالَ عَبْدُ الرَّزَّاقِ سَنَّ الْقَتْلَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ نَحْوَهُ بِمَعْنَاهُ قَالَ سَنَّ الْقَتْلَ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Waki'] dan [Abdurrazzaq] dari [Sufyan] dari [al A'masy] dari [Abdullah bin Murrah] dari [Masruq] dari [Abdullah bin Mas'ud] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah suatu jiwa terbunuh secara zhalim melainkan wajib bagi anak Adam untuk bertanggung jawab atas darahnya, karena dia adalah orang yang pertama kali mensunnahkan pembunuhan.\" Abdurrazzaq berkata; \"Mensunnahkan pembunuhan.\" Abu Isa berkata; 'Ini hadits hasan shahih, telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [al A'masy] dengan sanad seperti ini dengan makna yang sama, dia berkata, \"Mensunnahkan pembunuhan.\""},"2531":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ دَعَا إِلَى هُدًى كَانَ لَهُ مِنْ الْأَجْرِ مِثْلُ أُجُورِ مَنْ يَتَّبِعُهُ لَا يَنْقُصُ ذَلِكَ مِنْ أُجُورِهِمْ شَيْئًا وَمَنْ دَعَا إِلَى ضَلَالَةٍ كَانَ عَلَيْهِ مِنْ الْإِثْمِ مِثْلُ آثَامِ مَنْ يَتَّبِعُهُ لَا يَنْقُصُ ذَلِكَ مِنْ آثَامِهِمْ شَيْئًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah bercerita kepada kami [Ali bin Hujr] telah mengkhabarkan kepada kami [Isma'il bin Ja'far] dari [Al Ala' bin Abdurrahman] dari [bapaknya] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menyeru kepada petunjuk maka dia mendapatkan pahala seperti pahala orang yang mengikutinya tanpa mengurangi pahala mereka sedikit pun, dan barangsiapa yang menyeru kepada kesesatan maka dia mendapatkan dosa seperti dosa orang yang mengikutinya tanpa mengurangi dosa-dosa mereka sedikit pun\". Abu Isa berkata; 'Hadits ini hasan shahih\"."},"2532":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْمَسْعُودِيُّ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ ابْنِ جَرِيرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَنَّ سُنَّةَ خَيْرٍ فَاتُّبِعَ عَلَيْهَا فَلَهُ أَجْرُهُ وَمِثْلُ أُجُورِ مَنْ اتَّبَعَهُ غَيْرَ مَنْقُوصٍ مِنْ أُجُورِهِمْ شَيْئًا وَمَنْ سَنَّ سُنَّةَ شَرٍّ فَاتُّبِعَ عَلَيْهَا كَانَ عَلَيْهِ وِزْرُهُ وَمِثْلُ أَوْزَارِ مَنْ اتَّبَعَهُ غَيْرَ مَنْقُوصٍ مِنْ أَوْزَارِهِمْ شَيْئًاوَفِي الْبَاب عَنْ حُذَيْفَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوُ هَذَا وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ الْمُنْذِرِ بْنِ جَرِيرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ رُوِيَ عَنْ عُبَيْدِ اللَّهِ بْنِ جَرِيرٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْضًا","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [al Mas'udi] dari [Abdul Malik bin Umair] dari [Ibnu Jarir bin Abdullah] dari [bapaknya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mensunnahkan sunnah kebaikan, lalu dia diikuti atasnya, maka dia mendapatkan pahalanya dan seperti pahala orang yang mengikutinya tanpa mengurangi pahala mereka sedikit pun, dan barangsiapa mensunnahkan sunnah kejelekan, lalu dia diikuti atasnya, maka dia mendapatkan dosanya dan dosa orang yang mengikutinya tanpa mengurangi dosa mereka sedikit pun.\" Dan dalam hadits bab tersebut dari Hudzaifah. Abu Isa berkata; 'Ini hadits hasan shahih, dan telah diriwayatkan tidak hanya dari satu jalur saja, dari Jarir bin Abdullah dari Nabi shallallahu 'alaihi wasallam seperti hadits ini. Dan telah diriwayatkan hadits ini dari [al Mundzir bin Jarir bin Abdullah] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam, dan telah diriwayatkan dari Ubaidullah bin Jarir dari bapaknya dari Nabi shallallahu 'alaihi wasallam juga.\""},"2533":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَمْرٍو السُّلَمِيِّ عَنْ الْعِرْبَاضِ بْنِ سَارِيَةَ قَالَوَعَظَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا بَعْدَ صَلَاةِ الْغَدَاةِ مَوْعِظَةً بَلِيغَةً ذَرَفَتْ مِنْهَا الْعُيُونُ وَوَجِلَتْ مِنْهَا الْقُلُوبُ فَقَالَ رَجُلٌ إِنَّ هَذِهِ مَوْعِظَةُ مُوَدِّعٍ فَمَاذَا تَعْهَدُ إِلَيْنَا يَا رَسُولَ اللَّهِ قَالَ أُوصِيكُمْ بِتَقْوَى اللَّهِ وَالسَّمْعِ وَالطَّاعَةِ وَإِنْ عَبْدٌ حَبَشِيٌّ فَإِنَّهُ مَنْ يَعِشْ مِنْكُمْ يَرَى اخْتِلَافًا كَثِيرًا وَإِيَّاكُمْ وَمُحْدَثَاتِ الْأُمُورِ فَإِنَّهَا ضَلَالَةٌ فَمَنْ أَدْرَكَ ذَلِكَ مِنْكُمْ فَعَلَيْهِ بِسُنَّتِي وَسُنَّةِ الْخُلَفَاءِ الرَّاشِدِينَ الْمَهْدِيِّينَ عَضُّوا عَلَيْهَا بِالنَّوَاجِذِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى ثَوْرُ بْنُ يَزِيدَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَمْرٍو السُّلَمِيِّ عَنْ الْعِرْبَاضِ بْنِ سَارِيَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا حَدَّثَنَا بِذَلِكَ الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ثَوْرِ بْنِ يَزِيدَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَمْرٍو السُّلَمِيِّ عَنْ الْعِرْبَاضِ بْنِ سَارِيَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَالْعِرْبَاضُ بْنُ سَارِيَةَ يُكْنَى أَبَا نَجِيحٍ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ حُجْرِ بْنِ حُجْرٍ عَنْ عِرْبَاضِ بْنِ سَارِيَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah menceritakan kepada kami [Baqiyyah bin al Walid] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Abdurrahman bin Amru as Sulami] dari [al 'Irbadh bin Sariyah] dia berkata; suatu hari Rasulullah shallallahu 'alaihi wasallam memberi wejangan kepada kami setelah shalat subuh wejangan yang sangat menyentuh sehingga membuat air mata mengalir dan hati menjadi gemetar. Maka seorang sahabat berkata; 'seakan-akan ini merupakan wejangan perpisahan, lalu apa yang engkau wasiatkan kepada kami ya Rasulullah? ' Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku wasiatkan kepada kalian untuk (selalu) bertaqwa kepada Allah, mendengar dan ta'at meskipun terhadap seorang budak habasyi, sesungguhnya siapa saja diantara kalian yang hidup akan melihat perselisihan yang sangat banyak, maka jauhilah oleh kalian perkara-perkara yang dibuat-buat, karena sesungguhnya hal itu merupakan kesesatan. Barangsiapa diantara kalian yang menjumpai hal itu hendaknya dia berpegang teguh dengan sunnahku dan sunnah para Khulafaur Rasyidin yang mendapat petunjuk, gigitlah sunnah-sunnah itu dengan gigi geraham.\" Abu Isa berkata; hadits ini adalah hadits hasan shahih, [Tsaur bin Yazid] telah meriwayatkannya dari [Khalid bin Ma'dan] dari [Abdurrahman bin 'Amru as sulami] dari [Al 'Irbadh bin Sariyah] dari Nabi shallallahu 'alaihi wasallam, seperti hadits diatas ini. Dan telah menceritakan kepada kami seperti itu [Al Hasan bin Ali al Khallal] dan tidak tidak hanya satu orang saja, mereka berkata; telah menceritakan kepada kami [Abu 'Ashim] dari [Tsaur bin Yazid] dari [Khalid bin Ma'dan] dari [Abdurrahman bin 'Amru as sulami] dari [Al 'Irbadh bin Sariyah] dari Nabi shallallahu 'alaihi wasallam, seperti hadits diatas. Dan Al 'Irbadh bin Sariyah mempunyai kunyah Abu Najih. Dan telah diriwayatkan hadits ini dari [Hujr bin Hujr] dari ['Irbadh bin Sariyah] dari Nabi shallallahu 'alaihi wasallam seperti hadits diatas."},"2534":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ مَرْوَانَ بْنِ مُعَاوِيَةَ الْفَزَارِيِّ عَنْ كَثِيرِ بْنِ عَبْدِ اللَّهِ هُوَ ابْنُ عَمْرِو بْنِ عَوْفٍ الْمُزَنِيِّ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِبِلَالِ بْنِ الْحَارِثِ اعْلَمْ قَالَ مَا أَعْلَمُ يَا رَسُولَ اللَّهِ قَالَ اعْلَمْ يَا بِلَالُ قَالَ مَا أَعْلَمُ يَا رَسُولَ اللَّهِ قَالَ إِنَّهُ مَنْ أَحْيَا سُنَّةً مِنْ سُنَّتِي قَدْ أُمِيتَتْ بَعْدِي فَإِنَّ لَهُ مِنْ الْأَجْرِ مِثْلَ مَنْ عَمِلَ بِهَا مِنْ غَيْرِ أَنْ يَنْقُصَ مِنْ أُجُورِهِمْ شَيْئًا وَمَنْ ابْتَدَعَ بِدْعَةَ ضَلَالَةٍ لَا تُرْضِي اللَّهَ وَرَسُولَهُ كَانَ عَلَيْهِ مِثْلُ آثَامِ مَنْ عَمِلَ بِهَا لَا يَنْقُصُ ذَلِكَ مِنْ أَوْزَارِ النَّاسِ شَيْئًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَمُحَمَّدُ بْنُ عُيَيْنَةَ هُوَ مَصِّيصِيٌّ شَامِيٌّ وَكَثِيرُ بْنُ عَبْدِ اللَّهِ هُوَ ابْنُ عَمْرِو بْنِ عَوْفٍ الْمُزَنِيُّ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Muhammad bin 'Uyainah] dari [Marwan bin Mu'awiyah Al Fazari] dari [Katsir bin Abdullah] -dia adalah putra 'Amru bin Auf Al Muzani- dari [Ayahnya] dari [kakeknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada Bilal bin Al Harits: \"Ketahuilah!\" dia berkata; \"Apa yang saya harus kuketahui wahai Rasulullah?\" beliau menjawab: \"Ketahuilah wahai Bilal!\" dia bertanya lagi; \"Apa yang harus saya ketahui wahai Rasulullah?\" beliau menjawab: \"Barangsiapa menghidupkan salah satu sunnahku yang telah ditinggalkan sepeninggalku, maka ia akan mendapatkan pahala seperti pahala orang yang mengamalkannya tanpa mengurangi pahala mereka sedikitpun, dan barangsiapa membuat kebid'ahan Allah dan RasulNya tidak meridlainya, maka baginya dosa seperti dosa orang-orang yang mengikutinya tanpa mengurangi dosa-dosa mereka sedikitpun.\" Abu Isa berkata; Hadits ini hasan, Muhammad bin Uyainah adalah orang Mashish daerah Syam, Sedangkan Katsir bin Abdullah adalah Ibnu Amru bin 'Auf Al Muzani."},"2535":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ حَاتِمٍ الْأَنْصَارِيُّ الْبَصْرِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ قَالَ أَنَسُ بْنُ مَالِكٍقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بُنَيَّ إِنْ قَدَرْتَ أَنْ تُصْبِحَ وَتُمْسِيَ لَيْسَ فِي قَلْبِكَ غِشٌّ لِأَحَدٍ فَافْعَلْ ثُمَّ قَالَ لِي يَا بُنَيَّ وَذَلِكَ مِنْ سُنَّتِي وَمَنْ أَحْيَا سُنَّتِي فَقَدْ أَحَبَّنِي وَمَنْ أَحَبَّنِي كَانَ مَعِي فِي الْجَنَّةِوَفِي الْحَدِيثِ قِصَّةٌ طَوِيلَةٌ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ ثِقَةٌ وَأَبُوهُ ثِقَةٌ وَعَلِيُّ بْنُ زَيْدٍ صَدُوقٌ إِلَّا أَنَّهُ رُبَّمَا يَرْفَعُ الشَّيْءَ الَّذِي يُوقِفُهُ غَيْرُهُ قَالَ و سَمِعْت مُحَمَّدَ بْنَ بَشَّارٍ يَقُولُ قَالَ أَبُو الْوَلِيدِ قَالَ شُعْبَةُ حَدَّثَنَا عَلِيُّ بْنُ زَيْدٍ وَكَانَ رَفَّاعًا وَلَا نَعْرِفُ لِسَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَنَسٍ رِوَايَةً إِلَّا هَذَا الْحَدِيثَ بِطُولِهِ وَقَدْ رَوَى عَبَّادُ بْنُ مَيْسَرَةَ الْمِنْقَرِيُّ هَذَا الْحَدِيثَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَنَسٍ وَلَمْ يَذْكُرْ فِيهِ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ أَبُو عِيسَى وَذَاكَرْتُ بِهِ مُحَمَّدَ بْنَ إِسْمَعِيلَ فَلَمْ يَعْرِفْهُ وَلَمْ يُعْرَفْ لِسَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَنَسٍ هَذَا الْحَدِيثُ وَلَا غَيْرُهُ وَمَاتَ أَنَسُ بْنُ مَالِكٍ سَنَةَ ثَلَاثٍ وَتِسْعِينَ وَمَاتَ سَعِيدُ بْنُ الْمُسَيَّبِ بَعْدَهُ بِسَنَتَيْنِ مَاتَ سَنَةَ خَمْسٍ وَتِسْعِينَ","id":"Telah menceritakan kepada kami [Muslim bin Hatim Al Anshari Al Bashri] telah menceritakan kepada kami [Muhammad bin Abdullah Al Anshari] dari [Ayahnya] dari [Ali bin Zaid] dari [Sa'id bin Al Musayyaib] ia berkata; [Anas bin Malik] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Wahai anakku, jika kamu mampu pada pagi hari dan sore hari tanpa ada kecurangan dalam hatimu kepada seorangpun maka lakukanlah, \" kemudian beliau berabda kepadaku: \"Wahai anakku, itu termasuk dari sunnahku, barangsiapa menghidupkan sunnahku, berarti dia mencintaiku dan barangsiapa mencintaiku, maka dia akan bersamaku di surga.\" Dan dalam hadits ini ada kisah yang panjang. Abu Isa berkata; Hadits ini hasan gharib dari jalur ini. Muhammad bin Abdullah Al Anshari adalah perawi tsiqah, Ayahnya juga tsiqah, sedangkan Ali bin Zaid shaduq, namun dia memarfu'kan hadits yang di mauqufkan oleh yang lainnya, dia mengatakan: Aku mendengar Muhammad bin Basyar berkata; Abul Walid berkata; Syu'bah berkata; telah menceritakan kepada kami Ali bin Zaid dan dia adalah orang yang biasa memafru'kan hadits, kami tidak mengetahui riwayat Sa'id bin Al Musayyab dari Anas selain hadits panjang ini, [Abbad bin Maysarah Al Minqari] telah meriwayatkan hadits ini dari [Ali bin Zaid] dari [Anas] dan tidak menyebutkan dalam hadits ini dari Sa'id bin Al Musayyab. Abu Isa berkata; Dan aku menyebutkannya kepada Muhammad bin Isma'Il, akan tetapi dia tidak mengetahuinya, hadits tidak diketahui dari riwayat Sa'id dari Anas, demikian juga tidak dari yang lainnya, karena Anas bin Malik wafat tahun sembilan puluh tiga sedangkan Sa'id bin Musayyab wafat dua tahun setelahnya yaitu tahun sembilan puluh lima.\""},"2536":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتْرُكُونِي مَا تَرَكْتُكُمْ فَإِذَا حَدَّثْتُكُمْ فَخُذُوا عَنِّي فَإِنَّمَا هَلَكَ مَنْ كَانَ قَبْلَكُمْ بِكَثْرَةِ سُؤَالِهِمْ وَاخْتِلَافِهِمْ عَلَى أَنْبِيَائِهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Biarkanlah (taklif) yang aku tinggalkan pada kalian, bila aku menyampaikan (sesuatu) pada kalian, ambillah dariku karena sesungguhnya orang-orang sebelum kalian binasa karena banyaknya pertanyaan dan perselisihan mereka terhadap para nabi mereka.\" Abu Isa berkata; Hadits ini hasan shahih."},"2537":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ الْبَزَّارُ وَإِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رِوَايَةًيُوشِكُ أَنْ يَضْرِبَ النَّاسُ أَكْبَادَ الْإِبِلِ يَطْلُبُونَ الْعِلْمَ فَلَا يَجِدُونَ أَحَدًا أَعْلَمَ مِنْ عَالِمِ الْمَدِينَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَهُوَ حَدِيثُ ابْنِ عُيَيْنَةَ وَقَدْ رُوِيَ عَنْ ابْنِ عُيَيْنَةَ أَنَّهُ قَالَ فِي هَذَا سُئِلَ مَنْ عَالِمُ الْمَدِينَةِ فَقَالَ إِنَّهُ مَالِكُ بْنُ أَنَسٍ و قَالَ إِسْحَقُ بْنُ مُوسَى سَمِعْتُ ابْنَ عُيَيْنَةَ يَقُولُ هُوَ الْعُمَرِيُّ الزَّاهِدُ وَاسْمُهُ عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ و سَمِعْت يَحْيَى بْنَ مُوسَى يَقُولُ قَالَ عَبْدُ الرَّزَّاقِ هُوَ مَالِكُ بْنُ أَنَسٍ وَالْعُمَرِيُّ هُوَ عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ مِنْ وَلَدِ عُمَرَ بْنِ الْخَطَّابِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ash Shabbah Al Bazzar] dan [Ishaq bin Musa Al Anshari] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Abu Shalih] dari [Abu Hurairah] secara periwayatan; \"Hampir saja orang-orang mengencangkan untanya untuk menuntut ilmu, mereka tidak mendapatkan seorang alim yang lebih berilmu dari alim Madinah.\" Abu Isa berkata; Hadits ini hasan yaitu hadits Ibnu Uyainah. Dan diriwayatkan dari Ibnu Uyainah, ia berkata mengenai hadits ini, ia pernah ditanya; \"Siapakah orang yang alim dari penduduk Madinah?\" Ia menjawab; \"Malik bin Anas.\" Ishaq bin Musa mengatakan; Aku mendengar Ibnu Uyainah berkata; \"Yaitu Al Umari, orang yang zuhud, namanya Abdul Aziz bin Abdullah. Dan aku mendengar Yahya bin Musa berkata; Abdurrazzaq mengatakan; \"Dia adalah Malik bin Anas. Sementara Al Umari adalah Abdullah bin Abdullah, keturunan 'Umar bin Al Khaththab.\""},"2538":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا رَوْحُ بْنُ جَنَاحٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقِيهٌ أَشَدُّ عَلَى الشَّيْطَانِ مِنْ أَلْفِ عَابِدٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَلَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ الْوَلِيدِ بْنِ مُسْلِمٍ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Ibrahim bin Musa] telah menceritakan kepada kami [Al Walid bin Muslim] telah mengabarkan kepada kami [Rauh bin Janah] dari [Mujahid] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang yang faqih itu lebih berat bagi setan daripada seribu orang ahli ibadah.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari jalur ini dari hadits Al Walid bin Muslim.\""},"2539":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خِدَاشٍ الْبَغْدَادِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ الْوَاسِطِيُّ حَدَّثَنَا عَاصِمُ بْنُ رَجَاءِ بْنِ حَيْوَةَ عَنْ قَيْسِ بْنِ كَثِيرٍ قَالَقَدِمَ رَجُلٌ مِنْ الْمَدِينَةِ عَلَى أَبِي الدَّرْدَاءِ وَهُوَ بِدِمَشْقَ فَقَالَ مَا أَقْدَمَكَ يَا أَخِي فَقَالَ حَدِيثٌ بَلَغَنِي أَنَّكَ تُحَدِّثُهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَمَا جِئْتَ لِحَاجَةٍ قَالَ لَا قَالَ أَمَا قَدِمْتَ لِتِجَارَةٍ قَالَ لَا قَالَ مَا جِئْتُ إِلَّا فِي طَلَبِ هَذَا الْحَدِيثِ قَالَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ سَلَكَ طَرِيقًا يَبْتَغِي فِيهِ عِلْمًا سَلَكَ اللَّهُ بِهِ طَرِيقًا إِلَى الْجَنَّةِ وَإِنَّ الْمَلَائِكَةَ لَتَضَعُ أَجْنِحَتَهَا رِضَاءً لِطَالِبِ الْعِلْمِ وَإِنَّ الْعَالِمَ لَيَسْتَغْفِرُ لَهُ مَنْ فِي السَّمَوَاتِ وَمَنْ فِي الْأَرْضِ حَتَّى الْحِيتَانُ فِي الْمَاءِ وَفَضْلُ الْعَالِمِ عَلَى الْعَابِدِ كَفَضْلِ الْقَمَرِ عَلَى سَائِرِ الْكَوَاكِبِ إِنَّ الْعُلَمَاءَ وَرَثَةُ الْأَنْبِيَاءِ إِنَّ الْأَنْبِيَاءَ لَمْ يُوَرِّثُوا دِينَارًا وَلَا دِرْهَمًا إِنَّمَا وَرَّثُوا الْعِلْمَ فَمَنْ أَخَذَ بِهِ أَخَذَ بِحَظٍّ وَافِرٍقَالَ أَبُو عِيسَى وَلَا نَعْرِفُ هَذَا الْحَدِيثَ إِلَّا مِنْ حَدِيثِ عَاصِمِ بْنِ رَجَاءِ بْنِ حَيْوَةَ وَلَيْسَ هُوَ عِنْدِي بِمُتَّصِلٍ هَكَذَا حَدَّثَنَا مَحْمُودُ بْنُ خِدَاشٍ هَذَا الْحَدِيثَ وَإِنَّمَا يُرْوَى هَذَا الْحَدِيثُ عَنْ عَاصِمِ بْنِ رَجَاءِ بْنِ حَيْوَةَ عَنْ دَاوُدَ بْنِ جَمِيلٍ عَنْ كَثِيرِ بْنِ قَيْسٍ عَنْ أَبِي الدَّرْدَاءِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَذَا أَصَحُّ مِنْ حَدِيثِ مَحْمُودِ بْنِ خِدَاشٍ وَرَأْيُ مُحَمَّدِ بْنِ إِسْمَعِيلَ هَذَا أَصَحُّ","id":"Telah menceritakan kepada kami [Mahmud bin Khidasy Al Baghdadi] telah menceritakan kepada kami [Muhammad bin Yazid Al Washiti] telah menceritakan kepada kami [Ashim bin Raja` bin Haiwah] dari [Qais bin Katsir] ia berkata; Seseorang dari Madinah mendatangi [Abu Darda`] di Damaskus, Abu Darda` bertanya; \"Apa yang membuatmu datang kemari wahai saudaraku?\" Orang itu menjawab: \"Satu hadits yang telah sampai kepadaku bahwa anda menceritakannya dari Rasulullah shallallahu 'alaihi wasallam.\" Abu Darda` bertanya; \"Bukankah kau datang karena keperluan lain?\" Orang itu menjawab; \"Tidak.\" Abu Darda` bertanya; \"Bukankah kau datang untuk berniaga?\" Orang itu menjawab: \"Tidak, aku datang hanya untuk mencari hadits tersebut.\" Abu Darda` berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menempuh jalan untuk mencari ilmu, maka Allah akan menuntunnya menuju surga dan para malaikat akan meletakkan sayap-sayapnya karena senang kepada pencari ilmu, sesungguhnya orang berilmu itu akan dimintakan ampunan oleh (makhluq) yang berada di langit dan di bumi hingga ikan di air, keutamaan orang yang berlilmu atas ahli ibadah laksana keutamaan rembulan atas seluruh bintang, sesungguhnya ulama adalah pewaris pada nabi dan sesungguhnya para nabi tidak mewariskan dinar dan dirham, mereka hanya mewariskan ilmu, maka siapa yang mengambilnya berarti ia telah mengambil bagian yang banyak.\" Abu Isa berkata; \"Kami hanya mengetahui hadits ini kecuali dari hadits Ashim bin Raja` bin Haiwah dan hadits ini menurutku tidak tersambung (sanadnya). Demikian Mahmud bin Khidasy menceritakan hadits ini kepada kami. hadits ini hanya diriwayatkan dari [Ashim bin Raja` bin Haiwah] dari [Dawud bin Jamil] dari [Katsir bin Qais] dari [Abu Darda`] dari Nabi shallallahu 'alaihi wasallam. Hadits ini lebih shahih dari hadits Mahmud bin Khidasy dan pendapat Muhammad bin Isma'il ini lebih benar."},"2540":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ ابْنِ أَشْوَعَ عَنْ يَزِيدَ بْنِ سَلَمَةَ الْجُعْفِيِّ قَالَقَالَ يَزِيدُ بْنُ سَلَمَةَ يَا رَسُولَ اللَّهِ إِنِّي قَدْ سَمِعْتُ مِنْكَ حَدِيثًا كَثِيرًا أَخَافُ أَنْ يُنْسِيَنِي أَوَّلَهُ آخِرُهُ فَحَدِّثْنِي بِكَلِمَةٍ تَكُونُ جِمَاعًا قَالَ اتَّقِ اللَّهَ فِيمَا تَعْلَمُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَيْسَ إِسْنَادُهُ بِمُتَّصِلٍ وَهُوَ عِنْدِي مُرْسَلٌ وَلَمْ يُدْرِكْ عِنْدِي ابْنُ أَشْوَعَ يَزِيدَ بْنَ سَلَمَةَ وَابْنُ أَشْوَعَ اسْمُهُ سَعِيدُ بْنُ أَشْوَعَ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abul Ahwas] dari [Sa'id bin Masruq] dari [Ibnu Asywa'] dari [Yazid bin Salamah Al Ju'fi] ia berkata; Yazid bin Salamah berkata; \"Wahai Rasulullah, aku telah mendengar banyak hadits dari anda, aku takut akan lupa awal dan akhirnya, maka beritahukanlah kepadaku suatu kalimat yang merangkum itu semua!.\" Beliau menjawab: \"Bertakwalah kepada Allah dalam hal-hal yang kamu ketahui.\" Abu Isa berkata; Hadits ini sanadnya tidak muttashil (tidak bersambung), hadits ini menurut saya mursal, menurut saya Ibnu Asywa' tidak bertemu dengan Yazid bin Salamah. Nama Ibnu Asywa' adalah Sa'id bin Asywa'."},"2541":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا خَلَفُ بْنُ أَيُّوبَ الْعَامِرِيُّ عَنْ عَوْفٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَصْلَتَانِ لَا تَجْتَمِعَانِ فِي مُنَافِقٍ حُسْنُ سَمْتٍ وَلَا فِقْهٌ فِي الدِّينِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَلَا نَعْرِفُ هَذَا الْحَدِيثَ مِنْ حَدِيثِ عَوْفٍ إِلَّا مِنْ حَدِيثِ هَذَا الشَّيْخِ خَلَفِ بْنِ أَيُّوبَ الْعَامِرِيِّ وَلَمْ أَرَ أَحَدًا يَرْوِي عَنْهُ غَيْرَ أَبِي كُرَيْبٍ مُحَمَّدِ بْنِ الْعَلَاءِ وَلَا أَدْرِي كَيْفَ هُوَ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Khalaf bin Ayyub Al 'Amiri] dari ['Auf] dari [Ibnu Sirin] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua hal yang tidak akan berkumpul pada diri orang munafik, yaitu; akhlaq yang baik dan pemahaman dalam masalah agama.\" Abu Isa berkata; Hadits ini gharib, dan kami tidak mengetahui hadits ini dari 'Auf kecuali dari hadits syaikh ini, yaitu Khalaf bin Ayyub Al 'Amiri, dan saya tidak melihat seorang pun yang meriwayatkan darinya selain Abu Kuraib Muhammmad bin Al Ala` sementara saya tidak tahu tentang dia.\""},"2542":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ حَدَّثَنَا سَلَمَةُ بْنُ رَجَاءٍ حَدَّثَنَا الْوَلِيدُ بْنُ جَمِيلٍ حَدَّثَنَا الْقَاسِمُ أَبُو عَبْدِ الرَّحْمَنِ عَنْ أَبِي أُمَامَةَ الْبَاهِلِيِّ قَالَذُكِرَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلَانِ أَحَدُهُمَا عَابِدٌ وَالْآخَرُ عَالِمٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضْلُ الْعَالِمِ عَلَى الْعَابِدِ كَفَضْلِي عَلَى أَدْنَاكُمْ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ وَمَلَائِكَ��َهُ وَأَهْلَ السَّمَوَاتِ وَالْأَرَضِينَ حَتَّى النَّمْلَةَ فِي جُحْرِهَا وَحَتَّى الْحُوتَ لَيُصَلُّونَ عَلَى مُعَلِّمِ النَّاسِ الْخَيْرَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ قَالَ سَمِعْت أَبَا عَمَّارٍ الْحُسَيْنَ بْنَ حُرَيْثٍ الْخُزَاعِيَّ يَقُولُ سَمِعْتُ الْفُضَيْلَ بْنَ عِيَاضٍ يَقُولُ عَالِمٌ عَامِلٌ مُعَلِّمٌ يُدْعَى كَبِيرًا فِي مَلَكُوتِ السَّمَوَاتِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul A'la Ash Shan'ani] telah menceritakan kepada kami [Salamah bin Raja`] telah menceritakan kepada kami [Al Walid bin Jamil] telah menceritakan kepada kami [Al Qashim Abu Abdurrahman] dari [Abu Umamah Al Bahili] ia berkata; \"Dua orang disebutkan di sisi Rasulullah shallallahu 'alaihi wasallam, salah seorang adalah ahli ibadah dan yang lain seorang yang berilmu, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keutamaan seorang alim dari seorang abid seperti keutamaanku dari orang yang paling rendah di antara kalian, \" kemudian beliau melanjutkan sabdanya: \"Sesungguhnya Allah, MalaikatNya serta penduduk langit dan bumi bahkan semut yang ada di dalam sarangnya sampai ikan paus, mereka akan mendoakan untuk orang yang mengajarkan kebaikan kepada manusia.\" Abu Isa berkata; Hadits ini hasan gharib shahih. Perawi berkata; \"Aku mendengar Abu 'Ammar Al Husain bin Huraits Al Khuza'I berkata; Aku mendengar Al Fudlail bin Iyadl berkata; \"Seorang alim yang mengamalkan ilmunya dan mengajarkan ilmunya akan dipanggil besar oleh para Malaikat yang ada di langit.\""},"2543":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ الشَّيْبَانِيُّ الْبَصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ دَرَّاجٍ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَنْ يَشْبَعَ الْمُؤْمِنُ مِنْ خَيْرٍ يَسْمَعُهُ حَتَّى يَكُونَ مُنْتَهَاهُ الْجَنَّةُهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Umar bin Hafs Asy Syaibani Al Bashri] telah menceritakan kepada kami [Abdullah bin Wahab] dari ['Amru bin Al Harits] dari [Darraj] dari [Abul Haitsam] dari [Abu Sa'id Al Khudri] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Seorang mukmin tidak akan merasa kenyang dengan kebaikan yang dia dengar sehingga akhir kesudahannya adalah surga.\" Hadits ini hasan gharib"},"2544":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ الْوَلِيدِ الْكِنْدِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ إِبْرَاهِيمَ بْنِ الْفَضْلِ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكَلِمَةُ الْحِكْمَةُ ضَالَّةُ الْمُؤْمِنِ فَحَيْثُ وَجَدَهَا فَهُوَ أَحَقُّ بِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَإِبْرَاهِيمُ بْنُ الْفَضْلِ الْمَدَنِيُّ الْمَخْزُومِيُّ يُضَعَّفُ فِي الْحَدِيثِ مِنْ قِبَلِ حِفْظِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Umar bin Al Walid Al Kindi] telah menceritakan kepada kami [Abdullah bin Numair] dari [Ibrahim bin Al Fadlal] dari [Sa'id Al Maqburi] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"\"Kalimat hikmah adalah barang seorang mukmin yang hilang, maka dimana saja ia menemukannya ia lebih berhak untuk mengambilnya.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari jalur ini, Ibrahim bin Al Fadlal Al Madani Al Makhzumi dilemahkan dalam masalah hadits dari sisi hafalannya.\""},"2545":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَا تَدْخُلُوا الْجَنَّةَ حَتَّى تُؤْمِنُوا وَلَا تُؤْمِنُوا حَتَّى تَحَابُّوا أَلَا أَدُلُّكُمْ عَلَى أَمْرٍ إِذَا أَنْتُمْ فَعَلْتُمُوهُ تَحَابَبْتُمْ أَفْشُوا السَّلَامَ بَيْنَكُمْوَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ سَلَامٍ وَشُرَيْحِ بْنِ هَانِئٍ عَنْ أَبِيهِ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَالْبَرَاءِ وَأنَسٍ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Muawiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku berada di tanganNya, kalian tidak akan masuk surga hingga beriman, dan tidak akan beriman hingga saling mencintai. Maukah aku tunjukkan kepada kalian tentang sesuatu yang bila kalian lakukan, kalian akan saling mencintai?, tebarkanlah salam diantara kalian.\" Dalam hal ini ada hadits serupa dari Abdullah bin Salam, Syuraij bin Hani' dari ayahnya, dan Abdullah bin 'Amru dan Al Barra` dan Anas, serta Ibnu Umar. Abu Isa berkata; Hadits ini hasan shahih."},"2546":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ وَالْحُسَيْنُ بْنُ مُحَمَّدٍ الْحَرِيرِيُّ الْبَلْخِيُّ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ جَعْفَرِ بْنِ سُلَيْمَانَ الضُّبَعِيِّ عَنْ عَوْفٍ عَنْ أَبِي رَجَاءٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَجُلًا جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ السَّلَامُ عَلَيْكُمْ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرٌ ثُمَّ جَاءَ آخَرُ فَقَالَ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِشْرُونَ ثُمَّ جَاءَ آخَرُ فَقَالَ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثُونَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَفِي الْبَاب عَنْ عَلِيٍّ وَأَبِي سَعِيدٍ وَسَهْلِ بْنِ حُنَيْفٍ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] dan [Al Husain bin Muhammad Al Hariri Al Bajali] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Katsir] dari [Ja'far bin Sulaiman Adl Dluba'i] dari ['Auf] dari [Abu Raja`] dari [Imran bin Hushain] bahwa seseorang datang menemui Nabi shallallahu 'alaihi wasallam lalu mengucapkan: \"ASSALAAMU'ALAIKUM.\" Imran berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sepuluh.\" Kemudian yang lain datang dan mengucapkan: \"ASSALAAMU'ALAIKUM WA RAHMATULLAAH.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Dua puluh.\" Selanjutnya yang lain tiba, ia mengucapkan; \"ASSALAAMU'ALAIKUM WA RAHMATULLAAHI WA BARAKAATUH.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Tiga puluh.\" Abu Isa berkata; Hadits ini hasan shahih gharib melalui sanad ini dan dalam hal ini ada hadits serupa dari Ali dan Abu Sa'id serta Sahl bin Hunaif."},"2547":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ عَبْدِ الْأَعْلَى عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَاسْتَأْذَنَ أَبُو مُوسَى عَلَى عُمَرَ فَقَالَ السَّلَامُ عَلَيْكُمْ أَأَدْخُلُ قَالَ عُمَرُ وَاحِدَةٌ ثُمَّ سَكَتَ سَاعَةً ثُمَّ قَالَ السَّلَامُ عَلَيْكُمْ أَأَدْخُلُ قَالَ عُمَرُ ثِنْتَانِ ثُمَّ سَكَتَ سَاعَةً فَقَالَ السَّلَامُ عَلَيْكُمْ أَأَدْخُلُ فَقَالَ عُمَرُ ثَلَاثٌ ثُمَّ رَجَعَ فَقَالَ عُمَرُ لِلْبَوَّابِ مَا صَنَعَ قَالَ رَجَعَ قَالَ عَلَيَّ بِهِ فَلَمَّا جَاءَهُ قَالَ مَا هَذَا الَّذِي صَنَعْتَ قَالَ السُّنَّةُ قَالَ آلسُّنَّةُ وَاللَّهِ لَتَأْتِيَنِّي عَلَى هَذَا بِبُرْهَانٍ أَوْ بِبَيِّنَةٍ أَوْ لَأَفْعَلَنَّ بِكَ قَالَ فَأَتَانَا وَنَحْنُ رُفْقَةٌ مِنْ الْأَنْصَارِ فَقَالَ يَا مَعْشَرَ الْأَنْصَارِ أَلَسْتُمْ أَعْلَمَ النَّاسِ بِحَدِيثِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَمْ يَقُلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الِاسْتِئْذَانُ ثَلَاثٌ فَإِنْ أُذِنَ لَكَ وَإِلَّا فَارْجِعْ فَجَعَلَ الْقَوْمُ يُمَازِحُونَهُ قَالَ أَبُو سَعِيدٍ ثُمَّ رَفَعْتُ رَأْسِي إِلَيْهِ فَقُلْتُ فَمَا أَصَابَكَ فِي هَذَا مِنْ الْعُقُوبَةِ فَأَنَا شَرِيكُكَ قَالَ فَأَتَى عُمَرَ فَأَخْبَرَهُ بِذَلِكَ فَقَالَ عُمَرُ مَا كُنْتُ عَلِمْتُ بِهَذَاوَفِي الْبَاب عَنْ عَلِيٍّ وَأُمِّ طَارِقٍ مَوْلَاةِ سَعْدٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْجُرَيْرِيُّ اسْمُهُ سَعِيدُ بْنُ إِيَاسٍ يُكْنَى أَبَا مَسْعُودٍ وَقَدْ رَوَى هَذَا غَيْرُهُ أَيْضًا عَنْ أَبِي نَضْرَةَ وَأَبُو نَضْرَةَ الْعَبْدِيُّ اسْمُهُ الْمُنْذِرُ بْنُ مَالِكِ بْنِ قُطَعَةَ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [Abdul A'la bin Abdul A'la] dari [Al Jurairi] dari [Abu Nadlrah] dari [Abu Sa'id] ia berkata; Abu Musa meminta izin kepada Umar, sambil berucap; \"ASSALAAMU'ALAIKUM, apakah aku boleh masuk?\" Umar berkata; \"Satu, setelah itu ia diam sesaat.\" Selanjutnya Abu Musa mengucapkan; \"ASSALAAMU'ALAIKUM, apakah aku boleh masuk?\" Umar berkata; \"Dua, setelah itu ia diam sesaat.\" Abu Musa mengulanginya; \"ASSALAAMU'ALAIKUM, apakah aku boleh masuk?\" Umar berkata; \"Tiga.\" Setelah itu Abu Musa beranjak pergi, lalu Umar berkata kepada penjaga pintu; \"Apa yang ia lakukan?\" Penjaga pintu menjawab; \"Ia sudah beranjak pergi.\" Umar berkata; \"Suruh ia dating kembali.\" Saat Abu Musa datang, Umar bertanya: \"Apa yang telah kamu lakukakn?\" Abu Musa menjawab; \"Sunnah.\" Umar berkata; \"Sunnah? demi Allah, kamu harus membawa bukti atau aku akan menghukummu.\" Abu Sa'id melanjutkan; \"Lalu Abu Musa mendatangi kami, sementara kami tengah bersama beberapa orang Anshar, Abu Musa berkata; \"Wahai sekalian kaum Anshar, bukankah kalian yang paling tahu tentang hadits Rasulullah shallallahu 'alaihi wasallam?, bukankah Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Meminta izin itu tiga kali, bila kamu diizinkan (silahkan masuk) dan bila tidak, maka kembalilah.\" Orang-orangpun mencandainya. Abu Sa'id berkata; Lalu aku mengangkat kepalaku, aku bertanya: \"Apakah kamu akan mendapakan hukuman karena masalah ini?, sungguh aku akan menyertaimu.\" Ia mendatangi Umar lalu memberitahukannya. Umar berkata; Aku belum mengetahui mengenai masalah ini. Dalam hal ini ada hadits serupa dari Ali dan Ummu Thariq budak milik Sa'ad. Abu Isa berkata; Hadits ini hasan shahih. Nama Al Jurairi adalah Sa'id bin Iyas, julukannya Abu Mas'ud. Yang lain juga meriwayatkan hadits ini dari Abu Nadlrah Al Abdi, namnya adalah Al Mundzir bin Malik bin Qatha'ah."},"2548":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنِي أَبُو زُمَيْلٍ حَدَّثَنِي ابْنُ عَبَّاسٍ حَدَّثَنِي عُمَرُ بْنُ الْخَطَّابِ قَالَاسْتَأْذَنْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثًا فَأَذِنَ لِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَأَبُو زُمَيْلٍ اسْمُهُ سِمَاكٌ الْحَنَفِيُّ وَإِنَّمَا أَنْكَرَ عُمَرُ عِنْدَنَا عَلَى أَبِي مُوسَى حَيْثُ رَوَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الِاسْتِئْذَانُ ثَلَاثٌ فَإِذَا أُذِنَ لَكَ وَإِلَّا فَارْجِعْ وَقَدْ كَانَ عُمَرُ اسْتَأْذَنَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثًا فَأَذِنَ لَهُ وَلَمْ يَكُنْ عَلِمَ هَذَا الَّذِي رَوَاهُ أَبُو مُوسَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ فَإِنْ أُذِنَ لَكَ وَإِلَّا فَارْجِعْ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Umar bin Yunus] telah menceritakan kepada kami [Ikrimah bin 'Ammar] telah menceritakan kepada kami [Abu Zumail] telah menceritakan kepadaku [Ibnu 'Abbas] telah menceritakan kepadaku [Umar bin Al Khaththab] ia berkata; \"Aku pernah meminta izin kepada Rasulullah shallallahu 'alaihi wasallam hingga tiga kali, lalu beliau memberiku izin.\" Abu Isa berkata; Hadits ini hasan gharib, Abu Zumail namanya adalah Simak Al Hanafi. Umar pernah mengingkari Abu Musa di sisi kami, karena satu hadits yang diriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Minta izin itu tiga kali, apabila kamu diizinkan (silahkan masuk) dan jika tidak, maka kembalilah.\" Umar pernah meminta izin kepada Nabi shallallahu 'alaihi wasallam tiga kali, kemudian diizinkan, sementara Umar belum mengetahui hadits yang telah diriwayatkan oleh Abu Musa dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Apabila kamu diizinkan (silahkah masuk) namun jika tidak, maka kembalilah.\""},"2549":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَدَخَلَ رَجُلٌ الْمَسْجِدَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ فِي نَاحِيَةِ الْمَسْجِدِ فَصَلَّى ثُمَّ جَاءَ فَسَلَّمَ عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْكَ ارْجِعْ فَصَلِّ فَذَكَرَ الْحَدِيثَ بِطُولِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَرَوَى يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ هَذَا عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ فَقَالَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ وَلَمْ يَذْكُرْ فِيهِ فَسَلَّمَ عَلَيْهِ وَقَالَ وَعَلَيْكَ قَالَ وَحَدِيثُ يَحْيَى بْنِ سَعِيدٍ أَصَحُّ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Abdullah bin Numair] telah menceritakan kepada kami ['Ubaidullah bin Umar] dari [Sa'id Al Maqburi] dari [Abu Hurairah] ia berkata; \"Seseorang masuk masjid, sementara Rasulullah shallallahu 'alaihi wasallam tengah duduk di pojok masjid, ia shalat kemudian mengucapkan salam kepada beliau, Rasulullah shallallahu 'alaihi wasallam bersabda: \"WA 'ALAIK (dan keatasmu juga), kembalilah lalu shalatlah.\" Lalu perawi menyebutkan hadits yang panjang. Abu Isa berkata; Hadits ini hasan. [Yahya bin Sa'id Al Qaththan] telah meriwayatkan hadits ini dari [Ubaidullah bin Umar] dari [Sa'id Al Maqburi] ia berkata dari [Ayahnya] dari [Abu Hurairah], namun dia tidak menyebutkan (lafadl); \"Lalu orang itu mengucapkan salam kepada beliau.\" Juga tidak menyebutkan: \"WA 'ALAIK.\" Abu Isa berkata; Hadits Yahya bin Sa'id lebih shahih."},"2550":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ الْكُوفِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ عَامِرٍ الشَّعْبِيِّ حَدَّثَنِي أَبُو سَلَمَةَ أَنَّ عَائِشَةَ حَدَّثَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا إِنَّ جِبْرِيلَ يُقْرِئُكِ السَّلَامَ قَالَتْ وَعَلَيْهِ السَّلَامُ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُوَفِي الْبَاب عَنْ رَجُلٍ مِنْ بَنِي نُمَيْرٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ الزُّهْرِيُّ أَيْضًا عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ","id":"Telah menceritakan kepada kami [Ali bin Al Mundzir Al Kufi] telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Zakariya bin Abu Za`idah] dari [Amir Asy Sya'bi] telah menceritakan kepadaku [Abu Salamah] bahwa [Aisyah] bercerita padanya bahwa Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Sesungguhnya Jibril mengucapkan salam untukmu.\" 'Aisyah menjawab; \"WA 'ALAIHISSALAAM WA RAHMATULLAHI WA BARAKAATUH.\" Dalam hal ini ada hadits serupa dari seseorang dari Bani Numair dari Ayahnya dari kakeknya. Abu Isa berkata; Hadits ini hasan shahih dan [Az Zuhri] juga telah meriwayatkannya dari [Abu Salamah] dari ['Aisyah]."},"2551":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا قُرَّانُ بْنُ تَمَّامٍ الْأَسَدِيُّ عَنْ أَبِي فَرْوَةَ يَزِيدَ بْنِ سِنَانٍ عَنْ سُلَيْمِ بْنِ عَامِرٍ عَنْ أَبِي أُمَامَةَ قَالَقِيلَ يَا رَسُولَ اللَّهِ الرَّجُلَانِ يَلْتَقِيَانِ أَيُّهُمَا يَبْدَأُ بِالسَّلَامِ فَقَالَ أَوْلَاهُمَا بِاللَّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ قَالَ مُحَمَّدٌ أَبُو فَرْوَةَ الرَّهَاوِيُّ مُقَارِبُ الْحَدِيثِ إِلَّا أَنَّ ابْنَهُ مُحَمَّدَ بْنَ يَزِيدَ يَرْوِي عَنْهُ مَنَاكِيرَ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Qarran bin Tammam Al Asadi] dari [Abu Farwah Yazid bin Sinan] dari [Sulaim bin 'Amir] dari [Abu Umamah] ia berkata; \"Dikatakan; \"Wahai Rasulullah, Ada dua orang yang bertemu, mana diantara keduanya yang lebih dulu memulai salam?\" Beliau menjawab: \"Yang paling dekat dengan (rahmat) Allah di antara keduanya.\" Abu Isa berkata; Hadits ini hasan. Muhammad mengatakan; Abu Farwah Ar Rahawi riwayat haditsnya muqarrib (mendekati shahih), hanya saja putranya, Muhammad bin Yazid, meriwayatkan hadits-hadits munkar darinya."},"2552":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ مِنَّا مَنْ تَشَبَّهَ بِغَيْرِنَا لَا تَشَبَّهُوا بِالْيَهُودِ وَلَا بِالنَّصَارَى فَإِنَّ تَسْلِيمَ الْيَهُودِ الْإِشَارَةُ بِالْأَصَابِعِ وَتَسْلِيمَ النَّصَارَى الْإِشَارَةُ بِالْأَكُفِّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ إِسْنَادُهُ ضَعِيفٌ وَرَوَى ابْنُ الْمُبَارَكِ هَذَا الْحَدِيثَ عَنْ ابْنِ لَهِيعَةَ فَلَمْ يَرْفَعْهُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ibnu Lahi'ah] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan termasuk golonganku orang yang tasyabbuh (menyerupai atau mengikuti) dengan selain kami, janganlah kalian tasyabbuh dengan orang-orang Yahudi dan orang-orang Nashrani, sesungguhnya salamnya orang-orang Yahudi adalah memberikan isyarat dengan jari tangan, sedangkan salamnya orang orang Nashrani adalah memberikan isyarat dengan telapak tangan.\" Abu Isa berkata; Hadits ini sanadnya lemah, [Ibnul Mubarak] meriwayatkan hadits ini dari [Ibnu Lahi'ah] namun tidak memarfu'kannya."},"2553":{"ar":"حَدَّثَنَا أَبُو الْخَطَّابِ زِيَادُ بْنُ يَحْيَى الْبَصْرِيُّ حَدَّثَنَا أَبُو عَتَّابٍ سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ سَيَّارٍ قَالَ كُنْتُ أَمْشِي مَعَ ثَابِتٍ الْبُنَانِيِّ فَمَرَّ عَلَى صِبْيَانٍ فَسَلَّمَ عَلَيْهِمْ فَقَالَ ثَابِتٌكُنْتُ مَعَ أَنَسٍ فَمَرَّ عَلَى صِبْيَانٍ فَسَلَّمَ عَلَيْهِمْ وَقَالَ أَنَسٌ كُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَرَّ عَلَى صِبْيَانٍ فَسَلَّمَ عَلَيْهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ رَوَاهُ غَيْرُ وَاحِدٍ عَنْ ثَابِتٍ وَرُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَنَسٍ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ ثَابِتٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Al Khaththab Ziyad bin Yahya Al Bashri] telah menceritakan kepada kami [Abu Attab Sahal bin Hamad] telah menceritakan kepada kami [Syu'bah] dari [Sayyar] ia berkata; Aku berjalan bersama Tsabit Al Bannani, dan melewati anak-anak kecil, lalu ia mengucapkan salam kepada mereka. [Tsabit] berkata; Aku pernah bersama [Anas], ia melewati anak-anak kecil lalu mengucapkan salam pada mereka. Anas lalu berkata: \"Aku pernah bersama Rasulullah shallallahu 'alaihi wasallam, beliau melewati anak-anak kecil lalu mengucapkan salam kepada mereka.\" Abu Isa berkata; Hadits ini shahih diriwayatkan oleh beberapa perawi dari Tsabit. Dan diriwayatkan melalui sanad lain dari Anas. Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ja'far bin Sulaiman] dari [Tsabit] dari [Anas] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"2554":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ بَهْرَامَ أَنَّهُ سَمِعَ شَهْرَ بْنَ حَوْشَبٍ يَقُولُ سَمِعْتُ أَسْمَاءَ بِنْتَ يَزِيدَ تُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ فِي الْمَسْجِدِ يَوْمًا وَعُصْبَةٌ مِنْ النِّسَاءِ قُعُودٌ فَأَلْوَى بِيَدِهِ بِالتَّسْلِيمِ وَأَشَارَ عَبْدُ الْحَمِيدِ بِيَدِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ قَالَ أَحْمَدُ بْنُ حَنْبَلٍ لَا بَأْسَ بِحَدِيثِ عَبْدِ الْحَمِيدِ بْنِ بَهْرَامَ عَنْ شَهْرِ بْنِ حَوْشَبٍ و قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ شَهْرٌ حَسَنُ الْحَدِيثِ وَقَوَّى أَمْرَهُ و قَالَ إِنَّمَا تَكَلَّمَ فِيهِ ابْنُ عَوْنٍ ثُمَّ رَوَى عَنْ هِلَالِ بْنِ أَبِي زَيْنَبَ عَنْ شَهْرِ بْنِ حَوْشَبٍ أَنْبَأَنَا أَبُو دَاوُدَ الْمَصَاحِفِيُّ بَلْخِيٌّ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ عَنْ ابْنِ عَوْنٍ قَالَ إِنَّ شَهْرًا نَزَكُوهُ قَالَ أَبُو دَاوُدَ قَالَ النَّضْرُ نَزَكُوهُ أَيْ طَعَنُوا فِيهِ وَإِنَّمَا طَعَنُوا فِيهِ لِأَنَّهُ وَلِيَ أَمْرَ السُّلْطَانِ","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah bin Al Mubarak] telah mengabarkan kepada kami [Abdul Hamid bin Bahram] bahwa dia mendengar [Syahr bin Hausyab] berkata; Aku mendengar [Asma` binti Yazid] bercerita bahwa suatu hari Rasulullah shallallahu 'alaihi wasallam berjalan dekat masjid, sementara sekelompok wanita tengah duduk-duduk, beliau melambaikan tangan sebagai isyarat salam. Abdul Hamid memberi isyarat dengan tangannya. Abu Isa berkata; Hadits ini hasan. Ahmad bin Hambal berkata; tidak ada masalah dengan hadits Abdullah bin Bahram dari Syahr bin Hausyab. Muhammad bin Ismail berkata; Syahr haditsnya hasan dan ia memperkuat masalahnya. Perawi berkata; Hanya Ibnu 'Aun-lah yang membicarakannya. Kemudian ia meriwayatkan dari Hilal bin Abu Zainab dari Syahr bin Hausyab telah memberitakan kepada kami Abu Dawud Al Mushafihi Balkhi telah mengabarkan kepada kami An Nadlr bin Syumail dari Ibnu 'Aun ia berkata; \"Mereka menuduh Syahr.\" Abu Dawud berkata; \"An Nadlr berkata; Nazakuuhu artinya mereka mencelanya. Mereka mencelanya hanya karena ia menjabat sebagai sultan.\""},"2555":{"ar":"حَدَّثَنَا أَبُو حَاتِمٍ الْبَصْرِيُّ الْأَنْصَارِيُّ مُسْلِمُ بْنُ حَاتِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بُنَيَّ إِذَا دَخَلْتَ عَلَى أَهْلِكَ فَسَلِّمْ يَكُنْ بَرَكَةً عَلَيْكَ وَعَلَى أَهْلِ بَيْتِكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abu Hatim Al Bashri Al Anshari yaitu Muslim bin Hatim], telah menceritakan kepada kami [Muhammad bin Abdullah Al Anshari] dari [Ayahnya] dari [Ali bin Zaid] dari [Sa'id bin Al Musayyab] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Wahai anakku, jika kamu masuk menemui keluargamu, ucapkanlah salam, niscaya akan menjadi berkah bagimu dan bagi keluargamu.\" Abu Isa berkata; Hadits ini hasan shahih gharib."},"2556":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ الصَّبَّاحِ بَغْدَادِيٌّ حَدَّثَنَا سَعِيدُ بْنُ زَكَرِيَّا عَنْ عَنْبَسَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مُحَمَّدِ بْنِ زَاذَانَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّلَامُ قَبْلَ الْكَلَامِ وَبِهَذَا الْإِسْنَادِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَدْعُوا أَحَدًا إِلَى الطَّعَامِ حَتَّى يُسَلِّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ مُنْكَرٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ و سَمِعْت مُحَمَّدًا يَقُولُ عَنْبَسَةُ بْنُ عَبْدِ الرَّحْمَنِ ضَعِيفٌ فِي الْحَدِيثِ ذَاهِبٌ وَمُحَمَّدُ بْنُ زَاذَانَ مُنْكَرُ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Al Fadlal bin Ash Shabbah Baghdadi] telah menceritakan kepada kami [Sa'id bin Zakaria] dari [Anbasah bin Abdurrahman] dari [Muhammad bin Zadzan] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Salam itu sebelum berbicara.\" Dan dengan sanad ini pula. dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian memanggil seseorang untuk makan hingga mengucapkan salam.\" Abu Isa berkata; Hadits ini munkar, kami tidak mengetahuinya kecuali dari jalur ini, dan aku mendengar Muhammad berkata; Anbasah bin Abdurrahman lemah dalam masalah hadits dan dzahib (haditsnya tidak diterima) sedangkan Muhammad bin Zadzan haditsnya munkar."},"2557":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَبْدَءُوا الْيَهُودَ وَالنَّصَارَى بِالسَّلَامِ وَ��ِذَا لَقِيتُمْ أَحَدَهُمْ فِي الطَّرِيقِ فَاضْطَرُّوهُمْ إِلَى أَضْيَقِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian memulai salam terhadap orang-orang Yahudi dan Nasrani, apbila kalian menamui salah seorang dari mereka di jalan, maka paksalah mereka ke (jalan) yang paling sempit.\" Abu Isa berkata; Hadits ini hasan shahih."},"2558":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْإِنَّ رَهْطًا مِنْ الْيَهُودِ دَخَلُوا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا السَّامُ عَلَيْكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ فَقَالَتْ عَائِشَةُ بَلْ عَلَيْكُمْ السَّامُ وَاللَّعْنَةُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَائِشَةُ إِنَّ اللَّهَ يُحِبُّ الرِّفْقَ فِي الْأَمْرِ كُلِّهِ قَالَتْ عَائِشَةُ أَلَمْ تَسْمَعْ مَا قَالُوا قَالَ قَدْ قُلْتُ عَلَيْكُمْوَفِي الْبَاب عَنْ أَبِي بَصْرَةَ الْغِفَارِيِّ وَابْنِ عُمَرَ وَأَنَسٍ وَأَبِي عَبْدِ الرَّحْمَنِ الْجُهَنِيِّ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Sa'id bin Abdurrahman Al Makhzumi] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] ia berkata; \"Sekelompok orang yahudi dating menemui Nabi shallallahu 'alaihi wasallam, lalu mereka mengucapkan: \"ASSAAMU 'ALAIKUM (semoga kematian menimpamu).\" Maka Nabi shallallahu 'alaihi wasallam menjawab: WA 'ALAIKUM (dan semoga menimpa kalian).\" Namun 'Aisyah berkata; \"Bahkan atas kalian kematian dan laknat.\" Setelah itu Nabi shallallahu 'alaihi wasallam bersabda: \"Hai Aisyah, sesungguhnya Allah mencintai kelemah lembutan dalam segala hal.\" Aisyah berkata; \"Apakah anda tidak mendengar ucapan mereka?\" Beliau menjawab: \"Aku tadi sudah menjawab: WA 'ALAIKUM.\" Dalam hal ini ada hadits serupa dari Abu Bashrah Al Ghifari, Ibnu Umar, Anas dan Abu Abdurrahman Al Juhani. Abu Isa berkata; Hadits Aisyah hasan shahih."},"2559":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ أَنَّ أُسَامَةَ بْنَ زَيْدٍ أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِمَجْلِسٍ وَفِيهِ أَخْلَاطٌ مِنْ الْمُسْلِمِينَ وَالْيَهُودِ فَسَلَّمَ عَلَيْهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] bahwa [Usamah bin Zaid] telah mengabarkan kepadanya bahwa Nabi shallallahu 'alaihi wasallam melintasi suatu majlis, sementara di majlis tersebut terdapat kaum muslimin dan orang-orang Yahudi yang membaur, lalu beliau mengucap salam kepada mereka.\" Abu Isa berkata; Hadits ini hasan shahih."},"2560":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَإِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَا حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ عَنْ حَبِيبِ بْنِ الشَّهِيدِ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُسَلِّمُ الرَّاكِبُ عَلَى الْمَاشِي وَالْمَاشِي عَلَى الْقَاعِدِ وَالْقَلِيلُ عَلَى الْكَثِيرِوَزَادَ ابْنُ الْمُثَنَّى فِي حَدِيثِهِ وَيُسَلِّمُ الصَّغِيرُ عَلَى الْكَبِيرِ وَفِي الْبَاب عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍ وَفَضَالَةَ بْنِ عُبَيْدٍ وَجَابِرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي هُرَيْرَةَ و قَالَ أَيُّوبُ السَّخْتِيَانِيُّ وَيُونُسُ بْنُ عُبَيْدٍ وَعَلِيُّ بْنُ زَيْدٍ إِنَّ الْحَسَنَ لَمْ يَسْمَعْ مِنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibrahim bin Ya'qub] keduanya berkata; telah menceritakan kepada kami [Rauh bin 'Ubadah] dari [Habib bin Asy Syahid] dari [Al Hasan] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Hendaknya yang berkendaraan memberi salam kepada yang berjalan, yang berjalan memberi salam kepada yang duduk, kelompok yang sedikit memberi salam kepada yang banyak.\" Ibnu Mutsanna menambahkan dalam haditsnya: \"Hendaknya yang kecil memberi salam kepada yang besar.\" Dalam hal ini ada hadits serupa dari Abdurrahman bin Syibl, Fadlallah bin Ubaid dan Jabir. Abu Isa berkata; Hadits ini diriwayatkan melalui sanad lain dari Abu Hurairah. Ayyub As Sakhtiyani, Yunus bin Ubaid dan Ali bin Zaid mengatakan bahwa Al Hasan tidak mendengar dari Abu Hurairah.\""},"2561":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَنْبَأَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُسَلِّمُ الصَّغِيرُ عَلَى الْكَبِيرِ وَالْمَارُّ عَلَى الْقَاعِدِ وَالْقَلِيلُ عَلَى الْكَثِيرِقَالَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah memberitakan kepada kami [Abdullah bin Al Mubarak] telah memberitakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari nabi shallallahu 'alaihi wasallam beliau bersabda: \"Hendaknya yang kecil memberi salam kepada yang besar, yang berjalan memberi salam kepada yang duduk dan (kelompok) yang sedikit memberi salam kepada yang banyak.\" Abu Isa berkata; Hadits ini hasan shahih."},"2562":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَنْبَأَنَا عَبْدُ اللَّهِ أَنْبَأَنَا حَيْوَةُ بْنُ شُرَيْحٍ أَخْبَرَنِي أَبُو هَانِئٍ اسْمُهُ حُمَيْدُ بْنُ هَانِئٍ الْخَوْلَانِيُّ عَنْ أَبِي عَلِيٍّ الْجَنْبِيِّ عَنْ فَضَالَةَ بْنِ عُبَيْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُسَلِّمُ الْفَارِسُ عَلَى الْمَاشِي وَالْمَاشِي عَلَى الْقَائِمِ وَالْقَلِيلُ عَلَى الْكَثِيرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو عَلِيٍّ الْجَنْبِيُّ اسْمُهُ عَمْرُو بْنُ مَالِكٍ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah memberitakan kepada kami [Abdullah] telah memberitakan kepada kami [Haiwah bin Syuraih] telah mengabarkan kepada kami [Abu Hani` namanya adalah Humaid bin Hani` Al Khaulani], dari [Abu Ali Al Janbi] dari [Fadlalah bin 'Ubaid] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya yang berkendaraan memberi salam kepada yang berjalan, yang berjalan memberi salam kepada yang berdiri dan (kelompok) yang sedikit memberi salam kepada yang banyak.\" Abu Isa berkata; Hadits ini hasan shahih. Abu Ali Al Janbi namanya adalah 'Amru bin Malik."},"2563":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا انْتَهَى أَحَدُكُمْ إِلَى مَجْلِسٍ فَلْيُسَلِّمْ فَإِنْ بَدَا لَهُ أَنْ يَجْلِسَ فَلْيَجْلِسْ ثُمَّ إِذَا قَامَ فَلْيُسَلِّمْ فَلَيْسَتْ الْأُولَى بِأَحَقَّ مِنْ الْآخِرَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ أَيْضًا عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Sa'id Al Maqburi] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian tiba di suatu majlis, maka ucapkanlah salam, jika dia hendak duduk, silahkan ia duduk, dan jika hendak berdiri, maka ucapkanlah salam, karena yang pertama tidak lebih berhak daripada yang terakhir.\" Abu Isa berkata; Hadits ini hasan, hadits ini diriwayatkan juga dari [Ibnu 'Ajlan] dari [Sa'id Al Maqburi] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam."},"2564":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَشَفَ سِتْرًا فَأَدْخَلَ بَصَرَهُ فِي الْبَيْتِ قَبْلَ أَنْ يُؤْذَنَ لَهُ فَرَأَى عَوْرَةَ أَهْلِهِ فَقَدْ أَتَى حَدًّا لَا يَحِلُّ لَهُ أَنْ يَأْتِيَهُ لَوْ أَنَّهُ حِينَ أَدْخَلَ بَصَرَهُ اسْتَقْبَلَهُ رَجُلٌ فَفَقَأَ عَيْنَيْهِ مَا عَيَّرْتُ عَلَيْهِ وَإِنْ مَرَّ الرَّجُلُ عَلَى بَابٍ لَا سِتْرَ لَهُ غَيْرِ مُغْلَقٍ فَنَظَرَ فَلَا خَطِيئَةَ عَلَيْهِ إِنَّمَا الْخَطِيئَةُ عَلَى أَهْلِ الْبَيْتِوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي أُمَامَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِثْلَ هَذَا إِلَّا مِنْ حَدِيثِ ابْنِ لَهِيعَةَ وَأَبُو عَبْدِ الرَّحْمَنِ الْحُبُلِيُّ اسْمُهُ عَبْدُ اللَّهِ بْنُ يَزِيدَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Ubaidullah bin Abu Ja'far] dari [Abu Abdurrahman Al Hubulli] dari [Abu Dzarr] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membuka tabir kemudian mengarahkan pandangannya ke dalam rumah sebelum diizinkan, lalu dia melihat aurat pemilik rumah, maka dia telah melakukan pelanggaran yang tidak halal dilakukan, seandainya ketika dia mengarahkan pandangannya ada seseorang yang menghadap kepadanya lalu mencolok kedua matanya, niscaya aku tidak menyalahkannya, namun jika seseorang melewati sebuah pintu yang tidak ada tabirnya dan tidak tertutup kemudian dia melihatnya, maka tidak ada kesalahan baginya, akan tetapi kesalahan ada pada penghuni rumah.\" Dan dalam bab ini ada hadits dari Abu Hurairah dan Abu Umamah. Abu Isa berkata; Hadits ini gharib, kami tidak mengetahui hadits seperti ini kecuali dari hadits Ibnu Lahi'ah, sedangkan Abu Abdurrahman Al Hubulli namanya adalah Abdullah bin Yazid."},"2565":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ حُمَيْدٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي بَيْتِهِ فَاطَّلَعَ عَلَيْهِ رَجُلٌ فَأَهْوَى إِلَيْهِ بِمِشْقَصٍ فَتَأَخَّرَ الرَّجُلُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafi] dari [Humaid] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam berada di rumah, lalu ada seseorang mengintip beliau, beliau pun mencolokkan anak panah padanya, hingga membuat orang tersebut mundur.\" Abu Isa berkata; Hadits ini hasan shahih."},"2566":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّأَنَّ رَجُلًا اطَّلَعَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ جُحْرٍ فِي حُجْرَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِدْرَاةٌ يَحُكُّ بِهَا رَأْسَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ عَلِمْتُ أَنَّكَ تَنْظُرُ لَطَعَنْتُ بِهَا فِي عَيْنِكَ إِنَّمَا جُعِلَ الِاسْتِئْذَانُ مِنْ أَجْلِ الْبَصَرِوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sahl bin Sa'd As Sa'idi], bahwa seseorang mengintip Rasulullah shallallahu 'alaihi wasallam dari salah satu kamar Nabi shallallahu 'alaihi wasallam, ketika itu Nabi shallallahu 'alaihi wasallam membawa sisir yang dipakai menggaruk kepala, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Andai aku tahu kamu melihat, niscaya akan aku tusukkan sisir ini ke matamu, sesungguhnya meminta izin itu diberlakukan karena pandangan.\" Dalam hal ini ada hadits serupa dari Abu Hurairah. Abu Isa berkata; Hadits ini hasan shahih."},"2567":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي عَمْرُو بْنُ أَبِي س��فْيَانَ أَنَّ عَمْرَو بْنَ عَبْدِ اللَّهِ بْنِ صَفْوَانَ أَخْبَرَهُ أَنَّ كَلَدَةَ بْنَ حَنْبَلٍ أَخْبَرَهُأَنَّ صَفْوَانَ بْنَ أُمَيَّةَ بَعَثَهُ بِلَبَنٍ وَلِبَإٍ وَضَغَابِيسَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَعْلَى الْوَادِي قَالَ فَدَخَلْتُ عَلَيْهِ وَلَمْ أُسَلِّمْ وَلَمْ أَسْتَأْذِنْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْجِعْ فَقُلْ السَّلَامُ عَلَيْكُمْ أَأَدْخُلُ وَذَلِكَ بَعْدَ مَا أَسْلَمَ صَفْوَانُقَالَ عَمْرٌو وَأَخْبَرَنِي بِهَذَا الْحَدِيثِ أُمَيَّةُ بْنُ صَفْوَانَ وَلَمْ يَقُلْ سَمِعْتُهُ مِنْ كَلَدَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ ابْنِ جُرَيْجٍ وَرَوَاهُ أَبُو عَاصِمٍ أَيْضًا عَنْ ابْنِ جُرَيْجٍ مِثْلَ هَذَا","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [Rauh bin 'Ubadah] dari [Ibnu Juraij] telah mengabarkan kepadaku ['Amru bin Abu Sufyan] bahwa ['Amru bin Abdullah bin Sufwan] telah mengabarkan kepadanya bahwa [Kaladah bin Hambal] telah mengabarkan kepadanya bahwa Sufwan bin Umayyah mengutusnya untuk membawa susu, susu yang baru di perah dan mentimun kepada Nabi shallallahu 'alaihi wasallam, sedangkan Nabi shallallahu 'alaihi wasallam tengah berada di atas lembah, \" Kaldah berkata; \"Kemudian aku menemui beliau tanpa mengucapkan salam dan tanpa izin, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Kembalilah dan ucapkan: Assalaamu'alaikum, apakah aku boleh masuk?\" peristiwa itu terjadi setelah Shufwan masuk Islam.\" 'Amru berkata; telah mengabarkan kepadaku ['Umayyah bin Shufwan] dengan hadits ini, namun dia tidak mengatakan; \"Aku telah mendengarnya dari Kaladah. Abu Isa berkata; Hadits ini hasan gharib, kami tidak mengetahuinya kecuali dari hadits Ibnu Juraij, dan [Abu 'Ashim] juga telah meriwayatkan dari [Ibnu Juraij] hadits seperti ini."},"2568":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ أَنْبَأَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَاسْتَأْذَنْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي دَيْنٍ كَانَ عَلَى أَبِي فَقَالَ مَنْ هَذَا فَقُلْتُ أَنَا فَقَالَ أَنَا أَنَا كَأَنَّهُ كَرِهَ ذَلِكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengabarkan kepada kami [Ibnu Al Mubarak] telah memberitakan kepada kami [Syu'bah] dari [Muhammad bin Al Munkadir] dari [Jabir] ia berkata; \"Aku meminta izin kepada Nabi shallallahu 'alaihi wasallam karena hutang yang menimpa ayahku, beliau bertanya: \"Siapa itu?\" aku menjawab; \"Saya.\" Beliau bersabda: \"Saya, saya.\" Sepertinya beliau membencinya. Abu Isa berkata; Hadits ini hasan shahih."},"2569":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ نُبَيْحٍ الْعَنَزِيِّ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَاهُمْ أَنْ يَطْرُقُوا النِّسَاءَ لَيْلًاوَفِي الْبَاب عَنْ أَنَسٍ وَابْنِ عُمَرَ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ رُوِيَ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَاهُمْ أَنْ يَطْرُقُوا النِّسَاءَ لَيْلًا قَالَ فَطَرَقَ رَجُلَانِ بَعْدَ نَهْيِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ كُلُّ وَاحِدٍ مِنْهُمَا مَعَ امْرَأَتِهِ رَجُلًا","id":"Telah mengabarkan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Al Aswad bin Qais] dari [Nubaih Al Anbari] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam melarang para sahabat datang menemui para istri pada malam hari.\" Dan dalam bab ini ada hadits serupa dari Anas, Ibnu Umar dan Ibnu Abbas. Abu Isa berkata; Hadits ini hasan shahih, telah diriwayatkan dari beberapa jalur dari Jabir dari Nabi shallallahu 'alaihi wasallam, telah diriwayatkan dari Ibnu Abbas bahwa Nabi shallallahu 'alaihi wasallam melarang para sahabat datang menemui para istri pada malam hari. Ibnu Abbas berkata; \"Ada dua orang lelaki yang datang di waktu malam setelah ada larangan dari Nabi shallallahu 'alaihi wasallam, ternyata masing-masing dari mereka mendapatkan istrinya sedang bersama lelaki lain.\""},"2570":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا شَبَابَةُ عَنْ حَمْزَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَتَبَ أَحَدُكُمْ كِتَابًا فَلْيُتَرِّبْهُ فَإِنَّهُ أَنْجَحُ لِلْحَاجَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ مُنْكَرٌ لَا نَعْرِفُهُ عَنْ أَبِي الزُّبَيْرِ إِلَّا مِنْ هَذَا الْوَجْهِ قَالَ وَحَمْزَةُ هُوَ عِنْدِي ابْنُ عَمْرٍو النَّصِيبِيُّ هُوَ ضَعِيفٌ فِي الْحَدِيثِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Syababah] dari [Hamzah] dari [Abu Az Zubair] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian menulis surat, maka hendaknya ia merendahkan diri, karena hal itu akan lebih mengena kepada yang dimaksud.\" Abu Isa berkata; Hadits ini munkar, kami tidak mengetahuinya dari Abu Az Zubair kecuali dari jalur ini, dia berkata; Hamzah menurutku adalah Ibnu 'Amru An Nashibi, dia lemah dalam masalah hadits."},"2571":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْحَارِثِ عَنْ عَنْبَسَةَ عَنْ مُحَمَّدِ بْنِ زَاذَانَ عَنْ أُمِّ سَعْدٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَدَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ يَدَيْهِ كَاتِبٌ فَسَمِعْتُهُ يَقُولُ ضَعْ الْقَلَمَ عَلَى أُذُنِكَ فَإِنَّهُ أَذْكَرُ لِلْمُمْلِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَهُوَ إِسْنَادٌ ضَعِيفٌ وَعَنْبَسَةُ بْنُ عَبْدِ الرَّحْمَنِ وَمُحَمَّدُ بْنُ زَاذَانَ يُضَعَّفَانِ فِي الْحَدِيثِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdullah bin Al Harits] dari [Anbasah] dari [Muhammad bin Zadzan] dari [Ummu Sa'd] dari [Zaid bin Tsabit] ia berkata; Aku masuk menemui Rasulullah shallallahu 'alaihi wasallam, sementara di hadapan beliau terdapat seorang juru tulis, aku mendengar beliau berkata; \"Letakkanlah pena di atas telingamu karena itu dapat menguatkan ingatan orang yang mendikte.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari jalur ini dan sanad ini lemah. Anbasah bin Abdurrahman dan Muhammad bin Zadzan dilemahkan dalam masalah hadits."},"2572":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ خَارِجَةَ بْنِ زَيْدِ بْنِ ثَابِتٍ عَنْ أَبِيهِ زَيْدِ بْنِ ثَابِتٍ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَتَعَلَّمَ لَهُ كَلِمَاتٍ مِنْ كِتَابِ يَهُودَ قَالَ إِنِّي وَاللَّهِ مَا آمَنُ يَهُودَ عَلَى كِتَابِي قَالَ فَمَا مَرَّ بِي نِصْفُ شَهْرٍ حَتَّى تَعَلَّمْتُهُ لَهُ قَالَ فَلَمَّا تَعَلَّمْتُهُ كَانَ إِذَا كَتَبَ إِلَى يَهُودَ كَتَبْتُ إِلَيْهِمْ وَإِذَا كَتَبُوا إِلَيْهِ قَرَأْتُ لَهُ كِتَابَهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ هَذَا الْوَجْهِ عَنْ زَيْدِ بْنِ ثَابِتٍ رَوَاهُ الْأَعْمَشُ عَنْ ثَابِتِ بْنِ عُبَيْدٍ الْأَنْصَارِيِّ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَ أَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَتَعَلَّمَ السُّرْيَانِيَّةَ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Abdurrahman bin Abu Az Zinad] dari [Ayahnya] dari [Kharijah bin Zaid bin Tsabit] dari ayahnya yaitu [Zaid bin Tsabit] ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkanku mempelajari bahasa orang-orang Yahudi untuk beliau, beliau bersabda: \"Demi Allah, aku tidak percaya Yahudi atas suratku.\" Zaid berkata; \"Setengah bulan berlalu hingga aku dapat menguasainya untuk beliau.\" Saat aku mengusainya, apabila beliau hendak mengirim surat kepada orang-orang Yahudi, aku menulisnya kepada mereka dan apabila mereka mengirim surat kepada beliau, maka aku membacakan surat mereka untuk beliau.\" Abu Isa berkata; Hadits ini shahih. Diriwayatkan melalui sanad lain dari Zaid bin Tsabit. Diriwayatkan oleh [Al A'masy] dari [Tsabit bin Ubaid Al Anshari] dari [Zaid bin Tsabit] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkanku untuk mempelajari bahasa Suryani.\""},"2573":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ حَمَّادٍ الْبَصْرِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ قَبْلَ مَوْتِهِ إِلَى كِسْرَى وَإِلَى قَيْصَرَ وَإِلَى النَّجَاشِيِّ وَإِلَى كُلِّ جَبَّارٍ يَدْعُوهُمْ إِلَى اللَّهِ وَلَيْسَ بِالنَّجَاشِيِّ الَّذِي صَلَّى عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Yusuf bin Hammad Al Bashri] telah menceritakan kepada kami [Abdul A'la] dari [Sa'id] dari [Qatadah] dari [Anas] bahwa sebelum wafatnya Rasulullah shallallahu 'alaihi wasallam, beliau sempat menulis surat kepada Kisra (raja persi), Kaisar (raja Romawi), Najasyi dan kepada setiap penguasa diktator, beliau menyeru mereka (beriman) kepada Allah, bukankah raja Najasyi pernah di shalati oleh Nabi shallallahu 'alaihi wasallam?.\" Abu Isa berkata; Hadits ini hasan shahih gharib."},"2574":{"ar":"حَدَّثَنَا سُوَيْدٌ أَنْبَأَنَا عَبْدُ اللَّهِ أَنْبَأَنَا يُونُسُ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ أَخْبَرَهُ أَنَّ أَبَا سُفْيَانَ بْنَ حَرْبٍ أَخْبَرَهُأَنَّ هِرَقْلَ أَرْسَلَ إِلَيْهِ فِي نَفَرٍ مِنْ قُرَيْشٍ وَكَانُوا تُجَّارًا بِالشَّامِ فَأَتَوْهُ فَذَكَرَ الْحَدِيثَ قَالَ ثُمَّ دَعَا بِكِتَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُرِئَ فَإِذَا فِيهِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ مِنْ مُحَمَّدٍ عَبْدِ اللَّهِ وَرَسُولِهِ إِلَى هِرَقْلَ عَظِيمِ الرُّومِ السَّلَامُ عَلَى مَنْ اتَّبَعَ الْهُدَى أَمَّا بَعْدُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو سُفْيَانَ اسْمُهُ صَخْرُ بْنُ حَرْبٍ","id":"Telah menceritakan kepada kami [Suwaid] telah menceritakan kepada kami [Abdullah] telah memberitakan kepada kami [Yunus] dari [Az Zuhri] telah mengabarkan kepadaku [Ubaidullah bin Abdullah] dari [Ibnu Abbas] bahwa dia menceritakan kepadanya bahwa [Abu Sufyan bin Harb] menceritakan kepadanya bahwa Hiraklius (raja Romawi) mengutus seseorang menmeuinya ketika ia bersama sekelompok orang-orang Quraisy dan mereka adalah para pedagang di Syam, setelah itu mereka mendatangi Heraklius, lalu dia menyebutkan hadits, Abu Sufyan berkata; kemudian Heraklius meminta surat dari Rasulullah shallallahu 'alaihi wasallam, ketika dibaca di dalamnya tertulis: \"BISMILLAAHIR RAHMAANIR RAHIIM (dengan nama Allah yang maha pengasih lagi maha penyayang), dari Muhammad hamba Allah dan RasulNya, kepada Hiraklius raja Romawi, salam keselamatan bagi orang yang mengikuti petunjuk, amma ba'du.\" Abu Isa berkata; Hadits ini hasan shahih, nama Abu Sufyan adalah Shakhr bin Harb."},"2575":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا أَرَادَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَكْتُبَ إِلَى الْعَجَمِ قِيلَ لَهُ إِنَّ الْعَجَمَ لَا يَقْبَلُونَ إِلَّا كِتَابًا عَلَيْهِ خَاتَمٌ فَاصْطَنَعَ خَاتَمًا قَالَ فَكَأَنِّي أَنْظُرُ إِلَى بَيَاضِهِ فِي كَفِّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [Ayahku] dari [Qatadah] dari [Anas bin Malik] ia berkata; \"Saat Nabi Allah shallallahu 'alaihi wasallam hendak mengirim surat kepada bangsa ajam (non Arab), dikatakan kepada beliau: \"Sesungguhnya orang-orang ajam (non Arab) tidak mau menerima surat kecuali telah di bubuhi stempel. Beliau pun membuat stempel (cincin).\" Anas berkata; \"Sepertinya aku melihat putihnya telapak tangan beliau.\" Abu Isa berkata; Hadits ini hasan shahih."},"2576":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ حَدَّثَنَا ابْنُ أَبِي لَيْلَى عَنْ الْمِقْدَادِ بْنِ الْأَسْوَدِ قَالَأَقْبَلْتُ أَنَا وَصَاحِبَانِ لِي قَدْ ذَهَبَتْ أَسْمَاعُنَا وَأَبْصَارُنَا مِنْ الْجَهْدِ فَجَعَلْنَا نَعْرِضُ أَنْفُسَنَا عَلَى أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَيْسَ أَحَدٌ يَقْبَلُنَا فَأَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَى بِنَا أَهْلَهُ فَإِذَا ثَلَاثَةُ أَعْنُزٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَلِبُوا هَذَا اللَّبَنَ بَيْنَنَا فَكُنَّا نَحْتَلِبُهُ فَيَشْرَبُ كُلُّ إِنْسَانٍ نَصِيبَهُ وَنَرْفَعُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَصِيبَهُ فَيَجِيءُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ اللَّيْلِ فَيُسَلِّمُ تَسْلِيمًا لَا يُوقِظُ النَّائِمَ وَيُسْمِعُ الْيَقْظَانَ ثُمَّ يَأْتِي الْمَسْجِدَ فَيُصَلِّي ثُمَّ يَأْتِي شَرَابَهُ فَيَشْرَبُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah bin Al Mubarak] telah mengabarkan kepada kami [Sulaiman bin Al Mughirah] telah menceritakan kepada kami [Tsabit Al Banani] telah menceritakan kepada kami [Ibnu Abu Laila] dari [Al Miqdad bin Al Aswad] ia berkata; Aku pergi bersama dua temanku, pendengaran dan penglihatan kami sudah tiada karena faktor keletihan (karena kelaparan), kami menawarkan diri kepada para sahabat nabi shallallahu 'alaihi wasallam, tapi tidak seorang pun menerima kami, lalu kami mendatangi Nabi shallallahu 'alaihi wasallam, maka beliau membawa kami menuju keluarga beliau, di sana ada tiga kambing, nabi shallallahu 'alaihi wasallam bersabda: \"Perahlah susu ini untuk kita.\" Kami memerahnya lalu masing-masing meminum bagiannya, kami mengangkat bagian Rasulullah shallallahu 'alaihi wasallam, pada malam harinya Rasulullah shallallahu 'alaihi wasallam tiba, beliau mengucapkan salam dengan salam yang tidak membangunkan orang tidur dan bisa didengar oleh yang terjaga. Setelah itu beliau pergi ke masjid lalu shalat, selanjutnya beliau mendatangi minuman beliau kemudian meminumnya. Abu Isa berkata; Hadits ini hasan shahih."},"2577":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَنَصْرُ بْنُ عَلِيٍّ قَالَا حَدَّثَنَا أَبُو أَحْمَدَ عَنْ سُفْيَانَ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا سَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَبُولُ فَلَمْ يَرُدَّ عَلَيْهِ يَعْنِي السَّلَامَحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى النَّيْسَابُورِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ الضَّحَّاكِ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَفِي الْبَاب عَنْ عَلْقَمَةَ ابْنِ الْفَغْوَاءِ وَجَابِرٍ وَالْبَرَاءِ وَالْمُهَاجِرِ بْنِ قُنْفُذٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] dan [Nashr bin Ali] keduanya berkata; telah menceritakan kepada kami [Abu Ahmad] dari [Sufyan] dari [Adl Dlahhak bin Utsman] dari [Nafi] dari [Ibnu Umar] bahwa seseorang mengucapkan salam kepada Nabi shallallahu 'alaihi wasallam saat beliau kencing, namun beliau tidak membalasnya -yaitu membalas salam.- Telah menceritakan kepada kami [Muhammad bin Yahya An Naisaburi] telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Adl Dlahhak] dengan sanad seperti ini. Dalam hal ini ada hadits serupa dari 'Alqmah bin Al Faghwa`, Jabir, Barra` dan Al Muhajir bin Qunfudz. Abu Isa berkata; Hadits ini hasan shahih."},"2578":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي تَمِيمَةَ الْهُجَيْمِيِّ عَنْ رَجُلٍ مِنْ قَوْمِهِ قَالَطَلَبْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ أَقْدِرْ عَلَيْهِ فَجَلَسْتُ فَإِذَا نَفَرٌ هُوَ فِيهِمْ وَلَا أَعْرِفُهُ وَهُوَ يُصْلِحُ بَيْنَهُمْ فَلَمَّا فَرَغَ قَامَ مَعَهُ بَعْضُهُمْ فَقَالُوا يَا رَسُولَ اللَّهِ فَلَمَّا رَأَيْتُ ذَلِكَ قُلْتُ عَلَيْكَ السَّلَامُ يَا رَسُولَ اللَّهِ عَلَيْكَ السَّلَامُ يَا رَسُولَ اللَّهِ عَلَيْكَ السَّلَامُ يَا رَسُولَ اللَّهِ قَالَ إِنَّ عَلَيْكَ السَّلَامُ تَحِيَّةُ الْمَيِّتِ إِنَّ عَلَيْكَ السَّلَامُ تَحِيَّةُ الْمَيِّتِ ثَلَاثًا ثُمَّ أَقْبَلَ عَلَيَّ فَقَالَ إِذَا لَقِيَ الرَّجُلُ أَخَاهُ الْمُسْلِمَ فَلْيَقُلْ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ ثُمَّ رَدَّ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَعَلَيْكَ وَرَحْمَةُ اللَّهِ وَعَلَيْكَ وَرَحْمَةُ اللَّهِ وَعَلَيْكَ وَرَحْمَةُ اللَّهِقَالَ أَبُو عِيسَى وَقَدْ رَوَى هَذَا الْحَدِيثَ أَبُو غِفَارٍ عَنْ أَبِي تَمِيمَةَ الْهُجَيْمِيِّ عَنْ أَبِي جُرَيٍّ جَابِرِ بْنِ سُلَيْمٍ الْهُجَيْمِيِّ قَالَ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ وَأَبُو تَمِيمَةَ اسْمُهُ طَرِيفُ بْنُ مُجَالِدٍ","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Khalid Al Hadza`] dari [Abu Tamimah Al Hujaimi] dari [salah seorang kaumnya], dia berkata; Aku mencari Nabi shallallahu 'alaihi wasallam, namun aku tidak menemukan beliau. Ketika aku duduk, tiba-tiba ada seseorang berada di tengah kumpulan orang-orang, namun saya tidak mengenalnya, menetara dia tengah mendamaikan di antara mereka. Setelah itu, sebagian di antara mereka berdiri bersamanya, lalu mereka berkata; \"Wahai Rasulullah, \" melihat seperti itu aku langsung mengucapkan; \"'ALAIKAS SALAM wahai Rasulullah, 'ALAIKAS SALAM wahai Rasulullah, 'ALAIKAS SALAM wahai Rasulullah.\" Beliau lalu bersabda: \"Sesungguhnya 'ALAIKAS SALAM ucapan untuk orang yang telah meninggal.\" -beliau mengucapkannya hingga tiga kali- kemudian beliau menghadapku sambil bersabda: \"Apabila salah seorang bertemu dengan saudaranya semuslim, hendaknya ia mengucapkan; \"ASSALAAMU 'ALAIKUM WARAHMATULLAH.\" Setelah itu Nabi shallallahu 'alaihi wasallam menjawab salamku, beliau mengucapkan: \"WA 'ALAIKA WARAHMATULLAH, WA 'ALAIKA WARAHMATULLAH, WA 'ALAIKA WARAHMATULLAH.\" Abu Isa berkata; [Abu Ghifar] telah meriwayatkan hadits ini dari [Abu Tamimah Al Hujaimi] dari [Abu Jurai Jabir bin Sulaim Al Hujaimi], dia berkata; aku datang menemui Nabi shallallahu 'alaihi wasallam, lalu dia menyebutkan hadits, Abu Tamimah namanya adalah Tharif bin Mujalid."},"2579":{"ar":"حَدَّثَنَا بِذَلِكَ الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ أَبِي غِفَارٍ الْمُثَنَّى بْنِ سَعِيدٍ الطَّائِيِّ عَنْ أَبِي تَمِيمَةَ الْهُجَيْمِيِّ عَنْ جَابِرِ بْنِ سُلَيمٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ عَلَيْكَ السَّلَامُ فَقَالَ لَا تَقُلْ عَلَيْكَ السَّلَامُ وَلَكِنْ قُلْ السَّلَامُ عَلَيْكَوَذَكَرَ قِصَّةً طَوِيلَةً وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami seperti itu [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami [Abu Usamah] dari [Abu Ghifar Al Mutsanna bin Sa'id Ath Tha`i] dari [Abu Tamimah Al Hujaimi] dari [Jabir bin Sulaim] ia berkata; Aku datang menemui Nabi shallallahu 'alaihi wasallam sambil mengucapkan; 'ALAIKASSALAAM.\" Beliau bersabda: \"Jangan ucapkan 'ALAIKASSALAAM, tapi ucapkanlah; ASSALAAMU 'ALAIKA.\" Lalu perawi menyebutkan kisah yang panjang. Dan hadits ini hasan shahih."},"2580":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُثَنَّى حَدَّثَنَا ثُمَامَةُ بْنُ عَبْدِ اللَّهِ بْنِ أَنَسِ بْنِ مَالِكٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَلَّمَ سَلَّمَ ثَلَاثًا وَإِذَا تَكَلَّمَ بِكَلِمَةٍ أَعَادَهَا ثَلَاثًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Abdushshamad bin Abdul Warits] telah menceritakan kepada kami [Abdullah bin Al Mutsanna] telah menceritakan kepada kami [Tsumamah bin Abdullah bin Anas bin Malik] dari [Anas bin Malik], bahwa apabila Rasulullah shallallahu 'alaihi wasallam mengucap salam, beliau mengucap salam sebanyak tiga kali dan apabila mengucapkan suatu kalimat beliau mengulanginya sampai tiga kali.\" Abu Isa berkata; Hadits ini hasan shahih gharib. "},"2581":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَبِي مُرَّةَ مَوْلَى عَقِيلِ بْنِ أَبِي طَالِبٍ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا هُوَ جَالِسٌ فِي الْمَسْجِدِ وَالنَّاسُ مَعَهُ إِذْ أَقْبَلَ ثَلَاثَةُ نَفَرٍ فَأَقْبَلَ اثْنَانِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَهَبَ وَاحِدٌ فَلَمَّا وَقَفَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلَّمَا فَأَمَّا أَحَدُهُمَا فَرَأَى فُرْجَةً فِي الْحَلْقَةِ فَجَلَسَ فِيهَا وَأَمَّا الْآخَرُ فَجَلَسَ خَلْفَهُمْ وَأَمَّا الْآخَرُ فَأَدْبَرَ ذَاهِبًا فَلَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ عَنْ النَّفَرِ الثَّلَاثَةِ أَمَّا أَحَدُهُمْ فَأَوَى إِلَى اللَّهِ فَأَوَاهُ اللَّهُ وَأَمَّا الْآخَرُ فَاسْتَحْيَا فَاسْتَحْيَا اللَّهُ مِنْهُ وَأَمَّا الْآخَرُ فَأَعْرَضَ فَأَعْرَضَ اللَّهُ عَنْهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو وَاقِدٍ اللَّيْثِيُّ اسْمُهُ الْحَارِثُ بْنُ عَوْفٍ وَأَبُو مُرَّةَ مَوْلَى أُمِّ هَانِئٍ بِنْتِ أَبِي طَالِبٍ وَاسْمُهُ يَزِيدُ وَيُقَالُ مَوْلَى عَقِيلِ بْنِ أَبِي طَالِبٍ","id":"Telah menceritakan kepada kami [Al Anshari] telah menceritakan kepada kami [Ma'n] telah menceritakan kepada kami [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Abu Murrah] bekas budak Uqail bin Abu Thalib, dari [Abu Waqid Al Laitsi], bahwa ketika Rasulullah shallallahu 'alaihi wasallam duduk di masjid sedangkan orang-orang tengah bersama beliau, tiba-tiba tiga orang datang, dua orang menghadap Rasulullah shallallahu 'alaihi wasallam sementara yang satunya pergi. Saat keduanya berdiri dihadapan Rasulullah shallallahu 'alaihi wasallam, keduanya mengucap salam. Salah satunya melihat celah di halaqah lalu duduk di celah itu, yang satunya duduk di belakang mereka sementara yang lain pergi berpaling. Setelah Rasulullah shallallahu 'alaihi wasallam usai, beliau bersabda: \"Maukah aku beritahukan kepada kalian tentang tiga orang itu? Salah satunya berlindung kepada Allah lalu Allah memberinya perlindungan, yang lain merasa malu lalu Allah malu padanya, sedang yang lain berpaling, maka Allah berpaling darinya.\" Abu Isa berkata; Hadits ini hasan shahih. Abu Waqid Al Laitsi namanya adalah Al Harits bin 'Auf. Abu Murrah adalah bekas budak milik Ummu Hani` binti Abu Thalib, namanya adalah Yazid, ada yang mengatakan dia adalah budak milik 'Uqail bin Abu Thalib.\""},"2582":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا شَرِيكٌ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكُنَّا إِذَا أَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَلَسَ أَحَدُنَا حَيْثُ يَنْتَهِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَقَدْ رَوَاهُ زُهَيْرُ بْنُ مُعَاوِيَةَ عَنْ سِمَاكٍ أَيْضًا","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Syarik] dari [Simak bin Harb] dari [Jabir bin Samurah] ia berkata; Apabila kami datang kepada Nabi shallallahu 'alaihi wasallam, maka salah seorang dari kami duduk hingga di tempat yang paling akhir.\" Hadits ini hasan shahih gharib, [Zuhair bin Mu'awiyah] juga telah meriwayatkannya dari [Simak]."},"2583":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ وَلَ��ْ يَسْمَعْهُ مِنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِنَاسٍ مِنْ الْأَنْصَارِ وَهُمْ جُلُوسٌ فِي الطَّرِيقِ فَقَالَ إِنْ كُنْتُمْ لَا بُدَّ فَاعِلِينَ فَرُدُّوا السَّلَامَ وَأَعِينُوا الْمَظْلُومَ وَاهْدُوا السَّبِيلَوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي شُرَيْحٍ الْخُزَاعِيِّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Barra`] tapi ia tidak mendengar hadits ini dari Abu Ishaq, bahwa Rasulullah shallallahu 'alaihi wasallam pernah melewati sekelompok orang Anshar, sementara mereka tengah duduk-duduk di (pinggir) jalanan, maka beliau bersabda: \"Bila kalian masih tetap melakukannya (duduk di pinggit jalan), jawablah salam, tolonglah orang yang didzalimi dan tunjukkan jalan.\" Dalam hal ini ada hadits serupa dari Abu Hurairah dan Abu Syuraih Al Khuza'i. Abu Isa berkata; Hadits ini hasan gharib."},"2584":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ وَإِسْحَقُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ الْأَجْلَحِ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مُسْلِمَيْنِ يَلْتَقِيَانِ فَيَتَصَافَحَانِ إِلَّا غُفِرَ لَهُمَا قَبْلَ أَنْ يَفْتَرِقَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ الْبَرَاءِ مِنْ غَيْرِ وَجْهٍ وَالْأَجْلَحُ هُوَ ابْنُ عَبْدِ اللَّهِ بْنِ حُجَيَّةَ بْنِ عَدِيٍّ الْكِنْدِيُّ","id":"Telah menceritakan kepada kami [Sufyan bin Waqi'] dan [Ishaq bin Manshur] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Numair] dari [Al 'Ajlah] dari [Abu Ishaq] dari [Al Barra` bin 'Azib] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah dua orang muslim yang bertemu kemudian saling berjabat tangan, kecuali dosa keduanya akan diampuni sebelum berpisah.\" Abu Isa berkata; Hadits ini hasan gharib dari hadits Abu Ishaq dari Al Barra`. Dan hadits ini diriwayatkan dari Al Barra` dari jalur sanad lain. Al 'Ajlah adalah Ibnu Abdullah bin Hujayyah bin Adi Al Kindi."},"2585":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا حَنْظَلَةُ بْنُ عُبَيْدِ اللَّهِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ الرَّجُلُ مِنَّا يَلْقَى أَخَاهُ أَوْ صَدِيقَهُ أَيَنْحَنِي لَهُ قَالَ لَا قَالَ أَفَيَلْتَزِمُهُ وَيُقَبِّلُهُ قَالَ لَا قَالَ أَفَيَأْخُذُ بِيَدِهِ وَيُصَافِحُهُ قَالَ نَعَمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Handlalah bin 'Ubaidillah] dari [Anas bin Malik] ia berkata; Seseorang bertanya; \"Wahai Rasulullah, apakah kami harus menundukkan kepala apabila salah seorang dari kami bertemu dengan saudaranya atau sahabatnya?\" beliau menjawab: \"Tidak.\" Ia bertanya; \"Apakah dia harus mendekap dan menciumnya?\" beliau menjawab: \"Tidak.\" Orang itu bertanya lagi; \"Apakah harus meraih tangannya dan menjabatnya?\" beliau menjawab: \"Ya.\" Abu Isa berkata; Hadits ini hasan shahih."},"2586":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا هَمَّامٌ عَنْ قَتَادَةَ قَالَ قُلْتُ لِأَنَسِ بْنِ مَالِكٍهَلْ كَانَتْ الْمُصَافَحَةُ فِي أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Hammam] dari [Qatadah] ia berkata; Aku bertanya kepada [Anas]; \"Apakah di antara sahabat-sahabat Rasulullah shallallahu 'alaihi wasallam biasa berjabat tangan?\" Dia menjawab; \"Ya.\" Abu Isa berkata; Hadits ini hasan shahih."},"2587":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ الطَّائِفِيُّ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ خَيْثَمَةَ عَنْ رَجُلٍ عَنْ ابْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِنْ تَمَامِ التَّحِيَّةِ الْأَخْذُ بِالْيَدِوَفِي الْبَاب عَنْ الْبَرَاءِ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَلَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ يَحْيَى بْنِ سُلَيْمٍ عَنْ سُفْيَانَ سَأَلْتُ مُحَمَّدَ بْنَ إِسْمَعِيلَ عَنْ هَذَا الْحَدِيثِ فَلَمْ يَعُدَّهُ مَحْفُوظًا و قَالَ إِنَّمَا أَرَادَ عِنْدِي حَدِيثَ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ خَيْثَمَةَ عَمَّنْ سَمِعَ ابْنَ مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا سَمَرَ إِلَّا لِمُصَلٍّ أَوْ مُسَافِرٍ قَالَ مُحَمَّدٌ وَإِنَّمَا يُرْوَى عَنْ مَنْصُورٍ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ أَوْ غَيْرِهِ قَالَ مِنْ تَمَامِ التَّحِيَّةِ الْأَخْذُ بِالْيَدِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah Adl Dlabbi] telah menceritakan kepada kami [Yahya bin Sulaim Ath Tha`i] dari [Sufyan] dari [Manshur] dari [Khaitsamah] dari [Seseorang] dari [Ibnu Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Termasuk kesempurnaan penghormatan adalah berjabat tangan.\" Dan dalam bab ini, ada hadits dari Al Barra` dan Ibnu Umar. Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari hadits Yahya bin Sulaim dari Sufyan. Aku bertanya kepada Muhammad bin Isma'il tentang hadits ini, dia tidak menganggapnya mahfudz (terjaga), Perawi berkata; \"Yang ia maksud menurutku adalah hadits Sufyan dari Manshur dari Khaitsamah dari orang yang pernah mendengar Ibnu Mas'ud dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada obrolan (setelah shalat isya`) kecuali bagi orang yang sedang shalat atau orang yang bepergian.\" Muhammad berkata; \"Sementara yang diriwayatkan dari Manshur dari Abu Ishaq dari Abdurrahman bin Yazid atau yang lainnya adalah hadits; \"Termasuk kesempurnaan penghormatan adalah menjabat tangan.\""},"2588":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ عَنْ عُبَيْدِ اللَّهِ بْنِ زَحْرٍ عَنْ عَلِيِّ بْنِ يَزِيدَ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ أَبِي أُمَامَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَمَامُ عِيَادَةِ الْمَرِيضِ أَنْ يَضَعَ أَحَدُكُمْ يَدَهُ عَلَى جَبْهَتِهِ أَوْ قَالَ عَلَى يَدِهِ فَيَسْأَلُهُ كَيْفَ هُوَ وَتَمَامُ تَحِيَّاتِكُمْ بَيْنَكُمْ الْمُصَافَحَةُقَالَ أَبُو عِيسَى هَذَا إِسْنَادٌ لَيْسَ بِالْقَوِيِّ قَالَ مُحَمَّدٌ وَعُبَيْدُ اللَّهِ بْنُ زَحْرٍ ثِقَةٌ وَعَلِيُّ بْنُ يَزِيدَ ضَعِيفٌ وَالْقَاسِمُ بْنُ عَبْدِ الرَّحْمَنِ يُكْنَى أَبَا عَبْدِ الرَّحْمَنِ وَهُوَ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ خَالِدِ بْنِ يَزِيدَ بْنِ مُعَاوِيَةَ وَهُوَ ثِقَةٌ وَالْقَاسِمُ شَامِيٌّ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yahya bin Ayyub] dari ['Ubaidullah bin Zahr] dari [Ali bin Yazid] dari [Al Qasim Abu Abdurrahman] dari [Abu Umamah] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Termasuk kesempurnaan menjenguk orang sakit adalah seseorang dari kalian meletakkan tangannya di atas dahinya -atau bersabda; Di atas tangannya- lalu menanyakan kabarnya, dan termasuk kesempurnaan penghormatan di antara kalian adalah berjabat tangan.\" Abu Isa berkata; Sanad ini tidak kuat. Muhammad berkata; 'Ubaidullah tsiqah dan Ali bin Yazid lemah. Qasim bin Abdurrahman kun-yah (julukannya) adalah Abu Abdurrahman yaitu bekas budak Abdurrahman bin Yazid bin Muawiyah, ia tsiqah, sedangkan Al Qasim adalah penduduk Syam.\""},"2589":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ يَحْيَى بْنِ مُحَمَّدِ بْنِ عَبَّادٍ الْمَدَنِيُّ حَدَّثَنِي أَبِي يَحْيَى بْنُ مُحَمَّدٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْقَدِمَ زَيْدُ بْنُ حَارِثَةَ الْمَدِينَةَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِي فَأَتَاهُ فَقَرَعَ الْبَابَ فَقَامَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُرْيَانًا يَجُرُّ ثَوْبَهُ وَاللَّهِ مَا رَأَيْتُهُ عُرْيَانًا قَبْلَهُ وَلَا بَعْدَهُ فَاعْتَنَقَهُ وَقَبَّلَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ الزُّهْرِيِّ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Ibrahim bin Yahya bin Muhammad bin 'Abbad Al Madani] telah menceritakan kepadaku [ayahku, Yahya bin Muhammad] dari [Muhammad bin Ishaq] dari [Muhammad bin Muslim Az Zuhri] dari ['Urwah bin Zubair] dari ['Aisyah] ia berkata; \"Zaid bin Haritsah tiba di Madinah, sementara Rasulullah sedang berada di rumahku, Zaid datang dan mengetuk pintu, lalu Rasulullah shallallahu 'alaihi wasallam berdiri menghampirinya dalam keadaan tidak mengenakan baju sambil menarik kainnya, demi Allah aku tidak pernah melihat beliau tidak mengenakan baju sebelum dan sesudahnya, lalu beliau mendekap Zaid dan menciuminya.\" Abu Isa berkata; Hadits ini hasan gharib, kami tidak mengetahuinya dari hadits Az Zuhri kecuali dari jalur ini."},"2590":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ وَأَبُو أُسَامَةَ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ سَلَمَةَ عَنْ صَفْوَانَ بْنِ عَسَّالٍ قَالَقَالَ يَهُودِيٌّ لِصَاحِبِهِ اذْهَبْ بِنَا إِلَى هَذَا النَّبِيِّ فَقَالَ صَاحِبُهُ لَا تَقُلْ نَبِيٌّ إِنَّهُ لَوْ سَمِعَكَ كَانَ لَهُ أَرْبَعَةُ أَعْيُنٍ فَأَتَيَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَاهُ عَنْ تِسْعِ آيَاتٍ بَيِّنَاتٍ فَقَالَ لَهُمْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا تَمْشُوا بِبَرِيءٍ إِلَى ذِي سُلْطَانٍ لِيَقْتُلَهُ وَلَا تَسْحَرُوا وَلَا تَأْكُلُوا الرِّبَا وَلَا تَقْذِفُوا مُحْصَنَةً وَلَا تُوَلُّوا الْفِرَارَ يَوْمَ الزَّحْفِ وَعَلَيْكُمْ خَاصَّةً الْيَهُودَ أَنْ لَا تَعْتَدُوا فِي السَّبْتِ قَالَ فَقَبَّلُوا يَدَهُ وَرِجْلَهُ فَقَالَا نَشْهَدُ أَنَّكَ نَبِيٌّ قَالَ فَمَا يَمْنَعُكُمْ أَنْ تَتَّبِعُونِي قَالُوا إِنَّ دَاوُدَ دَعَا رَبَّهُ أَنْ لَا يَزَالَ فِي ذُرِّيَّتِهِ نَبِيٌّ وَإِنَّا نَخَافُ إِنْ تَبِعْنَاكَ أَنْ تَقْتُلَنَا الْيَهُودُوَفِي الْبَاب عَنْ يَزِيدَ بْنِ الْأَسْوَدِ وَابْنِ عُمَرَ وَكَعْبِ بْنِ مَالِكٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abdullah bin Idris] dan [Abu Usamah] dari [Syu'bah] dari ['Amr bin Murrah] dari [Abdullah bin Salamah] dari [Shafwan bin 'Assal] ia berkata; \"Seorang Yahudi berkata kepada sahabatnya; \"Marilah kita berangkat bersama menemui Nabi ini!\" sahabatnya menjawab: \"Jangan katakan Nabi, sungguh apabila dia mendengar perkataanmu, maka dia akan memiliki empat mata (bahasa kiasan dari senang), \" lalu keduanya mendatangi Rasulullah shallallahu 'alaihi wasallam dan bertanya kepada beliau tentang sembilan ayat bayyinat, beliau bersabda kepada mereka: \"Janganlah kalian menyekutukan Allah dengan sesuatu apapun, jangan mencuri, jangan berzina, jangan membunuh jiwa yang diharamkan oleh Allah kecuali dengan benar, jangan menjelek-jelekkan orang yang tidak bersalah kepada penguasa agar penguasa membunuhnya, jangan melakukan sihir, jangan memakan riba, jangan menuduh (berbuat zina) wanita-wanita suci, jangan berpaling lari dari medan pertempuran, dan kepada kalian khususnya wahai orang-orang Yahudi, janganlah kalian melampaui batas pada hari sabtu.\" Shafwan berkata; Mereka langsung mencium kedua tangan dan kaki beliau, lalu keduanya mengatakan; \"Kami bersaksi bahwa engkau adalah Nabi.\" Beliau bertanya: \"Lalu apa yang menghalangi kalian tidak mengikutiku?\" Shafwan berkata; Mereka mengatakan: \"Sesungguhnya Nabi Daud berdo'a kepada Rabbnya agar senantiasa ada dari keturunannya seorang nabi, sesungguhnya kami takut jika mengikutimu orang-orang Yahudi akan membunuh kami.\" Dan dalam bab ini, ada hadits dari Yazid bin Al Aswad, Ibnu Umar dan Ka'ab bin Malik. Abu Isa berkata; Hadits ini hasan shahih."},"2591":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ أَبِي النَّضْرِ أَنَّ أَبَا مُرَّةَ مَوْلَى أُمِّ هَانِئِ بِنْتِ أَبِي طَالِبٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أُمَّ هَانِئٍ تَقُولُذَهَبْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ فَوَجَدْتُهُ يَغْتَسِلُ وَفَاطِمَةُ تَسْتُرُهُ بِثَوْبٍ قَالَتْ فَسَلَّمْتُ فَقَالَ مَنْ هَذِهِ قُلْتُ أَنَا أُمُّ هَانِئٍ فَقَالَ مَرْحَبًا بِأُمِّ هَانِئٍقَالَ فَذَكَرَ فِي الْحَدِيثِ قِصَّةً طَوِيلَةً هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] telah menceritakan kepada kami [Ma'n] telah menceritakan kepada kami [Malik] dari [Abu An Nadlr] bahwa [Abu Murrah] bekas budak Ummu Hani` binti Abu Thalib memberitahunya bahwa ia mendengar [Ummu Hani`] berkata; Aku pergi menemui Rasulullah shallallahu 'alaihi wasallam di tahun penaklukkan kota Makkah, aku menemui beliau, ketika beliau tengah mandi, sementara Fathimah menutupi beliau dengan sehelai kain. Ummu Hani' berkata; \"Aku lalu mengucapkan salam, beliau bertanya: \"Siapa itu?\" aku menjawab; \"Saya Ummu Hani`.\" Beliau bersabda: \"Selamat datang, Ummu Hani`.\" Perawi berkata; \"Lalu Dia menyebut kisah panjang dalam hadits ini. hadits ini hasan shahih.\""},"2592":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا مُوسَى بْنُ مَسْعُودٍ أَبُو حُذَيْفَةَ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ عِكْرِمَةَ بْنِ أَبِي جَهْلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ جِئْتُهُ مَرْحَبًا بِالرَّاكِبِ الْمُهَاجِرِوَفِي الْبَاب عَنْ بُرَيْدَةَ وَابْنِ عَبَّاسٍ وَأَبِي جُحَيْفَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَيْسَ إِسْنَادُهُ بِصَحِيحٍ لَا نَعْرِفُهُ مِثْلَ هَذَا إِلَّا مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ مُوسَى بْنِ مَسْعُودٍ عَنْ سُفْيَانَ وَمُوسَى بْنُ مَسْعُودٍ ضَعِيفٌ فِي الْحَدِيثِ وَرَوَى هَذَا الْحَدِيثَ عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ مُرْسَلًا وَلَمْ يَذْكُرْ فِيهِ عَنْ مُصْعَبِ بْنِ سَعْدٍ وَهَذَا أَصَحُّ قَالَ سَمِعْت مُحَمَّدَ بْنَ بَشَّارٍ يَقُولُ مُوسَى بْنُ مَسْعُودٍ ضَعِيفٌ فِي الْحَدِيثِ قَالَ مُحَمَّدُ بْنُ بَشَّارٍ وَكَتَبْتُ كَثِيرًا عَنْ مُوسَى بْنِ مَسْعُودٍ ثُمَّ تَرَكْتُهُ","id":"Telah menceritakan kepada kami ['Abdu bin Humaid] dan yang lainnya, mereka berkata; telah menceritakan kepada kami [Musa bin Mas'ud yaitu Abu Hudzaifah] dari [Sufyan] dari [Abu Ishaq] dari [Mush'ab bin Sa'd] dari [Ikrimah bin Abu Jahal] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda di saat aku menemui beliau: \"Selamat datang wahai pengendara yang berhijrah.\" Dan dalam bab ini, ada hadits dari Buraidah, Ibnu Abbas, dan Abu Juhaifah. Abu Isa berkata; Hadits ini sanadnya tidak shahih, kami tidak mengetahuinya seperti ini kecuali dari jalur ini dari haditsnya Musa bin Mas'ud dari Sufyan, sedangkan Musa bin Mas'ud adalah lemah dalam hadits, hadits ini juga telah diriwayatkan oleh [Abdurrahman bin Mahdi] dari [Sufyan] dari [Abu Ishaq] secara mursal, dan di dalam riwayatnya tidak disebutkan: Dari Mus'ab bin Sa'd, dan hadits ini lebih shahih. Abu Isa berkata; Aku telah mendengar Muhammad bin Basyar berkata; Musa bin Mas'ud lemah dalam hadits. Muhammad bin Basyar mengatakan; \"Aku menulis banyak hadits dari Musa bin Mas'ud, setelah itu aku meninggalkannya.\""},"2593":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمُسْلِمِ عَلَى الْمُسْلِمِ سِتٌّ بِالْمَعْرُوفِ يُسَلِّمُ عَلَيْهِ إِذَا لَقِيَهُ وَيُجِيبُهُ إِذَا دَعَاهُ وَيُشَمِّتُهُ إِذَا عَطَسَ وَيَعُودُهُ إِذَا مَرِضَ وَيَتْبَعُ جَنَازَتَهُ إِذَا مَاتَ وَيُحِبُّ لَهُ مَا يُحِبُّ لِنَفْسِهِوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي أَيُّوبَ وَالْبَرَاءِ وَأَبِي مَسْعُودٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ تَكَلَّمَ بَعْضُهُمْ فِي الْحَارِثِ الْأَعْوَرِ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abul Ahwas] dari [Abu Ishaq] dari [Al Harits] dari [Ali] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hak kebaikan seorang muslim atas muslim lainnya itu ada enam, yaitu; mengucapkan salam jika bertemu, memenuhi undangannya, mendo'akan YARHAMUKALLAAH (semoga Allah memberimu rahmat) apabila bersin, menjenguknya apabila sakit, mengiringi jenazahnya apabila meninggal dan mencintainya sebagaimana mencintai diri sendiri.\" Dan dalam bab ini, ada hadits dari Abu Hurairah, Abu Ayyub, Al Barra` dan Abu Mas'ud. Abu Isa berkata; Hadits ini hasan, dan telah diriwayatkan dari banyak jalur dari Nabi shallallahu 'alaihi wasallam, namun sebagian ulama membicarakan Al Harits Al A'war."},"2594":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى الْمَخْزُومِيُّ الْمَدَنِيُّ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمُؤْمِنِ عَلَى الْمُؤْمِنِ سِتُّ خِصَالٍ يَعُودُهُ إِذَا مَرِضَ وَيَشْهَدُهُ إِذَا مَاتَ وَيُجِيبُهُ إِذَا دَعَاهُ وَيُسَلِّمُ عَلَيْهِ إِذَا لَقِيَهُ وَيُشَمِّتُهُ إِذَا عَطَسَ وَيَنْصَحُ لَهُ إِذَا غَابَ أَوْ شَهِدَقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمُحَمَّدُ بْنُ مُوسَى الْمَخْزُومِيُّ الْمَدَنِيُّ ثِقَةٌ رَوَى عَنْهُ عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ وَابْنُ أَبِي فُدَيْكٍ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Muhammad bin Musa Al Makhzumi Al Madani] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hak seorang mukmin atas mukmin lainnya ada enam, yaitu; menjenguknya apabila sakit, mengiringi jenazahnya apabila meninggal, memenuhi undangannya, mengucapkan salam apabila bertemu, mendo'akan YARHAMUKALLAAH (semoga Allah memberimu rahmat) apabila bersin, dan menasehatinya apabila tidak hadir atau hadir.\" Perawi berkata; Hadits ini hasan shahih, adapun Muhammad bin Musa Al Makhzumi Al Madani adalah tsiqah, Abdul Aziz bin Muhammad dan Ibnu Abu Fudaik telah meriwayatkan hadits darinya."},"2595":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا زِيَادُ بْنُ الرَّبِيعِ حَدَّثَنَا حَضْرَمِيٌّ مَوْلَى الْجَارُودِ عَنْ نَافِعٍ أَنَّرَجُلًا عَطَسَ إِلَى جَنْبِ ابْنِ عُمَرَ فَقَالَ الْحَمْدُ لِلَّهِ وَالسَّلَامُ عَلَى رَسُولِ اللَّهِ قَالَ ابْنُ عُمَرَ وَأَنَا أَقُولُ الْحَمْدُ لِلَّهِ وَالسَّلَامُ عَلَى رَسُولِ اللَّهِ وَلَيْسَ هَكَذَا عَلَّمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَّمَنَا أَنْ نَقُولَ الْحَمْدُ لِلَّهِ عَلَى كُلِّ حَالٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ زِيَادِ بْنِ الرَّبِيعِ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] telah menceritakan kepada kami [Ziyad bin Rabi'] telah menceritakan kepada kami [Hadlrami] bekas budak Al Jarud, dari [Nafi'], bahwa seseorang bersin di sisi [Ibnu Umar] lalu dia mengucapkan \"ALHAMDULILLAAH WASSALAAMU 'ALAA RASUULILLAAH (segala puji bagi Allah dan keselamatan atas Rasulullah).\" Ibnu Umar menjawab; lalu aku berkata; \"ALHAMDULILLAAH WASSALAAMU 'ALAA RASUULILLAAH (segala puji bagi Allah dan keselamatan atas Rasulullah)?, bukan demikian Rasulullah shallallahu 'alaihi wasallam mengajarkan kepada kami, beliau mengajarkan kepada kami supaya mengucapkan; \"ALHAMDULILLAAH 'ALA KULLI HAAL (segala puji bagi Allah dalam kondisi apapun).\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari hadits Ziyad bin Ar Rabi'."},"2596":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ حَكِيمِ بْنِ دَيْلَمَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَكَانَ الْيَهُودُ يَتَعَاطَسُونَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْجُونَ أَنْ يَقُولَ لَهُمْ يَرْحَمُكُمْ اللَّهُ فَيَقُولُ يَهْدِيكُمُ اللَّهُ وَيُصْلِحُ بَالَكُمْوَفِي الْبَاب عَنْ عَلِيٍّ وَأَبِي أَيُّوبَ وَسَالِمِ بْنِ عُبَيْدٍ وَعَبْدِ اللَّهِ بْنِ جَعْفَرٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Hakim bin Dailam] dari [Abu Burdah] dari [Abu Musa] ia berkata; \"Orang-orang Yahudi bersin di sisi Nabi shallallahu 'alaihi wasallam dengan harapan beliau akan mengucapkan \"YARHAMUKUMULLAAH (semoga Allah merahmati kalian), \" Namun beliau mengucapkan: \"YAHDIIKUMULLAAH WA YUSHLIH BAALAKUM (semoga Allah memberikan hidayah kepada kalian dan memperbaiki kondisi kalian).\" Dan dalam bab ini, ada hadits semisal dari Ali, Abu Ayyub, Salim bin 'Ubaid, Abdullah bin Ja'far dan Abu Hurairah. Abu Isa berkata; Hadits ini hasan shahih."},"2597":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ سَالِمِ بْنِ عُبَيْدٍأَنَّهُ كَانَ مَعَ الْقَوْمِ فِي سَفَرٍ فَعَطَسَ رَجُلٌ مِنْ الْقَوْمِ فَقَالَ السَّلَامُ عَلَيْكُمْ فَقَالَ عَلَيْكَ وَعَلَى أُمِّكَ فَكَأَنَّ الرَّجُلَ وَجَدَ فِي نَفْسِهِ فَقَالَ أَمَا إِنِّي لَمْ أَقُلْ إِلَّا مَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَطَسَ رَجُلٌ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ السَّلَامُ عَلَيْكُمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكَ وَعَلَى أُمِّكَ إِذَا عَطَسَ أَحَدُكُمْ فَلْيَقُلْ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ وَلْيَقُلْ لَهُ مَنْ يَرُدُّ عَلَيْهِ يَرْحَمُكَ اللَّهُ وَلْيَقُلْ يَغْفِرُ اللَّهُ لَنَا وَلَكُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ اخْتَلَفُوا فِي رِوَايَتِهِ عَنْ مَنْصُورٍ وَقَدْ أَدْخَلُوا بَيْنَ هِلَالِ بْنِ يَسَافٍ وَسَالِمٍ رَجُلًا","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Ahmad Az Zubairi] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Hilal bin Yasaf] dari [Salim bin 'Ubaid] bahwa dia bersama suatu kaum dalam suatu perjalanan, lalu seseorang bersin dan mengucapkan; \"ASSALAAMU'ALAIKUM, \" Maka Salim menjawab; 'ALAIKA WA ALA UMMIKA, \" ternyata orang itu merasa tidak enak, maka Salim bertanya; \"Bukankah aku tidak mengucapkan selain yang dikatakan oleh Nabi shallallahu 'alaihi wasallam? Suatu kali seseorang bersin di sisi Nabi shallallahu 'alaihi wasallam, kemudian dia mengucapkan; \"ASSALAAMU'ALAIKUM, \" maka Nabi shallallahu 'alaihi wasallam menjawab: 'ALAIKA WA ALA UMMIKA (keselamatan atas kamu dan atas ibumu), \" jika salah seorang dari kalian bersin, hendaknya mengucapkan \"ALHAMDULILLAAHI RABBIL 'AALAMIIN (segala puji bagi Allah), \" dan orang yang menjawabnya mengucapkan \"YARHAMU KALLAAH (semoga Allah merahmatimu), \" kemudian ia mengucapkan \"YAGHFIRULLAAHU LANAA WA LAKUM (semoga Allah mengampuni kami dan kalian).\""},"2598":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَخْبَرَنَا شُعْبَةُ أَخْبَرَنِي ابْنُ أَبِي لَيْلَى عَنْ أَخِيهِ عِيسَى بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِي أَيُّوبَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا عَطَسَ أَحَدُكُمْ فَلْيَقُلْ الْحَمْدُ لِلَّهِ عَلَى كُلِّ حَالٍ وَلْيَقُلْ الَّذِي يَرُدُّ عَلَيْهِ يَرْحَمُكَ اللَّهُ وَلْيَقُلْ هُوَ يَهْدِيكُمُ اللَّهُ وَيُصْلِحُ بَالَكُمْحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ ابْنِ أَبِي لَيْلَى بِهَذَا الْإِسْنَادِ نَحْوَهُ قَالَ هَكَذَا رَوَى شُعْبَةُ هَذَا الْحَدِيثَ عَنْ ابْنِ أَبِي لَيْلَى عَنْ أَبِي أَيُّوبَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ ابْنُ أَبِي لَيْلَى يَضْطَرِبُ فِي هَذَا الْحَدِيثِ يَقُولُ أَحْيَانًا عَنْ أَبِي أَيُّوبَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَقُولُ أَحْيَانًا عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ يَحْيَى الثَّقَفِيُّ الْمَرْوَزِيُّ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ ابْنِ أَبِي لَيْلَى عَنْ أَخِيهِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Daud] telah mengabarkan kepada kami [Syu'bah] telah mengabarkan kepada kami [Ibnu Abu Laila] dari saudaranya yaitu [Isa bin Abdurrahman] dari [Abdurrahman bin Abu Laila] dari [Abu Ayyub] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian bersin, hendaknya dia mengucapkan \"ALHAMDULILLAAH 'ALA KULLI HAAL (segala puji bagi Allah dalam kondisi apapun), \" kemudian orang yang menjawabnya mengucapkan \"YARHAMUKALLAAH (semoga Allah merahmatimu), \" lalu dia membalas \"YAHDIKUMULLAAHU WA YUSLIH BAALAKUM (semoga Allah memberi petunjuk kepada kalian dan memperbaiki kondisi kalian).\" Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Ibnu Abu Laila] dengan sanad seperti ini. Abu Isa berkata; Demikianlah Syu'bah meriwayatkan hadits ini dari Ibnu Abu Laila dari Abu Ayyub dari Nabi shallallahu 'alaihi wasallam, Ibnu Abu Laila meriwayatkan hadits ini secara mudltharib (matan atau sanadnya berlawanan), terkadang mengatakan; Dari Abu Ayyub dari Nabi shallallahu 'alaihi wasallam, terkadang mengatakan; Dari Ali dari Nabi shallallahu 'alaihi wasallam.\" Telah menceritakan kepada kami [Muhammad bin Basyar] dan [Muhammad bin Yahya Ats Tsaqafi Al Marwazi] keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id Al Qattan] dari [Ibnu Abu Laila] dari saudaranya yaitu [Isa] dari [Abdurrahman bin Abu Laila] dari [Ali] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"2599":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلَيْنِ عَطَسَا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَمَّتَ أَحَدَهُمَا وَلَمْ يُشَمِّتْ الْآخَرَ فَقَالَ الَّذِي لَمْ يُشَمِّتْهُ يَا رَسُولَ اللَّهِ شَمَّتَّ هَذَا وَلَمْ تُشَمِّتْنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ حَمِدَ اللَّهَ وَإِنَّكَ لَمْ تَحْمَدْ اللَّهَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Sulaiman At Taimi] dari [Anas bin Malik], bahwa dua orang bersin di dekat nabi shallallahu 'alaihi wasallam, salah satunya didoakan oleh Rasulullah shallallahu 'alaihi wasallam, tapi yang lain tidak, lalu yang tidak didoakan berkata; \"Wahai Rasulullah, mengapa anda mendoakannya, dan tidak mendoakanku?.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ia memuji Allah sementara kamu tidak.\" Abu Isa berkata; Hadits ini hasan shahih. Hadits ini juga diriwayatkan dari Abu Hurairah dari nabi shallallahu 'alaihi wasallam."},"2600":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ عَنْ أَبِيهِ قَالَعَطَسَ رَجُلٌ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا شَاهِدٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْحَمُكَ اللَّهُ ثُمَّ عَطَسَ الثَّانِيَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا رَجُلٌ مَزْكُومٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ إِلَّا أَنَّهُ قَالَ لَهُ فِي الثَّالِثَةِ أَنْتَ مَزْكُومٌ قَالَ هَذَا أَصَحُّ مِنْ حَدِيثِ ابْنِ الْمُبَارَكِ وَقَدْ رَوَى شُعْبَةُ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ هَذَا الْحَدِيثَ نَحْوَ رِوَايَةِ يَحْيَى بْنِ سَعِيدٍ حَدَّثَنَا بِذَلِكَ أَحْمَدُ بْنُ الْحَكَمِ الْبَصْرِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ بِهَذَا وَرَوَى عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ نَحْوَ رِوَايَةِ ابْنِ الْمُبَارَكِ وَقَالَ لَهُ فِي الثَّالِثَةِ أَنْتَ مَزْكُومٌ حَدَّثَنَا بِذَلِكَ إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ikrimah bin 'Ammar] dari [Iyas bin Salamah] dari [Ayahnya] ia berkata; \"Seseorang bersin di dekat Rasulullah shallallahu 'alaihi wasallam dan saya menyaksikan hal itu, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah merahmatimu.\" Lalu ia bersin kedua kali, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang ini baru terserang pilek.\" Abu Isa berkata; Hadits ini hasan shahih. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Ikrimah bin 'Ammar] dari [Iyas bin Salamah] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam sepertinya hadits di atas, hanya saja ia menyebutkan (dengan redaksi), beliau bersabda padanya di kali yang ketiga: \"Engkau baru terserang pilek.\" Ini lebih shahih dari hadits Ibnu Al Mubarak. [Syu'bah] telah meriwayatkan hadits ini dari [Ikrimah bin 'Ammar] seperti riwayat Yahya bin Sa'id. Telah menceritakan kepada kami [Ahmad bin Al Hakam Al Bashri] seperti itu, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Ikrimah bin 'Ammar] seperti ini. [Abdurrahman bin Mahdi] juga telah meriwayatkan dari [Ikrimah bin 'Ammar] seperti riwayat Ibnu Al Mubarak, Beliau bersabda kepadanya pada kali ketiga: \"Engkau terserang pilek.\" Telah menceritakan kepada kami [Ishaq bin Manshur] seperti itu, telah menceritakan kepada kami [Abdurrahman bin Mahdi]."},"2601":{"ar":"حَدَّثَنَا الْقَاسِمُ بْنُ دِينَارٍ الْكُوفِيُّ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ السَّلُولِيُّ الْكُوفِيُّ عَنْ عَبْدِ السَّلَامِ بْنِ حَرْبٍ عَنْ يَزِيدَ بْنِ عَبْدِ الرَّحْمَنِ أَبِي خَالِدٍ عَنْ عُمَرَ بْنِ إِسْحَقَ بْنِ أَبِي طَلْحَةَ عَنْ أُمِّهِ عَنْ أَبِيهَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُشَمَّتُ الْعَاطِسُ ثَلَاثًا فَإِنْ زَادَ فَإِنْ شِئْتَ فَشَمِّتْهُ وَإِنْ شِئْتَ فَلَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَإِسْنَادُهُ مَجْهُولٌ","id":"Telah menceritakan kepada kami [Al Qasim bin Dinar Al Kufi] telah menceritakan kepada kami [Ishaq bin Manshur As Saluli Al Kufi] dari [Abdussalam bin Harb] dari [Yazid bin Abdurrahman Abu Khalid] dari [Umar bin Ishaq bin Abu Thalhah] dari [ibunya] dari [Ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang bersin mengucapkan do'a tiga kali, jika dia ingin menambah (mendo'akannya), silahkan menjawabnya dan jika tidak, maka tidak mengapa.\" Abu Isa berkata; Hadits ini gharib, dan isnadnya tidak diketahui."},"2602":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ وَزِيرٍ الْوَاسِطِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا عَطَسَ غَطَّى وَجْهَهُ بِيَدِهِ أَوْ بِثَوْبِهِ وَغَضَّ بِهَا صَوْتَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Wazir Al Washiti] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muhammad bin 'Ajlan] dari [Sumaiya] dari [Abu Shalih] dari [Abu Hurairah] bahwa apabila Nabi shallallahu 'alaihi wasallam bersin, beliau menutup wajahnya dengan tangan atau kainnya sambil merendahkan suaranya.\" Abu Isa berkata; Hadits ini hasan shahih."},"2603":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ عَجْلَانَ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُطَاسُ مِنْ اللَّهِ وَالتَّثَاؤُبُ مِنْ الشَّيْطَانِ فَإِذَا تَثَاءَبَ أَحَدُكُمْ فَلْيَضَعْ يَدَهُ عَلَى فِيهِ وَإِذَا قَالَ آهْ آهْ فَإِنَّ الشَّيْطَانَ يَضْحَكُ مِنْ جَوْفِهِ وَإِنَّ اللَّهَ يُحِبُّ الْعُطَاسَ وَيَكْرَهُ التَّثَاؤُبَ فَإِذَا قَالَ الرَّجُلُ آهْ آهْ إِذَا تَثَاءَبَ فَإِنَّ الشَّيْطَانَ يَضْحَكُ فِي جَوْفِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Ibnu 'Ajlan] dari [Al Maqburi] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bersin itu dari Allah, sedangkan menguap itu dari setan, apabila salah seorang dari kalian menguap, hendaklah meletakkan tangannya di mulutnya dan bila sampai mengucapkan; aah, aah, sesungguhnya setan tertawa di dalam rongganya, sesungguhnya Allah menyukai bersin dan membenci menguap, bila seseorang mengucapkan: aah, aah, saat menguap, sesungguhnya setean tertawa di dalamnya.\" Abu Isa berkata; hadits ini hasan shahih."},"2604":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يُحِبُّ الْعُطَاسَ وَيَكْرَهُ التَّثَاؤُبَ فَإِذَا عَطَسَ أَحَدُكُمْ فَقَالَ الْحَمْدُ لِلَّهِ فَحَقٌّ عَلَى كُلِّ مَنْ سَمِعَهُ أَنْ يَقُولَ يَرْحَمُكَ اللَّهُ وَأَمَّا التَّثَاؤُبُ فَإِذَا تَثَاءَبَ أَحَدُكُمْ فَلْيَرُدَّهُ مَا اسْتَطَاعَ وَلَا يَقُولَنَّ هَاهْ هَاهْ فَإِنَّمَا ذَلِكَ مِنْ الشَّيْطَانِ يَضْحَكُ مِنْهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ وَهَذَا أَصَحُّ مِنْ حَدِيثِ ابْنِ عَجْلَانَ وَابْنُ أَبِي ذِئْبٍ أَحْفَظُ لِحَدِيثِ سَعِيدٍ الْمَقْبُرِيِّ وَأَثْبَتُ مِنْ مُحَمَّدِ بْنِ عَجْلَانَ قَالَ سَمِعْت أَبَا بَكْرٍ الْعَطَّارَ الْبَصْرِيَّ يَذْكُرُ عَنْ عَلِيِّ بْنِ الْمَدِينِيِّ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ قَالَ مُحَمَّدُ بْنُ عَجْلَانَ أَحَادِيثُ سَعِيدٍ الْمَقْبُرِيِّ رَوَى بَعْضَهَا سَعِيدٌ عَنْ أَبِي هُرَيْرَةَ وَبَعْضُهَا عَنْ سَعِيدٍ عَنْ رَجُلٍ عَنْ أَبِي هُرَيْرَةَ وَاخْتَلَطَ عَلَيَّ فَجَعَلْتُهَا عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Ibnu Abu Dzi'b] dari [Sa'id bin Abu Sa'id Al Anshari Al Maqburi] dari [Ayahnya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah menyukai bersin dan membenci menguap, bila salah seorang dari kalian bersin lalu mengucapkan; \"ALHAMDULILLAAH, \" wajib bagi yang mendengarnya untuk mengucapkan; \"YARHAMUKALAAH, \" sedangkan uapan, bila salah seorang dari kalian menguap, hendaklah ia menangkal sebisanya dan jangan sampai mengucapkan; \"aah, aah, \" karena hal itu dari setan, ia akan menertawakannya.\" Abu Isa berkata; Hadits ini hasan shahih, dan hadits ini lebih shahih dari hadits Ibnu 'Ajlan. Ibnu Abu Dzi`b lebih hafal hadits Sa'id Al Maqburi dan lebih kuat dari Muhammad bin 'Ajlan. Perawi berkata; Aku mendengar Abu Bakar Al 'Aththar Al Bashri menyebutkan dari Ali bin Al Madani dari Yahya bin Sa'id ia berkata; Muhammad bin 'Ajlan berkata; hadits-hadits Sa'id Al Maqburi, sebagiannya diriwayatkan oleh Sa'id dari Abu Hurairah, dan sebagaiannya dari Sa'id dari seseorang dari Abu Hurairah, sanad ini kacau lalu aku menjadikannya dari Sa'id dari Abu Hurairah."},"2605":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا شَرِيكٌ عَنْ أَبِي الْيَقْظَانِ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ أَبِيهِ عَنْ جَدِّهِ رَفَعَهُقَالَ الْعُطَاسُ وَالنُّعَاسُ وَالتَّثَاؤُبُ فِي الصَّلَاةِ وَالْحَيْضُ وَالْقَيْءُ وَالرُّعَافُ مِنْ الشَّيْطَانِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ شَرِيكٍ عَنْ أَبِي الْيَقْظَانِ قَالَ وَسَأَلْتُ مُحَمَّدَ بْنَ إِسْمَعِيلَ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قُلْتُ لَهُ مَا اسْمُ جَدِّ عَدِيٍّ قَالَ لَا أَدْرِي وَذُكِرَ عَنْ يَحْيَى بْنِ مَعِينٍ قَالَ اسْمُهُ دِينَارٌ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Syarik] dari [Abul Yaqdlan] dari [Adi bin Tsabit] dari [Ayahnya] dari [kakeknya] dia memarfu'kannya (sampai kepada Nabi), dia berkata; \"Bersin, ngantuk dan menguap dalam shalat, termasuk haid, muntah dan mimisan semuanya dari setan.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari hadits Syarik dari Abul Yaqdlan, dia berkata; Aku bertanya kepada Muhammad bin Isma'il tentang 'Adi bin Tsabit dari Ayahnya dari kakeknya, aku bertanya; \"Siapa nama kakeknya 'Adi?\" Muhammad bin Isma`il menjawab; \"Aku tidak tahu.\" Telah disebutkan dari Yahya bin Ma'in dia berkata; \"Namanya adalah Dinar.\""},"2606":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُقِمْ أَحَدُكُمْ أَخَاهُ مِنْ مَجْلِسِهِ ثُمَّ يَجْلِسُ فِيهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seseorang dari kalian menyuruh saudaranya berdiri dari tempat duduknya, kemudian ia duduk di tempat itu.\" Abu Isa berkata; Hadits ini hasan shahih."},"2607":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُقِمْ أَحَدُكُمْ أَخَاهُ مِنْ مَجْلِسِهِ ثُمَّ يَجْلِسُ فِيهِقَالَ وَكَانَ الرَّجُلُ يَقُومُ لِابْنِ عُمَرَ فَلَا يَجْلِسُ فِيهِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah mengabarkan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seseorang dari kalian menyuruh saudaranya berdiri dari tempat duduknya kemudian ia duduk di tempat itu.\" Salim berkata; \"Seseorang berdiri untuk Ibnu Umar, namun Ibnu Umar tidak mau duduk di tempat itu.\" Abu Isa berkata; Hadits ini shahih."},"2608":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ الْوَاسِطِيُّ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ عَمِّهِ وَاسِعِ بْنِ حَبَّانَ عَنْ وَهْبِ بْنِ حُذَيْفَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرَّجُلُ أَحَقُّ بِمَجْلِسِهِ وَإِنْ خَرَجَ لِحَاجَتِهِ ثُمَّ عَادَ فَهُوَ أَحَقُّ بِمَجْلِسِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَفِي الْبَاب عَنْ أَبِي بَكْرَةَ وَأَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Khalid bin Abdullah Al Washiti] dari ['Amru bin Yahya] dari [Muhammad bin Yahya bin Habban] dari pamannya yaitu [Wasi' bin Habban] dari [Wahb bin Hudzaifah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seseorang berhak atas tempat duduknya, bila ia pergi untuk menunaikan hajat kemudian kembali, ia lebih berhak atas tempat duduk tersebut.\" Abu Isa berkata; Hadits ini hasan shahih gharib. Dalam hal ini, ada hadits serupa dari Abu Bakrah, Abu Sa'id dan Abu Hurairah."},"2609":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا أُسَامَةُ بْنُ زَيْدٍ حَدَّثَنِي عَمْرُو بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِلرَّجُلِ أَنْ يُفَرِّقَ بَيْنَ اثْنَيْنِ إِلَّا بِإِذْنِهِمَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ عَامِرٌ الْأَحْوَلُ عَنْ عَمْرِو بْنِ شُعَيْبٍ أَيْضًا","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Usamah bin Zaid] telah menceritakan kepadaku ['Amru bin Syu'aib] dari [Ayahnya] dari [Abdullah bin 'Amru] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seseorang untuk memisahkan (tempat duduk) dua orang kecuali atas izin keduanya.\" Abu Isa berkata; Hadits ini hasan shahih, ['Amir Al Ahwal] juga meriwayatkannya dari ['Amr bin Syu'aib]."},"2610":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي مِجْلَزٍ أَنَّرَجُلًا قَعَدَ وَسْطَ حَلْقَةٍ فَقَالَ حُذَيْفَةُ مَلْعُونٌ عَلَى لِسَانِ مُحَمَّدٍ أَوْ لَعَنَ اللَّهُ عَلَى لِسَانِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَعَدَ وَسْطَ الْحَلْقَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو مِجْلَزٍ اسْمُهُ لَاحِقُ بْنُ حُمَيْدٍ","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Syu'bah] dari [Qatadah] dari [Abu Mijlaz] bahwa seseorang duduk di tengah-tengah halaqah (perkumpulan), lalu [Hudzaifah] berkata; \"Terlaknat berdasarkan lisan Muhammad atau Allah melaknat melalui lisan Muhammad shallallahu 'alaihi wasallam, orang yang duduk di tengah-tengah halaqah.\" Abu Isa berkata; Hadits ini hasan shahih, adapun nama Abu Mijlaz adalah Lahiq bin Humaid."},"2611":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا عَفَّانُ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَلَمْ يَكُنْ شَخْصٌ أَحَبَّ إِلَيْهِمْ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَكَانُوا إِذَا رَأَوْهُ لَمْ يَقُومُوا لِمَا يَعْلَمُونَ مِنْ كَرَاهِيَتِهِ لِذَلِكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami ['Affan] telah mengabarkan kepada kami [Hammad bin Salamah] dari [Humaid] dari [Anas] ia berkata; \"Tidak ada seorangpun yang lebih mereka (para sahabat) cintai selain dari Rasulullah shallallahu 'alaihi wasallam, Anas berkata; Apabila melihat beliau, mereka tidak bangkit karena mereka tahu bahwa beliau tidak menyukai yang demikian.\" Abu Isa berkata; Hadits ini hasan shahih gharib dari jalur ini.\""},"2612":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبِ بْنِ الشَّهِيدِ عَنْ أَبِي مِجْلَزٍ قَالَخَرَجَ مُعَاوِيَةُ فَقَامَ عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ وَابْنُ صَفْوَانَ حِينَ رَأَوْهُ فَقَالَ اجْلِسَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ سَرَّهُ أَنْ يَتَمَثَّلَ لَهُ الرِّجَالُ قِيَامًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِوَفِي الْبَاب عَنْ أَبِي أُمَامَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ حَبِيبِ بْنِ الشَّهِيدِ عَنْ أَبِي مِجْلَزٍ عَنْ مُعَاوِيَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Qibishah] telah menceritakan kepada kami [Sufyan] dari [Habib bin Asy Syahid] dari [Abu Mijlaz] ia berkata; \"Suatu ketika Mu'awiyah keluar, ketika melihatnya, Abdullah bin Zubair dan Ibnu Safwan langsung berdiri, [Mu'awiyah] berkata; \"Duduklah kalian, aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa senang menjadikan orang-orang berdiri untuknya, maka bersiap-siaplah menempati tempatnya di neraka.\" Dan dalam bab ini, ada hadits dari Abu Umamah. Abu Isa berkata; Hadits ini hasan. Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Usamah] dari [Habib bin Asy Syahid] dari [Abu Mijlaz] dari [Mu'awiyah] dari Nabi shallallahu 'alaihi wasallam seperti hadits diatas."},"2613":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسٌ مِنْ الْفِطْرَةِ الِاسْتِحْدَادُ وَالْخِتَانُ وَقَصُّ الشَّارِبِ وَنَتْفُ الْإِبْطِ وَتَقْلِيمُ الْأَظْفَارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] dan lainnya, mereka berkata; telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lima hal termasuk (sunnah) fitrah, yaitu; mencukur rambut kemaluan, khitan, mencukur kumis, mencabut bulut ketiak dan memotong kuku, \" Abu Isa berkata; Hadits ini hasan shahih."},"2614":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَهَنَّادٌ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ مُصْعَبِ بْنِ شَيْبَةَ عَنْ طَلْقِ بْنِ حَبِيبٍ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَشْرٌ مِنْ الْفِطْرَةِ قَصُّ الشَّارِبِ وَإِعْفَاءُ اللِّحْيَةِ وَالسِّوَاكُ وَالِاسْتِنْشَاقُ وَقَصُّ الْأَظْفَارِ وَغَسْلُ الْبَرَاجِمِ وَنَتْفُ الْإِبْطِ وَحَلْقُ الْعَانَةِ وَانْتِقَاصُ الْمَاءِقَالَ زَكَرِيَّا قَالَ مُصْعَبٌ وَنَسِيتُ الْعَاشِرَةَ إِلَّا أَنْ تَكُونَ الْمَضْمَضَةَ قَالَ أَبُو عِيسَى انْتِقَاصُ الْمَاءِ الِاسْتِنْجَاءُ بِالْمَاءِ وَفِي الْبَاب عَنْ عَمَّارِ بْنِ يَاسِرٍ وَابْنِ عُمَرَ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Qutaibah] dan [Hannad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Zakariya bin Abu Za`idah] dari [Mush'ab bin Syaibah] dari [Thalq bin Habib] dari [Abdullah bin Az Zubair] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sepuluh hal yang termasuk (sunnah) fitrah, yaitu; mencukur kumis, memanjangkan jenggot, bersiwak, Istinsyaq (menghirup air lewat hidung), memotong kuku, membasuh ruas jari, mencabut bulu ketiak, mencukur rambut kemaluan, beristinja` -Mush'ab mengatakan; Saya lupa yang kesepuluh- mungkin berkumur.\" Abu Isa berkata; \"Intiqash al-maa` artinya beristinja` dengan air.\" Dalam hal ini ada hadits serupa dari Ammar bin Yasir, Ibnu Umar dan Abu Hurairah. Abu Isa berkata; Hadits ini hasan."},"2615":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا صَدَقَةُ بْنُ مُوسَى أَبُو مُحَمَّدٍ صَاحِبُ الدَّقِيقِ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ وَقَّتَ لَهُمْ فِي كُلِّ أَرْبَعِينَ لَيْلَةً تَقْلِيمَ الْأَظْفَارِ وَأَخْذَ الشَّارِبِ وَحَلْقَ الْعَانَةِ","id":"Telah menceritakan kepada kami [Ishaq bin Manhsur] telah mengabarkan kepada kami [Abdushshamad bin Abdul Warits] telah menceritakan kepada kami [Shadaqah bin Musa Abu Muhammad] telah menceritakan kepada kami [Abu Imran Al Jauni] dari [Anas bin Malik] dari nabi shallallahu 'alaihi wasallam, bahwa beliau memberi batas waktu setiap empatpuluh malam untuk memotong kuku, mencukur kumis dan mencukur rambut kemaluan.\""},"2616":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَوُقِّتَ لَنَا فِي قَصِّ الشَّارِبِ وَتَقْلِيمِ الْأَظْفَارِ وَحَلْقِ الْعَانَةِ وَنَتْفِ الْإِبْطِ لَا يُتْرَكُ أَكْثَرَ مِنْ أَرْبَعِينَ يَوْمًاقَالَ هَذَا أَصَحُّ مِنْ حَدِيثِ الْأَوَّلِ وَصَدَقَةُ بْنُ مُوسَى لَيْسَ عِنْدَهُمْ بِالْحَافِظِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ja'far bin Sulaiman] dari [Abu 'Imran Al Jauni] dari [Anas bin Malik] ia berkata; \"Kami diberi batas waktu untuk mencukur kumis, memotong kuku, mencukur bulu kemaluan, mencabut bulu ketiak, tidak dibiarkan lebih dari empatpuluh hari.\" Abu Isa berkata; Hadits ini lebih shahih dari hadits pertama. Shadaqah bin Musa menurut mereka bukan seorang yang hafidz."},"2617":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ الْوَلِيدِ الْكِنْدِيُّ الْكُوفِيُّ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُصُّ أَوْ يَأْخُذُ مِنْ شَارِبِهِ وَكَانَ إِبْرَاهِيمُ خَلِيلُ الرَّحْمَنِ يَفْعَلُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Muhammad bin Umar bin Al Walid Al Kindi Al Kufi] telah menceritakan kepada kami [Yahya bin Adam] dari [Isra`il] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; \"Nabi shallallahu 'alaihi wasallam biasa mencukur atau memotong kumis beliau, dan Ibrahim kekasih Ar Rahman juga melakukan hal yang sama.\" Abu Isa berkata; Hadits ini hasan gharib."},"2618":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ يُوسُفَ بْنِ صُهَيْبٍ عَنْ حَبِيبِ بْنِ يَسَارٍ عَنْ زَيْدِ بْنِ أَرْقَمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يَأْخُذْ مِنْ شَارِبِهِ فَلَيْسَ مِنَّاوَفِي الْبَاب عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ يُوسُفَ بْنِ صُهَيْبٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Abidah bin Humaid] dari [Yusuf bin Shuhaib] dari [Habib bin Yasar] dari [Zaid bin Arqam] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tidak mencukur kumisnya, maka dia bukan termasuk golonganku.\" Dan dalam bab ini, ada juga hadits dari Al Mughirah bin Syu'bah. Abu Isa berkata; Hadits ini hasan shahih. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Yusuf bin Shuhaib] dengan sanad yang semakna hadits ini."},"2619":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عُمَرُ بْنُ هَارُونَ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْخُذُ مِنْ لِحْيَتِهِ مِنْ عَرْضِهَا وَطُولِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ و سَمِعْت مُحَمَّدَ بْنَ إِسْمَعِيلَ يَقُولُ عُمَرُ بْنُ هَارُونَ مُقَارِبُ الْحَدِيثِ لَا أَعْرِفُ لَهُ حَدِيثًا لَيْسَ لَهُ أَصْلٌ أَوْ قَالَ يَنْفَرِدُ بِهِ إِلَّا هَذَا الْحَدِيثَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْخُذُ مِنْ لِحْيَتِهِ مِنْ عَرْضِهَا وَطُولِهَا لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عُمَرَ بْنِ هَارُونَ وَرَأَيْتُهُ حَسَنَ الرَّأْيِ فِي عُمَرَ قَالَ أَبُو عِيسَى و سَمِعْت قُتَيْبَةَ يَقُولُ عُمَرُ بْنُ هَارُونَ كَانَ صَاحِبَ حَدِيثٍ وَكَانَ يَقُولُ الْإِيمَانُ قَوْلٌ وَعَمَلٌ قَالَ قُتَيْبَةُ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ عَنْ رَجُلٍ عَنْ ثَوْرِ بْنِ يَزِيدَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَصَبَ الْمَنْجَنِيقَ عَلَى أَهْلِ الطَّ��ئِفِ قَالَ قُتَيْبَةُ قُلْتُ لِوَكِيعٍ مَنْ هَذَا قَالَ صَاحِبُكُمْ عُمَرُ بْنُ هَارُونَ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Umar bin Harun] dari [Usamah bin Zaid] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [kakeknya] bahwa Nabi shallallahu 'alaihi wasallam mengambil (memotong) jenggotnya dari bagian samping dan bagian yang panjang.\" Abu Isa berkata; Hadits ini gharib, dan aku mendengar Muhammad bin Isma'il berkata; Umar bin Harun muqaribul hadits, aku tidak mengetahui dia memiliki hadits yang tidak ada asalnya, atau dia mengatakan; \"Haditsnya munfarid (diriwayatkan sendirian) kecuali hadits ini, \"Bahwa Nabi shallallahu 'alaihi wasallam mengambil jenggotnya dari bagian samping dan bagian yang panjang, \" kami tidak mengetahuinya kecuali dari hadits Umar bin Harun dan menurutku pendapatnya tentang Umar baik. Abu Isa berkata; Aku mendengar Qutaibah berkata; Umar bin Harun adalah orang yang memiliki hadits, dan dia yang mengatakan: \"Iman itu ucapan dan perbuatan.\" Qutaibah berkata; telah menceritakan kepada kami Waqi' bin Al Jarrah dari seseorang dari Tsaur bin Yazid bahwa Nabi shallallahu 'alaihi wasallam menyerang penduduk Tha`if dengan manjanik (senjata kuno sejenis pelontar batu, pent.). Qutaibah berkata; Aku bertanya kepada Waqi'; \"Siapa dia?\" dia menjawab; \"Sahabat kalian, Umar bin Harun.\""},"2620":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْفُوا الشَّوَارِبَ وَأَعْفُوا اللِّحَىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khiallal] telah menceritakan kepada kami [Abdullah bin Numair] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Cukurlah kumis dan biarkan jenggot.\" Abu Isa berkata; Hadits ini shahih."},"2621":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ أَبِي بَكْرِ بْنِ نَافِعٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَنَا بِإِحْفَاءِ الشَّوَارِبِ وَإِعْفَاءِ اللِّحَىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو بَكْرِ بْنُ نَافِعٍ هُوَ مَوْلَى ابْنِ عُمَرَ ثِقَةٌ وَعُمَرُ بْنُ نَافِعٍ ثِقَةٌ وَعَبْدُ اللَّهِ بْنُ نَافِعٍ مَوْلَى ابْنِ عُمَرَ يُضَعَّفُ","id":"Telah menceritakan kepada kami [Al Anshari] telah menceritakan kepada kami [Ma'nu] telah menceritakan kepada kami [Malik] dari [Abu Bakar bin Nafi'] dari [Ayahnya] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk mencukur kumis dan membiarkan jenggot.\" Abu Isa berkata; Hadits ini hasan shahih. Abu Bakar bin Nafi' yaitu bekas budak Ibnu Umar adalah perawi tsiqah, sedangkan Umar bin Nafi' perawi tsiqah, sementara Abdullah bin Nafi' budak Ibnu Umar, dilemahkan."},"2622":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسْتَلْقِيًا فِي الْمَسْجِدِ وَاضِعًا إِحْدَى رِجْلَيْهِ عَلَى الْأُخْرَىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَعَمُّ عَبَّادِ بْنِ تَمِيمٍ هُوَ عَبْدُ اللَّهِ بْنُ زَيْدِ بْنِ عَاصِمٍ الْمَازِنِيُّ","id":"Telah menceritakan kepada kami [Sa'id bin Abdurrahman Al Makhzumi] dan yang lain, mereka berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Abbad bin Tamim] dari [Pamannya] bahwa ia melihat Nabi shallallahu 'alaihi wasallam terlentang di masjid sambil meletakkan salah satu kaki di atas sebelah kaki yang lain.\" Abu Isa berkata; Hadits ini hasan shahih. Paman 'Abbad bin Tamim adalah Abdullah bin Zaid bin 'Ashim Al Mazini."},"2623":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ أَسْبَاطِ بْنِ مُحَمَّدٍ الْقُرَشِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ خِدَاشٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَلْقَى أَحَدُكُمْ عَلَى ظَهْرِهِ فَلَا يَضَعْ إِحْدَى رِجْلَيْهِ عَلَى الْأُخْرَىهَذَا حَدِيثٌ رَوَاهُ غَيْرُ وَاحِدٍ عَنْ سُلَيْمَانَ التَّيْمِيِّ وَلَا يُعْرَفُ خِدَاشٌ هَذَا مَنْ هُوَ وَقَدْ رَوَى لَهُ سُلَيْمَانُ التَّيْمِيُّ غَيْرَ حَدِيثٍ","id":"Telah menceritakan kepada kami ['Ubaid bin Asbath bin Muhammad Al Qurasyi] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Sulaiman At Taimi] dari [Khidasy] dari [Abu Az Zubair] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian berbaring di atas punggungnya, janganlah meletakkan salah satu kakinya di atas yang lain.\" Hadits ini diriwayatkan oleh orang banyak dari Sulaiman At Taimi, dan tidak di ketahui siapa sebenarnya Khidasy, sementara Sulaiman meriwayatkan darinya bukan cuma satu hadits."},"2624":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ اشْتِمَالِ الصَّمَّاءِ وَالِاحْتِبَاءِ فِي ثَوْبٍ وَاحِدٍ وَأَنْ يَرْفَعَ الرَّجُلُ إِحْدَى رِجْلَيْهِ عَلَى الْأُخْرَى وَهُوَ مُسْتَلْقٍ عَلَى ظَهْرِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam melarang isytimalus shama` dan duduk ihtiba' dengan mengenakan sehelai kain, dan terlentang diatas punggungnya dengan mengangkat sebelah kaki di atas kaki yang lain.\" Abu Isa berkata; Hadits ini hasan shahih. "},"2625":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ وَعَبْدُ الرَّحِيمِ عَنْ مُحَمَّدِ بْنِ عَمْرٍو حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا مُضْطَجِعًا عَلَى بَطْنِهِ فَقَالَ إِنَّ هَذِهِ ضَجْعَةٌ لَا يُحِبُّهَا اللَّهُوَفِي الْبَاب عَنْ طِهْفَةَ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى وَرَوَى يَحْيَى بْنُ أَبِي كَثِيرٍ هَذَا الْحَدِيثَ عَنْ أَبِي سَلَمَةَ عَنْ يَعِيشَ بْنِ طِهْفَةَ عَنْ أَبِيهِ وَيُقَالُ طِخْفَةُ وَالصَّحِيحُ طِهْفَةُ وَقَالَ بَعْضُ الْحُفَّاظِ الصَّحِيحُ طِخْفَةُ وَيُقَالُ طِغْفَةُ يَعِيشُ هُوَ مِنْ الصَّحَابَةِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami ['Abdah bin Sulaiman] dan [Abdurrahim] dari [Muhammad bin 'Amru] telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah melihat seseorang tengkurap, lalu beliau bersabda: \"Sesungguhnya tengkurap tidak disukai Allah.\" Dalam hal ini ada hadits serupa dari Thihfah dan Ibnu Umar. Abu Isa berkata; [Yahya bin Abu Katsir] meriwayatkan hadits ini dari [Abu Salamah] dari [Ya'isy bin Thihfah] dari [Ayahnya], dikatakan juga Thikfah, namun yang benar adalah Thihfah. Sebagaian hafidz mengatakan bahwa yang benar adalah Thikhfah. Ada juga yang menyebut Thighfah Ya'isy, ia adalah salah seorang sahabat."},"2626":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا بَهْزُ بْنُ حَكِيمٍ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَقُلْتُ يَا رَسُولَ اللَّهِ عَوْرَاتُنَا مَا نَأْتِي مِنْهَا وَمَا نَذَرُ قَالَ احْفَظْ عَوْرَتَكَ إِلَّا مِنْ زَوْجَتِكَ أَوْ مَا مَلَكَتْ يَمِينُكَ فَقَالَ الرَّجُلُ يَكُونُ مَعَ الرَّجُلِ قَالَ إِنْ اسْتَطَعْتَ أَنْ لَا يَرَاهَا أَحَدٌ فَافْعَلْ قُلْتُ وَالرَّجُلُ يَكُونُ خَالِيًا قَالَ فَاللَّهُ أَحَقُّ أَنْ يُسْتَحْيَا مِنْهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَجَدُّ بَهْزٍ اسْمُهُ مُعَاوِيَةُ بْنُ حَيْدَةَ الْقُشَيْرِيُّ وَقَدْ رَوَى الْجُرَيْرِيُّ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ وَهُوَ وَالِدُ بَهْزٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Bahz bin Hakim] telah menceritakan kepada kami [Ayahku] dari [kakekku] ia berkata; Aku bertanya; \"Wahai Rasulullah, aurat mana sajakah yang yang harus kami tutup dan yang kami biarkan (terbuka)? beliau menjawab: \"Jagalah auratmu kecuali kepada istrimu atau budak yang kamu miliki, \" dia bertanya lagi; \"Jika sesama lelaki?\" beliau menjawab: \"Jika kamu mampu supaya tidak terlihat oleh seorangpun, maka lakukanlah.\" Aku bertanya; \"Jika seseorang sendirian?\" beliau menjawab: \"Allah lebih patut dimalui.\" Abu Isa berkata; Hadits ini hasan, kakeknya Bahz namanya Mu'awiyah bin Haidah Al Qusyairi, dan Jurairi meriwayatkan dari Hakim bin Mu'awiyah, dia adalah ayahnya Bahz."},"2627":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ مُحَمَّدٍ الدُّورِيُّ الْبَغْدَادِيُّ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ الْكُوفِيُّ أَخْبَرَنَا إِسْرَائِيلُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئًا عَلَى وِسَادَةٍ عَلَى يَسَارِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَرَوَى غَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئًا عَلَى وِسَادَةٍ وَلَمْ يَذْكُرْ عَلَى يَسَارِهِ","id":"Telah menceritakan kepada kami [Abbas bin Muhammad Ad Duri Al Baghdadi] telah menceritakan kepada kami [Ishaq bin Manshur Al Kufi] telah mengabarkan kepada kami [Isra`il] dari [Simak bin Harb] dari [Jabir bin Samurah] ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam bersandarkan bantal ke sebelah kiri beliau.\" Abu Isa berkata; Hadits ini hasan gharib, banyak perawi meriwayatkan hadits ini dari Isra`il dari Simak dari Jabir bin Samurah, dia berkata; \"Aku pernah melihat Nabi shallallahu 'alaihi wasallam bersandarkan bantal.\" Namun dia tidak menyebutkan; \"Ke sebelah kiri beliau.\""},"2628":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ عِيسَى حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئًا عَلَى وِسَادَةٍهَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Yusuf bin Isa] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Simak bin Harb] dari [Jabir bin Samurah] ia berkata; \"Aku pernah melihat Nabi shallallahu 'alaihi wasallam bersandarkan bantal.\" Hadits ini shahih."},"2629":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِسْمَعِيلَ بْنِ رَجَاءٍ عَنْ أَوْسِ بْنِ ضَمْعَجٍ عَنْ أَبِي مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُؤَمُّ الرَّجُلُ فِي سُلْطَانِهِ وَلَا يُجْلَسُ عَلَى تَكْرِمَتِهِ فِي بَيْتِهِ إِلَّا بِإِذْنِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Isma'il bin Raja`] dari [Aus bin Dlam'aj] dari [Abu Mas'ud] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seseorang menjadi imam di daerah kekuasaan (orang lain) dan jangan duduk di tempat terhormat di rumah (orang lain) kecuali atas izin darinya.\" Abu Isa berkata; Hadits ini hasan shahih."},"2630":{"ar":"حَدَّثَنَا أَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ حَدَّثَنِي أَبِي حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ قَال سَمِعْتُ أَبِي بُرَيْدَةَ يَقُولُبَيْنَمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي إِذْ جَاءَهُ رَجُلٌ وَمَعَهُ حِمَارٌ فَقَالَ يَا رَسُولَ اللَّهِ ارْكَبْ وَتَأَخَّرَ الرَّجُلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْتَ أَحَقُّ بِصَدْرِ دَابَّتِكَ إِلَّا أَنْ تَجْعَلَهُ لِي قَالَ قَدْ جَعَلْتُهُ لَكَ قَالَ فَرَكِبَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَفِي الْبَاب عَنْ قَيْسِ بْنِ سَعْدِ بْنِ عُبَادَةَ","id":"Telah menceritakan kepada kami [Abu 'Ammar Al Husain bin Huraits] telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] telah menceritakan kepada kami [Ayahku] telah menceritakan kepadaku [Abdullah bin Buraidah] ia berkata; Aku mendengar [Abu Buraidah] berkata; \"Ketika Nabi shallallahu 'alaihi wasallam sedang berjalan, datanglah seseorang dengan membawa keledai sambil berkata; \"Wahai Rasulullah, naiklah!.\" Orang itu bergeser, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kamu lebih berhak untuk menempati tempat kendaraanmu kecuali jika kamu persilahkan untukku.\" orang itu berkata; Aku telah mempersilahkan untuk anda.\" Abu Buraidah berkata; \"Rasulullah lalu mengendarainya.\" Abu Isa berkata; Hadits ini hasan gharib dari jalur ini, dan dalam bab ini, ada juga hadits dari Qais bin Sa'd bin 'Ubadah."},"2631":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكُمْ أَنْمَاطٌ قُلْتُ وَأَنَّى تَكُونُ لَنَا أَنْمَاطٌ قَالَ أَمَا إِنَّهَا سَتَكُونُ لَكُمْ أَنْمَاطٌ قَالَ فَأَنَا أَقُولُ لِامْرَأَتِي أَخِّرِي عَنِّي أَنْمَاطَكِ فَتَقُولُ أَلَمْ يَقُلْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا سَتَكُونُ لَكُمْ أَنْمَاطٌ قَالَ فَأَدَعُهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Al Munkadir] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian memiliki permadani?\" Aku katakan; \"Dari mana kami dapatkan permadani?\". Beliau bersabda: \"Sungguh suatu saat nanti kalian akan memiliki permadani\". Jabir berkata; Kemudian aku katakan istriku; \"Berikan kepadaku permadanimu.\" Istrinya berkata; \"Bukankah Nabi Shallallahu 'alaihi wa salam telah bersabda bahwa suatu hari nanti kalian akan memiliki permadani?\". Lalu aku membiarkannya. Abu Isa berkata; Hadits ini hasan shahih."},"2632":{"ar":"حَدَّثَنَا عَبَّاسٌ الْعَنْبَرِيُّ حَدَّثَنَا النَّضْرُ بْنُ مُحَمَّدٍ هُوَ الْجُرَشِيُّ الْيَمَامِيُّ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ عَنْ أَبِيهِ قَالَلَقَدْ قُدْتُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْحَسَنَ وَالْحُسَيْنَ عَلَى بَغْلَتِهِ الشَّهْبَاءِ حَتَّى أَدْخَلْتُهُ حُجْرَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا قُدَّامُهُ وَهَذَا خَلْفُهُوَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَعَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami ['Abbas Al Anbari] telah menceritakan kepada kami [An Nadlr bin Muhammad yaitu Al Jurasyi Al Yamami] telah menceritakan kepada kami [Ikrimah bin 'Ammar] dari [Iyas bin Salamah] dari [Ayahnya] ia berkata; Aku pernah menuntun (kendaraan) Nabi Allah shallallahu 'alaihi wasallam, sementara Al Hasan dan Al Husain berada di atas keledai yang warna putihnya lebih banyak dari warna hitam, hingga aku membawanya masuk ke dalam kamar Nabi shallallahu 'alaihi wasallam, yang ini di depan beliau dan yang satunya lagi di belakang beliau.\" Dan dalam bab ini, ada juga hadits dari Ibnu Abbas dan Abdullah bin Ja'far, Abu Isa berkata; Hadits ini hasan shahih gharib dari jalur ini."},"2633":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يُونُسُ بْنُ عُبَيْدٍ عَنْ عَمْرِو بْنِ سَعِيدٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نَظْرَةِ الْفُجَاءَةِ فَأَمَرَنِي أَنْ أَصْرِفَ بَصَرِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو زُرْعَةَ بْنُ عَمْرٍو اسْمُهُ هَرِمٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Yunus bin 'Ubaid] dari ['Amru bin Sa'id] dari [Abu Zur'ah bin 'Amru bin Jarir] dari [Jarir bin Abdullah] ia berkata; Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang pandangan sepintas, lalu beliau memerintahkanku untuk mengalihkan pandanganku.\" Abu Isa berkata; Hadits ini hasan shahih. Abu Zur'ah bin Amru namanya adalah Harim."},"2634":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا شَرِيكٌ عَنْ أَبِي رَبِيعَةَ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِرَفَعَهُ قَالَ يَا عَلِيُّ لَا تُتْبِعْ النَّظْرَةَ النَّظْرَةَ فَإِنَّ لَكَ الْأُولَى وَلَيْسَتْ لَكَ الْآخِرَةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ شَرِيكٍ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Syarik] dari [Abu Rabi'ah] dari [Ibnu Buraidah] dari [Ayahnya] ia memarfu'kan (menyambungkan sampai Nabi shallallahu 'alaihi wasallam), sabdanya; \"Wahai Ali, janganlah kamu ikuti pandangan yang pertama dengan pandangan berikutnya, karena yang pertama untukmu dan yang kedua bukan lagi untukmu.\" Abu Isa berkata; Hadits ini hasan gharib, kami tidak mengetahuinya kecuali dari hadits Syarik."},"2635":{"ar":"حَدَّثَنَا سُوَيْدٌ حَدَّثَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ نَبْهَانَ مَوْلَى أُمِّ سَلَمَةَ أَنَّهُ حَدَّثَهُ أَنَّ أُمَّ سَلَمَةَ حَدَّثَتْهُأَنَّهَا كَانَتْ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَيْمُونَةَ قَالَتْ فَبَيْنَا نَحْنُ عِنْدَهُ أَقْبَلَ ابْنُ أُمِّ مَكْتُومٍ فَدَخَلَ عَلَيْهِ وَذَلِكَ بَعْدَ مَا أُمِرْنَا بِالْحِجَابِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجِبَا مِنْهُ فَقُلْتُ يَا رَسُولَ اللَّهِ أَلَيْسَ هُوَ أَعْمَى لَا يُبْصِرُنَا وَلَا يَعْرِفُنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفَعَمْيَاوَانِ أَنْتُمَا أَلَسْتُمَا تُبْصِرَانِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid] telah menceritakan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus bin Yazid] dari [Ibnu Syihab] dari [Nabhan] bekas budak Ummu Salamah, bahwa ia telah menceritakan kepadanya, bahwa ia pernah berada di sisi Rasulullah shallallahu 'alaihi wasallam dan Maimunah, [Ummu Salamah] berkata; Ketika kami berada di sisi beliau, Ibnu Ummi Maktum dating dan menghadap kepada beliau, yaitu setelah kami diperintahkan untuk berhijab, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berhijablah kalian berdua darinya, \" maka aku bertanya; \"Wahai Rasulullah, bukankah dia buta, dia tidak dapat melihat dan tidak mengetahui kami?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Apakah kamu berdua buta?\" Bukankah kamu berdua dapat melihatnya?.\" Abu Isa berkata; Hadits ini hasan shahih."},"2636":{"ar":"حَدَّثَنَا سُوَيْدٌ حَدَّثَنَا عَبْدُ اللَّهِ أَخْبَرَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ذَكْوَانَ عَنْ مَوْلَى عَمْرِو بْنِ الْعَاصِأَنَّ عَمْرَو بْنَ الْعَاصِ أَرْسَلَهُ إِلَى عَلِيٍّ يَسْتَأْذِنُهُ عَلَى أَسْمَاءَ بِنْتِ عُمَيْسٍ فَأُذِنَ لَهُ حَتَّى إِذَا فَرَغَ مِنْ حَاجَتِهِ سَأَلَ الْمَوْلَى عَمْرَو بْنَ الْعَاصِ عَنْ ذَلِكَ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا أَوْ نَهَى أَنْ نَدْخُلَ عَلَى النِّسَاءِ بِغَيْرِ إِذْنِ أَزْوَاجِهِنَّوَفِي الْبَاب عَنْ عُقْبَةَ بْنِ عَامِرٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَجَابِرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid] telah menceritakan kepada kami [Abdullah] telah mengabarkan kepada kami [Syu'bah] dari [Al Hakam] dari [Dzakwan] dari [Bekas budak 'Amru bin Al Ash] bahwa ['Amru bin Al Ash] pernah mengutusnya menemui Ali untuk meminta izin menemui Asma` binti Umais, lalu ia memberi izin, setelah menunaikan keperluannya, budak itu bertanya kepada 'Amru bin Al Ash tentang masalah itu, 'Amru menjawab; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang kami atau melarang kami memasuki kediaman wanita-wanita tanpa izin suami-suami mereka.\" Dalam hal ini ada hadits serupa dari 'Uqbah bin 'Amir, Abdullah bin 'Amru dan Jabir. Abu Isa berkata; Hadits ini hasan shahih."},"2637":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ أَبِي عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ وَسَعِيدِ بْنِ زَيْدِ بْنِ عَمْرِو بْنِ نُفَيْلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا تَرَكْتُ بَعْدِي فِي النَّاسِ فِتْنَةً أَضَرَّ عَلَى الرِّجَالِ مِنْ النِّسَاءِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى هَذَا الْحَدِيثَ غَيْرُ وَاحِدٍ مِنْ الثِّقَاتِ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَذْكُرُوا فِيهِ عَنْ سَعِيدِ بْنِ زَيْدِ بْنِ عَمْرِو بْنِ نُفَيْلٍ وَلَا نَعْلَمُ أَحَدًا قَالَ عَنْ أُسَامَةَ بْنِ زَيْدٍ وَسَعِيدُ بْنُ زَيْدٍ غَيْرُ الْمُعْتَمِرِ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul A'la Ash Shan'ani] telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [Ayahnya] dari [Abu Utsman] dari [Usamah bin Zaid] dari [Sa'id bin Zaid bin 'Amru bin Nufail] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah aku tinggalkan sepeninggalku fitnah yang lebih membahayakan bagi kaum lelaki melebihi wanita.\" Abu Isa berkata; Hadits ini hasan shahih. Hadits ini diriwayatkan oleh beberapa orang dari perawi-perawi tsiqah dari Sulaiman At Taimi dari Abu Utsman dari Usamah bin Zaid dari nabi shallallahu 'alaihi wasallam, mereka tidak menyebutkan; dari Sa'id bin Zaid bin 'Amru bin Nufail. Dan kami tidak mengetahui seorangpun berkata; Dari Usamah bin Zaid dan Sa'id bin Zaid selain Al Mu'tamir. Dalam hal ini, ada hadits serupa dari Abu Sa'id. Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Sulaiman At Taimi] dari [Abu Utsman] dari [Usamah bin Zaid] dari Nabi shallallahu 'alaihi wasallam seperti hadits diatas."},"2638":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ أَخْبَرَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَ مُعَاوِيَةَ بِالْمَدِينَةِ يَخْطُبُ يَقُولُأَيْنَ عُلَمَاؤُكُمْ يَا أَهْلَ الْمَدِينَةِ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ هَذِهِ الْقُصَّةِ وَيَقُولُ إِنَّمَا هَلَكَتْ بَنُو إِسْرَائِيلَ حِينَ اتَّخَذَهَا نِسَاؤُهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ مُعَاوِيَةَ","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] telah mengabarkan kepada kami [Humaid bin Abdurrahman] ia mendengar [Mu'awiyah] berkhutbah di Madinah, ia berkata; \"Manakah para ulama kalian, wahai penduduk Madinah? Sesungguhnya aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam melarang menyambung rambut, beliau bersabda: \"Sesungguhnya Bani Isra`il binasa karena wanita-wanita mereka melakukan hal itu.\" Abu Isa berkata; Hadits ini hasan sahih dan hadits ini diriwayatkan melalui beberapa sanad dari Mu'awiyah."},"2639":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ وَالْمُتَنَمِّصَاتِ مُبْتَغِيَاتٍ لِلْحُسْنِ مُغَيِّرَاتٍ خَلْقَ اللَّهِقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ شُعْبَةُ وَغَيْرُ وَاحِدٍ مِنْ الْأَئِمَّةِ عَنْ مَنْصُورٍ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami ['Ubaidah bin Humaid] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] bahwa Nabi shallallahu 'alaihi wasallam melaknat wanita-wanita yang mentato dan yang meminta ditato, wanita-wanita yang mencukur alis demi mencari keindahan dan merubah ciptaan Allah.\" Abu Isa berkata; Hadits ini hasan shahih. [Syu'bah] dan lainnya meriwayatkannya dari para imam dari [Manshur]."},"2640":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَعَنَ اللَّهُ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ وَالْوَاشِمَةَ وَالْمُسْتَوْشِمَةَقَالَ نَافِعٌ الْوَشْمُ فِي اللِّثَةِ قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ عَائِشَةَ وَمَعْقِلِ بْنِ يَسَارٍ وَأَسْمَاءَ بِنْتِ أَبِي بَكْرٍ وَابْنِ عَبَّاسٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَلَمْ يَذْكُرْ فِيهِ يَحْيَى قَوْلَ نَافِعٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah bin Al Mubarak] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah melaknat wanita yang menyambung rambut dan yang meminta disambung rambutnya, wanita yang mentato dan yang meminta ditato.\" Nafi' bekata: \"Tato di gusi.\" Abu Isa berkata; Hadits ini hasan shahih. Dalam hal ini, ada hadits serupa dari 'Aisyah, Ma'qil bin Yasar, Asma` binti Abu Bakar dan Ibnu Abbas. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas, dalam hadits tersebut Yahya tidak menyebutkan perkataan Nafi'. Abu Isa berkata; Hadits ini hasan shahih."},"2641":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ وَهَمَّامٌ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُتَشَبِّهَاتِ بِالرِّجَالِ مِنْ النِّسَاءِ وَالْمُتَشَبِّهِينَ بِالنِّسَاءِ مِنْ الرِّجَالِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] dan [Hammam] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam melaknat wanita-wanita yang menyerupai lelaki dan lelaki-lelaki yang menyerupai wanita.\" Abu Isa berkata; Hadits ini hasan shahih."},"2642":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ وَأَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُخَنَّثِينَ مِنْ الرِّجَالِ وَالْمُتَرَجِّلَاتِ مِنْ النِّسَاءِقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ عَائِشَةَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dan [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam melaknat laki-laki yang menyerupai wanita dan wanita yang menyerupai laki-laki.\" Abu Isa berkata; Hadits ini hasan shahih, dan dalam bab ini, ada juga hadits dari 'Aisyah."},"2643":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ ثَابِتِ بْنِ عُمَارَةَ الْحَنَفِيِّ عَنْ غُنَيْمِ بْنِ قَيْسٍ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ عَيْنٍ زَانِيَةٌ وَالْمَرْأَةُ إِذَا اسْتَعْطَرَتْ فَمَرَّتْ بِالْمَجْلِسِ فَهِيَ كَذَا وَكَذَا يَعْنِي زَانِيَةًوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id Al Qattan] dari [Tsabit bin 'Umarah Al Hanafi] dari [Ghunaim bin Qais] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap mata memiliki bagian dari zina, dan wanita yang memakai wewangian kemudian lewat di perkumpulan (lelaki) berarti dia begini dan begini.\" Maksud beliau berbuat zina. Dan dalam bab ini ada juga hadits dari Abu Hurairah, Abu Isa berkata; Hadits ini hasan shahih."},"2644":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ سُفْيَانَ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ رَجُلٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طِيبُ الرِّجَالِ مَا ظَهَرَ رِيحُهُ وَخَفِيَ لَوْنُهُ وَطِيبُ النِّسَاءِ مَا ظَهَرَ لَوْنُهُ وَخَفِيَ رِيحُهُحَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ الطُّفَاوِيِّ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ إِلَّا أَنَّ الطُّفَاوِيَّ لَا نَعْرِفُهُ إِلَّا فِي هَذَا الْحَدِيثِ وَلَا نَعْرِفُ اسْمَهُ وَحَدِيثُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ أَتَمُّ وَأَطْوَلُ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Daud Al Hafari] dari [Sufyan] dari [Al Jurairi] dari [Abu Nadlrah] dari [seseorang] dari [Abu Hurairah] ia berkata; bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Minyak wanginya lelaki baunya menyengat dan warnyanya tidak kelihatan, sedangkan minyak wangi wanita adalah yang warnanya kelihatan dan baunya tidak tercium.\" Telah menceritakan kepada kami [Ali bin Hujr] telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Al Jurairi] dari [Abu Nadlrah] dari [Ath Thafawi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dengan hadits dan maksud yang sama. Abu Isa berkata; Hadits ini hasan, namun Ath Thafawi tidak kami ketahui kecuali dalam hadits ini, namanya pun tidak kami ketahui, sedangkan hadits Isma'il bin Ibrahim lebih lengkap dan lebih panjang.\""},"2645":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ خَيْرَ طِيبِ الرَّجُلِ مَا ظَهَرَ رِيحُهُ وَخَفِيَ لَوْنُهُ وَخَيْرَ طِيبِ النِّسَاءِ مَا ظَهَرَ لَوْنُهُ وَخَفِيَ رِيحُهُ وَنَهَى عَنْ مِيثَرَةِ الْأُرْجُوَانِهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu Bakar Al Hanafi] dari [Sa'id] dari [Qatadah] dari [Al Hasan] dari ['Imran bin Hushain] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda kepadaku: \"Sesungguhnya wewangian lelaki yang terbaik adalah baunya semerbak namun warnanya tidak terlihat, sedangkan wewangian wanita yang terbaik adalah yang nampak warnanya namun baunya tidak tercium.\" Dan Beliau melarang celupan (wantek) yang warnanya sangat merah. Hadits ini hasan gharib melalui sanad ini."},"2646":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عَزْرَةُ بْنُ ثَابِتٍ عَنْ ثُمَامَةَ بْنِ عَبْدِ اللَّهِ قَالَكَانَ أَنَسٌ لَا يَرُدُّ الطِّيبَ وَقَالَ أَنَسٌ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَرُدُّ الطِّيبَوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami ['Azrah bin Tsabit] dari [Tsumamah bin Abdullah] ia berkata; \"Anas tidak pernah menolak pemberian minyak wangi, [Anas] berkata; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam tidak pernah menolak pemberian minyak wangi.\" Dan dalam bab ini, ada juga hadits dari Abu Hurairah. Abu Isa berkata; Hadits ini hasan shahih."},"2647":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ عَبْدِ اللَّهِ بْنِ مُسْلِمٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثٌ لَا تُرَدُّ الْوَسَائِدُ وَالدُّهْنُ وَاللَّبَنُ الدُّهْنُ يَعْنِي بِهِ الطِّيبَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَعَبْدُ اللَّهِ هُوَ ابْنُ مُسْلِمِ بْنِ جُنْدُبٍ وَهُوَ مَدَنِيٌّ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Abdullah bin Muslim] dari [Ayahnya] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga hal yang tidak layak untuk ditolak, yaitu; (pemberian) bantal, minyak dan susu, minyak yaitu yang ada wewangiannya.\" Abu Isa berkata; Hadits ini gharib, Abdullah adalah Ibnu Muslim bin Jundub, seseorang penduduk Madinah."},"2648":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَلِيفَةَ أَبُو عَبْدِ اللَّهِ بَصْرِيٌّ وَعَمْرُو بْنُ عَلِيٍّ قَالَا حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ حَجَّاجٍ الصَّوَّافِ عَنْ حَنَانٍ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُعْطِيَ أَحَدُكُمْ الرَّيْحَانَ فَلَا يَرُدَّهُ فَإِنَّهُ خَرَجَ مِنْ الْجَنَّةِقَالَ هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَلَا نَعْرِفُ حَنَانًا إِلَّا فِي هَذَا الْحَدِيثِ وَأَبُو عُثْمَانَ النَّهْدِيُّ اسْمُهُ عَبْدُ الرَّحْمَنِ بْنُ مُلٍّ وَقَدْ أَدْرَكَ زَمَنَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَرَهُ وَلَمْ يَسْمَعْ مِنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Khalifah Abu Abdillah Bashri] dan ['Amru bin Ali] keduanya berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dari [Hajjaj Ash Shawwaf] dari [Hanan] dari [Abu Utsman An Nahdi] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian diberi bunga Raihan, janganlah menolaknya, karena dia berasal dari surga.\" Perawi berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari jalur ini, dan kami tidak mengetahui Hanan kecuali dalam hadits ini, adapun nama Abu Utsman An Nahdi adalah Abdurrahman bin Mull, dan dia semasa dengan Nabi shallallahu 'alaihi wasallam namun tidak pernah melihat beliau dan tidak mendengar hadits dari beliau."},"2649":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقِ بْنِ سَلَمَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُبَاشِرُ الْمَرْأَةُ الْمَرْأَةَ حَتَّى تَصِفَهَا لِزَوْجِهَا كَأَنَّمَا يَنْظُرُ إِلَيْهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Muawiyah] dari [Al A'masy] dari [Syaqiq bin Salamah] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang isteri menceritakan cirri-ciri wanita lain pada suaminya sehingga suaminya seolah-olah melihatnya.\" Abu Isa berkata; Hadits ini hasan shahih."},"2650":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي زِيَادٍ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ أَخْبَرَنِي الضَّحَّاكُ بْنُ عُثْمَانَ أَخْبَرَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْظُرُ الرَّجُلُ إِلَى عَوْرَةِ الرَّجُلِ وَلَا تَنْظُرُ الْمَرْأَةُ إِلَى عَوْرَةِ الْمَرْأَةِ وَلَا يُفْضِي الرَّجُلُ إِلَى الرَّجُلِ فِي الثَّوْبِ الْوَاحِدِ وَلَا تُفْضِي الْمَرْأَةُ إِلَى الْمَرْأَةِ فِي الثَّوْبِ الْوَاحِدِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abdullah bin Abu Ziyad] telah menceritakan kepada kami [Zaid bin Hubab] telah menceritakan kepada kami [Adl Dlahhak bin Utsman] telah mengabarkan kepadaku [Zaid bin Aslam] dari [Abdurrahman bin Abu Sa'id Al Khudri] dari [Ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang laki-laki melihat aurat laki-laki lain dan janganlah seorang wanita melihat aurat wanita lain, janganlah seorang laki-laki satu selimut dengan laki-laki lainnya dan juga janganlah seorang wanita satu selimut dengan wanita lainnya.\" Abu Isa berkata; Hadits ini hasan gharib shahih."},"2651":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ وَيَزِيدُ بْنُ هَارُونَ قَالَا حَدَّثَنَا بَهْزُ بْنُ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقُلْتُ يَا نَبِيَّ اللَّهِ عَوْرَاتُنَا مَا نَأْتِي مِنْهَا وَمَا نَذَرُ قَالَ احْفَظْ عَوْرَتَكَ إِلَّا مِنْ زَوْجَتِكَ أَوْ مَا مَلَكَتْ يَمِينُكَ قُلْتُ يَا رَسُولَ اللَّهِ إِذَا كَانَ الْقَوْمُ بَعْضُهُمْ فِي بَعْضٍ قَالَ إِنْ اسْتَطَعْتَ أَنْ لَا يَرَاهَا أَحَدٌ فَلَا يَرَاهَا قَالَ قُلْتُ يَا نَبِيَّ اللَّهِ إِذَا كَانَ أَحَدُنَا خَالِيًا قَالَ فَاللَّهُ أَحَقُّ أَنْ يُسْتَحْيَا مِنْهُ مِنْ النَّاسِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Mu'adz] dan [Yazid bin Harun] keduanya berkata; telah menceritakan kepada kami [Bahz bin Hakim] dari [Ayahnya] dari [kakeknya] ia berkata; Aku berkata; \"Wahai Nabiyullah, manakah aurat kami yang harus kami tutupi dan yang kami biarkan terbuka?\" Beliau menjawab: \"Jagalah auratmu kecuali dari istrimu atau budakmu.\" Aku bertanya: \"Wahai Rasulullah, bila dengan sejenis?\" Beliau menjawab: \"Bila kau mampu agar tidak ada seorang pun yang melihatnya, maka jangan sampai ia melihatnya.\" Aku berkata; \"Wahai nabiyullah, bila salah seorang dari kami sendirian?\" Beliau menjawab: \"Hendaknya ia lebih layak untuk malu kepada Allah daripada kepada manusia.\" Abu Isa berkata; Hadits ini hasan."},"2652":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ عَنْ زُرْعَةَ بْنِ مُسْلِمِ بْنِ جَرْهَدٍ الْأَسْلَمِيِّ عَنْ جَدِّهِ جَرْهَدٍ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجَرْهَدٍ فِي الْمَسْجِدِ وَقَدْ انْكَشَفَ فَخِذُهُ فَقَال إِنَّ الْفَخِذَ عَوْرَةٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ مَا أَرَى إِسْنَادَهُ بِمُتَّصِلٍ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Abu An Nadlrah] bekas budak Umar bin 'Ubaidullah, dari [Zur'ah bin Muslim bin Jarhad Al Aslami] dari kakeknya yaitu [Jarhad] ia berkata; Nabi shallallahu 'alaihi wasallam melintasi Jarhad di masjid, sedangkan pahanya tersingkap, maka beliau bersabda: \"Sesungguhnya paha itu aurat.\" Abu Isa berkata; Hadits ini hasan, menurutku sanadnya tidak bersambung."},"2653":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ أَبِي الزِّنَادِ قَالَ أَخْبَرَنِي ابْنُ جَرْهَدٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ وَهُوَ كَاشِفٌ عَنْ فَخِذِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَطِّ فَخِذَكَ فَإِنَّهَا مِنْ الْعَوْرَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Abu Az Zinad] ia berkata; telah mengabarkan kepada kami [Ibnu Jarhad] dari [Ayahnya] bahwa Nabi shallallahu 'alaihi wasallam melewatinya ketika itu pahanya tersingkap, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Tutuplah pahamu karena itu termasuk aurat.\" Abu Isa berkata; Hadits ini hasan."},"2654":{"ar":"حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ الْحَسَنِ بْنِ صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ عَبْدِ اللَّهِ بْنِ جَرْهَدٍ الْأَسْلَمِيِّ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْفَخِذُ عَوْرَةٌقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Washil bin Abdul A'la] telah menceritakan kepada kami [Yahya bin Adam] dari [Al Hasan bin Shalih] dari [Abdullah bin Muhammad bin 'Uqail] dari [Abdullah bin Jarhad Al Aslami] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabada: \"Paha itu aurat.\" Abu Isa berkata; Hadits ini hasan gharib, melalui sanad ini."},"2655":{"ar":"حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى الْكُوفِيُّ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ إِسْرَائِيلَ عَنْ أَبِي يَحْيَى عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْفَخِذُ عَوْرَةٌوَفِي الْبَاب عَنْ عَلِيٍّ وَمُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ جَحْشٍ وَلِعَبْدِ اللَّهِ بْنِ جَحْشٍ صُحْبَةٌ وَلِابْنِهِ مُحَمَّدٍ صُحْبَةٌ","id":"Telah menceritakan kepada kami [Washil bin Abdul A'la Al Kufi] telah menceritakan kepada kami [Yahya bin Adam] dari [Isra`il] dari [Abu Yahya] dari [Mujahid] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Paha adalah aurat.\" Dan dalam bab ini, ada juga hadits dari Ali dan Muhammad bin Abdullah bin Jahsy. Abdullah bin Jahsy pernah bertemu Nabi shallallahu 'alaihi wasallam. Anaknya, Muhammad juga pernah bertemu beliau."},"2656":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا خَالِدُ بْنُ إِلْيَاسَ عَنْ صَالِحِ بْنِ أَبِي حَسَّانَ قَال سَمِعْتُ سَعِيدَ بْنَ الْمُسَيَّبِ يَقُولُإِنَّ اللَّهَ طَيِّبٌ يُحِبُّ الطَّيِّبَ نَظِيفٌ يُحِبُّ النَّظَافَةَ كَرِيمٌ يُحِبُّ الْكَرَمَ جَوَادٌ يُحِبُّ الْجُودَ فَنَظِّفُوا أُرَاهُ قَالَ أَفْنِيَتَكُمْ وَلَا تَشَبَّهُوا بِالْيَهُودِقَالَ فَذَكَرْتُ ذَلِكَ لِمُهَاجِرِ بْنِ مِسْمَارٍ فَقَالَ حَدَّثَنِيهِ عَامِرُ بْنُ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ إِلَّا أَنَّهُ قَالَ نَظِّفُوا أَفْنِيَتَكُمْ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَخَالِدُ بْنُ إِلْيَاسَ يُضَعَّفُ وَيُقَالُ ابْنُ إِيَاسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu 'Amir Al 'Aqadi] telah menceritakan kepada kami [Khalid bin Ilyas] dari [Shalih bin Abu Hassan] ia berkata; Aku mendengar [Sa'id bin Al Musayyab] berkata; \"Sesungguhnya Allah Maha Baik, dan menyukai kepada yang baik, Maha Bersih dan menyukai kepada yang bersih, Maha Pemurah, dan menyukai kemurahan, dan Maha Mulia dan menyukai kemuliaan, karena itu bersihkanlah diri kalian, \" aku mengiranya dia berkata; \"Halaman kalian, dan janganlah kalian menyerupai orang-orang Yahudi, \" Shalih bin Abu Hassan berkata; Hadits itu aku sampaikan kepada [Muhajir bin Mismar], lalu dia berkata; \" [Amir bin Sa'ad bin Abu Waqqas] telah menceritakannya kepadaku dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam dengan hadits yang semisal, Namun dalam hadits tersebut beliau bersabda: \"Bersihkanlah halaman kalian.\" Abu Isa berkata; Hadits ini gharib, dan Khalid bin Ilyas telah dilemahkan, dan dia juga dinamakan Ibnu Iyas."},"2657":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ نِيْزَكَ الْبَغْدَادِيُّ حَدَّثَنَا الْأَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا أَبُو مُحَيَّاةَ عَنْ لَيْثٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِيَّاكُمْ وَالتَّعَرِّيَ فَإِنَّ مَعَكُمْ مَنْ لَا يُفَارِقُكُمْ إِلَّا عِنْدَ الْغَائِطِ وَحِينَ يُفْضِي الرَّجُلُ إِلَى أَهْلِهِ فَاسْتَحْيُوهُمْ وَأَكْرِمُوهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَأَبُو مُحَيَّاةَ اسْمُهُ يَحْيَى بْنُ يَعْلَى","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Nizak Al Baghdadi] telah menceritakan kepada kami [Al Aswad bin 'Amir] telah menceritakan kepada kami [Abu Muhayyah] dari [Laits] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian telanjang (tanpa busana), karena kalian selalu bersama golongan (Malaikat) yang tidak berpisah dengan kalian, kecuali ketika buang air besar dan ketika seorang lelaki bersetubuh dengan istrinya, karena itu, malulah kepada mereka dan muliakanlah mereka.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari jalur ini, sedangkan Abu Muhayyah namanya adalah Yahya bin Ya'la.\""},"2658":{"ar":"حَدَّثَنَا الْقَاسِمُ بْنُ دِينَارٍ الْكُوفِيُّ حَدَّثَنَا مُصْعَبُ بْنُ الْمِقْدَامِ عَنْ الْحَسَنِ بْنِ صَالِحٍ عَنْ لَيْثِ بْنِ أَبِي سُلَيْمٍ عَنْ طَاوُسٍ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يَدْخُلْ الْحَمَّامَ بِغَيْرِ إِزَارٍ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يُدْخِلْ حَلِيلَتَهُ الْحَمَّامَ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يَجْلِسْ عَلَى مَائِدَةٍ يُدَارُ عَلَيْهَا بِالْخَمْرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ طَاوُوسٍ عَنْ جَابِرٍ إِلَّا مِنْ هَذَا الْوَجْهِ قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ لَيْثُ بْنُ أَبِي سُلَيْمٍ صَدُوقٌ وَرُبَّمَا يَهِمُ فِي الشَّيْءِ قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ وَقَالَ أَحْمَدُ بْنُ حَنْبَلٍ لَيْثٌ لَا يُفْرَحُ بِحَدِيثِهِ كَانَ لَيْثٌ يَرْفَعُ أَشْيَاءَ لَا يَرْفَعُهَا غَيْرُهُ فَلِذَلِكَ ضَعَّفُوهُ","id":"Telah menceritakan kepada kami [Al Qasim bin Dinar Al Kufi] telah menceritakan kepada kami [Mush'ab bin Al Miqdam] dari [Al Hasan bin Shalih] dari [Laits bin Abu Sulaim] dari [Thawus] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa beriman kepada Allah dan hari akhir, janganlah masuk kamar mandi tanpa busana, barangsiapa beriman kepada Allah dan hari akhir, janganlah memasukkan istrinya ke pemandian (umum), dan barangsiapa beriman kepada Allah dan hari akhir, janganlah duduk di dekat meja yang di atasnya diedarkan khamar.\" Abu Isa berkata; Hadits ini hasan gharib, kami tidak mengetahui hadits tersebut dari Thawus dari Jabir kecuali dari jalur ini. Muhammad bin Isma`il berkata; Laits bin Abu Sulaim shuduq (jujur dalam periwayatan hadits), walaupun sebagia periwayatannya ada yang wahm (cacat). Muhammad bin Isma`il berkata; Ahmad bin Hanbal berkata; \"Haditsnya Laits tidak di bisa diandalkan, sebab Laits sering merafa'kan hadits yang tidak dirafa'kan oleh perawi yang lain, oleh karena itu mereka melemahkannya.\""},"2659":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ الْأَعْرَجِ عَنْ أَبِي عُذْرَةَ وَكَانَ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى الرِّجَالَ وَالنِّسَاءَ عَنْ الْحَمَّامَاتِ ثُمَّ رَخَّصَ لِلرِّجَالِ فِي الْمَيَازِرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ حَمَّادِ بْنِ سَلَمَةَ وَإِسْنَادُهُ لَيْسَ بِذَاكَ الْقَائِمِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Abdullah bin Syaddad Al A'raj] dari [Abu 'Udzri] -dia pernah bertemu Nabi shallallahu 'alaihi wasallam- dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam melarang para lelaki dan wanita masuk kamar mandi (umum), kemudian beliau memberikan keringan bagi para lelaki jika mengenakan sarung (kain penutup).\" Abu Isa berkata; Kami tidak mengetahui hadits ini kecuali dari hadits Hammad bin Salamah, sedangkan sanadnya tidak sedemikian kuat."},"2660":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَنْبَأَنَا شُعْبَةُ عَنْ مَنْصُورٍ قَال سَمِعْتُ سَالِمَ بْنَ أَبِي الْجَعْدِ يُحَدِّثُ عَنْ أَبِي الْمَلِيحِ الْهُذَلِيِّ أَنَّنِسَاءً مِنْ أَهْلِ حِمْصَ أَوْ مِنْ أَهْلِ الشَّامِ دَخَلْنَ عَلَى عَائِشَةَ فَقَالَتْ أَنْتُنَّ اللَّاتِي يَدْخُلْنَ نِسَاؤُكُنَّ الْحَمَّامَاتِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ امْرَأَةٍ تَضَعُ ثِيَابَهَا فِي غَيْرِ بَيْتِ زَوْجِهَا إِلَّا هَتَكَتْ السِّتْرَ بَيْنَهَا وَبَيْنَ رَبِّهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah memberitakan kepada kami [Syu'bah] dari [Manshur] ia berkata; Aku mendengar [Salim bin Abu Al Ja'd] menceritakan dari [Abu Al Malih Al Hudzali] bahwa beberapa wanita dari penduduk Himsh atau Syam masuk menemui ['Aisyah], ia berkata; \"Kaliankah yang menyuruh wanita-wanita kalian masuk ke kamar mandi (umum)? Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang wanita menanggalkan bajunya di selain rumah suaminya, melainkan ia telah merusak tabir antara dirinya dengan Rabbnya.\" Abu Isa berkata; Hadits ini hasan."},"2661":{"ar":"حَد��َثَنَا سَلَمَةُ بْنُ شَبِيبٍ وَالْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ وَعَبْدُ بْنُ حُمَيْدٍ وَغَيْرُ وَاحِدٍ وَاللَّفْظُ لِلْحَسَنِ بْنِ عَلِيٍّ قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّهُ سَمِعَ ابْنَ عَبَّاسٍ يَقُولُ سَمِعْتُ أَبَا طَلْحَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ كَلْبٌ وَلَا صُورَةُ تَمَاثِيلَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Salamah bin Syabib] dan [Al Hasan bin Ali Al Khallal] dan [Abdu bin Humaid] dan yang lain, sedangkan redaksi haditsnya milik Al Hasan bin Ali, mereka berkata; telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] bahwa ia mendengar [Ibnu Abbas] berkata; Aku mendengar [Abu Thalhah] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malaikat tidak akan memasuki rumah yang ada anjing dan gambarnya.\" Abu Isa berkata; Hadits ini hasan shahih."},"2662":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّ رَافِعَ بْنَ إِسْحَقَ أَخْبَرَهُقَالَ دَخَلْتُ أَنَا وَعَبْدُ اللَّهِ بْنُ أبِي طَلْحَةَ عَلَى أَبِي سَعِيدٍ الْخُدْرِيِّ نَعُودُهُ فَقَالَ أَبُو سَعِيدٍ أَخْبَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْمَلَائِكَةَ لَا تَدْخُلُ بَيْتًا فِيهِ تَمَاثِيلُ أَوْ صُورَةٌشَكَّ إِسْحَقُ لَا يَدْرِي أَيُّهُمَا قَالَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Rauh bin 'Ubadah] telah menceritakan kepada kami [Malik bin Anas] dari [Ishaq bin Abdullah bin Abu Thalhah] bahwa [Rabi' bin Ishaq] telah menceritakan kepadanya, ia berkata; Aku dan Abdullah bin Abu Thalhah pernah menemui [Abu Sa'id Al Khudri] untuk menjenguknya. Abu Sa'id berkata; telah mengabarkan kepada kami Rasulullah shallallahu 'alaihi wasallam bahwa Malaikat tidak akan memasuki rumah yang ada patung atau gambarnya.\" Ishaq ragu (dengan redaksi haditsnya), tidak tahu yang mana (antara patung atau gambar). Abu Isa berkata; Hadits ini hasan shahih."},"2663":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ حَدَّثَنَا مُجَاهِدٌ قَالَ حَدَّثَنَا أَبُو هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَانِي جِبْرِيلُ فَقَالَ إِنِّي كُنْتُ أَتَيْتُكَ الْبَارِحَةَ فَلَمْ يَمْنَعْنِي أَنْ أَكُونَ دَخَلْتُ عَلَيْكَ الْبَيْتَ الَّذِي كُنْتَ فِيهِ إِلَّا أَنَّهُ كَانَ فِي بَابِ الْبَيْتِ تِمْثَالُ الرِّجَالِ وَكَانَ فِي الْبَيْتِ قِرَامُ سِتْرٍ فِيهِ تَمَاثِيلُ وَكَانَ فِي الْبَيْتِ كَلْبٌ فَمُرْ بِرَأْسِ التِّمْثَالِ الَّذِي بِالْبَابِ فَلْيُقْطَعْ فَلْيُصَيَّرْ كَهَيْئَةِ الشَّجَرَةِ وَمُرْ بِالسِّتْرِ فَلْيُقْطَعْ وَيُجْعَلْ مِنْهُ وِسَادَتَيْنِ مُنْتَبَذَتَيْنِ يُوطَآَنِ وَمُرْ بِالْكَلْبِ فَيُخْرَجْ فَفَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ ذَلِكَ الْكَلْبُ جَرْوًا لِلْحَسَنِ أَوْ الْحُسَيْنِ تَحْتَ نَضَدٍ لَهُ فَأَمَرَ بِهِ فَأُخْرِجَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ عَائِشَةَ وَأَبِي طَلْحَةَ","id":"Telah menceritakan kepada kami [Suwaid] telah menceritakan kepada kami [Abdullah bin Al Mubarak] telah mengabarkan kepada kami [Yunus bin Abu Ishaq] telah mengabarkan kepada kami [Mujahid] ia berkata; telah menceritakan kepada kami [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jibril datang kepadaku, kemudian dia berkata; \"Sesungguhnya tadi malam aku datang kepadamu, dan tidak ada yang menghalangiku masuk menemuimu dalam rumah yang kamu tempati, kecuali karena pada pintu rumah ada gambar seorang lelaki, dan di dalam rumah ada tabir tipis yang bergambar dan ada anjingnya, perintahkan agar kepala gambar-gambar yang ada di pintu diptong dan jadikan seperti bentuk pohon, perintahkan agar tabir itu dipotong kemudian dijadikan dua bantal yang di hamparkan dan di jadikan tempat sandaran serta perintahkan agar anjing itu dikeluarkan dari rumah.\" Lalu Rasulullah shallallahu 'alaihi wasallam melakukannya, anjing itu adalah anak anjing yang di jadikan mainan untuk Hasan dan Husain, \" kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan supaya anjing tersebut di keluarkan.\" Abu Isa berkata; Hadits ini hasan shahih, dan dalam bab ini, ada juga hadits dari 'Aisyah dan Abu Thalhah."},"2664":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ مُحَمَّدٍ الْبَغْدَادِيُّ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا إِسْرَائِيلُ عَنْ أَبِي يَحْيَى عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَمَرَّ رَجُلٌ وَعَلَيْهِ ثَوْبَانِ أَحْمَرَانِ فَسَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَرُدَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَمَعْنَى هَذَا الْحَدِيثِ عِنْدَ أَهْلِ الْعِلْمِ أَنَّهُمْ كَرِهُوا لُبْسَ الْمُعَصْفَرِ وَرَأَوْا أَنَّ مَا صُبِغَ بِالْحُمْرَةِ بِالْمَدَرِ أَوْ غَيْرِ ذَلِكَ فَلَا بَأْسَ بِهِ إِذَا لَمْ يَكُنْ مُعَصْفَرًا","id":"Telah menceritakan kepada kami [Abbas bin Muhammad Al Baghdadi] telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Isra`il] dari [Abu Yahya] dari [Mujahid] dari [Abdullah bin 'Amru] ia berkata; Seseorang memakai dua kain yang berwarna merah lewat, lalu mengucapkan salam kepada Nabi shallallahu 'alaihi wasallam, namun beliau tidak menjawab salamnya.\" Abu Isa berkata; Hadits ini hasan gharib dari jalur ini. Makna hadits ini menurut para ahli ilmu, mereka memakruhkan mengenakan pakaian yang diwarnai dengan warna kuning (seluruh bagiannya), mereka berpendapat bahwa kain yang diwarnai warna merah dengan bahan dari madar (jenis tanah liat yang kering) atau dengan yang lainnya hukumnya tidak apa-apa, jika warnanya tidak menjadi kuning.\""},"2665":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ هُبَيْرَةَ بْنِ يَرِيمَ قَالَ قَالَ عَلِيٌّنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ خَاتَمِ الذَّهَبِ وَعَنْ الْقَسِّيِّ وَعَنْ الْمِيثَرَةِ وَعَنْ الْجِعَةِقَالَ أَبُو الْأَحْوَصِ وَهُوَ شَرَابٌ يُتَّخَذُ بِمِصْرَ مِنْ الشَّعِيرِ قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Hubairah bin Yarim] ia berkata; [Ali] berkata; Nabi shallallahu 'alaihi wasallam melarang mengenakan cincin emas, qassi, mitsarah dan ji'ah.\" Abu Al Ahwash berkata; \"Itu adalah minuman yang terbuat dari gandum di Mesir.\" Abu Isa berkata; Hadits ini hasan shahih. "},"2666":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَعَبْدُ الرّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ الْأَشْعَثِ بْنِ سُلَيْمٍ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدِ بْنِ مُقَرِّنٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَبْعٍ وَنَهَانَا عَنْ سَبْعٍ أَمَرَنَا بِاتِّبَاعِ الْجَنَازَةِ وَعِيَادَةِ الْمَرِيضِ وَتَشْمِيتِ الْعَاطِسِ وَإِجَابَةِ الدَّاعِي وَنَصْرِ الْمَظْلُومِ وَإِبْرَارِ الْقَسَمِ وَرَدِّ السَّلَامِ وَنَهَانَا عَنْ سَبْعٍ عَنْ خَاتَمِ الذَّهَبِ أَوْ حَلْقَةِ الذَّهَبِ وَآنِيَةِ الْفِضَّةِ وَلُبْسِ الْحَرِيرِ وَالدِّيبَاجِ وَالْإِسْتَبْرَقِ وَالْقَسِّيِّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَشْعَثُ بْنُ سُلَيْمٍ هُوَ أَشْعَثُ بْنُ أَبِي الشَّعْثَاءِ اسْمُهُ سُلَيْمُ بْنُ الْأَسْوَدِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Abdurrahman bin Mahdi] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Asy'ats bin Sulaim] dari [Mu'awiyah bin Suwaid bin Muqarrin] dari [Al Barra` bin Azib] ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kepada kami tujuh hal dan melarang tujuh hal, beliau memerintahkan kami untuk mengiringi jenazah, menjenguk orang sakit, mendoakan orang yang bersin, memenuhi undangan, menolong orang yang teraniaya, menunaikan sumpah dan menjawab salam. Beliau melarang tujuh hal dari kami, yaitu mengenakan cincin emas atau kalung emas, bejana emas, mengenakan sutera, sutra tebal dan sutera tipis dan qassi.\" Abu Isa berkata; Hadits ini shahih. Asy'ats bin Sulaim adalah Asy'ats bin Abu Al Asy Sya'tsa`, namanya Sulaim bin Al Aswad."},"2667":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مَيْمُونِ بْنِ أَبِي شَبِيبٍ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَسُوا الْبَيَاضَ فَإِنَّهَا أَطْهَرُ وَأَطْيَبُ وَكَفِّنُوا فِيهَا مَوْتَاكُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Habib bin Abu Tsabit] dari [Maimun bin Abu Syabib] dari [Samurah bin Jundub] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kenakanlah pakaian warna putih, karena itu lebih suci dan lebih baik, dan gunakanlah kain putih untuk mangkafani mayit kalian.\" Abu Isa berkata; Hadits ini hasan shahih, dan dalam bab ini, ada juga hadits dari Ibnu Abbas dan Ibnu Umar."},"2668":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْثَرُ بْنُ الْقَاسِمِ عَنْ الْأَشْعَثِ وَهُوَ ابْنُ سَوَّارٍ عَنْ أَبِي إِسْحَقَ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي لَيْلَةٍ إِضْحِيَانٍ فَجَعَلْتُ أَنْظُرُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِلَى الْقَمَرِ وَعَلَيْهِ حُلَّةٌ حَمْرَاءُ فَإِذَا هُوَ عِنْدِي أَحْسَنُ مِنْ الْقَمَرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ الْأَشْعَثِ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abtsar bin Al Qasim] dari [Al Asy'ats yaitu Ibnu Sawwar] dari [Abu Ishaq] dari [Jabir bin Samurah] ia berkata; \"Pada malam bulan purnama aku melihat Rasulullah shallallahu 'alaihi wasallam, aku melihat Rasulullah shallallahu 'alaihi wasallam dan melihat bulan, ketika itu beliau tengah mengenakan pakaian berwarna merah, beliau bagiku lebih bagus rupanya daripada bulan.\" Abu Isa berkata; Hadits ini hasan gharib, kami tidak mengetahuinya kecuali dari hadits Al Asy'ats."},"2669":{"ar":"وَرَوَى شُعْبَةُ وَالثَّوْرِيُّ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَرَأَيْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُلَّةً حَمْرَاءَحَدَّثَنَا بِذَلِكَ مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ بِهَذَا وَفِي الْحَدِيثِ كَلَامٌ أَكْثَرُ مِنْ هَذَا قَالَ سَأَلْتُ مُحَمَّدًا قُلْتُ لَهُ حَدِيثُ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ أَصَحُّ أَوْ حَدِيثُ جَابِرِ بْنِ سَمُرَةَ فَرَأَى كِلَا الْحَدِيثَيْنِ صَحِيحًا وَفِي الْبَاب عَنْ الْبَرَاءِ وَأَبِي جُحَيْفَةَ","id":"Telah menceritakan kepada kami [Syu'bah] dan [Ats Tsauri] dari [Abu Ishaq] dari [Al Bara` bin Azib] ia berkata; Aku melihat Rasulullah shallallahu 'alaihi wasallam mengenakan busana merah.\" Telah menceritakan kepada kami [Mahmud bin Ghailan] seperti itu, telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dan telah menceritakan kepada kami [Muhammad bin Basyr] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dengan hadits serupa. Dalam hadits tersebut, terdapat pembicaraan yang lebih banyak dari hadits ini. Perawi berkata; Aku bertanya kepada Muhammad, Aku berkata padanya: \"Apakah hadits Abu Ishaq dari Al Barra` lebih shahih atau hadits Jabir bin Samurah?.\" Muhammad menilai kedua hadits itu shahih. Dalam hal ini, ada hadits serupa dari Al Barra` dan Abu Juhaifah."},"2670":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ إِيَادِ بْنِ لَقِيطٍ عَنْ أَبِيهِ عَنْ أَبِي رِمْثَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ بُرْدَانِ أَخْضَرَانِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عُبَيْدِ اللَّهِ بْنِ إِيَادٍ وَأَبُو رِمْثَةَ التَّيْمِيُّ يُقَالُ اسْمُهُ حَبِيبُ بْنُ حَيَّانَ وَيُقَالُ اسْمُهُ رِفَاعَةُ بْنُ يَثْرِبِيٍّ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami ['Ubaidullah bin Iyad bin Laqith] dari [Ayahnya] dari [Abu Rimtsah] ia berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam mengenakan dua selimut berwarna hijau.\" Abu Isa berkata; Hadits ini hasan gharib, kami hanya mengetahuinya dari hadits 'Ubaidullah bin Iyad dan Abu Rimtsah At Taimi. Ada yang mengatakan bahwa namanya adalah Habib bin Hayyan, yang lain mengatakan namanya Rifa'ah bin Yatsribi."},"2671":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ أَخْبَرَنِي أَبِي عَنْ مُصْعَبِ بْنِ شَيْبَةَ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ عَائِشَةَ قَالَتْخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ غَدَاةٍ وَعَلَيْهِ مِرْطٌ مِنْ شَعَرٍ أَسْوَدَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Yahya bin Zakariya bin Abu Za`idah] telah mengabarkan kepadaku [Ayahku] dari [Mush'ab bin Syaibah] dari [Shafiyah binti Syaibah] dari ['Aisyah] ia berkata; \"Pada suatu pagi, Nabi shallallahu 'alaihi wasallam pergi sambil mengenakan pakaian dari bulu berwarna hitam.\" Abu Isa berkata; Hadits ini hasan gharib shahih."},"2672":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ الصَّفَّارُ أَبُو عُثْمَانَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ حَسَّانَ أَنَّهُ حَدَّثَتْهُ جَدَّتَاهُ صَفِيَّةُ بِنْتُ عُلَيْبَةَ وَدُحَيْبَةُ بِنْتُ عُلَيْبَةَ حَدَّثَتَاهُ عَنْ قَيْلَةَ بِنْتِ مَخْرَمَةَ وَكَانَتَا رَبِيبَتَيْهَا وَقَيْلَةُ جَدَّةُ أَبِيهِمَا أُمُّ أُمِّهِ أَنَّهَا قَالَتْقَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ الْحَدِيثَ بِطُولِهِ حَتَّى جَاءَ رَجُلٌ وَقَدْ ارْتَفَعَتْ الشَّمْسُ فَقَالَ السَّلَامُ عَلَيْكَ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْكَ السَّلَامُ وَرَحْمَةُ اللَّهِ وَعَلَيْهِ تَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْمَالُ مُلَيَّتَيْنِ كَانَتَا بِزَعْفَرَانٍ وَقَدْ نَفَضَتَا وَمَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَسِيبُ نَخْلَةٍقَالَ أَبُو عِيسَى حَدِيثُ قَيْلَةَ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ اللَّهِ بْنِ حَسَّانَ","id":"Telah menceritakan kepada kami ['Abdu bin Humaid] telah menceritakan kepada kami ['Affan bin Muslim Ash Shaffar Abu Utsman] telah menceritakan kepada kami [Abdullah bin Hassan] bahwa dua orang neneknya yaitu [Shafiyyah binti 'Ulayyah] dan [Duhaibah binti 'Ulaibah] telah menceritakan kepadanya, dari [Qailah binti Makhramah], keduanya (Shafiyah dan Duhaibah) adalah anak tiri Qailah, sementara Qailah adalah nenek dari ayah mereka berdua, dia berkata; \"Kami datang kepada Nabi shallallahu 'alaihi wasallam, -kemudian ia menyebutkan hadits panjang- sampai datanglah seseorang, sementara sinar matahari tengah naik sepenggalahan, lalu dia mengatakan; \"ASSALAAMU 'ALAIKA YA RASULALLAAH, \" Rasulullah shallallahu 'alaihi wasallam menjawab: \"WA'ALAIKAS SALAM WARAHMATULLAAH.\" Beliau yaitu Nabi shallallahu 'alaihi wasallam tengah mengenakan pakaian dan selimut usang yang diberi minyak za'faran, ketika itu Nabi shallallahu 'alaihi wasallam membawa pelepah kurma.\" Abu Isa berkata; Kami tidak mengetahui hadits Qailah kecuali dari hadits Abdullah bin Hasan."},"2673":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ ح و حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ حَمَّادِ بْنِ زَيْدٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّزَعْفُرِ لِلرِّجَالِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى شُعْبَةُ هَذَا الْحَدِيثَ عَنْ إِسْمَعِيلَ ابْنِ عُلَيَّةَ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ التَّزَعْفُرِ حَدَّثَنَا بِذَلِكَ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا آدَمُ عَنْ شُعْبَةَ قَالَ أَبُو عِيسَى وَمَعْنَى كَرَاهِيَةِ التَّزَعْفُرِ لِلرِّجَالِ أَنْ يَتَزَعْفَرَ الرَّجُلُ يَعْنِي أَنْ يَتَطَيَّبَ بِهِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad bin Zaid] ia berkata, -dan diriwayatkan dari jalur lain- telah menceritakan kepada kami [Ishaq bin Manshur] telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Hammad bin Zaid] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang seorang laki-laki mengenakan za'faran.\" Abu Isa berkata; Hadits ini hasan shahih. [Syu'bah] meriwayatkan hadits ini dari [Isma'il bin 'Ulaiyah] dari [Abdul Aziz bin Shuhaib] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam melarang mengenakan za'faran. Telah menceritakan kepada kami [Abdullah bin Abdurrahman] seperti itu, telah menceritakan kepada kami [Adam] dari [Syu'bah]. Abu Isa berkata; \"Makna makruhnya mengenakan za'faran bagi lelaki adalah bila dipakai untuk wewangian.\""},"2674":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ عَنْ شُعْبَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ قَال سَمِعْتُ أَبَا حَفْصِ بْنَ عُمَرَ يُحَدِّثُ عَنْ يَعْلَى بْنِ مُرَّةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْصَرَ رَجُلًا مُتَخَلِّقًا قَالَ اذْهَبْ فَاغْسِلْهُ ثُمَّ اغْسِلْهُ ثُمَّ لَا تَعُدْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ اخْتَلَفَ بَعْضُهُمْ فِي هَذَا الْإِسْنَادِ عَنْ عَطَاءِ بْنِ السَّائِبِ قَالَ عَلِيٌّ قَالَ يَحْيَى بْنُ سَعِيدٍ مَنْ سَمِعَ مِنْ عَطَاءِ بْنِ السَّائِبِ قَدِيمًا فَسَمَاعُهُ صَحِيحٌ وَسَمَاعُ شُعْبَةَ وَسُفْيَانَ مِنْ عَطَاءِ بْنِ السَّائِبِ صَحِيحٌ إِلَّا حَدِيثَيْنِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ زَاذَانَ قَالَ شُعْبَةُ سَمِعْتُهُمَا مِنْهُ بِآخِرَةٍ قَالَ أَبُو عِيسَى يُقَالُ إِنَّ عَطَاءَ بْنَ السَّائِبِ كَانَ فِي آخِرِ أَمْرِهِ قَدْ سَاءَ حِفْظُهُ وَفِي الْبَاب عَنْ عَمَّارٍ وَأَبِي مُوسَى وَأَنَسٍ وَأَبُو حَفْصٍ هُوَ أَبُو حَفْصِ بْنُ عُمَرَ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Daud Ath Thayalisi] dari [Syu'bah] dari [Atha` bin As Sa`ib] ia berkata; Aku mendengar [Abu Hafs bin Umar] menceritakan dari [Ya'la bin Murrah] bahwa Nabi shallallahu 'alaihi wasallam melihat seorang lelaki berlumuran minyak wangi yang berwarna kuning, kemudian beliau bersabda: \"Pergi dan cucilah kemudian cucilah dan jangan ulangi lagi.\" Abu Isa berkata; Hadits ini hasan, sebagian ulama berbeda pendapat tentang sanad ini dari Atha` bin As Sa`ib, Ali berkata bahwa Yahya bin Sa'id berkata; Barangsiapa mendengar dari Atha` pada waktu dulu, maka hadits yang dia dengar shahih, sementara hadits yang didengar oleh Syu'bah dan Sufyan dari Atha` bin Sa`ib adalah shahih, kecuali dua hadits yaitu dari Atha` dari Zadzan dimana Syu'bah berkata; Aku mendengar darinya di masa-masa akhir (hayatnya). Abu Isa berkata; Dikatakan bahwa hafalan Atha` bin Sa`ib buruk pada masa-masa akhir hayatnya. Dan dalam bab ini, ada juga hadits dari 'Ammar, Abu Musa, Anas dan Abu Hafs yaitu Abu Hafs bin Umar."},"2675":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ الْأَزْرَقُ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ حَدَّثَنِي مَوْلَى أَسْمَاءَ عَنْ ابْنِ عُمَرَ قَال سَمِعْتُ عُمَرَ يَذْكُرُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَبِسَ الْحَرِيرَ فِي الدُّنْيَا لَمْ يَلْبَسْهُ فِي الْآخِرَةِوَفِي الْبَاب عَنْ عَلِيٍّ وَحُذَيْفَةَ وَأَنَسٍ وَغَيْرِ وَاحِدٍ وَقَدْ ذَكَرْنَاهُ فِي كِتَابِ اللِّبَاسِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي عَمْرٍو مَوْلَى أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ الصِّدِّيقِ وَاسْمُهُ عَبْدُ اللَّهِ وَيُكْنَى أَبَا عَمْرٍو وَقَدْ رَوَى عَنْهُ عَطَاءُ بْنُ أَبِي رَبَاحٍ وَعَمْرُو بْنُ دِينَارٍ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ishaq bin Yusuf Al Azraq] telah menceritakan kepada kami [Abdul Malik bin Abu Sulaiman] telah menceritakan kepada kami [Bekas budak Asma`] dari [Ibnu Umar] ia berkata; Aku mendengar [Umar] menyebutkan, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memakai kain sutra di dunia, maka dia tidak akan memakainya di akhirat.\" Dan dalam bab ini, ada juga hadits dari Ali, Hudzaifah, Anas dan lainnya. Kami telah menyebutkannya dalam kitabul libas (kitab tentang pakaian). Abu Isa berkata; Hadits ini hasan shahih, telah diriwayatkan dari beberapa jalur sanad dari Abu 'Amru bekas budak Asma` binti Abu Bakar Ash Shiddiq, namanya adalah Abdullah sedangkan julukannya adalah Abu 'Amru. Atha` bin Abu Rabah dan 'Amru bin Dinar meriwayatkan hadits darinya."},"2676":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَسَمَ أَقْبِيَةً وَلَمْ يُعْطِ مَخْرَمَةَ شَيْئًا فَقَالَ مَخْرَمَةُ يَا بُنَيَّ انْطَلِقْ بِنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقْتُ مَعَهُ قَالَ ادْخُلْ فَادْعُهُ لِي فَدَعَوْتُهُ لَهُ فَخَرَج النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ قَبَاءٌ مِنْهَا فَقَالَ خَبَأْتُ لَكَ هَذَا قَالَ فَنَظَر إِلَيْهِ فَقَال رَضِيَ مَخْرَمَةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَابْنُ أَبِي مُلَيْكَةَ اسْمُهُ عَبْدُ اللَّهِ بْنُ عُبَيْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Abu Mulaikah] dari [Al Miswar bin Al Makhramah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah membagi-bagikan pakaian, dan tidak memberikan bagian sama sekali kepada Makhramah, maka Makhramah berkata; \"Wahai anakku, berangkatlah bersama kami menghadap Rasulullah shallallahu 'alaihi wasallam, \" akupun berangkat bersamanya, lalu Makhramah berkata; \"Masuklah dan panggilkan beliau untukku, \" aku pun memanggil beliau, maka Nabi shallallahu 'alaihi wasallam keluar dengan membawa pakaian, sambil bersabda: \"Aku simpan ini untukmu.\" Al Miswar berkata; Makhramah memandang beliau, lalu berkata; \"Makhramah rela.\" Abu Isa berkata; Hadits ini hasan shahih, Ibnu Mulaikah namanya adalah Abdullah bin 'Ubaidullah bin Abu Mulaikah."},"2677":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الزَّعْفَرَانِيُّ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يُحِبَّ أَنْ يَرَى أَثَرَ نِعْمَتِهِ عَلَى عَبْدِهِوَفِي الْبَاب عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِيهِ وَعِمْرَانَ بْنِ حُصَيْنٍ وَابْنِ مَسْعُودٍ قَالَ أَبُو عِيسَى هَ��َا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad Az Za'farani] telah menceritakan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah senang bila melihat bekas nikmat-Nya yang diberikan kepada hamba-NYa.\" Dan dalam bab ini, ada juga hadits dari Abul Ahwas dari ayahnya dan Imran bin Hushain serta Ibnu Mas'ud, Abu Isa berkata; Hadits ini hasan."},"2678":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ دَلْهَمِ بْنِ صَالِحٍ عَنْ حُجَيْرِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ النَّجَاشِيَّ أَهْدَى إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُفَّيْنِ أَسْوَدَيْنِ سَاذَجَيْنِ فَلَبِسَهُمَا ثُمَّ تَوَضَّأَ وَمَسَحَ عَلَيْهِمَاقَالَ هَذَا حَدِيثٌ حَسَنٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ دَلْهَمٍ وَقَدْ رَوَاهُ مُحَمَّدُ بْنُ رَبِيعَةَ عَنْ دَلْهَمٍ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Waki'] dari [Dalham bin Shalih] dari [Hujair bin 'Abdullah] dari [Ibnu Buraidah] dari [Ayahnya] bahwa Najasyi menghadiahkan sepasang sepatu berwarna hitam yang tidak di bordir kepada Nabi shallallahu 'alaihi wasallam, lalu beliau memakainya dan berwudlu sambil mengusap keduanya.\" Abu Isa berkata; Hadits ini hasan, hanyasannya kami mengetahui hadits ini dari hadits Dalham, sedangkan [Muhammad bin Rabi'ah] telah meriwayatkannya dari [Dalham]."},"2679":{"ar":"حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ الْهَمْدَانِيُّ حَدَّثَنَا عَبْدَةُ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ نَتْفِ الشَّيْبِ وَقَالَ إِنَّهُ نُورُ الْمُسْلِمِقَالَ هَذَا حَدِيثٌ حَسَنٌ قَدْ رُوِيَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ وَغَيْرِ وَاحِدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ","id":"Telah menceritakan kepada kami [Harun bin Ishaq Al Hamdani] telah menceritakan kepada kami ['Abdah] dari [Muhammad bin Ishaq] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] bahwa Nabi shallallahu 'alaihi wasallam melarang mencabuti rambut uban, beliau bersabda: \"Sesungguhnya uban itu cahaya bagi seorang muslim.\" Abu Isa berkata; Hadits ini hasan, telah diriwayatkan dari [Abdurrahman bin Al Harits] dan yang lainnya dari ['Amru bin Syu'aib]."},"2680":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى حَدَّثَنَا شَيْبَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْتَشَارُ مُؤْتَمَنٌقَالَ هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَى غَيْرُ وَاحِدٍ عَنْ شَيْبَانَ بْنِ عَبْدِ الرَّحْمَنِ النَّحْوِيِّ وَشَيْبَانُ هُوَ صَاحِبُ كِتَابٍ وَهُوَ صَحِيحُ الْحَدِيثِ وَيُكْنَى أَبَا مُعَاوِيَةَ حَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ الْعَطَّارُ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ قَالَ قَالَ عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ إِنِّي لَأُحَدِّثُ الْحَدِيثَ فَمَا أَخْرِمُ مِنْهُ حَرْفًا","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Al Hasan bin Musa] telah menceritakan kepada kami [Syaiban] dari [Abdul Malik bin 'Umair] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya seorang penasehat adalah orang yang amanah.\" Abu Isa berkata; Hadits ini hasan, banyak yang meriwayatkan hadits ini dari Syaiban bin Abdurrahman An Nahwi, sedangkan Syaiban adalah pemilik kitab, haditsnya shahih, julukannya Abu Mu'awiyah. Telah menceritakan kepada kami Abdul Jabbar bin Al 'Ala Al Athar dari Sufyan bin 'Uyainah, dia berkata; Abdul Malik bin 'Umair berkata; Aku menyampaikan hadits dan tidak ada satu huruf pun yang aku kurangi."},"2681":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ دَاوُدَ بْنِ أَبِي عَبْدِ اللَّهِ عَنْ ابْنِ جُدْعَانَ عَنْ جَدَّتِهِ عَنْ أُمِّ سَلَمَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْتَشَارُ مُؤْتَمَنٌوَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَأَبِي هُرَيْرَةَ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ أُمِّ سَلَمَةَ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Waki'] dari [Daud bin Abu Abdullah] dari [Ibnu Jud'an] dari [neneknya] dari [Ummu Salamah], dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya seorang penasehat adalah orang yang amanah (dapat di percaya).\" Dan dalam bab ini, ada juga hadits dari Ibnu Mas'ud, Abu Hurairah dan Ibnu Umar. Abu Isa berkata; Hadits ini gharib dari hadits Ummu Salamah."},"2682":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ وَحَمْزَةَ ابْنَيْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الشُّؤْمُ فِي ثَلَاثَةٍ فِي الْمَرْأَةِ وَالْمَسْكَنِ وَالدَّابَّةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ وَبَعْضُ أَصْحَابِ الزُّهْرِيِّ لَا يَذْكُرُونَ فِيهِ عَنْ حَمْزَةَ إِنَّمَا يَقُولُونَ عَنْ سَالِمٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَكَذَا رَوَى لَنَا ابْنُ أَبِي عُمَرَ هَذَا الْحَدِيثَ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ وَحَمْزَةَ ابْنَيْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِمَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ وَلَمْ يَذْكُرْ فِيهِ سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ حَمْزَةَ وَرِوَايَةُ سَعِيدٍ أَصَحُّ لِأَنَّ عَلِيَّ بْنَ الْمَدِينِيِّ وَالْحُمَيْدِيَّ رَوَيَا عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ وَذَكَرَا عَنْ سُفْيَانَ قَالَ لَمْ يَرْوِ لَنَا الزُّهْرِيُّ هَذَا الْحَدِيثَ إِلَّا عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ وَرَوَى مَالِكٌ هَذَا الْحَدِيثَ عَنْ الزُّهْرِيِّ وَقَالَ عَنْ سَالِمٍ وَحَمْزَةَ ابْنَيْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِمَا وَفِي الْبَاب عَنْ سَهْلِ بْنِ سَعْدٍ وَعَائِشَةَ وَأَنَسٍ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنْ كَانَ الشُّؤْمُ فِي شَيْءٍ فَفِي الْمَرْأَةِ وَالدَّابَّةِ وَالْمَسْكَنِ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dan [Hamzah] -dua putra Abdullah bin Umar, dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Terkadang) kesialan itu ada pada tiga hal, yaitu; wanita, tempat tinggal dan binatang tunggangan (kendaraan).\" Abu Isa berkata; hadits ini shahih, sebagaian sahabat Az Zuhri tidak menyebutkannya dari Hamzah, mereka hanya mengatakan; Dari Salim dari Ayahnya dari Nabi shallallahu 'alaihi wasallam. Demikianlah Ibnu Abu Umar meriwayatkan hadits ini kepada kami, dari Sufyan bin 'Uyainah dari Az Zuhri dari Salim dan Hamzah, -dua putra Abdullah bin Umar, - dari ayahnya dari Nabi shallallahu 'alaihi wasallam. Telah menceritakan kepada kami [Sa'id bin Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [Ayahnya] dari nabi shallallahu 'alaihi wasallam seperti itu, namun ia tidak menyebut; Sa'id bin Abdurrahman dari Hamzah. Sedangkan riwayat Sa'id lebih shahih, karena [Ali bin Al Madini] dan [Humaidi] meriwayatkan dari [Sufyan] dari [Az Zuhri] dari [Salim] dari [Ayahnya], keduanya menyebutkan; dari Sufyan. Abu Isa berkata; Az Zuhri tidak meriwayatkan hadits ini untuk kami kecuali dari Salim dari Ibnu Umar. [Malik] juga meriwayatkan hadits ini dari [Az Zuhri] dan berkata; Dari [Salim] dan [Hamzah] -dua putra Abdullah bin Umar, - dari [ayah mereka berdua]. Dalam hal ini, ada hadits serupa dari Sahl bin Sa'ad, 'Aisyah dan Anas. Dan diriwayatkan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Bila kesialan ada pada sesuatu, maka hal itu ada pada wanita, hewa tunggangan (kendaraan) dan tempat tinggal.\""},"2683":{"ar":"وَقَدْ رُوِيَ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ قَال سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُلَا شُؤْمَ وَقَدْ يَكُونُ الْيُمْنُ فِي الدَّارِ وَالْمَرْأَةِ وَالْفَرَسِحَدَّثَنَا بِذَلِكَ عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ سُلَيْمَانَ بْنِ سُلَيْمٍ عَنْ يَحْيَى بْنِ جَابِرٍ الطَّائِيِّ عَنْ مُعَاوِيَةَ بْنِ حَكِيمٍ عَنْ عَمِّهِ حَكِيمِ بْنِ مُعَاوِيَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا","id":"Dan telah diriwayatkan dari Hakim bin Mu'awiyah bahwa dia berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada kesialan, dan terkadang keberkahan itu ada pada rumah, istri dan kendaraan, \" Telah menceritakan kepada kami [Ali bin Hujr] yang seperti itu, telah menceritakan kepada kami [Isma'il bin Ayyasy] dari [Sulaiman bin Sulaim] dari [Yahya bin Jabir Ath Tha`i] dari [Mu'awiyah bin Hakim] dari [pamannya, Hakim bin Mu'awiyah] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini."},"2684":{"ar":"حَدَّثَنَا هَنَّادٌ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ قَالَ ح و حَدَّثَنِي ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كُنْتُمْ ثَلَاثَةً فَلَا يَتَنَاجَى اثْنَانِ دُونَ صَاحِبِهِمَاو قَالَ سُفْيَانُ فِي حَدِيثِهِ لَا يَتَنَاجَى اثْنَانِ دُونَ الثَّالِثِ فَإِنَّ ذَلِكَ يُحْزِنُهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يَتَنَاجَى اثْنَانِ دُونَ وَاحِدٍ فَإِنَّ ذَلِكَ يُؤْذِي الْمُؤْمِنَ وَاللَّهُ عَزَّ وَجَلَّ يَكْرَهُ أَذَى الْمُؤْمِنِ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَأَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Hannad] ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] ia berkata. (Dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Syaqiq] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bila kalian bertiga, janganlah dua orang berbisik-bisik tanpa menyertakan orang ketiga.\" Sufyan berkata dalam haditsnya; \"Janganlah dua orang berbisik-bisik tanpa menyertakan orang ketiga, karena hal itu akan membuatnya sedih.\" Abu Isa berkata; Hadits ini hasan shahih. Dan diriwayatkan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah dua orang berbisik-bisik tanpa menyertakan yang satunya, karena itu akan menyakitkan orang mu`min, dan Allah 'azza wajalla membenci menyakiti orang mu`min.\" Dalam hal ini, ada hadits serupa dari Ibnu Umar, Abu Hurairah dan Ibnu Abbas."},"2685":{"ar":"حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى الْكُوفِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ أَبِي جُحَيْفَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْيَضَ قَدْ شَابَ وَكَانَ الْحَسَنُ بْنُ عَلِيٍّ يُشْبِهُهُ وَأَمَرَ لَنَا بِثَلَاثَةَ عَشَرَ قَلُوصًا فَذَهَبْنَا نَقْبِضُهَا فَأَتَانَا مَوْتُهُ فَلَمْ يُعْطُونَا شَيْئًا فَلَمَّا قَامَ أَبُو بَكْرٍ قَالَ مَنْ كَانَتْ لَهُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِدَةٌ فَلْيَجِئْ فَقُمْتُ إِلَيْهِ فَأَخْبَرْتُهُ فَأَمَرَ لَنَا بِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَى مَرْوَانُ بْنُ مُعَاوِيَةَ هَذَا الْحَدِيثَ بِإِسْنَادٍ لَهُ عَنْ أَبِي جُحَيْفَةَ نَحْوَ هَذَا وَقَدْ رَوَى غَيْرُ وَاحِدٍ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ أَبِي جُحَيْفَةَ قَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ الْحَسَنُ بْنُ عَلِيٍّ يُشْبِهُهُ وَلَمْ يَزِيدُوا عَلَى هَذَا","id":"Telah menceritakan kepada kami [Washil bin Abdul A'la Al Kufi] telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Isma'il bin Abu Khalid] dari [Abu Juhaifah] ia berkata; Aku melihat (muka) Rasulullah shallallahu 'alaihi wasallam putih (agak kemerah-merahan) dan tampak beruban, sementara Al Hasan bin Ali mirip beliau, beliau memerintahkan supaya memberikan kepada kami (kaumnya) tigabelas unta muda, kami lalu pergi hendak mengambilnya, belum sempat kami mengambilnya, berita kematian beliau sampai kepada kami, lantas mereka (para sahabat) tidak memberiku apa pun. Saat Abu Bakar berdiri, ia berkata; \"Barangsiapa memiliki tanggungan dari Rasulullah shallallahu 'alaihi wasallam, hendaklah ia datang.\" Aku pun menghampirinya dan memberitahunya, lalu ia memerintahkan untuk memberikan tigabelas unta kepada kami.\" Abu Isa berkata; Hadits ini hasan. [Marwan bin Mu'awiyah] juga meriwayatkan hadits ini dengan sanadnya dari [Abu Juhaifah] seperti di atas. Dan yang lain juga meriwayatkan dari Isma'il bin Abu Khalid dari Abu Juhaifah, ia berkata; Aku melihat Nabi shallallahu 'alaihi wasallam sedangkan Al Hasan bin Ali mirip beliau.\" Mereka tidak menambahkan lebih dari ini."},"2686":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ حَدَّثَنَا أَبُو جُحَيْفَةَ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ الْحَسَنُ بْنُ عَلِيٍّ يُشْبِهُهُقَالَ أَبُو عِيسَى وَهَكَذَا رَوَى غَيْرُ وَاحِدٍ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ نَحْوَ هَذَا وَفِي الْبَاب عَنْ جَابِرٍ وَأَبُو جُحَيْفَةَ اسْمُهُ وَهْبٌ السُّوَائِيُّ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Isma'il bin Abu Khalid] telah menceritakan kepada kami [Abu Juhaifah] ia berkata; Aku melihat Rasulullah shallallahu 'alaihi wasallam sedangkan Al Hasan bin Ali mirip beliau.\" Abu Isa berkata; Seperti itu juga yang diriwayatkan oleh beberapa orang dari Isma'il bin Abu Khalid. Dalam hal ini, ada hadits serupa dari Jabir. Abu Juhaifah namanya adalah Wahb As Suwa`i."},"2687":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَلِيٍّ قَالَمَا سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَعَ أَبَوَيْهِ لِأَحَدٍ غَيْرَ سَعْدِ بْنِ أَبِي وَقَّاصٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Sa'id Al Jauhari] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Yahya bin Sa'id] dari [Sa'id bin Al Musayyab] dari [Ali] ia berkata; Aku tidak pernah mendengar Rasulullah shallallahu 'alaihi wasallam menjadikan kedua orang tua beliau sebagai tebusan untuk orang lain, selain Sa'd bin Abi Waqqash.\""},"2688":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ الْبَزَّارُ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُدْعَانَ وَيَحْيَى بْنِ سَعِيدٍ سَمِعَا سَعِيدَ بْنَ الْمُسَيَّبِ يَقُولُ قَالَ عَلِيٌّمَا جَمَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَاهُ وَأُمَّهُ لِأَحَدٍ إِلَّا لِسَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَ لَهُ يَوْمَ أُحُدٍ ارْمِ فِدَاكَ أَبِي وَأُمِّي وَقَالَ لَهُ ارْمِ أَيُّهَا الْغُلَامُ الْحَزَوَّرُوَفِي الْبَاب عَنْ الزُّبَيْرِ وَجَابِرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ عَلِيٍّ","id":"Telah menceritakan kepada kami [Al Hasan bin Ash Shabbah Al Bazzar] telah menceritakan kepada kami [Sufyan] dari [Ibnu Jud'an] dan [Yahya bin Sa'id] keduanya mendengar [Sa'id bin Al Musayyab] berkata; [Ali] berkata; Rasulullah shallallahu 'alaihi wasallam tidak pernah menjadikan ayah dan ibu beliau sebagai tebusan untuk seseorang kecuali untuk Sa'd bin Abi Waqqash. Beliau mengucapkannya pada saat perang Uhud: \"Lemparlah, demi ayah dan ibuku menjadi penebusmu.\" Beliau juga bersabda kepadanya: \"Lemparlah wahai pemuda yang kuat.\" Dalam hal ini, ada hadits serupa dari Az Zubair dan Jabir. Abu Isa berkata; Hadits ini hasan shahih dan diriwayatkan melalui beberapa jalur dari Ali."},"2689":{"ar":"وَقَدْ رَوَى غَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَجَمَعَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَوَيْهِ يَوْمَ أُحُدٍ قَالَ ارْمِ فِدَاكَ أَبِي وَأُمِّيحَدَّثَنَا بِذَلِكَ قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ وَعَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَ جَمَعَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَوَيْهِ يَوْمَ أُحُدٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah di riwayatkan dari beberapa orang, dari Yahya bin Sa'id dari Sa'id bin Al Musayyab dari Sa'd bin Abu Waqqash ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah menjadikan kedua orang tua beliau sebagai tebusan untukku saat perang Uhud, beliau bersabda: \"Lemparlah, demi ayah dan ibuku menjadi tebusanmu.\" Telah menceritakan kepada kami [Qutaibah] seperti itu, telah menceritakan kepada kami [Al Laits bin Sa'ad] dan [Abdul Aziz bin Muhammad] dari [Yahya bin Sa'id] dari [Sa'id bin Al Musayyab] dari [Sa'd bin Abu Waqqash] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam menjadikan kedua orang tuanya sebagai tebusan untukku.\" Hadits ini hasan shahih."},"2690":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا أَبُو عُثْمَانَ شَيْخٌ لَهُ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ يَا بُنَيَّوَفِي الْبَاب عَنْ الْمُغِيرَةِ وَعُمَرَ بْنِ أَبِي سَلَمَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ مِنْ غَيْرِ هَذَا الْوَجْهِ عَنْ أَنَسٍ وَأَبُو عُثْمَانَ هَذَا شَيْخٌ ثِقَةٌ وَهُوَ الْجَعْدُ بْنُ عُثْمَانَ وَيُقَالُ ابْنُ دِينَارٍ وَهُوَ بَصْرِيٌّ وَقَدْ رَوَى عَنْهُ يُونُسُ بْنُ عُبَيْدٍ وَشُعْبَةُ وَغَيْرُ وَاحِدٍ مِنْ الْأَئِمَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] telah menceritakan kepada kami [Abu 'Awanah] telah menceritakan kepada kami [Abu Utsman] -seorang syaikhnya- dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Wahai anakku.\" Dan dalam bab ini, ada hadits dari Al Mughirah dan Umar bin Abu Salamah. Abu Isa berkata; Hadits ini hasan shahih gharib dari jalur ini, dan hadits ini juga diriwayatkan melalui jalur lain dari Anas, sedangkan Abu Utsman adalah seorang syaikh yang tsiqah, dia adalah Al Ja'd bin Utsman dan dinamakan juga Ibnu Dinar, dia orang Bashrah, orang-orang yang telah meriwayatkan hadits darinya antara lain; Yunus bin Ubaid, Syu'bah dan tidak sedikit dari para ulama.\""},"2691":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ حَدَّثَنِي عَمِّي يَعْقُوبُ بْنُ إِبَرَاهِيمَ حَدَّثَنَا شَرِيكٌ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِتَسْمِيَةِ الْمَوْلُودِ يَوْمَ سَابِعِهِ وَوَضْعِ الْأَذَى عَنْهُ وَالْعَقِّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim bin Sa'd bin Ibrahim bin Abdurrahman bin 'Auf] telah menceritakan kepadaku pamanku yaitu [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Syarik] dari [Muhammad bin Ishaq] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [kakeknya] bahwa Nabi shallallahu 'alaihi wasallam memerintahkan agar memberikan nama kepada bayi yang lahir pada hari ketujuh, membersihkan kotoran darinya dan di aqiqahkan.\" Abu Isa berkata; Hadits ini hasan gharib."},"2692":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْأَسْوَدِ أَبُو عَمْرٍو الْوَرَّاقُ الْبَصْرِيُّ حَدَّثَنَا مُعَمَّرُ بْنُ سُلَيْمَانَ الرَّقِّيُّ عَنْ عَلِيِّ بْنِ صَالِحٍ الْمَكِّيِّ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحَبُّ الْأَسْمَاءِ إِلَى اللَّهِ عَزَّ وَجَلَّ عَبْدُ اللَّهِ وَعَبْدُ الرَّحْمَنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Al Aswad Abu 'Amru Al Warraq Al Bashri] telah menceritakan kepada kami [Mu'ammar bin Sulaiman Ar Raqqi] dari [Ali bin Shalih Al Makki] dari [Abdullah bin Utsman] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Nama-nama yang paling disukai Allah 'azza wajalla adalah Abdullah dan Abdurrahman.\" Abu Isa berkata; Hadits ini hasan gharib melalui jalur ini."},"2693":{"ar":"حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ الْعَمِّيُّ الْبَصْرِيُّ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ الْعُمَرِيِّ عَنْ نَافِعٍ عَنْ ابْن عُمَرَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحَبَّ الْأَسْمَاءِ إِلَى اللَّهِ عَبْدُ اللَّهِ وَعَبْدُ الرَّحْمَنِهَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami ['Uqbah bin Mukram Al Ammi Al Bashri] telah menceritakan kepada kami [Abu 'Ashim] dari [Abdullah bin Umar Al 'Umari] dari [Nafi'] dari [Ibnu Umar] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Nama-nama yang paling disukai Allah adalah Abdullah dan Abdurrahman.\" Abu Isa berkata; Hadits ini hasan melalui jalur ini."},"2694":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْهَيَنَّ أَنْ يُسَمَّى رَافِعٌ وَبَرَكَةُ وَيَسَارٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ هَكَذَا رَوَاهُ أَبُو أَحْمَدَ عَنْ سُفْيَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ عُمَرَ وَرَوَاهُ غَيْرُهُ عَنْ سُفْيَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو أَحْمَدَ ثِقَةٌ حَافِظٌ وَالْمَشْهُورُ عِنْدَ النَّاسِ هَذَا الْحَدِيثُ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ فِيهِ عَنْ عُمَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Jabir] dari [Umar bin Al Khaththab] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh aku melarang kalian memberikan nama Rafi', Barakah dan Yasar.\" Abu Isa berkata; Hadits ini gharib, demikianlah Abu Ahmad telah meriwayatkannya dari Sufyan dari Abu Az Zubair dari Jabir dari Umar, dan yang lainnya telah meriwayatkannya dari [Sufyan] dari [Abu Az Zubair] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam. Abu Ahmad adalah tsiqah hafidz, dan hadits ini yang masyhur dikalangan orang-orang adalah hadits dari Jabir dari Nabi shallallahu 'alaihi wasallam, dan di dalamnya tidak disebutkan, \"Dari Umar.\""},"2695":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ شُعْبَةَ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ الرَّبِيعِ بْنِ عُمَيْلَةَ الْفَزَارِيِّ عَنْ سَمُرَةَ بْنِ جُنْدَبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُسَمِّ غُلَامَكَ رَبَاحٌ وَلَا أَفْلَحُ وَلَا يَسَارٌ وَلَا نَجِيحٌ يُقَالُ أَثَمَّ هُوَ فَيُقَالُ لَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] dari [Syu'bah] dari [Manshur] dari [Hilal bin Yasaf] dari [Ar Rabi' bin 'Umailah Al Fazari] dari [Samurah bin Jundub] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu memberi nama anakmu; Rabah, Aflah, Yasar dan Najih, karena bila dikatakan; \"Apakah ia (dengan menyebutkan salah satu dari nama tersebut -pent) ada disana?\" dan di jawab; \"Tidak.\" Abu Isa berkata; Hadits ini hasan shahih. "},"2696":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَيْمُونٍ الْمَكِّيُّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَخْنَعُ اسْمٍ عِنْدَ اللَّهِ يَوْمَ الْقِيَامَةِ رَجُلٌ تَسَمَّى بِمَلِكِ الْأَمْلَاكِقَالَ سُفْيَانُ شَاهَانْ شَاهْ وَأَخْنَعُ يَعْنِي وَأَقْبَحُ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Maimun Al Makki] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah], yang (riwayatnya) sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Nama paling buruk di sisi Allah pada hari kiamat adalah seseorang yang diberi nama raja diraja.\" Sufyan -Syahan syah- mengatakan; \"Akhna' artinya paling buruk.\" Hadits ini hasan shahih."},"2697":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ وَأَبُو بَكْرٍ مُحَمَّدُ بْنُ بَشَّارٍ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيَّرَ اسْمَ عَاصِيَةَ وَقَالَ أَنْتِ جَمِيلَةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَإِنَّمَا أَسْنَدَهُ يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ وَرَوَى بَعْضُهُمْ هَذَا عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ أَنَّ عُمَرَ مُرْسَلًا وَفِي الْبَاب عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَعَبْدِ اللَّهِ بْنِ سَلَامٍ وَعَبْدِ اللَّهِ بْنِ مُطِيعٍ وَعَائِشَةَ وَالْحَكَمِ بْنِ سَعِيدٍ وَمُسْلِمٍ وَأُسَامَةَ بْنِ أَخْدَرِيٍّ وَشُرَيْحِ بْنِ هَانِئٍ عَنْ أَبِيهِ وَخَيْثَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim Ad Dauraqi] dan [Abu Bakar Muhammad bin Basyar] dan yang lain, mereka berkata; telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam merubah nama 'Ashiya (durhaka), beliau bersabda: \"Engkau adalah Jamilah (wanita cantik).\" Abu Isa berkata; Hadits ini hasan gharib, Yahya bin Sa'id Al Qaththan menyandarkannya dari 'Ubaidullah dari Nafi' dari Ibnu Umar, dan sebagaian dari mereka meriwayatkan hadits ini dari 'Ubaidullah dari Nafi' bahwa Umar, meriwayatkan secara mursal. Dalam hal ini, ada hadits serupa dari Abdurrahman bin Auf, Abdullah bin Salam, Abdullah bin Muthi', 'Aisyah, Hakam bin Sa'id, Muslim, Usamah bin Akhdari, Syuraikh bin Hani`, dari ayahnya dan Khaitsamah bin Abdurrahman dari ayahnya."},"2698":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ نَافِعٍ الْبَصْرِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ الْمُقَدَّمِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُغَيِّرُ الِاسْمَ الْقَبِيحَقَالَ أَبُو بَكْرٍ وَرُبَّمَا قَالَ عُمَرُ بْنُ عَلِيٍّ فِي هَذَا الْحَدِيثِ هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا وَلَمْ يَذْكُرْ فِيهِ عَنْ عَائِشَةَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Nafi' Al Bashri] telah menceritakan kepada kami [Umar bin Ali Al Muqaddami] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam merubah nama yang jelek.\" [Abu Bakar] berkata; Mungkin [Umar bin Ali] berkata dalam hadits ini, [Hisyam bin 'Urwah] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam secara mursal dan dalam hadits tidak menyebutkan, \"Dari 'Aisyah.\""},"2699":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِي أَسْمَاءً أَنَا مُحَمَّدٌ وَأَنَا أَحْمَدُ وَأَنَا الْمَاحِي الَّذِي يَمْحُو اللَّهُ بِيَ الْكُفْرَ وَأَنَا الْحَاشِرُ الَّذِي يُحْشَرُ النَّاسُ عَلَى قَدَمِي وَأَنَا الْعَاقِبُ الَّذِي لَيْسَ بَعْدِي نَبِيٌّوَفِي الْبَاب عَنْ حُذَيْفَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Sa'id bin Abdurrahman Al Makhzumi] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Muhammad bin Jubair bin Muth'im] dari [Ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku memiliki beberapa nama, aku adalah Muhammad, Ahmad, Al Mahi yang denganku Allah menghapus kekufuran, Al Hasyir (pengumpul) di mana manusia dikumpulkan di atas kakiku, Al 'Aqib (terakhir) yang tiada Nabi setelahku.\" Dalam hal ini, ada hadits serupa dari Hudzaifah. Abu Isa berkata; Hadits ini hasan shahih."},"2700":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَجْمَعَ أَحَدٌ بَيْنَ اسْمِهِ وَكُنْيَتِهِ وَيُسَمِّيَ مُحَمَّدًا أَبَا الْقَاسِمِوَفِي الْبَاب عَنْ جَابِرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ كَرِهَ بَعْضُ أَهْلِ الْعِلْمِ أَنْ يَجْمَعَ الرَّجُلُ بَيْنَ اسْمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكُنْيَتِهِ وَقَدْ فَعَلَ ذَلِكَ بَعْضُهُمْ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Ayahnya] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam melarang seseorang menyatukan antara nama dan kun-yahnya (julukan) dan memberi nama Muhammad Abu Al Qasim.\" Dalam hal ini, ada hadits serupa dari Jabir. Abu Isa berkata; Hadits ini hasan shahih. Beberapa ulama memakruhkan seseorang menyatukan antara nama Nabi shallallahu 'alaihi wasallam dengan kun-yahnya, namun sebagaian lain melakukannya.\""},"2701":{"ar":"رُوِيَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سَمِعَ رَجُلًا فِي السُّوقِ يُنَادِي يَا أَبَا الْقَاسِمِ فَالْتَفَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَال لَمْ أَعْنِكَ فَقَال النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَكْتَنُوا بِكُنْيَتِيحَدَّثَنَا بِذَلِكَ الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ حُمَيْدٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا وَفِي هَذَا الْحَدِيثِ مَا يَدُلُّ عَلَى كَرَاهِيَةِ أَنْ يُكَنَّى أَبَا الْقَاسِمِ","id":"Diriwayatkan dari Nabi shallallahu 'alaihi wasallam, beliau mendengar seseorang memanggil-manggil di pasar; \"Wahai Abu Al Qasim!\" Nabi shallallahu 'alaihi wasallam menoleh, lalu orang itu berkata; \"Bukan anda yang aku maksud.\" Setelah itu Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menjuluki seseorang dengan julukanku.\" Telah menceritakan kepada kami [Al Hasan bin Ali bin Khallal] seperti itu, telah menceritakan kepada kami [Yazid bin Harun] dari [Humaid] dari [Anas] dari Nabi shallallahu 'alaihi wasallam seperti di atas. Hadits ini menunjukkan makruhnya memberi kun-yah Abu Al Qasim."},"2702":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَمَّيْتُمْ بِي فَلَا تَكْتَنُوا بِيقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Al Husain bin Huraits] telah menceritakan kepada kami [Al Fadll bin Musa] dari [Al Husain bin Waqid] dari [Abu Az Zubair] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian memberi nama seperti namaku, maka janganlah memberi kun-yah (julukan) seperti kun-yahku.\" Abu Isa berkata; Hadits ini hasan gharib melalui sanad ini."},"2703":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ حَدَّثَنَا فِطْرُ بْنُ خَلِيفَةَ حَدَّثَنِي مُنْذِرٌ وَهُوَ الثَّوْرِيُّ عَنْ مُحَمَّدِ ابْنِ الْحَنَفِيَّةِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ وُلِدَ لِي بَعْدَكَ أُسَمِّيهِ مُحَمَّدًا وَأُكَنِّيهِ بِكُنْيَتِكَ قَالَ نَعَمْ قَالَ فَكَانَتْ رُخْصَةً لِيهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] telah menceritakan kepada kami [Fithr bin Khalifah] telah menceritakan kepadaku [Mundzir yaitu Ats Tsauri] dari [Muhammad bin Al Hanafiyah] dari [Ali bin Abu Thalib] dia bertanya; \"Wahai Rasulullah, bagaimana pendapat anda jika anakku lahir sepeninggalmu?, apakah aku boleh menamainya Muhammad dan memberinya kun-yah (julukan) seperti kun-yahmu?\" beliau menjawab: \"Ya.\" Ali berkata; \"Namun hal itu sebagai keringan khusus bagiku.\" Hadits ini hasan shahih."},"2704":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا يَحْيَى بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي غَنِيَّةَ حَدَّثَنِي أَبِي عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الشِّعْرِ حِكْمَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ إِنَّمَا رَفَعَهُ أَبُو سَعِيدٍ الْأَشَجُّ عَنْ ابْنِ أَبِي غَنِيَّةَ وَرَوَى غَيْرُهُ عَنْ ابْنِ أَبِي غَنِيَّةَ هَذَا الْحَدِيثَ مَوْقُوفًا وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ هَذَا الْوَجْهِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي الْبَاب عَنْ أُبَيِّ بْنِ كَعْبٍ وَابْنِ عَبَّاسٍ وَعَائِشَةَ وَبُرَيْدَةَ وَكَثِيرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ جَدِّهِ","id":"Telah menceritakan kepada kami [Abu Sa'id Al Asyaj] telah menceritakan kepada kami [Yahya bin Abdul Malik bin Abu Ghaniyyah] telah menceritakan kepada kami [Ayahku] dari ['Ashim] dari [Zirr] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di antara (bait-bait) syair itu ada yang mengandung hikmah.\" Abu Isa berkata; Hadits ini gharib dari jalur ini, yang memarfu'kannya (menyambungkan sampai kepada nabi) hanyalah Abu Sa'id Al Asyaj dari Ibnu Abu ghaniyyah, sedangkan yang lainnya telah meriwayatkan hadits ini dari Ibnu Abu Ghaniyyah secara Mauquf. Hadits ini diriwayatkan dari selain jalur ini dari Abdullah bin Mas'ud dari Nabi shallallahu 'alaihi wasallam. Dan dalam bab ini, ada hadits dari Ubay bin Ka'ab, Ibnu Abbas, Aisyah, Buraidah dan Katsir bin Abdullah dari Ayahnya dari kakeknya."},"2705":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الشِّعْرِ حِكَمًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Simak bin Harb] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di antara (bait-bait) syair itu ada yang mengandung hikmah.\" Abu Isa berkata; Hadits ini hasan shahih."},"2706":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى الْفَزَارِيُّ وَعَلِيُّ بْنُ حُجْرٍ الْمَعْنَى وَاحِدٌ قَالَا حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضَعُ لِحَسَّانَ مِنْبَرًا فِي الْمَسْجِدِ يَقُومُ عَلَيْهِ قَائِمًا يُفَاخِرُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ يُنَافِحُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَقُولُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يُؤَيِّدُ حَسَّانَ بِرُوحِ الْقُدُسِ مَا يُفَاخِرُ أَوْ يُنَافِحُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى وَعَلِيُّ بْنُ حُجْرٍ قَالَا حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَالْبَرَاءِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَهُوَ حَدِيثُ ابْنِ أَبِي الزِّنَادِ","id":"Telah menceritakan kepada kami [Isma'il bin Musa Al Fazari] dan [Ali bin Hujr] sedangkan maksudnya sama, keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Az Zinad] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk meletakkan mimbar buat Hasan (bin Tsabit) di masjid, yaitu sebagai tempat berdirinya, dia membanggakan diri Rasulullah shallallahu 'alaihi wasallam atau membela Rasulullah shallallahu 'alaihi wasallam, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah menguatkan Hasan dengan Ruhul Qudus yang dapat membanggakan atau membela Rasulullah shallallahu 'alaihi wasallam.\" Telah menceritakan kepada kami [Isma'il bin Musa] dan [Ali bin Hujr] keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Az Zinad] dari [Ayahnya] dari ['Urwah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam dengan hadits yang semisal. Dan dalam bab ini, ada hadits dari Abu Hurairah dan Al Barra'. Abu Isa berkata; Hadits ini hasan shahih gharib, yaitu hadits Ibnu Abu Az Zinad."},"2707":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا جَعْفَرُ بْنُ سُلَيْمَانَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ فِي عُمْرَةِ الْقَضَاءِ وَعَبْدُ اللَّهِ بْنُ رَوَاحَةَ بَيْنَ يَدَيْهِ يَمْشِي وَهُوَ يَقُولُ خَلُّوا بَنِي الْكُفَّارِ عَنْ سَبِيلِهِالْيَوْمَ نَضْرِبْكُمْ عَلَى تَنْزِيلِهِضَرْبًا يُزِيلُ الْهَامَ عَنْ مَقِيلِهِوَيُذْهِلُ الْخَلِيلَ عَنْ خَلِيلِهِفَقَالَ لَهُ عُمَرُ يَا ابْنَ رَوَاحَةَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي حَرَمِ اللَّهِ تَقُولُ الشِّعْرَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلِّ عَنْهُ يَا عُمَرُ فَلَهِيَ أَسْرَعُ فِيهِمْ مِنْ نَضْحِ النَّبْلِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رَوَى عَبْدُ الرَّزَّاقِ هَذَا الْحَدِيثَ أَيْضًا عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ نَحْوَ هَذَا وَرُوِيَ فِي غَيْرِ هَذَا الْحَدِيثِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ فِي عُمْرَةِ الْقَضَاءِ وَكَعْبُ بْنُ مَالِكٍ بَيْنَ يَدَيْهِ وَهَذَا أَصَحُّ عِنْدَ بَعْضِ أَهْلِ الْحَدِيثِ لِأَنَّ عَبْدَ اللَّهِ بْنَ رَوَاحَةَ قُتِلَ يَوْمَ مُؤْتَةَ وَإِنَّمَا كَانَتْ عُمْرَةُ الْقَضَاءِ بَعْدَ ذَلِكَ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ja'far bin Sulaiman] telah menceritakan kepada kami [Tsabit] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam memasuki Makkah pada saat Umratul Qadla`, sedangkan Abdullah bin Rawahah berjalan di depan beliau sambil bersyair; \"Biarkanlah orang-orang kafir pergi saat ini, kami akan menebas kalian atas kedatangan beliau, dengan tebusan yang melenyapkan kepala dari tempatnya dan yang membingungkan seorang kekasih dari kekasihnya.\" Umar berkata kepadanya; \"Wahai Ibnu Rawahah, berada di hadapan Rasulullah shallallahu 'alaihi wasallam dan di tanah haramillah (tempat yang Allah sucikan) ini kamu berani membaca sya'ir?\" Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Biarkan dia wahai Umar, syair itu lebih cepat mengenai mereka (orang-orang Kafir Quraisy) melebihi lemparan tombak.\" Abu Isa berkata; Hadits ini hasan shahih gharib dari jalur ini. Dan [Abdurrazzaq] telah meriwayatkan hadits ini dari [Ma'mar] dari [Az Zuhri] dari [Anas] dengan matan yang semakna. Riwayat lain menyebutkan bahwa Nabi shallallahu 'alaihi wasallam masuk Makkah pada saat Umratul Qadla`, sementara Ka'ab bin Malik berada di hadapan beliau.\" Dan hadits ini lebih shahih menurut sebagian ahli hadits, karena Abdullah bin Rawahah terbunuh pada saat perang Mu'tah, sedangkan Umratul Qadla` terjadi setelah peristiwa itu."},"2708":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا شَرِيكٌ عَنْ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَقِيلَ لَهَا هَلْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَمَثَّلُ بِشَيْءٍ مِنْ الشِّعْرِ قَالَتْ كَانَ يَتَمَثَّلُ بِشِعْرِ ابْنِ رَوَاحَةَ وَيَتَمَثَّلُ وَيَقُولُ وَيَأْتِيكَ بِالْأَخْبَارِ مَنْ لَمْ تُزَوِّدِوَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah menceritakan kepada kami [Syarik] dari [Al Miqdam bin Syuraih] dari [Ayahnya] dari ['Aisyah], (Ayah Miqdam) berkata; \"Pernah ditanyakan kepada 'Aisyah; \"Apakah Nabi shallallahu 'alaihi wasallam pernah mengucapkan sya'ir?\" 'Aisyah menjawab; \"Beliau pernah membaca sya'irnya Ibnu Rawahah dan beliau bersaya'ir dengan mengatakan: \"Dan orang yang tidak memberimu bekal datang kepadamu dengan membawa berita-berita.\" Dan dalam bab ini, ada hadits dari Ibnu Abbas. Abu Isa berkata; Hadits ini hasan shahih."},"2709":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا شَريكٌ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَشْعَرُ كَلِمَةٍ تَكَلَّمَتْ بِهَا الْعَرَبُ كَلِمَةُ لَبِيدٍ أَلَا كُلُّ شَيْءٍ مَا خَلَا اللَّهَ بَاطِلُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ الثَّوْرِيُّ وَغَيْرُهُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Syarik] dari [Abdul Malik bin 'Umair] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kalimat syair terbaik yang diucapkan bangsa Arab adalah kata-kata Labid, yaitu; \"Ingat, segala sesuatu selain Allah adalah batil.\" Abu Isa berkata; Hadits ini hasan shahih. [Ats Tsauri] dan lainnya meriwayatkan dari [Abdul Malik bin 'Umair]."},"2710":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَجَالَسْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرَ مِنْ مِائَةِ مَرَّةٍ فَكَانَ أَصْحَابُهُ يَتَنَاشَدُونَ الشِّعْرَ وَيَتَذَاكَرُونَ أَشْيَاءَ مِنْ أَمْرِ الْجَاهِلِيَّةِ وَهُوَ سَاكِتٌ فَرُبَّمَا تَبَسَّمَ مَعَهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ زُهَيْرٌ عَنْ سِمَاكٍ أَيْضًا","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Syarik] dari [Simak] dari [Jabir bin Samurah] ia berkata; Aku menemani Nabi shallallahu 'alaihi wasallam lebih dari seratus kali, para sahabat beliau menyenandungkan syair, mereka menyebut-nyebut perkara jahiliyah, sementara beliau diam, kadang beliau tersenyum bersama mereka.\" Abu Isa berkata; Hadits ini hasan shahih. [Zuhair] juga meriwayatkannya dari [Simak]."},"2711":{"ar":"حَدَّثَنَا عِيسَى بْنُ عُثْمَانَ بْنِ عِيسَى الرَّمْلِيُّ حَدَّثَنَا عَمِّي يَحْيَى بْنُ عِيسَى عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَمْتَلِئَ جَوْفُ أَحَدِكُمْ قَيْحًا يَرِيَهُ خَيْرٌ لَهُ مِنْ أَنْ يَمْتَلِئَ شِعْرًاوَفِي الْبَاب عَنْ سَعْدٍ وَأَبِي سَعِيدٍ وَابْنِ عُمَرَ وَأَبِي الدَّرْدَاءِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Isa bin Utsman bin Isa Ar Ramli] telah menceritakan kepada kami pamanku yaitu [Yahya bin Isa] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perut seseorang penuh dengan nanah yang berbau busuk itu lebih baik daripada penuh dengan bait-bait sya'ir.\" Dalam hal ini, ada hadits serupa dari Sa'd, Abu Sa'id, Ibnu Umar dan Abu Ad Darda`. Abu Isa berkata; Hadits ini hasan shahih."},"2712":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ يُونُسَ بْنِ جُبَيْرٍ عَنْ مُحَمَّدِ بْنِ سَعْدِ بْنِ أَبِي وَقَاصٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَمْتَلِئَ جَوْفُ أَحَدِكُمْ قَيْحًا خَيْرٌ لَهُ مِنْ أَنْ يَمْتَلِئَ شِعْرًاقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah mengabarkan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [Qatadah] dari [Yunus bin Jubair] dari [Muhammad bin Sa'd bin Abu Waqqash] dari [Ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perut seseorang penuh dengan nanah yang berbau busuk itu lebih baik daripada penuh dengan bait-bait sya'ir.\" Abu Isa berkata; Hadits ini hasan shahih."},"2713":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ الْمُقَدَّمِيُّ حَدَّثَنَا نَافِعُ بْنُ عُمَرَ الْجُمَحِيُّ عَنْ بِشْرِ بْنِ عَاصِمٍ سَمِعَهُ يُحَدِّثُ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ يَبْغَضُ الْبَلِيغَ مِنْ الرِّجَالِ الَّذِي يَتَخَلَّلُ بِلِسَانِهِ كَمَا تَتَخَلَّلُ الْبَقَرَةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَفِي الْبَاب عَنْ سَعْدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul A'la Ash Shan'ani] telah menceritakan kepada kami [Umar bin Ali Al Muqaddami] telah menceritakan kepada kami [Nafi' bin Umar Al Jumahi] dari [Bisyr bin 'Ashim] dia telah mendengarnya bercerita dari [Ayahnya] dari [Abdullah bin 'Amru] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah membenci para tukang syair yang memainkan lidahnya, sebagaimana sapi memainkan lidahnya.\" Abu Isa berkata; dari jalur ini, hadits ini hasan gharib. Dan dalam bab ini, ada juga hadits dari Sa'd."},"2714":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَبْدِ الْجَبَّارِ بْنِ عُمَرَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَنَامَ الرَّجُلُ عَلَى سَطْحٍ لَيْسَ بِمَحْجُورٍ عَلَيْهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ إِلَّا مِنْ هَذَا الْوَجْهِ وَعَبْدُ الْجَبَّارِ بْنُ عُمَرَ يُضَعَّفُ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] telah menceritakan kepada kami [Abdullah bin Wahab] dari [Abdul Jabbar bin Umar] dari [Muhammad bin Al Munkadir] dari [Jabir] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang seseorang tidur di atas atap yang tidak ada pelindungnya (pembatas sekelilingnya).\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya dari hadits Muhammad bin Al Munkadir dari Jabir kecuali dari jalur ini, sedangkan Abdul Jabbar bin Umar dinyatakan lemah."},"2715":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَوَّلُنَا بِالْمَوْعِظَةِ فِي الْأَيَّامِ مَخَافَةَ السَّآمَةِ عَلَيْنَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا مُحَمَّدُ بْنُ ��َشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ حَدَّثَنِي شَقِيقُ بْنُ سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ نَحْوَهُ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Wa`il] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam memberi kami nasehat pada hari-hari (tertentu) karena khawatir kami jemu.\" Abu Isa berkata; Hadits ini hasan shahih. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] telah menceritakan kepadaku [Syaqiq bin Salamah] dari [Abdullah bin Mas'ud] seperti hadits di atas."},"2716":{"ar":"حَدَّثَنَا أَبُو هِشَامٍ الرِّفَاعِيُّ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ قَالَسُئِلَتْ عَائِشَةُ وَأُمُّ سَلَمَةَ أَيُّ الْعَمَلِ كَانَ أَحَبَّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتَا مَا دِيمَ عَلَيْهِ وَإِنْ قَلَّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ كَانَ أَحَبُّ الْعَمَلِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا دِيمَ عَلَيْهِ حَدَّثَنَا بِذَلِكَ هَارُونُ بْنُ إِسْحَقَ الْهَمْدَانِيُّ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Hisyam Ar Rifa'I] telah menceritakan kepada kami [Ibnu Fudlail] dari [Al A'masy] dari [Abu Shalih] ia berkata; ['Aisyah] dan [Ummu Salamah] pernah ditanya tentang amalan apakah yang paling disukai Rasulullah shallallahu 'alaihi wasallam?\" keduanya menjawab; \"Amalan yang dilakkukan secara terus menerus sekalipun sedikit.\" Abu Isa berkata; Dari jalur ini, hadits ini hasan gharib. Dan telah diriwayatkan dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] bahwa dia berkata; \"Amalan yang paling disukai oleh Rasulullah shallallahu 'alaihi wasallam adalah yang dikerjakan secara terus menerus.\" [Harun bin Ishaq Al Hamdani] telah menceritakan yang demikian kepada kami, telah menceritakan kepada kami ['Abdah] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam dengan matan hadits yang semakna dengannya, hadits ini hasan shahih."},"2717":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ كَثِيرِ بْنِ شِنْظِيرٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمِّرُوا الْآنِيَةَ وَأَوْكِئُوا الْأَسْقِيَةَ وَأَجِيفُوا الْأَبْوَابَ وَأَطْفِئُوا الْمَصَابِيحَ فَإِنَّ الْفُوَيْسِقَةَ رُبَّمَا جَرَّتْ الْفَتِيلَةَ فَأَحْرَقَتْ أَهْلَ الْبَيْتِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad bin Zaid] dari [Katsir bin Syindzir] dari ['Atha` bin Abu Rabah] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tutuplah bejana-bejana kelian, tempat-tempat air kalian, dan pintu-pintu kalian serta padamkan lampu-lampu kalian, karena bisa jadi tikus menyeret sumbu lampu, lalu membakar penghuni rumah.\" Abu Isa berkata; Hadits ini hasan shahih. Diriwayatkan melalui sanad lain dari Jabir dari Nabi shallallahu 'alaihi wasallam."},"2718":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَافَرْتُمْ فِي الْخِصْبِ فَأَعْطُوا الْإِبِلَ حَظَّهَا مِنْ الْأَرْضِ وَإِذَا سَافَرْتُمْ فِي السَّنَةِ فَبَادِرُوا بِهَا نِقْيَهَا وَإِذَا عَرَّسْتُمْ فَاجْتَنِبُوا الطَّرِيقَ فَإِنَّهَا طُرُقُ الدَّوَابِّ وَمَأْوَى الْهَوَامِّ بِاللَّيْلِقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ جَابِرٍ وَأَنَسٍ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Aiziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian bepergian dimusim banyak rumput dan tanaman, maka berikanlah hak unta (untuk memakan tanaman dan rerumputan) bumi, dan apabila kalian bepergian saat kemarau, percepatlah kekuatannya dan bila kalian istirahat di akhir malam, jauhilah jalanan, karena jalanan merupakan jalan hewan dan tempat binatang beracun di malam hari.\" Abu Isa berkata; Hadits ini hasan shahih. Dalam hal ini ada hadits serupa dari Jabir dan Anas."},"2719":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ النَّوَّاسِ بْنِ سَمْعَانَ الْكِلَابِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ ضَرَبَ مَثَلًا صِرَاطًا مُسْتَقِيمًا عَلَى كَنَفَيْ الصِّرَاطِ زُورَانِ لَهُمَا أَبْوَابٌ مُفَتَّحَةٌ عَلَى الْأَبْوَابِ سُتُورٌ وَدَاعٍ يَدْعُو عَلَى رَأْسِ الصِّرَاطِ وَدَاعٍ يَدْعُو فَوْقَهُ{ وَاللَّهُ يَدْعُوا إِلَى دَارِ السَّلَامِ وَيَهْدِي مَنْ يَشَاءُ إِلَى صِرَاطٍ مُسْتَقِيمٍ }وَالْأَبْوَابُ الَّتِي عَلَى كَنَفَيْ الصِّرَاطِ حُدُودُ اللَّهِ فَلَا يَقَعُ أَحَدٌ فِي حُدُودِ اللَّهِ حَتَّى يُكْشَفَ السِّتْرُ وَالَّذِي يَدْعُو مِنْ فَوْقِهِ وَاعِظُ رَبِّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ قَالَ سَمِعْت عَبْدَ اللَّهِ بْنَ عَبْدِ الرَّحْمَنِ يَقُولُ سَمِعْتُ زَكَرِيَّا بْنَ عَدِيٍّ يَقُولُ قَالَ أَبُو إِسْحَقَ الْفَزَارِيُّ خُذُوا عَنْ بَقِيَّةَ مَا حَدَّثَكُمْ عَنْ الثِّقَاتِ وَلَا تَأْخُذُوا عَنْ إِسْمَعِيلَ بْنِ عَيَّاشٍ مَا حَدَّثَكُمْ عَنْ الثِّقَاتِ وَلَا غَيْرِ الثِّقَاتِ","id":"Telah menceritakan kepada kami [Ali bin Hujr As Sa'di] telah menceritakan kepada kami [Baqiyah bin Al Walid] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Jubair bin Nufair] dari [An Nawwas bin Sam'an Al Kilabi] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah membuat perumpamaan jalan yang lurus, di atas dua tepi jalan ada dua tembok, pada keduanya ada beberapa pintu terbuka, pintu-pintu itu bertirai dan disetiap penghujung jalan ada penyeru yang meyeru manusia dan penyeru yang menyeru di atasnya Dan Allah menyeru menuju negeri keselamatan, memberi petunjuk kepada siapa saja yang Ia kehendaki menuju jalan yang lurus. QS Yunus; 25 Pintu-pintu yang ada di sisi jalan adalah batasan-batasan Allah, karenanya janganlah ada seorang pun yang jatuh di batasan-batasan Allah hingga tirai terbuka, sementara yang menyeru dari atasnya adalah penyeru Rabbnya.\" Abu Isa berkata; Hadits ini hasan gharib. Ia berkata; Aku mendengar Abdullah bin Abdurrahman berkata; Aku mendengar Zakariya bin Adi berkata; Abu Ishaq Al Fazari berkata; \"Ambillah hadits yang disampaikan oleh para perawi tsiqah yang masih ada, dan jangan mengambil hadits yang disampaikan Isma'il bin Ayyasy, baik dari para perawi tsiqah atau bukan tsiqah.\""},"2720":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ الْأَنْصَارِيَّ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَقَالَ إِنِّي رَأَيْتُ فِي الْمَنَامِ كَأَنَّ جِبْرِيلَ عِنْدَ رَأْسِي وَمِيكَائِيلَ عِنْدَ رِجْلَيَّ يَقُولُ أَحَدُهُمَا لِصَاحِبِهِ اضْرِبْ لَهُ مَثَلًا فَقَالَ اسْمَعْ سَمِعَتْ أُذُنُكَ وَاعْقِلْ عَقَلَ قَلْبُكَ إِنَّمَا مَثَلُكَ وَمَثَلُ أُمَّتِكَ كَمَثَلِ مَلِكٍ اتَّخَذَ دَارًا ثُمَّ بَنَى فِيهَا بَيْتًا ثُمَّ جَعَلَ فِيهَا مَائِدَةً ثُمَّ بَعَثَ رَسُولًا يَدْعُو النَّاسَ إِلَى طَعَامِهِ فَمِنْهُمْ مَنْ أَجَابَ الرَّسُولَ وَمِنْهُمْ مَنْ تَرَكَهُ فَاللَّهُ هُوَ الْمَلِكُ وَالدَّارُ الْإِسْلَامُ وَالْبَيْتُ الْجَنَّةُ وَأَنْتَ يَا مُحَمَّدُ رَسُولٌ فَمَنْ أَجَابَكَ دَخَلَ الْإِسْلَامَ وَمَنْ دَخَلَ الْإِسْلَامَ دَخَلَ الْجَنَّةَ وَمَنْ دَخَلَ الْجَنَّةَ أَكَلَ مَا فِيهَاوَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِإِسْنَادٍ أَصَحَّ مِنْ هَذَا قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ مُرْسَلٌ سَعِيدُ بْنُ أَبِي هِلَالٍ لَمْ يُدْرِكْ جَابِرَ بْنَ عَبْدِ اللَّهِ وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] bahwa [Jabir bin Abdullah Al Anshari] berkata; \"Pada suatu hari, Rasulullah shallallahu 'alaihi wasallam keluar menemui kami, beliau bersabda: \"Sesungguhnya aku bermimpi seakan-akan Jibril berada di sisi kepalaku, sedangkan Mika'il berada di sisi kakiku, salah satu dari keduanya berkata kepada yang lain; \"Buatlah perumpamaan baginya, \" dia berkata; \"Dengarkanlah pasti telingamu mendengar dan fahamilah pasti hatimu memahami, perumpamaanmu dengan ummatmu seperti seorang raja yang hendak membuat istana, dan didalamnya dibangun rumah, setelah membangun rumah, dia menyiapkan jamuan makan dalam rumah tersebut, lalu dia menyuruh seorang utusan untuk mengundang rakyat agar menghadiri jamuannya, di antara mereka ada yang memenuhi undangan utusan tadi dan di antara mereka ada yang meninggalkannya, Allah sebagai rajanya, istana sebagai Islamnya, rumah sebagai surganya dan engkau wahai Muhammad adalah sebagai seorang utusannya, barangsiapa yang memenuhi undanganmu berarti dia masuk Islam, dan barangsiapa masuk Islam, berarti akan masuk surga dan barangsiapa masuk surga, berarti dia memakan apa yang ada di dalamnya.\" Hadits ini telah diriwayatkan dari beberapa jalur dari Nabi shallallahu 'alaihi wasallam dengan sanad yang lebih kuat dari sanad hadits ini. Abu Isa berkata; Hadits ini mursal, karena Sa'id bin Abu Hilal tidak bertemu dengan Jabir bin Abdullah. Dan dalam bab ini, ada juga hadits dari Ibnu Mas'ud."},"2721":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنْ جَعْفَرِ بْنِ مَيْمُونٍ عَنْ أَبِي تَمِيمَةَ الْهُجَيْمِيِّ عَنْ أَبِي عُثْمَانَ عَنْ ابْنِ مَسْعُودٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِشَاءَ ثُمَّ انْصَرَفَ فَأَخَذَ بِيَدِ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ حَتَّى خَرَجَ بِهِ إِلَى بَطْحَاءِ مَكَّةَ فَأَجْلَسَهُ ثُمَّ خَطَّ عَلَيْهِ خَطًّا ثُمَّ قَالَ لَا تَبْرَحَنَّ خَطَّكَ فَإِنَّهُ سَيَنْتَهِي إِلَيْكَ رِجَالٌ فَلَا تُكَلِّمْهُمْ فَإِنَّهُمْ لَا يُكَلِّمُونَكَ قَالَ ثُمَّ مَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيْثُ أَرَادَ فَبَيْنَا أَنَا جَالِسٌ فِي خَطِّي إِذْ أَتَانِي رِجَالٌ كَأَنَّهُمْ الزُّطُّ أَشْعَارُهُمْ وَأَجْسَامُهُمْ لَا أَرَى عَوْرَةً وَلَا أَرَى قِشْرًا وَيَنْتَهُونَ إِلَيَّ وَلَا يُجَاوِزُونَ الْخَطَّ ثُمَّ يَصْدُرُونَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كَانَ مِنْ آخِرِ اللَّيْلِ لَكِنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ جَاءَنِي وَأَنَا جَالِسٌ فَقَالَ لَقَدْ أَرَانِي مُنْذُ اللَّيْلَةَ ثُمَّ دَخَلَ عَلَيَّ فِي خَطِّي فَتَوَسَّدَ فَخِذِي فَرَقَدَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَقَدَ نَفَخَ فَبَيْنَا أَنَا قَاعِدٌ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَوَسِّدٌ فَخِذِي إِذَا أَنَا بِرِجَالٍ عَلَيْهِمْ ثِيَابٌ بِيضٌ اللَّهُ أَعْلَمُ مَا بِهِمْ مِنْ الْجَمَالِ فَانْتَهَوْا إِلَيَّ فَجَلَسَ طَائِفَةٌ مِنْهُمْ عِنْدَ رَأْسِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَطَائِفَةٌ مِنْهُمْ عِنْدَ رِجْلَيْهِ ثُمَّ قَالُوا بَيْنَهُمْ مَا رَأَيْنَا عَبْدًا قَطُّ أُوتِيَ مِثْلَ مَا أُوتِيَ هَذَا النَّبِيُّ إِنَّ عَيْنَيْهِ تَنَامَانِ وَقَلْبُهُ يَقْظَانُ اضْرِبُوا لَهُ مَثَلًا مَثَلُ سَيِّدٍ بَنَى قَصْرًا ثُمَّ جَعَلَ مَأْدُبَةً فَدَعَا النَّاسَ إِلَى طَعَامِهِ وَشَرَابِهِ فَمَنْ أَجَابَهُ أَكَلَ مِنْ طَعَامِهِ وَشَرِبَ مِنْ شَرَابِهِ وَمَنْ لَمْ يُجِبْهُ عَاقَبَهُ أَوْ قَالَ عَذَّبَهُ ثُمَّ ارْتَفَعُوا وَاسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ فَقَالَ سَمِعْتَ مَا قَالَ هَؤُلَاءِ وَهَلْ تَدْرِي مَنْ هَؤُلَاءِ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ هُمْ الْمَلَائِكَةُ فَتَدْرِي مَا الْمَثَلُ الَّذِي ضَرَبُوا قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ الْمَثَلُ الَّذِي ضَرَبُوا الرَّحْمَنُ تَبَارَكَ وَتَعَالَى بَنَى الْجَنَّةَ وَدَعَا إِلَيْهَا عِبَادَهُ فَمَنْ أَجَابَهُ دَخَلَ الْجَنَّةَ وَمَنْ لَمْ يُجِبْهُ عَاقَبَهُ أَوْ عَذَّبَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَأَبُو تَمِيمَةَ هُوَ الْهُجَيْمِيُّ وَاسْمُهُ طَرِيفُ بْنُ مُجَالِدٍ وَأَبُو عُثْمَانَ النَّهْدِيُّ اسْمُهُ عَبْدُ الرَّحْمَنِ بْنُ مُلٍّ وَسُلَيْمَانُ التَّيْمِيُّ قَدْ رَوَى هَذَا الْحَدِيثَ عَنْهُ مُعْتَمِرٌ وَهُوَ سُلَيْمَانُ بْنُ طَرْخَانَ وَلَمْ يَكُنْ تَيْمِيًّا وَإِنَّمَا كَانَ يَنْزِلُ بَنِي تَيْمٍ فَنُسِبَ إِلَيْهِمْ قَالَ عَلِيٌّ قَالَ يَحْيَى بْنُ سَعِيدٍ مَا رَأَيْتُ أَخْوَفَ لِلَّهِ تَعَالَى مِنْ سُلَيْمَانَ التَّيْمِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Abu Adi] dari [Ja'far bin Maymun] dari [Abu Tamimah Al Hujaimi] dari [Abu Utsman] dari [Ibnu Mas'ud] ia berkata; \"Seusai Rasulullah shallallahu 'alaihi wasallam shalat isya, beliau keluar sambil memegang tangan Abdullah bin Mas'ud, ketika sampai di suatu lembah makkah, beliau mendudukkannya kemudian membuat garis lingkaran di sekitarnya lalu bersabda: \"Janganlah kamu meninggalkan garismu, karena akan datang kepadamu beberapa orang dan janganlah kamu mengajak bicara kepada mereka, karena sesungguhnya mereka tidak mengajak bicara denganmu, \" Ibnu Mas'ud berkata; lalu Rasulullah shallallahu 'alaihi wasallam berlalu ke tempat yang beliau tuju, ketika aku sedang duduk di garisku, tiba-tiba datanglah kepadaku beberapa orang, seakan-akan mereka adalah orang-orang hitam India yang rambut dan tubuh mereka tidak terlihat, tapi tidak memakai kain penutup, mereka menghampiriku namun tidak bisa melewati garis, setelah itu mereka kembali kepada Rasulullah shallallahu 'alaihi wasallam, sampai ketika di akhir malam, Rasulullah shallallahu 'alaihi wasallam mendatangiku, sementara saya dalam keadaan duduk, lalu beliau bersabda: \"Sejak tadi malam aku tidak tidur, \" kemudian beliau masuk ke dalam garis bersamaku dan menjadikan pahaku untuk bantalnya lalu beliau tertidur. Jika Rasulullah shallallahu 'alaihi wasallam tidur, maka tarikan nafasnya terdengar. Ketika aku sedang duduk sementara Rasulullah shallallahu 'alaihi wasallam berbantalkan pahaku, tiba-tiba saya melihat beberapa orang dengan mengenakan pakaian serba putih, hanya Allah yang tahu akan keindahan mereka, mereka menghampiriku, sedangkan sebagian dari mereka duduk di sisi kepala Rasulullah shallallahu 'alaihi wasallam dan sebagian yang lainnya di sisi kaki beliau, lalu mereka berkata kepada sesamanya: \"Kita tidak pernah sama sekali melihat seorang hamba yang diberi sebagaimana yang diberikan kepada Nabi ini, sungguh kedua matanya tertidur sementara hatinya terjaga, buatlah oleh kalian permisalan untuknya, permisalannya seperti seorang tuan yang membangun istana, kemudian membuat jamuan makan, setelah itu ia mengundang orang-orang untuk menghadiri jamuan makan dan minumnya, barangsiapa memenuhi undangannya maka dia makan dan minum jamuan makanan dan minumannya, dan barangsiapa tidak memenuhi undangannya, maka dia akan memberinya sanksi, atau dia berkata; maka dia akan menyiksanya.\" kemudian mereka pergi, ketika itu Rasulullah shallallahu 'alaihi wasallam terjaga dari tidurnya, lalu beliau bertanya: \"Apakah kamu mendengar apa yang mereka katakan dan apakah kamu tahu siapa mereka?\" Aku menjawab; \"Allah dan RasulNya yang lebih tahu, \" beliau bersabda: \"Mereka adalah para Malaikat, kemudian apakah kamu tahu apa permisalan yang mereka buat?\" aku menjawab; \"Allah dan Rasul-Nya yang lebih tahu, \" beliau bersabda: \"Permisalan yang mereka buat adalah Allah yang Maha pemurah dan Maha Tinggi telah membangum surga dan menyeru hamba-hambaNya menuju surga, barangsiapa menjawab seruanNya, dia masuk surga dan barangsiapa tidak menjawabnya, Dia akan memberinya sanksi atau menyiksanya.\" Abu Isa berkata; Hadits ini hasan shahih gharib dari jalur ini, Abu Tamimah adalah Al Juhani, namanya adalah Tharif bin Mujalid, Abu Utsman An Nahdi namanya adalah Abdurrahman bin Mull. Hadits [Sulaiman At Taimi] telah meriwayatkan hadits ini darinya [Mu'tamir] dan dia adalah Sulaiman bin Tharkhan, bukan Taimi namun dia pernah singgah di Bani Taim sehingga dia dinisbahkan kepadanya. Ali berkata bahwa Yahya bin Sa'id berkata; \"Aku tidak pernah melihat orang yang lebih takut kepada Allah melebihi Sulaiman At Taimi.\""},"2722":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا مُحَمَّدُ بْنِ سِنَانٍ حَدَّثَنَا سَلِيمُ بْنُ حَيَّانَ بَصْرِيٌّ حَدَّثَنَا سَعِيدُ بْنُ مِينَاءَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا مَثَلِي وَمَثَلُ الْأَنْبِيَاءِ قَبْلِي كَرَجُلٍ بَنَى دَارًا فَأَكْمَلَهَا وَأَحْسَنَهَا إِلَّا مَوْضِعَ لَبِنَةٍ فَجَعَلَ النَّاسُ يَدْخُلُونَهَا وَيَتَعَجَّبُونَ مِنْهَا وَيَقُولُونَ لَوْلَا مَوْضِعُ اللَّبِنَةِوَفِي الْبَاب عَنْ أُبَيِّ بْنِ كَعْبٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Muhammad bin Sinan] telah menceritakan kepada kami [Sulaim bin Hayyan Bashri] telah menceritakan kepada kami [Sa'id bin Mina`] dari [Jabir bin Abdullah] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya perumpamaanku dengan para nabi sebelumku seperti seseorang yang membangun rumah, lalu ia menyelesaikan dan memperindahnya kecuali satu tempat batu bata yang kurang, lalu orang-orang memasukinya dan mereka terkesima karenanya, mereka berkata; \"Andai bukan karena satu tempat batu bata.\" Abu Isa berkata; Dalam hal ini, ada hadits serupa dari Ubay bin Ka'ab dan Abu Hurairah. Abu Isa berkata; Hadits ini hasan shahih gharib dari jalur ini."},"2723":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ زَيْدِ بْنِ سَلَّامٍ أَنَّ أَبَا سَلَّامٍ حَدَّثَهُ أَنَّ الْحَارِثَ الْأَشْعَرِيَّ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ أَمَرَ يَحْيَى بْنَ زَكَرِيَّا بِخَمْسِ كَلِمَاتٍ أَنْ يَعْمَلَ بِهَا وَيَأْمُرَ بَنِي إِسْرَائِيلَ أَنْ يَعْمَلُوا بِهَا وَإِنَّهُ كَادَ أَنْ يُبْطِئَ بِهَا فَقَالَ عِيسَى إِنَّ اللَّهَ أَمَرَكَ بِخَمْسِ كَلِمَاتٍ لِتَعْمَلَ بِهَا وَتَأْمُرَ بَنِي إِسْرَائِيلَ أَنْ يَعْمَلُوا بِهَا فَإِمَّا أَنْ تَأْمُرَهُمْ وَإِمَّا أَنْ آمُرَهُمْ فَقَالَ يَحْيَى أَخْشَى إِنْ سَبَقْتَنِي بِهَا أَنْ يُخْسَفَ بِي أَوْ أُعَذَّبَ فَجَمَعَ النَّاسَ فِي بَيْتِ الْمَقْدِسِ فَامْتَلَأَ الْمَسْجِدُ وَتَعَدَّوْا عَلَى الشُّرَفِ فَقَالَ إِنَّ اللَّهَ أَمَرَنِي بِخَمْسِ كَلِمَاتٍ أَنْ أَعْمَلَ بِهِنَّ وَآمُرَكُمْ أَنْ تَعْمَلُوا بِهِنَّ أَوَّلُهُنَّ أَنْ تَعْبُدُوا اللَّهَ وَلَا تُشْرِكُوا بِهِ شَيْئًا وَإِنَّ مَثَلَ مَنْ أَشْرَكَ بِاللَّهِ كَمَثَلِ رَجُلٍ اشْتَرَى عَبْدًا مِنْ خَالِصِ مَالِهِ بِذَهَبٍ أَوْ وَرِقٍ فَقَالَ هَذِهِ دَارِي وَهَذَا عَمَلِي فَاعْمَلْ وَأَدِّ إِلَيَّ فَكَانَ يَعْمَلُ وَيُؤَدِّي إِلَى غَيْرِ سَيِّدِهِ فَأَيُّكُمْ يَرْضَى أَنْ يَكُونَ عَبْدُهُ كَذَلِكَ وَإِنَّ اللَّهَ أَمَرَكُمْ بِالصَّلَاةِ فَإِذَا صَلَّيْتُمْ فَلَا تَلْتَفِتُوا فَإِنَّ اللَّهَ يَنْصِبُ وَجْهَهُ لِوَجْهِ عَبْدِهِ فِي صَلَاتِهِ مَا لَمْ يَلْتَفِتْ وَآمُرُكُمْ بِالصِّيَامِ فَإِنَّ مَثَلَ ذَلِكَ كَمَثَلِ رَجُلٍ فِي عِصَابَةٍ مَعَهُ صُرَّةٌ فِيهَا مِسْكٌ فَكُلُّهُمْ يَعْجَبُ أَوْ يُعْجِبُهُ رِيحُهَا وَإِنَّ رِيحَ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِ وَآمُرُكُمْ بِالصَّدَقَةِ فَإِنَّ مَثَلَ ذَلِكَ كَمَثَلِ رَجُلٍ أَسَرَهُ الْعَدُوُّ فَأَوْثَقُوا يَدَهُ إِلَى عُنُقِهِ وَقَدَّمُوهُ لِيَضْرِبُوا عُنُقَهُ فَقَالَ أَنَا أَفْدِيهِ مِنْكُمْ بِالْقَلِيلِ وَالْكَثِيرِ فَفَدَى نَفْسَهُ مِنْهُمْ وَآمُرُكُمْ أَنْ تَذْكُرُوا اللَّهَ فَإِنَّ مَثَلَ ذَلِكَ كَمَثَلِ رَجُلٍ خَرَجَ الْعَدُوُّ فِي أَثَرِهِ سِرَاعًا حَتَّى إِذَا أَتَى عَلَى حِصْنٍ حَصِينٍ فَأَحْرَزَ نَفْسَهُ مِنْهُمْ كَذَلِكَ الْعَبْدُ لَا يُحْرِزُ نَفْسَهُ مِنْ الشَّيْطَانِ إِلَّا بِذِكْرِ اللَّهِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا آمُرُكُمْ بِخَمْسٍ اللَّهُ أَمَرَنِي بِهِنَّ السَّمْعُ وَالطَّاعَةُ وَالْجِهَادُ وَالْهِجْرَةُ وَالْجَمَاعَةُ فَإِنَّهُ مَنْ فَارَقَ الْجَمَاعَةَ قِيدَ شِبْرٍ فَقَدْ خَلَعَ رِبْقَةَ الْإِسْلَامِ مِنْ عُنُقِهِ إِلَّا أَنْ يَرْجِعَ وَمَنْ ادَّعَى دَعْوَى الْجَاهِلِيَّةِ فَإِنَّهُ مِنْ جُثَا جَهَنَّمَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ وَإِنْ صَلَّى وَصَامَ قَالَ وَإِنْ صَلَّى وَصَامَ فَادْعُوا بِدَعْوَى اللَّهِ الَّذِي سَمَّاكُمْ الْمُسْلِمِينَ الْمُؤْمِنِينَ عِبَادَ اللَّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ الْحَارِثُ الْأَشْعَرِيُّ لَهُ صُحْبَةٌ وَلَهُ غَيْرُ هَذَا الْحَدِيثِ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ زَيْدِ بْنِ سَلَّامٍ عَنْ أَبِي سَلَّامٍ عَنْ الْحَارِثِ الْأَشْعَرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَأَبُو سَلَّامٍ الْحَبَشِيُّ اسْمُهُ مَمْطُورٌ وَقَدْ رَوَاهُ عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Aban bin Yazid] telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Zaid bin Sallam] bahwa [Abu Sallam] telah menceritakan kepadanya bahwa [Al Harits Al Asy'ari] telah menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah memerintahkan lima kalimat kepada Yahya bin Zakariya agar diamalkan dan memerintahkan Bani Israil supaya mengamalkannya, dan sesungguhnya ia hampir saja memperlambatnya. Isa berkata; \"Sesungguhnya Allah memerintahkan lima kalimat padamu agar kamu amalkan dan agar Bani Israil kamu perintahkan untuk mengamalkannya, perintahlah mereka atau aku yang memerintah mereka.\" Yahya menjawab; \"Aku khawatir bila kamu mendahuluiku menyampaikannya, aku akan dibenamkan atau disiksa.\" Isa kemudian mengumpulkan manusia di Baitul Maqdis, masjid penuh sesak hingga ke teras, Isa berkata; \"Sesungguhnya Allah memerintahkanku lima kalimat agar aku amalkan dan aku perintahkan kalian untuk mengamalkannya, pertama; sembahlah Allah dan jangan menyekutukanNya dengan sesuatu pun, sesungguhnya perumpamaan orang yang menyekutukan Allah sama seperti seseorang membeli budak dengan uang emas atau perak lalu ia berkata; Ini rumahku dan ini pekerjaanku, bekerjalah dan tunaikan untukku. Tapi budak itu malah bekerja dan menunaikan untuk orang lain, siapa di antara kalian yang mau budaknya seperti itu? Sesungguhnya Allah memerintahkan shalat pada kalian, bila kalian shalat, maka janganlah menoleh, karena Allah menghadapkankan wajah-Nya ke wajah hambaNya saat shalat, selama ia tidak menoleh. Aku memerintahkan kalian puasa, dan perumpamaannya seperti seseorang berada di tengah-tengah sekelompok orang, ia membawa kantong berisi minyak kesturi, kalian semua kagum atau semerbak baunya mengagumkan, seseungguhnya bau (mulut) orang yang berpuasa lebih harum bagi Allah melebihi minyak kesturi, aku juga memerintahkan kalian bersedekah, perumpamaannya seperti seseorang yang ditawan musuh, mereka membelenggu tangannya ke leher, mereka lalu memajukannya untuk ditebas lehernya, kemudian ia berkata; \"Aku menebusnya dari kalian dengan yang sedikit dan yang banyak, \" lalu tawanan tersebut menebus dirinya dari mereka. Aku memerintahkan kalian untuk mengingat Allah, sesungguhnya perumpamaannya seperti seseorang yang dikejar musuh dengan cepat, hingga ketika tiba di benteng yang kokoh, ia menjaga dirinya dari mereka, demikian halnya hamba, ia tidak menjaga diri dari setan kecuali dengan mengingat Allah.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Dan aku memerintahkan lima hal pada kalian yang diperintahkan Allah padaku, yaitu; mendengar, taat, jihad, hijrah dan jama'ah, sebab barangsiapa meninggalkan jama'ah barang sejengkal, maka ia telah melepas tali Islam dari lehernya, kecuali jika ia kembali. Dan barangsiapa menyerukan seruan jahiliyah, maka ia termasuk bangkai neraka jahanam.\" Seseorang bertanya; \"Wahai Rasulullah, meski ia shalat dan puasa?\" Beliau menjawab: \"Meski ia shalat dan puasa, oleh karena itu, serukanlah seruan Allah yang menyebut kalian sebagai kaum muslimin, mu`minin dan hamba-hamba Allah.\" Abu Isa berkata; Hadits ini hasan shahih gharib. Abu Isa berkata; Muhammad bin Isam'il Al Harits Al Asy'ari pernah bertemu Nabi shallallahu 'alaihi wasallam dan ia memiliki hadits lain selain hadits ini. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] telah menceritakan kepada kami [Aban bin Yazid] dari [Yahya bin Abu Katsir] dari [Zaid bin Sallam] dari [Abu Sallam] dari [Al Harits Al Asy'ari] dari Nabi shallallahu 'alaihi wasallam seperti di atas dengan maksud yang sama.\" Abu Isa berkata; Hadits ini hasan shahih gharib, dan Abu Sallam Al Habasyi namanya adalah Mamthur. [Ali bin Al Mubarak] telah meriwayatkan hadits ini dari [Yahya bin Abu Katsir]."},"2724":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُؤْمِنِ الَّذِي يَقْرَأُ الْقُرْآنَ كَمَثَلِ الْأُتْرُنْجَةِ رِيحُهَا طَيِّبٌ وَطَعْمُهَا طَيِّبٌ وَمَثَلُ الْمُؤْمِنِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ كَمَثَلِ التَّمْرَةِ لَا رِيحَ لَهَا وَطَعْمُهَا حُلْوٌ وَمَثَلُ الْمُنَافِقِ الَّذِي يَقْرَأُ الْقُرْآنَ كَمَثَلِ الرَّيْحَانَةِ رِيحُهَا طَيِّبٌ وَطَعْمُهَا مُرٌّ وَمَثَلُ الْمُنَافِقِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ كَمَثَلِ الْحَنْظَلَةِ رِيحُهَا مُرٌّ وَطَعْمُهَا مُرٌّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ شُعْبَةُ عَنْ قَتَادَةَ أَيْضًا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas] dari [Abu Musa Al Asy'ari] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan orang mu`min yang membaca al-Qur`an seperti buah utrujah, baunya harum dan rasanya enak, sedangkan perumpamaan orang mu`min yang tidak membaca al-Qur`an seperti buah kurma, tidak ada baunya namun rasanya manis, dan perumpamaan orang munafik yang membaca al-Qur`an seperti raihanah (sejenis tanaman), harum baunya tapi pahit rasanya dan perumpamaan munafik yang yang tidak membaca al-Qur`an seperti brotowali, baunya busuk dan rasanya pahit.\" Abu Isa berkata; Hadits ini hasan shahih dan [Syu'bah] juga meriwayatkannya dari [Qatadah]."},"2725":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُؤْمِنِ كَمَثَلِ الزَّرْعِ لَا تَزَالُ الرِّيَاحُ تُفَيِّئُهُ وَلَا يَزَالُ الْمُؤْمِنُ يُصِيبُهُ بَلَاءٌ وَمَثَلُ الْمُنَافِقِ مَثَلُ شَجَرَةِ الْأَرْزِ لَا تَهْتَزُّ حَتَّى تُسْتَحْصَدَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] dan yang lain, mereka berkata; telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan orang mu`min seperti tanaman, angin senantiasa menerpanya (ke kiri dan ke kanan) dan orang mu`min itu akan senantiasa tertimpa musibah, sedangkan perumpamaan orang munafik seperti pohon padi, tidaklah ia bergerak hingga di ketam.\" Abu Isa berkata; Hadits ini hasan shahih."},"2726":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ الشَّجَرِ شَجَرَةً لَا يَسْقُطُ وَرَقُهَا وَهِيَ مَثَلُ الْمُؤْمِنِ حَدِّثُونِي مَا هِيَ قَالَ عَبْدُ اللَّهِ فَوَقَعَ النَّاسُ فِي شَجَرِ الْبَوَادِي وَوَقَعَ فِي نَفْسِي أَنَّهَا النَّخْلَةُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هِيَ النَّخْلَةُ فَاسْتَحْيَيْتُ أَنْ أَقُولَ قَالَ عَبْدُ اللَّهِ فَحَدَّثْتُ عُمَرَ بِالَّذِي وَقَعَ فِي نَفْسِي فَقَالَ لَأَنْ تَكُونَ قُلْتَهَا أَحَبَّ إِلَيَّ مِنْ أَنْ يَكُونَ لِي كَذَا وَكَذَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] telah menceritakan kepada kami [Ma'nu] telah menceritakan kepada kami [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di antara pepohonan ada suatu pohon yang daunnya tidak berguguran, itu seperti seorang mu`min, beritahukanlah kepadaku pohon apa itu?\" Abdullah berkata; Orang-orang mengira pohon tersebut adalah pohon yang tumbuh dipadang pasir, sementara aku mengiranya pohon kurma. Nabi shallallahu 'alaihi wasallam bersabda: \"Ia adalah pohon kurma\" akan tetapi aku malu mengatakannya.\" Abdullah berkata; \"Lalu aku beritahukan kepada Umar apa yang aku kira, maka Umar berkata; \"Sungguh bila kamu mengatakannya itu lebih aku sukai daripada aku memiliki ini dan ini.\" Abu Isa berkata; Hadits ini hasan. Dalam hal ini ada hadits serupa dari Abu Hurairah radliallahu 'anhu."},"2727":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرَأَيْتُمْ لَوْ أَنَّ نَهْرًا بِبَابِ أَحَدِكُمْ يَغْتَسِلُ مِنْهُ كُلَّ يَوْمٍ خَمْسَ مَرَّاتٍ هَلْ يَبْقَى مِنْ دَرَنِهِ شَيْءٌ قَالُوا لَا يَبْقَى مِنْ دَرَنِهِ شَيْءٌ قَالَ فَذَلِكَ مَثَلُ الصَّلَوَاتِ الْخَمْسِ يَمْحُو اللَّهُ بِهِنَّ الْخَطَايَاوَفِي الْبَاب عَنْ جَابِرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا بَكْرُ بْنُ مُضَرَ الْقُرَشِيُّ عَنْ ابْنِ الْهَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Ibnu Al Had] dari [Muhammad bin Ibrahim] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagaimana menurut kalian bila di pintu salah seorang dari kalian ada sungai, lalu ia mandi lima kali setiap harinya, masihkan ada kotoran yang tersisa?\" mereka menjawab; \"Tidak akan ada kotorannya tersisa sedikit pun.\" Beliau bersabda: \"Itu seperti shalat lima waktu, dengannya Allah akan menghapus kesalahan-kesalahannya.\" Dalam hal ini, ada hadits serupa dari Jabir. Abu Isa berkata; Hadits ini hasan shahih. Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Bakr bin Mudlar Al Qurasy] dari [Ibnu Al Had] seperti hadits di atas."},"2728":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ يَحْيَى الْأَبَحُّ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ أُمَّتِي مَثَلُ الْمَطَرِ لَا يُدْرَى أَوَّلُهُ خَيْرٌ أَمْ آخِرُهُقَالَ وَفِي الْبَاب عَنْ عَمَّارٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ قَالَ وَرُوِي عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ أَنَّهُ كَانَ يُثَبِّتُ حَمَّادَ بْنَ يَحْيَى الْأَبَحَّ وَكَانَ يَقُولُ هُوَ مِنْ شُيُوخِنَا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad bin Yahya Al Abah] dari [Tsabit Al Bunani] dari [Anas] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan ummatku seperti hujan, tidak diketahui (apakah) yang baik pada permulannya ataukah akhirnya.\" Abu Isa berkata; Dalam hal ini, ada hadits serupa dari 'Ammar, Abdullah bin 'Amru dan Ibnu Umar. Abu Isa berkata; Hadits ini hasan gharib melalui sanad ini. ia berkata; Dan diriwayatkan dari Abdurrahman bin Mahdi bahwa dia menguatkan (hadits) Hammad bin Yahya Al Abah, ia berkata; \"Dia termasuk salah satu dari guru kami.\""},"2729":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا خَلَّادُ بْنُ يَحْيَي حَدَّثَنَا بَشِيرُ بْنُ الْمُهَاجِرِ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ تَدْرُونَ مَا هَذِهِ وَمَا هَذِهِ وَرَمَى بِحَصَاتَيْنِ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ هَذَاكَ الْأَمَلُ وَهَذَاكَ الْأَجَلُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami [Basyir bin Al Muhajir] telah menceritakan kepada kami [Abdullah bin Buraidah] dari [Ayahnya] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Tahukah kalian apakah ini dan apakah ini?\" -beliau sambil melempar dua batu kerikil, - para sahabat menjawab; \"Allah dan Rasul-Nya yang lebih tahu, \" beliau bersabda: \"Yang ini seperti cita-cita dan yang ini seperti ajal.\" Abu Isa berkata; Dari jalur ini, hadits ini hasan gharib."},"2730":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا أَجَلُكُمْ فِيمَا خَلَا مِنْ الْأُمَمِ كَمَا بَيْنَ صَلَاةِ الْعَصْرِ إِلَى مَغَارِبِ الشَّمْسِ وَإِنَّمَا مَثَلُكُمْ وَمَثَلُ الْيَهُودِ وَالنَّصَارَى كَرَجُلٍ اسْتَعْمَلَ عُمَّالًا فَقَالَ مَنْ يَعْمَلُ لِي إِلَى نِصْفِ النَّهَارِ عَلَى قِيرَاطٍ قِيرَاطٍ فَعَمِلَتْ الْيَهُودُ عَلَى قِيرَاطٍ قِيرَاطٍ فَقَالَ مَنْ يَعْمَلُ لِي مِنْ نِصْفِ النَّهَارِ إِلَى صَلَاةِ الْعَصْرِ عَلَى قِيرَاطٍ قِيرَاطٍ فَعَمِلَتْ النَّصَارَى عَلَى قِيرَاطٍ قِيرَاطٍ ثُمَّ أَنْتُمْ تَعْمَلُونَ مِنْ صَلَاةِ الْعَصْرِ إِلَى مَغَارِبِ الشَّمْسِ عَلَى قِيرَاطَيْنِ قِيرَاطَيْنِ فَغَضِبَتْ الْيَهُودُ وَالنَّصَارَى وَقَالُوا نَحْنُ أَكْثَرُ عَمَلًا وَأَقَلُّ عَطَاءً قَالَ هَلْ ظَلَمْتُكُمْ مِنْ حَقِّكُمْ شَيْئًا قَالُوا لَا قَالَ فَإِنَّهُ فَضْلِي أُوتِيهِ مَنْ أَشَاءُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ishaq bin Musa] telah menceritakan kepada kami [Ma'nu] telah menceritakan kepada kami [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ajal kalian seperti yang telah berlalu dari umat-umat sebelumnya, sama seperti waktu antara shalat ashar hingga terbenamnya matahari, sesungguhnya perumpamaan kalian dan perumpamaan Yahudi dan Nasrani seperti seseorang mempekerjakan beberapa pekerja, orang itu berkata; \"Siapa yang bekerja untukku hingga pertengahan siang, akan mendapatkan satu qirath satu qirath.\" Maka orang Yahudi bekerja untuk mendapatkan satu qirath satu qirath, lalu orang itu berkata; \"Siapa yang bekerja untukku dari pertengahan siang hingga shalat ashar akan mendapatkan satu qirath satu qirat.\" Orang Nasrani bekerja untuk mendapatkan satu qirath satu qirath. Selanjutnya kalian bekerja mulai dari shalat ashar hingga matahari terbenam dengan mendapatkan dua qirath dua qirath. Maka Yahudi dan Nasrani marah, mereka berkata; Kami kerja lebih banyak tapi imbalannya sedikit. Orang itu bertanya: \"Apakah aku menzhalimi hak kalian sedikit pun?\" Mereka menjawab; \"Tidak.\" orang itu berkata; \"Itulah karuniaku, aku memberikannya kepada siapa saja yang aku kehendaki.\" Abu Isa berkata; Hadits ini hasan shahih."},"2731":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا النَّاسُ كَإِبِلٍ مِائَةٍ لَا يَجِدُ الرَّجُلُ فِيهَا رَاحِلَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَقَالَ لَا تَجِدُ فِيهَا رَاحِلَةً أَوْ قَالَ لَا تَجِدُ فِيهَا إِلَّا رَاحِلَةً","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] dan yang lain, mereka berkata; telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya manusia itu seperti seratus unta, hampir saja seseorang tidak menemukan satu pun yang berangkat (yang layak untuk ditunggangi).\" Abu Isa berkata; Hadits ini hasan shahih. Telah menceritakan kepada kami [Sa'id bin Abdurrahman Al Makhzumi] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dengan sanad dan maksud yang sama. Dan beliau bersabda: \"Tidak ada satu pun yang berangkat, atau bersabda: \"Tidak ada kecuali satu pun yang berangkat.\""},"2732":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا مَثَلِي وَمَثَلُ أُمَّتِي كَمَثَلِ رَجُلٍ اسْتَوْقَدَ نَارًا فَجَعَلَتْ الذُّبَابُ وَالْفَرَاشُ يَقَعْنَ فِيهَا وَأَنَا آخُذُ بِحُجَزِكُمْ وَأَنْتُمْ تَقَحَّمُونَ فِيهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Mughirah bin Abdurrahman] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya perumpamaanku dan perumpamaan ummatku seperti seseorang yang menyalakan api kemudian lalat dan kupu-kupu jatuh di api itu, dan aku memegangi ikatan kain kalian, sementara kalian tetap memasukinya.\" Abu Isa berkata; hadits ini hasan shahih dan hadits ini juga diriwayatkan melalui sanad yang lain."},"2733":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَى أُبَيِّ بْنِ كَعْبٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أُبَيُّ وَهُوَ يُصَلِّي فَالْتَفَتَ أُبَيٌّ وَلَمْ يُجِبْهُ وَصَلَّى أُبَيٌّ فَخَفَّفَ ثُمَّ انْصَرَفَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ السَّلَامُ عَلَيْكَ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْكَ السَّلَامُ مَا مَنَعَكَ يَا أُبَيُّ أَنْ تُجِيبَنِي إِذْ دَعَوْتُكَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي كُنْتُ فِي الصَّلَاةِ قَالَ أَفَلَمْ تَجِدْ فِيمَا أَوْحَى اللَّهُ إِلَيَّ أَنْ{ اسْتَجِيبُوا لِلَّهِ وَلِلرَّسُولِ إِذَا دَعَاكُمْ لِمَا يُحْيِيكُمْ }قَالَ بَلَى وَلَا أَعُودُ إِنْ شَاءَ اللَّهُ قَالَ أَتُحِبُّ أَنْ أُعَلِّمَكَ سُورَةً لَمْ يَنْزِلْ فِي التَّوْرَاةِ وَلَا فِي الْإِنْجِيلِ وَلَا فِي الزَّبُورِ وَلَا فِي الْفُرْقَانِ مِثْلُهَا قَالَ نَعَمْ يَا رَسُولَ اللَّهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ تَقْرَأُ فِي الصَّلَاةِ قَالَ فَقَرَأَ أُمَّ الْقُرْآنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ مَا أُنْزِلَتْ فِي التَّوْرَاةِ وَلَا فِي الْإِنْجِيلِ وَلَا فِي الزَّبُورِ وَلَا فِي الْفُرْقَانِ مِثْلُهَا وَإِنَّهَا سَبْعٌ مِنْ الْمَثَانِي وَالْقُرْآنُ الْعَظِيمُ الَّذِي أُعْطِيتُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ أَنَسِ بْنِ مَالِكٍ وَفِيهِ عَنْ أَبِي سَعِيدِ بْنِ الْمُعَلَّى","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Al Ala` bin Abdurrahman] dari [Ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam pergi menemui Ubay bin Ka'ab, maka Rasulullah shallallahu 'alaihi wasallam memanggil: \"Hai Ubay!\" sementara dirinya tengah mengerjakan shalat, ia menoleh namun tidak menjawab beliau, dan Ubai tetap melanjutkan shalatnya, ia lalu mempercepat shalatnya dan langsung menghampiri Rasulullah shallallahu 'alaihi wasallam, Ubay mengucapkan; \"ASSALAAMU'ALAIKUM, wahai Rasulullah.\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"WA 'ALAIKASSALAAM, apa yang menghalangimu, wahai Ubay untuk menjawabku saat aku memanggilmu?\" Ubay menjawab; \"Wahai Rasulullah, aku tadi sedang mengerjakan shalat. Beliau bertanya: \"Apa kau tidak menemukan di antara yang diwahyukan Allah kepadaku agar kalian memenuhi panggilan Allah dan RasulNya bila menyeru kalian untuk sesuatu yang menghidupkan kalian?\" Ubay menjawab; \"Benar, aku tidak akan mengulangi, insya Allah.\" Beliau bersabda: \"Maukah aku ajarkan kepadamu satu surat yang tidak diturunkan di Taurat, Injil dan Zabur, dan dalam al-Qur`an juga tidak ada yang sepertinya?\" Ubay menjawab; \"Tentu, wahai Rasulullah.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagaimana kamu membaca saat shalat?\" Perawi berkata; \"Maka Ubay membaca ummul al-Qur`an (Al Fatehah). Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, tidaklah diturunkan di Taurat, Injil, Zabur dan dalam al-Qur`an seperti itu, sesungguhnya ia adalah tujuh (ayat) yang diulang-ulang dan al-Qur`an yang agung yang diberikan padaku.\" Abu Isa berkata; Hadits ini hasan shahih. Dalam hal ini, ada hadits serupa dari Anas bin Malik dan Abu Sa'id bin Al Mu'alla."},"2734":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ عَطَاءٍ مَوْلَى أَبِي أَحْمَدَ عَنْ أَبِي هُرَيْرَةَ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْثًا وَهُمْ ذُو عَدَدٍ فَاسْتَقْرَأَهُمْ فَاسْتَقْرَأَ كُلَّ رَجُلٍ مِنْهُمْ مَا مَعَهُ مِنْ الْقُرْآنِ فَأَتَى عَلَى رَجُلٍ مِنْهُمْ مِنْ أَحْدَثِهِمْ سِنًّا فَقَالَ مَا مَعَكَ يَا فُلَانُ قَالَ مَعِي كَذَا وَكَذَا وَسُورَةُ الْبَقَرَةِ قَالَ أَمَعَكَ سُورَةُ الْبَقَرَةِ فَقَالَ نَعَمْ قَالَ فَاذْهَبْ فَأَنْتَ أَمِيرُهُمْ فَقَالَ رَجُلٌ مِنْ أَشْرَافِهِمْ وَاللَّهِ يَا رَسُولَ اللَّهِ مَا مَنَعَنِي أَنْ أَتَعَلَّمَ سُورَةَ الْبَقَرَةِ إِلَّا خَشْيَةَ أَلَّا أَقُومَ بِهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَلَّمُوا الْقُرْآنَ وَاقْرَءُوهُ فَإِنَّ مَثَلَ الْقُرْآنِ لِمَنْ تَعَلَّمَهُ فَقَرَأَهُ وَقَامَ بِهِ كَمَثَلِ جِرَابٍ مَحْشُوٍّ مِسْكًا يَفُوحُ رِيحُهُ فِي كُلِّ مَكَانٍ وَمَثَلُ مَنْ تَعَلَّمَهُ فَيَرْقُدُ وَهُوَ فِي جَوْفِهِ كَمَثَلِ جِرَابٍ وُكِئَ عَلَى مِسْكٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَاهُ اللَّيْثُ بْنُ سَعْدٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ عَطَاءٍ مَوْلَى أَبِي أَحْمَدَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا وَلَمْ يَذْكُرْ فِيهِ عَنْ أَبِي هُرَيْرَةَ حَدَّثَنَا قُتَيْبَةُ عَنْ اللَّيْثِ فَذَكَرَهُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Hulwani] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Abdul Hamid bin Ja'far] dari [Sa'id Al Maqburi] dari [Atha`] bekas budak milik Abu Ahmad dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mengutus rombongan para sahabat dalam jumlah banyak, beliau meminta kepada mereka untuk membaca, beliau meminta setiap orang dari mereka untuk membacakan apa yang dia hafal dari Al Qur`an, beliau datang kepada seseorang yang paling muda umurnya di antara mereka dan bertanya: \"Apa yang kamu hafal dari Al Qur`an wahai Fulan?\" dia menjawab; \"Saya hafal ini dan ini dan surat Al Baqarah, \" beliau bertanya: \"Apakah kamu hafal surat Al Baqarah?\" dia menjawab; \"Ya, \" beliau bersabda kepadanya: \"Pergilah dan kamu yang jadi imam bagi mereka, \" Seseorang yang paling terkemuka di antara mereka berkata; \"Demi Allah wahai Rasulullah, tidak ada yang menghalangiku untuk mempelajari surat Al Baqarah selain karena aku takut tidak dapat mengamalkannya, \" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pelajarilah Al Qur`an dan bacalah, karena perumpamaan Al Qur`an bagi orang yang mempelajarinya kemudian membacanya seperti kantong yang penuh dengan minyak wangi, dimana wanginya semerbak ke setiap tempat, dan perumpamaan orang yang mempelajarinya kemudian tidur (tidak mengamalkannya) padahal Al Qur`an ada di hatinya seperti kantong yang berisi minyak wangi namun terikat.\" Abu Isa berkata; Hadits ini hasan, [Laits bin Sa'ad] telah meriwayatkannya dari [Sa'id Al Maqburi] dari [Atha`] budak milik Abu Ahmad, dari Nabi shallallahu 'alaihi wasallam secara mursal, dan di dalam hadits tersebut, tidak disebutkan dari Abu Hurairah. Telah menceritakan kepada kami [Qutaibah] dari [Laits] kemudian dia menyebutkan hadits."},"2735":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَجْعَلُوا بُيُوتَكُمْ مَقَابِرَ وَإِنَّ الْبَيْتَ الَّذِي تُقْرَأُ فِيهِ الْبَقَرَةُ لَا يَدْخُلُهُ الشَّيْطَانُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menjadikan rumah-rumah kalian seperti kuburan, sesungguhnya syetan tidak memasuki rumah yang dibacakan didalamnya surat Al Baqarah.\" Abu Isa berkata; Hadits ini hasan shahih."},"2736":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا حُسَيْنٌ الْجُعْفِيُّ عَنْ زَائِدَةَ عَنْ حَكِيمِ بْنِ جُبَيْرٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِكُلِّ شَيْءٍ سَنَامٌ وَإِنَّ سَنَامَ الْقُرْآنِ سُورَةُ الْبَقَرَةِ وَفِيهَا آيَةٌ هِيَ سَيِّدَةُ آيِ الْقُرْآنِ هِيَ آيَةُ الْكُرْسِيِّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ حَكِيمِ بْنِ جُبَيْرٍ وَقَدْ تَكَلَّمَ شُعْبَةُ فِي حَكِيمِ بْنِ جُبَيْرٍ وَضَعَّفَهُ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Husain Al Ju'fi] dari [Za`idah] dari [Hakim bin Jubair] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap sesuatu memiliki puncak, dan puncaknya Al Qur`an adalah surat Al Baqarah, di dalamnya terdapat ayat yang merupakan tuannya ayat-ayat dalam Al Qur`an yaitu ayat kursi.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari hadits Hakim bin Jubair, sementara Syu'bah mempermasalahkan tentang Hakim bin Jubair dan melemahkannya.\""},"2737":{"ar":"حَدَّثَنَا يَحْيَى بْنُ الْمُغِيرَةِ أَبُو سَلَمَةَ الْمَخْزُومِيُّ الْمَدَنِيُّ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ الْمُلَيْكِيِّ عَنْ زُرَارَةَ بْنِ مُصْعَبٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ حم الْمُؤْمِنَ إِلَى{ إِلَيْهِ الْمَصِيرُ }وَآيَةَ الْكُرْسِيِّ حِينَ يُصْبِحُ حُفِظَ بِهِمَا حَتَّى يُمْسِيَ وَمَنْ قَرَأَهُمَا حِينَ يُمْسِي حُفِظَ بِهِمَا حَتَّى يُصْبِحَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَقَدْ تَكَلَّمَ بَعْضُ أَهْلِ الْعِلْمِ فِي عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرِ بْنِ أَبِي مُلَيْكَةَ الْمُلَيْكِيِّ مِنْ قِبَلِ حِفْظِهِ وَزُرَارَةُ بْنُ مُصْعَبٍ هُوَ ابْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَهُوَ جَدُّ أَبِي مُصْعَبٍ الْمَدَنِيِّ","id":"Telah menceritakan kepada kami [Yahya bin Al Mughirah Abu Salamah Al Makhzumi Al Madani] telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Abdurrahman bin Abu Bakar Al Mulaiki] dari [Zurarah bin Mush'ab] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca HAA MIIM (dalam surat) Al Mu`min sampai ayat ILAIHIL MASHIIR dan membaca ayat kursi pada waktu pagi, maka ia akan di jaga hingga tiba waktu sore, dan barangsiapa membaca keduanya pada waktu sore maka ia akan dijaga hingga tiba waktu pagi.\" Abu Isa berkata; Hadits ini gharib, sebagian ahli ilmu telah membicarakan tentang Abdurrahman bin Abu Bakar bin Abu Mulaikah Al Mulaiki dari sisi hafalannya, Zurarah bin Mush'ab adalah Ibnu Abdurrahman bin 'Auf, kakek Abu Mush'ab Al Madani."},"2738":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي لَيْلَى عَنْ أَخِيهِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّأَنَّهُ كَانَتْ لَهُ سَهْوَةٌ فِيهَا تَمْرٌ فَكَانَتْ تَجِيءُ الْغُولُ فَتَأْخُذُ مِنْهُ قَالَ فَشَكَا ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَاذْهَبْ فَإِذَا رَأَيْتَهَا فَقُلْ بِسْمِ اللَّهِ أَجِيبِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَخَذَهَا فَحَلَفَتْ أَنْ لَا تَعُودَ فَأَرْسَلَهَا فَجَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا فَعَلَ أَسِيرُكَ قَالَ حَلَفَتْ أَنْ لَا تَعُودَ فَقَالَ كَذَبَتْ وَهِيَ مُعَاوِدَةٌ لِلْكَذِبِ قَالَ فَأَخَذَهَا مَرَّةً أُخْرَى فَحَلَفَتْ أَنْ لَا تَعُودَ فَأَرْسَلَهَا فَجَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا فَعَلَ أَسِيرُكَ قَالَ حَلَفَتْ أَنْ لَا تَعُودَ فَقَالَ كَذَبَتْ وَهِيَ مُعَاوِدَةٌ لِلْكَذِبِ فَأَخَذَهَا فَقَالَ مَا أَنَا بِتَارِكِكِ حَتَّى أَذْهَبَ بِكِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي ذَاكِرَةٌ لَكَ شَيْئًا آيَةَ الْكُرْسِيِّ اقْرَأْهَا فِي بَيْتِكَ فَلَا يَقْرَبُكَ شَيْطَانٌ وَلَا غَيْرُهُ قَالَ فَجَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا فَعَلَ أَسِيرُكَ قَالَ فَأَخْبَرَهُ بِمَا قَالَتْ قَالَ صَدَقَتْ وَهِيَ كَذُوبٌقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَفِي الْبَاب عَنْ أُبَيِّ بْنِ كَعْبٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Laila] dari saudaranya yaitu [Isa] dari [Abdurrahman bin Abu Laila] dari [Abu Ayyub Al Anshari] ia memiliki rak berisi kurma, ada hantu datang dan mengambilnya, lalu ia mengadukan hal itu kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pergilah, bila kau melihatnya, ucapkanlah BISMILLAAH, turutilah Rasulullah.\" lalu Abu Ayyub Al Anshari menangkapnya, hantu itu bersumpah tidak akan kembali. Akhirnya Abu Ayyub melepasnya lalu ia menemui Nabi shallallahu 'alaihi wasallam, beliau bertanya: \"Apa yang dilakukan tawananmu?\" Abu Ayyub menjawab: \"Ia bersumpah tidak akan kembali.\" Beliau bersabda: \"Ia dusta, memang ia terbiasa berdusta.\" Abdurrahman berkata; Abu Ayyub lalu menangkap yang kedua kalinya, hantu itu pun bersumpah untuk tidak kembali lagi, lantas Abu Ayyub melepasnya. Setelah itu Abu Ayyub datang menemui Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Apa yang di lakukan tawananmu?\" Abu Ayyub menjawab; \"Dia bersumpah untuk tidak kembali.\" Beliau bersabda: \"Dia dusta, memang ia terbiasa berdusta.\" Setelah itu Abu Ayyub menangkapnya lagi, lalu berkata; \"Aku tidak akan melepaskanmu sampai aku membawamu ke Nabi shallallahu 'alaihi wasallam.\" Hantu itu berkata; \"Aku ingatkan padamu tentang sesuatu, yaitu ayat kursi, bacalah ayat kursi di rumahmu, niscaya setan tidak akan mendekatimu dan tidak juga yang lainnya.\" Abu Ayyub pun menemui Nabi shallallahu 'alaihi wasallam, beliau bertanya: \"Apa yang dilakukan tawananmu?\" Abdurrahman berkata; lalu Abu Ayyub memberitahukan apa yang diucapkan hantu itu, maka beliau bersabda: \"Ia benar walaupun sebenarnya ia pendusta.\" Abu Isa berkata; Hadits ini hasan gharib. Dalam hal ini, ada hadits serupa dari Ubay bin Ka'ab."},"2739":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ مَنْصُورِ بْنِ الْمُعْتَمِرِ عَنْ إِبْرَاهِيمَ بْنِ يَزِيدَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ الْآيَتَيْنِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Jarir bin Abdul Hamid] dari [Mandhur bin Al Mu'tamir] dari [Ibrahim bin Yazid] dari [Abdurrahman bin Yazid] dari [Abu Mas'ud Al Anshari] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca dua ayat terakhir dari surat Al Baqarah pada malam hari, maka keduanya akan mencukupinya.\" Abu Isa berkata; Hadits ini hasan shahih."},"2740":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَشْعَثَ بْنِ عَبْدِ الرَّحْمَنِ الْجَرْمِيِّ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ الْجَرْمِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ كَتَبَ كِتَابًا قَبْلَ أَنْ يَخْلُقَ السَّمَوَاتِ وَالْأَرْضَ بِأَلْفَيْ عَامٍ أَنْزَلَ مِنْهُ آيَتَيْنِ خَتَمَ بِهِمَا سُورَةَ الْبَقَرَةِ وَلَا يُقْرَأَانِ فِي دَارٍ ثَلَاثَ لَيَالٍ فَيَقْرَ��ُهَا شَيْطَانٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Asy'ats bin Abdurrahman Al Jarmi] dari [Abu Qilabah] dari [Abu Al Asy'ats Al Jarmi] dari [Nu'man bin Basyir] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya Allah telah menulis kitab (Al Qur`an) sejak dua ribu tahun sebelum menciptakan langit dan bumi, Allah menurunkan dua ayat darinya sebagai penutup surat Al Baqarah, tidaklah keduanya dibaca dalam rumah selama tiga malam setan akan mendekatinya.\" Abu Isa berkata; Hadits ini hasan gharib."},"2741":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ أَخْبَرَنَا هِشَامُ بْنُ إِسْمَعِيلَ أَبُو عَبْدِ الْمَلِكِ الْعَطَّارِ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سُلَيْمَانَ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ حَدَّثَهُمْ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ نَوَّاسِ بْنِ سَمْعَانَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَأْتِي الْقُرْآنُ وَأَهْلُهُ الَّذِينَ يَعْمَلُونَ بِهِ فِي الدُّنْيَا تَقْدُمُهُ سُورَةُ الْبَقَرَةِ وَآلُ عِمْرَانَ قَالَ نَوَّاسٌ وَضَرَبَ لَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ أَمْثَالٍ مَا نَسِيتُهُنَّ بَعْدُ قَالَ تَأْتِيَانِ كَأَنَّهُمَا غَيَابَتَانِ وَبَيْنَهُمَا شَرْقٌ أَوْ كَأَنَّهُمَا غَمَامَتَانِ سَوْدَاوَانِ أَوْ كَأَنَّهُمَا ظُلَّةٌ مِنْ طَيْرٍ صَوَافَّ تُجَادِلَانِ عَنْ صَاحِبِهِمَاوَفِي الْبَاب عَنْ بُرَيْدَةَ وَأَبِي أُمَامَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَمَعْنَى هَذَا الْحَدِيثِ عِنْدَ أَهْلِ الْعِلْمِ أَنَّهُ يَجِيءُ ثَوَابُ قِرَاءَتِهِ كَذَا فَسَّرَ بَعْضُ أَهْلِ الْعِلْمِ هَذَا الْحَدِيثَ وَمَا يُشْبِهُ هَذَا مِنْ الْأَحَادِيثِ أَنَّهُ يَجِيءُ ثَوَابُ قِرَاءَةِ الْقُرْآنِ وَفِي حَدِيثِ النَّوَّاسِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَدُلُّ عَلَى مَا فَسَّرُوا إِذْ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ الَّذِينَ يَعْمَلُونَ بِهِ فِي الدُّنْيَا فَفِي هَذَا دَلَالَةٌ أَنَّهُ يَجِيءُ ثَوَابُ الْعَمَلِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Hisyam bin Isma'il Abu Abdul Malik Al Athar] telah mengabarkan kepada kami [Muhammad bin Syu'aib] telah menceritakan kepada kami [Ibrahim bin Sulaiman] dari [Al Walid bin Abdurrahman] dari [Jubair bin Nufair] dari [Nawwas bin Sam'an] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Al Qur`an akan datang pada hari Qiyamat bersama pemiliknya yang mengamalkannya di dunia, didahului oleh surat Al Baqarah dan Ali Imran, \" Nawwas berkata; Rasulullah shallallahu 'alaihi wasallam membuat perumpamaan untuk keduanya (surat Al Baqarah dan Ali Imran) dengan tiga perumpamaan yang aku tidak akan melupakan selamanya, beliau bersabda: \"Keduanya akan datang seperti dua awan, yang di antara keduanya ada cahaya, atau keduanya seperti dua awan tebal, atau keduanya seperti sekawanan burung yang membentangkan sayapnya, lalu keduanya berhujah untuk pemiliknya.\" Dan dalam bab ini, ada hadits dari Buraidah dan Abu Umamah. Abu Isa berkata; Dari jalur ini, hadits ini gharib, adapun makna hadits ini menurut ahli ilmu adalah akan datang pahala membacanya seperti ini, sebagian ahli ilmu menafsirkan hadits ini dan yang hadits serupa bahwa pahala membaca Al Qur`an akan datang, dan dalam hadits An Nawwas dari Nabi shallallahu 'alaihi wasallam ada dalil yang menunjukkan atas apa yang mereka tafsirkan, dimana Nabi shallallahu 'alaihi wasallam bersabda: \"Dan para pemiliknya yang mengamalkannya di dunia.\" Hadits ini menunjukkan pahala amal akan datang."},"2742":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ فِي تَفْسِيرِ حَدِيثِ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَمَا خَلَقَ اللَّهُ مِنْ سَمَاءٍ وَلَا أَرْضٍ أَعْظَمَ مِنْ آيَةِ الْكُرْسِيِّ قَالَ سُفْيَانُ لِأَنَّ آيَةَ الْكُرْسِيِّ هُوَ كَلَامُ اللَّهِ وَكَلَامُ اللَّهِ أَعْظَمُ مِنْ خَلْقِ اللَّهِ مِنْ السَّمَاءِ وَالْأَرْضِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] ia berkata; telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan bin 'Uyainah] tentang penafsiran hadits Abdulah bin Mas'ud, ia berkata; \"Tidaklah Allah menciptakan langit dan bumi yang lebih agung melebihi ayat kursi.\" Sufyan berkata; \"Karena ayat kursi adalah kalam Allah dan kalam Allah lebih agung dari ciptaan Allah seperti langit dan bumi.\""},"2743":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَنْبَأَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَال سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ يَقُولُبَيْنَمَا رَجُلٌ يَقْرَأُ سُورَةَ الْكَهْفِ إِذْ رَأَى دَابَّتَهُ تَرْكُضُ فَنَظَرَ فَإِذَا مِثْلُ الْغَمَامَةِ أَوْ السَّحَابَةِ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ السَّكِينَةُ نَزَلَتْ مَعَ الْقُرْآنِ أَوْ نَزَلَتْ عَلَى الْقُرْآنِوَفِي الْبَاب عَنْ أُسَيْدِ بْنِ حُضَيْرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah memberitakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata; Aku mendengar [Al Bara` bin 'Azib] berkata; \"Ketika seseorang membaca surat Al Kahfi, tiba-tiba ia melihat binatang tunggangannya menghentakkan kedua kakinya, kemudian ia memandang (keatas), ternyata seperti awan atau mendung. Lalu ia menemui Rasulullah shallallahu 'alaihi wasallam dan menceritakan hal itu kepada beliau. Lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Itu adalah ketenangan yang turun bersama al-Qur`an atau turun atas al-Qur`an.\" Dalam hal ini, ada hadits serupa dari Usaid bin Hudlair. Abu Isa berkata; Hadits ini hasan shahih."},"2744":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ ثَلَاثَ آيَاتٍ مِنْ أَوَّلِ الْكَهْفِ عُصِمَ مِنْ فِتْنَةِ الدَّجَّالِحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ بِهَذَا الْإِسْنَادِ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Salim bin Abu Al Ja'd] dari [Ma'dan bin Abu Thalhah] dari [Abu Ad Darda`] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa membaca tiga ayat permulaan surat Al Kahfi, maka ia akan terjaga dari fitnah Dajjal.\" Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [Ayahku] dari [Qatadah] dengan sanad dan maksud yang sama. Abu Isa berkata; Hadits ini hasan shahih."},"2745":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَسُفْيَانُ بْنُ وَكِيعٍ قَالَا حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ الرُّؤَاسِيُّ عَنْ الْحَسَنِ بْنِ صَالِحٍ عَنْ هَارُونَ أَبِي مُحَمَّدٍ عَنْ مُقَاتِلِ بْنِ حَيَّانَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِكُلِّ شَيْءٍ قَلْبًا وَقَلْبُ الْقُرْآنِ يس وَمَنْ قَرَأَ يس كَتَبَ اللَّهُ لَهُ بِقِرَاءَتِهَا قِرَاءَةَ الْقُرْآنِ عَشْرَ مَرَّاتٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ وَبِالْبَصْرَةِ لَا يَعْرِفُونَ مِنْ حَدِيثِ قَتَادَةَ إِلَّا مِنْ هَذَا الْوَجْهِ وَهَارُونُ أَبُو مُحَمَّدٍ شَيْخٌ مَجْهُولٌ حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ حَدَّثَنَا قُتَيْبَةُ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بِهَذَا وَفِي الْبَاب عَنْ أَبِي بَكْرٍ الصِّدِّيقِ وَلَا يَصِحُّ مِنْ قِبَلِ إِسْنَادِهِ وَإِسْنَادُهُ ضَعِيفٌ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Qutaibah] dan [Sufyan bin Waki'] keduanya berkata; telah menceritakan kepada kami [Humaid bin Abdurrahman Ar Ru`asi] dari [Al Hasan bin Shalih] dari [Harun Abu Muhammad] dari [Muqatil bin Hayyan] dari [Qatadah] dari [Anas] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya setiap sesuatu memiliki hati, dan hatinya Al Qur`an adalah surat Yasin, barangsiapa membaca surat Yasin, maka Allah akan mencatat baginya seperti membaca seluruh Al Qur`an sepuluh kali atas balasan bacaannya.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari hadits Humaid bin Abdurrahman. Sedangkan di Bashrah, orang-orang tidak mengetahuinya dari hadits Qatadah kecuali dari jalur ini. Harun Abu Muhammad adalah seorang syaikh yang majhul (tidak diketahui). Telah menceritakan kepada kami [Abu Musa bin Muhammad Al Mutsanna] telah menceritakan kepada kami [Ahmad bin Sa'id Ad Darimi] telah menceritakan kepada kami [Qutaibah] dari [Humaid bin Abdurrahman] dengan hadits ini. Dan dalam bab ini, ada hadits dari Abu Bakar Ash Shiddiq, namun tidak sah dari sisi sanadnya, karena sanadnya lemah. Dan dalam bab ini, ada juga hadits dari Abu Hurairah."},"2746":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ عَنْ عُمَرَ بْنِ أَبِي خَثْعَمٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ حم الدُّخَانَ فِي لَيْلَةٍ أَصْبَحَ يَسْتَغْفِرُ لَهُ سَبْعُونَ أَلْفَ مَلَكٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَعُمَرُ بْنُ أَبِي خَثْعَمٍ يُضَعَّفُ قَالَ مُحَمَّدٌ وَهُوَ مُنْكَرُ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Sufyan bin Waqi'] telah menceritakan kepada kami [Zaid bin Hubab] dari [Umar bin Abu Khats'am] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca HAA MIIM (surat) Ad Dukhan pada malam hari, maka tujuh puluh ribu malaikat akan memohonkan ampunan untuknya di pagi harinya.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari jalur ini, sebab Umar bin Abu Khats'am dilemahkan, Muhammad berkata; \"Dia adalah munkarul hadits (Sering meriwayatkan hadits munkar).\""},"2747":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَبْدِ الرَّحْمَنِ الْكُوفِيُّ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ عَنْ هِشَامٍ أَبِي الْمِقْدَامِ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ حم الدُّخَانَ فِي لَيْلَةِ الْجُمُعَةِ غُفِرَ لَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَهِشَامٌ أَبُو الْمِقْدَامِ يُضَعَّفُ وَلَمْ يَسْمَعْ الْحَسَنُ مِنْ أَبِي هُرَيْرَةَ هَكَذَا قَالَ أَيُّوبُ وَيُونُسُ بْنُ عُبَيْدٍ وَعَلِيُّ بْنُ زَيْدٍ","id":"Telah menceritakan kepada kami [Nashr bin Abdurrahman Al Kufi] telah menceritakan kepada kami [Zaid bin Hubab] dari [Hisyam Abu Al Miqdam] dari [Al Hasan] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca HAA MIIM (surat) Ad Dukhan pada malam jum'at, maka (dosa-dosanya) akan diampuni.\" Abu Isa berkata; Hadits ini hanya kami ketahui dari jalur ini. Hisyam Abu Al Miqdam dilemahkan dan Al Hasan tidak pernah mendengar dari Abu Hurairah. Demikian yang dikatakan Ayyub, Yunus bin Ubaid dan Ali bin Zaid."},"2748":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا يَحْيَى بْنُ عَمْرِو بْنِ مَالِكٍ النُّكْرِيُّ عَنْ أَبِيهِ عَنْ أَبِي الْجَوْزَاءِ عَنْ ابْنِ عَبَّاسٍ قَالَضَرَبَ بَعْضُ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خِبَاءَهُ عَلَى قَبْرٍ وَهُوَ لَا يَحْسِبُ أَنَّهُ قَبْرٌ فَإِذَا فِ��هِ إِنْسَانٌ يَقْرَأُ سُورَةَ تَبَارَكَ الَّذِي بِيَدِهِ الْمُلْكُ حَتَّى خَتَمَهَا فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي ضَرَبْتُ خِبَائِي عَلَى قَبْرٍ وَأَنَا لَا أَحْسِبُ أَنَّهُ قَبْرٌ فَإِذَا فِيهِ إِنْسَانٌ يَقْرَأُ سُورَةَ تَبَارَكَ الْمُلْكِ حَتَّى خَتَمَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هِيَ الْمَانِعَةُ هِيَ الْمُنْجِيَةُ تُنْجِيهِ مِنْ عَذَابِ الْقَبْرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] telah menceritakan kepada kami [Yahya bin 'Amru bin Malik An Nukri] dari [Ayahnya] dari [Abul Jauza`] dari [Ibnu Abbas] ia berkata; \"Sebagian sahabat Nabi shallallahu 'alaihi wasallam membuat kemah di atas pemakaman, ternyata ia tidak mengira jika berada di pemakaman, tiba-tiba ada seseorang membaca surat TABAARAKAL LADZII BIYADIHIL MULKU (Maha Suci Allah yang di tangan-Nyalah segala kerajaan) \". sampai selesai, kemudian dia datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah sesungguhnya, aku membuat kemahku di atas kuburan dan saya tidak mengira jika tempat tersebut adalah kuburan, kemudian ada seseorang membaca surat TABARAK (surat) Al Mulk sampai selesai, \" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dia adalah penghalang, dia adalah penyelamat yang menyelamatkannya dari siksa kubur.\" Abu Isa berkata; Dari jalur ini, hadits ini hasan gharib. Dan dalam bab ini, ada hadits dari Abu Hurairah. "},"2749":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ عَبَّاسٍ الْجُشَمِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ سُورَةً مِنْ الْقُرْآنِ ثَلَاثُونَ آيَةً شَفَعَتْ لِرَجُلٍ حَتَّى غُفِرَ لَهُ وَهِيَ سُورَةُ تَبَارَكَ الَّذِي بِيَدِهِ الْمُلْكُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abbas Al Jusyami] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya ada satu surat dalam Al Qur`an yang terdiri dari tiga puluh ayat, dan dapat memberikan syafa'at kepada seseorang hingga dia diampuni, yaitu surat TABAARAKAL LADZII BIYADIHIL MULKU.\" Abu Isa berkata; Hadits ini hasan."},"2750":{"ar":"حَدَّثَنَا هُرَيْمُ بْنُ مِسْعَرٍ التِّرْمِذِيُّ حَدَّثَنَا الْفُضَيْلُ بْنُ عِيَاضٍ عَنْ لَيْثٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَنَامُ حَتَّى يَقْرَأَ الم تَنْزِيلُ وَتَبَارَكَ الَّذِي بِيَدِهِ الْمُلْكُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ رَوَاهُ غَيْرُ وَاحِدٍ عَنْ لَيْثِ بْنِ أَبِي سُلَيْمٍ مِثْلَ هَذَا وَرَوَاهُ مُغِيرَةُ بْنُ مُسْلِمٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا وَرَوَى زُهَيْرٌ قَالَ قُلْتُ لِأَبِي الزُّبَيْرِ سَمِعْتَ مِنْ جَابِرٍ فَذَكَرَ هَذَا الْحَدِيثَ فَقَالَ أَبُو الزُّبَيْرِ إِنَّمَا أَخْبَرَنِيهِ صَفْوَانُ أَوِ ابْنُ صَفْوَانَ وَكَأَنَّ زُهَيْرًا أَنْكَرَ أَنْ يَكُونَ هَذَا الْحَدِيثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ لَيْثٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ حَدَّثَنَا هُرَيْمُ بْنُ مِسْعَرٍ حَدَّثَنَا فُضَيْلٌ عَنْ لَيْثٍ عَنْ طَاوُسٍ قَالَ تَفْضُلَانِ عَلَى كُلِّ سُورَةٍ فِي الْقُرْآنِ بِسَبْعِينَ حَسَنَةً","id":"Telah menceritakan kepada kami [Huraim bin Mis'ar At Turmudzi] telah menceritakan kepada kami [Al Fadll bin Iyadl] dari [Laits] dari [Abu Az Zubair] dari [Jabir] bahwa; \"Tidaklah Nabi shallallahu 'alaihi wasallam tidur hingga beliau membaca ALIF LAAM MIIM TANZIL dan TABAARAKALLADZI BIYADILIL MULK.\" Abu Isa berkata; Hadits ini diriwayatkan oleh beberapa perawi dari Laits bin Abu Sulaim seperti ini, dan diriwayatkan pula oleh [Mughirah bin Muslim] dari [Abu Az Zubair] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam seperti ini. [Zuhair] meriwayatkan, katanya; \"Aku bertanya kepada Abu Zubair; \"Apakah kamu mendengar dari Jabir?\" Ia pun menyebut hadits ini. [Abu Az Zubair] mengatakan; Hanya [Shafwan atau Ibnu Shafwan] yang mengabarkannya kepadaku. Sepertinya Zuhair mengingkari hadits ini dari Abu Az Zubair dari Jabir. Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Al Ahwash] dari [Laits] dari [Abu Az Zubair] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas. Perawi berkata; telah menceritakan kepada kami Huraim bin Mis'ar telah menceritakan kepada kami Fudlail dari Laits dari Thawus ia berkata; \"Keduanya melebihi setiap surat dalam al-Qur`an dengan tujuhpuluh kebaikan.\""},"2751":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى الْحَرَشِيُّ الْبَصْرِيُّ حَدَّثَنَا الْحَسَنُ بْنُ سَلْمِ بْنِ صَالِحٍ الْعِجْلِيُّ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ إِذَا زُلْزِلَتْ عُدِلَتْ لَهُ بِنِصْفِ الْقُرْآنِ وَمَنْ قَرَأَ قُلْ يَا أَيُّهَا الْكَافِرُونَ عُدِلَتْ لَهُ بِرُبُعِ الْقُرْآنِ وَمَنْ قَرَأَ قُلْ هُوَ اللَّهُ أَحَدٌ عُدِلَتْ لَهُ بِثُلُثِ الْقُرْآنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ هَذَا الشَّيْخِ الْحَسَنِ بْنِ سَلْمٍ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Musa Al Harasyi Al Bashri] telah menceritakan kepada kami [Al Hasan bin Salm bin Shalih Al Ijli] telah menceritakan kepada kami [Tsabit Al Bunani] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca \"IDZA ZULZILAT\" maka akan digantikan baginya dengan separuh Al Qur`an, barangsiapa membaca \"QUL YAA AYYUHAL KAAFIRUUN\" maka akan di gantikan baginya dengan seperempat Al Qur`an dan barangsiapa membaca \"QUL HUWALLAAHU AHAD\" maka akan disamakan baginya dengan sepertiga Al Qur`an.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari hadits syaikh ini, yaitu Al Hasan bin Salm. Dan dalam bab ini, ada juga hadits dari Ibnu Abbas."},"2752":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَمَانُ بْنُ الْمُغِيرَةِ الْعَنَزِيُّ حَدَّثَنَا عَطَاءٌ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا زُلْزِلَتْ تَعْدِلُ نِصْفَ الْقُرْآنِ وَقُلْ هُوَ اللَّهُ أَحَدٌ تَعْدِلُ ثُلُثَ الْقُرْآنِ وَقُلْ يَا أَيُّهَا الْكَافِرُونَ تَعْدِلُ رُبُعَ الْقُرْآنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ يَمَانِ بْنِ الْمُغِيرَةِ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Yaman bin Al Mughirah Al Anazi] telah mengabarkan kepada kami [Atha`] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Surat) IDZA ZULZILAT sama seperti separuh Al Qur`an, QUL HUWALLAAHU AHAD sama seperti sepertiga Al Qur`an dan QUL YAA AYYUHAL KAAFIRUUN sama seperti seperempat Al Qur`an.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari hadits Yaman bin Al Mughirah."},"2753":{"ar":"حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ الْعَمِّيُّ الْبَصْرِيُّ حَدَّثَنِي ابْنُ أَبِي فُدَيْكٍ أَخْبَرَنَا سَلَمَةُ بْنُ وَرْدَانَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ��ِرَجُلٍ مِنْ أَصْحَابِهِ هَلْ تَزَوَّجْتَ يَا فُلَانُ قَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ وَلَا عِنْدِي مَا أَتَزَوَّجُ بِهِ قَالَ أَلَيْسَ مَعَكَ قُلْ هُوَ اللَّهُ أَحَدٌ قَالَ بَلَى قَالَ ثُلُثُ الْقُرْآنِ قَالَ أَلَيْسَ مَعَكَ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ قَالَ بَلَى قَالَ رُبُعُ الْقُرْآنِ قَالَ أَلَيْسَ مَعَكَ قُلْ يَا أَيُّهَا الْكَافِرُونَ قَالَ بَلَى قَالَ رُبُعُ الْقُرْآنِ قَالَ أَلَيْسَ مَعَكَ إِذَا زُلْزِلَتْ الْأَرْضُ قَالَ بَلَى قَالَ رُبُعُ الْقُرْآنِ قَالَ تَزَوَّجْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami ['Uqbah bin Mukram Al Ammi Al Bashri] telah menceritakan kepadaku [Ibnu Abu Fudaik] telah mengabarkan kepada kami [Salamah bin Wardan] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bertanya kepada salah seorang sahabat beliau: \"Apakah kamu sudah menikah hai fulan?\" ia menjawab; \"Belum, demi Allah wahai Rasulullah, aku tidak memiliki sesuatu untuk aku pakai menikah.\" Rasulullah bertanya: \"Bukankah kamu punya (hafalan) QUL HUWALLAHU AHAD?\" Ia menjawab; \"Betul.\" Beliau bersabda: \"Sepertiga al-Qur'an.\" Beliau bertanya: \"Bukankah kau punya (hafalan) IDZAA JAA`A NASHRULLAAHI WAL FATH?\" ia menjawab; \"Benar.\" Beliau bersabda: \"Seperempat al-Qur'an.\" Beliau bertanya: \"Bukankah kamu punya (hafalan) QUL YAA`AYYUHAL KAAFIRUUN?\" ia menjawab; \"Benar.\" Beliau bersabda: \"Seperempat al-Qur'an.\" Beliau bertanya: \"Bukankah kau punya (hafalan) IDZAA ZULZILATIL ARDLU?\" ia menjawab; \"Benar.\" Beliau bersabda: \"Seperempat al-Qur'an.\" Beliau bersabda: \"Menikahlah.\" Abu Isa berkata; Hadits ini hasan."},"2754":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا زَائِدَةُ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ رَبِيعِ بْنِ خُثَيْمٍ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ امْرَأَةِ أَبِي أَيُّوبَ عَنْ أَبِي أَيُّوبَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَعْجِزُ أَحَدُكُمْ أَنْ يَقْرَأَ فِي لَيْلَةٍ ثُلُثَ الْقُرْآنِ مَنْ قَرَأَ اللَّهُ الْوَاحِدُ الصَّمَدُ فَقَدْ قَرَأَ ثُلُثَ الْقُرْآنِوَفِي الْبَاب عَنْ أَبِي الدَّرْدَاءِ وَأَبِي سَعِيدٍ وَقَتَادَةَ بْنِ النُّعْمَانِ وَأَبِي هُرَيْرَةَ وَأَنَسٍ وَابْنِ عُمَرَ وَأَبِي مَسْعُودٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَلَا نَعْرِفُ أَحَدًا رَوَى هَذَا الْحَدِيثَ أَحْسَنَ مِنْ رِوَايَةِ زَائِدَةَ وَتَابَعَهُ عَلَى رِوَايَتِهِ إِسْرَائِيلُ وَالْفُضَيْلُ بْنُ عِيَاضٍ وَقَدْ رَوَى شُعْبَةُ وَغَيْرُ وَاحِدٍ مِنْ الثِّقَاتِ هَذَا الْحَدِيثَ عَنْ مَنْصُورٍ وَاضْطَرَبُوا فِيهِ","id":"Telah menceritakan kepada kami [Qutaibah] dan [Muhammad bin Basyar] keduanya berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Za'idah] dari [Manshur] dari [Hilal bin Yasaf] dari [Rabi' bin Khutsaim] dari ['Amru bin Maimun] dari [Abdurrahman bin Abu Laila] dari [istrinya Abu Ayyub] dari [Abu Ayyub] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah salah seorang dari kalian mampu membaca sepertiga Al Qur`an dalam waktu semalam, barangsiapa membaca ALAAHUL WAAHIDUSH SHAMAD (Surat Al Ikhlas) berarti dia membaca sepertiga Al Qur`an.\" Dan dalam bab ini, ada hadits dari Abu Darda`, Abu Sa'id, Qatadah bin Nu'man, Abu Hurairah, Anas, Ibnu Umar dan Abu Mas'ud. Abu Isa berkata; Hadits ini hasan, dan kami tidak mengetahui seorang pun meriwayatkan hadits ini yang lebih baik dari riwayatnya Za`idah, dan riwayatnya disempurnakan pula oleh [Isra`il] dan [Al Fudlail bin Iyadl]. Syu'bah dan yang lainnya juga telah meriwayatkan hadits ini dari orang-orang tsiqah dari Manshur, namun mereka sedikit bertentangan dalam hadits ini."},"2755":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا إِسْحَقُ بْنُ سُلَيْمَانَ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ ابْنِ حُنَيْنٍ مَوْلًى لِآلِ زَيْدِ بْنِ الْخَطَّابِ أَوْ مَوْلَى زَيْدِ بْنِ الْخَطَّابِ عَنْ أَبِي هُرَيْرَةَ قَالَأَقْبَلْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعَ رَجُلًا يَقْرَأُ قُلْ هُوَ اللَّهُ أَحَدٌ اللَّهُ الصَّمَدُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَبَتْ قُلْتُ وَمَا وَجَبَتْ قَالَ الْجَنَّةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ مَالِكِ بْنِ أَنَسٍ وَابْنُ حُنَيْنٍ هُوَ عُبَيْدُ بْنُ حُنَيْنٍ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Ishaq bin Sulaiman] dari [Malik bin Anas] dari ['Ubaidullah bin Abdurrahman] dari [Ibnu Hunain] bekas budak milik keluarga Zaid bin Al Khaththab atau budak Zaid bin Al Khaththab, dari [Abu Hurairah] ia berkata; \"Saya pulang dari perjalanan bersama Nabi shallallahu 'alaihi wasallam, lalu beliau mendengar seseorang membaca QUL HUWALLAAHU AHAD ALAAHUSH SHAMAD, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wajib.\" Aku bertanya; \"Wajib apa?\" Beliau menjawab: \"(mendapatkan) Surga.\" Abu Isa berkata; Hadits ini hasan gharib, kami hanya mengetahuinya dari hadits Malik bin Anas. Ibnu Hunain adalah 'Ubaid bin Hunain."},"2756":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَرْزُوقٍ الْبَصْرِيُّ حَدَّثَنَا حَاتِمُ بْنُ مَيْمُونٍ أَبُو سَهْلٍ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ كُلَّ يَوْمٍ مِائَتَيْ مَرَّةٍ قُلْ هُوَ اللَّهُ أَحَدٌ مُحِيَ عَنْهُ ذُنُوبُ خَمْسِينَ سَنَةً إِلَّا أَنْ يَكُونَ عَلَيْهِ دَيْنٌوَبِهَذَا الْإِسْنَادِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَرَادَ أَنْ يَنَامَ عَلَى فِرَاشِهِ فَنَامَ عَلَى يَمِينِهِ ثُمَّ قَرَأَ قُلْ هُوَ اللَّهُ أَحَدٌ مِائَةَ مَرَّةٍ فَإِذَا كَانَ يَوْمُ الْقِيَامَةِ يَقُولُ لَهُ الرَّبُّ تَبَارَكَ وَتَعَالَى يَا عَبْدِيَ ادْخُلْ عَلَى يَمِينِكَ الْجَنَّةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ ثَابِتٍ عَنْ أَنَسٍ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ هَذَا الْوَجْهِ أَيْضًا عَنْ ثَابِتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Marzuq Al Bashri] telah menceritakan kepada kami [Hatim bin Maymun Abu Sahl] dari [Tsabit Al Bunani] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa membaca QUL HUWALLAAHU AHAD setiap hari seratus kali, niscaya dosa-dosanya selama lima puluh tahun akan terhapus, kecuali jika dia mempunyai hutang, \" Dan dengan sanad ini pula, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa beranjak tidur ke tempat tidurnya, kemudian miring ke sebelah kanannya sambil membaca QUL HUWALLAAHU AHAD sebanyak seratus kali, maka pada hari kiyamat, Rabb Tabaraka wa Ta'ala akan berkata kepadanya: \"Wahai hamba-Ku, masuklah surga di sebelah kananmu.\" Abu Isa berkata; Hadits ini gharib dari hadits Tsabit dari Anas, Dan hadits ini telah diriwayatkan juga dari jalur yang lain dari Tsabit."},"2757":{"ar":"حَدَّثَنَا الْعَبَّاسُ الدُّورِيُّ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنَا سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ هُوَ اللَّهُ أَحَدٌ تَعْدِلُ ثُلُثَ الْقُرْآنِهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Abbas Ad Duri] telah menceritakan kepada kami [Khalid bin Mukhlad] telah menceritakan kepada kami [Sulaiman bin Bilal] telah menceritakan kepada kami [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"QUL HUWALLAAHU AHAD menyamai sepertiga al-Qur'an.\" Hadits ini hasan shahih."},"2758":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا يَزِيدُ بْنُ كَيْسَانَ حَدَّثَنَا أَبُو حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْشُدُوا فَإِنِّي سَأَقْرَأُ عَلَيْكُمْ ثُلُثَ الْقُرْآنِ قَالَ فَحَشَدَ مَنْ حَشَدَ ثُمَّ خَرَجَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَ قُلْ هُوَ اللَّهُ أَحَدٌ ثُمَّ دَخَلَ فَقَالَ بَعْضُنَا لِبَعْضٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنِّي سَأَقْرَأُ عَلَيْكُمْ ثُلُثَ الْقُرْآنِ إِنِّي لَأَرَى هَذَا خَبَرًا جَاءَ مِنْ السَّمَاءِ ثُمَّ خَرَجَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي قُلْتُ سَأَقْرَأُ عَلَيْكُمْ ثُلُثَ الْقُرْآنِ أَلَا وَإِنَّهَا تَعْدِلُ ثُلُثَ الْقُرْآنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَأَبُو حَازِمٍ الْأَشْجَعِيُّ اسْمُهُ سَلْمَانُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Yazid bin Kaisan] telah menceritakan kepada kami [Abu Hazim] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berkumpullah, aku akan membacakan sepertiga al-Qur'an pada kalian.\" Abu Hurairah mengatakan; \"Orang-orang pun berkumpul, lalu Nabiyullah keluar, lalu beliau membaca QUL HUWALLAAHU AHAD, setelah itu beliau masuk. Maka sebagaian orang berkata pada yang lain; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku akan membacakan seperti al-Qur'an pada kalian, \" dan menurutku, ini adalah kabar dari langit. Setelah itu Nabiyullah keluar sambil bersabda: \"Aku tadi bersabda bahwa aku akan membaca sepertiga al-Qur'an untuk kalian, ingat, sesungguhnya ia menyamai sepertiga al-Qur'an.\" Abu Isa berkata; Hadits ini hasan shahih gharib melalui jalur ini. Abu Hatim Al Asyja'i namanya adalah Salman."},"2759":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي أُوَيْسٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَجُلٌ مِنْ الْأَنْصَارِ يَؤُمُّهُمْ فِي مَسْجِدِ قُبَاءَ فَكَانَ كُلَّمَا افْتَتَحَ سُورَةً يَقْرَأُ لَهُمْ فِي الصَّلَاةِ فَقَرَأَ بِهَا افْتَتَحَ بِقُلْ هُوَ اللَّهُ أَحَدٌ حَتَّى يَفْرُغَ مِنْهَا ثُمَّ يَقْرَأُ بِسُورَةٍ أُخْرَى مَعَهَا وَكَانَ يَصْنَعُ ذَلِكَ فِي كُلِّ رَكْعَةٍ فَكَلَّمَهُ أَصْحَابُهُ فَقَالُوا إِنَّكَ تَقْرَأُ بِهَذِهِ السُّورَةِ ثُمَّ لَا تَرَى أَنَّهَا تُجْزِئُكَ حَتَّى تَقْرَأَ بِسُورَةٍ أُخْرَى فَإِمَّا أَنْ تَقْرَأَ بِهَا وَإِمَّا أَنْ تَدَعَهَا وَتَقْرَأَ بِسُورَةٍ أُخْرَى قَالَ مَا أَنَا بِتَارِكِهَا إِنْ أَحْبَبْتُمْ أَنْ أَؤُمَّكُمْ بِهَا فَعَلْتُ وَإِنْ كَرِهْتُمْ تَرَكْتُكُمْ وَكَانُوا يَرَوْنَهُ أَفْضَلَهُمْ وَكَرِهُوا أَنْ يَؤُمَّهُمْ غَيْرُهُ فَلَمَّا أَتَاهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرُوهُ الْخَبَرَ فَقَالَ يَا فُلَانُ مَا يَمْنَعُكَ مِمَّا يَأْمُرُ بِهِ أَصْحَابُكَ وَمَا يَحْمِلُكَ أَنْ تَقْرَأَ هَذِهِ السُّورَةَ فِي كُلِّ رَكْعَةٍ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أُحِبُّهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ حُبَّهَا أَدْخَلَكَ الْجَنَّةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ ثَابِتٍ وَرَوَى مُبَارَكُ بْنُ فَضَالَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ أَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ إِنِّي أُحِبُّ هَذِهِ السُّورَةَ قُلْ هُوَ اللَّهُ أَحَدٌ فَقَالَ إِنَّ حُبَّكَ إِيَّاهَا يُدْخِلُكَ الْجَنَّةَ حَدَّثَنَا بِذَلِكَ أَبُو دَاوُدَ سُلَيْمَانُ بْنُ الْأَشْعَثِ حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا مُبَارَكُ بْنُ فَضَالَةَ بِهَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Isma'il bin Abu Uwais] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Ubaidullah bin Umar] dari [Tsabit Al Bunanni] dari [Anas bin Malik] ia berkata; \"Seorang sahabat Anshar mengimami mereka di Masjid Quba`, setiap kali mengawali untuk membaca surat (setelah al fatihah -pent) dalam shalat, ia selalu memulainya dengan membaca QUL HUWALLAHU AHAD hingga selesai, lalu ia melanjutkan dengan surat yang lain, dan ia selalu melakukannya di setiap rakaat. Lantas para sahabatnya berbicara padanya, kata mereka; \"Kamu membaca surat itu lalu menurutmu itu tidak mencukupimu, hingga kamu melanjutkannya dengan surat yang lain, bacalah surat tersebut atau tinggalkan lalu bacalah surat yang lain!.\" Sahabat Anshar itu berkata; \"Aku tidak akan meninggalkannya, bila kalian ingin aku menjadi imam kalian dengan membacanya, maka aku akan melakukannya dan bila kalian tidak suka, aku akan meninggalkan kalian.\" Sementara mereka menilainya sebagai orang yang paling mulia di antara mereka, maka mereka tidak ingin diimami oleh orang lain. Saat Nabi shallallahu 'alaihi wasallam mendatangi mereka, mereka memberitahukan masalah itu, lalu beliau bersabda: \"Hai fulan, apa yang menghalangimu untuk melakukan yang diperintahkan teman-temanmu dan apa yang mendorongmu membaca surat itu disetiap rakaat?\" ia menjawab; \"Wahai Rasulullah, sesungguhnya aku menyukainya.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya mencintainya akan memasukkanmu ke dalam surga.\" Abu Isa berkata; Hadits ini hasan gharib, shahih dari jalur ini dari hadits 'Ubaidullah bin Umar dari Tsabit. [Mubarak bin Fadlalah] meriwayatkan dari [Tsabit] dari [Anas] bahwa seseorang berkata; \"Wahai Rasulullah, sesungguhnya aku menyukai surat ini, yaitu QUL HUWALLAAHU AHAD.\" Beliau bersabda: \"Sesungguhnya mencintainya akan memasukkanmu ke dalam surga.\" Telah menceritakan kepada kami [Abu Dawud Sulaiman bin Al Asy'ats] seperti itu, telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Mubarak bin Fadlalah] seperti ini."},"2760":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ أَخْبَرَنِي قَيْسُ بْنُ أَبِي حَازِمٍ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَدْ أَنْزَلَ اللَّهُ عَلَيَّ آيَاتٍ لَمْ يُرَ مِثْلُهُنَّ{ قُلْ أَعُوذُ بِرَبِّ النَّاسِ }إِلَى آخِرِ السُّورَةِ وَ{ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ }إِلَى آخِرِ السُّورَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Isma'il bin Abu Khalid] telah mengabarkan kepadaku [Qais bin Abu Hazim] dari ['Uqbah bin Amir Al Juhani] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Allah menurunkan beberapa ayat yang belum pernah ditemukan bandingannya, yaitu; QUL A'UUDZU BIRABBIN NAAS hingga akhir surat dan QUL A'UUDZU BIRABBIL FALAQ hingga akhir surat.\" Abu Isa berkata; Hadits ini hasan shahih."},"2761":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَلِيِّ بْنِ رَبَاحٍ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَقْرَأَ بِالْمُعَوِّذَتَيْنِ فِي دُبُرِ كُلِّ صَلَاةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Ali bin Rabah] dari ['Uqbah bin Amir] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kepadaku agar aku membaca AL MU'AWWIDZATAIN (surat Al Falaq dan An Naas) setiap selesai shalat.\" Abu Isa berkata; Hadits ini hasan gharib."},"2762":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ وَهِشَامٌ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي يَقْرَأُ الْقُرْآنَ وَهُوَ مَاهِرٌ بِهِ مَعَ السَّفَرَةِ الْكِرَامِ الْبَرَرَةِ وَالَّذِي يَقْرَؤُهُ قَالَ هِشَامٌ وَهُوَ شَدِيدٌ عَلَيْهِ قَالَ شُعْبَةُ وَهُوَ عَلَيْهِ شَاقٌّ فَلَهُ أَجْرَانِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah menceritakan kepada kami [Syu'bah] dan [Hisyam] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari ['Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang membaca al Qur'an dan ia mahir membacanya, maka ia akan bersama golongan orang-orang mulia lagi baik sedangkan orang yang membacanya -Hisyam berkata; dengan susah, sementara Syu'bah mengatakan; dengan berat- maka ia akan mendapat dua pahala.\" Abu Isa berkata; Hadits ini hasan shahih."},"2763":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا حَفْصُ بْنُ سُلَيْمَانَ عَنْ كَثِيرِ بْنِ زَاذَانَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ الْقُرْآنَ وَاسْتَظْهَرَهُ فَأَحَلَّ حَلَالَهُ وَحَرَّمَ حَرَامَهُ أَدْخَلَهُ اللَّهُ بِهِ الْجَنَّةَ وَشَفَّعَهُ فِي عَشْرَةٍ مِنْ أَهْلِ بَيْتِهِ كُلُّهُمْ قَدْ وَجَبَتْ لَهُ النَّارُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَلَيْسَ إِسْنَادُهُ بِصَحِيحٍ وَحَفْصُ بْنُ سُلَيْمَانَ يُضَعَّفُ فِي الْحَدِيثِ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Hafs bin Sulaiman] dari [Katsir bin Zadzan] dari ['Ashim bin Dlamrah] dari [Ali bin Abu Thalib] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca Al Qur`an kemudian dia menghafalnya dan menghalalkan apa yang dihalalkan Al Qur`an serta mengharamkan apa yang diharamkan Al Qur`an, niscaya dengannya Allah akan memasukkannya ke dalam surga dan dapat memberi syafa'at kepada sepuluh keluarganya yang wajib masuk neraka.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari jalur ini, padahal sanadnya tidak shahih, Hafs bin Sulaiman telah dilemahkan dalam masalah hadits."},"2764":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ الْجُعْفِيُّ قَال سَمِعْتُ حَمْزَةَ الزَّيَّاتَ عَنْ أَبِي الْمُخْتَارِ الطَّائِيِّ عَنْ ابْنِ أَخِي الْحَارِثِ الْأَعْوَرِ عَنْ الْحَارِثِ قَالَمَرَرْتُ فِي الْمَسْجِدِ فَإِذَا النَّاسُ يَخُوضُونَ فِي الْأَحَادِيثِ فَدَخَلْتُ عَلَى عَلِيٍّ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ أَلَا تَرَى أَنَّ النَّاسَ قَدْ خَاضُوا فِي الْأَحَادِيثِ قَالَ وَقَدْ فَعَلُوهَا قُلْتُ نَعَمْ قَالَ أَمَا إِنِّي قَدْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَلَا إِنَّهَا سَتَكُونُ فِتْنَةٌ فَقُلْتُ مَا الْمَخْرَجُ مِنْهَا يَا رَسُولَ اللَّهِ قَالَ كِتَابُ اللَّهِ فِيهِ نَبَأُ مَا كَانَ قَبْلَكُمْ وَخَبَرُ مَا بَعْدَكُمْ وَحُكْمُ مَا بَيْنَكُمْ وَهُوَ الْفَصْلُ لَيْسَ بِالْهَزْلِ مَنْ تَرَكَهُ مِنْ جَبَّارٍ قَصَمَهُ اللَّهُ وَمَنْ ابْتَغَى الْهُدَى فِي غَيْرِهِ أَضَلَّهُ اللَّهُ وَهُوَ حَبْلُ اللَّهِ الْمَتِينُ وَهُوَ الذِّكْرُ الْحَكِيمُ وَهُوَ الصِّرَاطُ الْمُسْتَقِيمُ هُوَ الَّذِي لَا تَزِيغُ بِهِ الْأَهْوَاءُ وَلَا تَلْتَبِسُ بِهِ الْأَلْسِنَةُ وَلَا يَشْبَعُ مِنْهُ الْعُلَمَاءُ وَلَا يَخْلَقُ عَلَى كَثْرَةِ الرَّدِّ وَلَا تَنْقَضِي عَجَائِبُهُ هُوَ الَّذِي لَمْ تَنْتَهِ الْجِنُّ إِذْ سَمِعَتْهُ حَتَّى قَالُوا{ إِنَّا سَمِعْنَا قُرْآنًا عَجَبًا يَهْدِي إِلَى الرُّشْدِ فَآمَنَّا بِهِ }مَنْ قَالَ بِهِ صَدَقَ وَمَنْ عَمِلَ بِهِ أُجِرَ وَمَنْ حَكَمَ بِهِ عَدَلَ وَمَنْ دَعَا إِلَيْهِ هَدَى إِلَى صِرَاطٍ مُسْتَقِيمٍ خُذْهَا إِلَيْكَ يَا أَعْوَرُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَإِسْنَادُهُ مَجْهُولٌ وَفِي الْحَارِثِ مَقَالٌ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Husain bin Ali Al Ju'fi] ia berkata; Aku mendengar [Hamzah Az Zayyat] dari [Abu Al Mukhtar Ath Tha`i] dari [Ibnu Akhi Al Harits Al A'war] dari [Al Harits] ia berkata; \"Aku pernah lewat masjid, sedangkan orang-orang tengah larut dalam pembicaraan yang bathil, lalu aku menemui [Ali], aku berkata; \"Wahai Amirul Mukminin, apa anda tidak melihat orang-orang tengah larut dalam pembicaraan yang bathil (dengan mengabaikan membaca Al Qur'an -pent)?, \" Ali bertanya; \"Apakah mereka telah melakukannya?\" Aku menjawab; \"Ya.\" Ali berkata; \"Ingatlah, aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ingatlah, sesungguhnya akan terjadi fitnah.\" Lalu aku bertanya; \"Bagaimana solusinya wahai Rasulullah?\" beliau menjawab: \"Kitab Allah, di dalamnya ada kisah tentang peristiwa sebelum kalian, dan setelah kalian, hukum perkara diantara kalian, ia adalah (firman) yang memisahkan (antara yang hak dan yang bathil), bukan senda gurau, barangsiapa meninggalkannya karena bersikap sombong, maka Allah akan membinasakannya, dan barangsiapa mencari petunjuk pada selainnya, maka Allah akan menyesatkannya, ia adalah tali Allah yang kokoh, ia adalah peringatan yang bijaksana, ia adalah jalan yang lurus, dengannya keinginan-keinginan tidak akan menyimpang dan dengannya lisan-lisan tidak akan samar, ulama tidak pernah puas darinya, tidak usang meski sering diulang-ulang dan keajaiban-keajaibannya tidak kunjung habis, ia juga yang menyebabkan jin-jin tidak berhenti mendengarnya hingga mereka berkata; \"Sesungguhnya kami telah mendengarkan Al Qur`an yang menakjubkan, (yang) memberi petunjuk kapada jalan yang benar, lalu kami beriman kepadanya.\" (Al-Jinn: 1-2), barangsiapa berkata dengannya, maka ia benar, barangsiapa mengamalkannya, maka ia diberi pahala, barangsiapa memutuskan perkara dengannya, maka ia adil dan barangsiapa menyeru kepadanya, maka ia diberi petunjuk menuju jalan yang lurus, ambillah ia untukmu, wahai A'war.\" Abu Isa berkata; Hadits ini gharib, kami hanya mengetahuinya dari jalur ini, sanadnya majhul (tidak diketahui) dan Al Harits diperbincangkan."},"2765":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَنْبَأَنَا شُعْبَةُ أَخْبَرَنِي عَلْقَمَةُ بْنُ مَرْثَدٍ قَال سَمِعْتُ سَعْدَ بْنَ عُبَيْدَةَ يُحَدِّثُ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عُثْمَانَ بْنِ عَفَّانَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُقَالَ أَبُو عَبْدِ الرَّحْمَنِ فَذَاكَ الَّذِي أَقْعَدَنِي مَقْعَدِي هَذَا وَعَلَّمَ الْقُرْآنَ فِي زَمَنِ عُثْمَانَ حَتَّى بَلَغَ الْحَجَّاجَ بْنَ يُوسُفَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah memberitakan kepada kami [Syu'bah] telah mengabarkan kepadaku ['Alqamah bin Martsad] ia berkata; Aku mendengar [Sa'd bin 'Ubaidah] bercerita dari [Abu Abdurrahman] dari [Utsman bin Affan] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik kalian adalah yang mempelajari al-Qur'an dan mengajarkannya.\" Abu Abdurrahman berkata; \"Itulah yang membuatku duduk ditempat dudukku ini.\" Abu Abdurrahman masih tetap mengajar al-Qur'an dimasa Utsman hingga masa Al Hajjaj bin Yusuf.\" Abu Isa berkata; Hadits ini hasan shahih."},"2766":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ حَدَّثَنَا سُفْيَانُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُكُمْ أَوْ أَفْضَلُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ هَكَذَا رَوَى عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَغَيْرُ وَاحِدٍ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عُثْمَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسُفْيَانُ لَا يَذْكُرُ فِيهِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ وَقَدْ رَوَى يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ هَذَا الْحَدِيثَ عَنْ سُفْيَانَ وَشُعْبَةَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عُثْمَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا بِذَلِكَ مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ وَشُعْبَةَ قَالَ مُحَمَّدُ بْنُ بَشَّارٍ وَهَكَذَا ذَكَرَهُ يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ وَشْعْبَةَ غَيْرَ مَرَّةٍ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عُثْمَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مُحَمَّدُ بْنُ بَشَّارٍ وَأَصْحَابُ سُفْيَانَ لَا يَذْكُرُونَ فِيهِ عَنْ سُفْيَانَ عَنْ سَعْدِ بْنِ عُبَيْدَةَ قَالَ مُحَمَّدُ بْنُ بَشَّارٍ وَهُوَ أَصَحُّ قَالَ أَبُو عِيسَى وَقَدْ زَادَ شُعْبَةُ فِي إِسْنَادِ هَذَا الْحَدِيثِ سَعْدَ بْنَ عُبَيْدَةَ وَكَأَنَّ حَدِيثَ سُفْيَانَ أَصَحُّ قَالَ عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ يَحْيَى بْنُ سَعِيدٍ مَا أَحَدٌ يَعْدِلُ عِنْدِي شُعْبَةَ وَإِذَا خَالَفَهُ سُفْيَانُ أَخَذْتُ بِقَوْلِ سُفْيَانَ قَالَ أَبُو عِيسَى سَمِعْت أَبَا عَمَّارٍ يَذْكُرُ عَنْ وَكِيعٍ قَالَ قَالَ شُعْبَةُ سُفْيَانُ أَحْفَظُ مِنِّي وَمَا حَدَّثَنِي سُفْيَانُ عَنْ أَحَدٍ بِشَيْءٍ فَسَأَلْتُهُ إِلَّا وَجَدْتُهُ كَمَا حَدَّثَنِي وَفِي الْبَاب عَنْ عَلِيٍّ وَسَعْدٍ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Bisyr bin As Suri] telah menceritakan kepada kami [Sufyan] dari ['Alqamah bin Martsad] dari [Abu Abdurrahman As Sulami] dari [Utsman bin Affan] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik kalian atau seutama-utama kalian adalah yang belajar al Qur'an dan mengajarkannya.\" Abu Isa berkata; Hadits ini hasan shahih. Seperti itulah [Abdurrahman bin Mahdi] dan lainnya meriwayatkan dari [Sufyan Ats Tsauri] dari ['Alqamah bin Martsad] dari [Abu Abdurrahman] dari [Utsman] dari Nabi shallallahu 'alaihi wasallam. Sufyan tidak menyebutkan; \"Dari Sa'd bin 'Ubaidah. [Yahya bin Sa'id Al Qaththan] meriwayatkan hadits ini dari [Sufyan] dan [Syu'bah] dari ['Alqamah bin Martsad] dari [Sa'd bin 'Ubaidah] dari [Abu Abdurrahman] dari [Utsman] dari Nabi shallallahu 'alaihi wasallam. Telah menceritakan kepada kami [Muhammad bin Basyar] seperti itu, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] dan [Syu'bah]. Muhammad bin Basyar berkata; Seperti itu yang disebutkan Yahya bin Sa'id dari Sufyan dan Syu'bah bukan hanya sekali, dari 'Alqmah bin Martsad dari Sa'ad bin 'Ubaidah dari Abu Abdurrahman dari Utsman dari Nabi shallallahu 'alaihi wasallam. Muhammad bin Basyar dan sahabat-sahabat Sufyan tidak menyebutkan; \"Dari Sufyan dari Sa'ad bin 'Ubaidah.\" Muhammad bin Basyar berkata; \"Itu lebih shahih.\" Abu Isa berkata; \"Syu'bah menambahkan Sa'ad bin Ubaidah dalam sanadnya hadits ini, sepertinya hadits Sufyan lebih shahih.\" Ali bin Abdullah berkata; Yahya bin Abu Sa'id berkata; Menurutku, tidak ada seorang pun yang menyamai Syu'bah, namun apabila Sufyan berbeda pandangan dengannya, aku mengambil perkataan Sufyan.\" Abu Isa berkata; Aku mendengar Abu 'Ammar meriwayatkan dari Waki', ia berkata; Syu'bah berkata; Sufyan lebih hafal dariku, dan hadits yang diceritakan padaku oleh Sufyan dari seseorang, lalu aku tanyakan padanya melainkan aku temukan seperti yang ia ceritakan kepadaku. Dalam hal ini ada hadits serupa dari Ali dan Sa'd."},"2767":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ النُّعْمَانِ بْنِ سَعْدٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مِنْ حَدِيثِ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] dari [Abdurrahman bin Ishaq] dari [An Nu'man bin Sa'd] dari [Ali bin Abu Thalib] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik kalian adalah yang mempelajari al-Qur'an dan mengajarkannya.\" Abu Isa berkata; Hadits ini tidak kami ketahui dari hadits Ali dari Nabi shallallahu 'alaihi wasallam kecuali dari hadits Abdurrahman bin Ishaq."},"2768":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا الضَّحَّاكُ بْنُ عُثْمَانَ عَنْ أَيُّوبَ بْنِ مُوسَى قَال سَمِعْتُ مُحَمَّدَ بْنَ كَعْبٍ الْقُرَظِيَّ قَال سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ حَرْفًا مِنْ كِتَابِ اللَّهِ فَلَهُ بِهِ حَسَنَةٌ وَالْحَسَنَةُ بِعَشْرِ أَمْثَالِهَا لَا أَقُولُ الم حَرْفٌ وَلَكِنْ أَلِفٌ حَرْفٌ وَلَامٌ حَرْفٌ وَمِيمٌ حَرْفٌوَيُرْوَى هَذَا الْحَدِيثُ مِنْ غَيْرِ هَذَا الْوَجْهِ عَنْ ابْنِ مَسْعُودٍ وَرَوَاهُ أَبُو الْأَحْوَصِ عَنْ ابْنِ مَسْعُودٍ رَفَعَهُ بَعْضُهُمْ وَوَقَفَهُ بَعْضُهُمْ عَنْ ابْنِ مَسْعُودٍ قَالَ أَب��و عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ سَمِعْت قُتَيْبَةَ يَقُولُ بَلَغَنِي أَنَّ مُحَمَّدَ بْنَ كَعْبٍ الْقُرَظِيَّ وُلِدَ فِي حَيَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمُحَمَّدُ بْنُ كَعْبٍ يُكْنَى أَبَا حَمْزَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu Bakar Al Hanafi] telah menceritakan kepada kami [Adl dlahhak bin Utsman] dari [Ayyub bin Musa] ia berkata; Aku mendengar [Muhammad bin Ka'ab Al Quradli] berkata; Aku mendengar [Abdullah bin Mas'ud] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca satu huruf dari Kitabullah (Al Qur`an), maka baginya satu pahala kebaikan dan satu pahala kebaikan akan dilipat gandakan menjadi sepuluh kali, aku tidak mengatakan ALIF LAAM MIIM itu satu huruf, akan tetapi ALIF satu huruf, LAAM satu huruf dan MIIM satu huruf.\" Selain jalur ini, hadits ini juga diriwayatkan dari beberapa jalur dari sahabat Ibnu Mas'ud. Abul Ahwas telah meriwayatkan hadits ini dari Ibnu Mas'ud, sebagian perawi merafa'kannya (menyambungkannya sampai kepada Nabi) dan sebaian yang lainnya mewaqafkannya dari sahabat Ibnu Mas'ud. Abu Isa berkata; Hadits ini hasan shahih gharib dari jalur ini, aku telah mendengar Qutaibah berkata; telah sampai berita kepadaku bahwa Muhammad bin Ka'ab Al Quradli dilahirkan pada masa Nabi shallallahu 'alaihi wasallam masih hidup, dan Muhammad bin Ka'ab di juluki dengan Abu Hamzah."},"2769":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا بَكْرُ بْنُ خُنَيْسٍ عَنْ لَيْثِ بْنِ أَبِي سُلَيْمٍ عَنْ زَيْدِ بْنِ أَرْطَاةَ عَنْ أَبِي أُمَامَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَذِنَ اللَّهُ لِعَبْدٍ فِي شَيْءٍ أَفْضَلَ مِنْ رَكْعَتَيْنِ يُصَلِّيهِمَا وَإِنَّ الْبِرَّ لَيُذَرُّ عَلَى رَأْسِ الْعَبْدِ مَا دَامَ فِي صَلَاتِهِ وَمَا تَقَرَّبَ الْعِبَادُ إِلَى اللَّهِ بِمِثْلِ مَا خَرَجَ مِنْهُ قَالَ أَبُو النَّضْرِ يَعْنِي الْقُرْآنَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَبَكْرُ بْنُ خُنَيْسٍ قَدْ تَكَلَّمَ فِيهِ ابْنُ الْمُبَارَكِ وَتَرَكَهُ فِي آخِرِ أَمْرِهِ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ زَيْدِ بْنِ أَرْطَاةَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلٌ حَدَّثَنَا بِذَلِكَ إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مُعَاوِيَةَ عَنْ الْعَلَاءِ بْنِ الْحَارِثِ عَنْ زَيْدِ بْنِ أَرْطَاةَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُمْ لَنْ تَرْجِعُوا إِلَى اللَّهِ بِأَفْضَلَ مِمَّا خَرَجَ مِنْهُ يَعْنِي الْقُرْآنَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Abu An Nadlr] telah menceritakan kepada kami [Bakr bin Khunais] dari [Laits bin Abu Sulaim] dari [Zaid bin Arthah] dari [Abu Umamah] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Allah tidak mengizinkan seorang hamba pun dalam suatu hal yang lebih baik dari shalat dua rakaat yang ia lakukan, sesungguhnya kebaikan itu dibiarkan di atas kepala hamba selama ia berada dalam shalatnya dan tidaklah seorang hamba mendekatkan diri kepada Allah dapat menyamai sesuatu yang keluar darinya (dari Al Qur'an).\" Abu An Nadl berkata; Maksud beliau adalah al Qur'an. Abu Isa berkata; Hadits ini gharib, kami hanya mengetahuinya dari jalur ini. Bakr bin Khunais diperbincangkan oleh Ibnu Al Mubarak dan meninggalkannya di akhir hayatnya. Hadits ini juga diriwayatkan dari Zaid bin Arthah dari Jubair bin Nufair dari Nabi shallallahu 'alaihi wasallam secara mursal. Telah menceritakan kepada kami [Ishaq bin Manshur] seperti itu, telah menceritakan kepada kami [Abdurahman bin Mahdi] dari [Mu'awiyah] dari [Al Ala` bin Al Harits] dari [Zaid bin Arthah] dari [Jubair bin Nufair] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kalian tidak akan kembali kepada Allah dengan membawa seuatu yang lebih baik dari apa yang keluar darinya.\" maksud beliau al-Qur'an."},"2770":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا جَرِيرٌ عَنْ قَابُوسَ بْنِ أَبِي ظَبْيَانَ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الَّذِي لَيْسَ فِي جَوْفِهِ شَيْءٌ مِنْ الْقُرْآنِ كَالْبَيْتِ الْخَرِبِقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Jarir] dari [Qabus bin Abu Dlabyan] dari [Ayahnya] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang di dalam dirinya tidak ada sedikit pun al-Qur'an ibarat rumah yang runtuh.\" Abu Isa berkata; Hadits ini hasan shahih."},"2771":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ وَأَبُو نُعَيْمٍ عَنْ سُفْيَانَ عَنْ عَاصِمِ بْنِ أَبِي النَّجُودِ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُقَالُ لِصَاحِبِ الْقُرْآنِ اقْرَأْ وَارْتَقِ وَرَتِّلْ كَمَا كُنْتَ تُرَتِّلُ فِي الدُّنْيَا فَإِنَّ مَنْزِلَتَكَ عِنْدَ آخِرِ آيَةٍ تَقْرَأُ بِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ عَاصِمٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Daud Al Hafari] dan [Abu Nu'aim] dari [Sufyan] dari ['Ashim bin Abu Najud] dari [Zirr] dari [Abdullah bin 'Amru] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Kelak akan dikatakan kepada ahli Al Qur`an; Bacalah dan naiklah, kemudian bacalah dengan tartil sebagaimana kamu membacanya ketika di dunia, karena sesungguhnya tempatmu ada pada akhir ayat yang kamu baca.\" Abu Isa berkata; Hadits ini hasan shahih. Telah menceritakan kepada kami [Bundar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari ['Ashim] dengan sanad dan maksud yang sama."},"2772":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ أَخْبَرَنَا شُعْبَةُ عَنْ عَاصِمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَجِيءُ الْقُرْآنُ يَوْمَ الْقِيَامَةِ فَيَقُولُ يَا رَبِّ حَلِّهِ فَيُلْبَسُ تَاجَ الْكَرَامَةِ ثُمَّ يَقُولُ يَا رَبِّ زِدْهُ فَيُلْبَسُ حُلَّةَ الْكَرَامَةِ ثُمَّ يَقُولُ يَا رَبِّ ارْضَ عَنْهُ فَيَرْضَى عَنْهُ فَيُقَالُ لَهُ اقْرَأْ وَارْقَ وَتُزَادُ بِكُلِّ آيَةٍ حَسَنَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ نَحْوَهُ وَلَمْ يَرْفَعْهُ قَالَ أَبُو عِيسَى وَهَذَا أَصَحُّ مِنْ حَدِيثِ عَبْدِ الصَّمَدِ عَنْ شُعْبَةَ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [Abdushshamad bin Abdul Warits] telah mengabarkan kepada kami [Syu'bah] dari ['Ashim] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Pada hari kiyamat, Al Qur`an akan datang kemudian berkata; \"Wahai Rabb berilah dia pakaian, \" maka dipakaikanlah kepadanya mahkota kemuliaan, kemudian Al Qur`an berkata lagi; \"Wahai Rabb, tambahkanlah kepadanya, \" maka dipakaikan kepadanya pakaian kemuliaan, kemudian berkata lagi; \"Wahai Rabb ridlailah dia, \" akhirnya dia pun diridlai, kemudian dikatakan kepada ahli Al Qur`an; \"Bacalah dan naiklah, niscaya akan ditambahkan kepadamu satu pahala kebaikan pada setiap ayat.\" Abu Isa berkata; Hadits ini hasan shahih. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari ['Ashim bin Bahdalah] dari [Abu Shalih] dari [Abu Hurairah] dengan hadits yang semakna, namun dia tidak merafa'kannya. Abu Isa berkata; Hadits ini lebih shahih dari hadits Abdusshamad dari Syu'bah."},"2773":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ الْحَكَمِ الْوَرَّاقُ الْبَغْدَادِيُّ حَدَّثَنَا عَبْدُ الْمَجِيدِ بْنُ عَبْدِ الْعَزِيزِ عَنْ ابْنِ جُرَيْجٍ عَنْ الْمُطَّلِبِ بْن حَنْطَبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُرِضَتْ عَلَيَّ أُجُورُ أُمَّتِي حَتَّى الْقَذَاةُ يُخْرِجُهَا الرَّجُلُ مِنْ الْمَسْجِدِ وَعُرِضَتْ عَلَيَّ ذُنُوبُ أُمَّتِي فَلَمْ أَرَ ذَنْبًا أَعْظَمَ مِنْ سُورَةٍ مِنْ الْقُرْآنِ أَوْ آيَةٍ أُوتِيهَا رَجُلٌ ثُمَّ نَسِيَهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ قَالَ وَذَاكَرْتُ بِهِ مُحَمَّدَ بْنَ إِسْمَعِيلَ فَلَمْ يَعْرِفْهُ وَاسْتَغْرَبَهُ قَالَ مُحَمَّدٌ وَلَا أَعْرِفُ لِلْمُطَّلِبِ بْنِ عَبْدِ اللَّهِ سَمَاعًا مِنْ أَحَدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا قَوْلَهُ حَدَّثَنِي مَنْ شَهِدَ خُطْبَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ و سَمِعْت عَبْدَ اللَّهِ بْنَ عَبْدِ الرَّحْمَنِ يَقُولُ لَا نَعْرِفُ لِلْمُطَّلِبِ سَمَاعًا مِنْ أَحَدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَبْدُ اللَّهِ وَأَنْكَرَ عَلِيُّ بْنُ الْمَدِينِيِّ أَنْ يَكُونَ الْمُطَّلِبِ سَمِعَ مِنْ أَنَسٍ","id":"Telah menceritakan kepada kami [Abdul Wahab bin Al Hakam Al Warrak Al Baghdadi] telah menceritakan kepada kami [Abdul Majid bin Abdul Aziz] dari [Ibnu Juraij] dari [Al Muthallib bin Hanthab] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pahala-pahala ummatku ditampakkan kepadaku, hingga pahala seseorang yang membuang debu dari masjid, dan ditampakkan kepadaku dosa-dosa ummatku, maka tidak aku lihat dosa yang lebih besar dari satu surat atau satu ayat yang diberikan kepada seseorang kemudian dia melupakannya.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari jalur ini. Perawi berkata; Aku menyebutkan hadits ini kepada Muhammad bin Isma'il, namun dia tidak mengetahuinya bahkan menganggap hadits ini gharib (sendirian), Muhammad berkata; Aku tidak mengetahui kalau Al Muthallib bin Abdullah pernah mendengar dari salah seorang sahabat Nabi shallallahu 'alaihi wasallam, selain perkataannya, telah menceritakan kepadaku orang yang menyaksikan khutbah Nabi shallallahu 'alaihi wasallam.\" Perawi juga berkata; Aku mendengar Abdullah bin Abdurrahman berkata; \"Kami tidak mengetahui kalau Abdul Muthallib pernah mendengar dari salah seorang sahabat Nabi shallallahu 'alaihi wasallam.\" Abdullah berkata; Ali bin Al Madini mengingkari Al Muthallib bila dia pernah mendengar dari Anas."},"2774":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ الْوَاسِطِيُّ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبُو فَرْوَةَ يَزِيدُ بْنُ سِنَانٍ عَنْ أَبِي الْمُبَارَكِ عَنْ صُهَيْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا آمَنَ بِالْقُرْآنِ مَنْ اسْتَحَلَّ مَحَارِمَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَيْسَ إِسْنَادُهُ بِالْقَوِيِّ وَقَدْ خُولِفَ وَكِيعٌ فِي رِوَايَتِهِ و قَالَ مُحَمَّدٌ أَبُو فَرْوَةَ يَزِيدُ بْنُ سِنَانٍ الرُّهَاوِيُّ لَيْسَ بِحَدِيثِهِ بَأْسٌ إِلَّا رِوَايَةَ ابْنِهِ مُحَمَّدٍ عَنْهُ فَإِنَّهُ يَرْوِي عَنْهُ مَنَاكِيرَ قَالَ أَبُو عِيسَى وَقَدْ رَوَى مُحَمَّدُ بْنُ يَزِيدَ بْنِ سِنَانٍ عَنْ أَبِيهِ هَذَا الْحَدِيثَ فَزَادَ فِي هَذَا الْإِسْنَادِ عَنْ مُجَاهِدٍ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ صُهَيْبٍ وَلَا يُتَابَعُ مُحَمَّدُ بْنُ يَزِيدَ عَلَى رِوَايَتِهِ وَهُوَ ضَعِيفٌ وَأَبُو الْمُبَارَكِ رَجُلٌ مَجْهُولٌ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il Al Washiti] telah menceritakan kepada kami [Waqi'] telah menceritakan kepada kami [Abu Farwah Yazid bin Sinan] dari [Abu Al Mubarak] dari [Shuhaib] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak beriman kepada Al Qur`an orang yang menghalalkan apa yang diharamkan Al Qur`an.\" Abu Isa berkata; Hadits ini sanadnya tidak kuat, karena riwayat Waqi' tidak seperti itu. Muhammad berkata; Abu Farwah Yazid bin Sinan Ar Rahawi haditsnya tidak apa-apa kecuali yang diriwayatkan anaknya, Muhammad, karena anaknya telah meriwayatkan hadits-hadits munkar darinya. Abu Isa berkata; [Muhammad bin Yazid bin Sinan] telah meriwayatkan hadits ini dari [Ayahnya] kemudian dia menambahkan dalam sanadnya: Dari [Mujahid] dari [Sa'id bin Al Musayyib] dari [Shuhaib], padahal tidak ada yang menguatkan riwayat Muhammad bin Yazid, karena dia perawi yang lemah, sedangkan Abu Al Mubarak adalah seorang lelaki yang tidak diketahui."},"2775":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ كَثِيرِ بْنِ مُرَّةَ الْحَضْرَمِيِّ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْجَاهِرُ بِالْقُرْآنِ كَالْجَاهِرِ بِالصَّدَقَةِ وَالْمُسِرُّ بِالْقُرْآنِ كَالْمُسِرِّ بِالصَّدَقَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَمَعْنَى هَذَا الْحَدِيثِ أَنَّ الَّذِي يُسِرُّ بِقِرَاءَةِ الْقُرْآنِ أَفْضَلُ مِنْ الَّذِي يَجْهَرُ بِقِرَاءَةِ الْقُرْآنِ لِأَنَّ صَدَقَةَ السِّرِّ أَفْضَلُ عِنْدَ أَهْلِ الْعِلْمِ مِنْ صَدَقَةِ الْعَلَانِيَةِ وَإِنَّمَا مَعْنَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ لِكَيْ يَأْمَنَ الرَّجُلُ مِنْ الْعُجْبِ لِأَنَّ الَّذِي يُسِرُّ الْعَمَلَ لَا يُخَافُ عَلَيْهِ الْعُجْبُ مَا يُخَافُ عَلَيْهِ مِنْ عَلَانِيَتِهِ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Arafah] telah menceritakan kepada kami [Isma'il bin Ayyasy] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Katsir bin Murrah Al Hadlrami] dari ['Uqbah bin Amir] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seseorang yang membaca al-Qur'an dengan suara keras seperti orang yang menampak-nampakkan sedekah, sedangkan orang yang membaca al-Qur'an dengan suara lirih, seperti orang yang bersedekah dengan sembunyi-sembunyi.\" Abu Isa berkata; Hadits ini hasan gharib. Makna hadits ini adalah; \"Orang yang membaca al-Qur'an dengan suara lirih lebih baik dari yang membaca dengan suara keras, karena sedekah sembunyi-sembunyi itu lebih baik dari sedekah dengan terang-terangan menurut para ulama. Sedangkan menurut ulama mengenai makna hadits ini adalah agar seseorang terhindar dari sifat ujub, karena orang yang melakukan amalan dengan sembunyi-sembunyi itu tidak dikhawatirkan ujub seperti bila dilakukan secara terang-terangan.\""},"2776":{"ar":"حَدَّثَنَا عَليُّ بْنُ حُجْرٍ أَخْبَرَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بِلَالٍ عَنْ عِرْبَاضِ بْنِ سَارِيَةَ أَنَّهُ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ الْمُسَبِّحَاتِ قَبْلَ أَنْ يَرْقُدَ وَيَقُولُ إِنَّ فِيهِنَّ آيَةً خَيْرٌ مِنْ أَلْفِ آيَةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah menceritakan kepada kami [Baqiyyah bin Al Walid] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Abdullah bin Abu Bilal] dari [Irbadl bin Sariyah] ia menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam membaca surat-surat Al Musabbihaat sebelum tidur, kemudian beliau bersabda: \"Sesungguhnya pada surat-surat tersebut terdapat ayat yang lebih baik dari seribu ayat.\" Abu Isa berkata; Hadits ini hasan gharib. "},"2777":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا خَالِدُ بْنُ طَهْمَانَ أَبُو الْعَلَاءِ الْخَفَّافُ حَدَّثَنِي نَافِعُ بْنُ أَبِي نَافِعٍ عَنْ مَعْقِلِ بْنِ يَسَارٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ حِينَ يُصْبِحُ ثَلَاثَ مَرَّاتٍ أَعُوذُ بِاللَّهِ السَّمِيعِ الْعَلِيمِ مِنْ الشَّيْطَانِ الرَّجِيمِ وَقَرَأَ ثَلَاثَ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَكَّلَ اللَّهُ بِهِ سَبْعِينَ أَلْفَ مَلَكٍ يُصَلُّونَ عَلَيْهِ حَتَّى يُمْسِيَ وَإِنْ مَاتَ فِي ذَلِكَ الْيَوْمِ مَاتَ شَهِيدًا وَمَنْ قَالَهَا حِينَ يُمْسِي كَانَ بِتِلْكَ الْمَنْزِلَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Ahmad Az Zubairi] telah menceritakan kepada kami [Khalid bin Thaman Abu Al Ala` Al Khaffaf] telah menceritakan kepadaku [Nafi' bin Abu Nafi'] dari [Ma'qil bin Yasar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa membaca tiga kali di pagi hari, A'UUDZU BILLAAHI MINASY SYAITHAANIR RAJIIM kemudian membaca tiga ayat terakhir surat Al Hasyr, maka dengannya Allah akan menugaskan tujuhpuluh ribu malikat untuk mendoakannya hingga sore hari dan bila ia meninggal pada hari itu, ia mati dalam keadaan syahid dan barangsiapa mengucapkannya di sore hati, kedudukannya sama seperti itu.\" Abu Isa berkata; Hadits ini gharib, kami hanya mengetahuinya melalui sanad ini."},"2778":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ يَعْلَى بْنِ مَمْلَكٍ أَنَّهُسَأَلَ أُمَّ سَلَمَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قِرَاءَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَلَاتِهِ فَقَالَتْمَا لَكُمْ وَصَلَاتَهُ كَانَ يُصَلِّي ثُمَّ يَنَامُ قَدْرَ مَا صَلَّى ثُمَّ يُصَلِّي قَدْرَ مَا نَامَ ثُمَّ يَنَامُ قَدْرَ مَا صَلَّى حَتَّى يُصْبِحَ ثُمَّ نَعَتَتْ قِرَاءَتَهُ فَإِذَا هِيَ تَنْعَتُ قِرَاءَةً مُفَسَّرَةً حَرْفًا حَرْفًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ لَيْثِ بْنِ سَعْدٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ يَعْلَى بْنِ مَمْلَكٍ عَنْ أُمِّ سَلَمَةَ وَقَدْ رَوَى ابْنُ جُرَيْجٍ هَذَا الْحَدِيثَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ أُمِّ سَلَمَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُقَطِّعُ قِرَاءَتَهُ وَحَدِيثُ لَيْثٍ أَصَحُّ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Abdullah bin 'Ubaidullah bin Abu Malikah] dari [Ya'la bin Mamlak] bahwa ia pernah bertanya kepada [Ummu Salamah istri Nabi] shallallahu 'alaihi wasallam, tentang bacaan dan shalatnya Nabi shallallahu 'alaihi wasallam, Ummu Salamah menjawab; \"Apa urusan kalian dengan shalat beliau?, beliau shalat lalu tidur seukuran lamanya beliau shalat, setelah itu beliau shalat seukuran lamanya beliau tidur, kemudian beliau tidur seukuran lamanya beliau shalat hingga shubuh.\" Lalu Ummu Salamah menyebut bacaan beliau, ternyata ia menyebut bacaan yang dijelaskan satu huruf demi satu huruf.\" Abu Isa berkata; Hadits ini hasan shahih gharib, kami hanya mengetahuinya dari hadits Laits bin Sa'ad dari Ibnu Abu Mulaikah dari Ya'la bin Mamlak dari Ummu Salamah. [Ibnu Juraij] meriwayatkan hadits ini dari [Ibnu Abu Malikah] dari [Ummu Salamah] bahwa Nabi shallallahu 'alaihi wasallam memotong-motong bacaan beliau, sedangkan hadits Laits lebih shahih."},"2779":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ مُعَاوِيةَ بْنِ صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَيْسٍ هُوَ رَجُلٌ بَصْرِيٌّ قَالَ سَأَلْتُ عَائِشَةَعَنْ وِتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ كَانَ يُوتِرُ مِنْ أَوَّلِ اللَّيْلِ أَوْ مِنْ آخِرِهِ فَقَالَتْ كُلُّ ذَلِكَ قَدْ كَانَ يَصْنَعُ رُبَّمَا أَوْتَرَ مِنْ أَوَّلِ اللَّيْلِ وَرُبَّمَا أَوْتَرَ مِنْ آخِرِهِ فَقُلْتُ الْحَمْدُ لِلَّهِ الَّذِي جَعَلَ فِي الْأَمْرِ سَعَةً فَقُلْتُ كَيْفَ كَانَتْ قِرَاءَتُهُ أَكَانَ يُسِرُّ بِالْقِرَاءَةِ أَمْ يَجْهَرُ قَالَتْ كُلُّ ذَلِكَ قَدْ كَانَ يَفْعَلُ قَدْ كَانَ رُبَّمَا أَسَرَّ وَرُبَّمَا جَهَرَ قَالَ فَقُلْتُ الْحَمْدُ لِلَّهِ الَّذِي جَعَلَ فِي الْأَمْرِ سَعَةً قُلْتُ فَكَيْفَ كَانَ يَصْنَعُ فِي الْجَنَابَةِ أَكَانَ يَغْتَسِلُ قَبْلَ أَنْ يَنَامَ أَوْ يَنَامُ قَبْلَ أَنْ يَغْتَسِلَ قَالَتْ كُلُّ ذَلِكَ قَدْ كَانَ يَفْعَلُ فَرُبَّمَا اغْتَسَلَ فَنَامَ وَرُبَّمَا تَوَضَّأَ فَنَامَ قُلْتُ الْحَمْدُ لِلَّهِ الَّذِي جَعَلَ فِي الْأَمْرِ سَعَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Muawiyah bin Shalih] dari [Abdullah bin Abu Qais] seorang penduduk Bashrah, ia berkata; Aku bertanya kepada ['Aisyah] tentang shalat witir Rasulullah shallallahu 'alaihi wasallam; \"Bagaimana beliau shalat witir, apakah di permulaan malam atau di akhirnya?\" 'Aisyah menjawab; \"Semua itu pernah beliau lakukan, kadang beliau shalat witir di awal malam dan kadang shalat witir di akhirnya.\" Aku berkata; \"Segala puji bagi Allah yang memberikan keleluasaan dalam masalah ini, lalu aku bertanya; \"Bagaimana bacaan beliau? Apakah beliau membaca lirih atau dengan suara keras?\" 'Aisyah menjawab; \"Semua itu juga pernah beliau lakukan, kadang beliau membaca lirih dan kadang dengan suara keras.\" Aku berkata; \"Segala puji bagi Allah yang memberikan keleluasaan dalam masalah ini.\" Aku bertanya lagi; \"Bagaimana yang beliau lakukan ketika jinabat? Apakah beliau mandi sebelum tidur atau tidur sebelum mandi?\" 'Aisyah menjawab; \"Semua itu juga pernah beliau lakukan, kadang beliau mandi lalu tidur dan kadang wudlu lalu tidur.\" Aku menjawab; \"Segala puji bagi Allah yang memberikan keleluasaan dalam masalah ini.\" Abu Isa berkata; Melalui jalur ini, hadits ini hasan gharib."},"2780":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا عُثْمَانُ بْنُ الْمُغِيرَةِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابِرٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْرِضُ نَفْسَهُ بِالْمَوْقِفِ فَقَالَ أَلَا رَجُلٌ يَحْمِلْنِي إِلَى قَوْمِهِ فَإِنَّ قُرَيْشًا قَدْ مَنَعُونِي أَنْ أُبَلِّغَ كَلَامَ رَبِّيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] ia berkata; telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Israil] telah menceritakan kepada kami [Utsman bin Al Mughirah] dari [Salim bin Abu Al Ja'd] dari [Jabir] ia berkata; Nabi shallallahu 'alaihi wasallam menempatkan diri beliau di Mauqif, lalu bersabda: \"Adakah seseorang yang hendak membawaku ke kaumnya?, karena Quraisy melarangku menyampaikan firman Rabbku.\" Abu Isa berkata; Hadits ini gharib shahih."},"2781":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا شِهَابُ بْنُ عَبَّادٍ الْعَبْدِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ الْحَسَنِ بْنِ أَبِي يَزِيدَ الْهَمْدَانِيُّ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الرَّبُّ عَزَّ وَجَلَّ مَنْ شَغَلَهُ الْقُرْآنُ وَذِكْرِي عَنْ مَسْأَلَتِي أَعْطَيْتُهُ أَفْضَلَ مَا أُعْطِي السَّائِلِينَ وَفَضْلُ كَلَامِ اللَّهِ عَلَى سَائِرِ الْكَلَامِ كَفَضْلِ اللَّهِ عَلَى خَلْقِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Syihab bin 'Abbad Al 'Abdi] telah menceritakan kepada kami [Muhammad bin Al Hasan bin Abu Yazid Al Hamdani] dari ['Amru bin Qais] dari ['Athiyyah] dari [Abu Sa'id] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rabb Azza wa Jalla berfirman; \"Barangsiapa disibukkan oleh Al Qur`an dan berdzikir kepadaku untuk memohon kepadaKu, maka Aku akan memberikan kepadanya sesuatu yang terbaik dari yang Aku berikan kepada orang-orang yang memohon, \" dan kelebihan kalamullah (Al Qur`an) dari seluruh kalam adalah seperti kelebihan Allah dari seluruh makhlukNya.\" Abu Isa berkata; Hadits ini hasan gharib."},"2782":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ الْأُمَوِيُّ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَطِّعُ قِرَاءَتَهُ يَقُولُ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }ثُمَّ يَقِفُ{ الرَّحْمَنِ الرَّحِيمِ }ثُمَّ يَقِفُ وَكَانَ يَقْرَؤُهَا{ مَلِكِ يَوْمِ الدِّينِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَبِهِ يَقْرَأُ أَبُو عُبَيْدٍ وَيَخْتَارُهُ وَهَكَذَا رَوَى يَحْيَى بْنُ سَعِيدٍ الْأُمَوِيُّ وَغَيْرُهُ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ أُمِّ سَلَمَةَ وَلَيْسَ إِسْنَادُهُ بِمُتَّصِلٍ لِأَنَّ اللَّيْثَ بْنَ سَعْدٍ رَوَى هَذَا الْحَدِيثَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ يَعْلَى بْنِ مَمْلَكٍ عَنْ أُمِّ سَلمَةَ أَنَّهَا وَصَفَتْ قِرَاءَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرْفًا حَرْفًا وَحَدِيثُ اللَّيْثِ أَصَحُّ وَلَيْسَ فِي حَدِيثِ اللَّيْثِ وَكَانَ يَقْرَأُ{ مَلِكِ يَوْمِ الدِّينِ }","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah menceritakan kepada kami [Yahya bin Sa'id Al 'Umawi] dari [Ibnu Juraij] dari [Ibnu Abu Mulaikah] dari [Ummu Salamah] ia berkata; Rasulullah shallallahu 'alaihi wasallam biasa memotong bacaan beliau, beliau membaca; AL HAMDULILLAAHI RABBIL 'AALAMIIN, kemudian beliau berhenti, ARRAHMAANIRRaHIIM, kemudian beliau berhenti, lalu beliau membaca MAALIKI YAUMIDDIIN.\" Abu Isa berkata; Hadits ini gharib. Bacaan ini kemudian yang dibaca oleh Abu 'Ubaidah dan dipilihnya. Demikianlah Yahya bin Sa'id Al Umawi dan yang lainnya meriwayatkan dari Ibnu Juraij dari Ibnu Abu Mulaikah dari Ummu Salamah, namun sanadya tidak bersambung, karena [Al Laits bin Sa'd] meriwayatkan hadits ini dari [Ibnu Abu Mulaikah] dari [Ya'la bin Mamlak] dari [Ummu Salamah] bahwa Ummu Salamah menyebut bacaan Nabi shallallahu 'alaihi wasallam kalimat per kalimat, hadits Al Laits lebih shahih, namun dalam hadits Al Laits tidak disebutkan: \"Beliau membaca MALIKI YAUMID DIIN.\""},"2783":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ مُحَمَّدُ بْنُ أَبَانَ حَدَّثَنَا أَيُّوبُ بْنُ سُوَيْدٍ الرَّمْلِيُّ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ وَأُرَاهُ قَالَ وَعُثْمَانَ كَانُوا يَقْرَءُونَ{ مَالِكِ يَوْمِ الدِّينِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ إِلَّا مِنْ حَدِيثِ هَذَا الشَّيْخِ أَيُّوبَ بْنِ سُوَيْدٍ الرَّمْلِيِّ وَقَدْ رَوَى بَعْضُ أَصْحَابِ الزُّهْرِيِّ هَذَا الْحَدِيثَ عَنْ الزُّهْرِيِّ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ كَانُوا يَقْرَءُونَ{ مَالِكِ يَوْمِ الدِّينِ }وَرَوَى عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ كَانُوا يَقْرَءُونَ{ مَالِكِ يَوْمِ الدِّينِ }","id":"Telah menceritakan kepada kami [Abu Bakar Muhammad bin Abban] telah menceritakan kepada kami [Ayyub bin Suwaid Ar Ramli] dari [Yunus bin Yazid] dari [Az Zuhri] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam, Abu Bakar dan Umar -aku mengiranya mengatakan- Dan Utsman, mereka membaca; \"MAALIKI YAUMID DIIN.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya dari hadits Az Zuhri dari Anas bin Malik kecuali hadits dari syaikh ini, yaitu Ayyub bin Suwaid Ar Ramli, sebagian sahabat Az Zuhri telah meriwayatkan hadits ini dari Az Zuhri bahwa Nabi shallallahu 'alaihi wasallam, Abu Bakar dan Umar membaca; \"MAALIKI YAUMID DIIN.\" [Abdurrazzaq] telah meriwayatkan dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] bahwa Nabi shallallahu 'alaihi wasallam, Abu Bakar dan Umar membaca: \"MAALIKI YAUMID DIIN.\""},"2784":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ أَبِي عَلِيِّ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ أَنَّ النَّفْسَ بِالنَّفْسِ وَالْعَيْنُ بِالْعَيْنِ }حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ يُونُسَ بْنِ يَزِيدَ بِهَذَا الْإِسْنَادِ نَحْوَهُ قَالَ أَبُو عِيسَى وَأَبُو عَلِيِّ بْنُ يَزِيدَ هُوَ أَخُو يُونُسَ بْنِ يَزِيدَ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ قَالَ مُحَمَّدٌ تَفَرَّدَ ابْنُ الْمُبَارَكِ بِهَذَا الْحَدِيثِ عَنْ يُونُسَ بْنِ يَزِيدَ وَهَكَذَا قَرَأَ أَبُو عُبَيْدٍ{ وَالْعَيْنُ بِالْعَيْنِ }اتِّبَاعًا لِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Yunus bin Yazid] dari [Abu Ali bin Yazid] dari [Az Zuhri] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam membaca: \"ANNAN NAFSA BIN NAFSI WAL 'AINU BIL 'AINI (mata dengan mata).\" Al Maa`idah; 45. Telah menceritakan kepada kami [Suwaid bin Nashr] telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Yunus bin Yazid] dengan sanad dan maksud yang sama. Abu Isa berkata; Abu Ali bin Yazid adalah saudara Yunus bin Yazid, dan hadits ini hasan gharib. Muhammad berkata; Ibnu Al Mubarak sendirian dalam meriwayatkan hadits ini dari Yunus bin Yazid. Dan demikianlah Abu 'Ubaid membaca: \"WAL 'AINU BIL 'AINI\" mengikuti hadits ini."},"2785":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ زِيَادِ بْنِ أَنْعُمَ عَنْ عُتْبَةَ بْنِ حُمَيْدٍ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ عَنْ مُعَاذِ بْنِ جَبَلٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ هَلْ تَسْتَطِيعُ رَبَّكَ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ رِشْدِينَ وَلَيْسَ إِسْنَادُهُ بِالْقَوِيِّ وَرِشْدِينُ بْنُ سَعْدٍ وَالْأَفْرِيقِيُّ يُضَعَّفَانِ فِي الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Risydin bin Sa'ad] dari [Abdurrahman bin Ziyad bin An'um] dari ['Utbah bin Humaid] dari ['Ubadah bin Nusay] dari [Abdurrahman bin Ghunm] dari [Mu'adz bin Jabal] bahwa Nabi shallallahu 'alaihi wasallam membaca; \"HAL TASTATHII'U RABBAKA (sanggupkah Tuhanmu) Al Ma`idah: 112. Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari hadits Risydin, sedangkan sanadnya tidak kuat, karena Risydin bin Sa'd dan Al Afriqi keduanya dilemahkan dalam masalah hadits."},"2786":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ مُحَمَّدٍ الْبَصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ حَفْصٍ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَؤُهَا{ إِنَّهُ عَمِلَ غَيْرَ صَالِحٍ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ قَدْ رَوَاهُ غَيْرُ وَاحِدٍ عَنْ ثَابِتٍ الْبُنَانِيِّ نَحْوَ هَذَا وَهُوَ حَدِيثُ ثَابِتٍ الْبُنَانِيِّ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ أَيْضًا عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَ و سَمِعْت عَبْدَ بْنَ حُمَيْدٍ يَقُولُ أَسْمَاءُ بِنْتُ يَزِيدَ هِيَ أُمُّ سَلَمَةَ الْأَنْصَارِيَّةُ قَالَ أَبُو عِيسَى كِلَا الْحَدِيثَيْنِ عِنْدِي وَاحِدٌ وَقَدْ رَوَى شَهْرُ بْنُ حَوْشَبٍ غَيْرَ حَدِيثٍ عَنْ أُمِّ سَلَمَةَ الْأَنْصَارِيَّةِ وَهِيَ أَسْمَاءُ بِنْتُ يَزِيدَ وَقَدْ رُوِيَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوُ هَذَا","id":"Telah menceritakan kepada kami [Al Husain bin Muhammad Al Bashri] telah menceritakan kepada kami [Abdullah bin Hafs] telah menceritakan kepada kami [Tsabit Al Bunani] dari [Syahr bin Hausyab] dari [Ummu Salamah] bahwa Nabi shallallahu 'alaihi wasallam membaca: \"INNAHU AMILA GHAIRU SHAALIH (Sesungguhnya (perbuatan) nya, perbuatan yang tidak baik) QS Huud: 46. Abu Isa berkata; Hadits ini telah diriwayatkan banyak orang dari Tsabit Al Bunani dengan matan yang seperti ini, yaitu hadits Tsabit Al Bunani, hadits ini diriwayatkan juga dari Syahr bin Hausyab dari Asma` binti Yazid. Perawi berkata; Aku mendengar 'Abdu bin Humaid berkata; Asma' binti Yazid adalah Ummu Salamah Al Anshariyah. Abu Isa berkata; Kedua hadits itu menurutku sama, Syahr bin Hausyab telah meriwayatkan hadits selain hadits dari Ummu Salamah Al Anshariyah, yaitu Asma' binti Yazid, dan telah diriwayatkan dari 'Aisyah dari Nabi shallallahu 'alaihi wasallam hadits yang serupa."},"2787":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا وَكِيعٌ وَحَبَّانُ بْنُ هِلَالٍ قَالَا حَدَّثَنَا هَارُونُ النَّحْوِيُّ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أُمِّ سَلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ هَذِهِ الْآيَةَ{ إِنَّهُ عَمِلَ غَيْرَ صَالِحٍ }","id":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Waki'] dan [Habban bin Hilal] keduanya berkata; telah menceritakan kepada kami [Harun An Nahwi] dari [Tsabit Al Bunani] dari [Syahr bin Hausyab] dari [Ummu Salamah] bahwa Rasulullah shallallahu 'alaihi wasallam membaca ayat ini: \"INNAHU AMILA GHAIRU SHAALIH (Sesungguhnya (perbuatan) nya, perbuatan yang tidak baik).\" QS Huud: 46."},"2788":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ نَافِعٍ الْبَصْرِيُّ حَدَّثَنَا أُمَيَّةُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو الْجَارِيَةِ الْعَبْدِيُّ عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَرَأَ{ قَدْ بَلَغْتَ مِنْ لَدُنِّي عُذْرًا }مُثَقَّلَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَأُمَيَّةُ بْنُ خَالِدٍ ثِقَةٌ وَأَبُو الْجَارِيَةِ الْعَبْدِيُّ شَيْخٌ مَجْهُولٌ وَلَا نَعْرِفُ اسْمَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Nafi' Al Bashri] telah menceritakan kepada kami ['Umaiyah bin Khalid] telah menceritakan kepada kami [Abu Al Jariyah Al 'Abdi] dari [Syu'bah] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubay bin Ka'ab] dari Nabi shallallahu 'alaihi wasallam, beliau membaca: \"QAD BALAGHTA MIL LADUNNI 'UDZRAA (Sesungguhnya kamu sudah cukup memberikan uzur padaku) QS Al Kahfi: 76 dengan mutsaqqal.\" Abu Isa berkata; Hadits ini gharib, kami hanya mengetahuinya dari jalur ini. 'Umaiyah bin Khalid tsiqah, Abu Al Jariyah Al 'Abdi seorang syaikh majhul, kami tidak mengetahui namanya."},"2789":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا مُعَلَّى بْنُ مَنْصُورٍ حَدَّثَنَا مُحَمَّدُ بْنُ دِينَارٍ عَنْ سَعْدِ بْنِ أَوْسٍ عَنْ مِصْدَعٍ أَبِي يَحْيَى عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ فِي عَيْنٍ حَمِئَةٍ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَالصَّحِيحُ مَا رُوِيَ عَنْ ابْنِ عَبَّاسٍ قِرَاءَتُهُ وَيُرْوَى أَنَّ ابْنَ عَبَّاسٍ وَعَمْرَو بْنَ الْعَاصِ اخْتَلَفَا فِي قِرَاءَةِ هَذِهِ الْآيَةِ وَارْتَفَعَا إِلَى كَعْبِ الْأَحْبَارِ فِي ذَلِكَ فَلَوْ كَانَتْ عِنْدَهُ رِوَايَةٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَاسْتَغْنَى بِرِوَايَتِهِ وَلَمْ يَحْتَجْ إِلَى كَعْبٍ","id":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Mu'alla bin Manshur] telah menceritakan kepada kami [Muhammad bin Dinar] dari [Sa'ad bin Aus] dari [Mishda' Abu Yahya] dari [Ibnu Abbas] dari [Ubay bin Ka'ab] bahwa Nabi shallallahu 'alaihi wasallam membaca: \"FII 'AININ HAMI'ATIN (di dalam laut yang berlumpur hitam).\" QS Al Kahfi: 86. Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari jalur ini, dan yang shahih adalah hadits yang diriwayatkan dari Ibnu Abbas tentang bacaannya (Ibnu Abbas), dan diriwayatkan bahwa Ibnu Abbas dan 'Amru bin Al 'Ash berbeda pendapat tentang bacaan ayat ini, kemudian mereka mengajukannya kepada Ka'b Al Ahbar, seandainya Ibnu Abbas memiliki riwayat dari Nabi shallallahu 'alaihi wasallam, tentu sudah cukup baginya dengan riwayatnya dan tidak butuh lagi kepada Ka'b.\""},"2790":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ سُلَيْمَانَ الْأَعْمَشِ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَلَمَّا كَانَ يَوْمُ بَدْرٍ ظَهَرَتْ الرُّومُ عَلَى فَارِسَ فَأَعْجَبَ ذَلِكَ الْمُؤْمِنِينَ فَنَزَلَتْ{ الم غُلِبَتْ الرُّومُ إِلَى قَوْلِهِ يَفْرَحُ الْمُؤْمِنُونَ }قَالَ فَفَرِحَ الْمُؤْمِنُونَ بِظُهُورِ الرُّومِ عَلَى فَارِسَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَيُقْرَأُ غَلَبَتْ وَ{ غُلِبَتْ }يَقُولُ كَانَتْ غُلِبَتْ ثُمَّ غَلَبَتْ هَكَذَا قَرَأَ نَصْرُ بْنُ عَلِيٍّ غَلَبَتْ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [Ayahnya] dari [Sulaiman Al A'masy] dari ['Athiyyah] dari [Abu Sa'id] ia berkata; \"Saat terjadi perang Badar, pasukan Romawi menang atas Persia, hal itu mengejutkan kaum mukminin hingga turunlah ayat: \"ALIF LAAM MIIM, GHULIBATIR RUUM sampai ayat YAFRAHUL MUKMINUUNA.\" QS Ar-Ruum: 1-4. Abu Sa'id berkata; \"Bergembiralah orang orang mukmin dengan kemenangan bangsa Romawi atas bangsa Persia.\" Abu Isa berkata; Dari jalur ini, hadits ini hasan gharib. Ayat ini dibaca juga: \"GHALABAT dan GHULIBAT.\" Abu Isa berkata; \"Dahulu ayat ini dibaca GHULIBAT kemudian GHALABAT.\" Demikianlah Nashr bin Ali membaca; \"GHALABAT.\""},"2791":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ الرَّازِيُّ حَدَّثَنَا نُعَيْمُ بْنُ مَيْسَرَةَ النَّحْوِيُّ عَنْ فُضَيْلِ بْنِ مَرْزُوقٍ عَنْ عَطِيَّةَ الْعَوْفِيِّ عَنْ ابْنِ عُمَرَأَنَّهُ قَرَأَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ خَلَقَكُمْ مِنْ ضَعْفٍ }فَقَالَ{ مِنْ ضُعْفٍ }حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ فُضَيْلِ بْنِ مَرْزُوقٍ عَنْ عَطِيَّةَ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ فُضَيْلِ بْنِ مَرْزُوقٍ","id":"Telah menceritakan kepada kami [Muhammad bin Humaid Ar Razi] telah menceritakan kepada kami [Nu'aim bin Maisarah An Nahwi] dari [Fudlail bin Marzuq] dari ['Athiyyah Al Aufi] dari [Ibnu Umar] dia membaca di hadapan Nabi shallallahu 'alaihi wasallam; \"KHALAQAKUM MIN DLA'FIN (yang menciptakan kamu dari keadaan lemah) QS Ar Ruum; 54. kemudian beliau membaca: \"MIN DLU'FIN.\" Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Yazid bin Harun] dari [Fudlail bin Marzuq] dari ['Athiyyah] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan maksud yang sama. Abu Isa berkata; Hadits ini hasan gharib, kami tidak mengetahuinya kecuali dari hadits Fudlail bin Marzuq."},"2792":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ{ فَهَلْ مِنْ مُدَّكِرٍ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Ahmad Az Zubairi] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Al Aswad bin Yazid] dari [Abdullah bin Mas'ud], bahwa Rasulullah shallallahu 'alaihi wasallam membaca: \"FAHAL MIM MUDDAKIR (Maka adakah orang yang mau mengambil pelajaran?).\" QS Al-Qamar: 15. Abu Isa berkata; Hadits ini hasan shahih."},"2793":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ الضُّبَعِيُّ عَنْ هَارُونَ الْأَعْوَرِ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ{ فَرُوحٌ وَرَيْحَانٌ وَجَنَّةُ نَعِيمٍ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ هَارُونَ الْأَعْوَرِ","id":"Telah menceritakan kepada kami [Bisyr bin Hilal Ash Shawwaf] telah menceritakan kepada kami [Ja'far bin Sulaiman Adl Dluba'i] dari [Harun Al A'war] dari [Budail bin Maisarah] dari [Abdullah bin Syaqiq] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam membaca: \"FARUUHUN WA RAYHAANUW WAJANNATU NA'IIM (Maka dia memperoleh ketenteraman dan rezki serta jannah kenikmatan).\" Al Waaqi'ah: 89. Abu Isa berkata; Hadist ini hasan gharib, kami tidak mengetahuinya kecuali dari hadits Harun Al A'war."},"2794":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَ قَدِمْنَا الشَّامَ فَأَتَانَا أَبُو الدَّرْدَاءِ فَقَالَأَفِيكُمْ أَحَدٌ يَقْرَأُ عَلَيَّ قِرَاءَةَ عَبْدِ اللَّهِ قَالَ فَأَشَارُوا إِلَيَّ فَقُلْتُ نَعَمْ قَالَ كَيْفَ سَمِعْتَ عَبْدَ اللَّهِ يَقْرَأُ هَذِهِ الْآيَةَ{ وَاللَّيْلِ إِذَا يَغْشَى }قَالَ قُلْتُ سَمِعْتُهُ يَقْرَؤُهَا{ وَاللَّيْلِ إِذَا يَغْشَى }وَالذَّكَرِ وَالْأُنْثَى فَقَال أَبُو الدَّرْدَاءِ وَأَنَا وَاللَّهِ هَكَذَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَؤُهَا وَهَؤُلَاءِ يُرِيدُونَنِي أَنْ أَقْرَأَهَا{ وَمَا خَلَقَ }فَلَا أُتَابِعُهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا قِرَاءَةُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ{ وَاللَّيْلِ إِذَا يَغْشَى وَالنَّهَارِ إِذَا تَجَلَّى }وَالذَّكَرِ وَالْأُنْثَى","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Muawiyah] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] ia berkata; \"Kami tiba di Syam, lalu kami mendatangi Abu Ad Darda`, ia bertanya; \"Apakah di antara kalian ada yang mau membacakan untukku bacaan Abdullah?.\" 'Alqamah berkata; \"Kemudian orang-orang menunjukku, aku lantas mejawab; \"Baiklah.\" Abu Ad Darda` bertanya; \"Bagaimana kamu mendengarkan [Abdullah] membaca ayat ini; \"WAL LAILI IDZA YAGHSYAA?\" 'Alqamah berkata; Aku menjawab; \"Aku mendengarnya meambacanya; \"WAL LAILI IDZA YAGHSYAA, WADZ DZAKARA WAL UNTSAA (Demi malam apabila menutupi (cahaya siang), dan demi penciptaan laki-laki dan perempuan).\" QS Al Lail; 1, 3. [Abu Ad Darda`] berkata; Demi Allah, aku mendengar Rasulullah shallallahu 'alaihi wasallam membacanya seperti itu, namun orang-orang menginginkanku untuk membacanya; \"WA MAA KHALAQA, \" akan tetapi aku tidak menuruti mereka.\" Abu Isa berkata; Hadits ini hasan shahih. Demikian juga bacaan Abdullah bin Mas'ud; \"WAL LAILI IDZAA YAGHSYAA WAN NAHAARI IDZAA TAJALLAA WAD DZAKARA WAL UNTSAA.\" Demi malam apabila menutupi (cahaya siang), Dan siang apabila terang benderang, Dan penciptaan laki-laki dan perempuan).\" QS Al Lail; 1-3."},"2795":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَأَقْرَأَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أَنَا الرَّزَّاقُ ذُو الْقُوَّةِ الْمَتِينُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Isra`il] dari [Abu Ishaq] dari [Abdurrahman bin Yazid] dari [Abdullah bin Mas'ud] ia berkata; Rasulullah shallallahu 'alaihi wasallam membacakan kepadaku: \"INNII ANAR RAZZAAQU DZUL QUWWATIL MATIIN (Sesungguhnya Aku-lah Maha pemberi rezki yang mempunyai kekuatan lagi sangat kokoh).\" QS Adz Dzaariyat: 58. Abu Isa berkata; Hadits ini hasan shahih."},"2796":{"ar":"حَدَّثَنَا أَبُو زُرْعَةَ وَالْفَضْلُ بْنُ أَبِي طَالِبٍ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا الْحَسَنُ بْنُ بِشْرٍ عَنْ الْحَكَمِ بْنِ عَبْدِ الْمَلِكِ عَنْ قَتَادَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ وَتَرَى النَّاسَ سُكَارَى وَمَا هُمْ بِسُكَارَى }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَلَا نَعْرِفُ لِقَتَادَةَ سَمَاعًا مِنْ أَحَدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مِنْ أَنَسٍ وَأَبِي الطُّفَيْلِ وَهَذَا عِنْدِي مُخْتَصَرٌ إِنَّمَا يُرْوَى عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَقَرَأَ{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ }الْحَدِيثَ بِطُولِهِ وَحَدِيثُ الْحَكَمِ بْنِ عَبْدِ الْمَلِكِ عِنْدِي مُخْتَصَرٌ مِنْ هَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abu Zur'ah] dan [Al Fadhal bin Abu Thalib] dan yang lainnya, mereka berkata; telah menceritakan kepada kami [Al Hasan bin Bisyr] dari [Al Hakam bin Abdul Malik] dari [Qatadah] dari ['Imran bin Hushain] bahwa Nabi shallallahu 'alaihi wasallam membaca: \"WATARAN NAASA SUKAARAA WA MAA HUM BI SUKAARAA (kamu lihat manusia dalam keadaan mabuk, padahal Sebenarnya mereka tidak mabuk).\" QS Al-Hajj: 2. Abu Isa berkata; Hadits ini hasan, kami tidak mengetahui Qatadah pernah mendengar dari salah seorang sahabat Nabi shallallahu 'alaihi wasallam kecuali dari Anas dan Abu Thufail, dan hadits ini menurut saya hanya ringkasan, hadits ini hanya diriwayatkan dari [Qatadah] dari [Al Hasan] dari [Imran bin Hushain], dia berkata; Kami bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, kemudian beliau membaca: \"YAA AYYUHAN NAASUT TAQUU RABBAKUM (Wahai sekalian manusia, takutlah kalian kepada Rabb kalian).\" QS Al Hajj: 1 dengan redaksi yang panjang, sementara hadits Al Hakam bin Abdul Malik menurutku ringkasan dari hadits ini."},"2797":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَنْبَأَنَا شُعْبَةُ عَنْ مَنْصُورٍ قَال سَمِعْتُ أَبَا وَائِلٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بِئْسَمَا لِأَحَدِهِمْ أَوْ لِأَحَدِكُمْ أَنْ يَقُولَ نَسِيتُ آيَةَ كَيْتَ وَكَيْتَ بَلْ هُوَ نُسِّيَ فَاسْتَذْكِرُوا الْقُرْآنَ فَوَالَّذِي نَفْسِي بِيَدِهِ لَهُوَ أَشَدُّ تَفَصِّيًا مِنْ صُدُورِ الرِّجَالِ مِنْ النَّعَمِ مِنْ عُقُلِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah memberitakan kepada kami [Syu'bah] dari [Manshur] ia berkata; Aku mendengar [Abu Wa`il] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Alangkah buruknya salah seorang dari dari mereka atau salah seorang dari kalian bila mengatakan; \"Aku lupa ayat ini dan ini, \" bahkan ia pelupa (diciptakan dengan tabiat pelupa), oleh karena itu hafalkanlah al-Qur'an, demi Dzat yang jiwaku berada di tanganNya, terlepasnya (al-Qur'an) dari hati orang lebih dahsyat daripada unta yang terlepas dari ikatannya.\" Abu Isa berkata; Hadits ini hasan shahih."},"2798":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ وَعَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ أَخْبَرَاهُ أَنَّهُمَا سَمِعَا عُمَرَ بْنَ الْخَطَّابِ يَقُولُمَرَرْتُ بِهِشَامِ بْنِ حَكِيمِ بْنِ حِزَامٍ وَهُوَ يَقْرَأُ سُورَةَ الْفُرْقَانِ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَمَعْتُ قِرَاءَتَهُ فَإِذَا هُوَ يَقْرَأُ عَلَى حُرُوفٍ كَثِيرَةٍ لَمْ يُقْرِئْنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكِدْتُ أُسَاوِرُهُ فِي الصَّلَاةِ فَنَظَرْتُ حَتَّى سَلَّمَ فَلَمَّا سَلَّمَ لَبَّبْتُهُ بِرِدَائِهِ فَقُلْتُ مَنْ أَقْرَأَكَ هَذِهِ السُّورَةَ الَّتِي سَمِعْتُكَ تَقْرَؤُهَا فَقَالَ أَقْرَأَنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ لَهُ كَذَبْتَ وَاللَّهِ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُوَ أَقْرَأَنِي هَذِهِ السُّورَةَ الَّتِي تَقْرَؤُهَا فَانْطَلَقْتُ أَقُودُهُ إِلَى ا��نَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى حُرُوفٍ لَمْ تُقْرِئْنِيهَا وَأَنْتَ أَقْرَأْتَنِي سُورَةَ الْفُرْقَانِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسِلْهُ يَا عُمَرُ اقْرَأْ يَا هِشَامُ فَقَرَأَ عَلَيْهِ الْقِرَاءَةَ الَّتِي سَمِعْتُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ يَا عُمَرُ فَقَرَأْتُ بِالْقِرَاءَةِ الَّتِي أَقْرَأَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ مَالِكُ بْنُ أَنَسٍ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ نَحْوَهُ إِلَّا أَنَّهُ لَمْ يَذْكُرْ فِيهِ الْمِسْوَرَ بْنَ مَخْرَمَةَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] dan yang lain, mereka berkata; telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah bin Az Zubair] dari [Al Miswar bin Makhramah] dan [Abdurrahman bin Abd Al Qari`] keduanya mengebarkan bahwa keduanya mendengar [Umar bin Al Khaththab] berkata; \"Pada masas Rasulullah Shallallau 'alaihi wasallam masih hidup, aku melewati Hisyam bin Hakim bin Hizam, ketika itu ia tengah membaca surat Al Furqan, dan aku sempat mendengar bacaannya, ia membaca dalam beberapa bacaan yang tidak pernah dibacakan oleh Rasulullah shallallahu 'alaihi wasallam kepadaku, lantas aku hampir menarik kepalanya dalam shalat, aku terus saja melihatnya hingga ia salam, seusai salam aku tarik selendangnya, aku bertanya; \"Tadi aku sempat mendengarmu membaca surat (Al Qur'an), siapa yang membacakan surat (Al Qur'an) tersebut padamu?\" Ia menjawab; Rasulullah shallallahu 'alaihi wasallam-lah yang membacakannya padaku.\" Aku berkata padanya; \"Bohong. Demi Allah, Rasulullah shallallahu 'alaihi wasallam juga pernah membacakan surat yang kau baca itu padaku.\" Aku beranjak seraya menuntunnya menuju Nabi shallallahu 'alaihi wasallam, aku berkata; \"Wahai Rasulullah, aku tadi mendengar dia membaca surat Al Furqan dengan beberapa bacaan yang tidak anda bacakan padaku, sementara anda telah membacakan surat Al Furqan padaku.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Lepaskan dia wahai Umar, dan bacalah hai Hisyam.\" Hisyam pun membaca bacaan yang aku dengar, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Seperti itulah (surat Al Furqan) diturunkan.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda kepadaku: \"Bacalah, hai Umar, \" aku pun membaca dengan bacaan yang Nabi shallallahu 'alaihi wasallam bacakan padaku, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Seperti itulah (surat Al Furqan) diturunkan.\" Setelah itu Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya al-Qur'an ini diturunkan dalam tujuh huruf, maka bacalah yang mudah darinya.\" Abu Isa berkata; Hadits ini hasan shahih. [Malik bin Anas] dari [Az Zurhi] dengan sanad dan maksud yang sama, hanya saja ia tidak menyebut: \"Al Miswar bin Al Makhramah.\""},"2799":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى حَدَّثَنَا شَيْبَانُ عَنْ عَاصِمٍ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَلَقِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جِبْرِيلَ فَقَالَ يَا جِبْرِيلُ إِنِّي بُعِثْتُ إِلَى أُمَّةٍ أُمِّيِّينَ مِنْهُمْ الْعَجُوزُ وَالشَّيْخُ الْكَبِيرُ وَالْغُلَامُ وَالْجَارِيَةُ وَالرَّجُلُ الَّذِي لَمْ يَقْرَأْ كِتَابًا قَطُّ قَالَ يَا مُحَمَّدُ إِنَّ الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍوَفِي الْبَاب عَنْ عُمَرَ وَحُذَيْفَةَ بْنِ الْيَمَانِ وَأَبِي هُرَيْرَةَ وَأُمِّ أَيُّوبَ وَهِيَ امْرَأَةُ أَبِي أَيُّوبَ الْأَنْصَارِيِّ وَسَمُرَةَ وَابْنِ عَبَّاسٍ وَأَبِي جُهَيْمِ بْنِ الْحَارِثِ بْنِ الصِّمَّةِ وَعَمْرِو بْنِ الْعَاصِ وَأَبِي بَكْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ أُبَيِّ بْنِ كَعْبٍ مِنْ غَيْرِ وَجْهٍ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Al Hasan bin Musa] telah menceritakan kepada kami [Syaiban] dari [Ashim] dari [Zirr bin Hubaisy] dari [Ubay bin Ka'ab] ia berkata; Rasulullah shallallahu 'alaihi wasallam menemui Jibril, lalu beliau bersabda; \"Wahai Jibril, sesungguhnya aku diutus untuk ummat yang buta huruf, di antara mereka ada yang lemah, tua, renta, anak kecil lelaki dan perempuan dan orang yang sama sekali tidak bisa membaca.\" Jibril berkata; \"Wahai Muhammad, sesungguhnya al-Qur'an diturunkan dalam tujuh huruf.\" Dalam hal ini, ada hadits serupa dari Umar, Hudzaifah bin Al Yaman, Abu Hurairah, Ummu Ayyub istri Abu Ayyub Al Anshari, Samurah, Ibnu Abbas, Abu Juhaim bin Al Harits bin Ash Shimmah, 'Amru bin Al 'Ash dan Abu Bakrah. Abu Isa berkata; Hadits ini hasan shahih. Dan diriwayatkan dari Ubay bin Ka'b melalui beberapa sanad."},"2800":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَفَّسَ عَنْ أَخِيهِ كُرْبَةً مِنْ كُرَبِ الدُّنْيَا نَفَّسَ اللَّهُ عَنْهُ كُرْبَةً مِنْ كُرَبِ يَوْمِ الْقِيَامَةِ وَمَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللَّهُ فِي الدُّنْيَا وَالْآخِرَةِ وَمَنْ يَسَّرَ عَلَى مُعْسِرٍ يَسَّرَ اللَّهُ عَلَيْهِ فِي الدُّنْيَا وَالْآخِرَةِ وَاللَّهُ فِي عَوْنِ الْعَبْدِ مَا كَانَ الْعَبْدُ فِي عَوْنِ أَخِيهِ وَمَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللَّهُ لَهُ طَرِيقًا إِلَى الْجَنَّةِ وَمَا قَعَدَ قَوْمٌ فِي مَسْجِدٍ يَتْلُونَ كِتَابَ اللَّهِ وَيَتَدَارَسُونَهُ بَيْنَهُمْ إِلَّا نَزَلَتْ عَلَيْهِمْ السَّكِينَةُ وَغَشِيَتْهُمْ الرَّحْمَةُ وَحَفَّتْهُمْ الْمَلَائِكَةُ وَمَنْ أَبْطَأَ بِهِ عَمَلُهُ لَمْ يُسْرِعْ بِهِ نَسَبُهُقَالَ أَبُو عِيسَى هَكَذَا رَوَى غَيْرُ وَاحِدٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ هَذَا الْحَدِيثِ وَرَوَى أَسْبَاطُ بْنُ مُحَمَّدٍ عَنْ الْأَعْمَشِ قَالَ حُدِّثْتُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ بَعْضَ هَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meringankan satu kesusahan saudaranya dari sekian kesusahan dunia, maka Allah akan meringankan kesusahan dari sekian kesusahan pada hari kiamat, barangsiapa menutupi (aib) seorang muslim, maka Allah akan menutupi (aib) nya di dunia dan akhirat, barangsiapa memberi kemudahan pada orang yang kesuahan, Allah akan memberinya kemudahan di dunia dan akhirat, Allah akan menolong hamba selama hamba menolong saudaranya, barangsiapa menempuh jalan untuk mencari ilmu, maka Allah akan memudahkan jalan untuknya menuju surga, tidaklah suatu kaum duduk di masjid, membaca kitab Allah dan saling mempelajarinya di antara mereka, melainkan ketanangan akan turun menghampiri mereka, rahmat akan meliputinya dan para malaikat akan menaunginya, dan barangsiapa yang amalnya lamban, maka nasabnya pun akan lamban.\" Abu Isa berkata; Seperti ini riwayat para perawi dari Al A'masy dari Abu Shalih dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam. [Asbath bin Muhammad] meriwayatkan dari [Al A'masy], ia berkata; Aku telah dikabari dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, kemudian ia menyebutkan sebagaian hadits ini."},"2801":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ أَسْبَاطِ بْنِ مُحَمَّدٍ الْقُرَشِيُّ قَالَ حَدَّثَنِي أَبِي عَنْ مُطَرِّفٍ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي بُرْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقُلْتُ يَا رَسُولَ اللَّهِ فِي كَمْ أَقْرَأُ الْقُرْآنَ قَالَ اخْتِمْهُ فِي شَهْرٍ قُلْتُ إِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ قَالَ اخْتِمْهُ فِي عِشْرِينَ قُلْتُ إِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ قَالَ اخْتِمْهُ فِي خَمْسَةَ عَشَرَ قُلْتُ إِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ قَالَ اخْتِمْهُ فِي عَشْرٍ قُلْتُ إِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ قَالَ اخْتِمْهُ فِي خَمْسٍ قُلْتُ إِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ قَالَ فَمَا رَخَّصَ لِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ يُسْتَغْرَبُ مِنْ حَدِيثِ أَبِي بُرْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَرُوِي عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمْ يَفْقَهْ مَنْ قَرَأَ الْقُرْآنَ فِي أَقَلَّ مِنْ ثَلَاثٍ وَرُوِي عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ اقْرَأْ الْقُرْآنَ فِي أَرْبَعِينَ و قَالَ إِسْحَقُ بْنُ إِبْرَاهِيمَ وَلَا نُحِبُّ لِلرَّجُلِ أَنْ يَأْتِيَ عَلَيْهِ أَكْثَرُ مِنْ أَرْبَعِينَ يَوْمًا وَلَمْ يَقْرَأْ الْقُرْآنَ لِهَذَا الْحَدِيثِ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ لَا يُقْرَأُ الْقُرْآنُ فِي أَقَلَّ مِنْ ثَلَاثٍ لِلْحَدِيثِ الَّذِي رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَخَّصَ فِيهِ بَعْضُ أَهْلِ الْعِلْمِ وَرُوِي عَنْ عُثْمَانَ بْنِ عَفَّانَ أَنَّهُ كَانَ يَقْرَأُ الْقُرْآنَ فِي رَكْعَةٍ يُوتِرُ بِهَا وَرُوِي عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَنَّهُ قَرَأَ الْقُرْآنَ فِي رَكْعَةٍ فِي الْكَعْبَةِ وَالتَّرْتِيلُ فِي الْقِرَاءَةِ أَحَبُّ إِلَى أَهْلِ الْعِلْمِ","id":"Telah menceritakan kepada kami ['Ubaid bin Asbath bin Muhammad Al Qurasy] ia berkata; telah menceritakan kepadaku [Ayahku] dari [Mutharrif] dari [Abu Ishaq] dari [Abu Burdah] dari [Abdullah bin 'Amru] ia berkata; Aku berkata; \"Wahai Rasulullah, seberapa lama aku harus menghatamkan al-Qur'an?\" Beliau menjawab: \"Khatamkan setiap bulan.\" Aku berkata; \"Aku bisa lebih mampu dan lebih baik dari itu.\" Beliau bersabda: \"Khatamkan dalam duapuluh hari.\" Aku berkata; \"Aku bisa lebih baik dari itu.\" Beliau bersabda: \"Khatamkan dalam limabelas hari.\" Aku berkata; \"Aku bisa lebih baik dari itu.\" Beliau bersabda: \"Khatamkan dalam sepuluh hari.\" Aku berkata; \"Aku dapat lebih baik dari itu.\" Beliau bersabda: \"Khatamkan dalam lima hari.\" Abdullah berkata; \"Setelah itu beliau tidak memberiku keringanan.\" Abu Isa berkata; Hadits ini hasan shahih, dinilai gharib dari hadits Abu Burdah dari Abdullah bin 'Amru. Hadits ini juga diriwayatkan melalui sanad lain dari Abdullah bin 'Amru. Dan diriwayatkan dari Abdullah bin 'Amru dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah dapat memahaminya orang yang membaca (mengkhatamkan) al-Qur'an kurang dari tiga hari.\" Diriwayatkan dari Abdullah bin 'Amru bahwa Nabi shallallahu 'alaihi wasallam bersabda padanya: \"Bacalah (khatamkan) al-Qur'an dalam empatpuluh hari.\" Ishaq bin Ibrahim berkata; \"Berdasarkan hadits ini, maka kami tidak suka bila empatpuluh hari berlalu dari seseorang, sementara dirinya belum pernah mengkhatamkan al-Qur'an. Sebagaian ulama menyatakan bahwa al-Qur'an tidak dihatamkan kurang dari tiga hari, berdasarkan hadits yang diriwayatkan dari Nabi shallallahu 'alaihi wasallam. Sementara sebagaian ulama yang lain memberi keringanan dalam hal ini. Diriwayatkan dari Utsman bin Affan bahwa ia menghatamkan al-Qur'an dalam satu rakaat witir.\" Diriwayatkan dari Sa'ii bin Jubair, bahwa ia mengkhatamkan al-Qur'an dalam satu rakaat di (samping) ka'bah. Dan para ulama lebih menyukai membaca secara tartil."},"2802":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي النَّضْرِ الْبَغْدَادِيُّ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ هُوَ ابْنُ شَقِيقٍ عَنْ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ سِمَاكِ بْنِ الْفَضْلِ عَنْ وَهْبِ بْنِ مُنَبِّهٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ اقْرَأْ الْقُرْآنَ فِي أَرْبَعِينَقَالَ أَب��و عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ رَوَى بَعْضُهُمْ عَنْ مَعْمَرٍ عَنْ سِمَاكِ بْنِ الْفَضْلِ عَنْ وَهْبِ بْنِ مُنَبِّهٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ عَبْدَ اللَّهِ بْنَ عَمْرٍو أَنْ يَقْرَأَ الْقُرْآنَ فِي أَرْبَعِينَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu An Nadlr Al Baghdadi] telah menceritakan kepada kami [Ali bin Al Hasan bin Syaqiq] dari [Abdullah bin Al Mubarak] dari [Ma'mar] dari [Simak bin Al Fadll] dari [Wahab bin Munabbih] dari [Abdullah bin 'Amru] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Khatamkanlah al-Qur'an selama empat puluh (hari).\" Abu Isa berkata; Hadits ini hasan gharib. Sebagaian perawi meriwayatkan dari Ma'mar dari Simak bin Al Fadll dari Wahab bin Munabbih bahwa Nabi shallallahu 'alaihi wasallam memerintahkan Abdullah bin 'Amru supaya mengkhatamkan al-Qur'an selama empat puluh hari.\""},"2803":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا الْهَيْثَمُ بْنُ الرَّبِيعِ حَدَّثَنَا صَالِحٌ الْمُرِّيُّ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَيُّ الْعَمَلِ أَحَبُّ إِلَى اللَّهِ قَالَ الْحَالُّ الْمُرْتَحِلُ قَالَ وَمَا الْحَالُّ الْمُرْتَحِلُ قَالَ الَّذِي يَضْرِبُ مِنْ أَوَّلِ الْقُرْآنِ إِلَى آخِرِهِ كُلَّمَا حَلَّ ارْتَحَلَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ ابْنِ عَبَّاسٍ إِلَّا مِنْ هَذَا الْوَجْهِ وَإِسْنَادُهُ لَيْسَ بِالْقَوِيِّ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا صَالِحٌ الْمُرِّيُّ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ وَلَمْ يَذْكُرْ فِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى وَهَذَا عِنْدِي أَصَحُّ مِنْ حَدِيثِ نَصْرِ بْنِ عَلِيٍّ عَنْ الْهَيْثَمِ بْنِ الرَّبِيعِ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] telah menceritakan kepada kami [Al Haitsam bin Rabi'] telah menceritakan kepada kami [Shalih Al Murri] dari [Qatadah] dari [Zurarah bin Aufa] dari [Ibnu Abbas] ia berkata; Seorang lelaki betanya; \"Wahai Rasulullah, amalan apa yang paling dicintai oleh Allah?\" beliau menjawab: \"AL HALLU dan AL MURTAHILU.\" Dia bertanya; \"Apakah yang dimaksud AL HALLU dan AL MURTAHILU?\" beliau menjawab: \"Yaitu orang yang terus menerus menyambung (selalu mengkhatamkan) dari awal Al Qur`an sampai akhir, seusai (menghatamkan Al Qur'an), dia memulainya lagi.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya dari hadits Ibnu Abbas kecuali dari jalur ini, sementara sanadnya tidak kuat. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Shalih Al Murri] dari [Qatadah] dari [Zurarah bin Aufa] dari Nabi shallallahu 'alaihi wasallam dengan maksud yang sama, namun ia tidak menyebutkan dari Ibnu Abbas. Abu Isa berkata; Hadits ini menurutku lebih shahih dari hadits Nashr bin Ali dari Al Haitsam bin Rabi'."},"2804":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمْ يَفْقَهْ مَنْ قَرَأَ الْقُرْآنَ فِي أَقَلَّ مِنْ ثَلَاثٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [An Nadlr bin Syumail] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Yazid bin Abdullah bin Asy Syikhir] dari [Abdullah bin 'Amru] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak akan memahaminya, seseorang yang mengkhatamkan al-Qur'an kurang dari tiga hari.\" Abu Isa berkata; Hadits ini hasan shahih. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dengan sanad yang sama."},"2805":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْأَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ فِي الْقُرْآنِ بِغَيْرِ عِلْمٍ فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Bisyr bin Assari] telah menceritakan kepada kami [Sufyan] dari [Abdul A'la] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berkata tentang al-Qur'an tanpa ilmu, maka bersiap-siaplah menempati tempatnya di neraka.\" Abu Isa berkata; Hadits ini hasan shahih."},"2806":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا سُوَيْدُ بْنُ عَمْرٍو الْكَلْبِيُّ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْأَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اتَّقُوا الْحَدِيثَ عَنِّي إِلَّا مَا عَلِمْتُمْ فَمَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ وَمَنْ قَالَ فِي الْقُرْآنِ بِرَأْيِهِ فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'], telah menceritakan kepada kami [Suwaid bin 'Amru Al Kalbi] telah menceritakan kepada kami [Abu 'Awanah] dari [Abdul A'la] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jagalah diri untuk menceritakan dariku kecuali yang kalian ketahui, barangsiapa berdusta atas namaku, maka bersiap-siaplah untuk menempati tempatnya di neraka dan barangsiapa mengatakan tentang al-Qur'an dengan pendapatnya, maka bersiap-siaplah menempati tempatnya di neraka.\" Abu Isa berkata; Hadits ini hasan."},"2807":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا سُهَيْلُ بْنُ عَبْدِ اللَّهِ وَهُوَ ابْنُ أَبِي حَزْمٍ أَخُو حَزْمٍ الْقُطَعِيِّ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ جُنْدَبِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ فِي الْقُرْآنِ بِرَأْيِهِ فَأَصَابَ فَقَدْ أَخْطَأَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَقَدْ تَكَلَّمَ بَعْضُ أَهْلِ الْحَدِيثِ فِي سُهَيْلِ بْنِ أَبِي حَزْمٍ وَهَكَذَا رُوِيَ عَنْ بَعْضِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ أَنَّهُمْ شَدَّدُوا فِي هَذَا فِي أَنْ يُفَسَّرَ الْقُرْآنُ بِغَيْرِ عِلْمٍ وَأَمَّا الَّذِي رُوِيَ عَنْ مُجَاهِدٍ وَقَتَادَةَ وَغَيْرِهِمَا مِنْ أَهْلِ الْعِلْمِ أَنَّهُمْ فَسَّرُوا الْقُرْآنَ فَلَيْسَ الظَّنُّ بِهِمْ أَنَّهُمْ قَالُوا فِي الْقُرْآنِ أَوْ فَسَّرُوهُ بِغَيْرِ عِلْمٍ أَوْ مِنْ قِبَلِ أَنْفُسِهِمْ وَقَدْ رُوِيَ عَنْهُمْ مَا يَدُلُّ عَلَى مَا قُلْنَا أَنَّهُمْ لَمْ يَقُولُوا مِنْ قِبَلِ أَنْفُسِهِمْ بِغَيْرِ عِلْمٍ حَدَّثَنَا الْحُسَيْنُ بْنُ مَهْدِيٍّ الْبَصْرِيُّ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ قَالَ مَا فِي الْقُرْآنِ آيَةٌ إِلَّا وَقَدْ سَمِعْتُ فِيهَا شَيْئًا حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الْأَعْمَشِ قَالَ قَالَ مُجَاهِدٌ لَوْ كُنْتُ قَرَأْتُ قِرَاءَةَ ابْنِ مَسْعُودٍ لَمْ أَحْتَجْ إِلَى أَنْ أَسْأَلَ ابْنَ عَبَّاسٍ عَنْ كَثِيرٍ مِنْ الْقُرْآنِ مِمَّا سَأَلْتُ","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Habban bin Hilal] telah menceritakan kepada kami [Suhail bin Abdullah] dia adalah Ibnu Abu Hazm saudaranya Hazm Al Qutha'I, telah menceritakan kepada kami [Abu Imran Al Jauni] dari [Jundub bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengatakan tentang Al Qur`an dengan pendapatnya, maka dia tetap salah walaupun pendapatnya benar.\" Abu Isa berkata; Hadits ini gharib, sebagian ahli hadits membicarakan Suhail bin Abu Hazm, dan demikianlah telah diriwayatkan dari sebagian ulama dari para sahabat Nabi shallallahu 'alaihi wasallam dan yang lainnya, bahwa mereka memperketat dalam masalah ini, yaitu tentang menafsirkan Al Qur`an tanpa Ilmu, adapun yang diriwayatkan dari Mujahid, Qatadah dan lainnya dari para ulama, bahwa mereka menafsirkan Al Qur`an bukan karena prasangka yang ada pada mereka, kemudian mereka mengatakan tentang Al Qur`an atau menafsirkannya tanpa dasar ilmu atau dari diri mereka, telah diriwayatkan dari mereka, mengenai dalil yang menunjukkan atas apa yang kami katakana, bahwa mereka tidak mengatakan tentang Al Qur`an dari diri mereka tanpa dasar ilmu. Telah menceritakan kepada kami Al Husain bin Mahdi Al Bashri telah mengabarkan kepada kami Abdurrazzaq dari Ma'mar dari Qatadah ia berkata; \"Tidak ada satu ayat pun dari Al Qur`an kecuali aku telah mendengar apa yang terkandung di dalamnya.\" Telah menceritakan kepada kami Ibnu Abu Umar telah menceritakan kepada kami Sufyan bin 'Uyainah dari Al A'masy ia berkata; Mujahid berkata; \"Seandainya aku membaca dengan bacaan Ibnu Mas'ud, maka aku tidak perlu lagi bertanya kepada Ibnu Abbas tentang banyak hal dari Al Qur`an, sebagaimana yang saya tanyakan.\""},"2808":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى صَلَاةً لَمْ يَقْرَأْ فِيهَا بِأُمِّ الْقُرْآنِ فَهِيَ خِدَاجٌ هِيَ خِدَاجٌ غَيْرُ تَمَامٍ قَالَ قُلْتُ يَا أَبَا هُرَيْرَةَ إِنِّي أَحْيَانًا أَكُونُ وَرَاءَ الْإِمَامِ قَالَ يَا ابْنَ الْفَارِسِيِّ فَاقْرَأْهَا فِي نَفْسِكَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ اللَّهُ تَعَالَى قَسَمْتُ الصَّلَاةَ بَيْنِي وَبَيْنَ عَبْدِي نِصْفَيْنِ فَنِصْفُهَا لِي وَنِصْفُهَا لِعَبْدِي وَلِعَبْدِي مَا سَأَلَ يَقْرَأُ الْعَبْدُ فَيَقُولُ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }فَيَقُولُ اللَّهُ تَبَارَكَ وَتَعَالَى حَمِدَنِي عَبْدِي فَيَقُولُ{ الرَّحْمَنِ الرَّحِيمِ }فَيَقُولُ اللَّهُ أَثْنَى عَلَيَّ عَبْدِي فَيَقُولُ{ مَالِكِ يَوْمِ الدِّينِ }فَيَقُولُ مَجَّدَنِي عَبْدِي وَهَذَا لِي وَبَيْنِي وَبَيْنَ عَبْدِي{ إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ }وَآخِرُ السُّورَةِ لِعَبْدِي وَلِعَبْدِي مَا سَأَلَ يَقُولُ{ اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ صِرَاطَ الَّذِينَ أَنْعَمْتَ عَلَيْهِمْ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَى شُعْبَةُ وَإِسْمَعِيلُ بْنُ جَعْفَرٍ وَغَيْرُ وَاحِدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا الْحَدِيثِ وَرَوَى ابْنُ جُرَيْجٍ وَمَالِكُ بْنُ أَنَسٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي السَّائِبِ مَوْلَى هِشَامِ بْنِ زُهْرَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا وَرَوَى ابْنُ أَبِي أُوَيْسٍ عَنْ أَبِيهِ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي أَبِي وَأَبُو السَّائِبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا أَخْبَرَنَا بِذَلِكَ مُحَمَّدُ بْنُ يَحْيَى وَيَعْقُوبُ بْنُ سُفْيَانَ الْفَارِسِيُّ قَالَا حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي أُوَيْسٍ عَنْ أَبِيهِ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ حَدَّثَنِي أَبِي وَأَبُو السَّائِبِ مَوْلَى هِشَامِ بْنِ زُهْرَةَ وَكَانَا جَلِيسَيْنِ لِأَبِي هُرَيْرَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى صَلَاةً لَمْ يَقْرَأْ فِيهَا بِأُمِّ الْقُرْآنِ فَهِيَ خِدَاجٌ غَيْرُ تَمَامٍ وَلَيْسَ فِي حَدِيثِ إِسْمَعِيلَ بْنِ أَبِي أُوَيْسٍ أَكْثَرُ مِنْ هَذَا وَسَأَلْتُ أَبَا زُرْعَةَ عَنْ هَذَا الْحَدِيثِ فَقَالَ كِلَا الْحَدِيثَيْنِ صَحِيحٌ وَاحْتَجَّ بِحَدِيثِ ابْنِ أَبِي أُوَيْسٍ عَنْ أَبِيهِ عَنْ الْعَلَاءِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Al Ala` bin Abdurrahman] dari [Ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat tanpa membaca ummul Qur'an (Al Fatihah), maka shalatnya kurang, shalatnya kurang, dan tidak sempurna.\" Abu Al Ala` berkata; Aku berkata; \"Hai Abu Hurairah, aku terkadang shalat di belakang imam.\" Abu Hurairah berkata; \"Hai Ibnu Al Farisi, bacalah sendiri, aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala berfirman: Aku membagi shalat antara Aku dan hambaKu menjadi dua bagian, separuhnya untukKu dan separuhnya untuk hambaKu, dan hambaKu berhak mendapat yang ia meminta. Bila seorang hamba membaca ALHAMDULILLAAHI RABBIL 'AALAMIIN, Allah Tabaraka wa Ta'ala berfirman; HambaKu memujiKu. Bila hamba membaca \"ARRAHMAANIRRAHIIM, \" Allah Tabaraka wa Ta'ala berfirman: \"HambaKu memujaku.\" Bila hamba membaca \"MAALIKI YAWMIDDIIN, \" Allah Tabaraka wa Ta'ala berfirman: \"HambaKu mengagungkanKu, dan ini untukKu, antara Aku dan hambaKu; IYYAAKA NA'BUDU WA IYYAAKA NASTA'IIN dan akhir surat untuk hambaKu dan hambaKu berhak mendapatkan yang ia minta, ia membaca: IHDINASH SHIRAATHAL MUSTAQIIM SHIRAATHAL LADZIINA AN'AMTA 'ALAIHIM GHARIL MAGHDLUUBI 'ALAIHIM WALADL DLAALLIIN.\" Abu Isa berkata; Hadits ini hasan. [Syu'bah], [Isma'il bin Ja'far] dan lainnya meriwayatkan dari [Al Ala` bin Abdurrahman] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti hadits ini. [Ibnu Juraij] dan [Malik bin Anas] meriwayatkan dari [Al Ala` bin Abdurrahman] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti ini. Telah mengabarkan kepada kami yang demikian itu [Muhammad bin Yahya] dan [Ya'qub bin Sufyan Al Farisi], keduanya berkata; telah menceritakan kepada kami [Isma'il bin Abu Uwais] dari [Ayahnya] dari [Al Ala` bin Abdurrahman] telah menceritakan kepadaku [Ayahku] dan [Abu As Sa`ib] bekas budak Hisyam bin Zuhrah, keduanya adalah teman Abu Hurairah, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa shalat tanpa membaca ummul Qur'an (Al Fatihah) maka shalatnya kurang, dan tidak sempurna.\" Tidak disebutkan dalam hadits Isamil bin Abu Uwais lebih dari matan itu, dan aku bertanya kepada Abu Zur'ah tentang hadits ini, ia menjawab; \"Kedua hadits itu shahih.\" Lalu ia berhujah dengan hadits Ibnu Abu Uwais dari Ayahnya dari Al Ala`."},"2809":{"ar":"أَخْبَرَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدٍ أَنْبَأَنَا عَمْرُو بْنُ أَبِي قَيْسٍ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عَبَّادِ بْنِ حُبَيْشٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ جَالِسٌ فِي الْمَسْجِدِ فَقَالَ الْقَوْمُ هَذَا عَدِيُّ بْنُ حَاتِمٍ وَجِئْتُ بِغَيْرِ أَمَانٍ وَلَا كِتَابٍ فَلَمَّا دُفِعْتُ إِلَيْهِ أَخَذَ بِيَدِي وَقَدْ كَانَ قَالَ قَبْلَ ذَلِكَ إِنِّي لَأَرْجُو أَنْ يَجْعَلَ اللَّهُ يَدَهُ فِي يَدِي قَالَ فَقَامَ فَلَقِيَتْهُ امْرَأَةٌ وَصَبِيٌّ مَعَهَا فَقَالَا إِنَّ لَنَا إِلَيْكَ حَاجَةً فَقَامَ مَعَهُمَا حَتَّى قَضَى حَاجَتَهُمَا ثُمَّ أَخَذَ بِيَدِي حَتَّى أَتَى بِي دَارَهُ فَأَلْقَتْ لَهُ الْوَلِيدَةُ وِسَادَةً فَجَلَسَ عَلَيْهَا وَجَلَسْتُ بَيْنَ يَدَيْهِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ مَا يُفِرُّكَ أَنْ تَقُولَ لَا إِلَهَ إِلَّا اللَّهُ فَهَلْ تَعْلَمُ مِنْ إِلَهٍ سِوَى اللَّهِ قَالَ قُلْتُ لَا قَالَ ثُمَّ تَكَلَّمَ سَاعَةً ثُمَّ قَالَ إِنَّمَا تَفِرُّ أَنْ تَقُولَ اللَّهُ أَكْبَرُ وَتَعْلَمُ أَنَّ شَيْئًا أَكْبَرُ مِنْ اللَّهِ قَالَ قُلْتُ لَا قَالَ فَإِنَّ الْيَهُودَ مَغْضُوبٌ عَلَيْهِمْ وَإِنَّ النَّصَارَى ضُلَّالٌ قَالَ قُلْتُ فَإِنِّي جِئْتُ مُسْلِمًا قَالَ فَرَأَيْتُ وَجْهَهُ تَبَسَّطَ فَرَحًا قَالَ ثُمَّ أَمَرَ بِي فَأُنْزِلْتُ عِنْدَ رَجُلٍ مِنْ الْأَنْصَارِ جَعَلْتُ أَغْشَاهُ آتِيهِ طَرَفَيْ النَّهَارِ قَالَ فَبَيْنَمَا أَنَا عِنْدَهُ عَشِيَّةً إِذْ جَاءَهُ قَوْمٌ فِي ثِيَابٍ مِنْ الصُّوفِ مِنْ هَذِهِ النِّمَارِ قَالَ فَصَلَّى وَقَامَ فَحَثَّ عَلَيْهِمْ ثُمَّ قَالَ وَلَوْ صَاعٌ وَلَوْ بِنِصْفِ صَاعٍ وَلَوْ بِقَبْضَةٍ وَلَوْ بِبَعْضِ قَبْضَةٍ يَقِي أَحَدُكُمْ وَجْهَهُ حَرَّ جَهَنَّمَ أَوْ النَّارِ وَلَوْ بِتَمْرَةٍ وَلَوْ بِشِقِّ تَمْرَةٍ فَإِنَّ أَحَدَكُمْ لَاقِي اللَّهَ وَقَائِلٌ لَهُ مَا أَقُولُ لَكُمْ أَلَمْ أَجْعَلْ لَكَ سَمْعًا وَبَصَرًا فَيَقُولُ بَلَى فَيَقُولُ أَلَمْ أَجْعَلْ لَكَ مَالًا وَوَلَدًا فَيَقُولُ بَلَى فَيَقُولُ أَيْنَ مَا قَدَّمْتَ لِنَفْسِكَ فَيَنْظُرُ قُدَّامَهُ وَبَعْدَهُ وَعَنْ يَمِينِهِ وَعَنْ شِمَالِهِ ثُمَّ لَا يَجِدُ شَيْئًا يَقِي بِهِ وَجْهَهُ حَرَّ جَهَنَّمَ لِيَقِ أَحَدُكُمْ وَجْهَهُ النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ فَإِنْ لَمْ يَجِدْ فَبِكَلِمَةٍ طَيِّبَةٍ فَإِنِّي لَا أَخَافُ عَلَيْكُمْ الْفَاقَةَ فَإِنَّ اللَّهَ نَاصِرُكُمْ وَمُعْطِيكُمْ حَتَّى تَسِيرَ الظَّعِينَةُ فِيمَا بَيْنَ يَثْرِبَ وَالْحِيرَةِ أَوْ أَكْثَرَ مَا تَخَافُ عَلَى مَطِيَّتِهَا السَّرَقَ قَالَ فَجَعَلْتُ أَقُولُ فِي نَفْسِي فَأَيْنَ لُصُوصُ طَيِّيءٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ سِمَاكِ بْنِ حَرْبٍ وَرَوَى شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عَبَّادِ بْنِ حُبَيْشٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَدِيثَ بِطُولِهِ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عَبَّادِ بْنِ حُبَيْشٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْيَهُودُ مَغْضُوبٌ عَلَيْهِمْ وَالنَّصَارَى ضُلَّالٌ فَذَكَرَ الْحَدِيثَ بِطُولِهِ","id":"Telah mengabarkan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Abdurrahman bin Sa'd] telah memberitakan kepada kami ['Amru bin Abu Qais] dari [Simak bin Harb] dari ['Abbad bin Hubaisy] dari [Adi bin Hatim] ia berkata; Aku datang menemui Rasulullah shallallahu 'alaihi wasallam, ketika ituu beliau tengah duduk di masjid, orang-orang berkata; \"Ini Adi bin Hatim.\" Aku datang tanpa jaminan keamanan ataupun surat. Saat aku diserahkan kepada beliau, beliau meraih tanganku, sebelum itu, beliau pernah bersabda; \"Sesungguhnya aku sangat berharap agar Allah meletakkan tangannya di tanganku.\" Adi berkata; \"Beliau berdiri, lalu seorang wanita bersama anaknya menemui beliau, Keduanya berkata; \"Kami ada perlu dengan anda.\" Maka beliau berdiri bersama keduanya, hingga beliau menuntaskan keperluan mereka berdua, setelah itu beliau meraih tanganku hingga beliau membawaku ke kediaman beliau, seorang budak menatakan bantal untuk beliau, beliau duduk dan aku duduk di hadapan beliau. Beliau memuja dan memuji Allah, selanjutnya beliau bertanya: \"Apa yang membuatmu benci untuk mengucapkan LAA ILAAHA ILLALLAAH, apa kamu tahu ada ilah selain Allah?\" aku menjawab; \"Tidak.\" selanjutnya beliau berbicara sesaat, lalu bersabda: \"Sesungguhnya kamu hanya takut mengucapkan ALLAAHU AKBAR dan kamu tahu bahwa ada sesuatu yang lebih besar dari Allah.\" Adi berkata; Aku menjawab; \"Tidak.\" Beliau bersabda: \"Sesungguhnya Yahudi dimurkai sedangkan Nasrani sesat.\" Adi berkata; Aku menjawab; \"Aku datang dalam keadaan muslim.\" Adi berkata; Lalu aku melihat wajah beliau lapang karena gembira, lalu beliau memerintahkan seseorang untuk membawaku, selanjutnya aku ditempatkan di rumah salah seorang Anshar. Di kedua penghujung siang, aku mendatangi beliau. Pada suatu sore, aku berada di dekat beliau, tiba-tiba sekelompok kaum berpakaian wool yamg bergaris mendatangi beliau. Adi berkata; \"Lalu beliau shalat, berdiri lalu menganjurkan mereka (untuk bersedekah), setelah itu beliau bersabda: \"Meski dengan satu sha', setengah sha', segenggam dan sedikit genggaman salah seorang di antara kalian menjaga wajahnya dari panasnya jahanam atau neraka, meski dengan satu kurma, meski dengan secuil kurma, sesungguhnya salah seorang dari kalian akan bertemu Allah dan ada yang berkata padanya seperti yang aku katakan pada kalian; \"Bukankah Aku telah membuatkan pendengaran dan penglihatan untukmu?\" Ia menjawab; \"Benar.\" Dia bertanya: \"Bukankah Aku telah memberikan harta dan anak untukmu?\" Ia menjawab: \"Benar.\" Dia bertanya: \"Mana (kebaikan) yang kau lakukan untuk dirimu?\" lalu ia melihat ke belakang, depan, kanan dan kirinya, tapi tidak menemukan apa pun yang menjaga wajahnya dari panasnya jahanam. Hendaklah salah seorang dari kalian menjaga wajahnya dari neraka meski dengan secuil kurma, bila ia tidak punya, maka dengan tutur kata yang baik, sesungguhnya aku tidak mengkhawatirkan kemiskinan pada kalian karena Allah penolong kalian dan pemberi kalian, hingga wanita berada dalam sekedup berjalan antara Yatsrib dan Hairah atau lebih jauh, tanpa rasa takut barang bawannya di curi.\" Adi berkata; Aku berkata dalam hati; \"Lalu dimana pencuri-pencuri Thayyi`? Abu Isa berkata; Hadits ini hasan gharib, kami hanya mengetahuinya dari hadits Simak bin Harb. [Syu'bah] meriwayatkan dari [Simak bin Harb] dari ['Abbad bin Hubaisy] dari [Adi bin Hatim] dari Nabi shallallahu 'alaihi wasallam secara panjang lebar. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] dari ['Abbad bin Hubaisy] dari [Adi bin Hatim] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Yahudi dimurkai dan Nasrani sesat.\" Kemudian ia menyebut hadits secara panjang lebar."},"2810":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَابْنُ أَبِي عَدِيٍّ وَمُحَمَّدُ بْنُ جَعْفَرٍ وَعَبْدُ الْوَهَّابِ قَالُوا حَدَّثَنَا عَوْفُ بْنُ أَبِي جَمِيلَةَ الْأَعْرَابِيُّ عَنْ قَسَامَةَ بْنِ زُهَيْرٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَعَالَى خَلَقَ آدَمَ مِنْ قَبْضَةٍ قَبَضَهَا مِنْ جَمِيعِ الْأَرْضِ فَجَاءَ بَنُو آدَمَ عَلَى قَدْرِ الْأَرْضِ فَجَاءَ مِنْهُمْ الْأَحْمَرُ وَالْأَبْيَضُ وَالْأَسْوَدُ وَبَيْنَ ذَلِكَ وَالسَّهْلُ وَالْحَزْنُ وَالْخَبِيثُ وَالطَّيِّبُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] dan [Ibnu Abu Adi] dan [Muhammad bin Ja'far] dan [Abdul Wahhab], mereka berkata; telah menceritakan kepada kami ['Auf bin Abu Jamilah Al A'rabi] dari [Qasamah bin Zuhair] dari [Abu Musa Al Asy'ari] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah Ta'ala menciptakan Adam dari genggaman yang di ambil dari seluruh bumi, lalu anak keturunan Adam datang sesuai dengan kadar bumi (tanah), di antara mereka ada yang (berkulit) merah, putih, hitam. Dan diantaranya pula ada yang ramah, sedih, keji dan baik.\" Abu Isa berkata; Hadits ini hasan shahih."},"2811":{"ar":"وَبِهَذَا الْإِسْنَادِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ فَبَدَّلَ الَّذِينَ ظَلَمُوا قَوْلًا غَيْرَ الَّذِي قِيلَ لَهُمْ }قَالَ قَالُوا حَبَّةٌ فِي شَعْرَةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Dan dengan sanad ini (Yaitu; Telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah]) dari Nabi shallallahu 'alaihi wasallam: \"Lalu orang-orang yang zhalim mengganti perintah dengan (mengerjakan) yang tidak diperintahkan kepada mereka.\" QS Al-Baqarah: 59, Beliau bersabda: \"Mereka berkata; biji dalam rambut.\" Abu Isa berkata; Hadits ini hasan shahih."},"2812":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَشْعَثُ السَّمَّانُ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فِي لَيْلَةٍ مُظْلِمَةٍ فَلَمْ نَدْرِ أَيْنَ الْقِبْلَةُ فَصَلَّى كُلُّ رَجُلٍ مِنَّا عَلَى حِيَالِهِ فَلَمَّا أَصْبَحْنَا ذَكَرْنَا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ{ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ أَشْعَثَ السَّمَّانِ أَبِي الرَّبِيعِ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ وَأَشْعَثُ يُضَعَّفُ فِي الْحَدِيثِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Asy'ats As Samman] dari ['Ashim bin 'Ubaidullah] dari [Abdullah bin 'Amir bin Rabi'ah] dari [Ayahnya] ia berkata; Kami bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan di malam yang gelap, kami tidak tahu mana kiblat, masing-masing dari kami shalat menghadap sesuai arahnya. Di pagi harinya, kami menceritakan hal itu kepada Nabi shallallahu 'alaihi wasallam, lalu turunlah ayat: \"Maka kemanapun kamu menghadap di situlah wajah Allah.\" QS Al-Baqarah: 115"},"2813":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ قَال سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى رَاحِلَتِهِ تَطَوُّعًا أَيْنَمَا تَوَجَّهَتْ بِهِ وَهُوَ جَاءٍ مِنْ مَكَّةَ إِلَى الْمَدِينَةِثُمَّ قَرَأَ ابْنُ عُمَرَ هَذِهِ الْآيَةَ{ وَلِلَّهِ الْمَشْرِقُ وَالْمَغْرِبُ }الْآيَةَ فَقَالَ ابْنُ عُمَرَ فَفِي هَذَا أُنْزِلَتْ هَذِهِ الْآيَةُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَيُرْوَى عَنْ قَتَادَةَ أَنَّهُ قَالَ فِي هَذِهِ الْآيَةِ{ وَلِلَّهِ الْمَشْرِقُ وَالْمَغْرِبُ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }قَالَ قَتَادَةُ هِيَ مَنْسُوخَةٌ نَسَخَهَا قَوْلُهُ{ فَوَلِّ وَجْهَكَ شَطْرَ الْمَسْجِدِ الْحَرَامِ }أَيْ تِلْقَاءَهُ حَدَّثَنَا بِذَلِكَ مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ وَيُرْوَى عَنْ مُجَاهِدٍ فِي هَذِهِ الْآيَةِ{ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }قَالَ فَثَمَّ قِبْلَةُ اللَّهِ حَدَّثَنَا بِذَلِكَ أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ النَّضْرِ بْنِ عَرَبِيٍّ عَنْ مُجَاهِدٍ بِهَذَا","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Abdul Malik bin Abu Sulaiman] ia berkata; Aku mendengar [Sa'id bin Jubair] menceritakan dari [Ibnu Umar] ia berkata; Nabi shallallahu 'alaihi wasallam pernah shalat sunnah di atas kendaraan beliau kemana pun kendaraan beliau menghadap, ketika itu beliau pergi dari Makkah menuju Madinah. Setelah itu Ibnu Umar membaca ayat ini: \"Dan kepunyaan Allah-lah timur dan barat.\" QS Al-Baqarah: 115. Ibnu Umar berkata; \"Berkenaan dengan peristiwa itulah, ayat ini turun.\" Abu Isa berkata; Hadits ini hasan shahih. Diriwayatkan dari Qatadah, ia berkata tentang ayat ini: Dan kepunyaan Allah-lah timur dan barat, maka kemanapun kamu menghadap di situlah wajah Allah.\" QS Al-Baqarah: 115 Qatadah berkata; Ayat ini mansukhah, dinasakh dengan firman Allah, \"Palingkanlah mukamu ke arah Masjidil Haram.\" QS Al-Baqarah: 144 yaitu arahnya. Telah menceritakan kepada kami yang demikian itu Muhammad bin Abdul Malik bin Abu Asy Syawarib, telah menceritakan kepada kami Yazid bin Zurai' dari Sa'id dari Qatadah. Dan diriwayatkan pula dari Mujahid tentang ayat ini: \"Maka kemanapun kamu menghadap, di situlah wajah Allah.\" QS Al-Baqarah: 115, ia berkata; \"Di sanalah kiblat Allah.\" Telah menceritakan kepada kami seperti itu Muhammad bin Al Ala` telah menceritakan kepada kami Waki' dari An Nadlr bin Arabi dari Mujahid seperti itu."},"2814":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسٍ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُقُلْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ اتَّخَذْتَ مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى فَنَزَلَتْ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Humaid Ath Thawil] dari [Anas] ia berkata; [Umar bin Al Khaththab] radliallahu 'anhu berkata; Aku berkata kepada Rasulullah shallallahu 'alaihi wasallam; \"Andai anda menjadikan sebagaian maqam untuk tempat shalat.\" Kemudian turunlah ayat: \"Dan jadikanlah sebahagian maqam Ibrahim tempat shalat.\" QS Al-Baqarah: 125. Abu Isa berkata; Hadits ini hasan shahih. Dalam hal ini, ada hadits serupa dari Ibnu Umar."},"2815":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ{ وَكَذَلِكَ جَعَلْنَاكُمْ أُمَّةً وَسَطًا }قَالَ عَدْلًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Abu Muawiyah] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam tentang firman Allah: \"Dan demikian (pula) Kami telah menjadikan kamu (umat Islam), umat yang adil dan pilihan agar kamu menjadi saksi atas (perbuatan) manusia.\" QS Al-Baqarah: 143, beliau bersabda: \"Adil.\" Abu Isa berkata; Hadits ini hasan shahih."},"2816":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ صَلَّى نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ أَوْ سَبْعَةَ عَشَرَ شَهْرًا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ أَنْ يُوَجَّهَ إِلَى الْكَعْبَةِ فَأَنْزَلَ اللَّهُ{ قَدْ نَرَى تَقَلُّبَ وَجْهِكَ فِي السَّمَاءِ فَلَنُوَلِّيَنَّكَ قِبْلَةً تَرْضَاهَا فَوَلِّ وَجْهَكَ شَطْرَ الْمَسْجِدِ الْحَرَامِ }فَوُجِّهَ نَحْوَ الْكَعْبَةِ وَكَانَ يُحِبُّ ذَلِكَ فَصَلَّى رَجُلٌ مَعَهُ الْعَصْرَ قَالَ ثُمَّ مَرَّ عَلَى قَوْمٍ مِنْ الْأَنْصَارِ وَهُمْ رُكُوعٌ فِي صَلَاةِ الْعَصْرِ نَحْوَ بَيْتِ الْمَقْدِسِ فَقَالَ هُوَ يَشْهَدُ أَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّهُ قَدْ وُجِّهَ إِلَى الْكَعْبَةِ قَالَ فَانْحَرَفُوا وَهُمْ رُكُوعٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ سُفْيَانُ الثَّوْرِيُّ عَنْ أَبِي إِسْحَقَ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Waki'] dari [Israil] dari [Abu Ishaq] dari [Al Bara` bin Azib] ia berkata; \"Setibanya Rasulullah shallallahu 'alaihi wasallam di Madinah, beliau shalat menghadap ke Baitul Maqdis selama enam belas atau tujuh belas bulan, namun Rasulullah shallallahu 'alaihi wasallam ingin menghadap ka'bah, maka Allah menurunkan ayat: \"Sungguh Kami (sering) melihat mukamu menengadah ke langit, maka sungguh kami akan memalingkan kamu ke kiblat yang kamu sukai. Palingkanlah mukamu ke arah Masjidil Haram.\" QS Al-Baqarah: 144. Kemudian beliau menghadapkan mukanya ke arah Ka'bah, dan beliau sangat menyukainya, lalu seseorang shalat ashar bersama beliau. Setelah itu ia melintasi suatu kaum dari sahabat Anshar, mereka tengah ruku' dalam shalat ashar sambil menghadap Baitul Maqdis.\" Barra` berkata; Sahabat tersebut bersaksi bahwa ia pernah shalat ashar bersama Rasulullah shallallahu 'alaihi wasallam dan beliau telah dihadapkan ke Ka'bah. Barra` berkata; \"Mereka pun mengalihkan wajahnya dalam keadaan ruku'.\" Abu Isa berkata; Hadits ini hasan shahih. [Sufyan Ats Tsauri] juga meriwayatkannya dari [Abu Ishaq]."},"2817":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَكَانُوا رُكُوعًا فِي صَلَاةِ الْفَجْرِوَفِي الْبَاب عَنْ عَمْرِو بْنِ عَوْفٍ الْمُزَنِيِّ وَابْنِ عُمَرَ وَعُمَارَةَ بْنِ أَوْسٍ وَأَنَسِ بْنِ مَالِكٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] ia berkata; \"Orang-orang tengah ruku' dalam shalat fajar.\" Dalam hal ini ada hadits serupa dari 'Amru bin Auf Al Muzanni, Ibnu Umar, 'Umarah bin Aus dan Anas bin Malik. Abu Isa berkata; Hadits Ibnu Umar hasan shahih."},"2818":{"ar":"حَدَّثَنَا هَنَّادٌ وَأَبُو عَمَّارٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا وُجِّهَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْكَعْبَةِ قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ بِإِخْوَانِنَا الَّذِينَ مَاتُوا وَهُمْ يُصَلُّونَ إِلَى بَيْتِ الْمَقْدِسِ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَمَا كَانَ اللَّهُ لِيُضِيعَ إِيمَانَكُمْ }الْآيَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] dan [Abu 'Ammar] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Isra'il] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; \"Saat Nabi shallallahu 'alaihi wasallam dialihkan ke arah Ka'bah, orang-orang berkata; \"Wahai Rasulullah, bagaimana dengan saudara-saudara kami yang telah meninggal, sementara mereka shalat menghadap Baitul Maqdis?\" Maka turunlah ayat: \"Dan Allah tidaklah menyia-nyiakan keimananmu.\" QS Al-Baqarah: 143. Abu Isa berkata; Hadits ini hasan shahih."},"2819":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يَزِيدُ بْنُ أَبِي حَكِيمٍ عَنْ سُفْيَانَ عَنْ عَاصِمٍ الْأَحْوَلِ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ عَنْ الصَّفَا وَالْمَرْوَةِ فَقَالَكَانَا مِنْ شَعَائِرِ الْجَاهِلِيَّةِ فَلَمَّا كَانَ الْإِسْلَامُ أَمْسَكْنَا عَنْهُمَا فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }قَالَ هُمَا تَطَوُّعٌ{ وَمَنْ تَطَوَّعَ خَيْرًا فَإِنَّ اللَّهَ شَاكِرٌ عَلِيمٌ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Yazid bin Abu Hakim] dari [Sufyan] dari ['Ashim Al Ahwal] ia berkata; Aku bertanya kepada [Anas bin Malik] tentang Shafa dan Marwah, ia menjawab: \"Keduanya termasuk syi'ar jahiliyah. Saat Islam datang, kami menahan diri dari keduanya, namun Allah Tabaraka wa Ta'ala menurunkan ayat: \"Sesungguhnya Shafaa dan Marwa adalah sebahagian dari syi'ar Allah. Maka barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'i antara keduanya.\" QS Al-Baqarah: 158, ia berkata; \"Keduanya sunnah.\"Dan barangsiapa yang mengerjakan suatu kebajikan dengan kerelaan hati, maka Sesungguhnya Allah Maha mensyukuri kebaikan lagi Maha Mengetahui.\" Abu Isa berkata; Hadits ini hasan shahih."},"2820":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا يَزِيدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَبِي مُلَيْكَةَ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ هَذِهِ الْآيَةِ{ هُوَ الَّذِي أَنْزَلَ عَلَيْكَ الْكِتَابَ مِنْهُ آيَاتٌ مُحْكَمَاتٌ }إِلَى آخِرِ الْآيَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتُمْ الَّذِينَ يَتَّبِعُونَ مَا تَشَابَهَ مِنْهُ فَأُولَئِكَ الَّذِينَ سَمَّاهُمْ اللَّهُ فَاحْذَرُوهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرُوِي عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ هَكَذَا رَوَى غَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَن�� ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ وَلَمْ يَذْكُرُوا فِيهِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ وَإِنَّمَا ذَكَرَ يَزِيدُ بْنُ إِبْرَاهِيمَ التُّسْتَرِيُّ عَنْ الْقَاسِمِ فِي هَذَا الْحَدِيثِ وَابْنُ أَبِي مُلَيْكَةَ هُوَ عَبْدُ اللَّهِ بْنُ عُبَيْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ سَمِعَ مِنْ عَائِشَةَ أَيْضًا","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Yazid bin Ibrahim] telah menceritakan kepada kami [Ibnu Abu Mulaikah] dari [Al Qasim bin Muhammad] dari ['Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang ayat ini: Dia-lah yang menurunkan Al Kitab (Al Qur'an) kepada kamu. Di antara (isi) nya ada ayat-ayat yang muhkamaat.\" QS Ali 'Imraan: 7, beliau bersabda: \"Jika kalian melihat orang-orang yang mengikuti sebahagian ayat-ayat yang mutasyabihat daripada (al Qur'an), merekalah yang Allah sebut (dalam ayat ini), oleh karena itu hendaklah kalian berhati-hati terhadap mereka.\" Abu Isa mengatakan; bahwa hadits ini hasan shahih. Dan telah diriwayatkan dari [Ayyub] dari [Ibnu Abu Mulaikah] dari [Aisyah] seperti ini, tidak satu orang yang meriwayatkan hadits ini dari Ibnu Abu Mulaikah dari Aisyah dan tidak menyebutkan di dalamnya dari Al Qasim bin Muhammad dan hanya menyebutkan Yazid bin Ibrahim At Tustari dari Al Qasim di dalam hadits ini, dan Ibnu Abu Mulaikah adalah Abdullah bin Ubaidullah bin Abu Mulaikah, dia mendengar dari Aisyah juga."},"2821":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِيهِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِكُلِّ نَبِيٍّ وُلَاةً مِنْ النَّبِيِّينَ وَإِنَّ وَلِيِّي أَبِي وَخَلِيلُ رَبِّي ثُمَّ قَرَأَ{ إِنَّ أَوْلَى النَّاسِ بِإِبْرَاهِيمَ لَلَّذِينَ اتَّبَعُوهُ وَهَذَا النَّبِيُّ وَالَّذِينَ آمَنُوا وَاللَّهُ وَلِيُّ الْمُؤْمِنِينَ }حَدَّثَنَا مَحْمُودٌ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِيهِ عَنْ أَبِي الضُّحَى عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ وَلَمْ يَقُلْ فِيهِ عَنْ مَسْرُوقٍ قَالَ أَبُو عِيسَى هَذَا أَصَحُّ مِنْ حَدِيثِ أَبِي الضُّحَى عَنْ مَسْرُوقٍ وَأَبُو الضُّحَى اسْمُهُ مُسْلِمُ بْنُ صُبَيْحٍ حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِيهِ عَنْ أَبِي الضُّحَى عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ حَدِيثِ أَبِي نُعَيْمٍ وَلَيْسَ فِيهِ عَنْ مَسْرُوقٍ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Sufyan] dari [Ayahnya] dari [Abu Adl Dluha] dari [Masruq] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya setiap Nabi memiliki para wali dari kalangan para Nabi, dan waliku adalah bapakku (Ibrahim), dan kekasihku adalah Rabbku.\" kemudian beliau membaca (ayat): Sesungguhnya orang yang paling dekat kepada Ibrahim ialah orang-orang yang mengikutinya dan Nabi ini (Muhammad), beserta orang-orang yang beriman (kepada Muhammad), dan Allah adalah Pelindung semua orang-orang yang beriman.\" QS Ali 'Imraan: 68. Telah menceritakan kepada kami [Mahmud] telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Ayahnya] dari [Abu Adl Dluha] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas. Namun ia tidak menyebut: \"Dari Masruq.\" Abu Isa berkata; Hadits ini lebih shahih dari hadits Abu Adl Dluha dari Masruq. Abu Adl Dluha namanya adalah Muslim bin Shubaih. Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ayahnya] dari [Abu Adl Dluha] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam seperti hadits Abu Nu'aim, tapi tidak menyebutkan: \"Dari Masruq.\""},"2822":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ السَّهْمِيُّ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةَ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }أَوْ{ مَنْ ذَا الَّذِي يُقْرِضُ اللَّهَ قَرْضًا حَسَنًا }قَالَ أَبُو طَلْحَةَ وَكَانَ لَهُ حَائِطٌ فَقَالَ يَا رَسُولَ اللَّهِ حَائِطِي لِلَّهِ وَلَوْ اسْتَطَعْتُ أَنْ أُسِرَّهُ لَمْ أُعْلِنْهُ فَقَالَ اجْعَلْهُ فِي قَرَابَتِكَ أَوْ أَقْرَبِيكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ مَالِكُ بْنُ أَنَسٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكِ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Abdullah bin Bakr As Sahmani] telah menceritakan kepada kami [Humaid] dari [Anas] ia berkata; \"Ketika turun ayat Kamu sekali-kali tidak sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sebahagian harta yang kamu cintai.\" QS Ali 'Imran: 92 atau Siapakah yang mau memberi pinjaman kepada Allah, pinjaman yang baik (menafkahkan hartanya di jalan Allah). QS Al-Baqarah: 245, kemudian Abu Thalhah, yang memiliki kebun berkata; \"Wahai Rasulullah, saya (infakkan) kebun saya ini di jalan Allah. Dan sekiranya saya mampu untuk menyembunyikannya tentu saya tidak menyatakannya. lalu beliau mengatakan \"Berikanlah kepada kerabat atau orang yang terdekat denganmu!\" Abu Isa mengatakan bahwa hadits ini hasan shahih. Dan [Malik bin Anas] telah meriwayatkan dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] "},"2823":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَزِيدَ قَال سَمِعْتُ مُحَمَّدَ بْنَ عَبَّادِ بْنِ جَعْفَرٍ الْمَخْزُومِيَّ يُحَدِّثُ عَنْ ابْنِ عُمَرَ قَالَقَامَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ الْحَاجُّ يَا رَسُولَ اللَّهِ قَالَ الشَّعِثُ التَّفِلُ فَقَامَ رَجُلٌ آخَرُ فَقَالَ أَيُّ الْحَجِّ أَفْضَلُ يَا رَسُولَ اللَّهِ قَالَ الْعَجُّ وَالثَّجُّ فَقَامَ رَجُلٌ آخَرُ فَقَالَ مَا السَّبِيلُ يَا رَسُولَ اللَّهِ قَالَ الزَّادُ وَالرَّاحِلَةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ ابْنِ عُمَرَ إِلَّا مِنْ حَدِيثِ إِبْرَاهِيمَ بْنِ يَزِيدَ الْخُوزِيِّ الْمَكِّيِّ وَقَدْ تَكَلَّمَ بَعْضُ أَهْلِ الْحَدِيثِ فِي إِبْرَاهِيمَ بْنِ يَزِيدَ مِنْ قِبَلِ حِفْظِهِ","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ibrahim bin Yazid] ia berkata; Aku mendengar [Muhammad bin 'Abbad bin Ja'far Al Makhzumi] menceritakan dari [Ibnu Umar] ia berkata; \"Seseorang menghadap Nabi shallallahu 'alaihi wasallam dan bertanya: \"Ya Rasulullah, siapakah orang yang berhaji itu? beliau menjawab: \"Orang yang kusut rambutnya (tidak disisir) dan yang bau badannya (tidak memakai wewangian) \" seseorang lainnya berdiri kemudian bertanya; \"Wahai Rasulullah, haji apakah yang paling afdhal?\" beliau menjawab: \"Mengeraskan suara (talbiyyah) dan mengalirkan darah hewan (kurban).\" yang lainya bertanya; \"Apakah as Sabil itu?\" beliau menjawab: \"Perbekalan (makanan) dan alat-alat pengangkutan serta sehat jasmani dan perjalanan pun aman.\" Abu Isa berkata; Kami tidak mengetahui hadits ini dari Ibnu Umar kecuali dari hadits Ibrahim bin Yazid Al Khuzi al Makki, sebagian ulama ahli hadits telah mengomentari Ibrahim bin Yazid dari segi hafalannya."},"2824":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ بُكَيْرِ بْنِ مِسْمَارٍ عَنْ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِ قَالَلَمَّا أَنْزَلَ اللَّهُ هَذِهِ الْآيَةَ{ تَعَالَوْا نَدْعُ أَبْنَاءَنَا وَأَبْنَاءَكُمْ وَنِسَاءَنَا وَنِسَاءَكُمْ }الْآيَةَ دَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيًّا وَفَاطِمَةَ وَحَسَنًا وَحُسَيْنًا فَقَالَ اللَّهُمَّ هَؤُلَاءِ أَهْلِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Bukair bin Mismar] dari ['Amir bin Sa'd bin Abu Waqash] dari [Ayahnya] ia berkata; \"Ketika Allah menurunkan ayat Marilah kita memanggil anak-anak kami dan anak-anak kamu, isteri-isteri kami dan isteri-isteri kamu.\" QS Ali Imraan: 61, Rasulullah shallallahu 'alaihi wasallam memanggil Ali, Fatimah, Hasan, dan Husain, kemudian berdoa: \"Ya Allah, inilah keluargaku\". Abu Isa mengatakan bahwa hadits ini hasan shahih gharib."},"2825":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي قَوْلِهِ تَعَالَى{ كُنْتُمْ خَيْرَ أُمَّةٍ أُخْرِجَتْ لِلنَّاسِ }قَالَ إِنَّكُمْ تَتِمُّونَ سَبْعِينَ أُمَّةً أَنْتُمْ خَيْرُهَا وَأَكْرَمُهَا عَلَى اللَّهِهَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَى غَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ بَهْزِ بْنِ حَكِيمٍ نَحْوَ هَذَا وَلَمْ يَذْكُرُوا فِيهِ{ كُنْتُمْ خَيْرَ أُمَّةٍ أُخْرِجَتْ لِلنَّاسِ }","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Bahz bin Hakim] dari [Ayahnya] dari [Kakeknya] bahwa dia mendengar Nabi shallallahu 'alaihi wasallam bersabda tentang firman Allah Ta'ala; Kamu adalah umat yang terbaik yang dilahirkan untuk manusia. QS Ali Imran: 110, beliau bersabda: \"Sesungguhnya kalian terbagi menjadi tujuh puluh umat, dan kalianlah yang terbaik (diantara mereka) serta paling mulia di sisi Allah.\" Hadits ini hasan. Beberapa perawi meriwayatkan hadits ini dari Bahz bin Hakim seperti ini, namun mereka tidak menyebut: Kamu adalah umat yang terbaik yang dilahirkan untuk manusia QS Ali Imran: 110."},"2826":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُمَيْدٌ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُسِرَتْ رَبَاعِيَتُهُ يَوْمَ أُحُدٍ وَشُجَّ وَجْهُهُ شَجَّةً فِي جَبْهَتِهِ حَتَّى سَالَ الدَّمُ عَلَى وَجْهِهِ فَقَالَ كَيْفَ يُفْلِحُ قَوْمٌ فَعَلُوا هَذَا بِنَبِيِّهِمْ وَهُوَ يَدْعُوهُمْ إِلَى اللَّهِ فَنَزَلَتْ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ }إِلَى آخِرِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Humaid] dari [Anas] bahwa pada perang Uhud, rahang Rasulullah shallallahu 'alaihi wasallam retak dan pelipisnya terluka hingga wajahnya mengalirkan darah. Beliau bersabda: \"Bagaimana mungkin suatu kaum akan beruntung sedang mereka memperlakukan nabinya seperti ini, padahal ia menyeru mereka ke jalan Allah.\" lalu turunlah ayat: Tak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka, atau mengazab mereka. QS Ali Imran: 128, Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2827":{"ar":"حَدَّثَنَا أَبُو السَّائِبِ سَلْمُ بْنُ جُنَادَةَ بْنِ سَلْمٍ الْكُوفِيُّ حَدَّثَنَا أَحْمَدُ بْنُ بَشِيرٍ عَنْ عُمَرَ بْنِ حَمْزَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ اللَّهُمَّ الْعَنْ أَبَا سُفْيَانَ اللَّهُمَّ الْعَنْ الْحَارِثَ بْنَ هِشَامٍ اللَّهُمَّ الْعَنْ صَفْوَانَ بْنَ أُمَيَّةَ قَالَ فَنَزَلَتْ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ }فَتَابَ اللَّهُ عَلَيْهِمْ فَأَسْلَمُوا فَحَسُنَ إِسْلَامُهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ يُسْتَغْرَبُ مِنْ حَدِيثِ عُمَرَ بْنِ حَمْزَةَ عَنْ سَالِمٍ عَنْ أَبِيهِ وَقَدْ رَوَاهُ الزُّهْرِيُّ عَنْ سَالِمٍ عَنْ أَبِيهِ لَمْ يَعْرِفْهُ مُحَمَّدُ بْنُ إِسْمَعِيلَ مِنْ حَدِيثِ عُمَرَ بْنِ حَمْزَةَ وَعَرَفَهُ مِنْ حَدِيثِ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Abu As Sa`ib Salm bin Junadah bin Salm Al Kufi] telah menceritakan kepada kami [Ahmad bin Basyir] dari [Umar bin Hamzah] dari [Salim bin Abdullah bin Umar] dari [Ayahnya] ia mengatakan; Rasulullah shallallahu 'alaihi wasallam pernah berdoa pada perang Uhud: \"Ya Allah, laknatlah Abu Sufyan, laknatlah Al Harits bin Hisyam, ya Allah, laknatlah Shafwan bin 'Umayyah.\" lalu turunlah ayat Tak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka, atau mengazab mereka. QS Ali Imran: 128, akan tetapi Allah mengampuni mereka, akhirnya mereka pun masuk Islam, dengan keIslaman yang baik.\" Abu Isa mengatakan bahwa hadits ini hasan gharib, dinilai asing dari hadits Umar bin Hamzah dari Salim dari Ayahnya, [Az Zuhri] telah meriwayatkan dari [Salim] dari [Ayahnya], namun Muhammad bin Isma'il tidak mengetahui dari Umar bin Hamzah, dan dia hanya mengetahui dari hadits Az Zuhri."},"2828":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ الْبَصْرِيُّ حَدَّثَنَا خَالِدُ ابْنُ الْحَارِثِ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو عَلَى أَرْبَعَةِ نَفَرٍ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَالِمُونَ }فَهَدَاهُمْ اللَّهُ لِلْإِسْلَامِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ يُسْتَغْرَبُ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ نَافِعٍ عَنْ ابْنِ عُمَرَ وَرَوَاهُ يَحْيَى بْنُ أَيُّوبَ عَنْ ابْنِ عَجْلَانَ","id":"Telah menceritakan kepada kami [Yahya bin Habib bin 'Arabi Al Bashri] telah menceritakan kepada kami [Khalid bin Al Harits] dari [Muhammad bin 'Ajlan] dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam mendakwahi empat orang, kemudian Allah menurunkan ayat; Tak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka, atau mengazab mereka karena sesungguhnya mereka itu orang-orang yang zhalim. QS Ali Imran: 128, lalu Allah memberi petunjuk mereka kepada Islam.\" Abu Isa berkata; Hadits in hasan gharib shahih dan dinilai gharib melalui sanad ini dari hadits Nafi' dari Ibnu Umar. [Yahya bin Ayub] juga meriwayatkannya dari [Ibnu 'Ajlan]."},"2829":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَا��َةَ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ عَنْ عَلِيِّ بْنِ رَبِيعَةَ عَنْ أَسْمَاءَ بْنِ الْحَكَمِ الْفَزَارِيِّ قَال سَمِعْتُ عَلِيًّا يَقُولُإِنِّي كُنْتُ رَجُلًا إِذَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا نَفَعَنِي اللَّهُ مِنْهُ بِمَا شَاءَ أَنْ يَنْفَعَنِي وَإِذَا حَدَّثَنِي رَجُلٌ مِنْ أَصْحَابِهِ اسْتَحْلَفْتُهُ فَإِذَا حَلَفَ لِي صَدَّقْتُهُ وَإِنَّهُ حَدَّثَنِي أَبُو بَكْرٍ وَصَدَقَ أَبُو بَكْرٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ رَجُلٍ يُذْنِبُ ذَنْبًا ثُمَّ يَقُومُ فَيَتَطَهَّرُ ثُمَّ يُصَلِّي ثُمَّ يَسْتَغْفِرُ اللَّهَ إِلَّا غَفَرَ لَهُ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ{ وَالَّذِينَ إِذَا فَعَلُوا فَاحِشَةً أَوْ ظَلَمُوا أَنْفُسَهُمْ ذَكَرُوا اللَّهَ }إِلَى آخِرِ الْآيَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ قَدْ رَوَاهُ شُعْبَةُ وَغَيْرُ وَاحِدٍ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ فَرَفَعُوهُ وَرَوَاهُ مِسْعَرٌ وَسُفْيَانُ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ فَلَمْ يَرْفَعَاهُ وَقَدْ رَوَاهُ بَعْضُهُمْ عَنْ مِسْعَرٍ فَأَوْقَفَهُ وَرَفَعَهُ بَعْضُهُمْ وَرَوَاهُ سُفْيَانُ الثَّوْرِيُّ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ فَأَوْقَفَهُ وَلَا نَعْرِفُ لِأَسْمَاءَ بْنِ الْحَكَمِ حَدِيثًا إِلَّا هَذَا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Utsman bin Al Mughirah] dari [Ali bin Rabi'ah] dari [Asma` bin Al Hakam Al Fazari] ia berkata; Aku mendengar [Ali] berkata; Aku adalah seseorang yang bila mendengar suatu hadits dari Rasulullah shallallahu 'alaihi wasallam, Allah memanfaatkanku darinya seperti yang Ia kehendaki dan bila seseorang sahabatku menceritakan kepadaku, aku memintanya bersumpah, bila ia bersumpah, aku membenarkannya. [Abu Bakar] pernah menceritakan kepadaku, sementara Abu Bakar adalah orang yang jujur, ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang melakukan suatu dosa, kemudian berdiri, wudhu lalu shalat, setelah itu ia meminta ampun kepada Allah melainkan pasti diampuni.\" Setelah itu Abu Bakar membaca ayat ini: Dan (juga) orang-orang yang apabila mengerjakan perbuatan keji atau menganiaya diri sendiri, mereka ingat akan Allah, lalu memohon ampun terhadap dosa-dosa mereka. QS Ali Imran: 135, hingga akhir ayat. Abu Isa berkata; Hadits ini diriwayatkan oleh [Syu'bah] dan beberapa orang dari [Utsman bin Al Mughirah] dan mereka memarfu'kannya. Diriwayatkan juga oleh [Mis'ar] dan [Sufyan] dari [Utsman bin Al Mughirah], tapi keduanya tidak memarfu'kannya. Sebagian lainnya meriwayatkannya dari Mis'ar dan memauqufkannya, sementara sebagian lainnya memarfu'kannya. Sufyan Ats Tsauri meriwayatkannya dari Utsman bin Al Mughirah lalu memauqufkannya. Kami tidak mengetahui hadits Amsa` bin Al Hakam selain hadits ini."},"2830":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَال سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُمَرِضْتُ فَأَتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي وَقَدْ أُغْمِيَ عَلَيَّ فَلَمَّا أَفَقْتُ قُلْتُ كَيْفَ أَقْضِي فِي مَالِي فَسَكَتَ عَنِّي حَتَّى نَزَلَتْ{ يُوصِيكُمُ اللَّهُ فِي أَوْلَادِكُمْ لِلذَّكَرِ مِثْلُ حَظِّ الْأُنْثَيَيْنِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ غَيْرُ وَاحِدٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ حَدَّثَنَا الْفَضْلُ بْنُ الصَّبَّاحِ الْبَغْدَادِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَفِي حَدِيثِ الْفَضْلِ بْنِ الصَّبَّاحِ كَلَامٌ أَكْثَرُ مِنْ هَذَا","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Muhammad bin Al Munkadir] ia berkata; Aku mendengar [Jabir bin Abdullah] berkata; \"Rasulullah shallallahu 'alaihi wasallam datang menjengukku ketika aku sakit dan jatuh pingsan. Setelah siuman, aku bertanya; \"Bagaimana aku akan menunaikan semua hartaku?\" beliau terdiam, akhirnya turunlah ayat: Allah mensyari'atkan bagimu tentang (pembagian pusaka untuk) anak-anakmu. Yaitu, bagian seorang anak lelaki sama dengan bagian dua orang anak perempuan. QS An-Nisa`: 11. Abu Isa mengatakan bahwa hadits ini hasan shahih. Dan telah meriwayatkan lebih dari satu orang dari Muhammad bin Al Munkadir, telah menceritakan kepada kami [Al Fadlal bin Ash Shabbah] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Munkadir] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam seperti itu, dan di dalam hadits Al Fadlal bin Ash Shabbah perkataannya lebih banyak dari ini."},"2831":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى حَدَّثَنَا قَتَادَةُ عَنْ أَبِي الْخَلِيلِ عَنْ أَبِي عَلْقَمَةَ الْهَاشِمِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَلَمَّا كَانَ يَوْمُ أَوْطَاسٍ أَصَبْنَا نِسَاءً لَهُنَّ أَزْوَاجٌ فِي الْمُشْرِكِينَ فَكَرِهَهُنَّ رِجَالٌ مِنَّا فَأَنْزَلَ اللَّهُ{ وَالْمُحْصَنَاتُ مِنْ النِّسَاءِ إِلَّا مَا مَلَكَتْ أَيْمَانُكُمْ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Habban bin HIilal] telah menceritakan kepada kami [Hammam bin Yahya] telah menceritakan kepada kami [Qatadah] dari [Abu Al Khalil] dari [Abu 'Alqamah Al Hasyimi] dari [Abu Sa'id Al Khudri] ia berkata; \"Ketika terjadi perang Authas, kami menggauli para wanita (tawanan) yang memiliki suami kaum musyrikin, maka sebagian orang diantara kami membenci mereka. Lalu Allah menurunkan ayat: Dan (diharamkan juga kamu mengawini) wanita yang bersuami, kecuali budak-budak yang kamu miliki. QS An-Nisa`: 24. Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2832":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ عَنْ شُعْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْكَبَائِرِ قَالَ الشِّرْكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ وَقَتْلُ النَّفْسِ وَقَوْلُ الزُّورِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ وَرَوَاهُ رَوْحُ بْنُ عُبَادَةَ عَنْ شُعْبَةَ وَقَالَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ وَلَا يَصِحُّ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul A'la Ash Shan'ani] telah menceritakan kepada kami [Khalid bin Al Harits] dari [Syu'bah] telah menceritakan kepada kami ['Ubaidullah bin Abu Bakar bin Anas] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam beliau bersabda tentang dosa-dosa besar, beliau bersabda: \"Mempersekutukan Allah, durhaka kepada kedua orang tua, bunuh diri, dan perkataan dusta.\" Abu Isa mengatakan bahwa hadits ini hasan shahih gharib. Dan [Rauh bin Ubadah] telah meriwayatkannya dari [Syu'bah] dan dia berkata dari [Abdullah bin Abu Bakar] dan tidak tidak shahih."},"2833":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ بَصْرِيٌّ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُحَدِّثُكُمْ بِأَكْبَرِ الْكَبَائِرِ قَالُوا بَلَى يَا رَسُولَ اللَّهِ قَالَ الْإِشْرَاكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ قَالَ وَجَلَسَ وَكَانَ مُتَّكِئًا قَالَ وَشَهَادَةُ الزُّورِ أَوْ قَالَ قَوْلُ الزُّورِ قَالَ فَمَا زَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُهَا حَتَّى قُلْنَا لَيْتَهُ سَكَتَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah Bashri] telah menceritakan kepada kami [Bisyr bin Al Mufadlal] telah menceritakan kepada kami [Al Jurairi] dari [Abdurrahman bin Abu Bakrah] dari [Ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah aku beritahukan kepada kalian tentang dosa-dosa yang paling besar?\" para sahabat menjawab; \"Tentu, wahai Rasulullah!\" Beliau bersabda: \"Mempersekutukan Allah, durhaka kepada kedua orang tua, -beliau yang tadinya bersandar kemudian duduk dan melanjutkan sabdanya- kesaksian palsu atau bersabda; perkataan dusta, \" Rasulullah shallallahu 'alaihi wasallam terus saja menyebut hal itu sampai kami berharap beliau menghentikannya. Abu Isa mengatakan bahwa hadits ini hasan shahih gharib."},"2834":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ هِشَامِ بْنِ سَعْدٍ عَنْ مُحَمَّدِ بْنِ زَيْدِ بْنِ مُهَاجِرِ بْنِ قُنْفُذٍ الْتَّيْمِيِّ عَنْ أَبِي أُمَامَةَ الْأَنْصَارِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أُنَيْسٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَكْبَرِ الْكَبَائِرِ الشِّرْكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ وَالْيَمِينُ الْغَمُوسُ وَمَا حَلَفَ حَالِفٌ بِاللَّهِ يَمِينَ صَبْرٍ فَأَدْخَلَ فِيهَا مِثْلَ جَنَاحِ بَعُوضَةٍ إِلَّا جُعِلَتْ نُكْتَةً فِي قَلْبِهِ إِلَى يَوْمِ الْقِيَامَةِقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَأَبُو أُمَامَةَ الْأَنْصَارِيُّ هُوَ ابْنُ ثَعْلَبَةَ وَلَا نَعْرِفُ اسْمَهُ وَقَدْ رَوَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَادِيثَ","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Hisyam bin Sa'd] dari [Muhammad bin Zaid bin Muhajir bin Qunfudz At Taimi] dari [Abu Umamah Al Anshari] dari [Abdullah bin Unais al Juhany] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya diantara dosa paling besar di antara dosa-dosa besar adalah mempersekutukan Allah, durhaka kepada kedua orang tua, sumpah yang menjerumuskan pelakunya ke neraka (palsu), dan sumpah yang dijadikan oleh seseorang untuk bersumpah karena terpaksa, dan ia menganggap (remeh) layaknya sayap seekor nyamuk, kecuali (sumpahnya) itu akan dijadikan noda hitam dalam hatinya sampai hari kiamat.\" Abu Isa mengatakan bahwa hadits ini hasan shahih gharib."},"2835":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أُمِّ سَلَمَةَ أَنَّهَا قَالَتْيَغْزُو الرِّجَالُ وَلَا تَغْزُو النِّسَاءُ وَإِنَّمَا لَنَا نِصْفُ الْمِيرَاثِ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ وَلَا تَتَمَنَّوْا مَا فَضَّلَ اللَّهُ بِهِ بَعْضَكُمْ عَلَى بَعْضٍ }قَالَ مُجَاهِدٌ وَأَنْزَلَ فِيهَا{ إِنَّ الْمُسْلِمِينَ وَالْمُسْلِمَاتِ }وَكَانَتْ أُمُّ سَلَمَةَ أَوَّلَ ظَعِينَةٍ قَدِمَتْ الْمَدِينَةَ مُهَاجِرَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ مُرْسَلٌ وَرَوَاهُ بَعْضُهُمْ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ مُرْسَلٌ أَنَّ أُمَّ سَلَمَةَ قَالَتْ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] dari [Ummu Salamah] ia berkata; \"Laki-laki pergi berperang, sedangkan wanita tidak berperang, dan (bagian) kami hanya setengah dari harta warisan.\" lalu Allah menurunkan Dan janganlah kamu iri hati terhadap apa yang dikaruniakan Allah kepada sebahagian kamu lebih banyak dari sebahagian yang lain QS An-Nisa`: 32, Mujahid mengatakan; Berkenaan dengan hal itu, ayat berikut turun Sesungguhnya laki-laki dan perempuan yang muslim, laki-laki dan perempuan yang mu'min. QS An-Nisa`: 35, Ummu Salamah adalah seorang wanita pertama kali ikut berhijrah ke Madinah. Abu Isa mengatakan bahwa hadits ini mursal."},"2836":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ رَجُلٍ مِنْ وَلَدِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْيَا رَسُولَ اللَّهِ لَا أَسْمَعُ اللَّهَ ذَكَرَ النِّسَاءَ فِي الْهِجْرَةِ فَأَنْزَلَ اللَّهُ تَعَالَى{ أَنِّي لَا أُضِيعُ عَمَلَ عَامِلٍ مِنْكُمْ مِنْ ذَكَرٍ أَوْ أُنْثَى بَعْضُكُمْ مِنْ بَعْضٍ }","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari [seseorang] anak Ummu Salamah, dari [Ummu Salamah] ia berkata; \"Wahai Rasulullah, aku tidak mendengar Allah menyebut kaum wanita dalam hijrah.\" Lalu Allah Ta'ala menurunkan Maka Rabb mereka memperkenankan permohonannya (dengan berfirman): 'Sesungguhnya Aku tidak menyia-nyiakan amal orang-orang yang beramal di antara kamu, baik laki-laki atau perempuan, (karena) sebagian kamu adalah turunan dari sebagian yang lain. QS Ali Imran: 195."},"2837":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ فَقُلْتُ يَا رَسُولَ اللَّهِ أَقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ إِنِّي أُحِبُّ أَنْ أَسْمَعَهُ مِنْ غَيْرِي فَقَرَأْتُ سُورَةَ النِّسَاءِ حَتَّى إِذَا بَلَغْتُ{ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }قَالَ فَرَأَيْتُ عَيْنَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَهْمِلَانِقَالَ أَبُو عِيسَى هَذَا أَصَحُّ مِنْ حَدِيثِ أَبِي الْأَحْوَصِ حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ نَحْوَ حَدِيثِ مُعَاوِيَةَ بْنِ هِشَامٍ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] telah menceritakan kepada kami [Sufyan Ats Tsauri] dari [Al A'masy] dari [Ibrahim] dari ['Abidah] dari [Abdullah] ia berkata; Rasulullah Shallallahu 'alahi wasallam bersabda kepadaku: \"Bacalah (al Qur'an) untukku.\" Aku menjawab; \"Wahai Rasulullah, haruskah aku membacanya, sementara (Al Qur'an) diturunkan kepadamu?\" beliau bersabda: \"Aku lebih senang mendengarnya dari orang lain.\" lalu kubaca surat an Nisa`, ketika sampai pada ayat Dan Kami mendatangkan kamu (Muhammad) sebagai saksi atas mereka itu (sebagai umatmu). QS An-Nisa`: 41, kulihat kedua matanya berlinang air mata.\" Abu Isa berkata; Hadits ini lebih shahih dari hadits Al Ahwash. Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengabarkan kepada kami [Ibnu Al Mubarak] dari [Sufyan] dari [Al A'masy] seperti hadits Mu'awiyah bin Hisyam."},"2838":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدٍ عَنْ أَبِي جَعْفَرٍ الرَّازِيِّ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَصَنَعَ لَنَا عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ طَعَامًا فَدَعَانَا وَسَقَانَا مِنْ الْخَمْرِ فَأَخَذَتْ الْخَمْرُ مِنَّا وَحَضَرَتْ الصَّلَاةُ فَقَدَّمُونِي فَقَرَأْتُ قُلْ يَا أَيُّهَا الْكَافِرُونَ لَا أَعْبُدُ مَا تَعْبُدُونَ وَنَحْنُ نَعْبُدُ مَا تَعْبُدُونَ قَالَ فَأَنْزَلَ اللَّهُ تَعَالَى{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى حَتَّى تَعْلَمُوا مَا تَقُولُونَ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Abdurahman bin Sa'd] dari [Abu Ja'far Ar Razi] dari [Atha` bin As Sa`ib] dari [Abu Abdurrahman As Sulami] dari [Ali bin Abu Thalib] ia berkata; \"Abdurrahman bin 'Auf pernah membuatkan makanan dan menyajikan khamr untuk kami, sampai kami (mabuk) karenanya. Ketika waktu shalat telah tiba, mereka mendorongku (menjadi imam), kemudian aku membaca; Katakanlah (Muhammad): Hai orang-orang kafir, aku tidak akan menyembah apa yang kalian sembah, dan kami akan menyembah apa yang kalian sembah.\" lalu Allah menurunkan (ayat): \"Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk, sehingga kamu mengerti apa yang kamu ucapkan.\" QS An-Nisa`: 43. Abu Isa mengatakan bahwa hadits ini hasan shahih gharib."},"2839":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّهُ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ حَدَّثَهُأَنَّ رَجُلًا مِنْ الْأَنْصَارِ خَاصَمَ الزُّبَيْرَ فِي شِرَاجِ الْحَرَّةِ الَّتِي يَسْقُونَ بِهَا النَّخْلَ فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرُّ فَأَبَى عَلَيْهِ فَاخْتَصَمُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلزُّبَيْرِ اسْقِ يَا زُبَيْرُ وَأَرْسِلْ الْمَاءَ إِلَى جَارِكَ فَغَضِبَ الْأَنْصَارِيُّ وَقَالَ يَا رَسُولَ اللَّهِ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَغَيَّرَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا زُبَيْرُ اسْقِ وَاحْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجُدُرِ فَقَالَ الزُّبَيْرُ وَاللَّهِ إِنِّي لَأَحْسِبُ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }الْآيَةَقَالَ أَبُو عِيسَى سَمِعْت مُحَمَّدًا يَقُولُ قَدْ رَوَى ابْنُ وَهْبٍ هَذَا الْحَدِيثَ عَنْ اللَّيْثِ بْنِ سَعْدٍ وَيُونُسُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ نَحْوَ هَذَا الْحَدِيثِ وَرَوَى شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ الزُّبَيْرِ وَلَمْ يَذْكُرْ فِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari ['Urwah bin Zubair] menceritakan bahwa [Abdullah bin Zubair] bercerita kepadanya, bahwa seorang Anshar bersengketa dengan Zubair tentang aliran air untuk dipakai menyirami pohon kurma, orang Anshar itu berkata; \"Biarkan air itu mengalir.\" Namun Zubair enggan (tidak menghiraukannya). Kemudian mereka mengadu kepada Rasulullah Shallallahu 'alahi wasallam, beliau bersabda kepada Zubair: \"Wahai Zubair siramlah, dan alirkanlah air kepada tetanggamu.\" Orang Anshar itu marah dan berkata; \"Wahai Rasulullah, apa dia sepupu anda?\" (mendengar hal itu) berubahlah wajah beliau sambil bersabda: \"Wahai Zubair, siramlah dan tahanlah air itu kembali ke kebun.\" Demi Allah aku menganggap ayat ini turun berkaitan dengan peristiwa itu, Maka demi Rabbmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan. QS An-Nisa`: 65. Abu Isa berkata; \"Aku mendengar Muhammad berkata; [Ibnu Wahab] meriwayatkan hadits ini dari [Al Laits bin Sa'd] dan [Yunus] dari [Az Zuhri] dari ['Urwah] dari [Abdullah bin Az Zubair] seperti hadits ini. [Syu'aib bin Abu Hamzah] meriwayatkan dari [Az Zuhri] dari ['Urwah] dari [Az Zubair] tanpa menyebut: \"Dari Abdullah bin Az Zubair.\""},"2840":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ مِسْعَرٍ وَغَيْرِهِ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ قَالَقَالَ رَجُلٌ مِنْ الْيَهُودِ لِعُمَرَ بْنِ الْخَطَّابِ يَا أَمِيرَ الْمُؤْمِنِينَ لَوْ عَلَيْنَا أُنْزِلَتْ هَذِهِ الْآيَةَ{ الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ وَأَتْمَمْتُ عَلَيْكُمْ نِعْمَتِي وَرَضِيتُ لَكُمْ الْإِسْلَامَ دِينًا }لَاتَّخَذْنَا ذَلِكَ الْيَوْمَ عِيدًا فَقَالَ لَهُ عُمَرُ بْنُ الْخَطَّابِ أَنِّي أَعْلَمُ أَيَّ يَوْمٍ أُنْزِلَتْ هَذِهِ الْآيَةُ أُنْزِلَتْ يَوْمَ عَرَفَةَ فِي يَوْمِ الْجُمُعَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Mis'ar] dan yang lain dari [Qais bin Muslim] dari [Thariq bin Syihab] ia berkata; \"Seorang yahudi berkata kepada [Umar bin Khattab]; \"Ya amirul mukminin, sekiranya ayat Pada hari ini telah Kusempurnakan untuk kamu agamamu, dan telah Ku-cukupkan kepadamu ni'mat-Ku, dan telah Ku-ridhai Islam itu jadi agama bagimu. ini turun kepada kami, pasti kami jadikan hari (turunnya) itu sebagai hari raya.\" Umar menjawab; \"Aku tahu betul kapan ayat ini diturunkan, ia diturunkan pada hari 'Arafah yang bertepatan dengan hari Jum'at.\" Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2841":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَمَّارِ بْنِ أَبِي عَمَّارٍ قَالَقَرَأَ ابْنُ عَبَّاسٍ{ الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ وَأَتْمَمْتُ عَلَيْكُمْ نِعْمَتِي وَرَضِيتُ لَكُمْ الْإِسْلَامَ دِينًا }وَعِنْدَهُ يَهُودِيٌّ فَقَالَ لَوْ أُنْزِلَتْ هَذِهِ عَلَيْنَا لَاتَّخَذْنَا يَوْمَهَا عِيدًا قَالَ ابْنُ عَبَّاسٍ فَإِنَّهَا نَزَلَتْ فِي يَوْمِ عِيدٍ فِي يَوْمِ جُمْعَةٍ وَيَوْمِ عَرَفَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammad bin Salamah] dari ['Ammar bin Abu 'Ammar] ia berkata; [Ibnu Abbas] pernah membaca: Pada hari ini telah Kusempurnakan untuk kamu agamamu, dan telah Ku-cukupkan kepadamu ni'mat-Ku, dan telah Ku-ridhai Islam itu jadi agama bagimu, sedang di sampingnya ada seorang yahudi yang mengatakan; \"Seandainya ayat ini turun kepada kami, pasti kami jadikan hari (turunnya) itu sebagai hari raya.\" Ibnu Abbas menjawab; \"Sesungguhnya ayat ini turun pada hari raya yaitu hari Jum'at pada hari 'Arafah.\" Abu Isa mengatakan bahwa hadits ini hasan gharib."},"2842":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمِينُ الرَّحْمَنِ مَلْأَى سَحَّاءُ لَا يُغِيضُهَا اللَّيْلُ وَالنَّهَارُ قَالَ أَرَأَيْتُمْ مَا أَنْفَقَ مُنْذُ خَلَقَ السَّمَوَاتِ وَالْأَرْضَ فَإِنَّهُ لَمْ يَغِضْ مَا فِي يَمِينِهِ وَعَرْشُهُ عَلَى الْمَاءِ وَبِيَدِهِ الْأُخْرَى الْمِيزَانُ يَرْفَعُ وَيَخْفِضُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَتَفْسِيرُ هَذِهِ الْآيَةِ{ وَقَالَتْ الْيَهُودُ يَدُ اللَّهِ مَغْلُولَةٌ غُلَّتْ أَيْدِيهِمْ وَلُعِنُوا بِمَا قَالُوا بَلْ يَدَاهُ مَبْسُوطَتَانِ يُنْفِقُ كَيْفَ يَشَاءُ }وَهَذَا حَدِيثٌ قَدْ رَوَتْهُ الْأَئِمَّةُ نُؤْمِنُ بِهِ كَمَا جَاءَ مِنْ غَيْرِ أَنْ يُفَسَّرَ أَوْ يُتَوَهَّمَ هَكَذَا قَالَ غَيْرُ وَاحِدٍ مِنْ الْأَئِمَّةِ مِنْهِمْ سُفْيَانُ الثَّوْرِيُّ وَمَالِكُ بْنُ أَنَسٍ وَابْنُ عُيَيْنَةَ وَابْنُ الْمُبَارَكِ أَنَّهُ تُرْوَى هَذِهِ الْأَشْيَاءُ وَيُؤْمَنُ بِهَا وَلَا يُقَالُ كَيْفَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] ia berkata; Rasulullah Shallallahu 'alahi wasallam bersabda: \"Tangan kanan Ar Rahman kaya dengan rizki dan berkah yang tak akan pernah berkurang karena siang maupun malam. Tahukah kalian apa saja yang telah didinfakanNya sejak pertama kali langit dan bumi ini diciptakan? sesungguhnya semua yang berada di tangan kananNya tidak berkurang, 'Arsy Nya diatas air dan tangan lainnya terdapat timbangan (rizki) yang sesekali naik dan terkadang turun.\" Abu Isa mengatakan; Hadit ini Hadits ini hasan shahih, dan tafsir dari ayat Orang-orang Yahudi berkata; 'Tangan Allah terbelenggu, sebenarnya tangan merekalah yang dibelenggu dan merekalah yang dila'nat disebabkan apa yang telah mereka katakan itu. (Tidak demikian), tetapi kedua-dua tangan Allah terbuka; Dia menafkahkan sebagaimana Dia kehendaki QS Al Ma`idah: 64. Hadits ini diriwayatkan oleh para imam, kami mengimaninya apa adanya, tanpa ditafsirkan atau diperkirakan. Demikianlah yang di riwayatkan dari beberapa imam seperti Sufyan Ats Tsauri, Malik bin Anas, Ibnu 'Uyainah dan Ibnu Al Mubarak, mereka berkata; \"Semua itu diriwayatkan dan di imani tanpa ditanyakan bagaimananya.\""},"2843":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شَرِيكٌ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا وَقَعَتْ بَنُو إِسْرَائِيلَ فِي الْمَعَاصِي نَهَتْهُمْ عُلَمَاؤُهُمْ فَلَمْ يَنْتَهُوا فَجَالَسُوهُمْ فِي مَجَالِسِهِمْ وَوَاكَلُوهُمْ وَشَارَبُوهُمْ فَضَرَبَ اللَّهُ قُلُوبَ بَعْضِهِمْ بِبَعْضٍ وَلَعَنَهُمْ{ عَلَى لِسَانِ دَاوُدَ وَعِيسَى ابْنِ مَرْيَمَ ذَلِكَ بِمَا عَصَوْا وَكَانُوا يَعْتَدُونَ }قَالَ فَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ مُتَّكِئًا فَقَالَ لَا وَالَّذِي نَفْسِي بِيَدِهِ حَتَّى تَأْطُرُوهُمْ عَلَى الْحَقِّ أَطْرًاقَالَ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ قَالَ يَزِيدُ وَكَانَ سُفْيَانُ الثَّوْرِيُّ لَا يَقُولُ فِيهِ عَنْ عَبْدِ اللَّهِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ مُحَمَّدِ بْنِ مُسْلِمِ بْنِ أَبِي الْوَضَّاحِ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَبَعْضُهُمْ يَقُولُ عَنْ أَبِي عُبَيْدَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلٌ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Syarik] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dari [Abdullah bin Mas'ud] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saat Bani Isra`il bergelimang dengan kemaksiatan-kemaksiatan, maka para ulama mereka melarang mereka, namun mereka tidak juga jera. Lalu para ulama mereka menemani mereka di majlis-majlis mereka, turut makan dan minum bersama mereka, lalu Allah mencampur adukkan hati mereka satu sama lain dan melaknat mereka melalui lisan Dawud dan Isa putra Maryam, itu karena mereka durhaka dan melanggar QS Al Ma`idah; 78. Ibnu Mas'ud berkata; Lalu Rasulullah shallallahu 'alaihi wasallam duduk bersandar kemudian bersabda: \"Demi Dzat yang jiwaku berada ditanganNya, hingga mereka benar-benar membelot di atas kebenaran.\" Abdullah bin Abdurrahman berkata; Yazid berkata; Sufyan Ats Tsauri tidak mengatakan; \"Dari Abdullah.\" Abu Isa berkata; Hadits ini hasan gharib. Hadits ini juga diriwayatkan dari [Muhammad bin Muslim bin Abu Al Wadlah] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas. Sebagian dari mereka berkata; Dari 'Ubaidah dari Nabi shallallahu 'alaihi wasallam secara mursal."},"2844":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَنِي إِسْرَائِيلَ لَمَّا وَقَعَ فِيهِمْ النَّقْصُ كَانَ الرَّجُلُ فِيهِمْ يَرَى أَخَاهُ عَلَى الذَّنْبِ فَيَنْهَاهُ عَنْهُ فَإِذَا كَانَ الْغَدُ لَمْ يَمْنَعْهُ مَا رَأَى مِنْهُ أَنْ يَكُونَ أَكِيلَهُ وَشَرِيبَهُ وَخَلِيطَهُ فَضَرَبَ اللَّهُ قُلُوبَ بَعْضِهِمْ بِبَعْضٍ وَنَزَلَ فِيهِمْ الْقُرْآنُ فَقَالَ{ لُعِنَ الَّذِينَ كَفَرُوا مِنْ بَنِي إِسْرَائِيلَ عَلَى لِسَانِ دَاوُدَ وَعِيسَى ابْنِ مَرْيَمَ ذَلِكَ بِمَا عَصَوْا وَكَانُوا يَعْتَدُونَ فَقَرَأَ حَتَّى بَلَغَ وَلَوْ كَانُوا يُؤْمِنُونَ بِاللَّهِ وَالنَّبِيِّ وَمَا أُنْزِلَ إِلَيْهِ مَا اتَّخَذُوهُمْ أَوْلِيَاءَ وَلَكِنَّ كَثِيرًا مِنْهُمْ فَاسِقُونَ }قَالَ وَكَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئًا فَجَلَسَ فَقَالَ لَا حَتَّى تَأْخُذُوا عَلَى يَدِ الظَّالِمِ فَتَأْطُرُوهُ عَلَى الْحَقِّ أَطْرًاحَدَّثَنَا بُنْدَارٌ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ وَأَمْلَاهُ عَلَيَّ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمِ بْنِ أَبِي الْوَضَّاحِ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Bundar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Ali bin Badzimah] dari [Abu Ubaidah] ia berkata; Rasulullah Shallallahu 'alahi wasallam bersabda: \"Ketika Bani Israil ditimpa kekurangan, salah seorang di antara mereka melihat saudaranya melakukan dosa, lalu ia mencegahnya, akan tetapi keesokan harinya ia tidak melarang dari apa yang telah dilihatnya (kemarin), bahkan ia menemaninya makan, minum, dan bergaul. Lalu Allah mencampur adukkan hati mereka satu sama lain, dan Allah menurunkan ayat tentang mereka: Telah dila'nati orang-orang kafir dari Bani Israil dengan lisan Daud dan 'Isa putra Maryam. Yang demikian itu, disebabkan mereka durhaka dan selalu melampaui batas Beliau membaca hingga sampai firmanNya: Sekiranya mereka beriman kepada Allah, kepada nabi (Musa) dan kepada apa yang diturunkan kepadanya (Nabi), niscaya mereka tidak akan mengambil orang-orang musyrikin itu menjadi penolong-penolong, tapi kebanyakan dari mereka adalah orang-orang yang fasik. QS Al Ma`idah; 78-81. Rasulullah Shallallahu 'alahi wasallam yang tadinya bersandar, kemudian beliau duduk dan bersabda: \"Tidak, (kalian tidak akan luput dari apa yang mereka alami) sehingga kalian mangarahkan orang dzalim lalu kalian benar-benar membelokkannya di atas kebenaran.\" Telah menceritakan kepada kami [Bundar] telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] dan ia mengimlakkannya kepadaku. Telah menceritakan kepada kami [Muhammad bin Muslim bin Abu Al Wadlah] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"2845":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ أَبِي مَيْسَرَةَ عَنْ عُمَرَ بْنِ الْخَطَّابِ أَنَّهُ قَالَاللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ }الْآيَةَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ ثُمَّ قَالَ اللَّهُمَّ بَيِّنَ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا يُرِيدُ الشَّيْطَانُ أَنْ يُوقِعَ بَيْنَكُمْ الْعَدَاوَةَ وَالْبَغْضَاءَ فِي الْخَمْرِ وَالْمَيْسِرِ إِلَى قَوْلِهِ فَهَلْ أَنْتُمْ مُنْتَهُونَ }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ انْتَهَيْنَا انْتَهَيْنَاقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ إِسْرَائِيلَ هَذَا الْحَدِيثُ مُرْسَلٌ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَمْرِو بْنِ شُرَحْبِيلَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَذَكَرَ نَحْوَهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ مُحَمَّدِ بْنِ يُوسُفَ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Muhammad bin Yusuf] telah mengabarkan kepada kami [Isra`il] telah menceritakan kepada kami [Abu Ishaq] dari ['Amru bin Syurahbil Abu Maisarah] dari [Umar bin Al Khaththab] ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Baqarah; Mereka bertanya kepadamu tentang khamer dan judi. QS Al Baqarah: 219, lalu Umar dipanggil dan dibacakan kepadanya. Setelah itu ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat An Nisa` Hai orang-orang yang beriman, janganlah kamu mendekati shalat sedang kamu mabuk QS An Nisa`: 43. Selanjutnya ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Mai`idah Sesungguhnya syaitan itu bermaksud hendak menimbulkan permusuhan dan kebencian di antara kamu lantaran (meminum) khamar dan berjudi itu, -sampai firmanNya- maka berhentilah kamu (dari mengerjakan pekerjaan itu) QS Al Ma`idah: 91. Umar lalu berkata; \"Kami berhenti, kami berhenti.\" Abu Isa berkata; Hadits ini juga diriwayatkan dari Isra`il secara mursal. Telah menceritakan kepada kami [Muhammad bin Al Ala`] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari [Abu Maisarah 'Amru bin Syurahbil] bahwa [Umar bin Al Khaththab] berkata; \"Ya Allah, Ya Allah, berilah kami penjelasan tentang khamar dengan penjelasan yang memadai.\" Lalu ia menyebutkan seperti di atas, namun hadits ini lebih shahih dari hadits Muhammad bin Yusuf."},"2846":{"ar":"حَدَّثَنَا بِذَلِكَ بُنْدَارٌ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ قَالَ الْبَرَاءُمَاتَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ يَشْرَبُونَ الْخَمْرَ فَلَمَّا نَزَلَ تَحْرِيمُهَا قَالَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَيْفَ بِأَصْحَابِنَا الَّذِينَ مَاتُوا وَهُمْ يَشْرَبُونَهَا فَنَزَلَتْ{ لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا }الْآيَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Bundar] seperti itu, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata; [Al Barra`] berkata; \"Sebagian sahabat Nabi Shallallahu 'alahi wasallam meninggal dunia sedangkan mereka suka meminum khamr, ketika turun (ayat) yang mengharamkannya, sebagian sahabat bertanya; \"Bagaimana dengan sahabat-sahabat kami, mereka meninggal sementara mereka suka meminumnya (khamar)?\" Maka turunlah ayat Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan yang shalih karena memakan makanan yang telah mereka makan dahulu, apabila mereka bertakwa serta beriman, dan mengerjakan amalan-amalan yang Shalih. QS Al Ma`idah: 93. Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2847":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي رِزْمَةَ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالُوا يَا رَسُولَ اللَّهِ أَرَأَيْتَ الَّذِينَ مَاتُوا وَهُمْ يَشْرَبُونَ الْخَمْرَ لَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ فَنَزَلَتْ{ لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا إِذَا مَا اتَّقَوْا وَآمَنُوا وَعَمِلُوا الصَّالِحَاتِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Abdul Aziz bin Abu Rizmah] dari [Isra`il] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Para sahabat bertanya; \"Wahai Rasulullah, bagaimana menurut anda mengenai orang-orang yang telah meninggal, sementara mereka dulu meminum khamar saat pengharaman khamar belum turun?, \" Lalu turun ayat Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan yang shalih karena memakan makanan yang telah mereka makan dahulu, apabila mereka bertakwa serta beriman, dan mengerjakan amalan-amalan yang Shalih QS Al Ma`idah: 93. Abu Isa berkata; Hadits ini hasan shahih."},"2848":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ أَبُو حَفْصٍ الْفَلَّاسُ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا عُثْمَانُ بْنُ سَعْدٍ حَدَّثَنَا عِكْرِمَةُ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي إِذَا أَصَبْتُ اللَّحْمَ انْتَشَرْتُ لِلنِّسَاءِ وَأَخَذَتْنِي شَهْوَتِي فَحَرَّمْتُ عَلَيَّ اللَّحْمَ فَأَنْزَلَ اللَّهُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تُحَرِّمُوا طَيِّبَاتِ مَا أَحَلَّ اللَّهُ لَكُمْ وَلَا تَعْتَدُوا إِنَّ اللَّهَ لَا يُحِبُّ الْمُعْتَدِينَ وَكُلُوا مِمَّا رَزَقَكُمْ اللَّهُ حَلَالًا طَيِّبًا }قَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَرَوَاهُ بَعْضُهُمْ عَنْ عُثْمَانَ بْنِ سَعْدٍ مُرْسَلًا لَيْسَ فِيهِ عَنْ ابْنِ عَبَّاسٍ وَرَوَاهُ خَالِدٌ الْحَذَّاءُ عَنْ عِكْرِمَةَ مُرْسَلًا","id":"Telah menceritakan kepada kami ['Amru bin Ali Abu Hafsh Al Fallas] telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Utsman bin Sa'd] telah menceritakan kepada kami [Ikrimah] dari [Ibnu Abbas] bahwa seseorang datang menemui Nabi shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, apabila aku memakan daging, lalu aku bertebaran ke kaum hawa, maka syahwatku akan mengendalikan diriku, oleh karena itu aku mengharamkan daging pada diriku.\" Maka Allah menurunkan ayat Hai orang-orang yang beriman, janganlah kamu haramkan apa-apa yang baik yang telah Allah halalkan bagi kamu, dan janganlah kamu melampaui batas. Sesungguhnya Allah tidak menyukai orang-orang yang melampaui batas. Dan makanlah makanan yang halal lagi baik dari apa yang Allah telah rizkikan kepadamu. QS Al Maa`idah: 87-88. Abu Isa berkata; Hadits ini hasan gharib. Dan sebagian dari mereka meriwayatkannya dari Utsman bin Sa'd secara mursal tanpa menyebutkan; \"Dari Ibnu Abbas.\" [Khalid Al Hadza'] juga meriwayatkannya dari [Ikrimah] secara mursal."},"2849":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا مُنْصُورُ بْنُ وَرْدَانَ عَنْ عَلِيِّ بْنِ عَبْدِ الْأَعْلَى عَنْ أَبِيهِ عَنْ أَبِي الْبَخْتَرِيِّ عَنْ عَلِيٍّ قَالَلَمَّا نَزَلَتْ{ وَلِلَّهِ عَلَى النَّاسِ حِجُّ الْبَيْتِ مَنْ اسْتَطَاعَ إِلَيْهِ سَبِيلًا }قَالُوا يَا رَسُولَ اللَّهِ فِي كُلِّ عَامٍ فَسَكَتَ قَالُوا يَا رَسُولَ اللَّهِ فِي كُلِّ عَامٍ قَالَ لَا وَلَوْ قُلْتُ نَعَمْ لَوَجَبَتْ فَأَنْزَلَ اللَّهُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَسْأَلُوا عَنْ أَشْيَاءَ إِنْ تُبْدَ لَكُمْ تَسُؤْكُمْ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ عَلِيٍّ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Abu Sa'id Al Asyaj] telah menceritakan kepada kami [Manshur bin Wardan] dari [Ali bin Abdul A'la] dari [Ayahnya] dari [Abu al Bakhtari] dari [Ali] ia berkata; Tatkala turun ayat Mengerjakan haji adalah kewajiban manusia terhadap Allah, yaitu (bagi) orang yang sanggup mengadakan perjalanan ke Baitullah QS Ali Imran: 97, para sahabat bertanya; \"Wahai Rasulullah, apakah (dilakukan) setiap tahun?\" Beliau terdiam, mereka bertanya lagi; \"Wahai Rasulullah, apakah (dilakukan) setiap tahun?\" beliau menjawab: \"Tidak, seandainya tadi kujawab ya, pasti akan menjadi wajib (hukumnya).\" Lalu Allah menurunkan Hai orang-orang yang beriman, janganlah kamu menanyakan (kepada Nabimu) hal-hal yang jika diterangkan kepadamu akan menyusahkan Kamu. QS Al Mai`idah: 101. Abu Isa mengatakan bahwa hadits ini hasan gharib."},"2850":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ نَاجِيَةَ بْنِ كَعْبٍ عَنْ عَلِيٍّأَنَّ أَبَا جَهْلٍ قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا لَا نُكَذِّبُكَ وَلَكِنْ نُكَذِّبُ بِمَا جِئْتَ بِهِ فَأَنْزَلَ اللَّهُ تَعَالَى{ فَإِنَّهُمْ لَا يُكَذِّبُونَكَ وَلَكِنَّ الظَّالِمِينَ بِآيَاتِ اللَّهِ يَجْحَدُونَ }حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ نَاجِيَةَ أَنَّ أَبَا جَهْلٍ قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ وَلَمْ يَذْكُرْ فِيهِ عَنْ عَلِيٍّ وَهَذَا أَصَحُّ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dari [Sufyan] dari [Abu Ishaq] dari [Najiyah bin Ka'ab] dari [Ali] bahwa Abu Jahal pernah berkata kepada Nabi shallallahu 'alaihi wasallam; \"Sesungguhnya kami tidak mendustakanmu, tapi kami mendustakan (agama) yang kamu bawa.\" Lalu Allah Ta'ala menurunkan Karena mereka sebenarnya bukan mendustakan kamu, akan tetapi orang-orang yang zhalim itu mengingkari ayat-ayat Allah QS Al An'am: 33. Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Abu Ishaq] dari [Najiyah] bahwa Abu Jahal pernah berkata kepada Nabi shallallahu 'alaihi wasallam, lalu ia menyebut seperti hadits di atas, tapi tidak menyebutkan; \"Dari Ali.\" Dan ini lebih shahih."},"2851":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُلَمَّا نَزَلَتْ هَذِهِ الْآيَةَ{ قُلْ هُوَ الْقَادِرُ عَلَى أَنْ يَبْعَثَ عَلَيْكُمْ عَذَابًا مِنْ فَوْقِكُمْ أَوْ مِنْ تَحْتِ أَرْجُلِكُمْ }قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعُوذُ بِوَجْهِكَ فَلَمَّا نَزَلَتْ{ أَوْ يَلْبِسَكُمْ شِيَعًا وَيُذِيقَ بَعْضَكُمْ بَأْسَ بَعْضٍ }قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَاتَانِ أَهْوَنُ أَوْ هَاتَانِ أَيْسَرُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dia mendengar [Jabir bin Abdullah] ia berkata: \"Ketika turun ayat ini Katakanlah: 'Dialah yang berkuasa untuk mengirimkan azab kepadamu dari atas kamu atau dari bawah kakimu QS Al Ma`idah: 65, Rasulullah Shallallahu 'alahi wasallam berdoa: \"Ya Allah aku berlindung dengan wajah-Mu, \" akan tetapi ketika turun Atau dia mencampurkan kamu dalam golongan-golongan (yang saling bertentangan) dan merasakan kepada sebahagian kamu keganasan sebahagian yang lain QS Al An'aam: 65, beliau bersabda: \"Dua ayat ini lebih ringan atau dua ayat ini lebih mudah.\" Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2852":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ أَبِي بَكْرِ بْنِ أَبِي مَرْيَمَ الْغَسَّانِيِّ عَنْ رَاشِدِ بْنِ سَعْدٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذِهِ الْآيَةِ{ قُلْ هُوَ الْقَادِرُ عَلَى أَنْ يَبْعَثَ عَلَيْكُمْ عَذَابًا مِنْ فَوْقِكُمْ أَوْ مِنْ تَحْتِ أَرْجُلِكُمْ }فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّهَا كَائِنَةٌ وَلَمْ يَأْتِ تَأْوِيلُهَا بَعْدُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Arafah] telah menceritakan kepada kami [Isma'il bin Ayyasy] dari [Abu Bakr bin Abu Maryam Al Ghassani] dari [Rasyid bin Sa'd] dari [Sa'd bin Abu Waqqash] dari Nabi shallallahu 'alaihi wasallam berkenaan dengan ayat ini Katakanlah: 'Dialah yang berkuasa untuk mengirimkan azab kepadamu, dari atas kamu atau dari bawah kakimu QS Al Ma`idah: 65, beliau bersabda: \"Ingatlah, sesungguhnya itu akan terjadi, sementara penjelasannya belum tiba sama sekali.\" Abu Isa mengatakan bahwa hadits ini hasan gharib."},"2853":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا نَزَلَتْ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }شَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَقَالُوا يَا رَسُولَ اللَّهِ وَأَيُّنَا لَا يَظْلِمُ نَفْسَهُ قَالَ لَيْسَ ذَلِكَ إِنَّمَا هُوَ الشِّرْكُ أَلَمْ تَسْمَعُوا مَا قَالَ لُقْمَانُ لِابْنِهِ{ يَا بُنَيَّ لَا تُشْرِكْ بِاللَّهِ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ali bin Khusyram] telah mengabarkan kepada kami [Isa bin Yunus] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] ia berkata; \"Saat turun ayat Orang-orang yang beriman dan tidak mencampuradukkan iman mereka dengan kezhaliman QS Al An`am: 82, kaum muslimin merasa berat karenanya dan bertanya; \"Wahai Rasulullah, adakah diantara kami yang tidak pernah mendzalimi dirinya?\" Beliau bersabda: \"Bukan begitu, maksudnya adalah syirk, bukankah kalian mendengar apa yang dikatakan Luqman kepada anaknya? Wahai anakku janganlah engkau mempersekutukan Allah, sesungguhnya syirik itu adalah kedzhaliman yang besar. QS Luqman: 13. Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2854":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ كُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْيَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ مَنْ زَعَمَ أَنَّ مُحَمَّدًا رَأَى رَبَّهُ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ }وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْظِرِينِي وَلَا تُعْجِلِينِي أَلَيْسَ يَقُولُ اللَّهُ تَعَالَى{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }قَالَتْ أَنَا وَاللَّهِ أَوَّلُ مَنْ سَأَلَ عَنْ هَذَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا ذَاكَ جِبْرِيلُ مَا رَأَيْتُهُ فِي الصُّورَةِ الَّتِي خُلِقَ فِيهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَمَنْ زَعَمَ أَنَّ مُحَمَّدًا كَتَمَ شَيْئًا مِمَّا أَنْزَلَ اللَّهُ عَلَيْهِ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ يَقُولُ اللَّهُ{ يَا أَيُّهَا الرَّسُولَ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ }وَمَنْ زَعَمَ أَنَّهُ يَعْلَمُ مَا فِي غَدٍ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَسْرُوقُ بْنُ الْأَجْدَعِ يُكْنَى أَبَا عَائِشَةَ وَهُوَ مَسْرُوقُ بْنُ عَبْدِ الرَّحْمَنِ وَكَذَا كَانَ اسْمُهُ فِي الدِّيوَانِ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ishaq bin Yusuf] telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] ia berkata; \"Aku bersandar didekat 'Aisyah lalu ['Aisyah] berkata; \"Wahai Abu Aisyah, tiga hal yang barangsiapa mengucapkan salah satunya, berarti ia telah dusta besar atas nama Allah, yaitu; barangsiapa mengira Muhammad pernah melihat Rabbnya berarti ia berdusta atas nama Allah, sementara Allah berfirman Dia tidak dapat dicapai oleh penglihatan mata, sedang dia dapat melihat segala yang kelihatan; dan dialah yang Maha halus lagi Maha Mengetahui QS Al An`am: 103, Dan tidak mungkin bagi seorang pun bahwa Allah berkata-kata dengan dia kecuali dengan perantaraan wahyu atau dibelakang tabir QS Asy Syura: 51.\" Tadinya aku bersandar, lalu aku duduk, aku berkata; \"Wahai Ummul Mukminin, tunggulah aku, jangan tergesa-gesa, bukankah Allah Ta'ala berfirman Dan Sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain QS An Najm: 13 Dan Sesungguhnya Muhammad itu melihat Jibril di ufuk yang terang QS At Takwiir: 23. 'Aisyah berkata; \"Demi Allah, aku adalah orang pertama kali menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau menjawab: \"Sesungguhnya dia itu adalah Jibril, aku tidak pernah melihatnya dalam wujud (asli) ciptaannya kecuali pada kedua kali itu, aku melihatnya turun dari langit, besarnya wujud dia menutupi (jarak) antara langit dan bumi dan barangsiapa mengira Muhammad menyembunyikan sesuatu yang diturunkan Allah padanya, berarti dia telah dusta besar atas nama Allah. Allah berfirman Hai rasul, sampaikanlah apa yang diturunkan kepadamu dari Rabbmu. QS Al Ma`idah: 67, Dan barangsiapa mengira bahwa ia mengetahui sesuatu dikeesokan harinya, berarti ia telah dusta besar atas nama Allah. Allah berfirman Katakanlah: 'Tidak ada seorangpun di langit dan di bumi yang mengetahui perkara yang ghaib, kecuali Allah QS An Naml: 65. Abu Isa berkata; Hadits ini hasan shahih. Masruq bin Al Ajda' kun-yahnya (julukan) adalah Abu Aisyah, ia adalah Masruq bin Abdurrahman. Seperti itulah namanya disebut dalam Ad Diiwaan."},"2855":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى الْبَصْرِيُّ الْحَرَشِيُّ حَدَّثَنَا زِيَادُ بْنُ عَبْدِ اللَّهِ الْبَكَّائِيُّ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَأَتَى أُنَاسٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ أَنَأْكُلُ مَا نَقْتُلُ وَلَا نَأْكُلُ مَا يَقْتُلُ اللَّهُ فَأَنْزَلَ اللَّهُ{ فَكُلُوا مِمَّا ذُكِرَ اسْمُ اللَّهِ عَلَيْهِ إِنْ كُنْتُمْ بِآيَاتِهِ مُؤْمِنِينَ إِلَى قَوْلِهِ وَإِنْ أَطَعْتُمُوهُمْ إِنَّكُمْ لَمُشْرِكُونَ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ هَذَا الْوَجْهِ عَنْ ابْنِ عَبَّاسٍ أَيْضًا وَرَوَاهُ بَعْضُهُمْ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا","id":"Telah menceritakan kepada kami [Muhammad bin Musa Al Bashri Al Harasy] telah menceritakan kepada kami [Ziyad bin Abdullah Al Bakka`i] telah menceritakan kepada kami [Atha` bin As Sa`ib] dari [Sa'id bin Jubair] dari [Abdullah bin Abbas] ia berkata; \"Orang-orang mendatangi Nabi shallallahu 'alaihi wasallam, lalu berkata; \"Wahai Rasulullah, apakah kita memakan (hewan) yang kita sembelih sementara kita tidak memakan yang disembelih Allah?\" Lalu Allah menurunkan Maka makanlah binatang-binatang (yang halal) yang disebut nama Allah ketika menyembelihnya, jika kamu beriman kepada ayat-ayatNya -hingga firmanNya- Dan jika kamu menuruti mereka, Sesungguhnya kamu tentulah menjadi orang-orang yang musyrik QS Al An`am: 118-121. Abu Isa berkata; Hadits ini hasan gharib. Hadits ini juga diriwayatkan dari Ibnu Abbas melalui sanad lain. Sebagian meriwayatkannya dari Atha` bin As Sa`ib dari Sa'id bin Jubair dari Nabi shallallahu 'alaihi wasallam secara mursal."},"2856":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ الصَّبَّاحِ الْبَغْدَادِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ دَاوُدَ الْأَوْدِيِّ عَنْ الشَّعْبِيِّ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَمَنْ سَرَّهُ أَنْ يَنْظُرَ إِلَى الصَّحِيفَةِ الَّتِي عَلَيْهَا خَاتَمُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْيَقْرَأْ هَذِهِ الْآيَاتِ{ قُلْ تَعَالَوْا أَتْلُ مَا حَرَّمَ رَبُّكُمْ عَلَيْكُمْ الْآيَةَ إِلَى قَوْلِهِ لَعَلَّكُمْ تَتَّقُونَ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Al Fadll bin Ash Shabbah Al Baghdadi] telah menceritakan kepada kami [Muhammad bin Fudhail] dari [Dawud Al Audi] dari [Asy Sya'bi] dari ['Alqamah] dari [Abdullah] ia berkata; \"Barangsiapa ingin melihat lembaran (wahyu) yang terdapat didalamnya stempel Muhammad shallallahu 'alaihi wasallam, hendaklah membaca ayat ini Katakanlah: 'Marilah kubacakan apa yang diharamkan atas kamu oleh Rabbmu -hingga firmanNya- Agar kamu bertakwa QS Al An`aam: 151-153. Abu Isa mengatakan bahwa hadits ini hasan gharib."},"2857":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا أَبِي عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِ اللَّهِ عَزَّ وَجَلَّ{ أَوْ يَأْتِيَ بَعْضُ آيَاتِ رَبِّكَ }قَالَ طُلُوعُ الشَّمْسِ مِنْ مَغْرِبِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَرَوَاهُ بَعْضُهُمْ وَلَمْ يَرْفَعْهُ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [Ayahku] dari [Ibnu Abu Laila] dari ['Athiyah] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam tentang firman Allah 'azza wajalla Atau kedatangan beberapa ayat Rabbmu QS Al An`am: 158, Beliau bersabda: \"Terbitnya matahari dari tempat terbenamnya.\" Abu Isa berkata; Hadits ini hasan gharib. Yang lain meriwayatkannya, namun tidak memarfu'kannya."},"2858":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ عَنْ فُضَيْلِ بْنِ غَزْوَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثٌ إِذَا خَرَجْنَ لَمْ{ يَنْفَعُ نَفْسًا إِيمَانُهَا لَمْ تَكُنْ آمَنَتْ مِنْ قَبْلُ }الْآيَةَ الدَّجَّالُ وَالدَّابَّةُ وَطُلُوعُ الشَّمْسِ مِنْ الْمَغْرِبِ أَوْ مِنْ مَغْرِبِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو حَازِمٍ هُوَ الْأَشْجَعِيُّ الْكُوفِيُّ وَاسْمُهُ سَلْمَانُ مَوْلَى عَزَّةَ الْأَشْجَعِيَّةِ","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Ya'la bin 'Ubaid] dari [Fudlail bin Ghazwan] dari [Abu Hazim] dari [Abu Hurairah] dari Nabi Shallallahu 'alahi wasallam, beliau bersabda: \"Tiga hal, jika semuanya telah terjadi, maka tidak akan berguna lagi keimanan seseorang yang sebelumnya ia tidak beriman terhadap ayat (Allah), yaitu; keluarnya Dajjal, binatang melata, dan terbitnya matahari dari barat atau dari tempat terbenamnya.\" Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2859":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ وَقَوْلُهُ الْحَقُّ إِذَا هَمَّ عَبْدِي بِحَسَنَةٍ فَاكْتُبُوهَا لَهُ حَسَنَةً فَإِنْ عَمِلَهَا فَاكْتُبُوهَا لَهُ بِعَشْرِ أَمْثَالِهَا وَإِذَا هَمَّ بِسَيِّئَةٍ فَلَا تَكْتُبُوهَا فَإِنْ عَمِلَهَا فَاكْتُبُوهَا بِمِثْلِهَا فَإِنْ تَرَكَهَا وَرُبَّمَا قَالَ لَمْ يَعْمَلْ بِهَا فَاكْتُبُوهَا لَهُ حَسَنَةً ثُمَّ قَرَأَ{ مَنْ جَاءَ بِالْحَسَنَةِ فَلَهُ عَشْرُ أَمْثَالِهَا }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata; bahwa Rasulullah Shallallahu 'alahi wasallam bersabda: \"Allah 'azza wajalla berfirman, sedangkan firmanNya adalah haq; 'Jika hambaKu berniat (mengamalkan) satu kebaikan, maka tulislah satu kebaikan untuknya, akan tetapi jika ia mengamalkannya maka tulislah untuknya sepuluh kebaikan yang serupa. Dan jika ia berniat satu kejahatan, janganlah kalian tulis hingga ia mengerjakannya, jika ia mengerjakannya, maka tulislah sebagai satu kejahatan yang serupa, akan tetapi jika (kejahatan itu) ia tinggalkan atau tidak ia kerjakan, maka tulislah sebagai satu kebaikan untuknya.\" kemudian beliau membaca: Barangsiapa membawa amal yang baik, maka baginya (pahala) sepuluh kali lipat amalnya QS Al An'am: 160. Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2860":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ هَذِهِ الْآيَةَ{ فَلَمَّا تَجَلَّى رَبُّهُ لِلْجَبَلِ جَعَلَهُ دَكًّا }قَالَ حَمَّادٌ هَكَذَا وَأَمْسَكَ سُلَيْمَانُ بِطَرَفِ إِبْهَامِهِ عَلَى أُنْمُلَةِ إِصْبَعِهِ الْيُمْنَى قَالَ فَسَاخَ الْجَبَلُ{ وَخَرَّ مُوسَى صَعِقًا }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ حَمَّادِ بْنِ سَلَمَةَ حَدَّثَنَا عَبْدُ الْوَهَّابِ الْوَرَّاقُ الْبَغْدَادِيُّ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] bahwa Nabi Shallallahu 'alahi wasallam membaca ayat ini Tatkala Rabbnya menampakkan diri kepada gunung itu, dijadikannya gunung itu hancur luluh. QS Al An`aam: 143. Hammad mengatakan beginilah, dan Sulaiman menempelkan ibu jarinya pada ruas jari (kelingkingnya) yang kanan, beliau bersabda: Gunung terbenam 'Dan Musa pun jatuh pingsan'. QS Al An`am: 143. Abu Isa mengatakan bahwa hadits ini hasan shahih gharib. Kami hanya mengetahuinya dari hadits Hammad bin Salamah. Telah menceritakan kepada kami [Abdul Wahab Al Warraq Al Baghdadi] telah menceritakan kepada kami [Mu'adz bin Mu'adz] dari [Hammad bin Salamah] dari [Tsabit] dari [Anas] dari Nabi shallallahu 'alaihi wasallam sepertinya dan hadits ini hasan."},"2861":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ زَيْدِ ابْنِ أَبِي أُنَيْسَةَ عَنْ عَبْدِ الْحَمِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ زَيْدِ بْنِ الْخَطَّابِ عَنْ مُسْلِمِ بْنِ يَسَارٍ الْجُهَنِيِّ أَنَّ عُمَرَ بْنَ الْخَطَّابِسُئِلَ عَنْ هَذِهِ الْآيَةِ{ وَإِذْ أَخَذَ رَبُّكَ مِنْ بَنِي آدَمَ مِنْ ظُهُورِهِمْ ذُرِّيَّتَهُمْ وَأَشْهَدَهُمْ عَلَى أَنْفُسِهِمْ أَلَسْتُ بِرَبِّكُمْ قَالُوا بَلَى شَهِدْنَا أَنْ تَقُولُوا يَوْمَ الْقِيَامَةِ إِنَّا كُنَّا عَنْ هَذَا غَافِلِينَ }فَقَالَ عُمَرُ بْنُ الْخَطَّابِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسْأَلُ عَنْهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ خَلَقَ آدَمَ ثُمَّ مَسَحَ ظَهْرَهُ بِيَمِينِهِ فَأَخْرَجَ مِنْهُ ذُرِّيَّةً فَقَالَ خَلَقْتُ هَؤُلَاءِ لِلْجَنَّةِ وَبِعَمَلِ أَهْلِ الْجَنَّةِ يَعْمَلُونَ ثُمَّ مَسَحَ ظَهْرَهُ فَاسْتَخْرَجَ مِنْهُ ذُرِّيَّةً فَقَالَ خَلَقْتُ هَؤُلَاءِ لِلنَّارِ وَبِعَمَلِ أَهْلِ النَّارِ يَعْمَلُونَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ فَفِيمَ الْعَمَلُ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ إِذَا خَلَقَ الْعَبْدَ لِلْجَنَّةِ اسْتَعْمَلَهُ بِعَمَلِ أَهْلِ الْجَنَّةِ حَتَّى يَمُوتَ عَلَى عَمَلٍ مِنْ أَعْمَالِ أَهْلِ الْجَنَّةِ فَيُدْخِلَهُ اللَّهُ الْجَنَّةَ وَإِذَا خَلَقَ الْعَبْدَ لِلنَّارِ اسْتَعْمَلَهُ بِعَمَلِ أَهْلِ النَّارِ حَتَّى يَمُوتَ عَلَى عَمَلٍ مِنْ أَعْمَالِ أَهْلِ النَّارِ فَيُدْخِلَهُ اللَّهُ النَّارَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَمُسْلِمُ بْنُ يَسَارٍ لَمْ يَسْمَعْ مِنْ عُمَرَ وَقَدْ ذَكَرَ بَعْضُهُمْ فِي هَذَا الْإِسْنَادِ بَيْنَ مُسْلِمِ بْنِ يَسَارٍ وَبَيْنَ عُمَرَ رَجُلًا مَجْهُولًا","id":"Telah menceritakan kepada kami [Al Ashari] telah menceritakan kepada kami [Ma'an] telah menceritakan kepada kami [Malik bin Anas] dari [Zaid bin Abu Unaisah] dari [Abdulhamid bin Abdurrahman bin Zaid bin Al Khathtahab] dari [Muslim bin Yasar Al Juhani] bahwa [Umar bin Al Khaththab] pernah ditanya tentang ayat \"Dan (ingatlah), ketika Rabbmu mengeluarkan keturunan anak-anak Adam dari sulbi mereka dan Allah mengambil kesaksian terhadap jiwa mereka (seraya berfirman): 'Bukankah Aku ini Rabbmu? ' Mereka menjawab: 'Betul (Engkau Rabb kami), kami menjadi saksi.' (Kami lakukan yang demikian itu) agar di hari kiamat kamu tidak mengatakan: 'Sesungguhnya kami (bani Adam) adalah orang-orang yang lengah terhadap ini (keesaan Rabb).\" (Al A'raaf: 172) Umar berkata: Saya mendengar Rasulullah Shallallahu 'alaihi wa Salam pernah ditanya tentangnya lalu beliau menjawab: \"Sesungguhya Allah menciptakan Adam kemudian Dia mengusap punggungnya dengan tangan kananNya lalu mengeluarkan keturunan, setelah itu berfirman: 'Aku ciptakan mereka semua untuk (menghuni) surga dan dengan amalan ahli surga.' Kemudian Ia usap punggungnya, maka keluarlah keturunan darinya, setelah itu Ia berfirman: 'Aku ciptakan mereka untuk (menghuni) neraka dan dengan amalan ahli neraka'.\" Lalu ada orang yang bertanya: Wahai Rasulullah, kalau demikian apa gunanya beramal? beliau menjawab: \"Sesungguhnya Allah jika menciptakan hamba sebagai ahli surga, ia akan dituntun olehNya untuk beramal dengan amal ahli surga sampai mereka mati dalam keadaan demikian lalu Allah memasukannya ke surga. Sedangkan jika Dia menciptakan hamba itu sebagai ahli neraka, ia akan dituntun olehNya untuk beramal dengan amal ahli neraka sampai mereka mati dalam keadaan demikian lalu Allah memasukannya ke dalam neraka.\" Abu Isa berkata: Hadits ini hasan. Muslim bin Yasar tidak mendengar dari Umar. Sebagaian dari mereka menyebutkan seseorang yang tidak diketahui dalam sanad ini antara Muslim bin Yasar dan Umar."},"2862":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا خَلَقَ اللَّهُ آدَمَ مَسَحَ ظَهْرَهُ فَسَقَطَ مِنْ ظَهْرِهِ كُلُّ نَسَمَةٍ هُوَ خَالِقُهَا مِنْ ذُرِّيَّتِهِ إِلَى يَوْمِ الْقِيَامَةِ وَجَعَلَ بَيْنَ عَيْنَيْ كُلِّ إِنْسَانٍ مِنْهُمْ وَبِيصًا مِنْ نُورٍ ثُمَّ عَرَضَهُمْ عَلَى آدَمَ فَقَالَ أَيْ رَبِّ مَنْ هَؤُلَاءِ قَالَ هَؤُلَاءِ ذُرِّيَّتُكَ فَرَأَى رَجُلًا مِنْهُمْ فَأَعْجَبَهُ وَبِيصُ مَا بَيْنَ عَيْنَيْهِ فَقَالَ أَيْ رَبِّ مَنْ هَذَا فَقَالَ هَذَا رَجُلٌ مِنْ آخِرِ الْأُمَمِ مِنْ ذُرِّيَّتِكَ يُقَالُ لَهُ دَاوُدُ فَقَالَ رَبِّ كَمْ جَعَلْتَ عُمْرَهُ قَالَ سِتِّينَ سَنَةً قَالَ أَيْ رَبِّ زِدْهُ مِنْ عُمْرِي أَرْبَعِينَ سَنَةً فَلَمَّا قُضِيَ عُمْرُ آدَمَ جَاءَهُ مَلَكُ الْمَوْتِ فَقَالَ أَوَلَمْ يَبْقَ مِنْ عُمْرِي أَرْبَعُونَ سَنَةً قَالَ أَوَلَمْ تُعْطِهَا ابْنَكَ دَاوُدَ قَالَ فَجَحَدَ آدَمُ فَجَحَدَتْ ذُرِّيَّتُهُ وَنُسِّيَ آدَمُ فَنُسِّيَتْ ذُرِّيَّتُهُ وَخَطِئَ آدَمُ فَخَطِئَتْ ذُرِّيَّتُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abd bin Humaid] telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hisyam bin Sa'ad] dari [Zaid bin Aslam] dari [Abu Shalih] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Saat Allah menciptakan Adam, Ia mengusap punggungnya lalu dari punggungnya berjatuhan setiap jiwa yang diciptakan Allah dari keturunan Adam hingga hari kiamat dan Ia menjadikan kilatan cahaya diantara kedua mata setiap orang dari mereka, kemudian mereka dihadapkan kepada Adam, ia bertanya: 'Wahai Rabb, siapa mereka? ' Allah menjawab: 'Mereka keturunanmu'. Adam melihat seseorang dari mereka dan kilatan cahaya diantara kedua matanya membuatnya kagum, Adam bertanya: Wahai Rabb siapa dia? Allah menjawab: Ia orang akhir zaman dari keturunanmu bernama Dawud. Adam bertanya: Wahai Rabb, berapa lama Engkau menciptakan umurnya? Allah menjawab: Enampuluh tahun. Adam bertanya: Wahai Rabb, tambahilah empatpuluh tahun dari umurku. Saat usia Adam ditentukan, malaikat maut mendatanginya lalu berkata: Bukankah usiaku masih tersisa empatpuluh tahun. Malaikat maut berkata: Bukankah kau telah memberikannya kepada anakmu, Dawud. Adam membantah lalu keturunannya juga membantah. Adam dibuat lupa dan keturunannya juga dibuat lupa. Adam salah dan keturunannya juga salah.\" Abu Isa berkata: Hadits ini hasan shahih. Diriwayatkan melalui sanad lain dari Abu Hurairah dari nabi Shallallahu 'alaihi wa Salam."},"2863":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا عُمَرُ بْنُ إِبْرَاهِيمَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمَّا حَمَلَتْ حَوَّاءُ طَافَ بِهَا إِبْلِيسُ وَكَانَ لَا يَعِيشُ لَهَا وَلَدٌ فَقَالَ سَمِّيهِ عَبْدَ الْحَارِثِ فَسَمَّتْهُ عَبْدَ الْحَارِثِ فَعَاشَ وَكَانَ ذَلِكَ مِنْ وَحْيِ الشَّيْطَانِ وَأَمْرِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ مَرْفُوعًا إِلَّا مِنْ حَدِيثِ عُمَرَ بْنِ إِبْرَاهِيمَ عَنْ قَتَادَةَ وَرَوَاهُ بَعْضُهُمْ عَنْ عَبْدِ الصَّمَدِ وَلَمْ يَرْفَعْهُ عُمَرُ بْنُ إِبْرَاهِيمَ شَيْخٌ بَصْرِيٌّ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mustanna] telah menceritakan kepada kami [Abdush Shamad bin Abdulwarits] telah menceritakan kepada kami [Umar bin Ibrahim] dari [Qatadah] dari [Al Hasan] dari [Samurah] dari Nabi Shallallahu 'alaihi wa Salam bersabda: \"Ketika Hawwa hamil, Iblis datang kepadanya dan ia (Hawwa) sebelumnya tidak memiliki seorangpun dari anaknya yang hidup, karena itu Iblis berkata padanya: Berilah nama Abdulharits. Ia pun hidup dan itulah sebagian wahyu dan perintah setan.\" Abu Isa mengatakan bahwa hadits ini hasan gharib.. Kami tidak mengetahuinya marfu' kecuali dari hadits Umar bin Ibrahim dari Qatadah. Sebagian dari mereka meriwayatkan dari Abdushshamad tapi tidak memarfu'kannya. Umar bin Ibrahim adalah seorang guru Bashrah."},"2864":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَلَمَّا كَانَ يَوْمُ بَدْرٍ جِئْتُ بِسَيْفٍ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ قَدْ شَفَى صَدْرِي مِنْ الْمُشْرِكِينَ أَوْ نَحْوَ هَذَا هَبْ لِي هَذَا السَّيْفَ فَقَالَ هَذَا لَيْسَ لِي وَلَا لَكَ فَقُلْتُ عَسَى أَنْ يُعْطَى هَذَا مَنْ لَا يُبْلِي بَلَائِي فَجَاءَنِي الرَّسُولُ فَقَالَ إِنَّكَ سَأَلْتَنِي وَلِيس لِي وَإِنَّهُ قَدْ صَارَ لِي وَهُوَ لَكَ قَالَ فَنَزَلَتْ{ يَسْأَلُونَكَ عَنْ الْأَنْفَالِ }الْآيَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ سِمَاكُ بْنُ حَرْبٍ عَنْ مُصْعَبٍ أَيْضًا وَفِي الْبَاب عَنْ عُبَادَةَ بْنِ الصَّامِتِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Bakar bin Ayyasy] dari [Ashim bin Bahdalah] dari [Mush'ab bin Sa'ad] dari [bapaknya] berkata: Pada hari tejadinya perang Badar, aku membawa sebilah pedang kepada Rasulullah Shallallahu 'alaihi wa Salam, aku berkata: Wahai Rasulullah sesungguhnya Allah telah menyembuhkan hatiku dari kaum musyrikin (atau yang senada dengan kalimat ini) aku meminta engkau mau memberikan pedang ini padaku. beliau menjawab: \"(Pedang) ini bukan milikku atau milikmu.\" Aku berharap pedang itu diberikan padaku karena tak ada yang berperang (segigih) aku. lalu Rasulullah mendatangiku kemudian bersabda: \"Engkau telah meminta padaku padahal itu bukan milikku, tapi sekarang sudah jadi milikku dan aku (akan memberikannya) padamu, \" lalu turun ayat: \"Mereka menanyakan kepadamu tentang (pembagian) harta rampasan perang.\" (Al Anfaal: 1). Abu Isa mengatakan bahwa hadits ini hasan shahih. Dan [Simak bin Harb] telah meriwayatkannya dari [Mush'ab] juga. Dan di bab dari Ubadah bin Ash Shamit"},"2865":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَدْرٍ قِيلَ لَهُ عَلَيْكَ الْعِيرَ لَيْسَ دُونَهَا شَيْءٌ قَالَ فَنَادَاهُ الْعَبَّاسُ وَهُوَ فِي وَثَاقِهِ لَا يَصْلُحُ وَقَالَ لِأَنَّ اللَّهَ وَعَدَكَ إِحْدَى الطَّائِفَتَيْنِ وَقَدْ أَعْطَاكَ مَا وَعَدَكَ قَالَ صَدَقْتَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Abdurrazzaq] dari [Isra`il] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] berkata: Seusai Rasulullah Shallallahu 'alaihi wa Salam perang Badar, dikatakan kepada beliau: Hendaklah baginda (menyerang) kafilah, ia tidak dilindungi apa pun. Lalu Abbas memanggil beliau, yang ketika itu Abbas tengah diikat, kata Abbas: Tidak patut. Karena Allah telah menjanjikan salah satu dari kedua kelompok dan Ia telah memberikan apa yang Ia janjikan kepada baginda. Beliau bersabda: \"Kau benar.\" Abu Isa berkata: Hadits ini hasan shahih."},"2866":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ الْيَمَامِيُّ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنَا أَبُو زُمَيْلٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عبَّاسٍ حَدَّثَنَا عُمَرُ بْنُ الْخَطَّابِ قَالَنَظَرَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمُشْرِكِينَ وَهُمْ أَلْفٌ وَأَصْحَابُهُ ثَلَاثُ مِائَةٍ وَبِضْعَةُ عَشَرَ رَجُلًا فَاسْتَقْبَلَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقِبْلَةَ ثُمَّ مَدَّ يَدَيْهِ وَجَعَلَ يَهْتِفُ بِرَبِّهِ اللَّهُمَّ أَنْجِزْ لِي مَا وَعَدْتَنِي اللَّهُمَّ آتِنِي مَا وَعَدْتَنِي اللَّهُمَّ إِنْ تُهْلِكْ هَذِهِ الْعِصَابَةَ مِنْ أَهْلِ الْإِسْلَامِ لَا تُعْبَدُ فِي الْأَرْضِ فَمَا زَالَ يَهْتِفُ بِرَبِّهِ مَادًّا يَدَيْهِ مُسْتَقْبِلَ الْقِبْلَةِ حَتَّى سَقَطَ رِدَاؤُهُ مِنْ مَنْكِبَيْهِ فَأَتَاهُ أَبُو بَكْرٍ فَأَخَذَ رِدَاءَهُ فَأَلْقَاهُ عَلَى مَنْكِبَيْهِ ثُمَّ الْتَزَمَهُ مِنْ وَرَائِهِ فَقَالَ يَا نَبِيَّ اللَّهِ كَفَاكَ مُنَاشَدَتَكَ رَبَّكَ إِنَّهُ سَيُنْجِزُ لَكَ مَا وَعَدَكَ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ إِذْ تَسْتَغِيثُونَ رَبَّكُمْ فَاسْتَجَابَ لَكُمْ أَنِّي مُمِدُّكُمْ بِأَلْفٍ مِنْ الْمَلَائِكَةِ مُرْدِفِينَ }فَأَمَدَّهُمْ اللَّهُ بِالْمَلَائِكَةِقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ عُمَرَ إِلَّا مِنْ حَدِيثِ عِكْرِمَةَ بْنِ عَمَّارٍ عَنْ أَبِي زُمَيْلٍ وَأَبُو زُمَيْلٍ اسْمُهُ سِمَاكٌ الْحَنَفِيُّ وَإِنَّمَا كَانَ هَذَا يَوْمَ بَدْرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Umar bin Yunus Al Yamami] telah menceritakan kepada kami [Ikrimah bin Ammar] telah menceritakan kepada kami [Abu Zumail] telah menceritakan kepada kami [Abdullah bin Abbas] telah menceritakan kepada kami [Umar bin Al Khaththab] berkata: Nabi Shallallahu 'alaihi wa Salam melihat kaum musyrikin yang berjumlah seribu orang sedangkan sahabatnya berjumlah tiga ratus lebih belasan orang, lalu beliau menghadap kiblat kemudian menengadahkan tangannya seraya berdo'a: ALLOOHUMMA ANJIZ LII MAA WA'ADTANII, ALLOOHUMMA IN TUHLIK HAADZIHIL 'ISHOOBATA MIN AHLIL ISLAAM, LAA TU'BAD FIL ARDHI \"Ya Allah berikan semua yang telah Engkau janjikan padaku, ya Allah datangkanlah semua yang telah Engkau janjikan padaku, ya Allah seandainya Engkau binasakan kaum muslimin ini, tentu tak ada lagi yang menyembahMu di muka bumi ini, \" beliau tak henti-hentinya berdo'a serta menengadahkan tangannya sampai selendangnya jatuh dari pundaknya lalu Abu Bakar mengambil dan meletakkannya kembali di pundaknya kemudian ia (seakan) memeluknya dari belakang dan mengatakan: Wahai Nabi Allah cukuplah kiranya baginda memanjatkan permohonan baginda karena Dia pasti akan memberikan semua yang telah dijanjikan itu. Lalu Allah menurunkan \"(Ingatlah), ketika kamu memohon pertolongan kepada Rabbmu, lalu diperkenankannya bagimu: 'Sesungguhnya Aku akan mendatangkan bala banbaginda kepada kamu dengan seribu malaikat yang datang berturut-turut.\" (Al Anfaal: 9) Abu Isa mengatakan bahwa hadits ini hasan shahih gharib, kami tidak mengetahuinya dari hadits Umar kecuali dari hadits Ikrimah bin Ammar dari Abu Zumail. Abu Zumail namanya Simak Al Hanafi. Ini terjadi pada perang Badar."},"2867":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ عَبَّادِ بْنِ يُوسُفَ عَنْ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْزَلَ اللَّهُ عَلَيَّ أَمَانَيْنِ لِأُمَّتِي{ وَمَا كَانَ اللَّهُ لِيُعَذِّبَهُمْ وَأَنْتَ فِيهِمْ وَمَا كَانَ اللَّهُ مُعَذِّبَهُمْ وَهُمْ يَسْتَغْفِرُونَ }فَإِذَا مَضَيْتُ تَرَكْتُ فِيهِمْ الِاسْتِغْفَارَ إِلَى يَوْمِ الْقِيَامَةِهَذَا حَدِيثٌ غَرِيبٌ وَإِسْمَعِيلُ بْنُ مُهَاجِرٍ يُضَعَّفُ فِي الْحَدِيثِ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [Ibnu Numair] dari [Ismail bin Ibrahim bin Muhajir] dari [Abbad bin Yusuf] dari [Abu Burdah bin Abu Musa] dari [ayahnya] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Allah menurunkan dua jaminan keamanan padaku untuk ummatku: 'Dan Allah sekali-kali tidak akan mengazab mereka, sedang kamu (Muhammad) berada di antara mereka. dan tidaklah (pula) Allah akan mengazab mereka, sedang mereka meminta ampun.\" (Al Anfaal: 33) dan bila aku meninggal, aku meninggalkan istighfar untuk mereka hingga hari kiamat.\" Hadits ini gharib. Ismail bin Muhajir dilemahkan dalam hadits."},"2868":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا وَكِيعٌ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ رَجُلٍ لَمْ يُسَمِّهِ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ هَذِهِ الْآيَةَ عَلَى الْمِنْبَرِ{ وَأَعِدُّوا لَهُمْ مَا اسْتَطَعْتُمْ مِنْ قُوَّةٍ }قَالَ أَلَا إِنَّ الْقُوَّةَ الرَّمْيُ ثَلَاثَ مَرَّاتٍ أَلَا إِنَّ اللَّهَ سَيَفْتَحُ لَكُمْ الْأَرْضَ وَسَتُكْفَوْنَ الْمُؤْنَةَ فَلَا يَعْجِزَنَّ أَحَدُكُمْ أَنْ يَلْهُوَ بِأَسْهُمِهِقَالَ أَبُو عِيسَى وَقَدْ رَوَى بَعْضُهُمْ هَذَا الْحَدِيثَ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ صَالِحِ بْنِ كَيْسَانَ رَوَاهُ أَبُو أُسَامَةَ وَغَيْرُ وَاحِدٍ عَنْ عُقْبَةَ بْنِ عَامِرٍ وَحَدِيثُ وَكِيعٍ أَصَحُّ وَصَالِحُ بْنُ كَيْسَانَ لَمْ يُدْرِكْ عُقْبَةَ بْنَ عَامِرٍ وَقَدْ أَدْرَكَ ابْنَ عُمَرَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Waki'] dari [Usamah bin Zaid] dari [Shalih bin Kaisan] dari [seseorang yang tidak disebut namanya] dari [Uqbah bin Amir] bahwa Rasulullah Shallallahu 'alaihi wa Salam membaca ayat ini di atas mimbar: \"Dan siapkanlah untuk menghadapi mereka kekuatan apa saja yang kamu sanggupi.\" (Al Anfaal: 60) lalu bersabda: \"Ketahuilah bahwa kekuatan adalah memanah (beliau ulang sabdanya sebanyak tiga kali) ketahuilah, bahwa Allah akan memberikan kemenangan di atas bumi ini dan akan dicukupkan makanan bagi kalian, karena itu janganlah ada diantara kalian yang merasa bosan untuk memainkan panah-panahnya.\" Abu Isa berkata: Sebagian dari mereka meriwayatkan hadits ini dari [Usamah bin Zaid] dari [Shalih bin Kaisan]. Dan diriwayatkan oleh Usamah dan beberapa orang dari Uqbah bin Amir. Hadits Waki' lebih shahih. Shalih bin Kaisan tidak bertemu Uqbah bin Amir dan ia bertemu Ibnu Umar."},"2869":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي عُبَيْدَةَ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَلَمَّا كَانَ يَوْمُ بَدْرٍ وَجِيءَ بِالْأَسَارَى قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَقُولُونَ فِي هَؤُلَاءِ الْأَسَارَى فَذَكَرَ فِي الْحَدِيثِ قِصَّةً طَوِيلَةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْفَلِتَنَّ مِنْهُمْ أَحَدٌ إِلَّا بِفِدَاءٍ أَوْ ضَرْبِ عُنُقٍ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ فَقُلْتُ يَا رَسُولَ اللَّهِ إِلَّا سُهَيْلَ ابْنَ بَيْضَاءَ فَإِنِّي قَدْ سَمِعْتُهُ يَذْكُرُ الْإِسْلَامَ قَالَ فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَمَا رَأَيْتُنِي فِي يَوْمٍ أَخْوَفَ أَنْ تَقَعَ عَلَيَّ حِجَارَةٌ مِنْ السَّمَاءِ مِنِّي فِي ذَلِكَ الْيَوْمِ قَالَ حَتَّى قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا سُهَيْلَ ابْنَ الْبَيْضَاءِ قَالَ وَنَزَلَ الْقُرْآنُ بِقَوْلِ عُمَرَ{ مَا كَانَ لِنَبِيٍّ أَنْ يَكُونَ لَهُ أَسْرَى حَتَّى يُثْخِنَ فِي الْأَرْضِ }إِلَى آخِرِ الْآيَاتِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَأَبُو عُبَيْدَةَ بْنُ عَبْدِ اللَّهِ لَمْ يَسْمَعْ مِنْ أَبِيهِ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Amru bin Murrah] dari [Abu Ubaidah bin Abdullah] dari [Abdullah bin Mas'ud] berkata: Pada waktu terjadinya perang Badar dan para tawanan didatangkan, Rasulullah Shallallahu 'alaihi wa Salam bertanya: \"Apa pendapat kalian tentang tawanan-tawanan ini?\" (kisah di sebutkan dalam hadits yang panjang) beliau bersabda: \"Jangan sampai ada yang lepas seorangpun dari mereka kecuali dengan tebusan atau tebasan (dibunuh).\" Abdullah bin Mas'ud berkata: Kecuali Suhail bin Al Baidha wahai Rasulullah, karena saya pernah mendengar ia telah memeluk Islam. Beliau terdiam. (Abdullah bin Mas'ud) berkata: Aku belum pernah mengalami rasa takut jangan-jangan turun hujan batu dari langit yang akan menimpaku kecuali saat itu sehingga beliau mengatakan: \"Ya, kecuali Suhail bin Al Baidha, \" lalu turunlah ayat yang bertepatan dengan perkataan Umar: \"Tidak patut, bagi seorang Nabi mempunyai tawanan sebelum ia dapat melumpuhkan musuhnya di muka bumi.\" (Al Anfaal: 67) Abu Isa mengatakan bahwa hadits ini hasan."},"2870":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنِي مُعَاوِيَةُ بْنُ عَمْرٍو عَنْ زَائِدَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمْ تَحِلَّ الْغَنَائِمُ لِأَحَدِ سُودِ الرُّءُوسِ مِنْ قَبْلِكُمْ كَانَتْ تَنْزِلُ نَارٌ مِنْ السَّمَاءِ فَتَأْكُلُهَا قَالَ سُلَيْمَانُ الْأَعْمَشُ فَمَنْ يَقُولُ هَذَا إِلَّا أَبُو هُرَيْرَةَ الْآنَ فَلَمَّا كَانَ يَوْمُ بَدْرٍ وَقَعُوا فِي الْغَنَائِمِ قَبْلَ أَنْ تَحِلَّ لَهُمْ فَأَنْزَلَ اللَّهُ تَعَالَى{ لَوْلَا كِتَابٌ مِنْ اللَّهِ سَبَقَ لَمَسَّكُمْ فِيمَا أَخَذْتُمْ عَذَابٌ عَظِيمٌ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ الْأَعْمَشِ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah mengkhabarkan kepadaku [Mu'awiyah bin Amru] dari [Za`idah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi Shallallahu 'alaihi wa Salam bersabda: \"Harta rampasan perang itu tidak dihalalkan bagi seorangpun sebelum kalian karena dulu langsung dilalap api yang turun dari langit.\" Sulaiman al A'masy berkata: Tak ada yang mengatakan hal ini selain Abu Hurairah dan ketika terjadinya perang Badar mereka (berebut) mengambil ghanimah sebelum Allah menghalalkannya. Lalu Allah menurunkan ayat: \"Kalau tidak ada ketetapan yang telah terdahulu dari Allah, niscaya kamu ditimpa siksaan yang besar karena tebusan yang kamu ambil.\" (Al Anffal: 68) Abu Isa mengatakan bahwa hadits ini hasan shahih gharib."},"2871":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ الْجُعْفِيُّ عَنْ زَائِدَةَ عَنْ شَبِيبِ بْنِ غَرْقَدَةَ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ حَدَّثَنَا أَبِيأَنَّهُ شَهِدَ حَجَّةَ الْوَدَاعِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَذَكَّرَ وَوَعَظَ ثُمَّ قَالَ أَيُّ يَوْمٍ أَحْرَمُ أَيُّ يَوْمٍ أَحْرَمُ أَيُّ يَوْمٍ أَحْرَمُ قَالَ فَقَالَ النَّاسُ يَوْمُ الْحَجِّ الْأَكْبَرِ يَا رَسُولَ اللَّهِ قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا أَلَا لَا يَجْنِي جَانٍ إِلَّا عَلَى نَفْسِهِ وَلَا يَجْنِي وَالِدٌ عَلَى وَلَدِهِ وَلَا وَلَدٌ عَلَى وَالِدِهِ أَلَا إِنَّ الْمُسْلِمَ أَخُو الْمُسْلِمِ فَلَيْسَ يَحِلُّ لِمُسْلِمٍ مِنْ أَخِيهِ شَيْءٌ إِلَّا مَا أَحَلَّ مِنْ نَفْسِهِ أَلَا وَإِنَّ كُلَّ رِبًا فِي الْجَاهِلِيَّةِ مَوْضُوعٌ لَكُمْ رُءُوسُ أَمْوَالِكُمْ لَا تَظْلِمُونَ وَلَا تُظْلَمُونَ غَيْرَ رِبَا الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ فَإِنَّهُ مَوْضُوعٌ كُلُّهُ أَلَا وَإِنَّ كُلَّ دَمٍ كَانَ فِي الْجَاهِلِيَّةِ مَوْضُوعٌ وَأَوَّلُ دَمٍ وُضِعَ مِنْ دِمَاءِ الْجَاهِلِيَّةِ دَمُ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ كَانَ مُسْتَرْضَعًا فِي بَنِي لَيْثٍ فَقَتَلَتْهُ هُذَيْلٌ أَلَا وَاسْتَوْصُوا بِالنِّسَاءِ خَيْرًا فَإِنَّمَا هُنَّ عَوَانٍ عِنْدَكُمْ لَيْسَ تَمْلِكُونَ مِنْهُنَّ شَيْئًا غَيْرَ ذَلِكَ إِلَّا أَنْ يَأْتِينَ بِفَاحِشَةٍ مُبَيِّنَةٍ فَإِنْ فَعَلْنَ فَاهْجُرُوهُنَّ فِي الْمَضَاجِعِ وَاضْرِبُوهُنَّ ضَرْبًا غَيْرَ مُبَرِّحٍ فَإِنْ أَطَعْنَكُمْ فَلَا تَبْغُوا عَلَيْهِنَّ سَبِيلًا أَلَا إِنَّ لَكُمْ عَلَى نِسَائِكُمْ حَقًّا وَلِنِسَائِكُمْ عَلَيْكُمْ حَقًّا فَأَمَّا حَقُّكُمْ عَلَى نِسَائِكُمْ فَلَا يُوطِئْنَ فُرُشَكُمْ مَنْ تَكْرَهُونَ وَلَا يَأْذَنَّ فِي بُيُوتِكُمْ لِمَنْ تَكْرَهُونَ أَلَا وَإِنَّ حَقَّهُنَّ عَلَيْكُمْ أَنْ تُحْسِنُوا إِلَيْهِنَّ فِي كِسْوَتِهِنَّ وَطَعَامِهِنَّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ أَبُو الْأَحْوَصِ عَنْ شَبِيبِ بْنِ غَرْقَدَةَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami [Husain bin Ali Al Ju'fi] dari [Za`idah] dari [Syabib bin Gharqadah] dari [Sulaiman bin Amru bin Al Ahwash] telah menceritakan kepada kami [bapakku] bahwa ia mengikuti haji Wada' bersama Rasulullah Shallallahu 'alaihi wa Salam, beliau membaca hamdalah dan memuji Allah, memberi peringatan dan nasihat, lalu bersabda \"Hari apakah yang paling haram, hari apakah yang paling haram, hari apakah yang paling haram?\" orang-orang menjawab: Hari haji akbar wahai Rasulullah. Beliau bersabda: \"Sesungguhnya darah kalian, harta kalian, dan kehormatan kalian haram (wajaib dijaga kehormatannya) atas kalian seperti haramnya hari kalian ini, di negeri kalian ini dan pada bulan ini. Ketahuilah bahwa tidaklah seseorang melakukan kejahatan melainkan akan ditanggung dirinya sendiri, begitu juga tidaklah orang tua berbuat jahat lantas dosanya ditanggung anaknya, ataupun anak berbuat jahat lantas orang tua menanggung dosanya. Ketahuilah bahwa muslim itu saudara bagi muslim lainnya, tidak halal bagi seorang muslim apa yang dimiliki saudaranya kecuali yang dihalalkan baginya. Ketahuilah bahwa segala bentuk riba ada zaman jahiliyyah harus ditinggalkan dan bagi kalian adalah harta pokok yang kalian miliki, kalian tidak mendzalimi ataupun didzalimi, juga riba Abbas bin Abdul mutthalib, semuanya harus ditinggalkan. Ketahuilah bahwa setiap darah pada masa jahiliyyah harus ditinggalkan dan tuntutan darah pertama-tama yang harus ditinggalkan adalah darah Al Harits bin Abdul Muthallib, yang ia pernah disusui (wanita) dari bani Laits lalu Hudail membunuhnya. Ketahuilah, hendaklah kalian pergauli mereka (istri) dengan kebaikan, karena mereka adalah diperintahkan tunduk untuk kalian, kalian tidak memiliki kekuasaan apa pun dari mereka selain karena ketundukan yang diwajibkan atas mereka, kecuali jika mereka melakukan hal yang keji (dosa) jika mereka melakukan hal itu maka pisahkanlah mereka dari tempat tidur mereka, dan pukullah mereka dengan pukulan yang tidak meninggalkan bekas. jika mereka menaatimu, maka janganlah kamu mencari-cari jalan untuk menyusahkannya, sesungguhnya kalian memiliki hak atas istri kalian, dan isteri kalian juga mempunyai hak atas kalian, adapun hak kalian atas isteri kalian adalah terlarang bagi mereka menghamparkan kasur (menyilahkan masuk ke dalam rumah) untuk orang-orang yang kalian benci, juga tidak mengijinkan siapa saja yang kalian benci untuk memasuki rumah kalian, adapun hak mereka atasmu adalah memberi pakaian dan makanan yang baik.\" Abu Isa mengatakan bahwa hadits ini hasan shahih. [Abu Al Ahwash] meriwayatkannya dari [Syabib bin Gharqadah]. "},"2872":{"ar":"حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ عَبْدِ الصَّمَدِ بْنِ عَبْدِ الْوَارِثِ حَدَّثَنَا أَبِي عَنْ أَبِيهِ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ يَوْمِ الْحَجِّ الْأَكْبَرِ فَقَالَ يَوْمُ النَّحْرِ","id":"Telah menceritakan kepada kami [Abdul Warits bin Abdushshamad bin Abdulwarits] telah menceritakan kepada kami [ayahku] dari [ayahnya] dari [Muhammad bin Ishaq] dari [Abu Ishaq] dari [Al Harits] dari [Ali] berkata: Aku pernah bertanya kepada Rasulullah Shallallahu 'alaihi wa Salam tentang hari haji akbar lalu beliau menjawab: \"Hari qurban.\""},"2873":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ وَعَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبَرَاءَةٌ مَعَ أَبِي بَكْرٍ ثُمَّ دَعَاهُ فَقَالَ لَا يَنْبَغِي لِأَحَدٍ أَنْ يُبَلِّغَ هَذَا إِلَّا رَجُلٌ مِنْ أَهْلِي فَدَعَا عَلِيًّا فَأَعْطَاهُ إِيَّاهَاقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ أَنَسِ بْنِ مَالِكٍ","id":"Telah menceritakan kepada kami [Bundar] telah menceritakan kepada kami [Affan bin Muslim] dan [Abdushshamad bin Abdulwarits] keduanya berkata: Telah menceritakan kepada kami [Hammad bin Salamah] dari [Simak bin Harb] dari [Anas bin Malik] berkata: Nabi hendak mengutus Abu Bakar (menyampaikan) Surat Baraa`ah (at Taubah) kemudian beliau memanggilnya dan mengatakan: Tidak boleh seorang pun menyampaikan surat ini kecuali salah seorang dari keluargaku, \" lalu beliau memanggil Ali dan diberikan padanya. Abu Isa mengatakan bahwa hadits ini hasan gharib. dari hadits Anas bin Malik."},"2874":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ حَدَّثَنَا سُفْيَانُ بْنُ حُسَيْنٍ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا بَكْرٍ وَأَمَرَهُ أَنْ يُنَادِيَ بِهَؤُلَاءِ الْكَلِمَاتِ ثُمَّ أَتْبَعَهُ عَلِيًّا فَبَيْنَا أَبُو بَكْرٍ فِي بَعْضِ الطَّرِيقِ إِذْ سَمِعَ رُغَاءَ نَاقَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقَصْوَاءِ فَخَرَجَ أَبُو بَكْرٍ فَزِعًا فَظَنَّ أَنَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا هُوَ عَلِيٌّ فَدَفَعَ إِلَيْهِ كِتَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَرَ عَلِيًّا أَنْ يُنَادِيَ بِهَؤُلَاءِ الْكَلِمَاتِ فَانْطَلَقَا فَحَجَّا فَقَامَ عَلِيٌّ أَيَّامَ التَّشْرِيقِ فَنَادَى ذِمَّةُ اللَّهِ وَرَسُولِهِ بَرِيئَةٌ مِنْ كُلِّ مُشْرِكٍ فَسِيحُوا فِي الْأَرْضِ أَرْبَعَةَ أَشْهُرٍ وَلَا يَحُجَّنَّ بَعْدَ الْعَامِ مُشْرِكٌ وَلَا يَطُوفَنَّ بِالْبَيْتِ عُرْيَانٌ وَلَا يَدْخُلُ الْجَنَّةَ إِلَّا مُؤْمِنٌ وَكَانَ عَلِيٌّ يُنَادِي فَإِذَا عَيِيَ قَامَ أَبُو بَكْرٍ فَنَادَى بِهَاقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ ابْنِ عَبَّاسٍ","id":"telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Sa'id bin Sulaiman] telah menceritakan kepada kami [Abbad bin Al Awwam] telah menceritakan kepada kami [Sufyan bin Husain] dari [Al Hakam bin Utaibah] dari [Miqsam] dari [Ibnu Abbas] berkata: Nabi Shallallahu 'alaihi wa Salam mengutus Abu Bakar dan memerintahkannya untuk menyampaikan kalimat-kalimat itu kemudian beliau mengutus Ali, saat Abu Bakar berada di sebagian jalan, ia mendengar suara unta Rasulullah Shallallahu 'alaihi wa Salam, al Qaswaa`, lalu Abu Bakar keluar dalam keadaan takut, ia mengiranya Rasulullah Shallallahu 'alaihi wa Salam tapi ternyata Ali. Ali menyerahkan surat Rasulullah Shallallahu 'alaihi wa Salam kepadanya dan memerintahkan Ali untuk menyampaikan kalimat-kalimat itu. Keduanya pergi lalu berhaji. Ali tinggal selama hari tasyriq lalu menyampaikan: Tanggungan Allah dan rasulNya terbebas dari setiap orang musyrik, bertebaranlah dimuka bumi selama empat bulan, jangan ada orang musyrik yang berhaji setelah tahun ini, janganlah mereka berthawaf di baitullah dengan telanjang dan tidak ada yang masuk surga kecuali orang mu`min. Ali yang menyeru dan bila lelah, Abu Bakar berdiri lalu menyerukannya. Abu Isa berkata: Hadits ini hasan gharib. melalui sanad ini dari hadits Ibnu Abbas."},"2875":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ زَيْدِ بْنِ يُثَيْعٍ قَالَ سَأَلْنَا عَلِيًّابِأَيِّ شَيْءٍ بُعِثْتَ فِي الْحَجَّةِ قَالَ بُعِثْتُ بِأَرْبَعٍ أَنْ لَا يَطُوفَ بِالْبَيْتِ عُرْيَانٌ وَمَنْ كَانَ بَيْنَهُ وَبَيْنَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهْدٌ فَهُوَ إِلَى مُدَّتِهِ وَمَنْ لَمْ يَكُنْ لَهُ عَهْدٌ فَأَجَلُهُ أَرْبَعَةُ أَشْهُرٍ وَلَا يَدْخُلُ الْجَنَّةَ إِلَّا نَفْسٌ مُؤْمِنَةٌ وَلَا يَجْتَمِعُ الْمُشْرِكُونَ وَالْمُسْلِمُونَ بَعْدَ عَامِهِمْ هَذَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ مِنْ حَدِيثِ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ أَبِي إِسْحَقَ وَرَوَاهُ الثَّوْرِيُّ عَنْ أَبِي إِسْحَقَ عَنْ بَعْضِ أَصْحَابِهِ عَنْ عَلِيٍّ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي إِسْحَقَ عَنْ زَيْدِ بْنِ يُثَيْعٍ عَنْ عَلِيٍّ نَحْوَهُ حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي إِسْحَقَ عَنْ زَيْدِ بْنِ أُثَيْعٍ عَنْ عَلِيٍّ نَحْوَهُ قَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ ابْنِ عُيَيْنَةَ كِلْتَا الرِّوَايَتَيْنِ يُقَالُ عَنْهُ عَنْ ابْنِ أُثَيْعٍ وَعَنْ ابْنِ يُثَيْعٍ وَالصَّحِيحُ هُوَ زَيْدُ بْنُ يُثَيْعٍ وَقَدْ رَوَى شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ زَيْدٍ غَيْرَ هَذَا الْحَدِيثِ فَوَهِمَ فِيهِ وَقَالَ زَيْدُ بْنُ أُثَيْلٍ وَلَا يُتَابَعُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Zaid bin Yutsai'] berkata: Kami bertanya kepada [Ali], apa yang diutuskan padamu saat haji? Ia menjawab: Aku diutus (untuk menyampaikan) empat hal; tidak boleh thawaf dengan telanjang, siapa pun yang punya janji dengan nabi Shallallahu 'alaihi wa Salam, janji itu berlaku hingga batas waktunya dan siapa pun yang tidak memiliki perjanjian, batas waktunya empat bulan, tidak masuk surga kecuali jiwa yang mu`min dan kaum musyrik tidak boleh menyatu dengan kaum muslimin setelah tahun mereka ini. Abu Isa berkata: Hadits ini hasan shahih dari hadits Sufyan bin Uyainah dari Abu Ishaq. [Ats Tsauri] meriwayatkannya dari [Abu Ishaq] dari [sebagaian sahabatnya] dari [Ali]. Dalam hal ini ada hadits serupa dari Abu Hurairah. Telah menceritakan kepada kami [Nashr bin Ali] dan lainnya, mereka berkata: Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Ishaq] dari [Zaid bin Yutsai'] dari [Ali] sepertinya. Telah menceritakan kepada kami [Ali bin Khasyram] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Ishaq] dari [Zaid bin Yutsai'] dari [Ali] sepertinya. Abu Isa berkata: Kedua hadits ini diriwayatkan dari Ibnu Uyainah, ada yang mengatakan dari Ibnu Utsyai' dan dari Ibnu Yusatai', yang benar dia adalah Zaid bin Yutsyai'. Syu'bah meriwayatkan bukan hadits ini dari Abu Ishaq dari Zaid lalu ia salah Didalamnya dan berkata: Zaid bin Utsail, tapi kesalahan ini tidak diteliti."},"2876":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ ثَوْبَانَ قَالَلَمَّا نَزَلَتْ{ وَالَّذِينَ يَكْنِزُونَ الذَّهَبَ وَالْفِضَّةَ }قَالَ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ فَقَالَ بَعْضُ أَصْحَابِهِ أُنْزِلَ فِي الذَّهَبِ وَالْفِضَّةِ مَا أُنْزِلَ لَوْ عَلِمْنَا أَيُّ الْمَالِ خَيْرٌ فَنَتَّخِذَهُ فَقَالَ أَفْضَلُهُ لِسَانٌ ذَاكِرٌ وَقَلْبٌ شَاكِرٌ وَزَوْجَةٌ مُؤْمِنَةٌ تُعِينُهُ عَلَى إِيمَانِهِقَالَ هَذَا حَدِيثٌ حَسَنٌ سَأَلْتُ مُحَمَّدَ بْنَ إِسْمَعِيلَ فَقُلْتُ لَهُ سَالِمُ بْنُ أَبِي الْجَعْدِ سَمِعَ مِنْ ثَوْبَانَ فَقَالَ لَا فَقُلْتُ لَهُ مِمَّنْ سَمِعَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَمِعَ مِنْ جَابِرِ بْنِ عَبْدِ اللَّهِ وَأَنَسِ بْنِ مَالِكٍ وَذَكَرَ غَيْرَ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Isra'il] dari [Manshur] dari [Salim bin Abu Al Ja'du] dari [Tsauban] berkata: Saat turun ayat: \"Dan orang-orang yang menyimpan emas dan perak.\" (At Taubah: 34) kami bersama nabi Shallallahu 'alaihi wa Salam dalam salah satu perjalanan beliau lalu sebagian sahabat beliau berkata: Telah diturunkan (ayat) tentang emas dan perak seperti itu, andai saja kita tahu harta terbaik lalu kita mengambilnya. Lalu beliau bersabda: \"Harta terbaik adalah lisan yang berdzikir, hati yang bersyukur dan istri mu`minah yang membantu keimanannya (suami).\" Abu Isa berkata: hadits ini hasan, aku bertanya kepada Muhammad bin Ismail, aku berkata padanya: Salim bin Abu Al ja'ad mendengar dari Tsauban? Ia menjawab: Tidak. Aku bertanya padanya: Dari mana ia (Salim) mendengar dari sahabat nabi Shallallahu 'alaihi wa Salam? Ia menjawab: Ia (Salim) mendengar dari Jabir bin Abdullah, Anas bin Malik dan ia menyebut beberapa sahabat nabi Shallallahu 'alaihi wa Salam."},"2877":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ يَزِيدَ الْكُوفِيُّ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ غُطَيْفِ بْنِ أَعْيَنَ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي عُنُقِي صَلِيبٌ مِنْ ذَهَبٍ فَقَالَ يَا عَدِيُّ اطْرَحْ عَنْكَ هَذَا الْوَثَنَ وَسَمِعْتُهُ يَقْرَأُ فِي سُورَةِ بَرَاءَةٌ{ اتَّخَذُوا أَحْبَارَهُمْ وَرُهْبَانَهُمْ أَرْبَابًا مِنْ دُونِ اللَّهِ }قَالَ أَمَا إِنَّهُمْ لَمْ يَكُونُوا يَعْبُدُونَهُمْ وَلَكِنَّهُمْ كَانُوا إِذَا أَحَلُّوا لَهُمْ شَيْئًا اسْتَحَلُّوهُ وَإِذَا حَرَّمُوا عَلَيْهِمْ شَيْئًا حَرَّمُوهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ السَّلَامِ بْنِ حَرْبٍ وَغُطَيْفُ بْنُ أَعْيَنَ لَيْسَ بِمَعْرُوفٍ فِي الْحَدِيثِ","id":"Telah menceritakan kepada kami [Al Husain bin Yazid Al Kufi] telah menceritakan kepada kami [Abdussalam bin Harb] dari [Ghuthaif bin A'yan] dari [Mush'ab bin Sa'ad] dari [Adi bin Hatim] berkata: Aku mendatangi nabi Shallallahu 'alaihi wa Salam dan di leherku ada salib emas, beliau bersabda: \"Hai Adi, buanglah patung ini darimu.\" Dan aku mendengar beliau membaca dalam surat Al Baraa`ah: Mereka menjadikan orang-orang alimnya dan rahib-rahib mereka sebagai Tuhan selain Allah.' (At Taubah: 31) beliau bersabda: \"Ingat, sesungguhnya mereka tidak menyembah mereka tapi bila mereka menghalalkan sesuatu, mereka menghalalkannya dan bila mengharamkan sesuatu, mereka mengharamkannya.\" Abu Isa berkata: Hadits ini gharib, kami hanya mengetahuinya dari hadits Abdussalam bin Harb sementara Ghuthaif bin A'yan tidak dikenal dalam hadits."},"2878":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ أَبِيهِ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَال سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُلَمَّا تُوُ��ِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ دُعِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلصَّلَاةِ عَلَيْهِ فَقَامَ إِلَيْهِ فَلَمَّا وَقَفَ عَلَيْهِ يُرِيدُ الصَّلَاةَ تَحَوَّلْتُ حَتَّى قُمْتُ فِي صَدْرِهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَعَلَى عَدُوِّ اللَّهِ عَبْدِ اللَّهِ بْنِ أُبَيٍّ الْقَائِلِ يَوْمَ كَذَا وَكَذَا كَذَا وَكَذَا يَعُدُّ أَيَّامَهُ قَالَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَبَسَّمُ حَتَّى إِذَا أَكْثَرْتُ عَلَيْهِ قَالَ أَخِّرْ عَنِّي يَا عُمَرُ إِنِّي خُيِّرْتُ فَاخْتَرْتُ قَدْ قِيلَ لِي{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }لَوْ أَعْلَمُ أَنِّي لَوْ زِدْتُ عَلَى السَّبْعِينَ غُفِرَ لَهُ لَزِدْتُ قَالَ ثُمَّ صَلَّى عَلَيْهِ وَمَشَى مَعَهُ فَقَامَ عَلَى قَبْرِهِ حَتَّى فُرِغَ مِنْهُ قَالَ فَعُجِبَ لِي وَجُرْأَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ فَوَاللَّهِ مَا كَانَ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ هَاتَانِ الْآيَتَانِ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }إِلَى آخِرِ الْآيَةِ قَالَ فَمَا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَهُ عَلَى مُنَافِقٍ وَلَا قَامَ عَلَى قَبْرِهِ حَتَّى قَبَضَهُ اللَّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'ad] dari [ayahnya] dari [Muhammad bin Ishaq] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin Utbah] dari [Ibnu Abbas] berkata: Saya pernah mendengar [Umar bin Al Khaththab] berkata: Pada hari kematian Abdullah bin Ubbai bin Salul, Rasulullah Shallallahu 'alaihi wa Salam dipanggil untuk menshalatinya, beliau berdiri namun tatkala beliau hendak shalat, aku beranjak dan berdiri didepan beliau: Wahai Rasulullah apakah engkau hendak menshalati musuh Allah Abdulllah bin Ubbai yang telah banyak melontarkan ucapan-ucapan menyakitkan semasa hidupnya? Rasulullah Shallallahu 'alaihi wa Salam pada saat itu hanya tersenyum dan setelah aku tanya beliau berulang-ulang, beliau mengatakan: \"Biarkan aku wahai Umar karena telah diberi pilihan dan aku akan memilih. Sungguh telah datang (wahyu) kepadaku: 'Kamu memohonkan ampun bagi mereka atau tidak kamu mohonkan ampun bagi mereka (adalah sama saja). Kendatipun kamu memohonkan ampun bagi mereka tujuh puluh kali, namun Allah sekali-kali tidak akan memberi ampunan kepada mereka. (At Taubah: 80) seandainya dengan memohon ampunan lebih dari tujuhpuluh kali ia akan diampuni, maka aku akan melakukannya.\" Beliau menshalati dan mengantarnya, lalu beliau berdiri didepan kuburnya, setelah beliau selesai, aku merasa heran pada keberanianku terhadap Rasulullah Shallallahu 'alaihi wa Salam. Allah dan RasulNya lebih mengetahui, tetapi tidak lama berselang, turunlah ayat ini: \"Dan janganlah kamu sekali-kali menyembahyangkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendo'akan) di kuburnya.\" (At Taubah: 84) Abu Isa mengatakan bahwa hadits ini hasan shahih gharib."},"2879":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ أَخْبَرَنَا نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَجَاءَ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ أُبَيٍّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ مَاتَ أَبُوهُ فَقَالَ أَعْطِنِي قَمِيصَكَ أُكَفِّنْهُ فِيهِ وَصَلِّ عَلَيْهِ وَاسْتَغْفِرْ لَهُ فَأَعْطَاهُ قَمِيصَهُ وَقَالَ إِذَا فَرَغْتُمْ فَآذِنُونِي فَلَمَّا أَرَادَ أَنْ يُصَلِّيَ جَذَبَهُ عُمَرُ وَقَالَ أَلَيْسَ قَدْ نَهَى اللَّهُ أَنْ تُصَلِّيَ عَلَى الْمُنَافِقِينَ فَقَالَ أَنَا بَيْنَ خِيرَتَيْنِ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ }فَصَلَّى عَلَيْهِ فَأَنْزَلَ اللَّهُ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }فَتَرَكَ الصَّلَاةَ عَلَيْهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Ubaidullah] telah mengkhabarkan kepada kami [Nafi'] dari [Ibnu Umar] berkata: Abdullah bin Abdullah bin Ubai mendatangi nabi Shallallahu 'alaihi wa Salam pada hari kematian bapaknya datang kepada Nabi Shallallahu 'alaihi wa Salam dan mengatakan: Sudikah baginda memberikan pakaian baginda lalu kujadikan kafan untuknya, shalatilah dia dan memintakan ampunan untuknya? beliau memberikan pakaiannya dan bersabda: \"Jika kalian telah selesai beritahu aku!\" ketika beliau hendak menshalatinya, Umar menghalanginya seraya mengatakan: Bukankah Allah melarang baginda untuk menshalati orang munafik? lalu beliau menjawab: \"Aku berada diantara dua pilihan: 'kamu memintakan ampunan ataupun kamu tidak memintakan ampunan untuk mereka, ' beliau menshalatinya lalu Allah menurunkan \"Dan janganlah kamu sekali-kali menyembahyangkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendo'akan) di kuburnya.\" (At Taubah: 84) Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2880":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ عِمْرَانَ بْنِ أَبِي أَنَسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ قَالَتَمَارَى رَجُلَانِ فِي الْمَسْجِدِ الَّذِي أُسِّسَ عَلَى التَّقْوَى مِنْ أَوَّلِ يَوْمٍ فَقَالَ رَجُلٌ هُوَ مَسْجِدُ قُبَاءَ وَقَالَ الْآخَرُ هُوَ مَسْجِدُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ مَسْجِدِي هَذَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ عِمْرَانَ بْنِ أَبِي أَنَسٍ وَقَدْ رُوِيَ هَذَا عَنْ أَبِي سَعِيدٍ مِنْ غَيْرِ هَذَا الْوَجْهِ وَرَوَاهُ أُنَيْسُ بْنُ أَبِي يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Imran bin Abu Anas] dari [Abdurrahman bin Abu Sa'ad] dari [Abu Sa'id Al Khudhri] berkata: Ada dua orang memperdebatkan masjid yang dibangun diatas landasan ketakwaan dari sejak hari pertama, salah satunya mengatakan bahwa maksudnya adalah masjid Quba` yang lain beranggapan maksudnya adalah masjid Rasulullah. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Yang dimaksud adalah masjidku ini.\" Abu Isa mengatakan bahwa hadits ini hasan shahih gharib dari hadits Imran bin Abu Anas. Dan hadits ini juga diriwayatkan dari Abu Sa'id melalui sanad lain. [Unais bin Abu Yahya] meriwayatkannya dari [ayahnya] dari [Abu Sa'id radliallahu 'anhu]."},"2881":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِ اللَّهِ عَزَّ وَجَلَّ{ لِلَّذِينَ أَحْسَنُوا الْحُسْنَى وَزِيَادَةٌ }قَالَ إِذَا دَخَلَ أَهْلُ الْجَنَّةِ الْجَنَّةَ نَادَى مُنَادٍ إِنَّ لَكُمْ عِنْدَ اللَّهِ مَوْعِدًا يُرِيدُ أَنْ يُنْجِزَكُمُوهُ قَالُوا أَلَمْ يُبَيِّضْ وُجُوهَنَا وَيُنْجِنَا مِنْ النَّارِ وَيُدْخِلْنَا الْجَنَّةَ قَالَ فَيُكْشَفُ الْحِجَابُ قَالَ فَوَاللَّهِ مَا أَعْطَاهُمْ اللَّهُ شَيْئًا أَحَبَّ إِلَيْهِمْ مِنْ النَّظَرِ إِلَيْهِقَالَ أَبُو عِيسَى حَدِيثُ حَمَّادِ بْنِ سَلَمَةَ هَكَذَا رَوَاهُ غَيْرُ وَاحِدٍ عَنْ حَمَّادِ بْنِ سَلَمَةَ مَرْفُوعًا رَوَاهُ سُلَيْمَانُ بْنُ الْمُغِيرَةِ هَذَا الْحَدِيثَ عَنْ ثَابِتٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَوْلَهُ وَلَمْ يَذْكُرْ فِيهِ عَنْ صُهَيْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit Al Bunani] dari [Abdurrahman bin Abi Laila] dari [Shuhaib] dari Nabi tentang firman Allah 'azza wajalla: \"Bagi orang-orang yang berbuat baik, ada pahala yang terbaik (surga) dan tambahannya.\" (Yuunus: 26) beliau bersabda: \"Jika penghuni surga memasuki surga, ada yang berseru: Sesungguhnya Allah memiliki satu janji yang ingin Dia penuhi untuk kalian semua. Mereka berkata: Bukankah Allah telah membuat wajah kami putih berseri, menyelamatkan kami dari neraka, dan memasukkan kami ke dalam surga? lalu dibukalah tabir, maka demi Allah, Dia tidak memberikan sesuatu yang paling mereka sukai dari pada memandangNya. Abu Isa berkata: Hadits Hammad bin Salamah seperti ini diriwayatkan oleh beberapa orang dari Hammad bin Salamah secara marfu'. [Sulaiman bin Al Mughirah] juga meriwayatkan hadits ini dari [Tsabit] dari [Abdurrahman bin Abu Laila] dengan menyebut sabda nabi Shallallahu 'alaihi wa Salam tapi ia tidak menyebut: Dari Shuhaib dari nabi Shallallahu 'alaihi wa Salam."},"2882":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ الْمُنْكَدِرِ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رَجُلٍ مِنْ أَهْلِ مِصْرَ قَالَسَأَلْتُ أَبَا الدَّرْدَاءِ عَنْ هَذِهِ الْآيَةِ{ لَهُمْ الْبُشْرَى فِي الْحَيَاةِ الدُّنْيَا }قَالَ مَا سَأَلَنِي عَنْهَا أَحَدٌ مُنْذُ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْهَا فَقَالَ مَا سَأَلَنِي عَنْهَا أَحَدٌ غَيْرُكَ مُنْذُ أُنْزِلَتْ فَهِيَ الرُّؤْيَا الصَّالِحَةُ يَرَاهَا الْمُسْلِمُ أَوْ تُرَى لَهُحَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رَجُلٍ مِنْ أَهْلِ مِصْرَ عَنْ أَبِي الدَّرْدَاءِ فَذَكَرَ نَحْوَهُ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي الدَّرْدَاءِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَلَيْسَ فِيهِ عَنْ عَطَاءِ بْنِ يَسَارٍ وَفِي الْبَاب عَنْ عُبَادَةَ بْنِ الصَّامِتِ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Ibnu Al Munkadir] dari [Atho` bin Yasar] dari [seorang penduduk Mesir], ia berkata: Aku bertanya kepada [Abu Ad Darda`] tentang ayat ini: \"Bagi mereka berita gembira di dalam kehidupan di dunia dan (dalam kehidupan) di akhirat.\" (Yuunus: 64) ia menjawab: Tidak ada seorang pun yang menanyakannya padaku sejak aku menanyakannya pada Rasulullah Shallallahu 'alaihi wa Salam, beliau menjawab: Tidak ada yang menanyakannya padaku selainmu sejak ayat itu diturunkan, ia adalah mimpi baik yang dilihat oleh orang mu`min atau diperlihatkan padanya.\" Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Abdul Aziz bin Rufai'] dari [Abu Shalih As Sammani] dari [Atho` bin Yasar] dari [seorang penduduk Mesir] dari [Abu Ad Darda`] lalu ia menyebut sepertinya. Telah menceritakan kepada kami [Ahmad bin Abdah Adl Dlabbi] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ashim bin Bahdalah] dari [Abu Shalih] dari [Abu Ad Darda`] dari nabi Shallallahu 'alaihi wa Salam sepertinya namun tidak disebutkan: Dari Atho` bin Yasar. Dalam hal ini ada hadits serupa dari Ubadah bin Ash Shamit."},"2883":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا الْحَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ يُوسُفَ بْنِ مِهْرَانَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمَّا أَغْرَقَ اللَّهُ فِرْعَوْنَ قَالَ{ آمَنْتُ أَنَّهُ لَا إِلَهَ إِلَّا الَّذِي آمَنَتْ بِهِ بَنُو إِسْرَائِيلَ }فَقَالَ جِبْرِيلُ يَا مُحَمَّدُ فَلَوْ رَأَيْتَنِي وَأَنَا آخُذُ مِنْ حَالِ الْبَحْرِ فَأَدُسُّهُ فِي فِيهِ مَخَافَةَ أَنْ تُدْرِكَهُ الرَّحْمَةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Al Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ali bin Zaid] dari [Yusuf bin Mihran] dari [Ibnu Abbas] bahwa Nabi Shallallahu 'alaihi wa Salam bersabda: \"Ketika Allah menenggelamkan Fir'aun, ia mengatakan: Aku beriman bahwa tiada tuhan selain yang diimani Bani Israil. Jibril berkata: Wahai Muhammad, Duh seandainya engkau melihatku ketika sedang mengurusi keadaan laut, lalu aku sumpal mulutnya karena khawatir ia mendapat rahmat. Abu Isa mengatakan bahwa hadits ini hasan."},"2884":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ أَخْبَرَنَا شُعْبَةُ أَخْبَرَنِي عَدِيُّ بْنُ ثَابِتٍ وَعَطَاءُ بْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ ذَكَرَ أَحَدُهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ ذَكَرَ أَنَّ جِبْرِيلَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَعَلَ يَدُسُّ فِي فِي فِرْعَوْنَ الطِّينَ خَشْيَةَ أَنْ يَقُولَ لَا إِلَهَ إِلَّا اللَّهُ فَيَرْحَمَهُ اللَّهُ أَوْ خَشْيَةَ أَنْ يَرْحَمَهُ اللَّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul a'la Ash Shan'ani] telah menceritakan kepada kami [Khalid bin Al Harits] telah mengkhabarkan kepada kami [Syu'bah] telah mengkhabarkan kepadaku [Adi bin Tsabit] dan [Atho` bin As Sa`ib] dari [Sa'id bin Jubair] dari [Ibnu Abbas], salah satunya menyebutkan dari Nabi Shallallahu 'alaihi wa Salam bahwa beliau menceritakan, Jibril 'alaihis salam menyumpalkan tanah ke mulut Fir'aun karena khawatir ia mengucapkan Laa ilaaha illallaah kemudian Allah merahmatinya atau takut kalau Allah mencurahkan rahmat padanya. Abu Isa mengatakan bahwa hadits ini hasan shahih gharib."},"2885":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ وَكِيعِ بْنِ حُدُسٍ عَنْ عَمِّهِ أَبِي رَزِينٍ قَالَ قُلْتُيَا رَسُولَ اللَّهِ أَيْنَ كَانَ رَبُّنَا قَبْلَ أَنْ يَخْلُقَ خَلْقَهُ قَالَ كَانَ فِي عَمَاءٍ مَا تَحْتَهُ هَوَاءٌ وَمَا فَوْقَهُ هَوَاءٌ وَخَلَقَ عَرْشَهُ عَلَى الْمَاءِقَالَ أَحْمَدُ بْنُ مَنِيعٍ قَالَ يَزِيدُ بْنُ هَارُونَ الْعَمَاءُ أَيْ لَيْسَ مَعَهُ شَيْءٌ قَالَ أَبُو عِيسَى هَكَذَا رَوَى حَمَّادُ بْنُ سَلَمَةَ وَكِيعُ بْنُ حُدُسٍ وَيَقُولُ شُعْبَةُ وَأَبُو عَوَانَةَ وَهُشَيْمٌ وَكِيعُ بْنُ عُدُسٍ وَهُوَ أَصَحُّ وَأَبُو رَزِينٍ اسْمُهُ لَقِيطُ بْنُ عَامِرٍ قَالَ وَهَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Yazid bin Harun] telah mengkhabarkan kepada kami [Hammad bin Salamah] dari [Ya'la bin Atho`] dan [Waki' bin Hudus] dari [pamannya, Abu Razin] berkata: Aku pernah bertanya: Wahai Rasulullah dimanakah Allah sebelum Dia menciptakan makhlukNya? beliau menjawab: \"Dia berada di awan yang tinggi, di atas dan di bawahnya tidak ada udara dan Dia menciptakan 'arsyNya di atas air.\" Ahmad bin Mani' berkata: Yazid bin Harun berkata: Istilah Ama` adalah tidak ada sesuatu pun bersamanya. Abu Isa berkata: Seperti itu Hammad bin Salamah dan Waki' meriwayatkan. Syu'bah, Abu Awanah, Husyaim dan Waki' bin Udus mengatakan dan itu lebih shahih. Abu Razin namanya Laqith bin Amir. Abu Isa mengatakan bahwa hadits ini hasan."},"2886":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يُمْلِي وَرُبَّمَا قَالَ يُمْهِلُ لِلظَّالِمِ حَتَّى إِذَا أَخَذَهُ لَمْ يُفْلِتْهُ ثُمَّ قَرَأَ{ وَكَذَلِكَ أَخْذُ رَبِّكَ إِذَا أَخَذَ الْقُرَى وَهِيَ ظَالِمَةٌ }الْآيَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَقَدْ رَوَاهُ أَبُو أُسَامَةَ عَنْ بُرَيْدٍ نَحْوَهُ وَقَالَ يُمْلِي حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ عَنْ أَبِي أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ جَدِّهِ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَقَالَ يُمْلِي وَلَمْ يَشُكَّ فِيهِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Buraid bin Abdullah] dari [Abu Buraidah] dari [Abu Musa] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya Allah Tabaaraka wa Ta'ala menangguhkan -mungkin bersabda: memberi penangguhan- untuk orang zhalim, hingga ketika Ia menyiksanya Dia tidak membiarkannya terlepas, \" lalu beliau membaca: \"Dan begitulah azab Tuhanmu, apabila dia mengazab penduduk negeri-negeri yang berbuat zhalim. Sesungguhnya azab-Nya itu adalah sangat pedih lagi keras.\" (Huud: 102) Abu Isa berkata: Hadits ini hasan shahih gharib. Abu Usamah meriwayatkannya dari Buraidah sepertinya dan berkata: Menangguhkan. Telah menceritakan kepada kami [Ibrahim bin Sa'id Al Jauhari] dari [Abu Usamah] dari [Buraid bin Abdullah bin Abu Burdah] dari [kakeknya, Abu Burdah] dari [Abu Musa] dari nabi Shallallahu 'alaihi wa Salam sepertinya dan berkata: Menangguhkan. Ia tidak ragu."},"2887":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ هُوَ عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا سُلَيْمَانُ بْنُ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةَ{ فَمِنْهُمْ شَقِيٌّ وَسَعِيدٌ }سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا نَبِيَّ اللَّهِ فَعَلَى مَا نَعْمَلُ عَلَى شَيْءٍ قَدْ فُرِغَ مِنْهُ أَوْ عَلَى شَيْءٍ لَمْ يُفْرَغْ مِنْهُ قَالَ بَلْ عَلَى شَيْءٍ قَدْ فُرِغَ مِنْهُ وَجَرَتْ بِهِ الْأَقْلَامُ يَا عُمَرُ وَلَكِنْ كُلٌّ مُيَسَّرٌ لِمَا خُلِقَ لَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ الْمَلِكِ بْنِ عَمْرٍو","id":"Telah menceritakan kepada kami [Bundar] telah menceritakan kepada kami [Abu Amir Al Aqadi Abdul Malik bin Amru] telah menceritakan kepada kami [Sulaiman bin Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] dari [Umar bin Al Khaththab] berkata: Ketika turun ayat: \"Maka di antara mereka ada yang celaka dan ada yang berbahagia.\" (Huud: 105) aku bertanya kepada Rasulullah Shallallahu 'alaihi wa Salam: Wahai Nabi Allah, apakah kami melakukan amalan berdasarkan sesuatu yang telah ditentukan ataukah berdasarkan sesuatu yang belum ditentukan? beliau menjawab: \"Berdasarkan sesuatu yang telah ditentukan (takdirnya), dan itu telah digariskan oleh pena, wahai Umar. Akan tetapi setiap orang diberi kemudahan untuk sesuatu yang diciptakan untuknya.\" Abu Isa mengatakan bahwa hadits ini hasan gharib. melalui sanad ini, kami hanya mengetahuinya dari hadits Abdulmalik bin Amru."},"2888":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ وَالْأَسْوَدِ عَنْ عَبْدِ اللَّهِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي عَالَجْتُ امْرَأَةً فِي أَقْصَى الْمَدِينَةِ وَإِنِّي أَصَبْتُ مِنْهَا مَا دُونَ أَنْ أَمَسَّهَا وَأَنَا هَذَا فَاقْضِ فِيَّ مَا شِئْتَ فَقَالَ لَهُ عُمَرُ لَقَدْ سَتَرَكَ اللَّهُ لَوْ سَتَرْتَ عَلَى نَفْسِكَ فَلَمْ يَرُدَّ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا فَانْطَلَقَ الرَّجُلُ فَأَتْبَعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا فَدَعَاهُ فَتَلَا عَلَيْهِ{ وَأَقِمْ الصَّلَاةَ طَرَفَيْ النَّهَارِ وَزُلَفًا مِنْ اللَّيْلِ إِنَّ الْحَسَنَاتِ يُذْهِبْنَ السَّيِّئَاتِ ذَلِكَ ذِكْرَى لِلذَّاكِرِينَ }إِلَى آخِرِ الْآيَةِ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ هَذَا لَهُ خَاصَّةً قَالَ لَا بَلْ لِلنَّاسِ كَافَّةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا رَوَى إِسْرَائِيلُ عَنْ سِمَاكٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ وَالْأَسْوَدِ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَرَوَى سُفْيَانُ الثَّوْرِيُّ عَنْ سِمَاكٍ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ وَرِوَايَةُ هَؤُلَاءِ أَصَحُّ مِنْ رِوَايَةِ الثَّوْرِيِّ وَرَوَى شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى النَّيْسَابُورِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ الْأَعْمَشِ وَسِمَاكٌ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ سِمَاكٍ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ وَلَمْ يَذْكُرْ فِيهِ الْأَعْمَشَ وَقَدْ رَوَى سُلَيْمَانُ التَّيْمِيُّ هَذَا الْحَدِيثَ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ ابْنِ مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak bin Harb] dari [Ibrahim] dari [Alqamah] dan [Al Aswad] dari [Abdullah] berkata: Ada seseorang datang kepada Nabi Shallallahu 'alaihi wa Salam dan mengatakan: Aku bercumbu dengan seorang wanita yang datang dari tempat jauh tetapi tidak sampai menggaulinya maka hukumlah aku ini sesuka Baginda! Umar berkata padanya: Sungguh Allah akan menutupi (kejelekanmu), seandainya engkau menyembunyikannya dalam hatimu. Rasulullah Shallallahu 'alaihi wa Salam tidak melontarkan (jawaban) sedikitpun padanya. Orang itu pergi dan beliau mengikutinya kemudian memanggilnya dan membacakan (ayat) padanya \"Dan dirikanlah sembahyang itu pada kedua tepi siang (pagi dan petang) dan pada bahagian permulaan daripada malam. Sesungguhnya perbuatan-perbuatan yang baik itu menghapuskan (dosa) perbuatan-perbuatan yang buruk. Itulah peringatan bagi orang-orang yang ingat.\" (Huud: 114) seseorang dari mereka bertanya: Apakah khusus untuk dia saja? Beliau menjawab: \"Tidak, tetapi untuk seluruh manusia.\" Abu Isa mengatakan bahwa hadits ini hasan shahih. Seperti itu [Isra'il] meriwayatkan dari [Simak] dari [Ibrahim] dari [Alqamah] dan [Al Aswad] dari [Abdullah] dari nabi Shallallahu 'alaihi wa Salam sepertinya. [Sufyan Ats Tsauri] meriwayatkan dari [Simak] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Abdullah] dari nabi Shallallahu 'alaihi wa Salam sepertinya. Riwayat mereka lebih shahih dari riwayat Ats Tsauri. [Syu'bah] meriwayatkan dari [Simak bin Harb] dari [Ibrahim] dari [Al Aswad] dari [Abdullah] dari nabi Shallallahu 'alaihi wa Salam sepertinya. Telah menceritakan kepada kami [Muhammad bin Yahya An Naisaburi] telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Sufyan Ats Tsauri] dari [Al A'masy] dan [Simak] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Abdullah] dari nabi Shallallahu 'alaihi wa Salam sepertinya dengan maknanya. Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Al Fadll bin Musa] dari [Sufyan] dari [Simak] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Abdullah bin Mas'ud] dari nabi Shallallahu 'alaihi wa Salam sepertinya dengan maknanya tapi tidak menyebut: Al A'masy. Dan [Sulaiman At Taimi] meriwayatkan hadits ini dari [Abu Utsman An Nahdi] dari [Ibnu Mas'ud] dari nabi Shallallahu 'alaihi wa Salam."},"2889":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ الْجُعْفِيُّ عَنْ زَائِدَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ مُعَاذٍ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ رَجُلًا لَقِيَ امْرَأَةً وَلَيْسَ بَيْنَهُمَا مَعْرِفَةٌ فَلَيْسَ يَأْتِي الرَّجُلُ شَيْئًا إِلَى امْرَأَتِهِ إِلَّا قَدْ أَتَى هُوَ إِلَيْهَا إِلَّا أَنَّهُ لَمْ يُج��امِعْهَا قَالَ فَأَنْزَلَ اللَّهُ{ وَأَقِمْ الصَّلَاةَ طَرَفَيْ النَّهَارِ وَزُلَفًا مِنْ اللَّيْلِ إِنَّ الْحَسَنَاتِ يُذْهِبْنَ السَّيِّئَاتِ ذَلِكَ ذِكْرَى لِلذَّاكِرِينَ }فَأَمَرَهُ أَنْ يَتَوَضَّأَ وَيُصَلِّيَ قَالَ مُعَاذٌ فَقُلْتُ يَا رَسُولَ اللَّهِ أَهِيَ لَهُ خَاصَّةً أَمْ لِلْمُؤْمِنِينَ عَامَّةً قَالَ بَلْ لِلْمُؤْمِنِينَ عَامَّةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَيْسَ إِسْنَادُهُ بِمُتَّصِلٍ عَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى لَمْ يَسْمَعْ مِنْ مُعَاذٍ وَمُعَاذُ بْنُ جَبَلٍ مَاتَ فِي خِلَافَةِ عُمَرَ وَقُتِلَ عُمَرُ وَعَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى غُلَامٌ صَغِيرٌ ابْنُ سِتِّ سِنِينَ وَقَدْ رَوَى عَنْ عُمَرَ وَرَآهُ وَرَوَى شُعْبَةُ هَذَا الْحَدِيثَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلٌ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Husain bin Ali Al Ju'fi] dari [Za`idah] dari [Abdul Malik bin Umair] dari [Abdurrahman bin Abi Laila] dari [Mu'adz] berkata: Seseorang mendatangi Nabi Shallallahu 'alaihi wa Salam lalu bertanya: Bagaimana jika ada seorang laki-laki bertemu dengan seorang wanita padahal mereka tidak saling mengenal dan lelaki itu bercumbu dengannya akan tetapi tidak sampai menggaulinya? ia berkata: Lalu Allah menurunkan \"Dan dirikanlah sembahyang itu pada kedua tepi siang (pagi dan petang) dan pada bahagian permulaan daripada malam. Sesungguhnya perbuatan-perbuatan yang baik itu menghapuskan (dosa) perbuatan-perbuatan yang buruk. Itulah peringatan bagi orang-orang yang ingat.\" (Huud: 114) kemudian beliau menyuruhnya untuk berwudhu dan shalat. Lantas Mu'adz bertanya: Wahai Rasulullah apakah ini dikhususkan baginya ataukah untuk kaum mu`minin secara keseluruhan? beliau menjawab: \"Ini untuk kaum mu`minin secara keseluruhan.\" Abu Isa berkata: Hadits ini sanadnya tidak tersambung. Abdurrahman bin Abu Laila tidak mendengar dari Mu'adz. Mu'adz bin Jabal meninggal di masa khilafah Umar. Umar meninggal saat Abdurrahman bin Abu Laila masih kecil berusia enam tahun. Ia perna meriwayatkan dari Umar dan pernah melihatnya. [Syu'bah] meriwayatkan hadits ini dari [Abdul Malik bin Umair] dari [Abdurrahman bin Abu Laila] dari nabi Shallallahu 'alaihi wa Salam secara mursal."},"2890":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ عَنْ ابْنِ مَسْعُودٍأَنَّ رَجُلًا أَصَابَ مِنْ امْرَأَةٍ قُبْلَةَ حَرَامٍ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ كَفَّارَتِهَا فَنَزَلَتْ{ وَأَقِمْ الصَّلَاةَ طَرَفَيْ النَّهَارِ وَزُلَفًا مِنْ اللَّيْلِ إِنَّ الْحَسَنَاتِ يُذْهِبْنَ السَّيِّئَاتِ }فَقَالَ الرَّجُلُ أَلِي هَذِهِ يَا رَسُولَ اللَّهِ فَقَالَ لَكَ وَلِمَنْ عَمِلَ بِهَا مِنْ أُمَّتِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sulaiman At Taimi] dari [Abu Utsman] dari [Ibnu Mas'ud], Ada seorang lelaki mencium seorang wanita, lalu ia mengahadap Nabi Shallallahu 'alaihi wa Salam dan bertanya tentang kaffaratnya (tebusannya) maka turunlah ayat: \"Dan dirikanlah sembahyang itu pada kedua tepi siang (pagi dan petang) dan pada bahagian permulaan daripada malam. Sesungguhnya perbuatan-perbuatan yang baik itu menghapuskan (dosa) perbuatan-perbuatan yang buruk.\" (Huud: 114) lantas lelaki itu bertanya lagi: Apakah ini khusus untukku wahai Rasulullah? beliau menjawab: \"Untukmu dan untuk ummatku yang melakukannya.\" Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2891":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا قَيْسُ بْنُ الرَّبِيعِ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِي الْيَسَرِ قَالَأَتَتْنِي امْرَأَةٌ تَبْتَاعُ تَمْرًا فَقُلْتُ إِنَّ فِي الْبَيْتِ تَمْرًا أَطْيَبَ مِنْهُ فَدَخَلَتْ مَعِي فِي الْبَيْتِ فَأَهْوَيْتُ إِلَيْهَا فَتَقَبَّلْتُهَا فَأَتَيْتُ أَبَا بَكْرٍ فَذَكَرْتُ ذَلِكَ لَهُ قَالَ اسْتُرْ عَلَى نَفْسِكَ وَتُبْ وَلَا تُخْبِرْ أَحَدًا فَلَمْ أَصْبِرْ فَأَتَيْتُ عُمَرَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ اسْتُرْ عَلَى نَفْسِكَ وَتُبْ وَلَا تُخْبِرْ أَحَدًا فَلَمْ أَصْبِرْ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ أَخَلَفْتَ غَازِيًا فِي سَبِيلِ اللَّهِ فِي أَهْلِهِ بِمِثْلِ هَذَا حَتَّى تَمَنَّى أَنَّهُ لَمْ يَكُنْ أَسْلَمَ إِلَّا تِلْكَ السَّاعَةَ حَتَّى ظَنَّ أَنَّهُ مِنْ أَهْلِ النَّارِ قَالَ وَأَطْرَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَوِيلًا حَتَّى أَوْحَى اللَّهُ إِلَيْهِ{ وَأَقِمْ الصَّلَاةَ طَرَفَيْ النَّهَارِ وَزُلَفًا مِنْ اللَّيْلِ إِلَى قَوْلِهِ ذِكْرَى لِلذَّاكِرِينَ }قَالَ أَبُو الْيَسَرِ فَأَتَيْتُهُ فَقَرَأَهَا عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَصْحَابُهُ يَا رَسُولَ اللَّهِ أَلِهَذَا خَاصَّةً أَمْ لِلنَّاسِ عَامَّةً قَالَ بَلْ لِلنَّاسِ عَامَّةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَقَيْسُ بْنُ الرَّبِيعِ ضَعَّفَهُ وَكِيعٌ وَغَيْرُهُ وَأَبُو الْيَسَرِ هُوَ كَعْبُ بْنُ عَمْرٍو قَالَ وَرَوَى شَرِيكٌ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ هَذَا الْحَدِيثَ مِثْلَ رِوَايَةِ قَيْسِ بْنِ الرَّبِيعِ قَالَ وَفِي الْبَاب عَنْ أَبِي أُمَامَةَ وَوَاثِلَةَ بْنِ الْأَسْقَعِ وَأَنَسِ بْنِ مَالِكٍ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengkhabarkan kepada kami [Yazid bin Harun] telah mengkhabarkan kepada kami [Qais bin Ar Rabi'] dari [Utsman bin Abdullah bin Mauhab] dari [Musa bin Thalhah] dari [Abu Al Yasar] berkata: Seorang wanita datang kepadaku seraya menjual kurma, aku berkata: Di rumah ada kurma yang lebih baik darinya. Wanita itu masuk rumah bersamaku lalu aku meraihnya, aku menciumnya lalu aku mendatangi Abu Bakar dan menyebutkan hal itu. Abu Bakar berkata: Tutupilah (aib) dirimu, bertaubatlah dan jangan beritahukan pada siapa pun. Aku tidak sabar, lalu aku mendatangi Umar dan menyebutkan hal itu padanya. Umar berkata: Tutupilah (aib) dirimu, bertaubatlah dan jangan beritahukan pada siapa pun. Aku tidak sabar lalu aku mendatangi Rasulullah Shallallahu 'alaihi wa Salam lalu aku memberitahukannya kepada beliau, beliau bersabda: \"Apa kau mengkhianati istri orang yang tengah berperang di jalan Allah?\" hingga ia berharap belum masuk Islam kecuali pada saat itu, hingga ia mengira termasuk penghuni neraka. Rasulullah Shallallahu 'alaihi wa Salam terdiam selang berapa lama hingga Allah mewahyukan pada beliau: \"Dan dirikanlah sembahyang itu pada kedua tepi siang (pagi dan petang) dan pada bahagian permulaan daripada malam\" hingga firmanNya: \"Peringatan bagi orang-orang yang mengingat.\" (Huud: 114-115) Abu Al Yasar berkata: Aku mendatangi beliau lalu Rasulullah Shallallahu 'alaihi wa Salam membacakannya padaku kemudian para sahabat beliau berkata: Wahai Rasulullah, apakah untuk dia saja ataukah untuk seluruh manusia? Beliau menjawab: Untuk seluruh manusia.\" Abu Isa berkata: Hadits ini hasan shahih gharib. Qais bin Ar Rabi' dilemahkan oleh Waki' dan lainnya. Abu Al Yasar adalah Ka'ab bin Amru. Abu Isa berkata: [Syarik] meriwayatkan hadits ini dari [Utsman bin Abdullah] seperti riwayat Qais bin Ar Rabi'. Abu Isa berkata: Dalam hal ini ada hadits serupa dari Abu Umamah, Watsilah bin Al Asqa' dan Anas bin Malik."},"2892":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ الْخُزَاعِيُّ الْمَرْوَزِيُّ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْكَرِيمَ ابْنَ الْكَرِيمِ ابْنِ الْكَرِيمِ ابْنِ الْكَرِيمِ يُوسُفُ بْنُ يَعْقُوبَ بْنِ إِسْحَقَ بْنِ إِبْرَاهِيمَ قَالَ وَلَوْ لَبِثْتُ فِي السِّجْنِ مَا لَبِثَ يُوسُفُ ثُمَّ جَاءَنِي الرَّسُولُ أَجَبْتُ ثُمَّ قَرَأَ{ فَلَمَّا جَاءَهُ الرَّسُولُ قَالَ ارْجِعْ إِلَى رَبِّكَ فَاسْأَلْهُ مَا بَالُ النِّسْوَةِ اللَّاتِي قَطَّعْنَ أَيْدِيَهُنَّ }قَالَ وَرَحْمَةُ اللَّهِ عَلَى لُوطٍ إِنْ كَانَ لَيَأْوِي إِلَى رُكْنٍ شَدِيدٍ إِذْ قَالَ{ لَوْ أَنَّ لِي بِكُمْ قُوَّةً أَوْ آوِي إِلَى رُكْنٍ شَدِيدٍ }فَمَا بَعَثَ اللَّهُ مِنْ بَعْدِهِ نَبِيًّا إِلَّا فِي ذِرْوَةٍ مِنْ قَوْمِهِحَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ وَعَبْدُ الرَّحِيمِ عَنْ مُحَمَّدِ بْنِ عَمْرٍو نَحْوَ حَدِيثِ الْفَضْلِ بْنِ مُوسَى إِلَّا أَنَّهُ قَالَ مَا بَعَثَ اللَّهُ بَعْدَهُ نَبِيًّا إِلَّا فِي ثَرْوَةٍ مِنْ قَوْمِهِ قَالَ مُحَمَّدُ بْنُ عَمْرٍو الثَّرْوَةُ الْكَثْرَةُ وَالْمَنَعَةُ قَالَ أَبُو عِيسَى وَهَذَا أَصَحُّ مِنْ رِوَايَةِ الْفَضْلِ بْنِ مُوسَى وَهَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Al Husain bin Huraits Al Khuza'I Al Marwazi] telah menceritakan kepada kami [Al Fadll bin Musa] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bahwa al Kariim (orang mulia) bin Al Karim bin al Karim bin al Karim adalah Yusuf bin Ya'qub bin Ishaq bin Ibrahim.\" Beliau bersabda: \"Seandainya aku tinggal di penjara sebagaimana yang dialami Yusuf, kemudian datang utusan padaku maka aku kujawab, lalu beliau bacakan ayat: 'Kembalilah kepada tuanmu dan tanyakanlah kepadanya bagaimana halnya wanita-wanita yang telah melukai tangannya?\" (Yusuf: 50) dan rahmat Allah atas Luth ketika ia hendak berlindung kepada keluarga yang kuat, ia berkata: \"Seandainya aku mempunyai kekuatan (untuk menolakmu) atau kalau aku dapat berlindung kepada keluarga yang kuat (tentu aku lakukan).\" (Huud: 80) dan Allah tidak mengutus seorang Nabi setelahnya kecuali dari keturunan teratas kaumnya. Abu Kuraib menceritakan pada kami, dari Abdah dan Abdurrahim dari Muhammad bin Amru seputar haditsnya Fadll bin Musa, ia berkata: Allah tidak mengutus seorang nabi setelahnya melainkan dari keturunan terbesar dari kaumnya. Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abdah] dan [Abdurrahim] dari [Muhammad bin Amru] seperti hadits Al Fadll bin Musa hanya saja ia menyebut: Tidaklah Allah mengutus seorang nabi pun setelahnya kecuali dari kaumnya yang terbanyak. Muhammad bin Amru berkata: Tsarwah artinya banyak dan kuat. Abu Isa berkata: Ini lebih shahih dari riwayat Al Fadll bin Musa dan hadits ini hasan."},"2893":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا أَبُو نُعَيْمٍ عَنْ عَبْدِ اللَّهِ بْنِ الْوَلِيدِ وَكَانَ يَكُونُ فِي بَنِي عِجْلٍ عَنْ بُكَيْرِ بْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَأَقْبَلَتْ يَهُودُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا أَبَا الْقَاسِمِ أَخْبِرْنَا عَنْ الرَّعْدِ مَا هُوَ قَالَ مَلَكٌ مِنْ الْمَلَائِكَةِ مُوَكَّلٌ بِالسَّحَابِ مَعَهُ مَخَارِيقُ مِنْ نَارٍ يَسُوقُ بِهَا السَّحَابَ حَيْثُ شَاءَ اللَّهُ فَقَالُوا فَمَا هَذَا الصَّوْتُ الَّذِي نَسْمَعُ قَالَ زَجْرُهُ بِالسَّحَابِ إِذَا زَجَرَهُ حَتَّى يَنْتَهِيَ إِلَى حَيْثُ أُمِرَ قَالُوا صَدَقْتَ فَأَخْبِرْنَا عَمَّا حَرَّمَ إِسْرَائِيلُ عَلَى نَفْسِهِ قَالَ اشْتَكَى عِرْقَ النَّسَا فَلَمْ يَجِدْ شَيْئًا يُلَائِمُهُ إِلَّا لُحُومَ الْإِبِلِ وَأَلْبَانَهَا فَلِذَلِكَ حَرَّمَهَا قَالُوا صَدَقْتَقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengkhabarkan kepada kami [Abu Nu'aim] dari [Abdullah bin Al Walid] ia pernah tinggal bersama Bani Ijil, dari [Bukair bin Syihab] dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata: Orang-orang yahudi mendatangi Rasulullah Shallallahu 'alaihi wa Salam dan berkata: Wahai Abu Al Qasim, ceritakan kepada kami apakah halilintar itu! beliau menjawab: \"Itu adalah seorang malaikat yang ditugaskan (mengatur) awan, bersamanya ada angin dari api untuk menggiring awan sesuai kehendak Allah.\" Mereka bertanya: Lalu dari mana asal suara (halilintar) yang kita dengar itu? Beliau menjawab: \"Itu adalah benturan dengan awan dan akan berhenti sesuai dengan perintah Allah.\" mereka berkata: Engkau benar, lalu ceritakan kepada kami tentang yang diharamkan Isra`il terhadap dirinya sendiri. Beliau menjawab: \"Ia (Ya'qub) menderita penyakit encok tetapi ia tidak mendapati sesuatu yang cocok baginya, yang ada hanyalah daging unta dan susunya, karena itulah beliau mengharamkannya.\" mereka berkata: Engkau benar. Abu Isa mengatakan bahwa hadits ini hasan gharib.."},"2894":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خِدَاشٍ الْبَغْدَادِيُّ حَدَّثَنَا سَيْفُ بْنُ مُحَمَّدٍ الثَّوْرِيُّ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ{ وَنُفَضِّلُ بَعْضَهَا عَلَى بَعْضٍ فِي الْأُكُلِ }قَالَ الدَّقَلُ وَالْفَارِسِيُّ وَالْحُلْوُ وَالْحَامِضُقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ رَوَاهُ زَيْدُ بْنُ أَبِي أُنَيْسَةَ عَنْ الْأَعْمَشِ نَحْوَ هَذَا وَسَيْفُ بْنُ مُحَمَّدٍ هُوَ أَخُو عَمَّارِ بْنِ مُحَمَّدٍ وَعَمَّارٌ أَثْبَتُ مِنْهُ وَهُوَ ابْنُ أُخْتِ سُفْيَانَ الثَّوْرِيِّ","id":"Telah menceritakan kepada kami [Mahmud bin Khidasy Al Baghdadi] telah menceritakan kepada kami [Saif bin Muhammad Ats Tsauri] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam tentang firman Allah: \"Kami melebihkan sebahagian tanam-tanaman itu atas sebahagian yang lain tentang rasanya.\" (Ar Ra'd: 4) beliau bersabda: Kurma dan buah dari Persia, (rasa) manis dan pahit.\" Abu Isa berkata: Hadits ini hasan gharib.. [Zaid bin Abu Unaisah] meriwayatkannya dari [Al A'masy] seperti ini. Saif bin Muhammad adalah saudari Ammar bin Muhammad dan Ammar lebih kuat hafalannya dari dia. Dia adalah keponakan Sufyan Ats Tsauri."},"2895":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ شُعَيْبِ بْنِ الْحَبْحَابِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقِنَاعٍ عَلَيْهِ رُطَبٌ فَقَالَ مَثَلُ{ كَلِمَةً طَيِّبَةً كَشَجَرَةٍ طَيِّبَةٍ أَصْلُهَا ثَابِتٌ وَفَرْعُهَا فِي السَّمَاءِ تُؤْتِي أُكُلَهَا كُلَّ حِينٍ بِإِذْنِ رَبِّهَا }قَالَ هِيَ النَّخْلَةُ{ وَمَثَلُ كَلِمَةٍ خَبِيثَةٍ كَشَجَرَةٍ خَبِيثَةٍ اجْتُثَّتْ مِنْ فَوْقِ الْأَرْضِ مَا لَهَا مِنْ قَرَارٍ }قَالَ هِيَ الْحَنْظَلُقَالَ فَأَخْبَرْتُ بِذَلِكَ أَبَا الْعَالِيَةِ فَقَالَ صَدَقَ وَأَحْسَنَ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو بَكْرِ بْنُ شُعَيْبِ بْنِ الْحَبْحَابِ عَنْ أَبِيهِ عَنْ أَنَسِ بْنِ مَالِكٍ نَحْوَهُ بِمَعْنَاهُ وَلَمْ يَرْفَعْهُ وَلَمْ يَذْكُرْ قَوْلَ أَبِي الْعَالِيَةِ وَهَذَا أَصَحُّ مِنْ حَدِيثِ حَمَّادِ بْنِ سَلَمَةَ وَرَوَى غَيْرُ وَاحِدٍ مِثْلَ هَذَا مَوْقُوفًا وَلَا نَعْلَمُ أَحَدًا رَفَعَهُ غَيْرَ حَمَّادِ بْنِ سَلَمَةَ وَرَوَاهُ مَعْمَرٌ وَحَمَّادُ بْنُ زَيْدٍ وَغَيْرُ وَاحِدٍ وَلَمْ يَرْفَعُوهُ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ شُعَيْبِ بْنِ الْحَبْحَابِ عَنْ أَنَسٍ نَحْوَ حَدِيثِ قُتَيْبَةَ وَلَمْ يَرْفَعْهُ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Hammad bin Salamah] dari [Syu'aib bin Al Habhab] dari [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa Salam diberi kain kudung berisi kurma basah lalu beliau membaca: \"Perumpamaan kalimat yang baik seperti pohon yang baik, akarnya teguh dan cabangnya (menjulang) ke langit, pohon itu memberikan buahnya pada setiap musim dengan seizin Rabbnya.\" (Ibrahiim: 24-25) Beliau bersabda: \"Itulah pohon kurma.\" \"Dan perumpamaan kalimat yang buruk seperti pohon yang buruk, yang telah dicabut dengan akar-akarnya dari permukaan bumi; tidak dapat tetap (tegak) sedikitpun.\" (Ibrahiim: 26) beliau bersabda: \"Itu adalah hanzhal.\" (sejenis labu yang pahit rasanya). Syu'aib berkata: Lalu aku beritahukan hal itu kepada Abu Al Aliyah, ia berkata: Ia benar dan baik. Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu Bakar bin Syu'aib bin Al Habhab] dari [ayahnya] dari [Anas bin Malik] sepertinya dengan maknanya tapi ia tidak memarfu'kannya dan tidak menyebut perkataan Abu Al Aliyah. Ini lebih shahih dari hadits Hammad bin Salamah. Beberapa orang meriwayatkan seperti ini secara mauquf dan kami tidak mengetahui seorang pun memauqufkannya selain Hammad bin Salamah. [Ma'mar], [Hammad bin Zaid] dan lainnya meriwayatkannya dan tidak memarfu'kannya. Telah menceritakan kepada kami [Ahmad bin Abdah Adl Dlabbi] telah menceritakan kepada kami [Hammd bin Zaid] dari [Syu'aib bin Al Habhab] dari [Anas] seprti hadits Qutaibah tapi ia tidak memarfu'kannya."},"2896":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي عَلْقَمَةُ بْنُ مَرْثَدٍ قَال سَمِعْتُ سَعْدَ بْنَ عُبَيْدَةَ يُحَدِّثُ عَنْ الْبَرَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِ اللَّهِ تَعَالَى{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }قَالَ فِي الْقَبْرِ إِذَا قِيلَ لَهُ مَنْ رَبُّكَ وَمَا دِينُكَ وَمَنْ نَبِيُّكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Alqamah bin Martsad] berkata: Aku mendengar [Sa'ad bin Ubaidah] menceritakan dari [Al Barra`] dari nabi Shallallahu 'alaihi wa Salam tentang firman Allah Ta'ala: \"Allah meneguhkan (iman) orang-orang yang beriman dengan Ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat.\" (Ibrahiim: 27) beliau bersabda: \"Di dalam kubur bila ia ditanya: Siapa Rabbmu, apa agamamu dan siapa nabimu?\" Abu Isa berkata: Hadits ini hasan shahih."},"2897":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ دَاوُدَ بْنِ أبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ تَلَتْ عَائِشَةُهَذِهِ الْآيَةَ{ يَوْمَ تُبَدَّلُ الْأَرْضُ غَيْرَ الْأَرْضِ }قَالَتْ يَا رَسُولَ اللَّهِ فَأَيْنَ يَكُونُ النَّاسُ قَالَ عَلَى الصِّرَاطِقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرُوِيَ مِنْ غَيْرِ هَذَا الْوَجْهِ عَنْ عَائِشَةَ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] berkata: [Aisyah] membaca (ayat): \"(Yaitu) pada hari (ketika) bumi diganti dengan bumi yang lain. (Ibrahiim: 48) ia berkata: Wahai Rasulullah dimanakah gerangan manusia (saat itu)? beliau menjawab: \"Di atas Shirath.\" Abu Isa mengatakan bahwa hadits ini hasan shahih. Juga diriwayatkan melalui sanad lain dari Aisyah."},"2898":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا نُوحُ بْنُ قَيْسٍ الْحُدَّانِيُّ عَنْ عَمْرِو بْنِ مَالِكٍ عَنْ أَبِي الْجَوْزَاءِ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَتْ امْرَأَةٌ تُصَلِّي خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَسْنَاءَ مِنْ أَحْسَنِ النَّاسِ فَكَانَ بَعْضُ الْقَوْمِ يَتَقَدَّمُ حَتَّى يَكُونَ فِي الصَّفِّ الْأَوَّلِ لِئَلَّا يَرَاهَا وَيَسْتَأْخِرُ بَعْضُهُمْ حَتَّى يَكُونَ فِي الصَّفِّ الْمُؤَخَّرِ فَإِذَا رَكَعَ نَظَرَ مِنْ تَحْتِ إِبْطَيْهِ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَلَقَدْ عَلِمْنَا الْمُسْتَقْدِمِينَ مِنْكُمْ وَلَقَدْ عَلِمْنَا الْمُسْتَأْخِرِينَ }قَالَ أَبُو عِيسَى وَرَوَى جَعْفَرُ بْنُ سُلَيْمَانَ هَذَا الْحَدِيثَ عَنْ عَمْرِو بْنِ مَالِكٍ عَنْ أَبِي الْجَوْزَاءِ نَحْوَهُ وَلَمْ يَذْكُرْ فِيهِ عَنْ ابْنِ عَبَّاسٍ وَهَذَا أَشْبَهُ أَنْ يَكُونَ أَصَحَّ مِنْ حَدِيثِ نُوحٍ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Nuh bin Qais Al Huddani] dari [Amru bin Malik] dari [Abu Al Jauza`] dari [Ibnu Abbas] berkata: Dahulu ada seorang wanita cantik yang shalat di belakang Rasulullah Shallallahu 'alaihi wa Salam, ia termasuk manusia paling rupawan, lalu sebagian orang maju sehingga dishaf pertama agar tidak melihatnya dan sebagian lainnya mundur hingga berada dishaf terakhir, maka apabila ruku, ' ia melihat dari bawah kedua ketiaknya. Lalu Allah menurunkan: \"Dan sesungguhnya Kami telah mengetahui orang-orang yang terdahulu daripada-mu dan sesungguhnya Kami mengetahui pula orang-orang yang terkemudian (daripadamu).\" (Al Hijr: 24) Abu Isa berkata: [Ja'far bin Sulaiman] meriwayatkan hadits ini dari [Amru bin Malik] dari [Abu Al Jauza`] sepertinya dan tidak menyebutkan: Dari Ibnu Abbas. Ini lebih shahih dari hadits Nuh."},"2899":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ عَنْ مَالِكِ بْنِ مِغْوَلٍ عَنْ جُنَيْدٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِجَهَنَّمَ سَبْعَةُ أَبْوَابٍ بَابٌ مِنْهَا لِمَنْ سَلَّ السَّيْفَ عَلَى أُمَّتِي أَوْ قَالَ عَلَى أُمَّةِ مُحَمَّدٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ مَالِكِ بْنِ مِغْوَلٍ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Utsman bin Umar] dari [Malik bin Mighwal] dari [Junaid] dari [Ibnu Umar] dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Neraka Jahannam itu mempunyai tujuh pintu salah satu (pintu) nya diperuntukkan bagi orang yang menghunus pedang kepada umatku (atau beliau mengatakan) kepada umat Muhammad.\" Abu Isa berkata: Hadits ini gharib, kami hanya mengetahuinya dari hadits Malik bin Mighwal."},"2900":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا أَبُو عَلِيٍّ الْحَنَفِيُّ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَمْدُ لِلَّهِ أُمُّ الْقُرْآنِ وَأُمُّ الْكِتَابِ وَالسَّبْعُ الْمَثَانِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Abu Ali Al Hanafi] dari [Ibnu Abi Dzi`Bukhari] dari [Al Maqburi] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"ALHAMDULILLAAH adalah induknya al Qur'an, induknya al Kitab, dan As Sab'ul Matsaani (tujuh ayat yang diulang-ulang).\" Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2901":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ الْعَلَاءِ بْنِ عَبْدَ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَنْزَلَ اللَّهُ فِي التَّوْرَاةِ وَلَا فِي الْإِنْجِيلِ مِثْلَ أُمِّ الْقُرْآنِ وَهِيَ السَّبْعُ الْمَثَانِي وَهِيَ مَقْسُومَةٌ بَيْنِي وَبَيْنَ عَبْدِي وَلِعَبْدِي مَا سَأَلَحَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَى أُبَيٍّ وَهُوَ يُصَلِّي فَذَكَرَ نَحْوَهُ بِمَعْنَاهُ قَالَ أَبُو عِيسَى حَدِيثُ عَبْدِ الْعَزِيزِ بْنِ مُحَمَّدٍ أَطْوَلُ وَأَتَمُّ وَهَذَا أَصَحُّ مِنْ حَدِيثِ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ هَكَذَا رَوَى غَيْرُ وَاحِدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ","id":"Telah menceritakan kepada kami [Al Husain bin Huraits] telah menceritakan kepada kami [Al Fadll bin Musa] dari [Abdulhamid bin Ja'far] dari [Al Ala` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] dari [Ubai bin Ka'ab] berkata: Nabi Shallallahu 'alaihi wa Salam bersabda: \"Allah tidak menurunkan (surat) di dalam Taurat ataupun di dalam Injil yang seperti induk al Qur'an (al Faatihah), dan ia adalah as Sab'ul Matsani (tujuh ayat yang diulang-ulang) ia juga (surat) yang dibagi antara Aku dan hambaKu dan bagi hambaKu apa yang ia minta.\" Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul aziz bin Muhammad] dari [Al Ala` bin Abdurrahman] dari [bapaknya] dari [Abu Hurairah] bahwa Nabi mendatangi Ubay ketika dia sedang shalat dan bersabda sebagaimana hadits di atas dengan maknanya. Abu Isa berkata: Hadits Abdul aziz bin Muhammad lebih panjang dan lengkap. Hadits ini lebih shahih dari hadits Abdulhamid bin Ja'far seperti ini. Beberapa orang meriwayatkan dari Al Ala' bin Abdurrahman."},"2902":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ لَيْثِ بْنِ أَبِي سُلَيْمٍ عَنْ بِشْرٍ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ{ لَنَسْأَلَنَّهُمْ أَجْمَعِينَ عَمَّا كَانُوا يَعْمَلُونَ }قَالَ عَنْ قَوْلِ لَا إِلَهَ إِلَّا اللَّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ لَيْثِ بْنِ أَبِي سُلَيْمٍ وَقَدْ رَوَى عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ لَيْثِ بْنِ أَبِي سُلَيْمٍ عَنْ بِشْرٍ عَنْ أَنَسٍ نَحْوَهُ وَلَمْ يَرْفَعْهُ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah Adl Dlabbi] telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [Laits bin Abu Sulaim] dari [Bisyr] dari [Anas bin Malik] dari nabi Shallallahu 'alaihi wa Salam tentang firmanNya: \"Maka demi Tuhanmu, kami pasti akan menanyai mereka semua, tentang apa yang telah mereka kerjakan dahulu.\" (Al Hijr: 92-93) beliau bersabda: \"Tentang ucapan: LAA ILAAHA ILLALLAAH.\" Abu Isa berkata: Hadits ini gharib. Kami hanya mengetahuinya dari hadits Laits bin Abu Sulaim. [Abdullah bin Idris] meriwayatkan dari [Laits bin Abu Sulaim] dari [Bisyr] dari [Anas] sepertinya dan ia tidak memarfu'kannya."},"2903":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا أَحْمَدُ بْنُ أَبِي الطَّيِّبِ حَدَّثَنَا مُصْعَبُ بْنُ سَلَّامٍ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّقُوا فِرَاسَةَ الْمُؤْمِنِ فَإِنَّهُ يَنْظُرُ بِنُورِ اللَّهِ ثُمَّ قَرَأَ{ إِنَّ فِي ذَلِكَ لَآيَاتٍ لِلْمُتَوَسِّمِينَ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ إِنَّمَا نَعْرِفُهُ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ عَنْ بَعْضِ أَهْلِ الْعِلْمِ فِي تَفْسِيرِ هَذِهِ الْآيَةِ{ إِنَّ فِي ذَلِكَ لَآيَاتٍ لِلْمُتَوَسِّمِينَ }قَالَ لِلْمُتَفَرِّسِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Ahmad bin Abu Ath Thayyib] telah menceritakan kepada kami [Mush'ab bin Sallam] dari [Amru bin Qais] dari [Athiyah] dari [Abu Sa'id Al Khudri] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Takutlah pada firasat orang mu`min karena sesungguhnya ia melihat dengan cahaya Allah.\" Lalu beliau membaca: \"Sesungguhnya pada yang demikian itu benar-benar terdapat tanda-tanda (kekuasaan Allah) bagi orang-orang yang memperhatikan tanda-tanda.\" (Al Hijr: 75) Abu Isa berkata: Hadits ini gharib, kami hanya mengetahuinya dari sanad ini. dan diriwayatkan dari sebagaian ahlul ilmi tentang penafsiran ayat ini: \"Sesungguhnya pada yang demikian itu benar-benar terdapat tanda-tanda (kekuasaan Allah) bagi orang-orang yang memperhatikan tanda-tanda.\" Yaitu untuk yang menjelaskan tanda-tanda."},"2904":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَلِيُّ بْنُ عَاصِمٍ عَنْ يَحْيَى الْبَكَّاءِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عُمَرَ قَال سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعٌ قَبْلَ الظُّهْرِ بَعْدَ الزَّوَالِ تُحْسَبُ بِمِثْلِهِنَّ فِي صَلَاةِ السَّحَرِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ مِنْ شَيْءٍ إِلَّا وَيُسَبِّحُ اللَّهَ تِلْكَ السَّاعَةَ ثُمَّ قَرَأَ{ يَتَفَيَّأُ ظِلَالُهُ عَنْ الْيَمِينِ وَالشَّمَائِلِ سُجَّدًا لِلَّهِ وَهُمْ دَاخِرُونَ }الْآيَةَ كُلَّهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَلِيِّ بْنِ عَاصِمٍ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Ali bin Ashim] dari [Yahya Al Bakka`] telah menceritakan kepadaku [Abdullah bin Umar] berkata: Aku mendengar [Umar bin Al Khaththab] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Empat (rakaat sunnah) sebelum zhuhur setelah matahari tergelincir dihitung seperti shalat akhir malam.\" Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidaklah ada sesuatu pun melainkan memahasucikan Allah pada saat itu.\" Lalu beliau membaca: \"Dan apakah mereka tidak memperhatikan segala sesuatu yang telah diciptakan Allah yang bayangannya berbolak-balik ke kanan dan ke kiri dalam keadaan sujud kepada Allah, sedang mereka berendah diri?\" (An Nahl: 48) Abu Isa berkata: Hadits ini gharib, kami hanya mengetahuinya dari hadits Ali bin Ashim."},"2905":{"ar":"حَدَّثَنَا أَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ عِيسَى بْنِ عُبَيْدٍ عَنْ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَبِي الْعَالِيَةِ قَالَ حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَلَمَّا كَانَ يَوْمُ أُحُدٍ أُصِيبَ مِنْ الْأَنْصَارِ أَرْبَعَةٌ وَسِتُّونَ رَجُلًا وَمِنْ الْمُهَاجِرِينَ سِتَّةٌ فِيهِمْ حَمْزَةُ فَمَثَّلُوا بِهِمْ فَقَالَتْ الْأَنْصَارُ لَئِنْ أَصَبْنَا مِنْهُمْ يَوْمًا مِثْلَ هَذَا لَنُرْبِيَنَّ عَلَيْهِمْ قَالَ فَلَمَّا كَانَ يَوْمُ فَتْحِ مَكَّةَ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَإِنْ عَاقَبْتُمْ فَعَاقِبُوا بِمِثْلِ مَا عُوقِبْتُمْ بِهِ وَلَئِنْ صَبَرْتُمْ لَهُوَ خَيْرٌ لِلصَّابِرِينَ }فَقَالَ رَجُلٌ لَا قُرَيْشَ بَعْدَ الْيَوْمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُفُّوا عَنْ الْقَوْمِ إِلَّا أَرْبَعَةًقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ أُبَيِّ بْنِ كَعْبٍ","id":"Telah menceritakan kepada kami [Abu Ammar Al Husain bin Huraits] telah menceritakan kepada kami [Al Fadll bin Musa] dari [Isa bin Ubaid] dari [Ar Rabi' bin Anas] dari [Abu Al Aliyah] berkata: Telah menceritakan kepadaku [Ubai bin Ka'ab] berkata: Ketika terjadi perang Uhud yang diikuti enam puluh empat orang dari Anshar dan enam orang dari Muhajirin termasuk Hamzah, mereka (orang kafir) mencabik-cabik (jasad) mereka (orang mukmin). Lalu orang Anshar mengatakan: Kalaulah mereka melakukannya hal yang serupa terhadap kami satu hari nanti, pasti kami melakukan balasan yang lebih dari ini. (Ubayy) berkata: Dan pada hari terjadinya penaklukkan Makkah, Allah menurunkan: \"Dan jika kamu memberikan balasan, maka balaslah dengan balasan yang sama dengan siksaan yang ditimpakan kepadamu. Akan tetapi jika kamu bersabar, sesungguhnya itulah yang lebih baik bagi orang-orang yang sabar.\" (An Nahl: 126) lalu seseorang mengatakan: Tidak ada lagi Quraisy setelah ini. kemudian Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tahan diri kalian (untuk menyerang) kaum (Quraisy) kecuali empat (orang).\" Abu Isa mengatakan bahwa hadits ini hasan gharib. dari hadits Ubai bin Ka'ab."},"2906":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أُسْرِيَ بِي لَقِيتُ مُوسَى قَالَ فَنَعَتَهُ فَإِذَا رَجُلٌ حَسِبْتُهُ قَالَ مُضْطَرِبٌ رَجِلُ الرَّأْسِ كَأَنَّهُ مِنْ رِجَالِ شَنُوءَةَ قَالَ وَلَقِيتُ عِيسَى قَالَ فَنَعَتَهُ قَالَ رَبْعَةٌ أَحْمَرُ كَأَنَّمَا خَرَجَ مِنْ دِيمَاسٍ يَعْنِي الْحَمَّامَ وَرَأَيْتُ إِبْرَاهِيمَ قَالَ وَأَنَا أَشْبَهُ وَلَدِهِ بِهِ قَالَ وَأُتِيتُ بِإِنَاءَيْنِ أَحَدُهُمَا لَبَنٌ وَالْآخَرُ خَمْرٌ فَقِيلَ لِي خُذْ أَيَّهُمَا شِئْتَ فَأَخَذْتُ اللَّبَنَ فَشَرِبْتُهُ فَقِيلَ لِي هُدِيتَ لِلْفِطْرَةِ أَوْ أَصَبْتَ الْفِطْرَةَ أَمَا إِنَّكَ لَوْ أَخَذْتَ الْخَمْرَ غَوَتْ أُمَّتُكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abdurrazzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Az Zuhri] telah mengkhabarkan kepadaku [Sa'id bin Al Musayyib] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Ketika aku di Isra`kan aku dipertemukan dengan Musa -beliau menyebutkan ciri-cirinya aku kira beliau bersabda- badannya tinggi dan tidak gemuk, rambutnya bergelombang sepertinya ia lelaki dari Syanu`ah.\" Beliau bersabda: \"Aku juga dipertemukan dengan Isa -dia berkata: beliau menyebutkan ciri-cirinya- badannya sedang kulitnya merah (wajah dan rambutnya nya berair) seakan akan baru keluar dari kamar mandi. Aku juga melihat Ibrahim dan aku adalah putranya yang paling mirip dia, lalu aku disuguhi dua bejana yang satu berisi susu dan yang lainnya berisi khamar, lantas aku ambil bejana yang berisi susu lalu kuminum. Setelah itu (dikatakan padaku): Engkau telah diberi petunjuk kepada fithrah, atau dengan redaksi 'Engkau tidak menyelisihi fithrah, Sekiranya kau ambil khamar, berarti engkau telah menjerumuskan umatmu.\" Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2907":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا أَبُو تُمَيْلَةَ عَنْ الزُّبَيْرِ بْنِ جُنَادَةَ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا انْتَهَيْنَا إِلَى بَيْتِ الْمَقْدِسِ قَالَ جِبْرِيلُ بِإِصْبَعِهِ فَخَرَقَ بِهِ الْحَجَرَ وَشَدَّ بِهِ الْبُرَاقَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim Ad Dauraqi] telah menceritakan kepada kami [Abu Tumailah] dari [Az Zubair bin Junadah] dari [Ibnu Buraidah] dari [ayahnya] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Saat kami tiba di Baitul Maqdis, Jibril berkata dengan jarinya lalu ia lubangi batu dan beliau pergunakan untuk menguatkan Buraq.\" Abu Isa berkata: Hadits ini hasan gharib.."},"2908":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمَّا كَذَّبَتْنِي قُرَيْشٌ قُمْتُ فِي الْحِجْرِ فَجَلَّى اللَّهُ لِي بَيْتَ الْمَقْدِسِ فَطَفِقْتُ أُخْبِرُهُمْ عَنْ آيَاتِهِ وَأَنَا أَنْظُرُ إِلَيْهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ مَالِكِ بْنِ صَعْصَعَةَ وَأَبِي سَعِيدٍ وَابْنِ عَبَّاسٍ وَأَبِي ذَرٍّ وَابْنِ مَسْعُودٍ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [al Laits] dari [Uqail] dari [Az Zuhri] dari [Abu Salamah] dari [Jabir bin Abdillah] bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Ketika Quraisy mendustakanku, aku berdiri di hijir ismail (dinding yang terletak di samping ka'bah) lalu Allah memperlihatkan Baitul Maqdis kepadaku lalu aku mulai menceritakan kepada mereka tentang tanda-tandanya sementara aku melihatnya.\" Abu Isa mengatakan bahwa hadits ini hasan shahih. "},"2909":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ وَمَا جَعَلْنَا الرُّؤْيَا الَّتِي أَرَيْنَاكَ إِلَّا فِتْنَةً لِلنَّاسِ }قَالَ هِيَ رُؤْيَا عَيْنٍ أُرِيَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ إِلَى بَيْتِ الْمَقْدِسِ قَالَ{ وَالشَّجَرَةَ الْمَلْعُونَةَ فِي الْقُرْآنِ }هِيَ شَجَرَةُ الزَّقُّومِقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Amru bin Dinar] dari [Ikrimah] dari [Ibnu Abbas] berkenaan dengan firman: \"Dan Kami tidak menjadikan mimpi yang telah Kami perlihatkan kepadamu, melainkan sebagai ujian bagi manusia\" (QS. Al-Isra'; 60), itulah mimpi nyata yang diperlihatkan kepada nabi Shallallahu 'alaihi wa Salam saat diisra`kan ke Baitul Maqdis, \"Dan (begitu pula) pohon kayu yang terkutuk dalam Al Qur`an.\" (Al Israa`: 60) maksudnya adalah pohon Zaqqum.\" Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2910":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ السُّدِّيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِ اللَّهِ تَعَالَى{ يَوْمَ نَدْعُو كُلَّ أُنَاسٍ بِإِمَامِهِمْ }قَالَ يُدْعَى أَحَدُهُمْ فَيُعْطَى كِتَابَهُ بِيَمِينِهِ وَيُمَدُّ لَهُ فِي جِسْمِهِ سِتُّونَ ذِرَاعًا وَيُبَيَّضُ وَجْهُهُ وَيُجْعَلُ عَلَى رَأْسِهِ تَاجٌ مِنْ لُؤْلُؤٍ يَتَلَأْلَأُ فَيَنْطَلِقُ إِلَى أَصْحَابِهِ فَيَرَوْنَهُ مِنْ بَعِيدٍ فَيَقُولُونَ اللَّهُمَّ ائْتِنَا بِهَذَا وَبَارِكْ لَنَا فِي هَذَا حَتَّى يَأْتِيَهُمْ فَيَقُولُ أَبْشِرُوا لِكُلِّ رَجُلٍ مِنْكُمْ مِثْلُ هَذَا قَالَ وَأَمَّا الْكَافِرُ فَيُسَوَّدُ وَجْهُهُ وَيُمَدُّ لَهُ فِي جِسْمِهِ سِتُّونَ ذِرَاعًا عَلَى صُورَةِ آدَمَ فَيُلْبَسُ تَاجًا فَيَرَاهُ أَصْحَابُهُ فَيَقُولُونَ نَعُوذُ بِاللَّهِ مِنْ شَرِّ هَذَا اللَّهُمَّ لَا تَأْتِنَا بِهَذَا قَالَ فَيَأْتِيهِمْ فَيَقُولُونَ اللَّهُمَّ أَخْزِهِ فَيَقُولُ أَبْعَدَكُمْ اللَّهُ فَإِنَّ لِكُلِّ رَجُلٍ مِنْكُمْ مِثْلَ هَذَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَالسُّدِّيُّ اسْمُهُ إِسْمَعِيلُ بْنُ عَبْدِ الرَّحْمَنِ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengkhabarkan kepada kami [Ubaidullah bin Musa] dari [Isra`il] dari [As Suddi] dari [ayahnya] dari [Abu Hurairah] dari Nabi Shallallahu 'alaihi wa Salam berkenaan dengan ayat \"(Ingatlah) suatu hari (yang di hari itu) Kami panggil tiap umat dengan pemimpinnya.\" (Al Israa`: 71) beliau bersabda: \"Salah seorang diantara mereka dipanggil lalu diberikan kitabnya dari kanannya dan badannya dilebarkan menjadi enampuluh hasta, wajahnya menjadi putih berseri dan di atas kepalanya diletakkan mahkota dari permata yang berkilauan lalu menghampiri teman-temannya, mereka melihatnya dari kejauhan seraya berdo'a: ALLOOHUMMA I'TINAA BIHAADZAA WABAARIK LANAA FII HAADZAA 'Ya Allah berilah kami hal yang sama dan berkahilah kami dengannya, ' sampailah ia di depan mereka lantas berkata: Berbahagialah karena masing-masing kalian akan mendapat seperti ini sedangkan orang kafir; wajahnya menghitam, badannya dilebarkan enampuluh hasta seperti Adam, dan dipakaikan di atas kepalanya sebuah mahkota, lantas teman-temannya melihat dan berkata: NA'UUDZU BILLAAHI MIN SYARRI HAADZAA, ALLOOHUMMA LAA TA'TINAA BIHAADZAA 'Kami berlindung kepada Allah dari kejelekan hal ini, ya Allah janganlah Engkau berikan hal ini kepada kami.' Datanglah ia menghampiri mereka dan mereka mengatakan: Ya Allah, hinakanlah dia, tetapi ia berkata: Kiranya Allah menjauhkan kalian dari impian kalian, dan masing-masing kalian seperti ini.\" Abu Isa mengatakan bahwa hadits ini hasan gharib."},"2911":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ دَاوُدَ بْنِ يَزِيدَ الزَّعَافِرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ{ عَسَى أَنْ يَبْعَثَكَ رَبُّكَ مَقَامًا مَحْمُودًا }سُئِلَ عَنْهَا قَالَ هِيَ الشَّفَاعَةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَدَاوُدُ الزَّعَافِرِيُّ هُوَ دَاوُدُ الْأَوْدِيُّ بْنُ يَزِيدَ بْنِ عَبْدِ اللَّهِ وَهُوَ عَمُّ عَبْدِ اللَّهِ بْنِ إِدْرِيسَ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Waki'] dari [Dawud bin Yazid Az Za'afiri] dari [ayahnya] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda tentang firmanNya: \"Mudah-mudahan Rabbmu mengangkat kamu ke tempat yang terpuji.\" (Al Israa`: 79) beliau pernah ditanya tentangnya dan menjawab: \"yaitu syafaat.\" Abu Isa mengatakan bahwa hadits ini hasan."},"2912":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا جَرِيرٌ عَنْ قَابُوسَ بْنِ أَبِي ظَبْيَانَ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ ثُمَّ أُمِرَ بِالْهِجْرَةِ فَنَزَلَتْ عَلَيْهِ{ وَقُلْ رَبِّ أَدْخِلْنِي مُدْخَلَ صِدْقٍ وَأَخْرِجْنِي مُخْرَجَ صِدْقٍ وَاجْعَلْ لِي مِنْ لَدُنْكَ سُلْطَانًا نَصِيرًا }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Jarir] dari [Qabus bin Abu Dlabyan] dari [ayahnya] dari [Ibnu Abbas] berkata: Nabi Shallallahu 'alaihi wa Salam berada di Makkah lalu diperintahkan berhijrah lalu turun ayat pada beliau: \"Ya Rabbku, masukkanlah aku di tempat yang terpuji dan keluarkanlah (pula) di tempat yang terpuji, dan berikanlah kepadaku dari sisi Engkau kekuasaan yang menolong.\" (Al Israa`: 80) Abu Isa berkata: Hadits ini hasan shahih."},"2913":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ دَاوُدَ بْنِ أَبَي هِنْدٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَتْ قُرَيْشٌ لِيَهُودَ أَعْطُونَا شَيْئًا نَسْأَلُ هَذَا الرَّجُلَ فَقَالَ سَلُوهُ عَنْ الرُّوحِ قَالَ فَسَأَلُوهُ عَنْ الرُّوحِ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي وَمَا أُوتِيتُمْ مِنْ الْعِلْمِ إِلَّا قَلِيلًا }قَالُوا أُوتِينَا عِلْمًا كَثِيرًا أُوتِينَا التَّوْرَاةَ وَمَنْ أُوتِيَ التَّوْرَاةَ فَقَدْ أُوتِيَ خَيْرًا كَثِيرًا فَأُنْزِلَتْ{ قُلْ لَوْ كَانَ الْبَحْرُ مِدَادًا لِكَلِمَاتِ رَبِّي لَنَفِدَ الْبَحْرُ }إِلَى آخِرِ الْآيَةَقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Yahya bin Zakariya bin Abu Za`idah] dari [Dawud bin Abu Hind] dari [Ikrimah] dari [Ibnu Abbas] berkata: kaum Quraisy berkata kepada seorang Yahudi: Berilah sesuatu yang bisa kami tanyakan pada lelaki ini (Rasulullah Shallallahu 'alaihi wa Salam)! Quraisy menjawab: Tanyakan padanya tentang ruh! lalu Allah menurunkan \"Dan mereka bertanya kepadamu tentang ruh. Katakanlah: 'Ruh itu termasuk urusan Rabb-ku, dan tidaklah kamu diberi pengetahuan melainkan sedikit.\" (Al Israa`: 85) mereka (yahudi) mengatakan: Kami diberi banyak ilmu, dan siapapun yang diberi Taurat sungguh ia telah diberi banyak kebaikan. Lalu diturunkan \"Sekiranya lautan menjadi tinta untuk (menulis) kalimat-kalimat Rabbku, sungguh habislah lautan itu sebelum habis (ditulis) kalimat-kalimat Rabbku, meskipun Kami datangkan tambahan sebanyak itu (pula).\" (Al Israa`: 108) Abu Isa mengatakan bahwa hadits ini hasan shahih gharib."},"2914":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَكُنْتُ أَمْشِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَرْثٍ بِالْمَدِينَةِ وَهُوَ يَتَوَكَّأُ عَلَى عَسِيبٍ فَمَرَّ بِنَفَرٍ مِنْ الْيَهُودِ فَقَالَ بَعْضُهُمْ لَوْ سَأَلْتُمُوهُ فَقَالَ بَعْضُهُمْ لَا تَسْأَلُوهُ فَإِنَّهُ يُسْمِعُكُمْ مَا تَكْرَهُونَ فَقَالُوا لَهُ يَا أَبَا الْقَاسِمِ حَدِّثْنَا عَنْ الرُّوحِ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاعَةً وَرَفَعَ رَأْسَهُ إِلَى السَّمَاءِ فَعَرَفْتُ أَنَّهُ يُوحَى إِلَيْهِ حَتَّى صَعِدَ الْوَحْيُ ثُمَّ قَالَ{ الرُّوحُ مِنْ أَمْرِ رَبِّي وَمَا أُوتِيتُمْ مِنْ الْعِلْمِ إِلَّا قَلِيلًا }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ali bin Khasyram] telah mengkhabarkan kepada kami [Isa bin Yunus] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] berkata: Aku pernah berjalan bersama Nabi Shallallahu 'alaihi wa Salam di sebuah ladang di Madinah dan beliau bersandar pada batang kurma, kemudian sekelompok orang yahudi lewat, lalu sebagian mereka mengatakan: Maukah kalian menanyakan (sesuatu) padanya? yang lainnya menyahut: Sekiranya kalian bertanya padanya, pasti ia akan menjawab dengan sesuatu yang kalian benci. Mereka bertanya padanya (Nabi Shallallahu 'alaihi wa Salam): Wahai Abu Al Qasim, beritahukan kepada kami tentang ruh! kemudian Rasulullah Shallallahu 'alaihi wa Salam berdiri sejenak dan mendongakkan kepalanya ke langit, dan aku tahu bahwa (saat itu) beliau mendapat wahyu sampai selesai lalu bersabda: \"Dan mereka bertanya kepadamu tentang ruh. Katakanlah: \"Ruh itu termasuk urusan Rabb-ku, dan tidaklah kamu diberi pengetahuan melainkan sedikit.\" (Al Israa`: 85) Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2915":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا بَهْزُ بْنُ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُمْ مَحْشُورُونَ رِجَالًا وَرُكْبَانًا وَتُجَرُّونَ عَلَى وُجُوهِكُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Yazid bin Harun] telah mengkhabarkan kepada kami [Bahz bin Hakim] dari [bapaknya] dari [kakeknya] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya kalian akan dikumpulkan (pada hari kiamat) ada yang berjalan, berkendaraan, dan akan diseret di atas wajah kalian.\" Abu Isa mengatakan bahwa hadits ini hasan."},"2916":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍإِنَّ نَوْفًا الْبِكَالِيَّ يَزْعُمُ أَنَّ مُوسَى صَاحِبَ بَنِي إِسْرَائِيلَ لَيْسَ بِمُوسَى صَاحِبِ الْخَضِرِ قَالَ كَذَبَ عَدُوُّ اللَّهِ سَمِعْتُ أُبَيَّ بْنَ كَعْبٍ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَامَ مُوسَى خَطِيبًا فِي بَنِي إِسْرَائِيلَ فَسُئِلَ أَيُّ النَّاسِ أَعْلَمُ فَقَالَ أَنَا أَعْلَمُ فَعَتَبَ اللَّهُ عَلَيْهِ إِذْ لَمْ يَرُدَّ الْعِلْمَ إِلَيْهِ فَأَوْحَى اللَّهُ إِلَيْهِ أَنَّ عَبْدًا مِنْ عِبَادِي بِمَجْمَعِ الْبَحْرَيْنِ هُوَ أَعْلَمُ مِنْكَ قَالَ أَيْ رَبِّ فَكَيْفَ لِي بِهِ فَقَالَ لَهُ احْمِلْ حُوتًا فِي مِكْتَلٍ فَحَيْثُ تَفْقِدُ الْحُوتَ فَهُوَ ثَمَّ فَانْطَلَقَ وَانْطَلَقَ مَعَهُ فَتَاهُ وَهُوَ يُوشَعُ بْنُ نُونٍ فَجَعَلَ مُوسَى حُوتًا فِي مِكْتَلٍ فَانْطَلَقَ هُوَ وَفَتَاهُ يَمْشِيَانِ حَتَّى أَتَيَا الصَّخْرَةَ فَرَقَدَ مُوسَى وَفَتَاهُ فَاضْطَرَبَ الْحُوتُ فِي الْمِكْتَلِ حَتَّى خَرَجَ مِنْ الْمِكْتَلِ فَسَقَطَ فِي الْبَحْرِ قَالَ وَأَمْسَكَ اللَّهُ عَنْهُ جِرْيَةَ الْمَاءِ حَتَّى كَانَ مِثْلَ الطَّاقِ وَكَانَ لِلْحُوتِ سَرَبًا وَكَانَ لِمُوسَى وَلِفَتَاهُ عَجَبًا فَانْطَلَقَا بَقِيَّةَ يَوْمِهِمَا وَلَيْلَتِهِمَا وَنُسِّيَ صَاحِبُ مُوسَى أَنْ يُخْبِرَهُ فَلَمَّا أَصْبَحَ مُوسَى قَالَ لِفَتَاهُ{ آتِنَا غَدَاءَنَا لَقَدْ لَقِينَا مِنْ سَفَرِنَا هَذَا نَصَبًا }قَالَ وَلَمْ يَنْصَبْ حَتَّى جَاوَزَ الْمَكَانَ الَّذِي أُمِرَ بِهِ قَالَ{ أَرَأَيْتَ إِذْ أَوَيْنَا إِلَى الصَّخْرَةِ فَإِنِّي نَسِيتُ الْحُوتَ وَمَا أَنْسَانِيهُ إِلَّا الشَّيْطَانُ أَنْ أَذْكُرَهُ وَاتَّخَذَ سَبِيلَهُ فِي الْبَحْرِ عَجَبًا }قَالَ مُوسَى{ ذَلِكَ مَا كُنَّا نَبْغِ فَارْتَدَّا عَلَى آثَارِهِمَا قَصَصًا }قَالَ يَقُصَّانِ آثَارَهُمَا قَالَ سُفْيَانُ يَزْعُمُ نَاسٌ أَنَّ تِلْكَ الصَّخْرَةَ عِنْدَهَا عَيْنُ الْحَيَاةِ وَلَا يُصِيبُ مَاؤُهَا مَيِّتًا إِلَّا عَاشَ قَالَ وَكَانَ الْحُوتُ قَدْ أُكِلَ مِنْهُ فَلَمَّا قُطِرَ عَلَيْهِ الْمَاءُ عَاشَ قَالَ فَقَصَّا آثَارَهُمَا حَتَّى أَتَيَا الصَّخْرَةَ فَرَأَى رَجُلًا مُسَجًّى عَلَيْهِ بِثَوْبٍ فَسَلَّمَ عَلَيْهِ مُوسَى فَقَالَ أَنَّى بِأَرْضِكَ السَّلَامُ قَالَ أَنَا مُوسَى قَالَ مُوسَى بَنِي إِسْرَائِيلَ قَالَ نَعَمْ قَالَ يَا مُوسَى إِنَّكَ عَلَى عِلْمٍ مِنْ عِلْمِ اللَّهِ عَلَّمَكَهُ لَا أَعْلَمُهُ وَأَنَا عَلَى عِلْمٍ مِنْ عِلْمِ اللَّهِ عَلَّمَنِيهِ لَا تَعْلَمُهُ فَقَالَ مُوسَى{ هَلْ أَتَّبِعُكَ عَلَى أَنْ تُعَلِّمَنِ مِمَّا عُلِّمْتَ رُشْدًا قَالَ إِنَّكَ لَنْ تَسْتَطِيعَ مَعِيَ صَبْرًا وَكَيْفَ تَصْبِرُ عَلَى مَا لَمْ تُحِطْ بِهِ خُبْرًا قَالَ سَتَجِدُنِي إِنْ شَاءَ اللَّهُ صَابِرًا وَلَا أَعْصِي لَكَ أَمْرًا }قَالَ لَهُ الْخَضِرُ{ فَإِنْ اتَّبَعْتَنِي فَلَا تَسْأَلْنِي عَنْ شَيْءٍ حَتَّى أُحْدِثَ لَكَ مِنْهُ ذِكْرًا }قَالَ نَعَمْ فَانْطَلَقَ الْخَضِرُ وَمُوسَى يَمْشِيَانِ عَلَى سَاحِلِ الْبَحْرِ فَمَرَّتْ بِهِمَا سَفِينَةٌ فَكَلَّمَاهُمْ أَنْ يَحْمِلُوهُمَا فَعَرَفُوا الْخَضِرَ فَحَمَلُوهُمَا بِغَيْرِ نَوْلٍ فَعَمَدَ الْخَضِرُ إِلَى لَوْحٍ مِنْ أَلْوَاحِ السَّفِينَةِ فَنَزَعَهُ فَقَالَ لَهُ مُوسَى قَوْمٌ حَمَلُونَا بِغَيْرِ نَوْلٍ عَمَدْتَ إِلَى سَفِينَتِهِمْ فَخَرَقْتَهَا{ لِتُغْرِقَ أَهْلَهَا لَقَدْ جِئْتَ شَيْئًا إِمْرًا قَالَ أَلَمْ أَقُلْ إِنَّكَ لَنْ تَسْتَطِيعَ مَعِيَ صَبْرًا قَالَ لَا تُؤَاخِذْنِي بِمَا نَسِيتُ وَلَا تُرْهِقْنِي مِنْ أَمْرِي عُسْرًا }ثُمَّ خَرَجَا مِنْ السَّفِينَةِ فَبَيْنَمَا هُمَا يَمْشِيَانِ عَلَى السَّاحِلِ وَإِذَا غُلَامٌ يَلْعَبُ مَعَ الْغِلْمَانِ فَأَخَذَ الْخَضِرُ بِرَأْسِهِ فَاقْتَلَعَهُ بِيَدِهِ فَقَتَلَهُ قَالَ لَهُ مُوسَى{ أَقَتَلْتَ نَفْسًا زَكِيَّةً بِغَيْرِ نَفْسٍ لَقَدْ جِئْتَ شَيْئًا نُكْرًا قَالَ أَلَمْ أَقُلْ لَكَ إِنَّكَ لَنْ تَسْتَطِيعَ مَعِيَ صَبْرًا }قَالَ وَهَذِهِ أَشَدُّ مِنْ الْأُولَى{ قَالَ إِنْ سَأَلْتُكَ عَنْ شَيْءٍ بَعْدَهَا فَلَا تُصَاحِبْنِي قَدْ بَلَغْتَ مِنْ لَدُنِّي عُذْرًا فَانْطَلَقَا حَتَّى إِذَا أَتَيَا أَهْلَ قَرْيَةٍ اسْتَطْعَمَا أَهْلَهَا فَأَبَوْا أَنْ يُضَيِّفُوهُمَا فَوَجَدَا فِيهَا جِدَارًا يُرِيدُ أَنْ يَنْقَضَّ }يَقُولُ مَائِلٌ فَقَالَ الْخَضِرُ بِيَدِهِ هَكَذَا{ فَأَقَامَهُ }فَقَالَ لَهُ مُوسَى قَوْمٌ أَتَيْنَاهُمْ فَلَمْ يُضَيِّفُونَا وَلَمْ يُطْعِمُونَا{ لَوْ شِئْتَ لَاتَّخَذْتَ عَلَيْهِ أَجْرًا قَالَ هَذَا فِرَاقُ بَيْنِي وَبَيْنِكَ سَأُنَبِّئُكَ بِتَأْوِيلِ مَا لَمْ تَسْتَطِعْ عَلَيْهِ صَبْرًا }قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْحَمُ اللَّهُ مُوسَى لَوَدِدْنَا أَنَّهُ كَانَ صَبَرَ حَتَّى يَقُصَّ عَلَيْنَا مِنْ أَخْبَارِهِمَا قَالَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأُولَى كَانَتْ مِنْ مُوسَى نِسْيَانٌ قَالَ وَجَاءَ عُصْفُورٌ حَتَّى وَقَعَ عَلَى حَرْفِ السَّفِينَةِ ثُمَّ نَقَرَ فِي الْبَحْرِ فَقَالَ لَهُ الْخَضِرُ مَا نَقَصَ عِلْمِي وَعِلْمُكَ مِنْ عِلْمِ اللَّهِ إِلَّا مِثْلُ مَا نَقَصَ هَذَا الْعُصْفُورُ مِنْ الْبَحْرِقَالَ سَعِيدُ بْنُ جُبَيْرٍ وَكَانَ يَعْنِي ابْنَ عَبَّاسٍ يَقْرَأُ وَكَانَ أَمَامَهُمْ مَلِكٌ يَأْخُذُ كُلَّ سَفِينَةٍ صَالِحَةٍ غَصْبًا وَكَانَ يَقْرَأُ وَأَمَّا الْغُلَامُ فَكَانَ كَافِرًا قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَاهُ الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ رَوَاهُ أَبُو إِسْحَقَ الْهَمْدَانِيُّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى سَمِعْت أَبَا مُزَاحِمٍ السَّمَرْقَنْدِيَّ يَقُولُ سَمِعْتُ عَلِيَّ بْنَ الْمَدِينِيِّ يَقُولُ حَجَجْتُ حَجَّةً وَلَيْسَ لِي هِمَّةٌ إِلَّا أَنْ أَسْمَعَ مِنْ سُفْيَانَ يَذْكُرُ فِي هَذَا الْحَدِيثِ الْخَبَرَ حَتَّى سَمِعْتُهُ يَقُولُ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ وَقَدْ كُنْتُ سَمِعْتُ هَذَا مِنْ سُفْيَانَ مِنْ قَبْلِ ذَلِكَ وَلَمْ يَذْكُرْ فِيهِ الْخَبَرَ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Amru bin Dinar] dari [Sa'id bin Jubair] berkata: Aku berkata kepada [Ibnu Abbas] bahwa Naufan Al Bikali beranggapan bahwa Musa yang bersama Bani Israil bukanlah Musa yang bersama Khadlir, ia (Ibnu Abbas) berkata: Musuh Allah telah berdusta, aku dengar [Ubai bin Ka'ab] berkata: Aku pernah mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda; \"Musa berdiri di depan Bani Israil untuk berkhutbah lalu ditanya: Siapakah orang yang paling tinggi ilmunya?, dia menjawab: Akulah orang yang paling tinggi ilmunya. lalu Allah menegurnya karena ia tidak diberi ilmu, lalu mewahyukan kepadanya: Ada seseorang diantara hamba-hambaKu di pertemuan dua lautan ia lebih tinggi ilmunya darimu. Musa bertanya: Wahai Rabb, bagaimana caranya agar hamba bisa bertemu dengannya? Allah berfirman: Bawalah seekor ikan, jika ikannya lenyap maka disitulah tempatnya. Musa berangkat disertai pembantunya (muridnya) yaitu Yusya' bin Nun. Musa memasukkan seekor ikan kedalam sebuah keranjang lalu keduanya berangkat dengan berjalan kaki tatkala sampai di sebuah batu karang, keduanya tertidur, ikan itu bergerak-gerak dan akhirnya jatuh ke laut lalu Allah menahan laju air sehingga menjadi (jembatan) seperti busur yang menjadi tempat bagi ikan itu untuk berenang, yang membuat Musa dan temannya terheran-heran. Keduanya berangkat kembali menghabiskan siang dan malamnya. Temannya lupa untuk mengingatkannya dan keesokan harinya berkatalah Musa kepada muridnya: \"Bawalah kemari makanan kita; sesungguhnya kita telah merasa letih karena perjalanan kita ini.\" (Al Israa`: 62) ia tidak merasa letih sehingga ia sampai di tempat yang telah ditentukan itu temannya berkata: \"Tahukah kamu tatkala kita mecari tempat berlindung di batu tadi, sesungguhnya aku lupa (menceritakan tentang) ikan itu dan tidak ada yang melupakan aku untuk menceritakannya kecuali syaitan dan ikan itu mengambil jalannya ke laut dengan cara yang aneh sekali. Musa berkata: Itulah (tempat) yang kita cari. Lalu keduanya kembali, mengikuti jejak mereka semula.\" (Al Israa`: 63-64) lalu keduanya mencari jejak mereka semula. (Sufyan) mengatakan: Orang-orang menyangka bahwa pada batu itu ada sumber kehidupan jika airnya menimpa sesuatu yang mati maka ia akan menjadi hidup, ia juga berkata: Ikan tersebut berasal dari air itu sehingga ketika tersiram airnya ia hidup (dan jatuh ke laut) mereka terus mengikuti jejak semula sehingga sampailah pada batu tadi dan melihat ada seorang lelaki yang tertutup pakaian lalu Musa mengucapkan salam padanya, ia (Khadlir) berkata: Bagaimana di negerimu ada salam? Musa berkata: Saya adalah Musa. Khadlir berkata: Musa bani Israil? Musa menjawab: Ya. Ia (Khadlir) berkata: Wahai Musa sesungguhnya engkau memiliki ilmu dari sekian banyak ilmu Allah yang diajarkan padamu dan tidak aku ketahui. Dan aku memiliki ilmu dari sekian banyak ilmu Allah yang diajarkan padaku dan tidak engkau ketahui.\"Musa berkata kepada Khadlir: Bolehkah aku mengikutimu supaya kamu mengajarkan kepadaku ilmu yang benar di antara ilmu-ilmu yang telah diajarkan kepadamu? Dia menjawab: Sesungguhnya kamu sekali-kali tidak akan sanggup sabar bersama aku. Dan bagaimana kamu dapat sabar atas sesuatu, yang kamu belum mempunyai pengetahuan yang cukup tentang hal itu? Musa berkata: Insya Allah kamu akan mendapati aku sebagai orang yang sabar, dan aku tidak akan menentangmu dalam sesuatu urusanpun. Dia berkata: Jika kamu mengikutiku, maka janganlah kamu menanyakan kepadaku tentang sesuatu apapun, sampai aku sendiri menerangkannya kepadamu.\" (Al Israa`: 66-70) Musa menjawab: Ya. Lalu berangkatlah Musa bersama Khadlir dengan berjalan kaki di tepi laut, kemudian melintaslah sebuah perahu di depannya lalu keduanya meminta mereka (pemilik perahu) untuk mengantar keduanya, mereka mengenali Khidr lalu mengantarnya tanpa diberi upah lalu dengan sengaja Khidr mencabut salah satu papan perahu Musa berkata: Mengapa engkau lakukan ini pada satu kaum yang telah mengantar tanpa diberi upah?\"Mengapa kamu melobangi perahu itu akibatnya kamu menenggelamkan penumpangnya? Sesungguhnya kamu telah berbuat sesuatu kesalahan yang besar. Dia (Khadlir) berkata: Bukankah aku telah berkata: Sesungguhnya kamu sekali-kali tidak akan sabar bersama dengan aku. Musa berkata: Janganlah kamu menghukum aku karena kelupaanku dan janganlah kamu membebani aku dengan sesuatu kesulitan dalam urusanku.\" (Al Israa`: 71-73) kemudian keduanya keluar dari perahu dan ketika mereka berjalan di tepi pantai ada seorang anak yang sedang bermain dengan anak lainnya, lalu Khadlir memegang kepalanya dan membunuhnya. Musa berkata padanya: \"Mengapa kamu membunuh jiwa yang bersih, bukan karena dia membunuh orang lain? Sesungguhnya kamu telah melakukan suatu yang mungkar.\" Khidhr berkata: \"Bukankah sudah kukatakan kepadamu, bahwa sesungguhnya kamu tidak akan dapat sabar bersamaku?\" (Al Israa`: 74-75) ia mengatakan: Ini lebih dahsyat dari yang pertama.\"Musa berkata: 'Jika aku bertanya kepadamu tentang sesuatu sesudah (kali) ini, maka janganlah kamu memperbolehkan aku menyertaimu, sesungguhnya kamu sudah cukup memberikan uzur padaku.\" Maka keduanya berjalan; hingga tatkala keduanya sampai kepada penduduk suatu negeri, mereka minta dijamu kepada penduduk negeri itu, tetapi penduduk negeri itu tidak mau menjamu mereka, kemudian keduanya mendapatkan dalam negeri itu dinding rumah yang hampir roboh. (Al Israa`: 76-77) ia mengatakan: (Dinding itu) miring, Khadlir mengisyaratkan dengan tangannya begini \"Maka (Khadlir) menegakkan dinding itu.\" (Al Israa`: 77) lalu Musa berkata padanya: \"(Kenapa engkau mau melakukan ini, padahal) mereka tidak menyambut kita sebagai tamu tidak pula memberi kita makanan?. Musa berkata: \"Jikalau kamu mau, niscaya kamu mengambil upah untuk itu.\" Khadlir berkata: \"Inilah perpisahan antara aku dengan kamu; kelak akan kuberitahukan kepadamu tujuan perbuatan-perbuatan yang kamu tidak dapat sabar terhadapnya.\" (Al Israa`: 77-78) Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Semoga Allah merahmati Musa, kalaulah ia adalah orang yang sabar, Allah akan mengisahkan berita-berita keduanya lebih banyak lagi kepada kita.\" Rasulullah juga bersabda: \"Yang pertama, adalah sesuatu yang Musa lupakan, datanglah seekor burung dan hinggap si tepi perahu lalu mematuk (sesuatu) di laut. Berkatalah Khadlir kepadanya: Ilmuku dan ilmumu sama sekali tidak akan mengurangi ilmu Allah sebagaimana tidak akan berkurangnya laut karena (patukan) burung tadi.\" Sa'id bin Jubair mengatakan bahwa Ibnu Abbas membacakan: WAKAANAT AMAAMAHUM MALIKUN YA'KHUDZU KULLAH SAFIINATIN SHOOLIHATIN GHOSBAN (Dalam alquran bukan amaamahum tapi waro'ahum, dan tidak ada kata shaalihatin) yang artinya 'Dan di depan mereka ada seorang raja yang akan merampas perahu yang baik mereka secara paksa.\" Ia juga membacakan: \"WA-AMMAL GHULAAMU FAKAANA KAAFIRON (Dalam redaksi alquran tidak ada redaksi kaafiron), yang maknanya; Adapun anak kecil (yang dibunuh) kelak ia akan menjadi orang kafir.\" Abu Isa mengatakan bahwa hadits ini adalah hasan shahih. [Az Zuhri] meriwayatkannya dari [Ubaidullah bin Abdullah bin Utbah] dari [Ibnu Abbas] dari [Ubai bin Ka'ab] dari nabi Shallallahu 'alaihi wa Salam. Dan [Abu Ishaq Al Hamdani] meriwayatkannya dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubai bin Ka'ab] dari nabi Shallallahu 'alaihi wa Salam. Abu Isa berkata: Aku mendengar [Abu Muzahim As Samarqandi] berkata: Aku mendengar [Ali bin Al Madini] berkata: Aku pergi haji dan aku tidak memiliki kepentingan selain untuk mendengar dari [Sufyan] menyebutkan khabar dalam hadits ini hingga aku mendengarnya berkata: telah menceritakan kepada kami [Amru bin Dinar], aku sebelumnya telah mendengar hadits ini dari Sufyan tapi ia tidak menyebutkan khabar Didalamnya."},"2917":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَليٍّ حَدَّثَنَا أَبُو قُتَيْبَةَ سَلْمُ بْنُ قُتَيْبَةَ حَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَبَّاسِ الْهَمْدَانِيُّ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْغُلَامُ الَّذِي قَتَلَهُ الْخَضِرُ طُبِعَ يَوْمَ طُبِعَ كَافِرًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Amru bin Ali] telah menceritakan kepada kami [Abu Qutaibah Salm bin Qutaibah] telah menceritakan kepada kami [Abdul Jabbar bin Al Abbas Al Hamdani] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubai bin Ka'ab] dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Anak yang dibunuh Khadlir itu diciptakan sebagai orang kafir saat diciptakan.\" Abu Isa mengatakan bahwa hadits ini hasan shahih gharib."},"2918":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا سُمِّيَ الْخَضِرَ لِأَنَّهُ جَلَسَ عَلَى فَرْوَةٍ بَيْضَاءَ فَاهْتَزَّتْ تَحْتَهُ خَضْرَاءَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Abdurrazzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sebab dinamakan Khidlir adalah karena ia duduk di atas tanah tandus putih lalu ada tanaman (khadhra') bergerak-gerak di bawahnya-Nama Khidir diambil dari dari Khadhra' tersebut--. Abu Isa berkata: Hadits ini hasan shahih gharib."},"2919":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مُحَمَّدِ بْنِ فُضَيْلٍ الْجَزَرِيُّ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا صَفْوَانُ بْنُ صَالِحٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ يَزِيدَ بْنِ يُوسُفَ الصَّنْعَانِيِّ عَنْ مَكْحُولٍ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ{ وَكَانَ تَحْتَهُ كَنْزٌ لَهُمَا }قَالَ ذَهَبٌ وَفِضَّةٌحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلاَّلُ حَدَّثَنَا صَفْوَانُ بْنُ صَالِحٍ حَدَّثَنَا الْوَلِيدُ بْن�� مُسْلِمٍ عَنْ يَزِيدَ بْنِ يُوسُفَ الصَّنْعَانِيِّ عَنْ يَزِيدَ بْنِ يَزِيدَ بْنِ جَابِرٍ عَنْ مَكْحُولٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ja'far bin Muhammad bin Fudlail Al Jazari] dan lainnya, mereka berkata: Telah menceritakan kepada kami [Shafwan bin Shalih] telah menceritakan kepada kami [Al Walid bin Muslim] dari [Yazid bin Yusuf Ash Shan'ani] dari [Makhlul] dari [Ummu Abi Darda`] dari [Abu Ad Darda`] dari Nabi Shallallahu 'alaihi wa Salam tentang firmanNya \"Dan di bawahnya ada harta benda simpanan bagi mereka berdua.\" (Al Israa`: 82) beliau bersabda: \"Emas dan perak.\" Abu Isa mengatakan bahwa hadits ini gharib. Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami [Shafwan bin Shalih] telah menceritakan kepada kami [Al Walid bin Muslim] dari [Yazid bin Yusuf Ash Shan'ani] dari [Yazid bin Yazid bin Jabir] dari [Makhul] dengan sanad ini sepertinya. Abu Isa berkata: Hadits ini hasan gharib."},"2920":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَغَيْرُ وَاحِدٍ الْمَعْنَى وَاحِدٌ وَاللَّفْظُ لِابْنِ بَشَّارٍ قَالُوا حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَبِي رَافِعٍ مِنْ حَدِيثِ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السَّدِّ قَالَ يَحْفِرُونَهُ كُلَّ يَوْمٍ حَتَّى إِذَا كَادُوا يَخْرِقُونَهُ قَالَ الَّذِي عَلَيْهِمْ ارْجِعُوا فَسَتَخْرِقُونَهُ غَدًا فَيُعِيدُهُ اللَّهُ كَأَشَدِّ مَا كَانَ حَتَّى إِذَا بَلَغَ مُدَّتَهُمْ وَأَرَادَ اللَّهُ أَنْ يَبْعَثَهُمْ عَلَى النَّاسِ قَالَ الَّذِي عَلَيْهِمْ ارْجِعُوا فَسَتَخْرِقُونَهُ غَدًا إِنْ شَاءَ اللَّهُ وَاسْتَثْنَى قَالَ فَيَرْجِعُونَ فَيَجِدُونَهُ كَهَيْئَتِهِ حِينَ تَرَكُوهُ فَيَخْرِقُونَهُ فَيَخْرُجُونَ عَلَى النَّاسِ فَيَسْتَقُونَ الْمِيَاهَ وَيَفِرُّ النَّاسُ مِنْهُمْ فَيَرْمُونَ بِسِهَامِهِمْ فِي السَّمَاءِ فَتَرْجِعُ مُخَضَّبَةً بِالدِّمَاءِ فَيَقُولُونَ قَهَرْنَا مَنْ فِي الْأَرْضِ وَعَلَوْنَا مَنْ فِي السَّمَاءِ قَسْوَةً وَعُلُوًّا فَيَبْعَثُ اللَّهُ عَلَيْهِمْ نَغَفًا فِي أَقْفَائِهِمْ فَيَهْلِكُونَ فَوَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ إِنَّ دَوَابَّ الْأَرْضِ تَسْمَنُ وَتَبْطَرُ وَتَشْكَرُ شَكَرًا مِنْ لُحُومِهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ إِنَّمَا نَعْرِفُهُ مِنْ هَذَا الْوَجْهِ مِثْلَ هَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] dan lainnya, maknanya sama sedangkan teksnya milik Ibnu Basyar, mereka berkata: Telah menceritakan kepada kami [Hisyam bin Abdul Malik] telah menceritakan kepada kami [Abu Awanah] dari [Qatadah] dari [Abu Rafi'] dari hadits [Abu Hurairah] dari Nabi Shallallahu 'alaihi wa Salam tentang dinding (yang dibangun Dzulqarnain) beliau bersabda: \"Setiap hari mereka (Ya`juj dan Ma`juj) menggalinya, sehingga ketika dinding itu hampir mereka menembusnya, pemimpinnya mengatakan: Sekarang pulanglah kalian, karena esok hari kalian pasti bisa menembusnya! tetapi Allah mengembalikannya seperti semula. dan keesokan harinya, ketika Allah hendak mengutus mereka kepada manusia, pemimpin mereka berkata: Sekarang pulanglah kalian, karena esok hari kalian akan merobohkannya jika Allah menghendaki\" ia mengucapkan insya Allah.\" Beliau bersabda: \"Pulanglah mereka dan mendapatinya seperti keadaanya semula saat mereka tinggalkan lalu mereka merobohkannya dan menyerang orang-orang, lalu mereka meminum air dan berlarilah orang-orang menghindari mereka, mereka pun melepaskan anak panah ke langit dan seketika itu juga panah tersebut berlumuran darah. Lantas mereka berkata: \"Kita telah menaklukan penduduk bumi dan menguasai yang berada di langit secara paksa.\" Lalu Allah mengirim ulat pada tengkuk mereka, demi Dzat yang jiwaku ada dalam tangannya, sesungguhnya hewan-hewan bumi menjadi gemuk, gesit dan sangat berterima kasih karena daging-daging mereka.\" Abu Isa berkata: Hadits ini hasan gharib, kami hanya mengetahuinya dari sanad ini seperti ini."},"2921":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ الْبُرْسَانِيُّ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ أَخْبَرَنِي أَبِي عَنْ ابْنِ مِينَاءَ عَنْ أَبِي سَعْدِ بْنِ أَبِي فَضَالَةَ الْأَنْصَارِيِّ وَكَانَ مِنْ الصَّحَابَةِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا جَمَعَ اللَّهُ النَّاسَ يَوْمَ الْقِيَامَةِ لِيَوْمٍ لَا رَيْبَ فِيهِ نَادَى مُنَادٍ مَنْ كَانَ أَشْرَكَ فِي عَمَلٍ عَمِلَهُ لِلَّهِ أَحَدًا فَلْيَطْلُبْ ثَوَابَهُ مِنْ عِنْدِ غَيْرِ اللَّهِ فَإِنَّ اللَّهَ أَغْنَى الشُّرَكَاءِ عَنْ الشِّرْكِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ مُحَمَّدِ بْنِ بَكْرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] dan lainnya, mereka berkata: Telah menceritakan kepada kami [Muhammad bin Bakr Al Bursani] dari [Abdul Hamid bin Ja'far] telah mengkhabarkan kepadaku [ayahku] dari [Ibnu Mina'] dari [Abu Sa'ad bin Abi Fadhalah al Anshari] (ia adalah seorang sahabat) berkata: Aku pernah mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Ketika Allah mengumpulkan seluruh manusia pada hari kiamat (yaitu hari yang tiada keraguan didalamnya), ada yang memanggil-manggil: Orang yang menyekutukan Allah dengan sesuatu ketika melakukan suatu amalan yang dilakukan, silahkan meminta pahalanya kepada selain Allah, karena Allah adalah Dzat yang paling tidak membutuhkan sekutu.\" Abu Isa mengatakan bahwa hadits ini hasan gharib, kami hanya mengetahuinya dari hadits Muhammad bin Bakru."},"2922":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ أَبِيهِ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى نَجْرَانَ فَقَالُوا لِي أَلَسْتُمْ تَقْرَءُونَ يَا أُخْتَ هَارُونَ وَقَدْ كَانَ بَيْنَ عِيسَى وَمُوسَى مَا كَانَ فَلَمْ أَدْرِ مَا أُجِيبُهُمْ فَرَجَعْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ أَلَا أَخْبَرْتَهُمْ أَنَّهُمْ كَانُوا يُسَمُّونَ بِأَنْبِيَائِهِمْ وَالصَّالِحِينَ قَبْلَهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ ابْنِ إِدْرِيسَ","id":"Telah menceritakan kepada kami [Abu Sa'id Al Asyuj] dan [Muhammad bin Al Mutsanna] keduanya berkata: Telah menceritakan kepada kami [Ibnu Idris] dari [ayahnya] dari [Simak bin Harb] dari [Alqamah bin Wa`il] dari [Al Mughirah bin Syu'bah] berkata: Rasulullah Shallallahu 'alaihi wa Salam mengutusku ke Najran, mereka bertanya: Bukankah kalian membaca: \"Hai saudara perempuan Harun.\" (Maryam: 28), dan antara Isa dan Musa terjalin kekerabatan yang sangat erat? -- Aku tidak mengetahui jawabannya lalu aku kembali ke Rasulullah Shallallahu 'alaihi wa Salam, aku memberitahukannya, beliau menjawab: \"Apa kau tidak memberitahu mereka bahwa mereka biasa menyebut-nyebut nabi-nabi mereka dan orang-orang shalih sebelum mereka?.\" Abu Isa berkata: Hadits ini hasan shahih gharib, kami hanya mengetahuinya dari hadits Ibnu Idris."},"2923":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا النَّضْرُ بْنُ إِسْمَعِيلَ أَبُو الْمُغِيرَةِ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَأَنْذِرْهُمْ يَوْمَ الْحَسْرَةِ }قَالَ يُؤْتَى بِالْمَوْتِ كَأَنَّهُ كَبْشٌ أَمْلَحُ حَتَّى يُوقَفَ عَلَى السُّورِ بَيْنَ الْجَنَّةِ وَالنَّارِ فَيُقَالُ يَا أَهْلَ الْجَنَّةِ فَيَشْرَئِبُّونَ وَيُقَالُ يَا أَهْلَ النَّارِ فَيَشْرَئِبُّونَ فَيُقَالُ هَلْ تَعْرِفُونَ هَذَا فَيَقُولُونَ نَعَمْ هَذَا الْمَوْتُ فَيُضْجَعُ فَيُذْبَحُ فَلَوْلَا أَنَّ اللَّهَ قَضَى لِأَهْلِ الْجَنَّةِ الْحَيَاةَ فِيهَا وَالْبَقَاءَ لَمَاتُوا فَرَحًا وَلَوْلَا أَنَّ اللَّهَ قَضَى لِأَهْلِ النَّارِ الْحَيَاةَ فِيهَا وَالْبَقَاءَ لَمَاتُوا تَرَحًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [An Nadlr bin Isma'il Abu Al Mughirah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id Al Khudri] radliallahu 'anhu, ia berkata: Rasulullah Shallallahu 'alaihi wa Salam membaca: \"Dan berilah mereka peringatan tentang hari penyesalan.\" (Maryam: 39) beliau bersabda: \"Kematian didatangkan seperti kambing kelabu hingga didirikan di di atas dinding antara surga dan neraka, lantas dikatakan: \"Wahai penduduk surga. Mereka melihat dengan mendongak. Dikatakan: Apa kalian mengetahui ini? mereka menjawab: Ya, itu adalah kematian. Kematian dibaringkan lalu disembelih. Andai Allah tidak menetapkan kehidupan abadi dan kekekalan bagi penduduk surga, niscaya mereka meninggal karena terlalu senang, dan seandainya Allah tidak menetapkan kehidupan abadi dan kekekalan bagi penduduk neraka niscaya mereka mati karena terlalu sedih.\" Abu Isa berkata: hadits ini hasan shahih."},"2924":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا الْحُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ عَنْ قَتَادَةَ فِي قَوْلِهِ{ وَرَفَعْنَاهُ مَكَانًا عَلِيًّا }قَالَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمَّا عُرِجَ بِي رَأَيْتُ إِدْرِيسَ فِي السَّمَاءِ الرَّابِعَةِقَالَ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ سَعِيدُ بْنُ أَبِي عَرُوبَةَ وَهَمَّامٌ وَغَيْرُ وَاحِدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ مَالِكِ بْنِ صَعْصَعَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثَ الْمِعْرَاجِ بِطُولِهِ وَهَذَا عِنْدَنَا مُخْتَصَرٌ مِنْ ذَاكَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Al Husain bin Muhammad] telah menceritakan kepada kami [Syaiban] dari [Qatadah] tentang firmanNya: \"Dan kami Telah mengangkatnya ke martabat yang tinggi.\" (Maryam: 57) ia berkata: Telah menceritakan kepada kami [Anas bin Malik] bahwa Nabi Shallallahu 'alaihi wa Salam bersabda: \"Ketika aku dimi'rajkan aku melihat Idris di langit ke empat.\" Abu Isa berkata: Dalam hal ini ada hadits serupa dari Abu Sa'id dari Nabi Shallallahu 'alaihi wa Salam. Abu Isa mengatakan bahwa hadits ini hasan shahih. [Sa'id bin Abu Urubah], [Hammad] dan lainnya meriwayatkannya dari [Qatadah] dari [Anas] dari [Malik bin Sha'sha'ah] dari nabi Shallallahu 'alaihi wa Salam hadits isra' mi'raj secara lengkap dan menurut kami hadits ini ringkasannya."},"2925":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا عُمَرُ بْنُ ذَرٍّ عَنْ أَبِيهِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِجِبْرِيلَ مَا يَمْنَعُكَ أَنْ تَزُورَنَا أَكْثَرَ مِمَّا تَزُورُنَا قَالَ فَنَزَلَتْ هَذِهِ الْآيَةَ{ وَمَا نَتَنَزَّلُ إِلَّا بِأَمْرِ رَبِّكَ }إِلَى آخِرِ الْآيَةَقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ حَدَّثَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ حَدَّثَنَا وَكِيعٌ عَنْ عُمَرَ بْنِ ذَرٍّ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Ya'la bin Ubaid] telah menceritakan kepada kami [Umar bin Dzarr] dari [ayahnya] dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda kepada Jibril: \"Apa yang menghalangimu untuk mengunjungi kami lebih sering dari biasanya?\" lalu turun ayat ini: \"Dan tidaklah kami (Jibril) Turun, kecuali dengan perintah Rabbmu.\" (Maryam: 64) hingga akhir ayat. Abu Isa berkata: Hadits ini hasan gharib. Telah menceritakan kepada kami [Al Husain bin Huraits] telah menceritakan kepada kami [Waki'] dari [Umar bin Dzarr] sepertinya."},"2926":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ السُّدِّيِّ قَالَ سَأَلْتُ مُرَّةَ الْهَمْدَانِيَّ عَنْ قَوْلِ اللَّهِ عَزَّ وَجَلَّ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا }فَحَدَّثَنِي أَنَّ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ حَدَّثَهُمْ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرِدُ النَّاسُ النَّارَ ثُمَّ يَصْدُرُونَ مِنْهَا بِأَعْمَالِهِمْ فَأَوَّلُهُمْ كَلَمْحِ الْبَرْقِ ثُمَّ كَالرِّيحِ ثُمَّ كَحُضْرِ الْفَرَسِ ثُمَّ كَالرَّاكِبِ فِي رَحْلِهِ ثُمَّ كَشَدِّ الرَّجُلِ ثُمَّ كَمَشْيِهِقَالَ هَذَا حَدِيثٌ حَسَنٌ وَرَوَاهُ شُعْبَةُ عَنْ السُّدِّيِّ وَلَمْ يَرْفَعْهُ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا شُعْبَةُ عَنْ السُّدِّيِّ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا }قَالَ يَرِدُونَهَا ثُمَّ يَصْدُرُونَ بِأَعْمَالِهِمْ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ شُعْبَةَ عَنْ السُّدِّيِّ بِمِثْلِهِ قَالَ عَبْدُ الرَّحْمَنِ قُلْتُ لِشُعْبَةَ إِنَّ إِسْرَائِيلَ حَدَّثَنِي عَنْ السُّدِّيِّ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شُعْبَةُ وَقَدْ سَمِعْتُهُ مِنْ السُّدِّيِّ مَرْفُوعًا وَلَكِنِّي عَمْدًا أَدَعُهُ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah mengkhabarkan kepada kami [Ubaidullah bin Musa] dari [Isra`il] dari [As Suddi] berkata: Aku pernah bertanya kepada [Murrah al Hamdany] tentang firman Allah \"Dan tidak ada seorangpun dari padamu melainkan mendatangi neraka itu.\" (Maryam: 71) lalu ia menceritakan padaku bahwa [Abdullah bin Mas'ud] mengisahkan kepada mereka, ia berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Manusia akan mendatangi neraka, kemudian ia melaluinya dikarenakan amalnya, adapun yang paling awal diantara mereka secepat kilat, lalu seperti angin, kemudian seperti larinya kuda, kemudian seperti seorang yang menunggangi tunggangan, kemudian seperti seseorang yang berlari, kemudian seperti (seseorang yang) berjalan.\" Abu Isa mengatakan bahwa hadits ini hasan. Syu'bah meriwayatkannya dari As Suddi tapi tidak memarfu'kannya. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Syu'bah] dari [As Suddi] dari [Murrah] dari [Abdullah bin Mas'ud]: \"Dan tidak ada seorangpun dari padamu melainkan mendatangi neraka itu.\" (Maryam: 71) ia berkata: Mereka mendatanginya lalu meninggalkannya berdasarkan amal-amal mereka. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Syu'bah] dari [As Suddi] sepertinya. Abdurrahman berkata: Aku berkata kepada Syu'bah bahwa Isra`il telah menceritakan kepadaku dari As Suddi dari Murrah dari Abdullah dari nabi Shallallahu 'alaihi wa Salam. Syu'bah berkata: Aku telah mendengarnya dari As Suddi secara marfu' tapi aku sengaja meninggalkannya."},"2927":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَحَبَّ اللَّهُ عَبْدًا نَادَى جِبْرِيلَ إِنِّي قَدْ أَحْبَبْتُ فُلَانًا فَأَحِبَّهُ قَالَ فَيُنَادِي فِي السَّمَاءِ ثُمَّ تَنْزِلُ لَهُ الْمَحَبَّةُ فِي أَهْلِ الْأَرْضِ فَذَلِكَ قَوْلُ اللَّهِ{ إِنَّ الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ سَيَجْعَلُ لَهُمْ الرَّحْمَنُ وُدًّا }وَإِذَا أَبْغَضَ اللَّهُ عَبْدًا نَادَى جِبْرِيلَ إِنِّي أَبْغَضْتُ فُلَانًا فَيُنَادِي فِي السَّمَاءِ ثُمَّ تَنْزِلُ لَهُ الْبَغْضَاءُ فِي الْأَرْضِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِيهِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu Hurairah] bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Jika Allah mencintai seorang hamba, Jibril dipanggil: Sesungguhya Aku mencintai si fulan maka cintailah ia) lalu ia (Jibril) berseru di langit, maka turunlah kecintaan untuknya di kalangan penduduk bumi. Itulah yang disebut dalam firman Allah: 'Sesungguhnya orang-orang yang beriman dan beramal saleh, kelak Allah Yang Maha Pemurah akan menanamkan dalam (hati) mereka rasa kasih sayang.' (Maryam: 96) sedangkan jika Allah membenci seorang hamba dipanggillah Jibril (sesungguhnya Aku membenci si fulan) lalu Jibril berseru di langit kemudian turunlah kebencian itu ke bumi.\" Abu Isa) engatakan bahwa hadits ini hasan shahih. [Abdurrahman bin Abdullah bin Dinar] meriwayatkan dari [ayahnya] dari [Abu Shalih] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam seperti hadits ini."},"2928":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَال سَمِعْتُ خَبَّابَ بْنَ الْأَرَتِّ يَقُولُجِئْتُ الْعَاصَ بْنَ وَائِلٍ السَّهْمِيَّ أَتَقَاضَاهُ حَقًّا لِي عِنْدَهُ فَقَالَ لَا أُعْطِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ فَقُلْتُ لَا حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ وَإِنِّي لَمَيِّتٌ ثُمَّ مَبْعُوثٌ فَقُلْتُ نَعَمْ فَقَالَ إِنَّ لِي هُنَاكَ مَالًا وَوَلَدًا فَأَقْضِيكَ فَنَزَلَتْ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا }الْآيَةَحَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ نَحْوَهُ قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] berkata: Aku mendengar [Khabbab bin Al Arat] berkata: Aku pernah mendatangi Al 'Ash bin Wa`il As Sahmi, aku menuntut hak padanya lalu ia mengatakan: Aku tidak akan memberikannya sehingga engkau kafir terhadap Muhammad. Aku katakan: Tidak, sampai kamu mati dan dibangkitkan. Ia berkata: Apakah aku akan mati dan dibangkitkan? Aku menjawab: Ya. Ia berkata: Sesungguhnya aku di hari akhirat nanti masih memiliki harta dan anak karena itu akan aku melunasi (hutang) mu. Maka turunlah (ayat): \"Maka apakah kamu telah melihat orang yang kafir kepada ayat-ayat Kami dan ia mengatakan: 'Pasti aku akan diberi harta dan anak.\" (Maryam: 77) Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] sepertinya. Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2929":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ أَخْبَرَنَا صَالِحُ بْنُ أَبِي الْأَخْضَرِ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا قَفَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خَيْبَرَ أَسْرَى لَيْلَةً حَتَّى أَدْرَكَهُ الْكَرَى أَنَاخَ فَعَرَّسَ ثُمَّ قَالَ يَا بِلَالُ اكْلَأْ لَنَا اللَّيْلَةَ قَالَ فَصَلَّى بِلَالٌ ثُمَّ تَسَانَدَ إِلَى رَاحِلَتِهِ مُسْتَقْبِلَ الْفَجْرِ فَغَلَبَتْهُ عَيْنَاهُ فَنَامَ فَلَمْ يَسْتَيْقِظْ أَحَدٌ مِنْهُمْ وَكَانَ أَوَّلَهُمْ اسْتِيقَاظًا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيْ بِلَالُ فَقَالَ بِلَالٌ بِأَبِي أَنْتَ يَا رَسُولَ اللَّهِ أَخَذَ بِنَفْسِي الَّذِي أَخَذَ بِنَفْسِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْتَادُوا ثُمَّ أَنَاخَ فَتَوَضَّأَ فَأَقَامَ الصَّلَاةَ ثُمَّ صَلَّى مِثْلَ صَلَاتِهِ لِلْوَقْتِ فِي تَمَكُّثٍ ثُمَّ قَالَ{ أَقِمْ الصَّلَاةَ لِذِكْرِي }قَالَ هَذَا حَدِيثٌ غَيْرُ مَحْفُوظٍ رَوَاهُ غَيْرُ وَاحِدٍ مِنْ الْحُفَّاظِ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَذْكُرُوا فِيهِ عَنْ أَبِي هُرَيْرَةَ وَصَالِحُ بْنُ أَبِي الْأَخْضَرِ يُضَعَّفُ فِي الْحَدِيثِ ضَعَّفَهُ يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ وَغَيْرُهُ مِنْ قِبَلِ حِفْظِهِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [An Nadlr bin Syumail] telah mengkhabarkan kepada kami [Shalih bin Al Akhdlar] dari [Az Zuhri] dari [Sa'id bin Al Musayyib] dari [Abu Hurairah] berkata: sepulang Rasulullah Shallallahu 'alaihi wa Salam dari Khaibar, beliau mengadakan perjalanan malam dan ketika rasa kantuk menyerang, beliau merundukkan (untanya) dan beliau turun untuk beristirahat lalu bersabda: \"Wahai Bilal, berjaga-jagalah malam ini.\" kemudian Bilal shalat, setelah itu ia bersandar pada tunggangannya (unta) menunggu pagi (shubuh), ia pun diserang rasa kantuk dan akhirnya tertidur. Dan tidak ada yang membangunkan seorang pun diantara mereka, sedangkan yang pertama kali bangun adalah Rasulullah. Lalu beliau bersabda: \"Hai Bilal!\" Bilal menjawab: baginda lebih aku muliakan melebihi ayahku, saya diserang rasa kantuk (tertidur) sebagaimana yang engkau alami. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tuntunlah unta kalian\" kemudian beliau menderumkan (untanya) Terus berwudhu, dan mendirikan shalat kemudian shalat sebagaimana shalatnya pada waktunya dengan pelan lalu beliau membaca: \"Dirikanlah shalat untuk mengingatKu.\" (Thaahaa: 14) Abu Isa berkata: Hadits ini tidak terjaga. Diriwayatkan oleh beberapa orang dari ahli hadits dari Az Zuhri dari Sa'id bin Al Musayyib bahwa nabi Shallallahu 'alaihi wa Salam, mereka tidak menyebut dari Abu Hurairah. Shalih bin Abu Al Akhdlar dilemahkan dalam hadits. Yahya bin Sa'id Al Qaththan dan lainnya melemahkannya dari sisi hafalannya."},"2930":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ دَرَّاجٍ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوَيْلُ وَادٍ فِي جَهَنَّمَ يَهْوِي فِيهِ الْكَافِرُ أَرْبَعِينَ خَرِيفًا قَبْلَ أَنْ يَبْلُغَ قَعْرَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مَرْفُوعًا إِلَّا مِنْ حَدِيثِ ابْنِ لَهِيعَةَ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Al Hasan bin Musa] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Darraj] dari [Abu Al Haitsam] dari [Abu Sa'id] dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Al Wail adalah nama sebuah lembah di neraka Jahannam, orang kafir akan jatuh ke dalamnya selama empatpuluh musim sebelum ia mencapai dasarnya.\" Abu Isa berkata: Hadits ini gharib, kami tidak mengetahui kemarfu'annya kecuali dari hadits Ibnu Lahi'ah. "},"2931":{"ar":"حَدَّثَنَا مُجَاهِدُ بْنُ مُوسَى الْبَغْدَادِيُّ وَالْفَضْلُ بْنُ سَهْلٍ الْأَعْرَجُ بَغْدَادِيٌّ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ غَزْوَانَ أَبُو نُوحٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَجُلًا قَعَدَ بَيْنَ يَدَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ لِي مَمْلُوكِينَ يُكَذِّبُونَنِي وَيَخُونُونَنِي وَيَعْصُونَنِي وَأَشْتُمُهُمْ وَأَضْرِبُهُمْ فَكَيْفَ أَنَا مِنْهُمْ قَالَ يُحْسَبُ مَا خَانُوكَ وَعَصَوْكَ وَكَذَّبُوكَ وَعِقَابُكَ إِيَّاهُمْ فَإِنْ كَانَ عِقَابُكَ إِيَّاهُمْ بِقَدْرِ ذُنُوبِهِمْ كَانَ كَفَافًا لَا لَكَ وَلَا عَلَيْكَ وَإِنْ كَانَ عِقَابُكَ إِيَّاهُمْ دُونَ ذُنُوبِهِمْ كَانَ فَضْلًا لَكَ وَإِنْ كَانَ عِقَابُكَ إِيَّاهُمْ فَوْقَ ذُنُوبِهِمْ اقْتُصَّ لَهُمْ مِنْكَ الْفَضْلُ قَالَ فَتَنَحَّى الرَّجُلُ فَجَعَلَ يَبْكِي وَيَهْتِفُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا تَقْرَأُ كِتَابَ اللَّهِ{ وَنَضَعُ الْمَوَازِينَ الْقِسْطَ لِيَوْمِ الْقِيَامَةِ فَلَا تُظْلَمُ نَفْسٌ شَيْئًا وَإِنْ كَانَ مِثْقَالَ }الْآيَةَ فَقَالَ الرَّجُلُ وَاللَّهِ يَا رَسُولَ اللَّهِ مَا أَجِدُ لِي وَلِهَؤُلَاءِ شَيْئًا خَيْرًا مِنْ مُفَارَقَتِهِمْ أُشْهِدُكُمْ أَنَّهُمْ أَحْرَارٌ كُلُّهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ الرَّحْمَنِ بْنِ غَزْوَانَ وَقَدْ رَوَى أَحْمَدُ بْنُ حَنْبَلٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَزْوَانَ هَذَا الْحَدِيثَ","id":"Telah menceritakan kepada kami [Mujahid bin Musa Al Baghdadi] dan [Al Fadll bin Sahal Al A'raj Baghdadi] dan lainnya, mereka berkata: Telah menceritakan kepada kami [Abdurrahman bin Ghazwan Abu Nuh] telah menceritakan kepada kami [Al Laits bin Sa'ad] dari [Malik bin Anas] dari [Az Zuhri] dari [Urwah] dari [Aisyah] bahwa seseorang duduk di depan Nabi Shallallahu 'alaihi wa Salam lalu berkata: Wahai Rasulullah, sesungguhnya saya memiliki dua orang budak mereka mendustai dan mengkhianati saya, mereka juga membangkang terhadap (perintah) saya, lalu saya umpat dan saya pukul mereka apakah saya berdosa kepada mereka? beliau menjawab \"Pengkhianatan, pembangkangan, dan kedustaan mereka terhadapmu, juga hukumanmu atas mereka, semua itu ada perhitungannya. Jika hukumanmu sebanding dengan kesalahan mereka, maka impaslah urusanmu dengannya. Tapi jika hukumanmu lebih ringan dibanding kesalahan mereka, maka kamu mendapat keutamaan. Namun jika hukuman yang kamu timpakan kepada mereka lebih berat dibanding kesalahan mereka, maka merekalah yang akan mendapat keutamaan darimu sebagai qishash.\" ia berkata; lalu menyesallah lelaki itu kemudian ia menangis dan berteriak lalu Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidakkah engkau membaca kitab Allah: 'Kami akan memasang timbangan yang tepat pada hari kiamat, maka tiadalah seseorang dirugikan barang sedikitpun.\" (Al Anbiyaa`: 47) lelaki itu berkata: Wahai Rasulullah, demi Allah, tidak ada sesuatu yang lebih baik bagi saya kecuali dengan memerdekakan mereka. Karena itu saksikanlah bahwa mereka semua saya merdekakan.\" Abu Isa mengatakan bahwa hadits ini gharib, kami hanya mengetahuinya dari hadits Abdurrahman bin Ghazwan. [Ahmad bin Hambal] meriwayatkan hadits ini dari [Abdurrahman bin Ghazwan]."},"2932":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى الْأُمَوِيُّ حَدَّثَنِي أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ أَبِي الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكْذِبْ إِبْرَاهِيمُ عَلَيْهِ السَّلَام فِي شَيْءٍ قَطُّ إِلَّا فِي ثَلَاثٍ قَوْلِهِ{ إِنِّي سَقِيمٌ }وَلَمْ يَكُنْ سَقِيمًا وَقَوْلُهُ لِسَارَّةَ أُخْتِي وَقَوْلِهِ{ بَلْ فَعَلَهُ كَبِيرُهُمْ هَذَا }وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسْتَغْرَبُ مِنْ حَدِيثِ ابْنِ إِسْحَقَ عَنْ أَبِي الزِّنَادِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Sa'id bin Yahya Al Umawi] telah menceritakan kepadaku [ayahku] telah menceritakan kepadaku [Muhammad bin Ishaq] dari [Abu Az Zinad] dari [Abdurrahman Al A'raj] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Ibrahim sama sekali tidak pernah berdusta dalam sesuatu pun kecuali dalam tiga perkara; (yaitu) ucapannya: Saya sakit, padahal tidak sakit. Ucapannya tentang Sarrah: Dia adalah saudariku. Dan ucapannya: Yang melakukannya (merobohkan patung-patung kecil) adalah (patung) yang paling besar ini.\" hadits ini diriwayatkan melalui sanad lain dari Abu Hurairah dari nabi Shallallahu 'alaihi wa Salam. Hadits Ibnu Ishaq dari Abu Az Zinad dinilai gharib. Abu Isa mengatakan bahwa hadits ini hasan shahih."},"2933":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ وَوَهْبُ بْنُ جَرِيرٍ وَأَبُو دَاوُدَ قَالُوا حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَوْعِظَةِ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ مَحْشُورُونَ إِلَى اللَّهِ عُرَاةً غُرْلًا ثُمَّ قَرَأَ{ كَمَا بَدَأْنَا أَوَّلَ خَلْقٍ نُعِيدُهُ وَعْدًا عَلَيْنَا }إِلَى آخِرِ الْآيَةِ قَالَ أَوَّلُ مَنْ يُكْسَى يَوْمَ الْقِيَامَةِ إِبْرَاهِيمُ وَإِنَّهُ سَيُؤْتَى بِرِجَالٍ مِنْ أُمَّتِي فَيُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ رَبِّ أَصْحَابِي فَيُقَالُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ فَلَمَّا تَوَفَّيْتَنِي كُنْتَ أَنْتَ الرَّقِيبَ عَلَيْهِمْ وَأَنْتَ عَلَى كُلِّ شَيْءٍ شَهِيدٌ إِنْ تُعَذِّبْهُمْ فَإِنَّهُمْ عِبَادُكَ وَإِنْ تَغْفِرْ لَهُمْ }إِلَى آخِرِ الْآيَةِ فَيُقَالُ هَؤُلَاءِ لَمْ يَزَالُوا مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ مُنْذُ فَارَقْتَهُمْحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ نَحْوَهُ قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَاهُ سُفْيَانُ الثَّوْرِيُّ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ نَحْوَهُ قَالَ أَبُو عِيسَى كَأَنَّهُ تَأَوَّلَهُ عَلَى أَهْلِ الرِّدَّةِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Waki'], [Wahab bin Jarir] dan [Abu Dawud] mereka berkata: Telah menceritakan kepada kami [Syu'bah] dari [Al Mughirah bin An Nu'man] dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata: Rasulullah Shallallahu 'alaihi wa Salam berdiri untuk memberikan nasehat, beliau bersabda: \"Hai manusia, sesungguhnya kalian akan dikumpulkan kepada Allah dalam keadaan telanjang dan belum dikhitan, \" lalu beliau membaca: \"Sebagaimana Kami telah memulai penciptaan pertama begitulah Kami akan mengulanginya itulah suatu janji yang pasti Kami tepati.\" (Al Anbiyaa`: 105) Orang yang pertama kali di beri pakaian pada hari itu adalah Ibrahim dan akan didatangkan sejumlah orang dari umatku mereka dimasukkan dalam golongan kiri (ahli neraka) lalu aku berdo'a: Wahai Rabb mereka semua adalah sahabatkku, lalu dijawab: Sesungguhnya kamu tidak tahu apa yang mereka buat-buat setelahmu. Lalu aku berdo'a sebagaimana yang diucapkan hamba shalih: 'Aku menjadi saksi atas mereka selagi aku bersama mereka namun tatkala Engkau wafatkan aku, Engkaulah yang mengawasi mereka dan Engkau Maha menyaksikan terhadap segala sesuatu. Jika Engkau siksa mereka maka sesungguhnya mereka adalah hambaMu.' (Al Maa`idah: 117-118) lalu dijawab: Mereka senantiasa murtad sepeninggalmu.\" Abu Isa mengatakan bahwa hadits ini hasan shahih. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Al Mughirah bin An Nu'man] sepertinya. Abu Isa berkata: Hadits ini hasan shahih. [Sufyan Ats Tsauri] meriwayatkannya dari [Al Mughirah bin An Nu'man] sepertinya. Abu Isa berkata: Sepertinya ia menakwilkannya atas orang-orang murtad."},"2934":{"ar":"بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ جُدْعَانَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا نَزَلَتْ{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ إِنَّ زَلْزَلَةَ السَّاعَةِ شَيْءٌ عَظِيمٌ إِلَى قَوْلِهِ وَلَكِنَّ عَذَابَ اللَّهِ شَدِيدٌ }قَالَ أُنْزِلَتْ عَلَيْهِ هَذِهِ الْآيَةُ وَهُوَ فِي سَفَرٍ فَقَالَ أَتَدْرُونَ أَيُّ يَوْمٍ ذَلِكَ فَقَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ ذَلِكَ يَوْمَ يَقُولُ اللَّهُ لِآدَمَ ابْعَثْ بَعْثَ النَّارِ فَقَالَ يَا رَبِّ وَمَا بَعْثُ النَّارِ قَالَ تِسْعُ مِائَةٍ وَتِسْعَةٌ وَتِسْعُونَ إِلَى النَّارِ وَوَاحِدٌ إِلَى الْجَنَّةِ قَالَ فَأَنْشَأَ الْمُسْلِمُونَ يَبْكُونَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَارِبُوا وَسَدِّدُوا فَإِنَّهَا لَمْ تَكُنْ نُبُوَّةٌ قَطُّ إِلَّا كَانَ بَيْنَ يَدَيْهَا جَاهِلِيَّةٌ قَالَ فَيُؤْخَذُ الْعَدَدُ مِنْ الْجَاهِلِيَّةِ فَإِنْ تَمَّتْ وَإِلَّا كَمُلَتْ مِنْ الْمُنَافِقِينَ وَمَا مَثَلُكُمْ وَالْأُمَمِ إِلَّا كَمَثَلِ الرَّقْمَةِ فِي ذِرَاعِ الدَّابَّةِ أَوْ كَالشَّامَةِ فِي جَنْبِ الْبَعِيرِ ثُمَّ قَالَ إِنِّي لَأَرْجُو أَنْ تَكُونُوا رُبْعَ أَهْلِ الْجَنَّةِ فَكَبَّرُوا ثُمَّ قَالَ إِنِّي لَأَرْجُو أَنْ تَكُونُوا ثُلُثَ أَهْلِ الْجَنَّةِ فَكَبَّرُوا ثُمَّ قَالَ إِنِّي لَأَرْجُو أَنْ تَكُونُوا نِصْفَ أَهْلِ الْجَنَّةِ فَكَبَّرُوا قَالَ لَا أَدْرِي قَالَ الثُّلُثَيْنِ أَمْ لَاقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Bismillaahirrahmaanirrahiim. Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Jud'an] dari [Al Hasan] dari [Imran bin Hushain] saat turun ayat: \"Hai manusia, bertakwalah kepada Tuhanmu; Sesungguhnya kegoncangan hari kiamat itu adalah suatu kejadian yang sangat besar (dahsyat), \" hingga \"Akan tetapi azab Allah itu sangat kerasnya.\" (Al Hajj: 1-2), ayat ini turun saat beliau berada dalam perjalanan. Beliau bertanya: \"Tahukah kalian, hari apa itu?\" mereka menjawab: Allah dan RasulNya lebih tahu. Beliau bersabda: \"Itulah hari ketika Allah berfirman kepada Adam: Utuslah utusan-utusan ke neraka. Adam bertanya: Wahai Rabb, apa maksud utusan-utusan ke nereka? Allah menjawab: sembilanratus sembilanpuluh sembilan orang masuk neraka sedangkan satu orang masuk surga.\" Kaum muslimin pun menangis lalu Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Beramallah istiqomah, dan usahakanlah untuk benar, karena tidak ada kenabian pun melainkan jahiliyah pasti ada dihadapannya, lalu diambillah bilangan kejahiliyahan, bila selesai (itulah yang terbaik), dan bila tidak selesai disempurnakan dari kaum munafik. Tidaklah perumpamaan kalian dengan ummat-ummat lain kecuali seperti tanda yang ada di lengan binatang (unta) atau seperti tahi lalat disisi unta.\" Lalu beliau bersabda: \"Sesungguhnya aku berharap kalian menjadi seperempat penghuni surga.\" Mereka bertakbir. Setelah itu beliau bersabda: \"Sesungguhnya aku berharap kalian menjadi sepertiga penghuni surga.\" Mereka bertakbir. Imran berkata: Aku tidak tahu apakah beliau menyebut dua pertiga atau tidak. Abu Isa berkata: Hadits ini hasan shahih. Diriwayatkan melalui sanad lain dari Al Hasan dari Imran bin Hushain dari nabi Shallallahu 'alaihi wa Salam."},"2935":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا هِشَامُ بْنُ أَبِي عَبْدِ اللَّهِ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَتَفَاوَتَ بَيْنَ أَصْحَابِهِ فِي السَّيْرِ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَوْتَهُ بِهَاتَيْنِ الْآيَتَيْنِ{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ إِنَّ زَلْزَلَةَ السَّاعَةِ شَيْءٌ عَظِيمٌ إِلَى قَوْلِهِ عَذَابَ اللَّهِ شَدِيدٌ }فَلَمَّا سَمِعَ ذَلِكَ أَصْحَابُهُ حَثُّوا الْمَطِيَّ وَعَرَفُوا أَنَّهُ عِنْدَ قَوْلٍ يَقُولُهُ فَقَالَ هَلْ تَدْرُونَ أَيُّ يَوْمٍ ذَلِكَ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ ذَاكَ يَوْمٌ يُنَادِي اللَّهُ فِيهِ آدَمَ فَيُنَادِيهِ رَبُّهُ فَيَقُولُ يَا آدَمُ ابْعَثْ بَعْثَ النَّارِ فَيَقُولُ يَا رَبِّ وَمَا بَعْثُ النَّارِ فَيَقُولُ مِنْ كُلِّ أَلْفٍ تِسْعُ مِائَةٍ وَتِسْعَةٌ وَتِسْعُونَ فِي النَّارِ وَوَاحِدٌ فِي الْجَنَّةِ فَيَئِسَ الْقَوْمُ حَتَّى مَا أَبَدَوْا بِضَاحِكَةٍ فَلَمَّا رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي بِأَصْحَابِهِ قَالَ اعْمَلُوا وَأَبْشِرُوا فَوَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ إِنَّكُمْ لَمَعَ خَلِيقَتَيْنِ مَا كَانَتَا مَعَ شَيْءٍ إِلَّا كَثَّرَتَاهُ يَأْجُوجُ وَمَأْجُوجُ وَمَنْ مَاتَ مِنْ بَنِي آدَمَ وَبَنِي إِبْلِيسَ قَالَ فَسُرِّيَ عَنْ الْقَوْمِ بَعْضُ الَّذِي يَجِدُونَ فَقَالَ اعْمَلُوا وَأَبْشِرُوا فَوَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ مَا أَنْتُمْ فِي النَّاسِ إِلَّا كَالشَّامَةِ فِي جَنْبِ الْبَعِيرِ أَوْ كَالرَّقْمَةِ فِي ذِرَاعِ الدَّابَّةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Hisyam bin Abu Abdullah] dari [Qatadah] dari [Al Hasan] dari [Imran bin Hushain] berkata: Kami bersama nabi Shallallahu 'alaihi wa Salam dalam suatu perjalanan, (kecepatan) perjalanan para sahabat berbeda-beda lalu Rasulullah Shallallahu 'alaihi wa Salam mengeraskan suara membaca kedua ayat ini: \"Hai manusia, bertakwalah kepada Tuhanmu; Sesungguhnya kegoncangan hari kiamat itu adalah suatu kejadian yang sangat besar (dahsyat), \" hingga \"Akan tetapi azab Allah itu sangat kerasnya.\" (Al Hajj: 1-2) saat mendengarnya, para sahabat mempercepat binatang tunggangan dan mereka tahu tentang berada dalam ucapan yang dibacakan Rasulullah Shallallahu 'alaihi wa Salam. Beliau bertanya: \"Tahukah kalian, hari apa itu?\" mereka menjawab: Allah dan RasulNya lebih tahu. Beliau bersabda: \"Itulah hari dimana Allah berfirman kepada Adam: utuslah utusan-utusan ke neraka. Adam bertanya: Wahai Rabb, apa itu utusan ke neraka? Allah menjawab: sembilanratus sembilanpuluh sembilan orang masuk neraka sedangkan satu orang masuk surga.\" Orang-orang ketika itu semuanya berputus asa hingga tidak ada yang menampakkan gigi serinya karena tertawa. Saat Rasulullah Shallallahu 'alaihi wa Salam melihat kondisi sahabat, beliau bersabda: \"Berbuatlah dan bergembiralah, demi Dzat yang jiwa Muhammad berada ditanganNya, sesungguhnya kalian bersama bersama dua makhluk, tidaklah keduanya bersamaan dengan sesuatu melainkan pasti memperbanyaknya; Ya'juj dan Ma'juj dan keturunan Adam yang mati serta keturunan Iblis.\" Imran berkata: Mereka pun bergembira dengan sebagian hal yang mereka temukan. Beliau bersabda: \"Berbuatlah dan bergembiralah, demi Dzat yang jiwa Muhammad berada ditanganNya, tidaklah kalian ditengah-tengah manusia melainkan seperti tahi lalat disebelah unta atau seperti tanda di lengan binatang ternak.\" Abu Isa berkata: Hadits ini hasan shahih."},"2936":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ قَالَ حَدَّثَنِي اللَّيْثُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ مُحَمَّدِ بْنِ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا سُمِّيَ الْبَيْتَ الْعَتِيقَ لِأَنَّهُ لَمْ يَظْهَرْ عَلَيْهِ جَبَّارٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ الزُّهْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ismail] dan lainnya, mereka berkata: Telah menceritakan kepada kami [Abdullah bin Shalih] berkata: Telah menceritakan kepadaku [Al Laits] dari [Abdurrahman bin Khalid] dari [Ibnu Syihab] dari [Muhammad bin Urwah bin Az Zubair] dari [Abdullah bin Az Zubair] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Adanya disebut Baitul 'Atiq karena tidak ada seorang congkak pun yang menguasainya.\" Abu Isa berkata: Hadits ini hasan shahih. Hadits ini juga diriwayatkan dari Az Zuhri dari nabi Shallallahu 'alaihi wa Salam secara mursal. Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada ksmi [Al Laits] dari [Uqail] dari [Az Zuhri] dari nabi Shallallahu 'alaihi wa Salam sepertinya."},"2937":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا أَبِي وَإِسْحَقُ بْنُ يُوسُفَ الْأَزْرَقُ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا أُخْرِجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَكَّةَ قَالَ أَبُو بَكْرٍ أَخْرَجُوا نَبِيَّهُمْ لَيَهْلِكُنَّ فَأَنْزَلَ اللَّهُ تَعَالَى{ أُذِنَ لِلَّذِينَ يُقَاتَلُونَ بِأَنَّهُمْ ظُلِمُوا وَإِنَّ اللَّهَ عَلَى نَصْرِهِمْ لَقَدِيرٌ }الْآيَةَ فَقَالَ أَبُو بَكْرٍ لَقَدْ عَلِمْتُ أَنَّهُ سَيَكُونُ قِتَالٌقَالَ هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَاهُ عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَغَيْرُهُ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِ عَنْ ابْنِ عَبَّاسٍ وَقَدْ رَوَاهُ بَطْرُ يَحِدَةِ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ مُرْسَلًا وَلَيْسَ فِيهِ عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [ayahku] dan [Ishaq bin Yusuf Al Azraq] dari [Sufyan Ats Tsauri] dari [Al A'masy] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata: Saat nabi Shallallahu 'alaihi wa Salam di usir dari Makkah, Abu Bakar berkata: Kalian mengusir nabi kalian, kalian benar-benar akan binasa. Lalu Allah Ta'ala menurunkan: \"Telah diizinkan (berperang) bagi orang-orang yang diperangi, karena sesungguhnya mereka telah dianiaya. dan Sesungguhnya Allah, benar-benar Maha Kuasa menolong mereka itu.\" (Al Hajj: 39) lalu Abu Bakar berkata: Aku tahu sesungguhnya akan terjadi peperangan.\" Abu Isa berkata: Hadits ini hasan. [Abdurrahamn bin Mahdi] dan lainnya meriwayatkan hadits ini dari [Sufyan] dari [Al A'masy] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] dari nabi Shallallahu 'alaihi wa Salam dengan menyebut dari [Ibnu Abbas]. Bathr Yahidah juga meriwayatkannya dari [Sufyan] dari [Al A'masy] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] secara mursal tanpa menyebut dari Ibnu Abbas."},"2938":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَلَمَّا أُخْرِجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَكَّةَ قَالَ رَجُلٌ أَخْرَجُوا نَبِيَّهُمْ فَنَزَلَتْ{ أُذِنَ لِلَّذِينَ يُقَاتَلُونَ بِأَنَّهُمْ ظُلِمُوا وَإِنَّ اللَّهَ عَلَى نَصْرِهِمْ لَقَدِيرٌ الَّذِينَ أُخْرِجُوا مِنْ دِيَارِهِمْ بِغَيْرِ حَقٍّ }النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu Ahmad Az Zubairi] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] berkata: Saat nabi Shallallahu 'alaihi wa Salam di usir dari Makkah, seseorang berkata: Mereka mengusir nabi mereka?. Lalu turunlah ayat: \"Telah diizinkan (berperang) bagi orang-orang yang diperangi, karena sesungguhnya mereka telah dianiaya. dan Sesungguhnya Allah, benar-benar Maha Kuasa menolong mereka itu. (Yaitu) orang-orang yang telah diusir dari kampung halaman mereka tanpa alasan yang benar.\" (Al Hajj: 39-40); nabi Shallallahu 'alaihi wa Salam dan para sahabat beliau."},"2939":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى وَعَبْدُ بْنُ حُمَيْدٍ وَغَيْرُ وَاحِدٍ الْمَعْنَى وَاحِدٌ قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ يُونُسَ بْنِ سُلَيْمٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ قَال سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُنْزِلَ عَلَيْهِ الْوَحْيُ سُمِعَ عِنْدَ وَجْهِهِ كَدَوِيِّ النَّحْلِ فَأُنْزِلَ عَلَيْهِ يَوْمًا فَمَكَثْنَا سَاعَةً فَسُرِّيَ عَنْهُ فَاسْتَقْبَلَ الْقِبْلَةَ وَرَفَعَ يَدَيْهِ وَقَالَ اللَّهُمَّ زِدْنَا وَلَا تَنْقُصْنَا وَأَكْرِمْنَا وَلَا تُهِنَّا وَأَعْطِنَا وَلَا تَحْرِمْنَا وَآثِرْنَا وَلَا تُؤْثِرْ عَلَيْنَا وَارْضِنَا وَارْضَ عَنَّا ثُمَّ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُنْزِلَ عَلَيَّ عَشْرُ آيَاتٍ مَنْ أَقَامَهُنَّ دَخَلَ الْجَنَّةَ ثُمَّ قَرَأَ{ قَدْ أَفْلَحَ الْمُؤْمِنُونَ }حَتَّى خَتَمَ عَشْرَ آيَاتٍحَدَّثَنَا مُحَمَّدُ بْنُ أَبَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ يُونُسَ بْنِ سُلَيْمٍ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ نَحْوَهُ بِمَعْنَاهُ قَالَ أَبُو عِيسَى هَذَا أَصَحُّ مِنْ الْحَدِيثِ الْأَوَّلِ سَمِعْت إِسْحَقَ بْنَ مَنْصُورٍ يَقُولُ رَوَى أَحْمَدُ بْنُ حَنْبَلٍ وَعَلِيُّ بْنُ الْمَدِينِيِّ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّزَّاقِ عَنْ يُونُسَ بْنِ سُلَيْمٍ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ هَذَا الْحَدِيثَ قَالَ أَبُو عِيسَى وَمَنْ سَمِعَ مِنْ عَبْدِ الرَّزَّاقِ قَدِيمًا فَإِنَّهُمْ إِنَّمَا يَذْكُرُونَ فِيهِ عَنْ يُونُسَ بْنِ يَزِيدَ وَبَعْضُهُمْ لَا يَذْكُرُ فِيهِ عَنْ يُونُسَ بْنِ يَزِيدَ وَمَنْ ذَكَرَ فِيهِ يُونُسَ بْنَ يَزِيدَ فَهُوَ أَصَحُّ وَكَانَ عَبْدُ الرَّزَّاقِ رُبَّمَا ذَكَرَ فِي هَذَا الْحَدِيثِ يُونُسَ بْنَ يَزِيدَ وَرُبَّمَا لَمْ يَذْكُرْهُ وَإِذَا لَمْ يَذْكُرْ فِيهِ يُونُسَ فَهُوَ مُرْسَلٌ","id":"Telah menceritakan kepada kami [Yahay bin Musa], [Abdu bin Humaid] dan lainnya, maknanya sama, mereka beraka: Telah menceritakan kepada kami [Abdurrazzaq] dari [Yunus bin Sulaim] dari [Az Zuhri] dari [Urwah bin Az Zubair] dari [Abdurrahman bin Abd Al Qari] berkata: Aku mendengar [Umar bin Al Khaththab] radliallahu 'anhu berkata: Bila turun wahyu kepada nabi Shallallahu 'alaihi wa Salam, didekat wajah beliau terdengar seperti dengungan lebah. Pada suatu hari, turun wahyu kepada beliau, kami diam sejenak, beliau terlihat gembira lalu menghadap kiblat dan berdoa: \"Ya Allah, tambahilah kami dan jangan kurangi kami, muliakan kami dan jangan hinakan kami, berilah kami dan jangan cegah kami, kedepankan kami dan jangan kesampingkan kami, ridhailah kami dan ridhailah perbuatan-perbuatan kami.\" setelah itu nabi Shallallahu 'alaihi wa Salam bersabda: \"Sepuluh ayat diturunkan padaku, barangsiapa menunaikannya akan masuk surga.\" Beliau membaca: \"Sungguhnya beruntung orang-orang yang beriman.\" Hingga sepuluh ayat. (Al Mu`minuun: 1). Telah menceritakan kepada kami [Muhammad bin Aban] telah menceritakan kepada kami [Abdurrazzaq] dari [Yunus bin Sulaim] dari [Yunus bin Yazid] dari [Az Zuhri] dengan sanad ini sepertinya dengan makna matanya. Abu Isa berkata: Ini lebih shahih dari hadits pertama. Aku mendengar [Ishaq bin Manshur] berkata: [Ahmad bin Hambal], [Ali bin Al Madini] dan [Ishaq bin Ibrahim] meriwayatkan dari [Abdurrazzaq] dari [Yunus bin Sulaim] dari [Yunus bin Yazid] dari [Az Zuhri] hadits ini. Abu Isa berkata: Dan orang yang dulu mendengar dari Abdurrazzaq, mereka hanya menyebut dari Yunus bin Yazid dan sebagaiannya tidak menyebutnya. Hadits yang menyebut dari Yunus bin Yazid lebih shahih. Abdurrazzaq mungkin menyebut Yunus bin Yazid dalam hadits ini dan mungkin tidak. Bila ia tidak menyebut Yunus berarti haditsnya mursal."},"2940":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ الرُّبَيِّعَ بِنْتَ النَّضْرِ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ ابْنُهَا الْحَارِثُ بْنُ سُرَاقَةَ أُصِيبَ يَوْمَ بَدْرٍ أَصَابَهُ سَهْمٌ غَرَبٌ فَأَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ أَخْبِرْنِي عَنْ حَارِثَةَ لَئِنْ كَانَ أَصَابَ خَيْرًا احْتَسَبْتُ وَصَبَرْتُ وَإِنْ لَمْ يُصِبْ الْخَيْرَ اجْتَهَدْتُ فِي الدُّعَاءِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أُمَّ حَارِثَةَ إِنَّهَا جَنَّةٌ فِي جَنَّةٍ وَإِنَّ ابْنَكِ أَصَابَ الْفِرْدَوْسَ الْأَعْلَى وَالْفِرْدَوْسُ رَبْوَةُ الْجَنَّةِ وَأَوْسَطُهَا وَأَفْضَلُهَاقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ أَنَسٍ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Rauh bin Ubadah] dari [Sa'id] dari [Qatadah] dari [Anas bin Malik] radliallahu 'anhu bahwa Ar Rubayyi' binti An Nadlr mendatangi nabi Shallallahu 'alaihi wa Salam dan putranya, Al Harits bin Suraqah, saat perang Badar terkena panah yang menyasar, ia mendatangi Rasulullah Shallallahu 'alaihi wa Salam laku berkata: Beritahukanlah padaku tentang Haritsah, bila ia mendapat kebaikan, aku akan mengharap pahala dan bersabar, bila tidak mendapat kebaikan, aku akan bersungguh-sungguh dalam berdoa. Nabi Shallallahu 'alaihi wa Salam bersabda: \"Hai Ummu Haritsah, sesungguhnya dalam surga itu ada surga lagi (surge bertingkat-tingkat) dan sesungguhnya putramu mendapatkan Firdaus tertinggi, dan Firdaus adalah bukit surga, tengah-tengah surga dan surga terbaik.\" Abu Isa berkata: Hadits ini hasan shahih gharib dari hadits Anas."},"2941":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَعِيدِ بْنِ وَهْبٍ الْهَمْدَانِيِّ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ هَذِهِ الْآيَةِ{ وَالَّذِينَ يُؤْتُونَ مَا آتَوْا وَقُلُوبُهُمْ وَجِلَةٌ }قَالَتْ عَائِشَةُ أَهُمْ الَّذِينَ يَشْرَبُونَ الْخَمْرَ وَيَسْرِقُونَ قَالَ لَا يَا بِنْتَ الصِّدِّيقِ وَلَكِنَّهُمْ الَّذِينَ يَصُومُونَ وَيُصَلُّونَ وَيَتَصَدَّقُونَ وَهُمْ يَخَافُونَ أَنْ لَا يُقْبَلَ مِنْهُمْ أُولَئِكَ الَّذِينَ يُسَارِعُونَ فِي الْخَيْرَاتِقَالَ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَعِيدٍ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Malik bin Mighwal] dari [Abdurrahman bin Sa'id bin Wahab Al Hamdani] bahwa [Aisyah], istri nabi Shallallahu 'alaihi wa Salam, berkata: Aku bertanya kepada Rasulullah Shallallahu 'alaihi wa Salam tentang ayat ini: \"Dan orang-orang yang memberikan apa yang Rabb mereka berikan, dengan hati yang takut, \" (Al Mu'minuun: 60) Aisyah bertanya: Apa mereka orang-orang yang meminum khamar dan mencuri? Beliau menjawab: Bukan, wahai putri Ash Shiddiq, tapi mereka adalah orang-orang yang puasa, shalat dan bersedekah, mereka takut kalau amalan mereka tidak diterima. Mereka itulah orang yang bersegera dalam kebaikan.\" Abu Isa berkata: Hadits ini juga diriwayatkan dari [Abdurrahman bin Sa'id] dari [Abu Hazim] dari [Abu Hurairah] dan nabi Shallallahu 'alaihi wa Salam seperti ini."},"2942":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ سَعِيدِ بْن يَزِيدَ أَبِي شُجَاعٍ عَنْ أَبِي السَّمْحِ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ{ وَهُمْ فِيهَا كَالِحُونَ }قَالَ تَشْوِيهِ النَّارُ فَتَقَلَّصُ شَفَتُهُ الْعَالِيَةُ حَتَّى تَبْلُغَ وَسَطَ رَأْسِهِ وَتَسْتَرْخِي شَفَتُهُ السُّفْلَى حَتَّى تَضْرِبَ سُرَّتَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Suwaid] telah mengkhabarkan kepada kami [Abdullah bin Al Mubarak] dari [Sa'id bin Yazid Abu Syuja'] dari [Abu As Samah] dari [Abu Al Hutsaim] dari [Abu Sa'id Al Khudri] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Muka mereka dibakar api neraka, dan mereka di dalam neraka itu dalam keadaan cacat.\" (Al Mu`minuun: 104) beliau bersabda: \"Neraka memanggangnya hingga bibir atasnya terkelupas hingga ke tengah kepalanya dan bibir bawahnya menjulur hingga mengenai pusarnya.\" Abu Isa berkata: Hadits ini hasan shahih gharib."},"2943":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ الْأَخْنَسِ أَخْبَرَنِي عَمْرُو بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَكَانَ رَجُلٌ يُقَالُ لَهُ مَرْثَدُ بْنُ أَبِي مَرْثَدٍ وَكَانَ رَجُلًا يَحْمِلُ الْأَسْرَى مِنْ مَكَّةَ حَتَّى يَأْتِيَ بِهِمْ الْمَدِينَةَ قَالَ وَكَانَتْ امْرَأَةٌ بَغِيٌّ بِمَكَّةَ يُقَالُ لَهَا عَنَاقٌ وَكَانَتْ صَدِيقَةً لَهُ وَإِنَّهُ كَانَ وَعَدَ رَجُلًا مِنْ أُسَارَى مَكَّةَ يَحْمِلُهُ قَالَ فَجِئْتُ حَتَّى انْتَهَيْتُ إِلَى ظِلِّ حَائِطٍ مِنْ حَوَائِطِ مَكَّةَ فِي لَيْلَةٍ مُقْمِرَةٍ قَالَ فَجَاءَتْ عَنَاقٌ فَأَبْصَرَتْ سَوَادَ ظِلِّي بِجَنْبِ الْحَائِطِ فَلَمَّا انْتَهَتْ إِلَيَّ عَرَفَتْهُ فَقَالَتْ مَرْثَدٌ فَقُلْتُ مَرْثَدٌ فَقَالَتْ مَرْحَبًا وَأَهْلًا هَلُمَّ فَبِتْ عِنْدَنَا اللَّيْلَةَ قَالَ قُلْتُ يَا عَنَاقُ حَرَّمَ اللَّهُ الزِّنَا قَالَتْ يَا أَهْلَ الْخِيَامِ هَذَا الرَّجُلُ يَحْمِلُ أَسْرَاكُمْ قَالَ فَتَبِعَنِي ثَمَانِيَةٌ وَسَلَكْتُ الْخَنْدَمَةَ فَانْتَهَيْتُ إِلَى كَهْفٍ أَوْ غَارٍ فَدَخَلْتُ فَجَاءُوا حَتَّى قَامُوا عَلَى رَأْسِي فَبَالُوا فَظَلَّ بَوْلُهُمْ عَلَى رَأْسِي وَأَعْمَاهُمْ اللَّهُ عَنِّي قَالَ ثُمَّ رَجَعُوا وَرَجَعْتُ إِلَى صَاحِبِي فَحَمَلْتُهُ وَكَانَ رَجُلًا ثَقِيلًا حَتَّى انْتَهَيْتُ إِلَى الْإِذْخِرِ فَفَكَكْتُ عَنْهُ كَبْلَهُ فَجَعَلْتُ أَحْمِلُهُ وَيُعْيِينِي حَتَّى قَدِمْتُ الْمَدِينَةَ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَنْكِحُ عَنَاقًا فَأَمْسَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَرُدَّ عَلَيَّ شَيْئًا حَتَّى نَزَلَتْ{ الزَّانِي لَا يَنْكِحُ إِلَّا زَانِيَةً أَوْ مُشْرِكَةً وَالزَّانِيَةُ لَا يَنْكِحُهَا إِلَّا زَانٍ أَوْ مُشْرِكٌ وَحُرِّمَ ذَلِكَ عَلَى الْمُؤْمِنِينَ }فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مَرْثَدُ{ الزَّانِي لَا يَنْكِحُ إِلَّا زَانِيَةً أَوْ مُشْرِكَةً وَالزَّانِيَةُ لَا يَنْكِحُهَا إِلَّا زَانٍ أَوْ مُشْرِكٌ }فَلَا تَنْكِحْهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Rauh bin Ubadah] dari [Ubaidullah bin Al Akhnas] telah mengkhabarkan kepadaku [Amru bin Syua'ib] dari [ayahnya] dari [kakeknya] berkata: Seseorang bernama Murtsad bin Abu Murtsad, ia adalah seseorang yang pernah menggendong seorang tawanan dari Makkah hingga ke Madinah. Ketika itu ia mempunyai teman seorang pelacur di Makkah bernama Anaq. Martsad kemudian meminta seseorang diantara tawanan Makkah untuk menggendongnya. Ia berkata: Aku pun datang hingga sampai ke naungan salah satu kebun Makkah di malam purnama. Anaq datang lalu melihat gelapnya naungan di tepi kebun. Saat ia tiba di hadapanku, ia mengenaliku, ia bertanya: Martsadkah ini? Aku menjawab: Iya, aku Martsad. Anaq berkata: Selamat datang, mari menginap ditempat kami malam ini. ia berkata: Aku berkata: Hai Anaq, sekarang Allah telah mengharamkan zina. Anaq kontan berteriak: \"Wahai pemilik tenda, orang inilah yang membawa tawanan-tawanan kalian. Ia berkata: Delapan orang menguntitku, aku menempuh kawasan Khandamah hingga sampai ke salah satu gua. Aku masuk lalu mereka tiba hingga berdiri di atas kepalaku. Mereka kencing, kencing mereka mengenaiku dan mereka dibutakan Allah hingga tidak bisa melihatku. Setelah itu mereka kembali dan aku pun kembali ke temanku, aku menggendongnya, kebetulan ia adalah orang yang berat, aku menggendongnya hingga sampai rumput idzkhir, aku melepas tali pengikatnya yang kebetulan tali tersebut besar. Kemudian aku mengendongnya dan ia cukup menjadikanku kelelahan, hingga akhirnya aku tiba di Madinah. Aku mendatangi Rasulullah Shallallahu 'alaihi wa Salam, aku berkata: \"Wahai Rasulullah, bagaimana kalau saya menikahi si 'Anaq? Rasulullah Shallallahu 'alaihi wa Salam diam tidak menjawab apa pun hingga turunlah ayat: \"Laki-laki yang berzina tidak mengawini melainkan perempuan yang berzina, atau perempuan yang musyrik; dan perempuan yang berzina tidak dikawini melainkan oleh laki-laki yang berzina atau laki-laki musyrik, dan yang demikian itu diharamkan atas orang-orang yang mukmin.\" (An Nuur: 3) Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Wahai Martsad, wanita pezina hanya menikahi wanita pezina dan pezina wanita hanya menikahi lelaki pezina atau lelaki musyrik, jangan nikahi dia.\" Abu Isa berkata: Hadits ini hasan gharib, kami hanya mengetahui hadits ini melalui sanad ini."},"2944":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَسُئِلْتُ عَنْ الْمُتَلَاعِنَيْنِ فِي إِمَارَةِ مُصْعَبِ بْنِ الزُّبَيْرِ أَيُفَرَّقُ بَيْنَهُمَا فَمَا دَرَيْتُ مَا أَقُولُ فَقُمْتُ مِنْ مَكَانِي إِلَى مَنْزِلِ عَبْدِ اللَّهِ بْنِ عُمَرَ فَاسْتَأْذَنْتُ عَلَيْهِ فَقِيلَ لِي إِنَّهُ قَائِلٌ فَسَمِعَ كَلَامِي فَقَالَ لِيَ ابْنَ جُبَيْرٍ ادْخُلْ مَا جَاءَ بِكَ إِلَّا حَاجَةٌ قَالَ فَدَخَلْتُ فَإِذَا هُوَ مُفْتَرِشٌ بَرْدَعَةَ رَحْلٍ لَهُ فَقُلْتُ يَا أَبَا عَبْدِ الرَّحْمَنِ الْمُتَلَاعِنَانِ أَيُفَرَّقُ بَيْنَهُمَا فَقَالَ سُبْحَانَ اللَّهِ نَعَمْ إِنَّ أَوَّلَ مَنْ سَأَلَ عَنْ ذَلِكَ فُلَانُ بْنُ فُلَانٍ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ لَوْ أَنَّ أَحَدَنَا رَأَى امْرَأَتَهُ عَلَى فَاحِشَةٍ كَيْفَ يَصْنَعُ إِنْ تَكَلَّمَ تَكَلَّمَ بِأَمْرٍ عَظِيمٍ وَإِنْ سَكَتَ سَكَتَ عَلَى أَمْرٍ عَظِيمٍ قَالَ فَسَكَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يُجِبْهُ فَلَمَّا كَانَ بَعْدَ ذَلِكَ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ الَّذِي سَأَلْتُكَ عَنْهُ قَدْ ابْتُلِيتُ بِهِ فَأَنْزَلَ اللَّهُ هَذِهِ الْآيَاتِ فِي سُورَةِ النُّورِ{ وَالَّذِينَ يَرْمُونَ أَزْوَاجَهُمْ وَلَمْ يَكُنْ لَهُمْ شُهَدَاءُ إِلَّا أَنْفُسُهُمْ }حَتَّى خَتَمَ الْآيَاتِ قَالَ فَدَعَا الرَّجُلَ فَتَلَاهُنَّ عَلَيْهِ وَوَعَظَهُ وَذَكَّرَهُ وَأَخْبَرَهُ أَنَّ عَذَابَ الدُّنْيَا أَهْوَنُ مِنْ عَذَابِ الْآخِرَةِ فَقَالَ لَا وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا كَذَبْتُ عَلَيْهَا ثُمَّ ثَنَّى بِالْمَرْأَةِ وَوَعَظَهَا وَذَكَّرَهَا وَأَخْبَرَهَا أَنَّ عَذَابَ الدُّنْيَا أَهْوَنُ مِنْ عَذَابِ الْآخِرَةِ فَقَالَتْ لَا وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا صَدَقَ فَبَدَأَ بِالرَّجُلِ فَشَهِدَ أَرْبَعَ شَهَادَاتٍ بِاللَّهِ إِنَّهُ لَمِنْ الصَّادِقِينَ وَالْخَامِسَةَ أَنَّ لَعْنَةَ اللَّهِ عَلَيْهِ إِنْ كَانَ مِنْ الْكَاذِبِينَ ثُمَّ ثَنَّى بِالْمَرْأَةِ فَشَهِدَتْ أَرْبَعَ شَهَادَاتٍ بِاللَّهِ إِنَّهُ لَمِنْ الْكَاذِبِينَ وَالْخَامِسَةَ أَنَّ غَضَبَ اللَّهِ عَلَيْهَا إِنْ كَانَ مِنْ الصَّادِقِينَ ثُمَّ فَرَّقَ بَيْنَهُمَاوَفِي الْبَاب عَنْ سَهْلِ بْنِ سَعْدٍ قَالَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Abdul Malik bin Abu Sulaiman] dari [Sa'ad bin Jubair] berkata: Aku ditanya tentang suami-istri yang bersumpah li'an dimasa kepemimpinan Mush'ab bin Az Zubair, apakah keduanya dipisah, aku tidak tahu apa yang harus aku ucapkan lalu aku beranjak dari tempatku menuju kediaman [Abdullah bin Umar], aku meminta izin masuk. Dikatakan kepadaku: Ia tengah istirahat siang. Ibnu Umar mendengar perkataanku lalu Ibnu Jubair berkata padaku: Silahkan masuk, kau datang pasti ada perlu. Sa'ad berkata: Aku masuk, ternyata ia tengah berbaring di atas alas pelana binatang tunggangan. Aku berkata: Wahai Abu Abdurrahman, suami-istri yang bersumpah lian, apakah keduanya dipisah? Ia menjawab: Subhaanallaah, tentu iya. Orang pertama yang menanyakan hal itu adalah fulan bin fulan. Ia mendatangi nabi Shallallahu 'alaihi wa Salam lalu berkata: Wahai Rasulullah, bagaimana menurut baginda, andai salah seorang diantara kami melihat istrinya melakukan zina, apa yang harus ia lakukan? Bila ia berbicara, ia mengutarakan kasus yang besar, tapi bila diam, ia pun mendiamkan kasus yang besar. Nabi Shallallahu 'alaihi wa Salam diam tidak menjawab. Setelah itu ia mendatangi nabi Shallallahu 'alaihi wa Salam dan berkata: kasus yang aku tanyakan itu menimpaku. Lalu Allah menurunkan ayat-ayat dalam surat An Nuur: \"Dan orang-orang yang menuduh isterinya (berzina), padahal mereka tidak ada mempunyai saksi-saksi selain diri mereka sendiri.\" (An Nuur: 6) hingga akhir ayat-ayat ini. Ibnu Umar berkata: Beliau memanggil orang itu, membacakan ayat-ayat itu padanya, menasehati, mengingatkan dan memberitahunya bahwa siksa dunia lebih ringan dari siksa akhirat. Orang itu berkata: Demi Yang mengutus baginda dengan kebenaran, aku tidak berdusta atasnya. Setelah itu nabi Shallallahu 'alaihi wa Salam mengulang hal serupa pada istrinya, menasehati, mengingatkan dan memberitahunya bahwa siksa dunia lebih ringan dari siksa akhirat. Istrinya berkata: Tidak, demi Yang mengutus baginda dengan kebenaran, ia tidak benar. Lalu Rasulullah Shallallahu 'alaihi wa Salam memulai dari yang lelaki lalu ia bersaksi empat kali atas nama Allah bahwa ia benar dan yang kelimanya adalah laknat Allah atasnya bila ia dusta. Setelah itu dilanjutkan istrinya, ia bersaksi empat kali atas nama Allah bahwa ia dusta dan yang kelima adalah siksa Allah atasnya bila suaminya benar. Setelah itu Rasulullah Shallallahu 'alaihi wa Salam memisahkan keduanya. Dalam hal ini ada hadits serupa dari Sahal bin Sa'id. Abu Isa berkata: Hadits ini hasan shahih."},"2945":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ حَدَّثَنِي عِكْرِمَةُ عَنْ ابْنِ عَبَّاسٍأَنَّ هِلَالَ بْنَ أُمَيَّةَ قَذَفَ امْرَأَتَهُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَرِيكِ بْنِ السَّحْمَاءِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّنَةَ وَإِلَّا حَدٌّ فِي ظَهْرِكَ قَالَ فَقَالَ هِلَالٌ يَا رَسُولَ اللَّهِ إِذَا رَأَى أَحَدُنَا رَجُلًا عَلَى امْرَأَتِهِ أَيَلْتَمِسُ الْبَيِّنَةَ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْبَيِّنَةَ وَإِلَّا فَحَدٌّ فِي ظَهْرِكَ قَالَ فَقَالَ هِلَالٌ وَالَّذِي بَعَثَكَ بِالْحَقِّ إِنِّي لَصَادِقٌ وَلَيَنْزِلَنَّ فِي أَمْرِي مَا يُبَرِّئُ ظَهْرِي مِنْ الْحَدِّ فَنَزَلَ{ وَالَّذِينَ يَرْمُونَ أَزْوَاجَهُمْ وَلَمْ يَكُنْ لَهُمْ شُهَدَاءُ إِلَّا أَنْفُسُهُمْ }فَقَرَأَ حَتَّى بَلَغَ{ وَالْخَامِسَةَ أَنَّ غَضَبَ اللَّهِ عَلَيْهَا إِنْ كَانَ مِنْ الصَّادِقِينَ }قَالَ فَانْصَرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَ إِلَيْهِمَا فَجَاءَا فَقَامَ هِلَالُ بْنُ أُمَيَّةَ فَشَهِدَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ يَعْلَمُ أَنَّ أَحَدَكُمَا كَاذِبٌ فَهَلْ مِنْكُمَا تَائِبٌ ثُمَّ قَامَتْ فَشَهِدَتْ فَلَمَّا كَانَتْ عِنْدَ الْخَامِسَةِ{ أَنَّ غَضَبَ اللَّهِ عَلَيْهَا إِنْ كَانَ مِنْ الصَّادِقِينَ }قَالُوا لَهَا إِنَّهَا مُوجِبَةٌ فَقَالَ ابْنُ عَبَّاسٍ فَتَلَكَّأَتْ وَنَكَسَتْ حَتَّى ظَنَّنَا أَنْ سَتَرْجِعُ فَقَالَتْ لَا أَفْضَحُ قَوْمِي سَائِرَ الْيَوْمِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْصِرُوهَا فَإِنْ جَاءَتْ بِهِ أَكْحَلَ الْعَيْنَيْنِ سَابِغَ الْأَلْيَتَيْنِ خَدَلَّجَ السَّاقَيْنِ فَهُوَ لِشَرِيكِ بْنِ السَّحْمَاءِ فَجَاءَتْ بِهِ كَذَلِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا مَا مَضَى مِنْ كِتَابِ اللَّهِ عَزَّ وَجَلَّ لَكَانَ لَنَا وَلَهَا شَأْنٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ هِشَامِ بْنِ حَسَّانَ وَهَكَذَا رَوَى عَبَّادُ بْنُ مَنْصُورٍ هَذَا الْحَدِيثَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَاهُ أَيُّوبُ عَنْ عِكْرِمَةَ مُرْسَلًا وَلَمْ يَذْكُرْ فِيهِ عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ibnu Abi Adi] telah menceritakan kepada kami [Hisyam bin Hassan] telah menceritakan kepadaku [Ikrimah] dari [Ibnu Abbas] bahwa Hilal bin Umaiyah menuduh istrinya berzina dengan Syarik bin As Sahma` di hadapan nabi Shallallahu 'alaihi wa Salam lalu Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Harus kau ajukan bukti, bila tidak, punggungmu akan dihukum cambuk.\" Hilal berkata: Wahai Rasulullah, bila salah seorang dari kami melihat seseorang berada di atas istrinya, masihkah perlu bukti? Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Harus mengajukan bukti, bila tidak, punggungmu akan dihukum cambuk.\" Hilal berkata: Demi Yang mengutus baginda dengan kebenaran, sesungguhnya aku benar, sungguh akan turun (wahyu) berkenaan denganku yang membebaskan punggungku dari hukuman had. Lalu turun ayat: \"Dan orang-orang yang menuduh isterinya (berzina), padahal mereka tidak ada mempunyai saksi-saksi selain diri mereka sendiri.\" (An Nuur: 6) beliau membaca hingga: \"Dan (sumpah) yang kelima: bahwa laknat Allah atasnya jika suaminya itu termasuk orang-orang yang benar.\" (An Nuur: 9) Ibnu Umar berkata: Nabi Shallallahu 'alaihi wa Salam pergi lalu mengirim utusan untuk menemui keduanya. Hilal bin Umaiyah berdiri lalu bersaksi, nabi Shallallahu 'alaihi wa Salam bersabda: Sesungguhnya Allah mengetahui bahwa salah satu dari kalian berdua musti ada yang dusta, adakah diantara kalian berdua yang mau bertaubat?\" istri Hilal berdiri lalu bersaksi, saat bersaksi yang kelima bahwa laknat Allah atasnya jika suaminya itu termasuk orang-orang yang benar, mereka berkata padanya: Wanita ini rupanya memang mengharuskan laknat datang. Ibnu Abbas berkata: Istri Hilal melambat dan menundukkan kepala hingga kami mengira ia akan menarik ucapannya lalu ia berkata: Aku tidak akan membongkar aib kaumku seharian penuh. Nabi Shallallahu 'alaihi wa Salam bersabda: \"Lihatlah ia, bila ia melahirkan (bayi) bermata lebar, pantatnya lebar dan betisnya besar berarti anaknya Syuraik bin As Sahma`. Dan ternyata ia melahirkan anak seperti itu. Nabi Shallallahu 'alaihi wa Salam bersabda: \"Andai bukan karena keputusan Allah 'azza wajalla yang telah berlalu tentu masih ada kasus yang menggantung antara kami dan dia.\" Abu Isa berkata: Hadits ini hasan gharib dari sanad ini dari hadits Hisyam bin Hasan. Seperti itulah [Abbad bin Manshur] meriwayatkan hadits ini dari [Ikrimah] dari [Ibnu Abbas] dari nabi Shallallahu 'alaihi wa Salam. [Ayyub] meriwayatkannya dari [Ikrimah] secara mursal dan tidak menyebut dari Ibnu Abbas."},"2946":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ قَالَتْلَمَّا ذُكِرَ مِنْ شَأْنِي الَّذِي ذُكِرَ وَمَا عَلِمْتُ بِهِ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيَّ خَطِيبًا فَتَشَهَّدَ وَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ أَشِيرُوا عَلَيَّ فِي أُنَاسٍ أَبَنُوا أَهْلِي وَاللَّهِ مَا عَلِمْتُ عَلَى أَهْلِي مِنْ سُوءٍ قَطُّ وَأَبَنُوا بِمَنْ وَاللَّهِ مَا عَلِمْتُ عَلَيْهِ مِنْ سُوءٍ قَطُّ وَلَا دَخَلَ بَيْتِي قَطُّ إِلَّا وَأَنَا حَاضِرٌ وَلَا غِبْتُ فِي سَفَرٍ إِلَّا غَابَ مَعِي فَقَامَ سَعْدُ بْنُ مُعَاذٍ رَضِيَ اللَّهُ عَنْهُ فَقَالَ ائْذَنْ لِي يَا رَسُولَ اللَّهِ أَنْ أَضْرِبَ أَعْنَاقَهُمْ وَقَامَ رَجُلٌ مِنْ بَنِي الْخَزْرَجِ وَكَانَتْ أُمُّ حَسَّانَ ابْنِ ثَابِتٍ مِنْ رَهْطِ ذَلِكَ الرَّجُلِ فَقَالَ كَذَبْتَ أَمَا وَاللَّهِ أَنْ لَوْ كَانُوا مِنْ الْأَوْسِ مَا أَحْبَبْتَ أَنْ تُضْرَبَ أَعْنَاقُهُمْ حَتَّى كَادَ أَنْ يَكُونَ بَيْنَ الْأَوْسِ وَالْخَزْرَجِ شَرٌّ فِي الْمَسْجِدِ وَمَا عَلِمْتُ بِهِ فَلَمَّا كَانَ مَسَاءُ ذَلِكَ الْيَوْمِ خَرَجْتُ لِبَعْضِ حَاجَتِي وَمَعِي أُمُّ مِسْطَحٍ فَعَثَرَتْ فَقَالَتْ تَعِسَ مِسْطَحٌ فَقُلْتُ لَهَا أَيْ أُمُّ تَسُبِّينَ ابْنَكِ فَسَكَتَتْ ثُمَّ عَثَرَتْ الثَّانِيَةَ فَقَالَتْ تَعِسَ مِسْطَحٌ فَانْتَهَرْتُهَا فَقُلْتُ لَهَا أَيْ أُمُّ تَسُبِّينَ ابْنَكِ فَسَكَتَتْ ثُمَّ عَثَرَتْ الثَّالِثَةَ فَقَالَتْ تَعِسَ مِسْطَحٌ فَانْتَهَرْتُهَا فَقُلْتُ لَهَا أَيْ أُمُّ تَسُبِّينَ ابْنَكِ فَقَالَتْ وَاللَّهِ مَا أَسُبُّهُ إِلَّا فِيكِ فَقُلْتُ فِي أَيِّ شَيْءٍ قَالَتْ فَبَقَرَتْ لِي الْحَدِيثَ قُلْتُ وَقَدْ كَانَ هَذَا قَالَتْ نَعَمْ وَاللَّهِ لَقَدْ رَجَعْتُ إِلَى بَيْتِي وَكَأَنَّ الَّذِي خَرَجْتُ لَهُ لَمْ أَخْرُجْ لَا أَجِدُ مِنْهُ قَلِيلًا وَلَا كَثِيرًا وَوُعِكْتُ فَقُلْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسِلْنِي إِلَى بَيْتِ أَبِي فَأَرْسَلَ مَعِي الْغُلَامَ فَدَخَلْتُ الدَّارَ فَوَجَدْتُ أُمَّ رُومَانَ فِي السُّفْلِ وَأَبُو بَكْرٍ فَوْقَ الْبَيْتِ يَقْرَأُ فَقَالَتْ أُمِّي مَا جَاءَ بِكِ يَا بُنَيَّةُ قَالَتْ فَأَخْبَرْتُهَا وَذَكَرْتُ لَهَا الْحَدِيثَ فَإِذَا هُوَ لَمْ يَبْلُغْ مِنْهَا مَا بَلَغَ مِنِّي قَالَتْ يَا بُنَيَّةُ خَفِّفِي عَلَيْكِ الشَّأْنَ فَإِنَّهُ وَاللَّهِ لَقَلَّمَا كَانَتْ امْرَأَةٌ حَسْنَاءُ عِنْدَ رَجُلٍ يُحِبُّهَا لَهَا ضَرَائِرُ إِلَّا حَسَدْنَهَا وَقِيلَ فِيهَا فَإِذَا هِيَ لَمْ يَبْلُغْ مِنْهَا مَا بَلَغَ مِنِّي قَالَتْ قُلْتُ وَقَدْ عَلِمَ بِهِ أَبِي قَالَتْ نَعَمْ قُلْتُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ نَعَمْ وَاسْتَعْبَرْتُ وَبَكَيْتُ فَسَمِعَ أَبُو بَكْرٍ صَوْتِي وَهُوَ فَوْقَ الْبَيْتِ يَقْرَأُ فَنَزَلَ فَقَالَ لِأُمِّي مَا شَأْنُهَا قَالَتْ بَلَغَهَا الَّذِي ذُكِرَ مِنْ شَأْنِهَا فَفَاضَتْ عَيْنَاهُ فَقَالَ أَقَسَمْتُ عَلَيْكِ يَا بُنَيَّةُ إِلَّا رَجَعْتِ إِلَى بَيْتِكِ فَرَجَعْتُ وَلَقَدْ جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْتِي فَسَأَلَ عَنِّي خَادِمَتِي فَقَالَتْ لَا وَاللَّهِ مَا عَلِمْتُ عَلَيْهَا عَيْبًا إِلَّا أَنَّهَا كَانَتْ تَرْقُدُ حَتَّى تَدْخُلَ الشَّاةُ فَتَأْكُلَ خَمِيرَتَهَا أَوْ عَجِينَتَهَا وَانْتَهَرَهَا بَعْضُ أَصْحَابِهِ فَقَالَ أَصْدِقِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَسْقَطُوا لَهَا بِهِ فَقَالَتْ سُبْحَانَ اللَّهِ وَاللَّهِ مَا عَلِمْتُ عَلَيْهَا إِلَّا مَا يَعْلَمُ الصَّائِغُ عَلَى تِبْرِ الذَّهَبِ الْأَحْمَرِ فَبَلَغَ الْأَمْرُ ذَلِكَ الرَّجُلَ الَّذِي قِيلَ لَهُ فَقَالَ سُبْحَانَ اللَّهِ وَاللَّهِ مَا كَشَفْتُ كَنَفَ أُنْثَى قَطُّ قَالَتْ عَائِشَةُ فَقُتِلَ شَهِيدًا فِي سَبِيلِ اللَّهِ قَالَتْ وَأَصْبَحَ أَبَوَايَ عِنْدِي فَلَمْ يَزَالَا حَتَّى دَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ صَلَّى الْعَصْرَ ثُمَّ دَخَلَ وَقَدْ اكْتَنَفَنِي أَبَوَايَ عَنْ يَمِينِي وَعَنْ شِمَالِي فَتَشَهَّدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ يَا عَائِشَةُ إِنْ كُنْتِ قَارَفْتِ سُوءًا أَوْ ظَلَمْتِ فَتُوبِي إِلَى اللَّهِ فَإِنَّ اللَّهَ يَقْبَلُ التَّوْبَةَ عَنْ عِبَادِهِ قَالَتْ وَقَدْ جَاءَتْ امْرَأَةٌ مِنْ الْأَنْصَارِ وَهِيَ جَالِسَةٌ بِالْبَابِ فَقُلْتُ أَلَا تَسْتَحْيِي مِنْ هَذِهِ الْمَرْأَةِ أَنْ تَذْكُرَ شَيْئًا فَوَعَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَالْتَفَتُّ إِلَى أَبِي فَقُلْتُ أَجِبْهُ قَالَ فَمَاذَا أَقُولُ فَالْتَفَتُّ إِلَى أُمِّي فَقُلْتُ أَجِيبِيهِ قَالَتْ أَقُولُ مَاذَا قَالَتْ فَلَمَّا لَمْ يُجِيبَا تَشَهَّدْتُ فَحَمِدْتُ اللَّهَ وَأَثْنَيْتُ عَلَيْهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قُلْتُ أَمَا وَاللَّهِ لَئِنْ قُلْتُ لَكُمْ إِنِّي لَمْ أَفْعَلْ وَاللَّهُ يَشْهَدُ إِنِّي لَصَادِقَةٌ مَا ذَاكَ بِنَافِعِي عِنْدَكُمْ لِي لَقَدْ تَكَلَّمْتُمْ وَأُشْرِبَتْ قُلُوبُكُمْ وَلَئِنْ قُلْتُ إِنِّي قَدْ فَعَلْتُ وَاللَّهُ يَعْلَمُ أَنِّي لَمْ أَفْعَلْ لَتَقُولُنَّ إِنَّهَا قَدْ بَاءَتْ بِهِ عَلَى نَفْسِهَا وَإِنِّي وَاللَّهِ مَا أَجِدُ لِي وَلَكُمْ مَثَلًا قَالَتْ وَالْتَمَسْتُ اسْمَ يَعْقُوبَ فَلَمْ أَقْدِرْ عَلَيْهِ إِلَّا أَبَا يُوسُفَ حِينَ قَالَ{ فَصَبْرٌ جَمِيلٌ وَاللَّهُ الْمُسْتَعَانُ عَلَى مَا تَصِفُونَ }قَالَتْ وَأُنْزِلَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَاعَتِهِ فَسَكَتْنَا فَرُفِعَ عَنْهُ وَإِنِّي لَأَتَبَيَّنُ السُّرُورَ فِي وَجْهِهِ وَهُوَ يَمْسَحُ جَبِينَهُ وَيَقُولُ الْبُشْرَى يَا عَائِشَةُ فَقَدْ أَنْزَلَ اللَّهُ بَرَاءَتَكِ قَالَتْ فَكُنْتُ أَشَدَّ مَا كُنْتُ غَضَبًا فَقَالَ لِي أَبَوَايَ قُومِي إِلَيْهِ فَقُلْتُ لَا وَاللَّهِ لَا أَقُومُ إِلَيْهِ وَلَا أَحْمَدُهُ وَلَا أَحْمَدُكُمَا وَلَكِنْ أَحْمَدُ اللَّهَ الَّذِي أَنْزَلَ بَرَاءَتِي لَقَدْ سَمِعْتُمُوهُ فَمَا أَنْكَرْتُمُوهُ وَلَا غَيَّرْتُمُوهُ وَكَانَتْ عَائِشَةُ تَقُولُ أَمَّا زَيْنَبُ بِنْتُ جَحْشٍ فَعَصَمَهَا اللَّهُ بِدِينِهَا فَلَمْ تَقُلْ إِلَّا خَيْرًا وَأَمَّا أُخْتُهَا حَمْنَةُ فَهَلَكَتْ فِيمَنْ هَلَكَ وَكَانَ الَّذِي يَتَكَلَّمُ فِيهِ مِسْطَحٌ وَحَسَّانُ بْنُ ثَابِتٍ وَالْمُنَافِقُ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ وَهُوَ الَّذِي كَانَ يَسُوسُهُ وَيَجْمَعُهُ وَهُوَ الَّذِي تَوَلَّى كِبْرَهُ مِنْهُمْ هُوَ وَحَمْنَةُ قَالَتْ فَحَلَفَ أَبُو بَكْرٍ أَنْ لَا يَنْفَعَ مِسْطَحًا بِنَافِعَةٍ أَبَدًا فَأَنْزَلَ اللَّهُ تَعَالَى هَذِهِ الْآيَةَ{ وَلَا يَأْتَلِ أُولُوا الْفَضْلِ مِنْكُمْ وَالسَّعَةِ }إِلَى آخِرِ الْآيَةِ يَعْنِي أَبَا بَكْرٍ{ أَنْ يُؤْتُوا أُولِي الْقُرْبَى وَالْمَسَاكِينَ وَالْمُهَاجِرِينَ فِي سَبِيلِ اللَّهِ }يَعْنِي مِسْطَحًا إِلَى قَوْلِهِ{ أَلَا تُحِبُّونَ أَنْ يَغْفِرَ اللَّهُ لَكُمْ وَاللَّهُ غَفُورٌ رَحِيمٌ }قَالَ أَبُو بَكْرٍ بَلَى وَاللَّهِ يَا رَبَّنَا إِنَّا لَنُحِبُّ أَنْ تَغْفِرَ لَنَا وَعَادَ لَهُ بِمَا كَانَ يَصْنَعُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ هِشَامِ بْنِ عُرْوَةَ وَقَدْ رَوَاهُ يُونُسُ بْنُ يَزِيدَ وَمَعْمَرٌ وَغَيْرُ وَاحِدٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ وَسَعِيدِ بْنِ الْمُسَيَّبِ وَعَلْقَمَةَ بْنِ وَقَّاصٍ اللَّيْثِيِّ وَعُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَائِشَةَ هَذَا الْحَدِيثَ أَطْوَلَ مِنْ حَدِيثِ هِشَامِ بْنِ عُرْوَةَ وَأَتَمَّ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin Urwah] telah mengkhabarkan kepadaku [ayahku] dari [Aisyah] berkata: Saat perihalku disebut sedemikian rupa dan aku tidak mengetahuinya, Rasulullah Shallallahu 'alaihi wa Salam berdiri berkhutbah dihadapanku, beliau membaca kalimat syahadat dan bertahmid dengan tahmid yang layak bagiNya, setelah itu beliau bersabda: \"Hadirin semua, berilah aku saran-saran tentang orang-orang yang menuduhkan keburukan pada keluargaku (maksud beliau 'Aisyah), demi Allah aku tidak mengetahui suatu keburukan pun atas keluargaku, dan mereka tuduhkan keburukan kepada orang yang demi Allah aku tidak mengetahui suatu keburukan pun atasnya (maksud beliau Shafwan bin Mu'aththal). Ia (Shafwan) tidak masuk rumahku sama sekali melainkan aku ada dan tidaklah aku pergi dalam suatu perjalanan melainkan ia (Shfawan) pergi berasamaku. Sa'ad bin Mu'adz radliallahu 'anhu berdiri lalu berkata: Wahai Rasulullah, izinkan aku menebas leher mereka. Seseorang dari bani Khajraj lantas berdiri, yang ibu Hassan bin Tsabit berasal dari kabilah orang tersebut, ia berkata: \"Kau dusta, demi Allah, bila meraka dari Aus, tentu tidak kau tebas leher-leher mereka.\" Hingga nyaris terjadi suatu keburukan antara Aus dan Khajraj di masjid dan aku tidak mengetahuinya. Sore harinya, dan masih hari itu juga, aku (Aisyah) pergi untuk suatu keperluan bersama Ummu Misthah, rupanya ia terpeleset lalu berkata: Celakalah Misthah. Aku berkata padanya: Hai ibu, kau mencela anakmu? Ia diam lalu terpeleset lagi, ia berkata: Celakalah Misthah, lalu aku membentaknya, aku berkata padanya: Hai ibu, kau mencela anakmu. Ia berkata: Demi Allah, aku tidak mencelanya kecuali berkenaan dengan kasus mu. Aku bertanya: Tentang apa? Ia menjawab lalu membeberkan masalahnya padaku. Aku bertanya: Sudah terjadi? Ia menjawab: Ya, demi Allah. Aku kembali pulang ke rumah, seolah-olah keperluan yang aku tuju tidak ada artinya, aku tidak mendapatkannya sedikit atau banyak, aku terserang panas. Aku berkata kepada Rasulullah Shallallahu 'alaihi wa Salam: Pulangkan aku ke rumah ayahku. Beliau mengirimku bersama seorang budak, aku masuk rumah lalu aku lihat Ummu Ruman tengah berada di bawah sementara Abu Bakar berada di atas rumah tengah membaca (al-Qur`an). Ibuku bertanya: Ada apa kau datang, wahai putriku? Aisyah berkata: Lalu aku memberitahukan kisah itu padanya ternyata ia belum mendengar seperti yang telah aku dengar. Ia berkata: Wahai putriku, ringankan kondisimu karena sesungguhnya demi Allah amat jarang sekali seorang wanita cantik yang diperistri seseorang yang punya madu dan ia cintai melainkan mereka akan hasud padanya dan dituduh bermacam-macam. Ternyata ia belum mendengar seperti yang aku dengar. Aisyah berkata: Aku bertanya: Apa ayahku sudah mengetahuinya? Ia menjawab: Ya. Aku bertanya: Rasulullah Shallallahu 'alaihi wa Salam juga? Ia menjawab: Ya. Aku sedih dan menangis hingga Abu Bakar mendengar suaraku saat ia berada di atas rumah membaca (al-Qur`an). Abu Bakar turun lalu bertanya kepada ibuku: Ada apa dia? Ia menjawab: Ia mendengar berita yang disebut-sebut berkenaan dengan masalahnya. Abu Bakar berlinangan air mata lalu berkata: Aku bersumpah untukmu wahai putriku kecuali kau kembali ke rumahmu. Aku kembali dan Rasulullah Shallallahu 'alaihi wa Salam telah sampai. Beliau bertanya kepada pelayanku tentang aku, pelayanku menjawab: Tidak, demi Allah aku tidak mengetahui keburukan padanya selain ia tidur hingga ada kambing masuk lalu memakan ragi adonan roti atau ragienya. Sebagaian sahabat Rasulullah Shallallahu 'alaihi wa Salam membentaknya lalu berkata: Benarkan Rasulullah Shallallahu 'alaihi wa Salam, hingga mereka mencelanya. Ia berkata: Subhaanallaah, demi Allah aku tidak mengetahui kondisinya kecuali seperti yang diketahui tukang emas atas emas lantak. Berita bohong ini pun terdengar oleh orang yang dituduhkan padanya (Shafwan) lalu ia berkata: Subhaanallaah, demi Allah aku sama sekali tidak pernah membuka pakaian wanita. Aisyah berkata: Ia (Shafwan) mati syahid di jalan Allah. Aisyah berkata: Kedua orang tuaku berada di dekatku, mereka tetap berada di dekatku hingga Rasulullah Shallallahu 'alaihi wa Salam masuk dan beliau usai shalat ashar. Kedua orang tuaku mengelilingku dari kanan dan kiri, nabi Shallallahu 'alaihi wa Salam membaca syahadat dan bertahmid seperti yang layak bagiNya, setelah itu beliau bersabda: \"Wahai Aisyah, bila kau melakukan suatu keburukan atau berbuat zhalim, bertaubatlah kepada Allah karena Allah menerima taubat hamba-hambaNya.\" Aisyah berkata: Seorang wanita Anshar datang dan tengah duduk di pintu, aku berkata: Apa kau tidak malu pada wanita ini dengan menyebut sesuatu. Rasulullah Shallallahu 'alaihi wa Salam kemudian memberikan nasehat lalu aku menoleh ke ayahku, aku berkata: Jawab dia. Abu Bakar bertanya: Apa yang harus aku katakan? Aku menoleh ke ibuku, aku berkata: Jawab dia. Ummu Misthah bertanya: Apa yang harus aku katakan? Saat keduanya tidak menjawab, aku membaca syahadat, aku bertahmid dan memuji dengan pujian yang patut baginya, selanjutnya aku berkata: Ingatlah, demi Allah bila aku katakan pada kalian bahwa aku tidak melakukannya, Allah tahu bahwa aku benar tapi itu tidak ada gunanya bagi kalian, kalian sudah bicara (macam-macam) dan hati kalian telah terasuki. Bila pun aku mengatakan aku telah melakukannya, Allah tahu bahwa aku tidak melakukannya, kalian pasti akan mengatakan bahwa ia telah mengakui perbuatannya, demi Allah tidak memiliki perumpamaan antara aku dan kalian. Aisyah melanjutkan: Aku mencari nama Ya'qub, tapi aku tidak mampu menyebutnya selain Abu Yusuf saat berkata: \"Maka kesabaran yang baik Itulah (kesabaranku) dan Allah sajalah yang dimohon pertolongan-Nya terhadap apa yang kamu ceritakan.\" (Yuusuf: 18) Aisyah meneruskan: Saat itu juga diturunkan wahyu pada Rasulullah Shallallahu 'alaihi wa Salam, kami diam lalu wahyu diangkat dari beliau, kami mengetahui kebahagiaan diwajah beliau, beliau mengusap dahi dan bersabda: \"Khabar gembira wahai Aisyah, Allah telah menurunkan pembebasanmu (berita kesucianmu).\" Aisyah berkata: Saat itu aku sangat marah sekali. Kedua orang tuaku berkata: Hampirilah beliau. Aku berkata: Tidak, demi Allah aku tidak akan menghampiri beliau, aku tidak memujinya dan tidak juga kalian berdua, tapi aku memuji Allah yang telah menurunkan berita kesucianku yang telah kalian sama dengarkan, tidak kalian ingkari dan juga tidak kalian rubah. Aisyah berkata: Zainab binti Jahsy dijaga Allah karena agamanya, ia tidak mengucapkan kata-kata selain kebaikan, sementara saudaranya, Hamnah, ia binasa bersama yang lainnya. Dan yang turut membicarakan khabar bohong (issue dusta) itu adalah Misthah, Hassan bin Tsabit dan si munafik, Abdullah bin Ubai bin Salul, dialah yang memimpin dan memprovokasinya, dialah yang menanggung dosanya diantara mereka, dia bersama Hamnah. Aisyah meneruskan: Abu Bakar bersumpah tidak akan memberi apa pun pada Misthah selamanya lalu Allah menurunkan ayat ini: \"Dan janganlah orang-orang yang mempunyai kelebihan dan kelapangan di antara kamu bersumpah untuk tidak memberi…..\" Hingga akhir ayat (An Nuur: 22) maksudnya Abu Bakar untuk memberi (bantuan) pada kerabat, orang-orang miskin dan muhajirin di jalan Allah. Yang dimaksudkan adalah Misthah, hingga firmanNya: \"Apakah kamu tidak ingin bahwa Allah mengampunimu? dan Allah adalah Maha Pengampun lagi Maha Penyayang.\" (An Nuur: 22) Abu Bakar berkata: Ya, demi Allah wahai Rabb kami, kami ingin Engkau mengampuni kami. Abu Bakar kembali melakukan seperti yang dilakukan semula (memberi infak untuk Mistah). Abu Isa berkata: Hadits ini hasan shahih dari hadits Hisyam bin Urwah. [Yunus bin Yazid], [Ma'mar] dan lainnya juga meriwayatkannya dari [Az Zuhri] dari [Urwah bin Az Zubair], [Sa'id bin Al Musayyib], [Alqamah bin Waqqash Al Laitsi] dan [Ubaidullah bin Abdullah] dari [Aisyah] yang lebih panjang dan lebih lengkap dari hadits Hisyam bin Urwah."},"2947":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْلَمَّا نَزَلَ عُذْرِي قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ فَذَكَرَ ذَلِكَ وَتَلَا الْقُرْآنَ فَلَمَّا نَزَلَ أَمَرَ بِرَجُلَيْنِ وَامْرَأَةٍ فَضُرِبُوا حَدَّهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ مُحَمَّدِ بْنِ إِسْحَقَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ibnu Abi Adi] dari [Muhammad bin Ishaq] dari [Abdullah bin Abu Bakar] dari [Umrah] dari [Aisyah] berkata: Saat turun (ayat) berita kesucianku, Rasulullah Shallallahu 'alaihi wa Salam berdiri di atas mimbar, menyebutkan hal itu dan beliau membaca al-Qur'an. Saat turun (ayat), beliau memerintahkan dua lelaki dan seorang perempuan agar dijatuhi hukuman. Abu Isa berkata: Hadits ini hasan gharib, kami hanya mengetahuinya dari hadits Muhammad bin Ishaq."},"2948":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ وَاصِلٍ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ عَبْدِ اللَّهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ الذَّنْبِ أَعْظَمُ قَالَ أَنْ تَجْعَلَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قَالَ قُلْتُ ثُمَّ مَاذَا قَالَ أَنْ تَقْتُلَ وَلَدَكَ خَشْيَةَ أَنْ يَطْعَمَ مَعَكَ قَالَ قُلْتُ ثُمَّ مَاذَا قَالَ أَنْ تَزْنِيَ بِحَلِيلَةِ جَارِكَقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ وَالْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Washil] dari [Abu Wa`il] dari [Amru bin Syurahbil] dari [Abdullah] berkata: Aku berkata: Wahai Rasulullah, dosa apa yang paling besar? Beliau menjawab: \"Kau membuat tandingan untuk Allah padahal Ia menciptakanmu.\" Ia berkata: Aku bertanya: Lalu apa? Belia menjawab: \"Kau membunuh anakmu karena khawatir makan bersamamu.\" Ia berkata: Aku bertanya: Lalu apa? Belia menjawab: \"Kau berzina dengan istri tetanggamu.\" Abu Isa berkata: Hadits ini hasan gharib. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Manshur] dan [Al A'masy] dari [Abu Wa`il] dari [Amru bin Syurahbil] dari [Abdullah] dari nabi Shallallahu 'alaihi wa Salam sepertinya. Abu Isa berkata: Hadits ini hasan shahih."},"2949":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا سَعِيدُ بْنُ الرَّبِيعِ أَبُو زَيْدٍ حَدَّثَنَا شُعْبَةُ عَنْ وَاصِلٍ الْأَحْدَبِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الذَّنْبِ أَعْظَمُ قَالَ أَنْ تَجْعَلَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ وَأَنْ تَقْتُلَ وَلَدَكَ مِنْ أَجْلِ أَنْ يَأْكُلَ مَعَكَ أَوْ مِنْ طَعَامِكَ وَأَنْ تَزْنِيَ بِحَلِيلَةِ جَارِكَ قَالَ وَتَلَا هَذِهِ الْآيَةَ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا يَزْنُونَ وَمَنْ يَفْعَلْ ذَلِكَ يَلْقَ أَثَامًا يُضَاعَفْ لَهُ الْعَذَابُ يَوْمَ الْقِيَامَةِ وَيَخْلُدْ فِيهِ مُهَانًا }قَالَ أَبُو عِيسَى حَدِيثُ سُفْيَانَ عَنْ مَنْصُورٍ وَالْأَعْمَشِ أَصَحُّ مِنْ حَدِيثِ وَاصِلٍ لِأَنَّهُ زَادَ فِي إِسْنَادِهِ رَجُلًا حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ وَاصِلٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ وَهَكَذَا رَوَى شُعْبَةُ عَنْ وَاصِلٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ وَلَمْ يَذْكُرْ فِيهِ عَمْرَو بْنَ شُرَحْبِيلَ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Sa'id bin Ar Rabi' Abu Zaid] telah menceritakan kepada kami [Syu'bah] dari [Washil Al Ahdab] dari [Abu Wa`il] dari [Abdullah] berkata: Aku bertanya kepada Rasulullah Shallallahu 'alaihi wa Salam: Dosa apa yang paling besar? Beliau menjawab: \"Kau membuat tandingan untuk Allah padahal Ia menciptakanmu, kau membunuh anakmu karena khawatir makan bersamamu atau dari makananmu dan kau berzina dengan istri tetanggamu.\" Abdullah berkata: Beliau membaca ayat ini: \"Dan orang-orang yang tidak menyembah ilah lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar, dan tidak berzina, barang siapa yang melakukan yang demikian itu, niscaya dia mendapat (pembalasan) dosa(nya).\" (Al Furqaan: 69) Abu Isa berkata: Hadits Sufyan dari Manshur dan Al A'masy lebih shahih dari hadits Washil karena ia menambah seseorang dalam sanadnya. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Washil] dari [Abu Wa`il] dari [Abdullah] dari nabi Shallallahu 'alaihi wa Salam sepertinya. Abu Isa berkata: Seperti ini Syu'bah meriwayatkan dari Washil dari Wa`il dari Abdullah tanpa menyebut Amru bin Syurahbil."},"2950":{"ar":"حَدَّثَنَا أَبُو الْأَشْعَثِ أَحْمَدُ بْنُ الْمِقْدَامِ الْعِجْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ الطُّفَاوِيُّ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْلَمَّا نَزَلَتْ هَذِهِ الْآيَةَ{ وَأَنْذِرْ عَشِيرَتَكَ الْأَقْرَبِينَ }قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا صَفِيَّةُ بِنْتَ عَبْدِ الْمُطَّلِبِ يَا فَاطِمَةُ بِنْتَ مُحَمَّدٍ يَا بَنِي عَبْدِ الْمُطَّلِبِ إِنِّي لَا أَمْلِكُ لَكُمْ مِنْ اللَّهِ شَيْئًا سَلُونِي مِنْ مَالِي مَا شِئْتُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا رَوَى وَكِيعٌ وَغَيْرُ وَاحِدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ نَحْوَ حَدِيثِ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ الطُّفَاوِيِّ وَرَوَى بَعْضُهُمْ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا وَلَمْ يَذْكُرْ فِيهِ عَنْ عَائِشَةَ وَفِي الْبَاب عَنْ عَلِيٍّ وَابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Abu Al Asy'ats Ahmad bin Al Miqdam Al Ijli] telah menceritakan kepada kami [Muhammad bin Abdurrahman Ath Thufawi] telah menceritakan kepada kami [Hisyam bin Urwah] dari [ayahnya] dari [Aisyah] berkata: Saat turun ayat ini: \"Dan berilah peringatan kepada kerabat-kerabatmu yang terdekat.\" (Asy Syu'araa`: 214) Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Wahai Shafiyah binti Abdul Muthallib, hai Fathimah binti Muhammad, hai bani Abdul Muthallib, sesungguhnya aku tidak berkuasa apa pun untuk kalian dari siksa Allah, (adapun masalah harta) silahkan mintalah hartaku semaumu.\" Abu Isa berkata: Hadits ini hasan shahih. Seperti itu [Waki'] dan lainnya meriwayatkan dari [Hisyam dari Urwah] dari [ayahnya] dari [Aisyah] seperti hadits Muhammad bin Abdurrahman Ath Thufawi. Sebagaian dari mereka meriwayatkan dari Hisyam bin Urwah dari ayahnya dari nabi Shallallahu 'alaihi wa Salam secara mursal tanpa menyebut dari Aisyah. Dalam hal ini ada hadits serupa dari Ali dan Ibnu Abbas."},"2951":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو الرَّقِّيُّ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا نَزَلَتْ{ وَأَنْذِرْ عَشِيرَتَكَ الْأَقْرَبِينَ }جَمَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُرَيْشًا فَخَصَّ وَعَمَّ فَقَالَ يَا مَعْشَرَ قُرَيْشٍ أَنْقِذُوا أَنْفُسَكُمْ مِنْ النَّارِ فَإِنِّي لَا أَمْلِكُ لَكُمْ مِنْ اللَّهِ ضَرًّا وَلَا نَفْعًا يَا مَعْشَرَ بَنِي عَبْدِ مَنَافٍ أَنْقِذُوا أَنْفُسَكُمْ مِنْ النَّارِ فَإِنِّي لَا أَمْلِكُ لَكُمْ مِنْ اللَّهِ ضَرًّا وَلَا نَفْعًا يَا مَعْشَرَ بَنِي قُصَيٍّ أَنْقِذُوا أَنْفُسَكُمْ مِنْ النَّارِ فَإِنِّي لَا أَمْلِكُ لَكُمْ ضَرًّا وَلَا نَفْعًا يَا مَعْشَرَ بَنِي عَبْدِ الْمُطَّلِبِ أَنْقِذُوا أَنْفُسَكُمْ مِنْ النَّارِ فَإِنِّي لَا أَمْلِكُ لَكُمْ ضَرًّا وَلَا نَفْعًا يَا فَاطِمَةُ بِنْتَ مُحَمَّدٍ أَنْقِذِي نَفْسَكِ مِنْ النَّارِ فَإِنِّي لَا أَمْلِكُ لَكِ ضَرًّا وَلَا نَفْعًا إِنَّ لَكِ رَحِمًا سَأَبُلُّهَا بِبَلَالِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ يُعْرَفُ مِنْ حَدِيثِ مُوسَى بْنِ طَلْحَةَ حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا شُعَيْبُ بْنُ صَفْوَانَ عَنْ عبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Zakariya bin Adi] telah menceritakan kepada kami [Ubaidullah bin Amru Ar Raqqi] dari [Abdul Malik bin Umair] dari [Musa bin Thalhah] dari [Abu Hurairah] berkata: Saat turun (ayat): \"Dan berilah peringatan kepada kerabat-kerabatmu yang terdekat.\" (Asy Syu'araa`: 214) Rasulullah Shallallahu 'alaihi wa Salam mengumpulkan kaum Quraisy, beliau menyebut secara khusus dan umum, beliau bersabda: \"Wahai sekalian kaum Quraisy, selamatkanlah diri kalian dari neraka karena sesungguhnya aku tidak memiliki kuasa membahayakan atau memberi manfaat atas diri kalian dari Allah, wahai sekalian bani Abdu Manaf, selamatkanlah diri kalian dari neraka karena sesungguhnya aku tidak memiliki kuasa membahayakan atau memberi manfaat atas diri kalian dari Allah, wahai sekalian bani Qushai, selamatkanlah diri kalian dari neraka karena sesungguhnya aku tidak memiliki kuasa membahayakan atau memberi manfaat atas diri kalian, wahai sekalian bani Abdul Muthallib, selamatkanlah diri kalian dari neraka karena sesungguhnya aku tidak memiliki kuasa membahayakan atau memberi manfaat atas diri kalian, wahai Fathimah binti Muhammad, selamatkanlah dirimu dari neraka karena sesungguhnya aku tidak memiliki kuasa membahayakan atau memberi manfaat atas dirimu, sesungguhnya engkau memiliki kekerabatan yang akan aku sambung semestinya.\" Abu Isa berkata: Hadits ini hasan shahih gharib dari jalur sanad yang diketahui eari hadits Musa bin Thalhah ini. telah menceritakan kepada kami [Ali bin Hujr] telah menceritakan kepada kami [Syu'aib bin Shafwan] dari [Abdul Malik bin Umair] dari [Musa bin Thalhah] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam sepertinya secara makna."},"2952":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي زِيَادٍ حَدَّثَنَا أَبُو زَيْدٍ عَنْ عَوْفٍ عَنْ قَسَامَةَ بْنِ زُهَيْرٍ حَدَّثَنَا الْأَشْعَرِيُّ قَالَلَمَّا نَزَلَ{ وَأَنْذِرْ عَشِيرَتَكَ الْأَقْرَبِينَ }وَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُصْبُعَيْهِ فِي أُذُنَيْهِ فَرَفَعَ مِنْ صَوْتِهِ فَقَالَ يَا بَنِي عَبْدِ مَنَافٍ يَا صَبَاحَاهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ أَبِي مُوسَى وَقَدْ رَوَاهُ بَعْضُهُمْ عَنْ عَوْفٍ عَنْ قَسَامَةَ بْنِ زُهَيْرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا وَلَمْ يَذْكُرْ فِيهِ عَنْ أَبِي مُوسَى وَهُوَ أَصَحُّ ذَاكَرْتُ بِهِ مُحَمَّدَ بْنَ إِسْمَعِيلَ فَلَمْ يَعْرِفْهُ مِنْ حَدِيثِ أَبِي مُوسَى","id":"Telah menceritakan kepada kami [Abdullah bin Abu Ziyad] telah menceritakan kepada kami [Abu Zaid] dari [Auf] dari [Qasamah bin Zuhair] telah menceritakan kepada kami [Al Asy'ari] berkata: Saat turun (ayat): \"Dan berilah peringatan kepada kerabat-kerabatmu yang terdekat.\" (Asy Syu'araa`: 214), Rasulullah Shallallahu 'alaihi wa Salam menyumbat telinga dengan jari-jari lalu melantangkan suaranya, beliau bersabda: \"Wahai Bani Manaf, Pagi ini ayo kita berkumpul\" (Kata-kata yang diucapkan saat sesuatu yang besar terjadi agar orang-orang berkumpul dan bersiap-siap menghadapinya, pent.) Abu Isa berkata: Hadits ini gharib melalui sanad ini dari hadits Abu Musa. Sebagaian lainnya meriwayatkan hadits ini dari Auf dari Qasamah bin Zuhair dari nabi Shallallahu 'alaihi wa Salam secara mursal tanpa menyebut dari Abu Musa. Ini lebih shahih. Aku menyebutkannya pada Muhammad bin Isma'il tapi ia tidak mengetahuinya dari hadits Abu Musa."},"2953":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَوْسِ بْنِ خَالِدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَخْرُجُ الدَّابَّةُ مَعَهَا خَاتَمُ سُلَيْمَانَ وَعَصَا مُوسَى فَتَجْلُو وَجْهَ الْمُؤْمِنِ وَتَخْتِمُ أَنْفَ الْكَافِرِ بِالْخَاتَمِ حَتَّى إِنَّ أَهْلَ الْخُوَانِ لَيَجْتَمِعُونَ فَيَقُولُ هَاهَا يَا مُؤْمِنُ وَيُقَالُ هَاهَا يَا كَافِرُ وَيَقُولُ هَذَا يَا مُؤْمِنُ وَيَقُولُ هَذَا يَا كَافِرُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَيْرِ هَذَا الْوَجْهِ فِي دَابَّةِ الْأَرْضِ وَفِي الْبَاب عَنْ أَبِي أُمَامَةَ وَحُذَيْفَةَ بْنِ أَسِيدٍ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Rauh bin Ubadah] dari [Hammad bin Salamah] dari [Ali bin Zaid] dari [Aus bin Khalid] dari [Abu Hurairah] nabi Shallallahu 'alaihi wa Salam bersabda: \" (Pada hari kiamat nanti), akan muncul binatang yang membawa stempel Sulaiman dan tongkat Musa, ia menerangkan wajah orang mu`min dan memberi tanda pada hidung orang kafir dengan stempel hingga para pemilik meja makan berkumpul lalu ia (sebagian dari mereka pada yang lain) berkata: \"Ini orang mu`min\", namun ia mendapat jawaban \"Kalau itu orang kafir.\" Yang lain juga berkata: \"Ini orang mu`min\", yang lain menolak dengan berkata: \"Oh, Itu orang kafir.\" Abu Isa berkata: Hadits ini hasan gharib. Hadits ini juga diriwayatkan dari Abu Hurairah dari nabi Shallallahu 'alaihi wa Salam melalui sanad lain yang menyebut binatang bumi. Dalam hal ini ada hadits serupa dari Abu Umamah dan Hudzaifah bin Asid."},"2954":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ يَزِيدَ بْنِ كَيْسَانَ حَدَّثَنِي أَبُو حَازِمٍ الْأَشْجَعِيُّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَمِّهِ قُلْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ لَكَ بِهَا يَوْمَ الْقِيَامَةِ قَالَ لَوْلَا أَنْ تُعَيِّرَنِي بِهَا قُرَيْشٌ أَنَّ مَا يَحْمِلُهُ عَلَيْهِ الْجَزَعُ لَأَقْرَرْتُ بِهَا عَيْنَكَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ وَلَكِنَّ اللَّهَ يَهْدِي مَنْ يَشَاءُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ يَزِيدَ بْنِ كَيْسَانَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Yazid bin Kaisan] telah menceritakan kepadaku [Abu Hazim Al Asyja'i] dari [Abu Hurairah] radliallahu 'anhu berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda kepada paman beliau: \" Ucapkan: LAA ILAAHA ILLALLAAH, dengannya aku akan bersaksi untuk membelamu pada hari kiamat.\" Ia menjawab: Andai kaum Quraisy tidak mencelaku bahwa yang mendorongku untuk mengucapkannya hanyalah ketakutan, pasti aku akan membuatmu senang dengan (mengucapkan) nya. Lalu Allah 'azza wajalla menurunkan ayat: \"Sesungguhnya kamu tidak akan dapat memberi petunjuk kepada orang yang kamu kasihi, tetapi Allah memberi petunjuk kepada orang yang dikehendaki-Nya, dan Allah lebih mengetahui orang-orang yang mau menerima petunjuk.\" (Al Qashash: 56) Abu Isa berkata: Hadits ini hasan gharib, kami hanya mengetahuinya dari hadits Yazid bin Kaisan."},"2955":{"ar":"بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ قَال سَمِعْتُ مُصْعَبَ بْنَ سَعْدٍ يُحَدِّثُ عَنْ أَبِيهِ سَعْدٍ قَالَأُنْزِلَتْ فِيَّ أَرْبَعُ آيَاتٍ فَذَكَرَ قِصَّةً وَقَالَتْ أُمُّ سَعْدٍ أَلَيْسَ قَدْ أَمَرَ اللَّهُ بِالْبِرِّ وَاللَّهِ لَا أَطْعَمُ طَعَامًا وَلَا أَشْرَبُ شَرَابًا حَتَّى أَمُوتَ أَوْ تَكْفُرَ قَالَ فَكَانُوا إِذَا أَرَادُوا أَنْ يُطْعِمُوهَا شَجَرُوا فَاهَا فَنَزَلَتْ هَذِهِ الْآيَةَ{ وَوَصَّيْنَا الْإِنْسَانَ بِوَالِدَيْهِ حُسْنًا وَإِنْ جَاهَدَاكَ لِتُشْرِكَ بِي }الْآيَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Bismillaahirrahmaanirrahiim. Telah menceritakan kepada kami [Muhammad bin Basyar] dan [Muhammad bin Al Mutsanna] keduanya berkata: telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] berkata: Aku mendengar [Mush'ab bin Sa'ad] menceritakan dari [ayahnya, Sa'ad] berkata: Empat ayat diturunkan berkenaan denganku. Ia menyebutkan kisah, Ummu Sa'ad berkata: Bukankah Allah memerintahkan berbuat baik, demi Allah aku tidak akan memakan apa pun dan tidak meminum apa pun hingga aku mati atau kau harus kufur. Mush'ab berkata: Bila mereka hendak memberinya makan, mereka membuka mulutnya lalu turunlah ayat ini: \"Dan kami wajibkan manusia (berbuat) kebaikan kepada dua orang ibu-bapaknya dan jika keduanya memaksamu untuk mempersekutukan Aku dengan sesuatu yang tidak ada pengetahuanmu tentang itu maka janganlah kamu mengikuti keduanya. Hanya kepadaKu-lah kembalimu, lalu Aku kabarkan kepadamu apa yang telah kamu kerjakan.\" (Al Ankabuut: 8) Abu Isa berkata: Hadits ini hasan shahih."},"2956":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أُسَامَةَ وَعَبْدُ اللَّهِ بْنُ بَكْرٍ السَّهْمِيُّ عَنْ حَاتِمِ بْنِ أَبِي صَغِيرَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ أَبِي صَالِحٍ عَنْ أُمِّ هَانِئٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ{ وَتَأْتُونَ فِي نَادِيكُمْ الْمُنْكَرَ }قَالَ كَانُوا يَخْذِفُونَ أَهْلَ الْأَرْضِ وَيَسْخَرُونَ مِنْهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ حَاتِمِ بْنِ أَبِي صَغِيرَةَ عَنْ سِمَاكٍ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا سُلَيْمُ بْنُ أَخْضَرَ عَنْ حَاتِمِ بْنِ أَبِي صَغِيرَةَ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Usamah] dan [Abdullah bin Bakr As Sahmi] dari [Hatim bin Abu Shaghirah] dari [Simak bin Harb] dari [Abu Shalih] dari [Ummu Hani`] dari nabi Shallallahu 'alaihi wa Salam tentang fimranNya: \"Dan mengerjakan kemungkaran di tempat-tempat pertemuanmu?\" (Al Ankabuut: 29) beliau bersabda: \"Mereka melempari penduduk dengan batu-batu kecil dan mencemoohnya.\" Abu Isa berkata: Hadits ini hasan, kami hanya mengetahuinya dari hadits Hatim bin Abu Shaghirah dari Simak. Telah menceritakan kepada kami [Ahmad bin Abdah] telah menceritakan kepada kami [Sulaim bin Akhdlar] dari [Hatim bin Abu Shaghirah] dengan sanad ini sepertinya."},"2957":{"ar":"حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدٍ ابْنُ عَثْمَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الْجُمَحِيُّ حَدَّثَنَا ابْنُ شِهَابٍ الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَبِي بَكْرٍ فِي مُنَاحَبَةِ{ الم غُلِبَتْ الرُّومُ }أَلَا احْتَطْتَ يَا أَبَا بَكْرٍ فَإِنَّ الْبِضْعَ مَا بَيْنَ ثَلَاثٍ إِلَى تِسْعٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Abu Musa Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Khalid Ibnu Atsmah] telah menceritakan kepada kami [Abdullah bin Abdurrahman Al Juhami] telah menceritakan kepada kami [Ibnu Syihab Az Zuhri] dari [Ubaidullah bin Abdullah bin Utbah] dari [Ibnu Abbas] Rasulullah Shallallahu 'alaihi wa Salam bersabda kepada Abu Bakar tentang jaminan ayat: (saat turun ayat) ALIF LAAM MIIM GHULIBATIRRUUM: \"Apa engkau tidak memprediksikan wahai Abu Bakar, sesungguhnya bidh'u itu adalah antara tiga hingga sembilan.\" Abu Isa berkata: Hadits ini hasan gharib dari jalur sanad ini dari hadits Az Zuhri dari Ubaidullah dari Ibnu Abbas."},"2958":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ سُلَيْمَانَ الْأَعْمَشِ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَلَمَّا كَانَ يَوْمُ بَدْرٍ ظَهَرَتْ الرُّومُ عَلَى فَارِسَ فَأَعْجَبَ ذَلِكَ الْمُؤْمِنِينَ فَنَزَلَتْ{ الم غُلِبَتْ الرُّومُ إِلَى قَوْلِهِ يَفْرَحُ الْمُؤْمِنُونَ بِنَصْرِ اللَّهِ }قَالَ فَفَرِحَ الْمُؤْمِنُونَ بِظُهُورِ الرُّومِ عَلَى فَارِسَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ كَذَا قَرَأَ نَصْرُ بْنُ عَلِيٍّ غَلَبَتْ الرُّومُ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [ayahnya] dari [Sulaiman Al A'masy] dari [Athiyah] dari [Abu Sa'id] berkata: Saat perang Badar, Romawi mengalahkan Persia, orang-orang mu`min heran akan hal itu lalu turun: \"Alif laam Miim, telah dikalahkan bangsa Romawi\" hingga firmanNya: \"Bergembiralah orang-orang yang beriman, karena pertolongan Allah.\" (Ar Ruum: 1-5) Abu Sa'id berkata: Orang-orang mu`min pun bergembira atas kemenangan Romawi atas Persia. Abu Isa berkata: Hadits ini hasan gharib dari jalur sanad ini. Nashr bin Ali membaca: GHALABATIR RUUM (bukan GHULIBAT sekalipun dalam teks aseli GHULIBAT)."},"2959":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو عَنْ أَبِي إِسْحَقَ الْفَزَارِيِّ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ حَبِيبِ بْنِ أَبِي عَمْرَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْن عَبَّاسٍفِي قَوْلِ اللَّهِ تَعَالَى{ الم غُلِبَتْ الرُّومُ فِي أَدْنَى الْأَرْضِ }قَالَ غُلِبَتْ وَغَلَبَتْ كَانَ الْمُشْرِكُونَ يُحِبُّونَ أَنْ يَظْهَرَ أَهْلُ فَارِسَ عَلَى الرُّومِ لِأَنَّهُمْ وَإِيَّاهُمْ أَهْلُ الْأَوْثَانِ وَكَانَ الْمُسْلِمُونَ يُحِبُّونَ أَنْ يَظْهَرَ الرُّومُ عَلَى فَارِسَ لِأَنَّهُمْ أَهْلُ الْكِتَابِ فَذَكَرُوهُ لِأَبِي بَكْرٍ فَذَكَرَهُ أَبُو بَكْرٍ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَمَا إِنَّهُمْ سَيَغْلِبُونَ فَذَكَرَهُ أَبُو بَكْرٍ لَهُمْ فَقَالُوا اجْعَلْ بَيْنَنَا وَبَيْنَكَ أَجَلًا فَإِنْ ظَهَرْنَا كَانَ لَنَا كَذَا وَكَذَا وَإِنْ ظَهَرْتُمْ كَانَ لَكُمْ كَذَا وَكَذَا فَجَعَلَ أَجَلًا خَمْسَ سِنِينَ فَلَمْ يَظْهَرُوا فَذَكَرُوا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا جَعَلْتَهُ إِلَى دُونَ قَالَ أُرَاهُ الْعَشْرَ قَالَ أَبُو سَعِيدٍ وَالْبِضْعُ مَا دُونَ الْعَشْرِ قَالَ ثُمَّ ظَهَرَتْ الرُّومُ بَعْدُ قَالَ فَذَلِكَ قَوْلُهُ تَعَالَى{ الم غُلِبَتْ الرُّومُ إِلَى قَوْلِهِ وَيَوْمَئِذٍ يَفْرَحُ الْمُؤْمِنُونَ بِنَصْرِ اللَّهِ يَنْصُرُ مَنْ يَشَاءُ }قَالَ سُفْيَانُ سَمِعْتُ أَنَّهُمْ ظَهَرُوا عَلَيْهِمْ يَوْمَ بَدْرٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ سُفْيَانَ الثَّوْرِيِّ عَنْ حَبِيبِ بْنِ أَبِي عَمْرَةَ","id":"Telah menceritakan kepada kami [Al Husain bin Huraits] telah menceritakan kepada kami [Mu'awiyah bin Amru] dari [Abu Ishaq Al Fazari] dari [Sufyan Ats Tsauri] dari [Habib bin Abu Umrah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] tentang firman Allah Ta'ala, \"Alif laam Miim. Telah dikalahkan bangsa Rumawi. Di negeri yang terdekat.\" (Ar Ruum: 1-3) ia berkata: GHULIBAT dan GHALABAT. Kaum musyrik senang terhadap kemenangan Persia atas Romawi karena kaum musyrikin dan orang-orang Persia adalah para penyembah berhala, sedangkan kaum muslimin senang atas kemenangan Romawi terhadap Persia karena mereka ahli kitab. Mereka sampaikan hal ini kepada Abu Bakar lalu Abu Bakar memberitahukannya kepada Rasulullah Shallallahu 'alaihi wa Salam, beliau bersabda: \"Ingat, sesungguhnya mereka (Persia) akan kalah.\" Kemudian Abu Bakar memberitahukannya kepada mereka. Mereka berkata: Tentukan suatu waktu, bila kami menang kami mendapatkan ini dan itu dan bila kalian menang kalian mendapatkan ini dan itu. Abu Bakar menentukan batas waktu lima tahun tapi mereka (Romawi) Tidak juga menang lalu mereka memberitahukan hal itu kepada nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Apa kau tidak memprediksikan (waktu) nya sebawahnya (kurang dari sepuluh)?\" Abu Bakar berkata: Menurutku sepuluh (tahun). Abu Sa'id berkata: Bidl'u adalah bilangan kurang dari sepuluh. Abu Sa'id berkata: Kemudian Romawi menang setelah itu, itulah firman Allah Ta'alaa: \"Alif laam Miim. Telah dikalahkan bangsa Rumawi\" hingga firmanNya: \"Karena pertolongan Allah. Dia menolong siapa yang dikehendakiNya.\" (Ar Ruum: 1-5) Sufyan berkata: Aku mendengar mereka (Romawi) mengalahkan Persia saat terjadi perang Badar. Abu Isa berkata: Hadits ini hasan shahih gharib, kami hanya mengetahuinya dari hadits Sufyan Ats Tsauri dari Habib bin Abu Umrah."},"2960":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي أُوَيْسٍ حَدَّثَنِي ابْنُ أَبِي الزِّنَادِ عَنْ أَبِي الزِّنَادِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ نِيَارِ بْنِ مُكْرَمٍ الْأَسْلَمِيِّ قَالَلَمَّا نَزَلَتْ{ الم غُلِبَتْ الرُّومُ فِي أَدْنَى الْأَرْضِ وَهُمْ مِنْ بَعْدِ غَلَبِهِمْ سَيَغْلِبُونَ فِي بِضْعِ سِنِينَ }فَكَانَتْ فَارِسُ يَوْمَ نَزَلَتْ هَذِهِ الْآيَةُ قَاهِرِينَ لِلرُّومِ وَكَانَ الْمُسْلِمُونَ يُحِبُّونَ ظُهُورَ الرُّومِ عَلَيْهِمْ لِأَنَّهُمْ وَإِيَّاهُمْ أَهْلُ كِتَابٍ وَفِي ذَلِكَ قَوْلُ اللَّهِ تَعَالَى{ وَيَوْمَئِذٍ يَفْرَحُ الْمُؤْمِنُونَ بِنَصْرِ اللَّهِ يَنْصُرُ مَنْ يَشَاءُ وَهُوَ الْعَزِيزُ الرَّحِيمُ }وَكَانَتْ قُرَيْشٌ تُحِبُّ ظُهُورَ فَارِسَ لِأَنَّهُمْ وَإِيَّاهُمْ لَيْسُوا بِأَهْلِ كِتَابٍ وَلَا إِيمَانٍ بِبَعْثٍ فَلَمَّا أَنْزَلَ اللَّهُ تَعَالَى هَذِهِ الْآيَةَ خَرَجَ أَبُو بَكْرٍ الصِّدِّيقُ رَضِيَ اللَّهُ عَنْهُ يَصِيحُ فِي نَوَاحِي مَكَّةَ{ الم غُلِبَتْ الرُّومُ فِي أَدْنَى الْأَرْضِ وَهُمْ مِنْ بَعْدِ غَلَبِهِمْ سَيَغْلِبُونَ فِي بِضْعِ سِنِينَ }قَالَ نَاسٌ مِنْ قُرَيْشٍ لِأَبِي بَكْرٍ فَذَلِكَ بَيْنَنَا وَبَيْنَكُمْ زَعَمَ صَاحِبُكَ أَنَّ الرُّومَ سَتَغْلِبُ فَارِسَ فِي بِضْعِ سِنِينَ أَفَلَا نُرَاهِنُكَ عَلَى ذَلِكَ قَالَ بَلَى وَذَلِكَ قَبْلَ تَحْرِيمِ الرِّهَانِ فَارْتَهَنَ أَبُو بَكْرٍ وَالْمُشْرِكُونَ وَتَوَاضَعُوا الرِّهَانَ وَقَالُوا لِأَبِي بَكْرٍ كَمْ تَجْعَلُ الْبِضْعُ ثَلَاثُ سِنِينَ إِلَى تِسْعِ سِنِينَ فَسَمِّ بَيْنَنَا وَبَيْنَكَ وَسَطًا تَنْتَهِي إِلَيْهِ قَالَ فَسَمَّوْا بَيْنَهُمْ سِتَّ سِنِينَ قَالَ فَمَضَتْ السِّتُّ سِنِينَ قَبْلَ أَنْ يَظْهَرُوا فَأَخَذَ الْمُشْرِكُونَ رَهْنَ أَبِي بَكْرٍ فَلَمَّا دَخَلَتْ السَّنَةُ السَّابِعَةُ ظَهَرَتْ الرُّومُ عَلَى فَارِسَ فَعَابَ الْمُسْلِمُونَ عَلَى أَبِي بَكْرٍ تَسْمِيَةَ سِتِّ سِنِينَ لِأَنَّ اللَّهَ تَعَالَى قَالَ فِي بِضْعِ سِنِينَ وَأَسْلَمَ عِنْدَ ذَلِكَ نَاسٌ كَثِيرٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ نِيَارِ بْنِ مُكْرَمٍ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي الزِّنَادِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Isma'il bin Abu Uwais] telah menceritakan kepadaku [Ibnu Abi Az Zinad] dari [Abu Az Zinad] dari [Urwah bin Az Zubair] dari [Niyar bin Mukram Al Aslami] berkata: Saat turun: \"Alif laam Miim. Telah dikalahkan bangsa Rumawi. Di negeri yang terdekat dan mereka sesudah dikalahkan itu akan menang. Dalam beberapa tahun lagi.\"(Ar Ruum: 1-4) saat ayat ini turun, Persia berhasil mengalahkan Romawi sementara kaum muslimin menyukai kemenangan Romawi atas Persia karena kaum muslimin dan Romawi sama-sama ahli kitab. Berkenaan dengan hal itu Allah berfirman: \"Karena pertolongan Allah. dia menolong siapa yang dikehendakiNya. dan dialah Maha Perkasa lagi Penyayang.\" (Ar Ruum: 5) kaum Quraisy menyukai kemenangan Persia karena mereka dan orang-orang Persia sama-sama bukan ahli kitab dan tidak percaya pada hari kebangkitan. Saat Allah Ta'ala menurunkan ayat ini, Abu Bakar Ash Shiddiq radliallahu 'anhu keluar dan berteriak di berbagai penjuru Makkah: \"Alif laam Miim. Telah dikalahkan bangsa Rumawi. Di negeri yang terdekat dan mereka sesudah dikalahkan itu akan menang. Dalam beberapa tahun lagi.\"(Ar Ruum: 1-4) Beberapa kalangan Quraisy berkata kepada Abu Bakar: Itu antara kami dan kalian, temanmu (Rasulullah Shallallahu 'alaihi wa Salam) mengira bahwa Romawi dan mengalahkan Persia dalam beberapa tahun, mari kita taruhan mengenai hal itu. Abu Bakar menjawab: Mari. Itu terjadi sebelum diharamkannya taruhan. Abu Bakar dan kaum musyrikin taruhan, mereka sama meletakkan taruhan. Mereka berkata kepada Abu Bakar: Berapa batasan bidl'u -tiga hingga sembilan tahun- sebutkan jumlah tepatnya. Niyar berkata: Mereka menyebut enam tahun diantara mereka. Kemudian enam tahun berlalu tapi Romawi tidak kunjung menang hingga kaum musyrikin mengambil taruhan Abu Bakar. Saat masuk tahun ketujuh, Romawi menang atas Persia, kaum muslimin mencela Abu Bakar karena menyebut enam tahun karena Allah Ta'ala berfirman: \"Dalam beberapa tahun.\" Dan saat itulah banyak orang masuk Islam. Abu Isa berkata: Hadits ini shahih hasan gharib dari hadits Niyar bin Mukram, kami hanya mengetahuinya dari hadits Abdurrahman bin Abu Az Zinad."},"2961":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا بَكْرُ بْنُ مُضَرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ زَحْرٍ عَنْ عَلِيِّ بْنِ يَزِيدَ عَنْ الْقَاسِمِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي أُمَامَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَبِيعُوا الْقَيْنَاتِ وَلَا تَشْتَرُوهُنَّ وَلَا تُعَلِّمُوهُنَّ وَلَا خَيْرَ فِي تِجَارَةٍ فِيهِنَّ وَثَمَنُهُنَّ حَرَامٌ وَفِي مِثْلِ هَذَا أُنْزِلَتْ عَلَيْهِ هَذِهِ الْآيَةَ{ وَمِنْ النَّاسِ مَنْ يَشْتَرِي لَهْوَ الْحَدِيثِ لِيُضِلَّ عَنْ سَبِيلِ اللَّهِ }إِلَى آخِرِ الْآيَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ إِنَّمَا يُرْوَى مِنْ حَدِيثِ الْقَاسِمِ عَنْ أَبِي أُمَامَةَ وَالْقَاسِمُ ثِقَةٌ وَعَلِيُّ بْنُ يَزِيدَ يُضَعَّفُ فِي الْحَدِيثِ قَالَهُ مُحَمَّدُ بْنُ إِسْمَعِيلَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Bakru bin Mudhalr] dari [Ubaidullah bin Zahr] dari [Ali bin Yazid] dari [Al Qasim bin Abdurrahman] dari [Abu Umamah] dari Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Janganlah kalian menjual budak-budak wanita penyanyi, jangan membelinya dan jangan ajari mereka, tidak ada kebaikan dalam memperdagangkan mereka dan harga mereka haram.\" Berkenaan dengan hal seperti ini, ayat berikut turun: \"Dan di antara manusia (ada) orang yang mempergunakan perkataan yang tidak berguna untuk menyesatkan (manusia) dari jalan Allah.\" Hingga akhir ayat. (Luqman: 6) Abu Isa berkata: Hadits ini gharib, hanya diriwayatkan dari hadits Al Qasim dari Abu Umamah. Al Qasim perawi tsiqah dan Ali bin Yazid dilemahkan dalam hadits. Muhammad bin Isma'il mengatakan seperti itu."},"2962":{"ar":"بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي زِيَادٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْأُوَيْسِيُّ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ هَذِهِ الْآيَةَ{ تَتَجَافَى جُنُوبُهُمْ عَنْ الْمَضَاجِعِ }نَزَلَتْ فِي انْتِظَارِ الصَّلَاةِ الَّتِي تُدْعَى الْعَتَمَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Bismillaahirrahmaanirrahiim. Telah menceritakan kepada kami [Abdullah bin Abu Ziyad] telah menceritakan kepada kami [Abdul Aziz bin Abdullah Al Uwaisi] dari [Sulaiman bin Bilal] dari [Yahya bin Sa'id] dari [Anas bin Malik] bahwa ayat ini: \"Lambung mereka jauh dari tempat tidurnya.\" (As Sajdah: 16) Turun berkenaan dengan menunggu shalat yang disebut al 'atamah (shalat isyak). Abu Isa berkata: Hadits ini hasan shahih gharib, kami hanya mengetahuinya dari sanad ini."},"2963":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ تَعَالَى أَعْدَدْتُ لِعِبَادِيَ الصَّالِحِينَ مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍ وَتَصْدِيقُ ذَلِكَ فِي كِتَابِ اللَّهِ عَزَّ وَجَلَّ{ فَلَا تَعْلَمُ نَفْسٌ مَا أُخْفِيَ لَهُمْ مِنْ قُرَّةِ أَعْيُنٍ جَزَاءً بِمَا كَانُوا يَعْمَلُونَ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] sampai kepada nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Allah Ta'ala berfirman: 'Aku telah menyiapkan sesuatu yang belum pernah dilihat mata, belum pernah didengar telinga dan tidak pernah terlintas dibenak manusia untuk hamba-hambaKu yang shalih.' Pembenarnya ada didalam kitab Allah 'azza wajalla: \"Tak seorangpun mengetahui berbagai nikmat yang menanti, yang indah dipandang sebagai balasan bagi mereka, atas apa yang mereka kerjakan.\" (As Sajdah: 17) Abu Isa berkata: Hadits ini hasan shahih."},"2964":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ مُطَرِّفِ بْنِ طَرِيفٍ وَعَبْدِ الْمَلِكِ وَهُوَ ابْنُ أَبْجَرَ سَمِعَا الشَّعْبِيَّ يَقُولُسَمِعْتُ الْمُغِيرَةَ بْنَ شُعْبَةَ عَلَى الْمِنْبَرِ يَرْفَعُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ مُوسَى عَلَيْهِ السَّلَام سَأَلَ رَبَّهُ فَقَالَ أَيْ رَبِّ أَيُّ أَهْلِ الْجَنَّةِ أَدْنَى مَنْزِلَةً قَالَ رَجُلٌ يَأْتِي بَعْدَمَا يَدْخُلُ أَهْلُ الْجَنَّةِ الْجَنَّةَ فَيُقَالُ لَهُ ادْخُلْ الْجَنَّةَ فَيَقُولُ كَيْفَ أَدْخُلُ وَقَدْ نَزَلُوا مَنَازِلَهُمْ وَأَخَذُوا أَخَذَاتِهِمْ قَالَ فَيُقَالُ لَهُ أَتَرْضَى أَنْ يَكُونَ لَكَ مَا كَانَ لِمَلِكٍ مِنْ مُلُوكِ الدُّنْيَا فَيَقُولُ نَعَمْ أَيْ رَبِّ قَدْ رَضِيتُ فَيُقَالُ لَهُ فَإِنَّ لَكَ هَذَا وَمِثْلَهُ وَمِثْلَهُ وَمِثْلَهُ فَيَقُولُ رَضِيتُ أَيْ رَبِّ فَيُقَالُ لَهُ فَإِنَّ لَكَ هَذَا وَعَشْرَةَ أَمْثَالِهِ فَيَقُولُ رَضِيتُ أَيْ رَبِّ فَيُقَالُ لَهُ فَإِنَّ لَكَ مَعَ هَذَا مَا اشْتَهَتْ نَفْسُكَ وَلَذَّتْ عَيْنُكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى بَعْضُهُمْ هَذَا الْحَدِيثَ عَنْ الشَّعْبِيِّ عَنْ الْمُغِيرَةِ وَلَمْ يَرْفَعْهُ وَالْمَرْفُوعُ أَصَحُّ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Mutharrif bin Tharif] dan [Abdul Malik yaitu Ibnu Abjar] keduanya mendengar [Asy Sya'bi], ia berkata: Aku mendengar [Al Mughirah bin Syu'bah] menceritakan di atas mimbar, ia menyambungkan (ucapannya) sampai nabi Shallallahu 'alaihi wa Salam, ia berkata: \"Musa 'alaihis salam bertanya kepada Rabbnya: Wahai Rabb, siapakah penghuni surga yang tingkatnya paling rendah? Rabbnya menjawab: Seseorang yang datang setelah seluruh penghuni surga masuk surga, dikatakan padanya: Masuklah surga. Orang itu berkata: Bagaimana aku masuk surga sementara mereka telah menempati tempat-tempat mereka dan mengambil jatah mereka. Dikatakan padanya: Maukah kamu memiliki apa yang dimiliki salah satu raja dunia? Ia menjawab: Ya, wahai Rabb, aku mau. Dikatakan padanya: Sesungguhnya ini milikmu, sepertinya, sepertinya dan sepertinya. Orang itu berkata: Aku rela, wahai Rabb. Dikatakan padanya: Ini dan sepuluh kali sepertinya menjadi milikmu. Orang itu berkata: Aku rela, wahai Rabb. Dikatakan padanya: Selain itu, kau mendapatkan apa yang diinginkan jiwamu dan dipandang nikmat matamu.\" Abu Isa berkata: Hasan shahih. Sebagaian dari mereka meriwayatkan hadits ini dari Asy Sya'bi dari Al Mughirah tapi ia tidak memarfu'kannya. Dan yang marfu' lebih shahih."},"2965":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا صَاعِدٌ الْحَرَّانِيُّ حَدَّثَنَا زُهَيْرٌ أَخْبَرَنَا قَابُوسُ بْنُ أَبِي ظَبْيَانَ أَنَّ أَبَاهُ حَدَّثَهُ قَالَ قُلْنَا لِابْنِ عَبَّاسٍأَرَأَيْتَ قَوْلَ اللَّهِ عَزَّ وَجَلَّ{ مَا جَعَلَ اللَّهُ لِرَجُلٍ مِنْ قَلْبَيْنِ فِي جَوْفِهِ }مَا عَنَى بِذَلِكَ قَالَ قَامَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا يُصَلِّي فَخَطَرَ خَطْرَةً فَقَالَ الْمُنَافِقُونَ الَّذِينَ يُصَلُّونَ مَعَهُ أَلَا تَرَى أَنَّ لَهُ قَلْبَيْنِ قَلْبًا مَعَكُمْ وَقَلْبًا مَعَهُمْ فَأَنْزَلَ اللَّهُ{ مَا جَعَلَ اللَّهُ لِرَجُلٍ مِنْ قَلْبَيْنِ فِي جَوْفِهِ }حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنِي أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengkhabarkan kepada kami [Sha'id Al Harrani] telah menceritakan kepada kami [Zuhair] telah mengkhabarkan kepada kami [Qabus bin Abu Dlabyan] bahwa [ayahnya] telah menceritakan kepadanya, ia berkata: Kami berkata kepada [Ibnu Abbas]: Tahukah kamu firman Allah 'azza wajalla: \"Allah sekali-kali tidak menjadikan bagi seseorang dua buah hati dalam rongganya.\" (Al Ahzaab: 4) apa maksudnya? Ibnu Abbas menjawab: Pada suatu hari, nabi Shallallahu 'alaihi wa Salam shalat lalu terlintas sesuatu dibenak beliau, orang-orang munafik yang shalat bersama beliau berkata: Apa kau tidak lihat, ia memiliki dua hati, satu hati bersama kalian dan satu hati bersama mereka. Lalu Allah menurunkan (ayat): \"Allah sekali-kali tidak menjadikan bagi seseorang dua buah hati dalam rongganya.\" (Al Ahzaab: 4), Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepadaku [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] sepertinya. Abu Isa berkata: Hadits ini hasan."},"2966":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ عَمَّهُ غَابَ عَنْ قِتَالِ بَدْرٍ فَقَالَ غِبْتُ عَنْ أَوَّلِ قِتَالٍ قَاتَلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُشْرِكِينَ لَئِنْ اللَّهُ أَشْهَدَنِي قِتَالًا لَلْمُشْرِكِينَ لَيَرَيَنَّ اللَّهُ كَيْفَ أَصْنَعُ فَلَمَّا كَانَ يَوْمُ أُحُدٍ انْكَشَفَ الْمُسْلِمُونَ فَقَالَ اللَّهُمَّ إِنِّي أَبْرَأُ إِلَيْكَ مِمَّا جَاءَ بِهِ هَؤُلَاءِ يَعْنِي الْمُشْرِكِينَ وَأَعْتَذِرُ إِلَيْكَ مِمَّا صَنَعَ هَؤُلَاءِ يَعْنِي أَصْحَابَهُ ثُمَّ تَقَدَّمَ فَلَقِيَهُ سَعْدٌ فَقَالَ يَا أَخِي مَا فَعَلْتَ أَنَا مَعَكَ فَلَمْ أَسْتَطِعْ أَنْ أَصْنَعَ مَا صَنَعَ فَوُجِدَ فِيهِ بِضْعٌ وَثَمَانُونَ مِنْ ضَرْبَةٍ بِسَيْفٍ وَطَعْنَةٍ بِرُمْحٍ وَرَمْيَةٍ بِسَهْمٍ فَكُنَّا نَقُولُ فِيهِ وَفِي أَصْحَابِهِ نَزَلَتْ{ فَمِنْهُمْ مَنْ قَضَى نَحْبَهُ وَمِنْهُمْ مَنْ يَنْتَظِرُ }قَالَ يَزِيدُ يَعْنِي هَذِهِ الْآيَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَاسْمُ عَمِّهِ أَنَسُ بْنُ النَّضْرِ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Yazid bin Harun] telah mengkhabarkan kepada kami [Humaid Ath Thawil] dari [Anas bin Malik] bahwa pamannya absen dalam peperangan Badar, ia berkata: Aku absen dalam perang pertama Rasulullah Shallallahu 'alaihi wa Salam melawan orang-orang musyrik, bila Allah menyertakanku dalam peperangan (berikutnya) melawan kaum musyrikin, sungguh Allah akan mengetahui apa yang akan aku lakukan. Saat perang Uhud kaum muslimin kocar-kacir, maka ia berkata: Ya Allah, sesungguhnya aku membebaskan diriku padamu dari yang dibawa oleh mereka -maksudnya kaum musyrikin- dan aku memohon ampunan padamu dari yang mereka lakukan -maksudnya para sahabatnya. Ia maju lalu ia ditemui Sa'ad, Sa'ad berkata: Saudaraku, yang aku lakukan bersamamu, aku tidak mampu untuk melalukan yang ia lakukan. Ternyata ditubuhnya terdapat delapanpuluh sekian tebasan pedang, tusukan tombak dan tancapan panah. Kami mengatakan berkenaan dengannya dan para sahabatnya turun (ayat): \"Maka di antara mereka ada yang gugur. dan di antara mereka ada (pula) yang menunggu-nunggu dan mereka tidak merubah (janjinya).\" (Al Ahzaab: 23) Yazid berkata: Maksudnya ayat tersebut. Abu Isa berkata: Hadits ini hasan shahih. Nama pamannya adalah Anas bin An Nadlr."},"2967":{"ar":"حَدَّثَنَا عَبْدُ الْقُدُّوسِ بْنُ مُحَمَّدٍ الْعَطَّارُ الْبَصْرِيُّ حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ عَنْ إِسْحَقَ بْنِ يَحْيَى بْنِ طَلْحَةَ عَنْ مُوسَى بْنِ طَلْحَةَ قَالَ دَخَلْتُ عَلَى مُعَاوِيَةَ فَقَالَأَلَا أُبَشِّرُكَ فَقُلْتُ بَلَى قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ طَلْحَةُ مِمَّنْ قَضَى نَحْبَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ مُعَاوِيَةَ إِلَّا مِنْ هَذَا الْوَجْهِ وَإِنَّمَا رُوِيَ هَذَا عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِيهِ","id":"Telah menceritakan kepada kami [Abdul Quddus bin Muhammad Al Aththar] telah menceritakan kepada kami [Amru bin Ashim] dari [Ishaq bin Yahya bin Thalhah] dari [Musa bin Thalhah] berkata: Aku mengunjungi [Mu'awiyah], ia berkata: Maukah kau aku beri khabar gembira? Aku menjawab: Ya. Ia berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Thalhah termasuk orang yang gugur.\" Abu Isa berkata: Hadits ini gharib, kami hanya mengetahuinya dari hadits Mu'awiyah melalui sanad ini. hadits ini hanya diriwayatkan dari Musa bin Thalhah dari ayahnya."},"2968":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا أُمِرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَخْيِيرِ أَزْوَاجِهِ بَدَأَ بِي فَقَالَ يَا عَائِشَةُ إِنِّي ذَاكِرٌ لَكِ أَمْرًا فَلَا عَلَيْكِ أَنْ لَا تَسْتَعْجِلِي حَتَّى تَسْتَأْمِرِي أَبَوَيْكِ قَالَتْ وَقَدْ عَلِمَ أَنَّ أَبَوَايَ لَمْ يَكُونَا لِيَأْمُرَانِي بِفِرَاقِهِ قَالَتْ ثُمَّ قَالَ إِنَّ اللَّهَ تَعَالَى يَقُولُ{ يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ إِنْ كُنْتُنَّ تُرِدْنَ الْحَيَاةَ الدُّنْيَا وَزِينَتَهَا فَتَعَالَيْنَ حَتَّى بَلَغَ لِلْمُحْسِنَاتِ مِنْكُنَّ أَجْرًا عَظِيمًا }فَقُلْتُ فِي أَيِّ هَذَا أَسْتَأْمِرُ أَبَوَيَّ فَإِنِّي أُرِيدُ اللَّهَ وَرَسُولَهُ وَالدَّارَ الْآخِرَةَ وَفَعَلَ أَزْوَاجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ مَا فَعَلْتُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا أَيْضًا عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Utsman bin Umar] dari [Yunus bin Yazid] dari [Az Zuhri] dari [Abu Salamah] dari [Aisyah] radliallahu 'anhaa, berkata: Saat Rasulullah Shallallahu 'alaihi wa Salam diperintahkan untuk memilih istri-istri beliau, beliau memulai dariku, beliau berkata: Hai Aisyah, aku mengingatkan suatu hal padamu, jangan terburu-buru hingga kau meminta izin pada kedua orang tuamu. Aisyah berkata: Beliau tahu bahwa kedua orang tuaku tidak akan memerintahkanku untuk berpisah dengan beliau. Setelah itu beliau bersabda: \"Sesungguhnya Allah Ta'ala berfirman: 'Hai nabi, Katakanlah kepada isteri-isterimu: 'Jika kamu sekalian mengingini kehidupan dunia dan perhiasannya, maka marilah\" hingga firmanNya: 'Bagi siapa yang berbuat baik diantaramu pahala yang besar.\" (Al Ahzaab: 28-29) aku bertanya: Untuk apa aku meminta izin kepada kedua orang tuaku, aku menginginkan Allah, rasulNya dan negeri akhirat. Selanjutnya para istri nabi Shallallahu 'alaihi wa Salam melakukan seperti yang aku lakukan. Abu Isa berkata: Hadits ini hasan shahih. Hadits ini juga diriwayatkan dari [Az Zuhri] dari [Urwah] dari [Aisyah] Radliyallaahu 'anhaa."},"2969":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ بْنِ الْأَصْبَهَانِيِّ عَنْ يَحْيَى بْنِ عُبَيْدٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ رَبِيبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّمَا يُرِيدُ اللَّهُ لِيُذْهِبَ عَنْكُمْ الرِّجْسَ أَهْلَ الْبَيْتِ وَيُطَهِّرَكُمْ تَطْهِيرًا }فِي بَيْتِ أُمِّ سَلَمَةَ فَدَعَا فَاطِمَةَ وَحَسَنًا وَحُسَيْنًا فَجَلَّلَهُمْ بِكِسَاءٍ وَعَلِيٌّ خَلْفَ ظَهْرِهِ فَجَلَّلَهُ بِكِسَاءٍ ثُمَّ قَالَ اللَّهُمَّ هَؤُلَاءِ أَهْلُ بَيْتِي فَأَذْهِبْ عَنْهُمْ الرِّجْسَ وَطَهِّرْهُمْ تَطْهِيرًا قَالَتْ أُمُّ سَلَمَةَ وَأَنَا مَعَهُمْ يَا نَبِيَّ اللَّهِ قَالَ أَنْتِ عَلَى مَكَانِكِ وَأَنْتِ عَلَى خَيْرٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ عَطَاءٍ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Muhammad bin Sulaiman bin Al Ashbahani] dari [Yahya bin Ubaid] dari [Atho` bin Abu Rabah] dari [Umar bin Abu Salamah] anak didik nabi Shallallahu 'alaihi wa Salam, berkata: Saat ayat ini turun kepada nabi Shallallahu 'alaihi wa Salam: \"Sesungguhnya Allah bermaksud hendak menghilangkan dosa dari kamu, hai ahlul bait dan membersihkan kamu sebersih-bersihnya.\" (Al Ahzaab: 33) Rasulullah Shallallahu'alaihiwasallam berada di rumah Ummu Salamah, beliau memanggil Fathimah, Hasan dan Husain lalu mengenakan pakaian pada mereka sementara Ali berada di belakang beliau lalu beliau juga mengenakan pakaian untuknya. Setelah itu beliau berdoa: \"ALLOOHUMMA HAA'ULAAI AHLU BAITII, FA'ADZHIB 'ANHUM ARRIJSA WATOHHIRHUM TAHTHIIRON \"Ya Allah, mereka adalah ahlul baitku, maka hilangkanlah dosa dari mereka dan bersihkanlah mereka sebersih-bersihnya.\" Ummu Salamah bertanya: Aku bersama mereka nabi Allah? beliau menjawab: \"Engkau berada ditempatmu dan engkau berada di atas kebaikan.\" Abu Isa berkata: Hadits ini gharib melalui sanad ini dari hadits Atho` dari Umar bin Abu Salamah."},"2970":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَمُرُّ بِبَابِ فَاطِمَةَ سِتَّةَ أَشْهُرٍ إِذَا خَرَجَ إِلَى صَلَاةِ الْفَجْرِ يَقُولُ الصَّلَاةَ يَا أَهْلَ الْبَيْتِ{ إِنَّمَا يُرِيدُ اللَّهُ لِيُذْهِبَ عَنْكُمْ الرِّجْسَ أَهْلَ الْبَيْتِ وَيُطَهِّرَكُمْ تَطْهِيرًا }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ حَمَّادِ بْنِ سَلَمَةَ قَالَ وَفِي الْبَاب عَنْ أَبِي الْحَمْرَاءِ وَمَعْقِلِ بْنِ يَسَارٍ وَأُمِّ سَلَمَةَ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Affan bin Muslim] telah menceritakan kepada kami [Hammad bin Salamah] telah mengkhabarkan kepada kami [Ali bin Zaid] dari [Anas bin Malik], Rasulullah Shallallahu 'alaihi wa Salam melewati depan pintu Fathimah selama enam bulan. Saat hendak shalat fajar, beliau menegur: \"Shalat wahai ahlul bait, 'sesungguhnya Allah bermaksud hendak menghilangkan dosa dari kamu, hai ahlul bait dan membersihkan kamu sebersih-bersihnya.\" (Al Ahzaab: 33) Abu Isa berkata: Hadits ini hasan gharib melalui sanad ini, kami hanya mengetahuinya dari hadits Hammad bin Salamah. Abu Isa berkata: Dalam hal ini ada hadits serupa dari Abu Al Hamra`, Ma'qil bin Yasar dan Ummu Salamah."},"2971":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبَانَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَوْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا مِنْ الْوَحْيِ لَكَتَمَ هَذِهِ الْآيَةَ{ وَإِذْ تَقُولُ لِلَّذِي أَنْعَمَ اللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ }الْآيَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Aban] telah menceritakan kepada kami [Ibnu Abi Adi] dari [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] dari [Aisyah] Radliyallaahu 'anhaa, berkata: Andai nabi Shallallahu 'alaihi wa Salam menyembunyikan suatu wahyu, pastilah beliau menyembunyikan ayat ini: \"Dan (ingatlah), ketika kamu berkata kepada orang yang Allah telah melimpahkan nikmat kepadanya dan kamu (juga) Telah memberi nikmat kepadanya.\" (Al Ahzaab: 37) Abu Isa berkata: Hadits ini hasan shahih."},"2972":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَمَا كُنَّا نَدْعُو زَيْدَ بْنَ حَارِثَةَ إِلَّا زَيْدَ ابْنَ مُحَمَّدٍ حَتَّى نَزَلَ الْقُرْآنُ{ ادْعُوهُمْ لِآبَائِهِمْ هُوَ أَقْسَطُ عِنْدَ اللَّهِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari [Musa bin Uqbah] dari [Salim] dari [Ibnu Umar] berkata: Kami tidak memanggil Zaid bin Haritsah selain Zaid bin Muhammad hingga turun (ayat) al-Qur`an: \"Panggilah mereka (anak-anak angkat itu) dengan (memakai) nama bapak-bapak mereka; itulah yang lebih adil pada sisi Allah.\" (Al Ahzaab: 5) "},"2973":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ عَنْ حُصَيْنٍ عَنْ عِكْرِمَةَ عَنْ أُمِّ عُمَارَةَ الْأَنْصَارِيَّةِأَنَّهَا أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ مَا أَرَى كُلَّ شَيْءٍ إِلَّا لِلرِّجَالِ وَمَا أَرَى النِّسَاءَ يُذْكَرْنَ بِشَيْءٍ فَنَزَلَتْ هَذِهِ الْآيَةَ{ إِنَّ الْمُسْلِمِينَ وَالْمُسْلِمَاتِ وَالْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ }الْآيَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَإِنَّمَا نَعْرِفُ هَذَا الْحَدِيثَ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Muhammad bin Katsir] telah menceritakan kepada kami [Sulaiman bin Katsir] dari [Hushain] dari [Ikrimah] dari [Ummu Umarah Al Anshariyyah] ia mendatangi nabi Shallallahu 'alaihi wa Salam lalu berkata: Aku tidak mengetahui segala sesuatu melainkan diperuntukkan kaum lelaki, dan setahuku kaum wanita tidak disebut sama sekali, lalu turunlah ayat ini: \"Sesungguhnya laki-laki dan perempuan yang muslim, laki-laki dan perempuan yang mukmin.\" (Al Ahzaab: 35) Abu Isa berkata: Hadits ini hasan gharib, kami hanya mengetahui hadits ini dari sanad ini."},"2974":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةَ{ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ }فِي شَأْنِ زَيْنَبَ بِنْتِ جَحْشٍ جَاءَ زَيْدٌ يَشْكُو فَهَمَّ بِطَلَاقِهَا فَاسْتَأْمَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَاتَّقِ اللَّهَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah Adl Dlabyi] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas] berkata: Saat turun ayat ini: \"Sedang kamu menyembunyikan di dalam hatimu apa yang Allah akan menyatakannya, dan kamu takut kepada manusia.\" (Al Ahzaab: 37) berkenaan dengan Zainab binti Jahsy. Zaid datang mengadu dan berkeinginan untuk mencerainya lalu meminta izin kepada nabi Shallallahu 'alaihi wa Salam, beliau lalu bersabda: \"Tahanlah terus isterimu dan bertakwalah kepada Allah.\" (Al Ahzaab: 37) Abu Isa berkata: Hadits ini hasan shahih."},"2975":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا أَخْبَرَنَا أَبُو أُسَامَةَ عَنْ الْحَسَنِ بْنِ الْحَكَمِ النَّخَعِيِّ قَالَ حَدَّثَنِي أَبُو سَبْرَةَ النَّخَعِيُّ عَنْ فَرْوَةَ بْنِ مُسَيْكٍ الْمُرَادِيِّ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَلَا أُقَاتِلُ مَنْ أَدْبَرَ مِنْ قَوْمِي بِمَنْ أَقْبَلَ مِنْهُمْ فَأَذِنَ لِي فِي قِتَالِهِمْ وَأَمَّرَنِي فَلَمَّا خَرَجْتُ مِنْ عِنْدِهِ سَأَلَ عَنِّي مَا فَعَلَ الْغُطَيْفِيُّ فَأُخْبِرَ أَنِّي قَدْ سِرْتُ قَالَ فَأَرْسَلَ فِي أَثَرِي فَرَدَّنِي فَأَتَيْتُهُ وَهُوَ فِي نَفَرٍ مِنْ أَصْحَابِهِ فَقَالَ ادْعُ الْقَوْمَ فَمَنْ أَسْلَمَ مِنْهُمْ فَاقْبَلْ مِنْهُ وَمَنْ لَمْ يُسْلِمْ فَلَا تَعْجَلْ حَتَّى أُحْدِثَ إِلَيْكَ قَالَ وَأُنْزِلَ فِي سَبَإٍ مَا أُنْزِلَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ وَمَا سَبَأٌ أَرْضٌ أَوْ امْرَأَةٌ قَالَ لَيْسَ بِأَرْضٍ وَلَا امْرَأَةٍ وَلَكِنَّهُ رَجُلٌ وَلَدَ عَشْرَةً مِنْ الْعَرَبِ فَتَيَامَنَ مِنْهُمْ سِتَّةٌ وَتَشَاءَمَ مِنْهُمْ أَرْبَعَةٌ فَأَمَّا الَّذِينَ تَشَاءَمُوا فَلَخْمٌ وَجُذَامُ وَغَسَّانُ وَعَامِلَةُ وَأَمَّا الَّذِينَ تَيَامَنُوا فَالْأُزْدُ وَالْأَشْعَرِيُّونَ وَحِمْيَرٌ وَكِنْدَةُ وَمَذْحِجٌ وَأنْمَارٌ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ وَمَا أَنْمَارٌ قَالَ الَّذِينَ مِنْهُمْ خَثْعَمُ وَبَجِيلَةُوَرُوِيَ هَذَا عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] dan [Abdu bin Humaid] keduanya berkata: Telah mengkhabarkan kepada kami [Abu Usamah] dari [Al Hasan bin Al Hakam An Nakha'i] berkata: telah menceritakan kepadaku [Abu Sabrah An Nakha'i] dari [Farwah bin Musaik Al Muradi] berkata: Aku mendatangi nabi Shallallahu 'alaihi wa Salam lalu berkata: Wahai Rasulullah, bolehkah aku memerangi diantara yang lari dengan orang terus maju diantara mereka. Beliau mengijinkanku untuk memerangi mereka dan menunjukku sebagai pemimpin. Saat aku meninggalkan beliau, beliau bertanya mengenaiku, apa yang dilakukan Al Ghuthaifi, beliau diberitahu bahwa aku telah berangkat dimalam hari. Lalu beliau mengirim utusan untuk mencari jejakku lalu utusan itu menyuruhku kembali, aku mendatangi beliau saat bersama dengan beberapa sahabat beliau. Beliau bersabda: \"Serulah kaum(mu), yang masuk Islam terimalah dan yang tidak masuk Islam, jangan terburu-buru hingga kau diberitahu. Farwah berkata: Surat Saba' diturunkan lalu seseorang berkata: Wahai Rasulullah, apa itu Saba', negerikah atau seorang wanitakah? Beliau menjawab: \"Bukan negeri atau seorang wanita, tapi ia adalah seorang lelaki yang melahirkan sepuluh anak berbangsa arab. Enam diantara mereka menuju ke arah kanan (Yaman) sedangkan keempat lainnya menuju ke arah kiri. Mereka yang berjalan ke arah kiri adalah Lakhm, Judzam, Ghassan dan Amilah sedangkan yang mengharap berkah adalah Azd, Asy'ari, Himyar, Kindah, Madzhij dan Anmar.\" Seseorang bertanya: Siapa itu Anmar? Beliau menjawab: \"Orang-orang yang diantaranya Khats'am dan Bajilah.\" Ini diriwayatkan dari Ibnu Abbas dari nabi Shallallahu 'alaihi wa Salam. Abu Isa berkata: Hadits ini hasan gharib."},"2976":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَضَى اللَّهُ فِي السَّمَاءِ أَمْرًا ضَرَبَتْ الْمَلَائِكَةُ بِأَجْنِحَتِهَا خُضْعَانًا لِقَوْلِهِ كَأَنَّهَا سِلْسِلَةٌ عَلَى صَفْوَانٍ فَإِذَا{ فُزِّعَ عَنْ قُلُوبِهِمْ قَالُوا مَاذَا قَالَ رَبُّكُمْ قَالُوا الْحَقَّ وَهُوَ الْعَلِيُّ الْكَبِيرُ }قَالَ وَالشَّيَاطِينُ بَعْضُهُمْ فَوْقَ بَعْضٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Amru bin Dinar] dari [Ikrimah] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Bila Allah telah menetapkan suatu hal di langit, para malaikat mengepak-ngepakkan sayap karena tunduk pada firman-Nya seperti rantai di atas batu besar halus. 'Sehingga apabila telah dihilangkan ketakutan dari hati mereka, mereka berkata: 'Apakah yang telah difirmankan oleh Rabb-mu? mereka menjawab: '(Perkataan) yang benar, ' dan Dia-lah yang Maha Tinggi lagi Maha Besar.\" (Saba`: 23) Beliau bersabda: \"Dan setan, sebagian berada diatas bagian lain.\" Abu Isa berkata: Hadits ini hasan shahih."},"2977":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ ابْنِ عَبَّاسٍ قَالَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ فِي نَفَرٍ مِنْ أَصْحَابِهِ إِذْ رُمِيَ بِنَجْمٍ فَاسْتَنَارَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا كُنْتُمْ تَقُولُونَ لِمِثْلِ هَذَا فِي الْجَاهِلِيَّةِ إِذَا رَأَيْتُمُوهُ قَالُوا كُنَّا نَقُولُ يَمُوتُ عَظِيمٌ أَوْ يُولَدُ عَظِيمٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّهُ لَا يُرْمَى بِهِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنَّ رَبَّنَا عَزَّ وَجَلَّ إِذَا قَضَى أَمْرًا سَبَّحَ لَهُ حَمَلَةُ الْعَرْشِ ثُمَّ سَبَّحَ أَهْلُ السَّمَاءِ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ حَتَّى يَبْلُغَ التَّسْبِيحُ إِلَى هَذِهِ السَّمَاءِ ثُمَّ سَأَلَ أَهْلُ السَّمَاءِ السَّادِسَةِ أَهْلَ السَّمَاءِ السَّابِعَةِ مَاذَا قَالَ رَبُّكُمْ قَالَ فَيُخْبِرُونَهُمْ ثُمَّ يَسْتَخْبِرُ أَهْلُ كُلِّ سَمَاءٍ حَتَّى يَبْلُغَ الْخَبَرُ أَهْلَ السَّمَاءِ الدُّنْيَا وَتَخْتَطِفُ الشَّيَاطِينُ السَّمْعَ فَيُرْمَوْنَ فَيَقْذِفُونَهُ إِلَى أَوْلِيَائِهِمْ فَمَا جَاءُوا بِهِ عَلَى وَجْهِهِ فَهُوَ حَقٌّ وَلَكِنَّهُمْ يُحَرِّفُونَهُ وَيَزِيدُونَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ الْحُسَيْنِ عَنْ ابْنِ عَبَّاسٍ عَنْ رِجَالٍ مِنْ الْأَنْصَارِ قَالُوا كُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ بِمَعْنَاهُ حَدَّثَنَا بِذَلِكَ الْحُسَيْنُ بْنُ حُرَيْثٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] telah menceritakan kepada kami [Abdul A'laa] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ali bin Husain] dari [Ibnu Abbas] berkata: Saat Rasulullah Shallallahu 'alaihi wa Salam duduk bersama beberapa sahabat beliau, ada bintang dilemparkan lalu bersinar, Rasulullah Shallallahu 'alaihi wa Salam bertanya: \"Apa komentar kalian untuk (hal) seperti ini dimasa jahiliyah saat kalian melihatnya?\" mereka menjawab: \"Dulu kami mengatakan ada orang besar meninggal atau calon orang besar lahir. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sebenarnya ia tidak dilemparkan karena kematian seseorang atau kehidupan seseorang, tapi Rabb kita 'azza wajalla bila memutuskan suatu hal, para malaikat pemikul 'arsy bertasbih lalu penghuni langit setelah mereka bertasbih lalu para penghuni langit setelah mereka bertasbih hingga tasbih sampai ke langit ini, penghuni langit keenam bertanya kepada penghuni langit ketujuh: Apa yang difirmankan Rabb kalian? Lalu mereka memberitahukannya, setelah itu penghuni setiap langit bertanya hingga kabar sampai ke penghuni langit terendah. Setan-setan mencuri dengar lalu mereka dilempari, lantas mereka menyampaikannya kepada wali-wali mereka. Yang mereka bawa itu benar, tapi mereka merubah dan menambah-nambahi.\" Abu Isa berkata: Hadits ini hasan shahi. Hadits ini juga diriwayatkan dari Az Zuhri dari Ali bin Al Husain dari Ibnu Abbas dari [beberapa orang Anshar], mereka berkata: Kami pernah berada di dekat nabi Shallallahu 'alaihi wa Salam lalu Ibnu Abbas menyebut hadits serupa dengan maknanya. Telah menceritakan kepada kami seperti itu [Al Husain bin Huraits] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Auza'i]."},"2978":{"ar":"حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْوَلِيدِ بْنِ الْعَيْزَارِ أَنَّهُ سَمِعَ رَجُلًا مِنْ ثَقِيفٍ يُحَدِّثُ عَنْ رَجُلٍ مِنْ كِنَانَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ فِي هَذِهِ الْآيَةِ{ ثُمَّ أَوْرَثْنَا الْكِتَابَ الَّذِينَ اصْطَفَيْنَا مِنْ عِبَادِنَا فَمِنْهُمْ ظَالِمٌ لِنَفْسِهِ وَمِنْهُمْ مُقْتَصِدٌ وَمِنْهُمْ سَابِقٌ بِالْخَيْرَاتِ }قَالَ هَؤُلَاءِ كُلُّهُمْ بِمَنْزِلَةٍ وَاحِدَةٍ وَكُلُّهُمْ فِي الْجَنَّةِقَالَ هَذَا حَدِيثٌ غَرِيبٌ حَسَنٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abu Musa Muhammad bin Al Mutsanna] dan [Muhammad bin Basyar] keduanya berkata: Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Al Walid bin Al Aizar] ia mendengar [seseorang dari Tsaqif] menceritakan dari [seseorang dari Kinanah] dari [Abu Sa'id Al Khudri] dari nabi Shallallahu 'alaihi wa Salam, beliau bersabda tentang ayat ini: \"Kemudian Kitab itu kami wariskan kepada orang-orang yang kami pilih di antara hamba-hamba kami, lalu di antara mereka ada yang menganiaya diri mereka sendiri dan di antara mereka ada yang pertengahan dan diantara mereka ada (pula) yang lebih dahulu berbuat kebaikan.\" (Faathir: 32) beliau bersabda: \"Mereka semua tingkatannya sama, mereka semua di surga.\" Abu Isa berkata: Hadits ini hasan gharib, kami hanya mengetahuinya dari sanad ini."},"2979":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ وَزِيرٍ الْوَاسِطِيُّ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ الْأَزْرَقُ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ أَبِي سُفْيَانَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَتْ بَنُو سَلَمَةَ فِي نَاحِيَةِ الْمَدِينَةِ فَأَرَادُوا النُّقْلَةَ إِلَى قُرْبِ الْمَسْجِدِ فَنَزَلَتْ هَذِهِ الْآيَةَ{ إِنَّا نَحْنُ نُحْيِ الْمَوْتَى وَنَكْتُبُ مَا قَدَّمُوا وَآثَارَهُمْ }فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ آثَارَكُمْ تُكْتَبُ فَلَا تَنْتَقِلُواقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ الثَّوْرِيِّ وَأَبُو سُفْيَانَ هُوَ طَرِيفٌ السَّعْدِيُّ","id":"Telah menceritakan kepada kami [Muhammad bin Wazir Al Wasithi] telah menceritakan kepada kami [Ishaq bin Yusuf Al Azraq] dari [Sufyan Ats Tsauri] dari [Abu Sufyan] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] berkata: Bani Salamah ada di tepi Madinah, mereka ingin pindah di dekat masjid lalu ayat ini turun: \"Sesungguhnya Kami menghidupkan orang-orang mati dan kami menuliskan apa yang telah mereka kerjakan dan bekas-bekas yang mereka tinggalkan.\" (Yaasiin: 12) Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Jejak-jejak (kaki) kalian dicatat, karena itu jangan pindah.\" Abu Isa berkata: Hadits ini hasan gharib dari hadits Ats Tsauri. Abu Sufyan adalah Tharif As Sa'di."},"2980":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّ قَالَقَالَ دَخَلْتُ الْمَسْجِدَ حِينَ غَابَتْ الشَّمْسُ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَدْرِي يَا أَبَا ذَرٍّ أَيْنَ تَذْهَبُ هَذِهِ قَالَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّهَا تَذْهَبُ فَتَسْتَأْذِنُ فِي السُّجُودِ فَيُؤْذَنُ لَهَا وَكَأَنَّهَا قَدْ قِيلَ لَهَا اطْلُعِي مِنْ حَيْثُ جِئْتِ فَتَطْلُعُ مِنْ مَغْرِبِهَا قَالَ ثُمَّ قَرَأَ وَذَلِكَ مُسْتَقَرٌّ لَهَا قَالَ وَذَلِكَ فِي قِرَاءَةِ عَبْدِ اللَّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim At Taimi] dari [ayahnya] dari [Abu Dzarr] berkata: Aku masuk masjid saat matahari terbenam sementara nabi Shallallahu 'alaihi wa Salam tengah duduk lalu beliau bertanya: \"Tahukah kamu wahai Abu Dzarr, kemana matahari pergi?\" ia berkata: Aku menjawab: Allah dan rasulNya lebih tahu. Beliau bersabda: \"Sesungguhnya ia pergi lalu meminta ijin untuk sujud, ia diijinkan dan seolah-olah dikatakan padanya: Terbitlah dari tempat kau datang. Lalu ia terbit dari tempat terbenamnya.\" Beliau membaca: \"Dan itulah tempat menetapnya.\" Itu terdapat dalam bacaan Abdullah. Abu Isa berkata: Hadits ini hasan shahih."},"2981":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ حَدَّثَنَا لَيْثُ بْنُ أَبِي سُلَيْمٍ عَنْ بِشْرٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ دَاعٍ دَعَا إِلَى شَيْءٍ إِلَّا كَانَ مَوْقُوفًا يَوْمَ الْقِيَامَةِ لَازِمًا بِهِ لَا يُفَارِقُهُ وَإِنْ دَعَا رَجُلٌ رَجُلًا ثُمَّ قَرَأَ قَوْلَ اللَّهِ عَزَّ وَجَلَّ{ وَقِفُوهُمْ إِنَّهُمْ مَسْئُولُونَ مَا لَكُمْ لَا تَنَاصَرُونَ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah Al Dlabyi] telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] telah menceritakan kepada kami [Laits bin Abu Sulaim] dari [Bisyr] dari [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidaklah seseorang mengajak kepada sesuatu melainkan pada hari kiamat dia diberhentikan pada suatu tempat yang selalu ia diami dan tidak ia tinggalkan. Walaupun ia hanya mengajak kepada satu orang. Kemudian beliau membacakan firman Allah 'azza wajalla: \"Dan tahanlah mereka (di tempat perhentian) karena Sesungguhnya mereka akan ditanya.\" (Ash Shaaffaat: 24) Abu Isa berkata: Hadits ini gharib."},"2982":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ زُهَيْرِ بْنِ مُحَمَّدٍ عَنْ رَجُلٍ عَنْ أَبِي الْعَالِيَةِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِ اللَّهِ تَعَالَى{ وَأَرْسَلْنَاهُ إِلَى مِائَةِ أَلْفٍ أَوْ يَزِيدُونَ }قَالَ عِشْرُونَ أَلْفًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengkhabarkan kepada kami [Al Walid bin Muslim] dari [Zuhair bin Muhammad] dari [seseorang] dari [Abu Al Aliyah] dari [Ubai bin Ka'ab] berkata: Aku bertanya kepada Rasulullah Shallallahu 'alaihi wa Salam tentang firman Allah Ta'ala: \"Dan kami utus dia kepada seratus ribu orang atau lebih.\" (Ash Shaaffaat: 147) beliau bersabda: \"Duapuluh ribu.\" Abu Isa berkata: Hadits ini gharib."},"2983":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدٍ ابْنُ عَثْمَةَ حَدَّثَنَا سَعِيدُ بْنُ بَشِيرٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِ اللَّهِ{ وَجَعَلْنَا ذُرِّيَّتَهُ هُمْ الْبَاقِينَ }قَالَ حَامٌ وَسَامٌ وَيَافِثُقَالَ أَبُو عِيسَى يُقَالُ يَافِتُ وَيَافِثُ بِالتَّاءِ وَالثَّاءِ وَيُقَالُ يَفِثُ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ سَعِيدِ بْنِ بَشِيرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Khalid bin Atsmah] telah menceritakan kepada kami [Sa'id bin Basyir] dari [Qatadah] dari [Al Hasan] dari [Samurah] dari nabi Shallallahu 'alaihi wa Salam tentang firman Allah: \"Dan kami jadikan anak cucunya orang-orang yang melanjutkan keturunan.\" (Ash Shaaffaat: 77) beliau bersabda: \"Ham, Sam dan Yafits.\" Abu Isa berkata: Dikatakan: Yaafit dan Yaafits, juga dikatakan: Yafits. Hadits ini hasan gharib, kami hanya mengetahuinya dari hadits Sa'id bin Basyir."},"2984":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُعَاذٍ الْعَقَدِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَامٌ أَبُو الْعَرَبِ وَحَامٌ أَبُو الْحَبَشِ وَيَافِثُ أَبُو الرُّومِ","id":"Telah menceritakan kepada kami [Bisyr bin Mu'adz Al Aqadi] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Sa'id bin Abu Urubah] dari [Qatadah] dari [Al Hasan] dari [Samurah] dari nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Sam bapak bangsa arab, Ham bapak bangsa Habasy (Etiopia, Afrika) dan Yafits bapak bangsa Romawi (Eropa).\""},"2985":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ وَعَبْدُ بْنُ حُمَيْدٍ الْمَعْنَى وَاحِدٌ قَالَا حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ يَحْيَى قَالَ عَبْدٌ هُوَ ابْنُ عَبَّادٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَمَرِضَ أَبُو طَالِبٍ فَجَاءَتْهُ قُرَيْشٌ وَجَاءَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَ أَبِي طَالِبٍ مَجْلِسُ رَجُلٍ فَقَامَ أَبُو جَهْلٍ كَيْ يَمْنَعَهُ وَشَكَوْهُ إِلَى أَبِي طَالِبٍ فَقَالَ يَا ابْنَ أَخِي مَا تُرِيدُ مِنْ قَوْمِكَ قَالَ إِنِّي أُرِيدُ مِنْهُمْ كَلِمَةً وَاحِدَةً تَدِينُ لَهُمْ بِهَا الْعَرَبُ وَتُؤَدِّي إِلَيْهِمْ الْعَجَمُ الْجِزْيَةَ قَالَ كَلِمَةً وَاحِدَةً قَالَ كَلِمَةً وَاحِدَةً قَالَ يَا عَمِّ قُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَقَالُوا إِلَهًا وَاحِدًا مَا سَمِعْنَا بِهَذَا فِي الْمِلَّةِ الْآخِرَةِ إِنْ هَذَا إِلَّا اخْتِلَاقٌ قَالَ فَنَزَلَ فِيهِمْ الْقُرْآنُ{ ص وَالْقُرْآنِ ذِي الذِّكْرِ بَلْ الَّذِينَ كَفَرُوا فِي عِزَّةٍ وَشِقَاقٍ إِلَى قَوْلِهِ مَا سَمِعْنَا بِهَذَا فِي الْمِلَّةِ الْآخِرَةِ إِنْ هَذَا إِلَّا اخْتِلَاقٌ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ نَحْوَ هَذَا الْحَدِيثِ و قَالَ يَحْيَى بْنُ عِمَارَةَ حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ نَحْوَهُ عَنْ الْأَعْمَشِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] dan [Abdu bin Humaid], maknanya sama, keduanya berkata: telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Yahya], berkata Abdu yaitu Ibnu Abbad, dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata: Abu Thalib sakit lalu orang-orang Quraisy mendatanginya dan nabi Shallallahu 'alaihi wa Salam juga mendatanginya. Didekat Abu Thalib ada tempat duduk seseorang, lalu Abu Jahal berdiri agar menghalangi beliau, mereka melaporkannya kepada Abu Thalib, Abu Thalib berkata: \"Wahai keponakanku, kau ada perlu dengan kaummu? Beliau menjawab: Sesungguhnya aku menginginkan satu kalimat mereka yang dijadikan agama oleh bangsa arab, dan orang ajam (non arab) akan membayar jizyah kepada mereka.\" Abu Thalib bertanya: Satu kalimat? Beliau menjawab: \"Satu kalimat.\" Beliau bersabda: \"Wahai paman, ucapkan: LAA ILAAHA ILLALLAAH, \" lalu mereka berkata: Tuhan yang Esa?, \"Kami tidak pernah mendengar hal Ini dalam agama yang terakhir, Ini (mengesakan Allah), tidak lain hanyalah (dusta) yang diada-adakan.\" (Shaad: 7) Ibnu Abbas berkata: Berkenaan dengan mereka, turunlah ayat: \"Shaad, demi Al Qur`an yang mempunyai keagungan. Sebenarnya orang-orang kafir itu (berada) dalam kesombongan dan permusuhan yang sengit.\" Hingga firman-Nya: \"Kami tidak pernah mendengar hal Ini dalam agama yang terakhir; Ini (mengesakan Allah), tidak lain hanyalah (dusta) yang diada-adakan.\" (Shaad: 1-7) Abu Isa berkata: Hadits ini hasan shahih. Yahya bin Sa'id meriwayatkan dari Sufyan dari Al A'masy seperti hadits ini. Yahya bin Imarah berkata: Telah menceritakan kepada kami [Bundar] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] sepertinya dari [Al A'masy]."},"2986":{"ar":"حَدَّثَنَا سَلَمَةُ بْنُ شَبِيبٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَانِي اللَّيْلَةَ رَبِّي تَبَارَكَ وَتَعَالَى فِي أَحْسَنِ صُورَةٍ قَالَ أَحْسَبُهُ قَالَ فِي الْمَنَامِ فَقَالَ يَا مُحَمَّدُ هَلْ تَدْرِي فِيمَ يَخْتَصِمُ الْمَلَأُ الْأَعْلَى قَالَ قُلْتُ لَا قَالَ فَوَضَعَ يَدَهُ بَيْنَ كَتِفَيَّ حَتَّى وَجَدْتُ بَرْدَهَا بَيْنَ ثَدْيَيَّ أَوْ قَالَ فِي نَحْرِي فَعَلِمْتُ مَا فِي السَّمَاوَاتِ وَمَا فِي الْأَرْضِ قَالَ يَا مُحَمَّدُ هَلْ تَدْرِي فِيمَ يَخْتَصِمُ الْمَلَأُ الْأَعْلَى قُلْتُ نَعَمْ قَالَ فِي الْكَفَّارَاتِ وَالْكَفَّارَاتُ الْمُكْثُ فِي الْمَسَاجِدِ بَعْدَ الصَّلَوَاتِ وَالْمَشْيُ عَلَى الْأَقْدَامِ إِلَى الْجَمَاعَاتِ وَإِسْبَاغُ الْوُضُوءِ فِي الْمَكَارِهِ وَمَنْ فَعَلَ ذَلِكَ عَاشَ بِخَيْرٍ وَمَاتَ بِخَيْرٍ وَكَانَ مِنْ خَطِيئَتِهِ كَيَوْمِ وَلَدَتْهُ أُمُّهُ وَقَالَ يَا مُحَمَّدُ إِذَا صَلَّيْتَ فَقُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ فِعْلَ الْخَيْرَاتِ وَتَرْكَ الْمُنْكَرَاتِ وَحُبَّ الْمَسَاكِينِ وَإِذَا أَرَدْتَ بِعِبَادِكَ فِتْنَةً فَاقْبِضْنِي إِلَيْكَ غَيْرَ مَفْتُونٍ قَالَ وَالدَّرَجَاتُ إِفْشَاءُ السَّلَامِ وَإِطْعَامُ الطَّعَامِ وَالصَّلَاةُ بِاللَّيْلِ وَالنَّاسُ نِيَامٌقَالَ أَبُو عِيسَى وَقَدْ ذَكَرُوا بَيْنَ أَبِي قِلَابَةَ وَبَيْنَ ابْنِ عَبَّاسٍ فِي هَذَا الْحَدِيثِ رَجُلًا وَقَدْ رَوَاهُ قَتَادَةُ عَنْ أَبِي قِلَابَةَ عَنْ خَالِدِ بْنِ اللَّجْلَاجِ عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Salamah bin Syabib] dan [Abdu bin Humaid] keduanya berkata: Telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Ayyub] dari [Abu Qilabah] dari [Ibnu Abbas] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Rabbku Tabaraka wa Ta'ala mendatangiku tadi malam dalam wujud yang paling indah -Ibnu Abbas berkata: Menurutku beliau bersabda: Dalam mimpi- lalu berfirman: 'Hai Muhammad, tahukah kamu apa yang diperdebatkan malaikat tertinggi.\" Beliau bersabda: \"Aku menjawab: \"Tidak. lalu Ia meletakkan tanganNya di atas pundakku hingga aku merasakan dinginnya diantara dadaku -atau beliau bersabda: dileherku- lalu aku mengetahui yang ada dilangit dan dibumi. Ia bertanya: 'hai Muhammad, tahukah kamu apa yang diperdebatkan malaikat tertinggi? ' Aku menjawab: Ya, tentang penebus (dosa) dan penebus (dosa) adalah berdiam diri di masjid setelah shalat, berjalan dengan kaki menuju (shalat) jamaah, menyempurnakan wudhu pada saat tidak disukai. Barangsiapa hidup seperti itu, ia hidup dengan baik, mati dalam kebaikan dan ia (terbebas) dari kesalahannya seperti saat dilahirkan ibunya. Ia bertanya: 'Hai Muhammad, bila kau berdoa, ucapkan: ALLAHUMMA INNI AS`ALUKA FI'LAL KHAIRAAT WA TARKAL MUNKARAAT WA HUBBAL MASAAKIIN WA IDZA ARADTA BI IBAADIKA FITNATAN FAQBIDLNI ILAKA GHARA MAFTUNN.' (Ya Allah, sesungguhnya aku meminta-Mu berbuat kebaikan, meninggalkan kemungkaran, mencintai orang-orang miskin dan bila Engkau menghendaki suatu fitnah pada hamba-hambaMu, wafatkan aku kepadaMu dalam keadaan tidak terkena fitnah) dan beliau bersabda; 'Dan ketinggian derajat diperoleh dengan cara menyebarkan salam, memberi makan, dan shalat malam ketika orang-orang tidur.\" Abu Isa berkata: Mereka menyebut [seseorang] dalam hadits ini antara [Abu Qilabah] dan [Ibnu Abbas]. Dan [Qatadah] meriwayatkan hadits ini dari [Abu Qilabah] dari [Khalid bin Al Lajlaj] dari [Ibnu Abbas]."},"2987":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي قِلَابَةَ عَنْ خَالِدِ بْنِ اللَّجْلَاجِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَانِي رَبِّي فِي أَحْسَنِ صُورَةٍ فَقَالَ يَا مُحَمَّدُ قُلْتُ لَبَّيْكَ رَبِّ وَسَعْدَيْكَ قَالَ فِيمَ يَخْتَصِمُ الْمَلَأُ الْأَعْلَى قُلْتُ رَبِّ لَا أَدْرِي فَوَضَعَ يَدَهُ بَيْنَ كَتِفَيَّ فَوَجَدْتُ بَرْدَهَا بَيْنَ ثَدْيَيَّ فَعَلِمْتُ مَا بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ فَقَالَ يَا مُحَمَّدُ فَقُلْتُ لَبَّيْكَ رَبِّ وَسَعْدَيْكَ قَالَ فِيمَ يَخْتَصِمُ الْمَلَأُ الْأَعْلَى قُلْتُ فِي الدَّرَجَاتِ وَالْكَفَّارَاتِ وَفِي نَقْلِ الْأَقْدَامِ إِلَى الْجَمَاعَاتِ وَإِسْبَاغِ الْوُضُوءِ فِي الْمَكْرُوهَاتِ وَانْتِظَارِ الصَّلَاةِ بَعْدَ الصَّلَاةِ وَمَنْ يُحَافِظْ عَلَيْهِنَّ عَاشَ بِخَيْرٍ وَمَاتَ بِخَيْرٍ وَكَانَ مِنْ ذُنُوبِهِ كَيَوْمِ وَلَدَتْهُ أُمُّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ قَالَ وَفِي الْبَاب عَنْ مُعَاذِ بْنِ جَبَلٍ وَعَبْدِ الرَّحْمَنِ بْنِ عَائِشٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ مُعَاذِ بْنِ جَبَلٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِطُولِهِ وَقَالَ إِنِّي نَعَسْتُ فَاسْتَثْقَلْتُ نَوْمًا فَرَأَيْتُ رَبِّي فِي أَحْسَنِ صُورَةٍ فَقَالَ فِيمَ يَخْتَصِمُ الْمَلَأُ الْأَعْلَى","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [ayahku] dari [Qatadah] dari [Abu Qilabah] dari [Khalid bin Al Lajlaj] dari [Ibnu Abbas] bahwa nabi Shallallahu 'alaihi wa Salam bersabda: \"Rabbiku mendatangiku dalam wujud yang paling indah lalu berfirman: 'Hai Muhammad, ' aku menjawab: Baik, Rabb. Ia bertanya: 'Tahukah kamu apa yang diperdebatkan malaikat tertinggi? ' Beliau menjawab: Rabb aku tidak tahu.' Lalu Ia meletakkan tanganNya di atas pundakku hingga aku merasakan dinginnya diantara dadaku lalu aku mengetahui yang ada ditimur dan dibarat. Ia bertanya: 'Hai Muhammad, ' aku menjawab: Baik, Rabb. Ia bertanya: 'Tahukah kamu apa yang diperdebatkan malaikat tertinggi? ' Aku menjawab: Tentang ketinggian derajat, penebus (dosa), melangkahkan kaki menuju (shalat) jamaah, menyempurnakan wudhu pada saat tidak disukai, menunggu shalat setelah shalat, barangsiapa hidup seperti itu, ia hidup dengan baik, mati dalam kebaikan dan ia (terbebas) dari kesalahannya seperti saat dilahirkan ibunya.\" Abu Isa berkata: Hadits ini hasan gharib dari sanad ini. Dalam hal ini ada hadits serupa dari Mu'adz bin Jabal dan Abdurrahman bin A`isy dari nabi Shallallahu 'alaihi wa Salam. Hadits ini juga diriwayatkan dari Mu'adz bin Jabal dari nabi Shallallahu 'alaihi wa Salam secara lengkap, beliau bersabda: \"Aku mengantuk lalu tertidur, aku melihat Rabbku dalam wujud yang paling indah kemudian bertanya, 'Apa yang diperdebatkan malaikat tertinggi?\" "},"2988":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هَانِئٍ أَبُو هَانِئٍ الْيَشْكُرِيُّ حَدَّثَنَا جَهْضَمُ بْنُ عَبْدِ اللَّهِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ زَيْدِ بْنِ سَلَّامٍ عَنْ أَبِي سَلَّامٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَايِشٍ الْحَضْرَمِيِّ أَنَّهُ حَدَّثَهُ عَنْ مَالِكِ بْنِ يَخَامِرَ السَّكْسَكِيِّ عَنْ مُعَاذِ بْنِ جَبَلٍ رَضِيَ اللَّهُ عَنْهُ قَالَاحْتُبِسَ عَنَّا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ غَدَاةٍ عَنْ صَلَاةِ الصُّبْحِ حَتَّى كِدْنَا نَتَرَاءَى عَيْنَ الشَّمْسِ فَخَرَجَ سَرِيعًا فَثُوِّبَ بِالصَّلَاةِ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَجَوَّزَ فِي صَلَاتِهِ فَلَمَّا سَلَّمَ دَعَا بِصَوْتِهِ فَقَالَ لَنَا عَلَى مَصَافِّكُمْ كَمَا أَنْتُمْ ثُمَّ انْفَتَلَ إِلَيْنَا ثُمَّ قَالَ أَمَا إِنِّي سَأُحَدِّثُكُمْ مَا حَبَسَنِي عَنْكُمْ الْغَدَاةَ أَنِّي قُمْتُ مِنْ اللَّيْلِ فَتَوَضَّأْتُ وَصَلَّيْتُ مَا قُدِّرَ لِي فَنَعَسْتُ فِي صَلَاتِي فَاسْتَثْقَلْتُ فَإِذَا أَنَا بِرَبِّي تَبَارَكَ وَتَعَالَى فِي أَحْسَنِ صُورَةٍ فَقَالَ يَا مُحَمَّدُ قُلْتُ لَبَّيْكَ رَبِّ قَالَ فِيمَ يَخْتَصِمُ الْمَلَأُ الْأَعْلَى قُلْتُ لَا أَدْرِي رَبِّ قَالَهَا ثَلَاثًا قَالَ فَرَأَيْتُهُ وَضَعَ كَفَّهُ بَيْنَ كَتِفَيَّ حَتَّى وَجَدْتُ بَرْدَ أَنَامِلِهِ بَيْنَ ثَدْيَيَّ فَتَجَلَّى لِي كُلُّ شَيْءٍ وَعَرَفْتُ فَقَالَ يَا مُحَمَّدُ قُلْتُ لَبَّيْكَ رَبِّ قَالَ فِيمَ يَخْتَصِمُ الْمَلَأُ الْأَعْلَى قُلْتُ فِي الْكَفَّارَاتِ قَالَ مَا هُنَّ قُلْتُ مَشْيُ الْأَقْدَامِ إِلَى الْجَمَاعَاتِ وَالْجُلُوسُ فِي الْمَسَاجِدِ بَعْدَ الصَّلَوَاتِ وَإِسْبَاغُ الْوُضُوءِ فِي الْمَكْرُوهَاتِ قَالَ ثُمَّ فِيمَ قُلْتُ إِطْعَامُ الطَّعَامِ وَلِينُ الْكَلَامِ وَالصَّلَاةُ بِاللَّيْلِ وَالنَّاسُ نِيَامٌ قَالَ سَلْ قُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ فِعْلَ الْخَيْرَاتِ وَتَرْكَ الْمُنْكَرَاتِ وَحُبَّ الْمَسَاكِينِ وَأَنْ تَغْفِرَ لِي وَتَرْحَمَنِي وَإِذَا أَرَدْتَ فِتْنَةَ قَوْمٍ فَتَوَفَّنِي غَيْرَ مَفْتُونٍ أَسْأَلُكَ حُبَّكَ وَحُبَّ مَنْ يُحِبُّكَ وَحُبَّ عَمَلٍ يُقَرِّبُ إِلَى حُبِّكَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا حَقٌّ فَادْرُسُوهَا ثُمَّ تَعَلَّمُوهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ سَأَلْتُ مُحَمَّدَ بْنَ إِسْمَعِيلَ عَنْ هَذَا الْحَدِيثِ فَقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ و قَالَ هَذَا أَصَحُّ مِنْ حَدِيثِ الْوَلِيدِ بْنِ مُسْلِمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ اللَّجْلَاجِ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَايِشٍ الْحَضْرَمِيُّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ وَهَذَا غَيْرُ مَحْفُوظٍ هَكَذَا ذَكَرَ الْوَلِيدُ فِي حَدِيثِهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَايِشٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَى بِشْرُ بْنُ بَكْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ هَذَا الْحَدِيثَ بِهَذَا الْإِسْنَادِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَايِشٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَذَا أَصَحُّ وَعَبْدُ الرَّحْمَنِ بْنُ عَايِشٍ لَمْ يَسْمَعْ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Mu'adz bin Hani` Al Yasykuri] telah menceritakan kepada kami [Jahdlam bin Abdullah] dari [Yahya bin Abu Katsir] dari [Zaid bin Sallam] dari [Abu Sallam] dari [Abdurrahman bin Ayisy Al Hadlrami] bahwa ia telah menceritakan kepadanya dari [Malik bi Yakhamir As Saksaki] dari [Mu'adz bin Jabal] radliallahu 'anhu berkata: \"Pada suatu pagi, Rasulullah Shallallahu 'alaihi wa Salam tertahan dari kami untuk shalat shubuh hingga hampir saja kami melihat matahari, beliau keluar dengan cepat lalu shalat diiqamati, Rasulullah Shallallahu 'alaihi wa Salam shalat dan mempercepatnya, saat salam beliau memanggil dengan suara keras, beliau bersabda pada kami: \"Tetaplah di shaf-shaf kalian seperti ini.\" Setelah itu beliau meninggalkan kami lalu bersabda \"Ingat, sesungguhnya aku akan memberitahukan kepada kalian apa yang menahanku dari kalian pagi ini. Di sebagian malam aku bangun lalu wudhu dan shalat semampuku, saat shalat aku mengantuk hingga tertidur. Tiba-tiba aku berada dihadapan Rabbku Tabaraka wa Ta'ala dalam wujud yang paling indah lalu bertanya: Hai Muhammad, ' aku menjawab: Baik, Rabb. Ia bertanya: 'Tahukah kamu apa yang diperdebatkan malaikat tertinggi? ' Beliau menjawab: Rabb aku tidak tahu.' Ia mengucapkan tiga kali, aku melihatNya lalu Ia meletakkan tanganNya di atas pundakku hingga aku merasakan dinginnya ujung-ujung jariNya diantara dadaku lalu segala sesuatu terlihat jelas olehku dan aku mengetahui. Ia bertanya: 'Hai Muhammad, ' aku menjawab: Baik, Rabb. Ia bertanya: 'Tahukah kamu apa yang diperdebatkan malaikat tertinggi? ' Aku menjawab: Tentang Penebus (dosa). Ia bertanya: Apa itu? Aku menjawab: Melangkahkan kaki menuju (shalat) jamaah, duduk dimasjid setelah shalat, menyempurnakan wudhu pada saat tidak disukai, ' lalu Ia berfirman seperti yang aku ucapkan: Memberi makan, melunakkan kata-kata, shalat di malam hari saat orang-orang tidur.' Ia berfirman: Mintalah, ucapkan: ALLAHUMMA INNI AS`ALUKA FI'LAL KHAIRAAT WA TARKAL MUNKARAAT WA HUBBAL MASAAKIIN WA AN TAGHFIRALII WA TARHAMNII WA IDZA ARADTA BI IBAADIKA FITNATAN FAQBIDLNI ILAKA GHARA MAFTUNN AS`ALUK HUBBAKJA WA HUBBA MAN YUHIBBUKA WA HUBBA AMALIN YUQARRIBU ILA HUBBIKA.' (Ya Allah, sesungguhnya aku meminta-Mu berbuat kebaikan, meninggalkan kemungkaran, mencintai orang-orang miskin, ampunilah aku dan rahmatilah aku, bila Engkau menghendaki suatu fitnah pada hamba-hambaMu, wafatkan aku kepadaMu dalam keadaan tidak terkena fitnah, aku mengharap cintaMu, cintanya orang yang mencintaiMu, cinta pada amalan yang mendekatkanku pada cintaMu). Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya itu benar, pelajarilah, \" mereka mempelajarinya. Abu Isa berkata: Hadits ini hasan shahih. Aku bertanya kepada Muhammad bin Isma'il tentang hadits ini, ia menjawab: Hadits ini hasan shahih. Abu Isa berkata: Ini lebih shahih dari hadits Al Walid ibn Muslim dari Abdurrahman bin Yazid bin Jabir. Abu Isa berkata: Telah menceritakan kepada kami [Khalid bin Al Lajlaj] telah menceritakan kepadaku [Abdurrahman bin Ayisy Al Hadlrami] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam, ia menyebut hadits ini dan hadits ini tidak terjaga. Seperti itu Al Walid menyebut dalam haditsnya dari Abdurrahman bin Ayisy, ia berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam. [Bisyr bin Bakr] meriwayatkan dari [Abdurrahman bin Yazid bin Jabir] hadits ini dengan sanad ini dari [Abdurrahman bin Ayisy] dari nabi Shallallahu 'alaihi wa Salam dan hadits ini lebih shahih. Abdurrahman bin Ayisy tidak mendengar dari nabi Shallallahu 'alaihi wa Salam."},"2989":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَلْقَمَةَ عَنْ يَحْيَى بْنِ عَبْدِ الرَّحْمَنِ بْنِ حَاطِبٍ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ قَالَلَمَّا نَزَلَتْ{ ثُمَّ إِنَّكُمْ يَوْمَ الْقِيَامَةِ عِنْدَ رَبِّكُمْ تَخْتَصِمُونَ }قَالَ الزُّبَيْرُ يَا رَسُولَ اللَّهِ أَتُكَرَّرُ عَلَيْنَا الْخُصُومَةُ بَعْدَ الَّذِي كَانَ بَيْنَنَا فِي الدُّنْيَا قَالَ نَعَمْ فَقَالَ إِنَّ الْأَمْرَ إِذًا لَشَدِيدٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Amru bin Alqamah] dari [Yahya bin Abdurrahman bin Hathib] dari [Abdullah bin Az Zubair] dari [ayahnya] berkata: Saat turun (ayat): \"Kemudian kamu pada hari kiamat akan berbantah-bantah di hadapan Rabbmu.\" (Az Zumar: 31) Az Zubair berkata: Wahai Rasulullah, apakah berbantah-bantahan terulang lagi setelah terjadi diantara kami di dunia? Beliau menjawab: \"Ya.\" Ia berkata: Kalau begitu masalahnya sangat berat. Abu Isa berkata: Hadits ini hasan shahih."},"2990":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ وَسُلَيْمَانُ بْنُ حَرْبٍ وحَجَّاجُ بْنُ مِنْهَالٍ قَالُوا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ إِنَّ اللَّهَ يَغْفِرُ الذُّنُوبَ جَمِيعًا }وَلَا يُبَالِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ ثَابِتٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ قَالَ وَشَهْرُ بْنُ حَوْشَبٍ يَرْوِي عَنْ أُمِّ سَلَمَةَ الْأَنْصَارِيَّةِ وَأُمُّ سَلَمَةَ الْأَنْصَارِيَّةُ هِيَ أَسْمَاءُ بِنْتُ يَزِيدَ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Habban bin Hilal], [Sulaiman bin Harb] dan [Hajjaj bin Minhal], mereka berkata: Telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Syahr bin Hausyab] dari [Asma` binti Yazid] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam membaca: \"Katakanlah: 'Hai hamba-hamba-Ku yang malampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah. Sesungguhnya Allah mengampuni dosa-dosa semuanya.\" (Az Zumar: 53) dan Allah tidak peduli. Abu Isa berkata: Hadits ini hasan gharib, kami hanya mengetahuinya dari hadits Tsabit dari Syahr bin Hausyab. Syahr bin Hausyab meriwayatkan dari Ummu Salamah Al Anshariyah. Ummu Salamah Al Anshariyah adalah Asma` binti Yazid. "},"2991":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنِي مَنْصُورٌ وَسُلَيْمَانُ الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَجَاءَ يَهُودِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مُحَمَّدُ إِنَّ اللَّهَ يُمْسِكُ السَّمَاوَاتِ عَلَى إِصْبَعٍ وَالْأَرَضِينَ عَلَى إِصْبَعٍ وَالْجِبَالَ عَلَى إِصْبَعٍ وَالْخَلَائِقَ عَلَى إِصْبَعٍ ثُمَّ يَقُولُ أَنَا الْمَلِكُ قَالَ فَضَحِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ نَوَاجِذُهُ قَالَ{ وَمَا قَدَرُوا اللَّهَ حَقَّ قَدْرِهِ }قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا فُضَيْلُ بْنُ عِيَاضٍ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَ فَضَحِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَجُّبًا وَتَصْدِيقًا قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [Manshur] dan [Sulaiman Al A'masy] dari [Ibrahim] dari [Abidah] dari [Abdullah] berkata: Seorang Yahudi mendatangi nabi Shallallahu 'alaihi wa Salam lalu berkata: Hai Muhammad, sesungguhnya Allah menahan langit dengan satu jari, bumi dengan satu jari, gunung dengan satu jari, para makhluk dengan satu jari lalu berfirman: Akulah Raja. Nabi Shallallahu 'alaihi wa Salam tertawa hingga terlihat gigi geraham beliau, beliau bersabda: \"Dan mereka tidak mengagungkan Allah dengan pengagungan yang semestinya padahal bumi seluruhnya dalam genggaman-Nya pada hari kiamat dan langit digulung dengan tangan kananNya. Maha Suci Tuhan dan Maha Tinggi dia dari apa yang mereka persekutukan.\" (Az Zumar: 67) Abu Isa berkata: Hadits ini hasan shahih. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Fudlail bin Iyadl] dari [Manshur] dari [Ibrahim] dari [Abidah] dari [Abdullah] bekata: Nabi Shallallahu 'alaihi wa Salam tertawa karena kagum dan memebenarkan. Abu Isa berkata: Hadits ini hasan shahih."},"2992":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُحَمَّدُ بْنُ الصَّلْتِ حَدَّثَنَا أَبُو كُدَيْنَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي الضُّحَى عَنْ ابْنِ عَبَّاسٍ قَالَمَرَّ يَهُودِيٌّ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا يَهُودِيُّ حَدِّثْنَا فَقَالَ كَيْفَ تَقُولُ يَا أَبَا الْقَاسِمِ إِذَا وَضَعَ اللَّهُ السَّمَوَاتِ عَلَى ذِهْ وَالْأَرْضَ عَلَى ذِهْ وَالْمَاءَ عَلَى ذِهْ وَالْجِبَالَ عَلَى ذِهْ وَسَائِرَ الْخَلْقِ عَلَى ذِهْ وَأَشَارَ أَبُو جَعْفَرٍ مُحَمَّدُ بْنُ الصَّلْتِ بِخِنْصَرِهِ أَوَّلًا ثُمَّ تَابَعَ حَتَّى بَلَغَ الْإِبْهَامَ فَأَنْزَلَ اللَّهُ{ وَمَا قَدَرُوا اللَّهَ حَقَّ قَدْرِهِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ ابْنِ عَبَّاسٍ إِلَّا مِنْ هَذَا الْوَجْهِ وَأَبُو كُدَيْنَةَ اسْمُهُ يَحْيَى بْنُ الْمُهَلَّبِ قَالَ رَأَيْتُ مُحَمَّدَ بْنَ إِسْمَعِيلَ رَوَى هَذَا الْحَدِيثَ عَنْ الْحَسَنِ بْنِ شُجَاعٍ عَنْ مُحَمَّدِ بْنِ الصَّلْتِ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengkhabarkan kepada kami [Muhammad bin Ash Shalt] telah menceritakan kepada kami [Abu Kudainah] dari [Atho` bin As Sa`ib] dari [Abu Adl Dluha] dari [Ibnu Abbas] berkata: Seorang Yahudi melintasi nabi Shallallahu 'alaihi wa Salam lalu nabi Shallallahu 'alaihi wa Salam berkata padanya: \"Hai Yahudi, berceritalah kepada kami.\" si Yahudi berkata: Apa yang kau ucapkan wahai Abu Al Qasim bila Allah meletakkan langit di jari ini, bumi di jari ini, air di jari ini, gunung di jari ini dan seluruh makhluk di jari ini. Abu Ja'far Muhammad bin Ash Shalt berisyarat dengan jari kelingking terlebih dahulu lalu diteruskan hingga ke jari jempol lalu Allah menurunkan: \"Dan mereka tidak mengagungkan Allah dengan pengagungan yang semestinya.\" (Az Zumar: 67) Abu Isa berkata: Hadits ini hasan gharib shahih, kami tidak mengetahuinya dari hadits Ibnu Abbas kecuali melalui sanad ini. Abu Kunaidah namanya Yahya bin Al Muhallab. Abu Isa berkata: Aku melihat [Muhammad bin Isma'il] meriwayatkan hadits ini dari [Al Hasan bin Syuja'] dari [Muhammad bin Ash Shalt]."},"2993":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ عَنْبَسَةَ بْنِ سَعِيدٍ عَنْ حَبِيبِ بْنِ أَبِي عَمْرَةَ عَنْ مُجَاهِدٍ قَالَ قَالَ ابْنُ عَبَّاسٍأَتَدْرِي مَا سَعَةُ جَهَنَّمَ قُلْتُ لَا قَالَ أَجَلْ وَاللَّهِ مَا تَدْرِي حَدَّثَتْنِي عَائِشَةُ أَنَّهَا سَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِهِ{ وَالْأَرْضُ جَمِيعًا قَبْضَتُهُ يَوْمَ الْقِيَامَةِ وَالسَّمَوَاتُ مَطْوِيَّاتٌ بِيَمِينِهِ }قَالَتْ قُلْتُ فَأَيْنَ النَّاسُ يَوْمَئِذٍ يَا رَسُولَ اللَّهِ قَالَ عَلَى جِسْرِ جَهَنَّمَوَفِي الْحَدِيثِ قِصَّةٌ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Anbasah bin Sa'id] dari [Habib bin Abu Amrah] dari [Mujahid] berkata: [Ibnu Abbas] bertanya: Tahukah kau seberapa luasnya jahanam? Aku menjawab: Tidak. Ibnu Abbas berkata: Ya, kau tidak tahu. Telah menceritakan kepadaku [Aisyah] bahwa ia bertanya kepada Rasulullah Shallallahu 'alaihi wa Salam tentang firmanNya: \"Padahal bumi seluruhnya dalam genggamanNya pada hari kiamat dan langit digulung dengan tangan kananNya.\" (Az Zumar: 67) Aisyah bertanya: Saat itu manusia dimana wahai Rasulullah? beliau menjawab: \"Di atas jembatan jahanam.\" Dalam hadits ini ada kisahnya. Abu Isa berkata: Hadits ini hasan shahih gharib melalui sanad ini."},"2994":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ أَنَّهَا قَالَتْيَا رَسُولَ اللَّهِ{ وَالْأَرْضُ جَمِيعًا قَبْضَتُهُ يَوْمَ الْقِيَامَةِ وَالسَّمَوَاتُ مَطْوِيَّاتٌ بِيَمِينِهِ }فَأَيْنَ الْمُؤْمِنُونَ يَوْمَئِذٍ قَالَ عَلَى الصِّرَاطِ يَا عَائِشَةُهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] dari [Aisyah] ia berkata: Wahai Rasulullah, \"Padahal bumi seluruhnya dalam genggamanNya pada hari kiamat dan langit digulung dengan tangan kananNya.\" (Az Zumar: 67) Saat itu orang-orang mu`min dimana? beliau menjawab: \"Di atas jembatan wahai Aisyah.\" Hadits ini hasan shahih."},"2995":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ مُطَرِّفٍ عَنْ عَطِيَّةَ الْعَوْفِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ أَنْعَمُ وَقَدْ الْتَقَمَ صَاحِبُ الْقَرْنِ الْقَرْنَ وَحَنَى جَبْهَتَهُ وَأَصْغَى سَمْعَهُ يَنْتَظِرُ أَنْ يُؤْمَرَ أَنْ يَنْفُخَ فَيَنْفُخَ قَالَ الْمُسْلِمُونَ فَكَيْفَ نَقُولُ يَا رَسُولَ اللَّهِ قَالَ قُولُوا حَسْبُنَا اللَّهُ وَنِعْمَ الْوَكِيلُ تَوَكَّلْنَا عَلَى اللَّهِ رَبِّنَا وَرُبَّمَا قَالَ سُفْيَانُ عَلَى اللَّهِ تَوَكَّلْنَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَاهُ الْأَعْمَشُ أَيْضًا عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Mutharrif] dari [Athiyah Al Aufi] dari [Abu Sa'id Al Khudri] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bagaimana aku merasa bahagia sementara (malaikat) peniup sangkakala telah memasukkan sangkakala ke mulut, telah menundukkan dahinya dan menyiapkan pendengarannya menanti perintah peniupan untuk meniup?.\" Orang-orang muslim bertanya: Apa yang harus kami ucapkan wahai Rasulullah? beliau menjawab: \"Ucapkan: HASBUNALLAAH WAN NI'MAL WAKILL TAWAKKALNAA 'ALALLAAH RABBINAA.\" (Cukuplah Allah bagi kami dan sebaik-baik penolong, kami bertawakkal kepada Allah Rabb kami) mungkin Sufyan berkata: 'ALALLAAHI TAWAKKALNAA (kepada Allah saja kami bertawakkal). Abu Isa berkata: Hadits ini hasan. [Al A'masy] juga meriwayatkan dari [Athiyah] dari [Abu Sa'id]."},"2996":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَسْلَمَ الْعِجْلِيِّ عَنْ بِشْرِ بْنِ شَغَافٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ أَعْرَابِيٌّ يَا رَسُولَ اللَّهِ مَا الصُّورُ قَالَ قَرْنٌ يُنْفَخُ فِيهِقَالَ هَذَا حَدِيثٌ حَسَنٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ سُلَيْمَانَ التَّيْمِيِّ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Isma'il bin Ibrahim] telah mengkhabarkan kepada kami [Sulaiman At Taimi] dari [Aslam Al Ijli] dari [Bisyr bin Syughaf] dari [Abdullah bin Amru] radliallahu 'anhumaa, ia berkata: Seorang badui berkata: Wahai Rasulullah, apakah maksud istilah As Shur itu? Beliau menjawab: \"Tanduk yang ditiup.\" Abu Isa berkata: Hadits ini hasan, kami hanya mengetahuinya dari hadits Sulaiman At Taimi."},"2997":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ يَهُودِيٌّ بِسُوقِ الْمَدِينَةِ لَا وَالَّذِي اصْطَفَى مُوسَى عَلَى الْبَشَرِ قَالَ فَرَفَعَ رَجُلٌ مِنْ الْأَنْصَارِ يَدَهُ فَصَكَّ بِهَا وَجْهَهُ قَالَ تَقُولُ هَذَا وَفِينَا نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَنُفِخَ فِي الصُّورِ فَصَعِقَ مَنْ فِي السَّمَوَاتِ وَمَنْ فِي الْأَرْضِ إِلَّا مَنْ شَاءَ اللَّهُ ثُمَّ نُفِخَ فِيهِ أُخْرَى فَإِذَا هُمْ قِيَامٌ يَنْظُرُونَ }فَأَكُونُ أَوَّلَ مَنْ رَفَعَ رَأْسَهُ فَإِذَا مُوسَى آخِذٌ بِقَائِمَةٍ مِنْ قَوَائِمِ الْعَرْشِ فَلَا أَدْرِي أَرَفَعَ رَأْسَهُ قَبْلِي أَمْ كَانَ مِمَّنْ اسْتَثْنَى اللَّهُ وَمَنْ قَالَ أَنَا خَيْرٌ مِنْ يُونُسَ بْنِ مَتَّى فَقَدْ كَذَبَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abdah bin Sulaiman] telah menceritakan kepada kami [Muhammad bin Amru] telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah] berkata: Seorang Yahudi di pasar Madinah berkata: Tidak, demi Yang memilih Musa atas seluruh manusia. Abu Hurairah berkata: Seorang Anshar mengangkat tangannya lalu menampar, ia berkata: Kau mengatakan itu sementara ditengah-tengah kita ada nabi Allah Shallallahu 'alaihi wa Salam. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Dan ditiuplah sangkakala, Maka matilah siapa yang di langit dan di bumi kecuali siapa yang dikehendaki Allah. Kemudian ditiup sangkakala itu sekali lagi Maka tiba-tiba mereka berdiri menunggu (putusannya masing-masing).\" (Az Zumar: 68), aku adalah orang pertama yang mengangkat kepala, ternyata Musa memegangi salah satu tiang Arsy, aku tidak tahu apakah ia mengangat kepalanya sebelumku ataukah termasuk yang dikecualikan Allah (tidak mati) dan barangsiapa mengatakan aku lebih baik dari Yunus bin Mata berarti ia dusta.\" Abu Isa berkata: Hadits ini hasan shahih."},"2998":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا الثَّوْرِيُّ أَخْبَرَنِي أَبُو إِسْحَقَ أَنَّ الْأَغَرَّ أَبَا مُسْلِمٍ حَدَّثَهُ عَنْ أَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُنَادِي مُنَادٍ إِنَّ لَكُمْ أَنْ تَحْيَوْا فَلَا تَمُوتُوا أَبَدًا وَإِنَّ لَكُمْ أَنْ تَصِحُّوا فَلَا تَسْقَمُوا أَبَدًا وَإِنَّ لَكُمْ أَنْ تَشِبُّوا فَلَا تَهْرَمُوا أَبَدًا وَإِنَّ لَكُمْ أَنْ تَنْعَمُوا فَلَا تَبْأَسُوا أَبَدًا فَذَلِكَ قَوْلُهُ تَعَالَى{ وَتِلْكَ الْجَنَّةُ الَّتِي أُورِثْتُمُوهَا بِمَا كُنْتُمْ تَعْمَلُونَ }قَالَ أَبُو عِيسَى وَرَوَى ابْنُ الْمُبَارَكِ وَغَيْرُهُ هَذَا الْحَدِيثَ عَنْ الثَّوْرِيِّ وَلَمْ يَرْفَعْهُ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] dan lainnya, mereka berkata: Telah menceritakan kepada kami [Abdurrazzaq] telah mengkhabarkan kepada kami [Ats Tsauri] telah mengkhabarkan kepadaku [Abu Ishaq] bahwa [Al Aghar Abu Muslim] telah menceritakan kepadanya dari [Abu Sa'id] dan [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Penyeru menyerukan: Sesungguhnya kalian hidup dan tidak mati selamanya, kalian sehat dan tidak sakit selamanya, kalian muda dan tidak tua selamanya, kalian bersenang-senang dan tidak akan bersedih selamanya. Itulah firman-Nya: \"Dan Itulah surga yang diwariskan kepada kamu disebabkan amal-amal yang dahulu kamu kerjakan.\" (Az Zukhruuf: 72) Abu Isa berkata: Ibnu Al Mubarak dan lainnya meriwayatkan hadits ini dari Ats Tsauri tapi tidak memarfu'kannya."},"2999":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ وَالْأَعْمَشِ عَنْ ذَرٍّ عَنْ يُسَيْعٍ الْحَضْرَمِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الدُّعَاءُ هُوَ الْعِبَادَةُ ثُمَّ قَرَأَ{ وَقَالَ رَبُّكُمْ ادْعُونِي أَسْتَجِبْ لَكُمْ إِنَّ الَّذِينَ يَسْتَكْبِرُونَ عَنْ عِبَادَتِي سَيَدْخُلُونَ جَهَنَّمَ دَاخِرِينَ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Manshur] dan [Al A'masy] dari [Dzarr] dari [Yusai' Al Hadlrami] dari [An Nu'man bin Basyir] berkata: Aku mendengar nabi Shallallahu 'alaihi wa Salam bersabda: \"Doa adalah ibadah\" kemudian beliau membaca: \"Dan Rabbmu berfirman: 'Berdoalah kepadaKu, niscaya akan Kuperkenankan bagimu. Sesungguhnya orang-orang yang menyombongkan diri dari menyembahKu akan masuk neraka Jahannam dalam keadaan hina dina.\" (Al Mu`min: 60) Abu Isa berkata: Hadits ini hasan shahih."},"3000":{"ar":"بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ ابْنِ مَسْعُودٍ قَالَاخْتَصَمَ عِنْدَ الْبَيْتِ ثَلَاثَةُ نَفَرٍ قُرَشِيَّانِ وَثَقَفِيٌّ أَوْ ثَقَفِيَّانِ وَقُرَشِيٌّ قَلِيلٌ فِقْهُ قُلُوبِهِمْ كَثِيرٌ شَحْمُ بُطُونِهِمْ فَقَالَ أَحَدُهُمْ أَتَرَوْنَ أَنَّ اللَّهَ يَسْمَعُ مَا نَقُولُ فَقَالَ الْآخَرُ يَسْمَعُ إِذَا جَهَرْنَا وَلَا يَسْمَعُ إِذَا أَخْفَيْنَا وَقَالَ الْآخَرُ إِنْ كَانَ يَسْمَعُ إِذَا جَهَرْنَا فَإِنَّهُ يَسْمَعُ إِذَا أَخْفَيْنَا فَأَنْزَلَ اللَّهُ{ وَمَا كُنْتُمْ تَسْتَتِرُونَ أَنْ يَشْهَدَ عَلَيْكُمْ سَمْعُكُمْ وَلَا أَبْصَارُكُمْ وَلَا جُلُودُكُمْ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Bismillaahirrahmaanirrahiim. Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Mujahid] dari [Abu Ma'mar] dari [Ibnu Mas'ud] berkata: Tiga orang berseteru didekat baitullah, dua orang Quraisy dan seorang Tsaqafi, atau dua orang Tsaqafi dan satu orang Quraisy, pemahaman hati mereka sedikit sedang lemak perut mereka banyak. Salah seorang diantara mereka berkata: Apa kalian tidak tahu bahwa Allah mendengar yang kalian katakan? Yang lain berkata: Ia mendengar bila kita katakan dengan keras dan tidak mendengar bila kita lirihkan. Yang lain berkata: Bila Ia mendengar saat kita berbicara keras, Ia juga mendengar saat kita berbicara lirih. Lalu Allah menurunkan: \"Kamu sekali-sekali tidak dapat bersembunyi dari kesaksian pendengaran, penglihatan dan kulitmu kepadamu.\" (Fushshilat: 22-23) Abu Isa berkata: Hadits ini hasan shahih."}};
